//! HIR to MIR Lowering
//!
//! This module converts High-level IR (HIR) to Mid-level IR (MIR).
//!
//! According to the architecture plan:
//! - HIR: Close to source, with high-level constructs preserved
//! - MIR: SSA form with phi nodes, ready for optimization
//! - LIR: Target-specific, close to machine code
//!
//! The existing IR implementation (with IrBuilder, optimization passes, etc.)
//! serves as our MIR level.

use crate::ir::drop_analysis::{DropBehavior, DropPointAnalyzer, DropPoints};
use crate::ir::hir::*;
use crate::ir::{
    BinaryOp, CallingConvention, CompareOp, EnvironmentLayout, FunctionKind,
    FunctionSignatureBuilder, IrBasicBlock, IrBlockId, IrBuilder, IrEnumVariant, IrField,
    IrFunction, IrFunctionId, IrFunctionSignature, IrGlobal, IrGlobalId, IrId, IrInstruction,
    IrLocal, IrModule, IrParameter, IrPhiNode, IrSourceLocation, IrTerminator, IrType, IrTypeDef,
    IrTypeDefId, IrTypeDefinition, IrValue, Linkage, UnaryOp,
};
use crate::stdlib::{MethodSignature, StdlibMapping};
use crate::tast::symbols::SymbolFlags;
use crate::tast::{
    InternedString, SourceLocation, StringInterner, SymbolId, SymbolTable, TypeId, TypeKind,
    TypeTable,
};
use log::{debug, trace, warn};
use std::cell::RefCell;
use std::collections::{BTreeMap, BTreeSet, HashMap, HashSet};
use std::rc::Rc;

/// Layout information for a single field in a @:cstruct class
#[derive(Debug, Clone)]
struct CStructFieldLayout {
    symbol_id: SymbolId,
    name: String,
    byte_offset: u32,
    ir_type: IrType,
    c_type: String, // "double", "long", "int", "void*", "Vec2", etc.
}

/// Precomputed C-compatible layout for a @:cstruct class
#[derive(Debug, Clone)]
struct CStructLayout {
    fields: Vec<CStructFieldLayout>,
    total_size: u32,
    alignment: u32,
    c_name: String,
    /// All dependency typedefs (for nested cstructs), in topological order
    dep_cdefs: Vec<String>,
    /// This struct's own typedef line (without deps)
    own_cdef: String,
    /// Full cdef: deps + own typedef
    cdef_string: String,
}

/// Layout information for a single field in a @:gpuStruct class
#[derive(Debug, Clone)]
struct GpuStructFieldLayout {
    symbol_id: SymbolId,
    name: String,
    byte_offset: u32,
    /// IR type used on CPU side (F32 for Float fields, I32 for Int, etc.)
    ir_type: IrType,
    /// MSL type string ("float", "int", "uint", etc.)
    msl_type: String,
    /// Size in bytes on GPU
    size: u32,
}

/// Precomputed GPU-compatible layout for a @:gpuStruct class
#[derive(Debug, Clone)]
struct GpuStructLayout {
    fields: Vec<GpuStructFieldLayout>,
    total_size: u32,
    alignment: u32,
    msl_name: String,
    /// MSL struct typedef string
    msl_typedef: String,
    /// Dependency typedefs for nested @:gpuStruct (in topological order)
    dep_typedefs: Vec<String>,
}

/// Context for lowering HIR to MIR
pub struct HirToMirContext<'a> {
    /// MIR builder
    builder: IrBuilder,

    /// Mapping from HIR symbols to MIR registers (for variables/parameters)
    symbol_map: BTreeMap<SymbolId, IrId>,

    /// Resolved IR types for pattern-bound variables (overrides convert_type for TypeParameter types)
    symbol_ir_types: BTreeMap<SymbolId, IrType>,

    /// Concrete TypeIds for pattern-bound variables (for toString dispatch on generic fields)
    symbol_type_ids: BTreeMap<SymbolId, TypeId>,

    /// Mapping from HIR function symbols to MIR function IDs
    function_map: BTreeMap<SymbolId, crate::ir::IrFunctionId>,

    /// Mapping from global variable symbols to MIR global IDs
    /// Used for static class fields and module-level variables
    global_symbol_map: BTreeMap<SymbolId, IrGlobalId>,

    /// External function map from previously compiled modules (e.g., stdlib)
    /// These are functions defined in other modules that can be called from this module
    external_function_map: BTreeMap<SymbolId, crate::ir::IrFunctionId>,

    /// Name-based external function map for cross-file lookups
    /// This is used when SymbolIds don't match (e.g., "StringTools.startsWith" -> IrFunctionId)
    external_function_name_map: BTreeMap<String, crate::ir::IrFunctionId>,

    /// Mapping from HIR blocks to MIR blocks
    block_map: BTreeMap<usize, IrBlockId>,

    /// Loop context for break/continue
    loop_stack: Vec<LoopContext>,

    /// Current HIR module being processed
    current_module: Option<String>,

    /// Error accumulator
    errors: Vec<LoweringError>,

    /// Warning accumulator (non-fatal diagnostics like exhaustiveness checks)
    diagnostics: Vec<diagnostics::Diagnostic>,

    /// SSA-derived optimization hints extracted from HIR metadata
    /// These are queried from DFG during HIR lowering and passed to MIR
    ssa_hints: SsaOptimizationHints,

    /// Counter for generating unique lambda names
    lambda_counter: u32,

    /// Dynamic global initializers (globals needing runtime initialization)
    dynamic_globals: Vec<(SymbolId, HirExpr)>,

    /// String interner for resolving InternedString to actual strings
    string_interner: &'a StringInterner,

    /// Type table for proper type conversion
    type_table: &'a Rc<RefCell<TypeTable>>,

    /// Track closure registers and their environment pointers
    /// Maps: closure_function_pointer_register -> environment_pointer_register
    closure_environments: BTreeMap<IrId, IrId>,

    /// Mapping from field SymbolId to (class_type_id, field_index)
    /// This allows us to find the index of a field within its class
    field_index_map: BTreeMap<SymbolId, (TypeId, u32)>,

    /// Mapping from (typedef_type_id, field_name) to field_index for anonymous struct fields
    /// This allows field access on typedef'd anonymous structs like FileStat
    /// where field symbols may be created at access sites rather than typedef declaration
    typedef_field_map: BTreeMap<(TypeId, InternedString), u32>,

    /// Mapping from field SymbolId to PropertyAccessInfo (for properties with custom getters/setters)
    /// This allows us to route property access through the appropriate getter/setter methods
    property_access_map: BTreeMap<SymbolId, crate::tast::PropertyAccessInfo>,

    /// Mapping from class TypeId to constructor IrFunctionId
    /// This allows new expressions to find the constructor by class type
    constructor_map: BTreeMap<TypeId, IrFunctionId>,

    /// Reflective constructor wrappers keyed by class TypeId.
    /// Each wrapper has a uniform ABI `(obj_ptr, args_array)` and invokes the
    /// real constructor after unboxing dynamic arguments.
    constructor_reflect_wrappers: BTreeMap<TypeId, IrFunctionId>,

    /// Mapping from qualified class name to constructor IrFunctionId
    /// This is a fallback when TypeIds don't match (e.g., across separately compiled files)
    constructor_name_map: BTreeMap<String, IrFunctionId>,

    /// Reference to HIR type declarations for inheritance lookup
    /// Needed to access parent class fields during field inheritance
    current_hir_types: &'a indexmap::IndexMap<TypeId, HirTypeDecl>,

    /// Standard library runtime function mapping
    stdlib_mapping: StdlibMapping,

    /// Symbol table for resolving symbols
    symbol_table: &'a SymbolTable,

    /// Track when we're inside a lambda and what its environment layout is
    current_env_layout: Option<EnvironmentLayout>,

    /// Current class type for instance methods (used to resolve implicit field accesses)
    current_this_type: Option<TypeId>,

    /// Mapping from variable SymbolIds to their monomorphized stdlib class names
    /// Used to track Vec<Int> -> VecI32, Vec<Float> -> VecF64, etc.
    /// This is needed because extern generic classes don't have proper TypeIds in the type table
    monomorphized_var_types: BTreeMap<SymbolId, String>,

    /// Mapping from result register IrIds to the stdlib class they belong to.
    /// Used to disambiguate method calls on TypeParameter receivers when multiple
    /// stdlib classes have the same method name (e.g., Arc.get vs MutexGuard.get).
    /// Set by the Dynamic/TypeParameter method dispatch handler after MIR wrapper calls.
    register_class_hints: BTreeMap<IrId, String>,

    /// Enums that need RTTI registration
    /// Maps enum SymbolId -> (runtime_type_id, enum_name, variant_names)
    enums_for_registration: BTreeMap<SymbolId, (u32, String, Vec<String>)>,

    /// Counter for generating unique wrapper function names
    next_wrapper_id: u32,

    // === Drop Tracking (Rust-style implicit drop semantics) ===
    /// Maps variable SymbolId to the IrId holding its current heap-allocated value
    /// When a variable is reassigned, we free its old value before assigning the new one
    owned_heap_values: BTreeMap<SymbolId, IrId>,

    /// Stack of scopes, each containing the variables that own heap allocations in that scope
    /// When a scope exits, we emit Free for all owned values in that scope
    /// Inner Vec contains (SymbolId, IrId) pairs of owned values
    drop_scope_stack: Vec<Vec<(SymbolId, IrId)>>,

    /// Set of IrIds that are temporaries needing drop after use
    /// These are intermediate values from expressions (e.g., `new Complex(...).mul(...)`)
    /// that need to be freed after the containing expression completes
    temp_heap_values: Vec<IrId>,

    /// Drop point analysis results for current function
    /// Contains last-use information for precise drop insertion
    current_drop_points: Option<DropPoints>,

    /// Current statement index during lowering (for drop point matching)
    current_stmt_index: usize,

    /// Symbols that have been reassigned in the current scope
    /// These should be skipped at scope exit (they're freed at reassignment time)
    reassigned_in_scope: BTreeSet<SymbolId>,

    /// Precomputed C-compatible layouts for @:cstruct classes
    /// Maps class TypeId to its CStructLayout
    cstruct_layouts: BTreeMap<TypeId, CStructLayout>,

    /// Precomputed GPU-compatible layouts for @:gpuStruct classes
    /// Maps class TypeId to its GpuStructLayout
    gpu_struct_layouts: BTreeMap<TypeId, GpuStructLayout>,

    /// Lazily-initialized TCC runtime function IDs for __c__ inline code
    tcc_func_ids: Option<TccFuncIds>,

    /// Current function's SymbolId (for function-level metadata like @:frameworks)
    current_function_symbol: Option<SymbolId>,

    /// Mapping from sorted anonymous field names to shape_id (for runtime shape table)
    /// Key: comma-joined sorted field names — Value: shape_id (u32)
    anonymous_shapes: BTreeMap<String, u32>,

    /// Next shape ID to allocate (incremented each time a new shape is registered)
    next_anon_shape_id: u32,

    /// Interface method ordering: maps interface SymbolId → ordered list of method names
    interface_method_names: BTreeMap<SymbolId, Vec<InternedString>>,

    /// Interface method return types: maps (interface SymbolId, method name) → return TypeId
    interface_method_return_types: BTreeMap<(SymbolId, InternedString), TypeId>,

    /// Interface vtables: maps (class SymbolId, interface SymbolId) → method SymbolIds
    /// Each entry's method order matches the interface's method_names order
    interface_vtables: BTreeMap<(SymbolId, SymbolId), Vec<SymbolId>>,

    /// Interface inheritance: maps interface SymbolId → parent interface SymbolIds
    /// Used to create transitive vtables for implementing classes
    interface_extends: BTreeMap<SymbolId, Vec<SymbolId>>,

    /// Class method lookup: maps (class_symbol, method_name) → method SymbolId
    /// Populated during register_class_metadata for iterator protocol dispatch
    class_method_symbols: BTreeMap<(SymbolId, InternedString), SymbolId>,

    /// Constrained type parameter info for function parameters.
    /// Maps IrFunctionId → Vec<(param_index, interface_SymbolId)>
    /// Used at call sites to wrap arguments in fat pointers for constrained type params.
    constrained_param_interfaces: BTreeMap<IrFunctionId, Vec<(usize, SymbolId)>>,

    /// Abstract type @:from conversion rules.
    /// Maps abstract name (InternedString) → list of from-rules.
    abstract_from_rules: BTreeMap<InternedString, Vec<HirCastRule>>,

    /// Abstract type @:to conversion rules.
    /// Maps abstract name (InternedString) → list of to-rules.
    abstract_to_rules: BTreeMap<InternedString, Vec<HirCastRule>>,

    /// Abstract @:forward rules.
    /// Maps abstract SymbolId → (underlying_type, forwarded method names). Empty vec = forward all.
    abstract_forward_rules: BTreeMap<SymbolId, (TypeId, Vec<InternedString>)>,

    /// Symbols known to hold boxed DynamicValue pointers (from maybe_box_value in Let/Assign).
    /// Used by the Dynamic BinaryOp path to distinguish actual boxed Dynamic values from
    /// raw i64 values that happen to have Dynamic type (e.g., untyped lambda params).
    boxed_dynamic_symbols: BTreeSet<SymbolId>,

    /// Symbols known to carry `Type.typeof(...)` boxed ValueType payloads.
    /// These values are runtime enum payload pointers encoded as i64 and need
    /// dedicated formatting paths for trace/Std.string/interpolation parity.
    value_type_symbols: BTreeSet<SymbolId>,

    /// Symbols holding raw anonymous object handles (not boxed DynamicValue*).
    /// These come from runtime functions like `haxe_ereg_matched_pos_anon` that return
    /// Ptr(U8) anon handles directly. Field access on these must use haxe_reflect_field
    /// directly, without haxe_unbox_reference_ptr (which would corrupt the raw handle).
    raw_anon_symbols: BTreeSet<SymbolId>,

    /// Allocation sizes for class instances (in bytes).
    /// Maps class TypeId → allocation size. Populated during register_class_metadata.
    /// Used by the New handler to allocate the correct size for objects.
    class_alloc_sizes: BTreeMap<TypeId, u64>,

    /// Name-keyed class allocation sizes (qualified_name → bytes).
    /// TypeIds are unstable across compilation contexts. This map provides a stable
    /// fallback for classes compiled in separate units (e.g., stdlib Exception).
    class_alloc_sizes_by_name: BTreeMap<String, u64>,

    /// Maps class registration TypeId → class SymbolId. Survives type_table overwrites.
    /// Used for field disambiguation when multiple classes have same-named fields.
    class_type_to_symbol: BTreeMap<TypeId, SymbolId>,

    /// Maps field SymbolId → class name string for BLADE cache serialization.
    field_class_names: BTreeMap<SymbolId, String>,

    // === Class Virtual Method Dispatch ===
    /// (child_class_symbol, method_name) for methods with is_override=true
    override_methods: BTreeSet<(SymbolId, InternedString)>,

    /// class SymbolId → parent class SymbolId (from extends)
    class_parent_map: BTreeMap<SymbolId, SymbolId>,

    /// (class_symbol, method_name) → method SymbolId (all class methods)
    class_method_by_name: BTreeMap<(SymbolId, InternedString), SymbolId>,

    /// class SymbolId → [(method_name, slot_index)] — virtual method slots
    class_virtual_slots: BTreeMap<SymbolId, Vec<(InternedString, u32)>>,

    /// class SymbolId → [method_SymbolId per slot] — most-derived implementation
    class_vtables: BTreeMap<SymbolId, Vec<SymbolId>>,

    /// base method SymbolId → (slot_index, defining_class) — checked at call sites
    virtual_dispatch_info: BTreeMap<SymbolId, (u32, SymbolId)>,

    /// Parameter default expressions for functions/constructors.
    /// Keyed by IrFunctionId, value is Vec matching user-visible params (excludes implicit 'this').
    /// Only populated for functions that have at least one parameter with a default value.
    function_param_defaults: BTreeMap<IrFunctionId, Vec<Option<HirExpr>>>,

    /// Constructor param counts from import modules (for BLADE-cached constructors).
    /// fill_default_args uses this when the constructor isn't in the local module yet.
    external_constructor_param_counts: BTreeMap<IrFunctionId, usize>,

    /// Parameter types for ALL functions from imported modules.
    /// Used by fill_default_args to fill missing optional params with correct types.
    external_function_param_types: BTreeMap<IrFunctionId, Vec<IrType>>,

    /// HIR parameter types for functions/constructors.
    /// Keyed by IrFunctionId, value is Vec<TypeId> of param types (excludes implicit 'this').
    /// Used for structural subtyping: detecting class→anon or wider-anon→anon at call sites.
    function_param_hir_types: BTreeMap<IrFunctionId, Vec<TypeId>>,

    /// Current function's return TypeId, set in lower_function_body.
    /// Used by the Return handler to box values for Null<T> return types.
    current_function_return_type: Option<TypeId>,

    /// Structural subtyping: tracks variables where an anon-typed variable is backed by
    /// a different runtime representation (class pointer or wider anonymous object).
    /// Field access is redirected at compile time; materialization only at escape points.
    anon_views: BTreeMap<SymbolId, AnonBacking>,

    /// Registers that hold async function results (Future handles).
    /// Method calls like `.await()` on these registers are dispatched to Future_await.
    async_result_registers: BTreeSet<IrId>,

    /// Classes that derive PartialEq — enables field-by-field == / != codegen
    derive_partial_eq_classes: BTreeSet<SymbolId>,

    /// Classes that derive PartialOrd — enables field-by-field < / <= / > / >= codegen
    derive_partial_ord_classes: BTreeSet<SymbolId>,

    /// Classes that derive Hash — enables synthetic hashCode() method
    derive_hash_classes: BTreeSet<SymbolId>,

    /// Classes that derive Clone — enables synthetic clone() method
    derive_clone_classes: BTreeSet<SymbolId>,

    /// Classes that derive Copy — implicit shallow copy at Let/Assign/Call boundaries
    derive_copy_classes: BTreeSet<SymbolId>,

    /// Classes that derive Drop — user-defined destructor called before Free
    derive_drop_classes: BTreeSet<SymbolId>,

    /// Maps IrId (allocation register) → class SymbolId for Drop dispatch
    ir_to_drop_class: BTreeMap<IrId, SymbolId>,

    /// @:manualDrop classes — compiler does NOT auto-free
    manual_drop_classes: BTreeSet<SymbolId>,

    /// Classes that derive Debug — enables synthetic toString() method
    derive_debug_classes: BTreeSet<SymbolId>,

    /// Classes that derive Default — enables synthetic static default() method
    derive_default_classes: BTreeSet<SymbolId>,

    /// Instance fields for classes with derive traits.
    /// Maps class SymbolId → list of (field_symbol, field_type, gep_index) for non-static fields.
    /// Used by PartialEq/PartialOrd/Hash codegen to iterate fields in order.
    class_instance_fields: BTreeMap<SymbolId, Vec<(SymbolId, TypeId, u32)>>,

    /// Field default value expressions — from @:default(value) metadata or field initializers.
    /// Maps field SymbolId → HirExpr to use as default in @:derive(Default).
    field_default_exprs: BTreeMap<SymbolId, HirExpr>,

    /// Custom debug format strings from @:debugFormat("pattern") metadata.
    /// Pattern uses {fieldName} placeholders, e.g. "({x}, {y})".
    debug_format_strings: BTreeMap<SymbolId, String>,
}

/// Tracks the backing representation of an anonymous-typed variable.
/// Used for deferred structural subtyping: the variable holds the original value
/// (class pointer or wider anon handle), and field access is redirected at compile time.
#[derive(Debug, Clone)]
enum AnonBacking {
    /// Value is a class pointer. Access fields via GEP at mapped indices.
    Class {
        class_symbol: SymbolId,
        class_type: TypeId,
        /// (target_field_name, gep_index, field_type_id)
        field_map: Vec<(String, u32, TypeId)>,
    },
    /// Value is a wider anonymous object. Access fields via remapped sorted index.
    WiderAnon {
        source_type: TypeId,
        /// (target_field_name, source_sorted_index, field_type_id)
        field_map: Vec<(String, usize, TypeId)>,
    },
}

/// TCC runtime function IDs for __c__ inline code lowering
#[derive(Debug, Clone, Copy)]
struct TccFuncIds {
    create: IrFunctionId,           // rayzor_tcc_create() -> I64
    compile: IrFunctionId,          // rayzor_tcc_compile(I64, PtrString) -> I32
    add_value_symbol: IrFunctionId, // rayzor_tcc_add_value_symbol(I64, PtrString, I64) -> I64
    relocate: IrFunctionId,         // rayzor_tcc_relocate(I64) -> I32
    get_symbol: IrFunctionId,       // rayzor_tcc_get_symbol(I64, PtrString) -> I64
    delete: IrFunctionId,           // rayzor_tcc_delete(I64) -> Void
    call0: IrFunctionId,            // rayzor_tcc_call0(I64) -> I64
    free_value: IrFunctionId,       // rayzor_tcc_free_value(I64) -> Void
    string_replace: IrFunctionId, // haxe_string_replace(PtrString, PtrString, PtrString) -> PtrString
    add_framework: IrFunctionId,  // rayzor_tcc_add_framework(I64, PtrString) -> I32
    add_include_path: IrFunctionId, // rayzor_tcc_add_include_path(I64, PtrString) -> I32
    add_file: IrFunctionId,       // rayzor_tcc_add_file(I64, PtrString) -> I32
    add_clib: IrFunctionId,       // rayzor_tcc_add_clib(I64, PtrString) -> I32
}

/// SSA-derived optimization hints from DFG analysis
/// These guide MIR generation and optimization without rebuilding SSA
#[derive(Debug, Default)]
struct SsaOptimizationHints {
    /// Functions that are inline candidates (small, simple control flow)
    inline_candidates: BTreeSet<SymbolId>,

    /// Functions with straight-line code (no branches, optimize aggressively)
    straight_line_functions: BTreeSet<SymbolId>,

    /// Functions with complex control flow (many phi nodes, careful optimization)
    complex_control_flow_functions: BTreeSet<SymbolId>,

    /// Functions with common subexpressions (CSE opportunities)
    cse_opportunities: BTreeSet<SymbolId>,
}

#[derive(Debug)]
struct LoopContext {
    continue_block: IrBlockId,
    break_block: IrBlockId,
    label: Option<SymbolId>,
    /// Maps symbol IDs to their exit block phi registers
    /// When breaking, we need to add incoming edges to these phi nodes
    exit_phi_nodes: BTreeMap<SymbolId, IrId>,
    /// Maps symbol IDs to their update block phi registers (for range/for loops).
    /// When continuing, we need to add incoming edges to these phi nodes
    /// so that the update block can merge values from both the continue path
    /// and the normal body-end path.
    continue_phi_nodes: BTreeMap<SymbolId, IrId>,
}

#[derive(Debug)]
pub struct LoweringError {
    pub message: String,
    pub location: SourceLocation,
}

/// Context for lambda function generation (Two-Pass Architecture)
struct LambdaContext {
    /// The function ID of the lambda
    func_id: IrFunctionId,
    /// Entry block of the lambda
    entry_block: IrBlockId,
    /// Offset for parameter registers (0 if no env, 1 if has env)
    param_offset: u32,
    /// Environment layout (if captures exist)
    env_layout: Option<EnvironmentLayout>,
}

/// Saved state for restoring after lambda generation
struct SavedLoweringState {
    current_function: Option<IrFunctionId>,
    current_block: Option<IrBlockId>,
    symbol_map: BTreeMap<SymbolId, IrId>,
    current_env_layout: Option<EnvironmentLayout>,
    // Drop tracking state - must be saved/restored to prevent lambda bodies
    // from inheriting (and freeing) the parent function's owned values
    owned_heap_values: BTreeMap<SymbolId, IrId>,
    drop_scope_stack: Vec<Vec<(SymbolId, IrId)>>,
    temp_heap_values: Vec<IrId>,
    reassigned_in_scope: BTreeSet<SymbolId>,
    current_drop_points: Option<DropPoints>,
    current_stmt_index: usize,
    boxed_dynamic_symbols: BTreeSet<SymbolId>,
    value_type_symbols: BTreeSet<SymbolId>,
    anon_views: BTreeMap<SymbolId, AnonBacking>,
    raw_anon_symbols: BTreeSet<SymbolId>,
}

impl<'a> HirToMirContext<'a> {
    /// Create a new lowering context
    pub fn new(
        module_name: String,
        source_file: String,
        string_interner: &'a StringInterner,
        type_table: &'a Rc<RefCell<TypeTable>>,
        hir_types: &'a indexmap::IndexMap<TypeId, HirTypeDecl>,
        symbol_table: &'a SymbolTable,
        stdlib_mapping: StdlibMapping,
    ) -> Self {
        let mut ctx = Self {
            builder: IrBuilder::new(module_name.clone(), source_file),
            symbol_map: BTreeMap::new(),
            symbol_ir_types: BTreeMap::new(),
            symbol_type_ids: BTreeMap::new(),
            function_map: BTreeMap::new(),
            global_symbol_map: BTreeMap::new(),
            external_function_map: BTreeMap::new(),
            external_function_name_map: BTreeMap::new(),
            block_map: BTreeMap::new(),
            loop_stack: Vec::new(),
            current_module: Some(module_name),
            errors: Vec::new(),
            diagnostics: Vec::new(),
            ssa_hints: SsaOptimizationHints::default(),
            lambda_counter: 0,
            dynamic_globals: Vec::new(),
            string_interner,
            type_table,
            closure_environments: BTreeMap::new(),
            field_index_map: BTreeMap::new(),
            typedef_field_map: BTreeMap::new(),
            property_access_map: BTreeMap::new(),
            constructor_map: BTreeMap::new(),
            constructor_reflect_wrappers: BTreeMap::new(),
            constructor_name_map: BTreeMap::new(),
            current_hir_types: hir_types,
            stdlib_mapping,
            symbol_table,
            current_env_layout: None,
            current_this_type: None,
            monomorphized_var_types: BTreeMap::new(),
            register_class_hints: BTreeMap::new(),
            enums_for_registration: BTreeMap::new(),
            next_wrapper_id: 0,
            // Drop tracking initialization
            owned_heap_values: BTreeMap::new(),
            drop_scope_stack: Vec::new(),
            temp_heap_values: Vec::new(),
            current_drop_points: None,
            current_stmt_index: 0,
            reassigned_in_scope: BTreeSet::new(),
            cstruct_layouts: BTreeMap::new(),
            gpu_struct_layouts: BTreeMap::new(),
            tcc_func_ids: None,
            current_function_symbol: None,
            anonymous_shapes: BTreeMap::new(),
            next_anon_shape_id: 0,
            interface_method_names: BTreeMap::new(),
            interface_method_return_types: BTreeMap::new(),
            interface_vtables: BTreeMap::new(),
            interface_extends: BTreeMap::new(),
            class_method_symbols: BTreeMap::new(),
            constrained_param_interfaces: BTreeMap::new(),
            abstract_from_rules: BTreeMap::new(),
            abstract_to_rules: BTreeMap::new(),
            abstract_forward_rules: BTreeMap::new(),
            boxed_dynamic_symbols: BTreeSet::new(),
            value_type_symbols: BTreeSet::new(),
            raw_anon_symbols: BTreeSet::new(),
            class_alloc_sizes: BTreeMap::new(),
            class_alloc_sizes_by_name: BTreeMap::new(),
            class_type_to_symbol: BTreeMap::new(),
            field_class_names: BTreeMap::new(),
            override_methods: BTreeSet::new(),
            class_parent_map: BTreeMap::new(),
            class_method_by_name: BTreeMap::new(),
            class_virtual_slots: BTreeMap::new(),
            class_vtables: BTreeMap::new(),
            virtual_dispatch_info: BTreeMap::new(),
            function_param_defaults: BTreeMap::new(),
            external_constructor_param_counts: BTreeMap::new(),
            external_function_param_types: BTreeMap::new(),
            function_param_hir_types: BTreeMap::new(),
            current_function_return_type: None,
            anon_views: BTreeMap::new(),
            async_result_registers: BTreeSet::new(),
            derive_partial_eq_classes: BTreeSet::new(),
            derive_partial_ord_classes: BTreeSet::new(),
            derive_hash_classes: BTreeSet::new(),
            derive_clone_classes: BTreeSet::new(),
            derive_copy_classes: BTreeSet::new(),
            derive_drop_classes: BTreeSet::new(),
            ir_to_drop_class: BTreeMap::new(),
            manual_drop_classes: BTreeSet::new(),
            derive_debug_classes: BTreeSet::new(),
            derive_default_classes: BTreeSet::new(),
            class_instance_fields: BTreeMap::new(),
            field_default_exprs: BTreeMap::new(),
            debug_format_strings: BTreeMap::new(),
        };

        // Pre-declare malloc so it's available for heap allocations during lowering
        ctx.declare_malloc();
        // Pre-declare free so it's available for drop semantics
        ctx.declare_free();

        ctx
    }

    /// Declare malloc function so we can call it during lowering for heap allocations
    fn declare_malloc(&mut self) {
        use super::modules::IrExternFunction;
        use super::{CallingConvention, IrFunctionSignature, IrId, IrParameter, IrType};
        use crate::tast::SymbolId;

        // Create malloc signature: fn malloc(size: u64) -> *u8
        let signature = IrFunctionSignature {
            parameters: vec![IrParameter {
                name: "size".to_string(),
                ty: IrType::U64,
                reg: IrId::new(0),
                by_ref: false,
            }],
            return_type: IrType::Ptr(Box::new(IrType::U8)),
            calling_convention: CallingConvention::C,
            can_throw: false,
            type_params: vec![],
            uses_sret: false,
        };

        // Allocate a function ID
        let func_id = self.builder.module.alloc_function_id();

        // Create extern function declaration (NOT a regular function!)
        // This is critical - extern functions go in extern_functions map
        // so Cranelift backend will link them to runtime symbols
        let extern_func = IrExternFunction {
            id: func_id,
            name: "malloc".to_string(),
            symbol_id: SymbolId::from_raw(u32::MAX - 1), // Dummy symbol ID for extern
            signature,
            source: "libc".to_string(),
        };

        self.builder
            .module
            .extern_functions
            .insert(func_id, extern_func);
    }

    /// Declare free function so we can call it during lowering for drop semantics
    fn declare_free(&mut self) {
        use super::modules::IrExternFunction;
        use super::{CallingConvention, IrFunctionSignature, IrId, IrParameter, IrType};
        use crate::tast::SymbolId;

        // Create free signature: fn free(ptr: *u8) -> void
        let signature = IrFunctionSignature {
            parameters: vec![IrParameter {
                name: "ptr".to_string(),
                ty: IrType::Ptr(Box::new(IrType::U8)),
                reg: IrId::new(0),
                by_ref: false,
            }],
            return_type: IrType::Void,
            calling_convention: CallingConvention::C,
            can_throw: false,
            type_params: vec![],
            uses_sret: false,
        };

        // Allocate a function ID
        let func_id = self.builder.module.alloc_function_id();

        // Create extern function declaration
        let extern_func = IrExternFunction {
            id: func_id,
            name: "free".to_string(),
            symbol_id: SymbolId::from_raw(u32::MAX - 2), // Dummy symbol ID for extern
            signature,
            source: "libc".to_string(),
        };

        self.builder
            .module
            .extern_functions
            .insert(func_id, extern_func);
    }

    // === Drop Tracking Methods (Rust-style implicit drop semantics) ===

    /// Enter a new scope for drop tracking
    fn enter_drop_scope(&mut self) {
        self.drop_scope_stack.push(Vec::new());
    }

    /// Exit a scope, emitting Free instructions for all owned heap values in that scope
    fn exit_drop_scope(&mut self) {
        if let Some(scope) = self.drop_scope_stack.pop() {
            for (symbol, _scope_ir_id) in scope {
                // Get the CURRENT value from owned_heap_values, not the stale scope entry.
                // The scope entry might have an old IrId if the variable was reassigned.
                let current_ir_id = match self.owned_heap_values.get(&symbol).copied() {
                    Some(id) => id,
                    None => {
                        // Variable was already freed or transferred (e.g., to closure)
                        continue;
                    }
                };

                // Skip lambda captures - they're owned by the closure
                if let Some(drop_points) = &self.current_drop_points {
                    if drop_points.lambda_captures.contains(&symbol) {
                        continue;
                    }
                }

                // Free this value if not terminated
                if !self.is_terminated() {
                    self.maybe_emit_drop_call(current_ir_id);
                    self.builder.build_free(current_ir_id);
                }

                // Remove from owned_heap_values since it's been freed
                self.owned_heap_values.remove(&symbol);
            }
        }
    }

    /// Cleanup all scopes - used for early return from functions
    /// Frees all heap values in all active scopes (innermost to outermost)
    fn cleanup_all_scopes(&mut self) {
        self.cleanup_all_scopes_except_symbol(None);
    }

    fn cleanup_all_scopes_except_symbol(&mut self, skip_symbol: Option<SymbolId>) {
        // Collect IrIds to free first (to avoid borrow conflict with maybe_emit_drop_call)
        let mut to_free = Vec::new();
        for scope in self.drop_scope_stack.iter().rev() {
            for (symbol, ir_id) in scope {
                // Skip the returned variable — its value escapes the function
                if skip_symbol == Some(*symbol) {
                    trace!(
                        "Drop: Skipping {:?} ({:?}) in cleanup (returned value)",
                        symbol,
                        ir_id
                    );
                    continue;
                }
                // Skip lambda captures
                if let Some(drop_points) = &self.current_drop_points {
                    if drop_points.lambda_captures.contains(symbol) {
                        trace!("Drop: Skipping {:?} in cleanup (lambda capture)", symbol);
                        continue;
                    }
                }

                if self.reassigned_in_scope.contains(symbol) {
                    // For reassigned variables, free the CURRENT value from owned_heap_values
                    // (the old value was already freed at reassignment time)
                    if let Some(&current_ir) = self.owned_heap_values.get(symbol) {
                        to_free.push((*symbol, current_ir));
                    }
                } else {
                    to_free.push((*symbol, *ir_id));
                }
            }
        }

        // Now emit drop calls and frees
        for (symbol, ir_id) in to_free {
            if !self.is_terminated() {
                // @:derive(Drop) — call drop() before Free
                self.maybe_emit_drop_call(ir_id);
                self.builder.build_free(ir_id);
                trace!(
                    "Drop: Freed {:?} ({:?}) in cleanup_all_scopes",
                    symbol,
                    ir_id
                );
            }
        }
        // Note: We don't clear the scopes here because the function is about to return.
        // The scopes will be cleared when the function context is dropped.
    }

    /// Cleanup only @:derive(Drop) class values at implicit function end.
    /// Unlike cleanup_all_scopes(), this only touches Drop-class values to avoid
    /// double-freeing non-Drop values that InsertFreePass handles.
    fn cleanup_drop_classes_only(&mut self) {
        let mut to_free = Vec::new();
        for scope in self.drop_scope_stack.iter().rev() {
            for (symbol, ir_id) in scope {
                // Skip lambda captures
                if let Some(drop_points) = &self.current_drop_points {
                    if drop_points.lambda_captures.contains(symbol) {
                        continue;
                    }
                }

                // Get the current IrId (may differ from scope entry if reassigned)
                let current_ir = if self.reassigned_in_scope.contains(symbol) {
                    match self.owned_heap_values.get(symbol).copied() {
                        Some(ir) => ir,
                        None => continue,
                    }
                } else {
                    *ir_id
                };

                // Only process Drop-class values
                if self.get_drop_class_for_ir(current_ir).is_some() {
                    to_free.push(current_ir);
                }
            }
        }

        for ir_id in to_free {
            if !self.is_terminated() {
                self.maybe_emit_drop_call(ir_id);
                self.builder.build_free(ir_id);
            }
        }
    }

    /// Register a heap-allocated value as owned by a variable
    /// This is called when a variable is assigned a newly allocated value (from `new`)
    fn register_owned_value(&mut self, symbol: SymbolId, ir_id: IrId) {
        // Check if this variable already owns a heap value
        if let Some(old_ir_id) = self.owned_heap_values.get(&symbol).copied() {
            // REASSIGNMENT: Free the old value immediately.
            // This is always safe because the old value's IrId dominates the current block:
            // - If from initial assignment: that block dominates all subsequent blocks
            // - If from phi node: phi is in loop header which dominates loop body
            if !self.is_terminated() {
                // @:derive(Drop) — call drop() before Free
                self.maybe_emit_drop_call(old_ir_id);
                self.builder.build_free(old_ir_id);
            }

            // DON'T update scope entries - this caused dominator issues.
            // The scope tracks the ORIGINAL declaration which may be from a different block.
            // Reassigned values are handled here at reassignment time, not at scope exit.
            // Mark this symbol as reassigned so scope exit skips it.
            self.reassigned_in_scope.insert(symbol);
        } else {
            // New declaration - add to current scope for cleanup on scope exit
            if let Some(current_scope) = self.drop_scope_stack.last_mut() {
                current_scope.push((symbol, ir_id));
            }
        }

        // Track the current value
        self.owned_heap_values.insert(symbol, ir_id);

        // Track Drop class association for @:derive(Drop)
        if !self.derive_drop_classes.is_empty() {
            if let Some(class_name) = self.register_class_hints.get(&ir_id).cloned() {
                for &class_sym in &self.derive_drop_classes {
                    if let Some(symbol_info) = self.symbol_table.get_symbol(class_sym) {
                        if self.string_interner.get(symbol_info.name) == Some(class_name.as_str()) {
                            self.ir_to_drop_class.insert(ir_id, class_sym);
                            break;
                        }
                    }
                }
            }
        }
    }

    /// Register a temporary heap-allocated value that needs dropping after use
    /// This is for intermediate results like `new Complex(...).mul(...)`
    fn register_temp_value(&mut self, ir_id: IrId) {
        self.temp_heap_values.push(ir_id);
    }

    /// Free all temporary values (called after expression completes)
    fn drop_temps(&mut self) {
        for ir_id in std::mem::take(&mut self.temp_heap_values) {
            self.builder.build_free(ir_id);
        }
    }

    /// Determine the drop behavior for a type using the Drop trait system.
    ///
    /// Uses the type's `is_extern` flag to identify runtime-managed types.
    /// - Extern classes (Thread, Channel, Arc, etc.) → RuntimeManaged
    /// - User-defined classes → AutoDrop
    /// - Primitives, arrays, Dynamic → NoDrop
    fn get_drop_behavior(&self, type_id: TypeId) -> DropBehavior {
        let type_table = self.type_table.borrow();
        if let Some(type_info) = type_table.get(type_id) {
            match &type_info.kind {
                // GenericInstance: Check if the base type is extern (e.g., Arc<T>, Channel<T>)
                TypeKind::GenericInstance { base_type, .. } => {
                    if let Some(base_info) = type_table.get(*base_type) {
                        if let Some(symbol_id) = base_info.symbol_id() {
                            if let Some(symbol) = self.symbol_table.get_symbol(symbol_id) {
                                // Use SymbolFlags::EXTERN from the TypedAST
                                if symbol.flags.contains(SymbolFlags::EXTERN) {
                                    return DropBehavior::RuntimeManaged;
                                }
                                // Fallback: Check stdlib class by native name or simple name
                                if self.is_stdlib_class_by_symbol(symbol) {
                                    return DropBehavior::RuntimeManaged;
                                }
                            }
                        }
                        // Base type is a non-extern Class
                        if matches!(&base_info.kind, TypeKind::Class { .. }) {
                            return DropBehavior::AutoDrop;
                        }
                    }
                    DropBehavior::NoDrop
                }
                TypeKind::Class { symbol_id, .. } => {
                    // Use SymbolFlags from the TypedAST
                    if let Some(symbol) = self.symbol_table.get_symbol(*symbol_id) {
                        // @:cstruct classes are user-managed (no AutoDrop header)
                        if symbol.flags.is_cstruct() {
                            return DropBehavior::RuntimeManaged;
                        }
                        if symbol.flags.contains(SymbolFlags::EXTERN) {
                            return DropBehavior::RuntimeManaged;
                        }
                        // Fallback: Check if it's a known stdlib class by native name or simple name.
                        // This handles cases where the EXTERN flag wasn't propagated
                        // through the symbol table (e.g., stdlib types loaded via imports
                        // where the local symbol doesn't carry the extern flag).
                        if self.is_stdlib_class_by_symbol(symbol) {
                            return DropBehavior::RuntimeManaged;
                        }
                    }
                    // Check for @:derive(Drop) — user-defined destructor
                    if self.derive_drop_classes.contains(symbol_id) {
                        return DropBehavior::AutoDropWithDtor;
                    }
                    // Check for @:manualDrop — user manages lifetime
                    if self.manual_drop_classes.contains(symbol_id) {
                        return DropBehavior::ManualDrop;
                    }
                    // User-defined (non-extern) classes need AutoDrop
                    DropBehavior::AutoDrop
                }
                // Arrays: runtime-managed buffer, no Free needed
                TypeKind::Array { .. } => DropBehavior::NoDrop,
                // Dynamic: unknown ownership at compile time, no Free
                TypeKind::Dynamic => DropBehavior::NoDrop,
                // Other types don't need drop
                _ => DropBehavior::NoDrop,
            }
        } else {
            DropBehavior::NoDrop
        }
    }

    /// Check if a symbol refers to a known stdlib class by trying native name then simple name
    fn is_stdlib_class_by_symbol(&self, symbol: &crate::tast::symbols::Symbol) -> bool {
        // Try lowered @:native name first (e.g., "rayzor::concurrent::Arc" -> "rayzor_concurrent_Arc")
        if let Some(native) = symbol.native_name {
            if let Some(native_str) = self.string_interner.get(native) {
                let lowered = native_str.replace("::", "_");
                if self.stdlib_mapping.is_stdlib_class(&lowered) {
                    return true;
                }
            }
        }
        // Fall back to simple name
        if let Some(class_name) = self.string_interner.get(symbol.name) {
            if self.stdlib_mapping.is_stdlib_class(class_name) {
                return true;
            }
        }
        false
    }

    /// Check if a type needs drop (convenience wrapper for get_drop_behavior)
    fn type_needs_drop(&self, type_id: TypeId) -> bool {
        matches!(
            self.get_drop_behavior(type_id),
            DropBehavior::AutoDrop | DropBehavior::AutoDropWithDtor
        )
    }

    /// Detect reflective Type allocation calls that return fresh class instances.
    fn is_reflective_type_alloc_call(&self, callee: &HirExpr, arg_count: usize) -> bool {
        let is_alloc_method = |name: &str| matches!(name, "createInstance" | "createEmptyInstance");

        match &callee.kind {
            HirExprKind::Variable { symbol, .. } => {
                if let Some((class_name, method_name, _)) =
                    self.get_stdlib_runtime_info(*symbol, TypeId::invalid(), Some(arg_count), None)
                {
                    if class_name == "Type" && is_alloc_method(method_name) {
                        return true;
                    }
                }

                let Some(sym) = self.symbol_table.get_symbol(*symbol) else {
                    return false;
                };
                let method_name = self.string_interner.get(sym.name).unwrap_or("");
                if !is_alloc_method(method_name) {
                    return false;
                }

                if let Some(qn) = sym.qualified_name.and_then(|q| self.string_interner.get(q)) {
                    return qn == "Type.createInstance"
                        || qn == "Type.createEmptyInstance"
                        || qn.ends_with(".Type.createInstance")
                        || qn.ends_with(".Type.createEmptyInstance");
                }
                false
            }
            HirExprKind::Field { object, field } => {
                let owner_is_type = if let HirExprKind::Variable { symbol, .. } = &object.kind {
                    self.symbol_table.get_symbol(*symbol).is_some_and(|sym| {
                        self.string_interner.get(sym.name) == Some("Type")
                            || sym
                                .qualified_name
                                .and_then(|q| self.string_interner.get(q))
                                .is_some_and(|qn| qn == "Type" || qn.ends_with(".Type"))
                    })
                } else {
                    false
                };
                if !owner_is_type {
                    return false;
                }

                self.symbol_table
                    .get_symbol(*field)
                    .and_then(|sym| self.string_interner.get(sym.name))
                    .is_some_and(is_alloc_method)
            }
            _ => false,
        }
    }

    /// Check drop points and emit Free for variables at their last use
    /// Called after each statement during lowering
    fn check_drop_points_after_statement(&mut self) {
        use crate::ir::drop_analysis::should_drop_at_statement;

        // Get drop points - if none, skip
        let drop_points = match &self.current_drop_points {
            Some(dp) => dp,
            None => return,
        };

        // Check each owned heap variable to see if it should be dropped
        // We iterate over owned_heap_values to find variables that are:
        // 1. Heap-allocated (tracked in drop_points.heap_allocated)
        // 2. Not escaping (not in drop_points.escaping)
        // 3. At their last use (drop_points.last_use[symbol].statement_index == current_stmt_index)
        let current_idx = self.current_stmt_index;
        let mut to_drop = Vec::new();

        for (&symbol, &ir_id) in &self.owned_heap_values {
            if should_drop_at_statement(drop_points, symbol, current_idx) {
                to_drop.push((symbol, ir_id));
            }
        }

        // Emit Free for each variable at its last use
        for (symbol, ir_id) in to_drop {
            self.builder.build_free(ir_id);
            // Remove from owned_heap_values since it's been freed
            self.owned_heap_values.remove(&symbol);
        }
    }

    /// Look up a function ID by symbol, checking both local and external function maps
    fn get_function_id(&self, symbol: &SymbolId) -> Option<IrFunctionId> {
        let result = self
            .function_map
            .get(symbol)
            .copied()
            .or_else(|| self.external_function_map.get(symbol).copied());
        result
    }

    /// Resolve a class symbol from a receiver type, handling aliases/generic instances.
    /// Falls back to the persisted class_type_to_symbol map when TypeIds drift.
    fn resolve_receiver_class_symbol(&self, type_id: TypeId) -> Option<SymbolId> {
        let mut current = type_id;
        {
            let type_table = self.type_table.borrow();
            let mut visited = HashSet::new();
            loop {
                if !visited.insert(current) {
                    break;
                }
                match type_table.get(current).map(|ti| &ti.kind) {
                    Some(TypeKind::Class { symbol_id, .. }) => return Some(*symbol_id),
                    Some(TypeKind::TypeAlias { target_type, .. }) => {
                        current = *target_type;
                    }
                    Some(TypeKind::GenericInstance { base_type, .. }) => {
                        current = *base_type;
                    }
                    _ => break,
                }
            }
        }

        self.class_type_to_symbol
            .get(&current)
            .copied()
            .or_else(|| self.class_type_to_symbol.get(&type_id).copied())
    }

    /// Resolve the canonical runtime class TypeId used by MIR type metadata.
    /// TAST class TypeIds can differ from HIR/MIR TypeIds; runtime RTTI registration
    /// is keyed by MIR TypeId, so we map through class_symbol when needed.
    fn resolve_runtime_class_type_id(
        &self,
        tast_type_id: TypeId,
        class_symbol: SymbolId,
    ) -> TypeId {
        let has_mir_type = |tid: TypeId| {
            self.builder
                .module
                .types
                .values()
                .any(|typedef| typedef.type_id == tid)
        };

        if self.class_type_to_symbol.get(&tast_type_id) == Some(&class_symbol)
            && has_mir_type(tast_type_id)
        {
            return tast_type_id;
        }

        let symbol_type_id = TypeId::from_raw(class_symbol.as_raw());
        let mut best: Option<(u8, TypeId)> = None;
        for (candidate_type_id, sym) in &self.class_type_to_symbol {
            if *sym != class_symbol {
                continue;
            }

            // Prefer TypeIds that are known canonical class IDs:
            // 1) Present as a typedef in the current MIR module
            // 2) Present in class_alloc_sizes (seeded from imported class metadata)
            // 3) Not just the SymbolId-derived synthetic fallback.
            let score = if has_mir_type(*candidate_type_id) {
                3
            } else if self.class_alloc_sizes.contains_key(candidate_type_id) {
                2
            } else if *candidate_type_id != symbol_type_id {
                1
            } else {
                0
            };

            match best {
                Some((best_score, best_tid)) => {
                    if score > best_score
                        || (score == best_score && candidate_type_id.as_raw() < best_tid.as_raw())
                    {
                        best = Some((score, *candidate_type_id));
                    }
                }
                None => best = Some((score, *candidate_type_id)),
            }
        }

        if let Some((_, tid)) = best {
            return tid;
        }

        // Last-resort fallback: match class short name to MIR typedef name.
        // This handles symbol-id drift between TAST/HIR when class_type_to_symbol
        // has not been populated for the current symbol-id variant.
        if let Some(class_name) = self
            .symbol_table
            .get_symbol(class_symbol)
            .and_then(|s| self.string_interner.get(s.name))
        {
            let mut by_name: Option<TypeId> = None;
            for typedef in self.builder.module.types.values() {
                if typedef.name == class_name {
                    by_name = Some(typedef.type_id);
                    break;
                }
            }
            if let Some(tid) = by_name {
                return tid;
            }
        }

        tast_type_id
    }

    /// Resolve a method symbol by (class, method_name), walking parent classes.
    fn resolve_class_method_symbol(
        &self,
        class_symbol: SymbolId,
        method_name: InternedString,
    ) -> Option<SymbolId> {
        let mut current = Some(class_symbol);
        let mut visited = HashSet::new();
        while let Some(cls) = current {
            if !visited.insert(cls) {
                break;
            }
            if let Some(method_symbol) = self
                .class_method_symbols
                .get(&(cls, method_name))
                .copied()
                .or_else(|| self.class_method_by_name.get(&(cls, method_name)).copied())
            {
                return Some(method_symbol);
            }
            current = self.class_parent_map.get(&cls).copied();
        }
        None
    }

    /// Check whether a method symbol is declared on the class or one of its parents.
    /// This avoids ambiguous bare-name fallback when multiple classes share names
    /// like `toString`, especially across lazy-loaded import modules.
    fn symbol_belongs_to_class_hierarchy(
        &self,
        method_symbol: SymbolId,
        class_symbol: SymbolId,
    ) -> bool {
        let method_scope = match self.symbol_table.get_symbol(method_symbol) {
            Some(sym) => sym.scope_id,
            None => return false,
        };

        let mut current = Some(class_symbol);
        let mut visited = HashSet::new();
        while let Some(cls) = current {
            if !visited.insert(cls) {
                break;
            }
            let cls_scope = self.symbol_table.get_symbol(cls).map(|s| s.scope_id);
            if cls_scope == Some(method_scope) {
                return true;
            }
            current = self.class_parent_map.get(&cls).copied();
        }

        false
    }

    /// Resolve a function ID by symbol with a qualified-name fallback across local/external maps.
    fn resolve_function_id_with_qualified_fallback(
        &self,
        symbol: SymbolId,
    ) -> Option<IrFunctionId> {
        if let Some(func_id) = self.get_function_id(&symbol) {
            return Some(func_id);
        }

        let qual_name = self
            .symbol_table
            .get_symbol(symbol)
            .and_then(|s| s.qualified_name)
            .and_then(|qn| self.string_interner.get(qn))?;

        for (local_sym, &local_func_id) in &self.function_map {
            let local_qual = self
                .symbol_table
                .get_symbol(*local_sym)
                .and_then(|s| s.qualified_name)
                .and_then(|qn| self.string_interner.get(qn));
            if local_qual == Some(qual_name) {
                return Some(local_func_id);
            }
        }

        for (ext_sym, &ext_func_id) in &self.external_function_map {
            let ext_qual = self
                .symbol_table
                .get_symbol(*ext_sym)
                .and_then(|s| s.qualified_name)
                .and_then(|qn| self.string_interner.get(qn));
            if ext_qual == Some(qual_name) {
                return Some(ext_func_id);
            }
        }

        self.external_function_name_map.get(qual_name).copied()
    }

    /// Resolve an instance method function ID from receiver type + method name.
    fn resolve_method_function_id(
        &self,
        receiver_type: TypeId,
        method_name: InternedString,
    ) -> Option<IrFunctionId> {
        let class_symbol = self.resolve_receiver_class_symbol(receiver_type)?;
        let method_symbol_opt = self.resolve_class_method_symbol(class_symbol, method_name);
        if let Some(method_symbol) = method_symbol_opt {
            if let Some(func_id) = self.resolve_function_id_with_qualified_fallback(method_symbol) {
                return Some(func_id);
            }
        }

        let class_name_hint = self
            .symbol_table
            .get_symbol(class_symbol)
            .and_then(|s| s.qualified_name.or(Some(s.name)))
            .and_then(|n| self.string_interner.get(n));
        let method_decl_loc = method_symbol_opt
            .and_then(|method_symbol| self.symbol_table.get_symbol(method_symbol))
            .map(|s| s.definition_location)
            .unwrap_or(SourceLocation::unknown());

        let mut name_matches = BTreeSet::new();

        for (candidate_sym, &func_id) in &self.function_map {
            if let Some(sym_info) = self.symbol_table.get_symbol(*candidate_sym) {
                if sym_info.name != method_name {
                    continue;
                }
                name_matches.insert(func_id);
                if self.symbol_belongs_to_class_hierarchy(*candidate_sym, class_symbol) {
                    return Some(func_id);
                }
                if method_decl_loc.is_valid() && sym_info.definition_location == method_decl_loc {
                    return Some(func_id);
                }
                if let Some(class_hint) = class_name_hint {
                    let qual_match = sym_info
                        .qualified_name
                        .and_then(|qn| self.string_interner.get(qn))
                        .map(|qn| qn.contains(class_hint))
                        .unwrap_or(false);
                    if qual_match {
                        return Some(func_id);
                    }
                }
            }
        }

        for (candidate_sym, &func_id) in &self.external_function_map {
            if let Some(sym_info) = self.symbol_table.get_symbol(*candidate_sym) {
                if sym_info.name != method_name {
                    continue;
                }
                name_matches.insert(func_id);
                if self.symbol_belongs_to_class_hierarchy(*candidate_sym, class_symbol) {
                    return Some(func_id);
                }
                if method_decl_loc.is_valid() && sym_info.definition_location == method_decl_loc {
                    return Some(func_id);
                }
                if let Some(class_hint) = class_name_hint {
                    let qual_match = sym_info
                        .qualified_name
                        .and_then(|qn| self.string_interner.get(qn))
                        .map(|qn| qn.contains(class_hint))
                        .unwrap_or(false);
                    if qual_match {
                        return Some(func_id);
                    }
                }
            }
        }

        let method_name_str = self.string_interner.get(method_name)?;
        let class_short_hint = class_name_hint
            .and_then(|n| n.rsplit('.').next())
            .filter(|s| !s.is_empty());
        let mut module_name_matches = BTreeSet::new();
        for (func_id, func) in &self.builder.module.functions {
            if func.name != method_name_str {
                continue;
            }
            module_name_matches.insert(*func_id);
            if let Some(class_hint) = class_name_hint {
                let qual_match = func
                    .qualified_name
                    .as_deref()
                    .map(|qn| {
                        qn.contains(class_hint)
                            || class_short_hint
                                .map(|short| qn.contains(short))
                                .unwrap_or(false)
                    })
                    .unwrap_or(false);
                if qual_match {
                    return Some(*func_id);
                }
            }
        }
        if module_name_matches.len() == 1 {
            return module_name_matches.iter().next().copied();
        }

        let mut extern_name_matches = BTreeSet::new();
        for (func_id, func) in &self.builder.module.extern_functions {
            if func.name != method_name_str {
                continue;
            }
            extern_name_matches.insert(*func_id);
        }
        if extern_name_matches.len() == 1 {
            return extern_name_matches.iter().next().copied();
        }

        if name_matches.len() == 1 {
            return name_matches.iter().next().copied();
        }

        None
    }

    /// Find a MIR function by its bare name in function_map
    fn find_function_by_name(&self, name: &str) -> Option<IrFunctionId> {
        let module = &self.builder.module;
        for (func_id, func) in &module.functions {
            if func.name == name {
                return Some(*func_id);
            }
        }
        None
    }

    /// Find a MIR function by its bare name in external_function_map/extern_functions
    fn find_external_function_by_name(&self, name: &str) -> Option<IrFunctionId> {
        self.external_function_name_map
            .get(name)
            .copied()
            .or_else(|| {
                self.builder
                    .module
                    .extern_functions
                    .iter()
                    .find(|(_, f)| f.name == name)
                    .map(|(id, _)| *id)
            })
    }

    /// Build a heap allocation (via malloc) for class instances
    /// This is used for class instances that may escape the current function
    fn build_heap_alloc(&mut self, size: u64) -> Option<IrId> {
        // Look up malloc in extern_functions (where declare_malloc adds it)
        let malloc_id = self
            .builder
            .module
            .extern_functions
            .iter()
            .find(|(_, f)| f.name == "malloc")
            .map(|(id, _)| *id)
            .or_else(|| {
                // Fallback: check external_function_name_map
                self.external_function_name_map.get("malloc").copied()
            })?;

        // Create size constant
        let size_reg = self.builder.build_const(IrValue::U64(size))?;

        // Call malloc - returns Ptr(U8)
        let ptr_u8_ty = IrType::Ptr(Box::new(IrType::U8));
        self.builder
            .build_call_direct(malloc_id, vec![size_reg], ptr_u8_ty)
    }

    /// Check if a class symbol has the @:cstruct flag
    fn is_cstruct_class(&self, type_id: TypeId) -> bool {
        let type_table = self.type_table.borrow();
        if let Some(type_info) = type_table.get(type_id) {
            if let Some(symbol_id) = type_info.symbol_id() {
                if let Some(sym) = self.symbol_table.get_symbol(symbol_id) {
                    return sym.flags.is_cstruct();
                }
            }
        }
        false
    }

    /// Get or compute the CStruct layout for a class type
    fn get_or_compute_cstruct_layout(&mut self, type_id: TypeId) -> Option<CStructLayout> {
        if let Some(layout) = self.cstruct_layouts.get(&type_id) {
            return Some(layout.clone());
        }

        // Look up class info from type table
        let (symbol_id, class_name, no_mangle) = {
            let type_table = self.type_table.borrow();
            let type_info = type_table.get(type_id)?;
            let symbol_id = type_info.symbol_id()?;
            let sym = self.symbol_table.get_symbol(symbol_id)?;
            let name = self.string_interner.get(sym.name)?.to_string();
            let no_mangle = sym.flags.is_no_mangle();
            (symbol_id, name, no_mangle)
        };

        // Get fields from field_index_map for this type.
        // Try matching by type_id first, then fall back to matching by class symbol_id
        // (TypeIds can differ between expression types and registration types)
        let mut fields_with_index: Vec<(SymbolId, u32)> = Vec::new();
        for (field_sym, (class_ty, idx)) in &self.field_index_map {
            if *class_ty == type_id {
                fields_with_index.push((*field_sym, *idx));
            }
        }
        // Fallback: if no fields found by type_id, match fields by name.
        // TypeIds can differ between expression types and registration types,
        // so we find fields whose name matches our class's field names.
        if fields_with_index.is_empty() {
            // Get the class name to match against field_index_map entries
            let class_name_interned = self.symbol_table.get_symbol(symbol_id).map(|s| s.name);

            // Find all unique class type_ids in field_index_map
            let field_class_tys: std::collections::HashSet<TypeId> =
                self.field_index_map.values().map(|(ty, _)| *ty).collect();

            // For each class type_id, check if its fields belong to our class
            // by checking field names against what the class should have
            for candidate_ty in &field_class_tys {
                // Check if this candidate type has the same class name/symbol
                let is_our_class = self.current_hir_types.iter().any(|(tid, decl)| {
                    if *tid != *candidate_ty {
                        return false;
                    }
                    if let HirTypeDecl::Class(c) = decl {
                        c.symbol_id == symbol_id
                    } else {
                        false
                    }
                });
                if is_our_class {
                    for (field_sym, (class_ty, idx)) in &self.field_index_map {
                        if class_ty == candidate_ty {
                            fields_with_index.push((*field_sym, *idx));
                        }
                    }
                    break;
                }
            }
        }
        fields_with_index.sort_by_key(|(_, idx)| *idx);

        let c_name = if no_mangle {
            class_name.clone()
        } else {
            // Simple mangling: package_ClassName
            class_name.replace('.', "_")
        };

        let mut byte_offset: u32 = 0;
        let mut max_align: u32 = 1;
        let mut layout_fields = Vec::new();

        let mut dep_cdefs: Vec<String> = Vec::new();

        for (field_sym_id, _idx) in &fields_with_index {
            let sym = self.symbol_table.get_symbol(*field_sym_id)?;
            let field_name = self.string_interner.get(sym.name)?.to_string();
            let ir_type = self.convert_type(sym.type_id);

            // Resolve field type to determine C type mapping.
            // Check the original Haxe type (before IR conversion) for rich type info.
            let (size, align, c_type, ir_type) =
                self.resolve_cstruct_field_type(sym.type_id, ir_type, &mut dep_cdefs);

            // Align offset
            if align > 0 {
                byte_offset = (byte_offset + align - 1) & !(align - 1);
            }
            if align > max_align {
                max_align = align;
            }

            layout_fields.push(CStructFieldLayout {
                symbol_id: *field_sym_id,
                name: field_name,
                byte_offset,
                ir_type,
                c_type,
            });

            byte_offset += size;
        }

        // Pad total size to alignment
        if max_align > 0 {
            byte_offset = (byte_offset + max_align - 1) & !(max_align - 1);
        }

        // Build cdef string — own typedef only
        let mut own_cdef = format!("typedef struct {{ ");
        for f in &layout_fields {
            own_cdef.push_str(&format!("{} {}; ", f.c_type, f.name));
        }
        own_cdef.push_str(&format!("}} {};\n", c_name));

        // Full cdef includes dependency typedefs first, then own typedef
        let mut full_cdef = String::new();
        for dep in &dep_cdefs {
            full_cdef.push_str(dep);
        }
        full_cdef.push_str(&own_cdef);

        let layout = CStructLayout {
            fields: layout_fields,
            total_size: byte_offset,
            alignment: max_align,
            c_name,
            dep_cdefs,
            own_cdef,
            cdef_string: full_cdef,
        };

        self.cstruct_layouts.insert(type_id, layout.clone());
        Some(layout)
    }

    /// Resolve a field's Haxe type to C type info for @:cstruct layout.
    ///
    /// Returns (size_bytes, alignment, c_type_string, ir_type).
    /// For nested @:cstruct types, recursively computes their layout and adds
    /// dependency typedefs to `dep_cdefs`.
    fn resolve_cstruct_field_type(
        &mut self,
        haxe_type_id: TypeId,
        ir_type: IrType,
        dep_cdefs: &mut Vec<String>,
    ) -> (u32, u32, String, IrType) {
        // Check the Haxe-level type for rich info (Ptr, Usize, nested cstruct, etc.)
        let type_info = {
            let type_table = self.type_table.borrow();
            type_table.get(haxe_type_id).map(|t| (t.kind.clone(), t.id))
        };

        if let Some((kind, _tid)) = type_info {
            match &kind {
                // Abstract types: Ptr<T>, Ref<T>, Box<T>, Usize, CString
                TypeKind::Abstract {
                    symbol_id,
                    type_args,
                    ..
                } => {
                    let abstract_name = self
                        .symbol_table
                        .get_symbol(*symbol_id)
                        .and_then(|s| self.string_interner.get(s.name))
                        .map(|s| s.to_string())
                        .unwrap_or_default();

                    match abstract_name.as_str() {
                        "Ptr" => {
                            // Ptr<T> → T* if T is @:cstruct, else void*
                            let c_type = if let Some(inner_tid) = type_args.first() {
                                self.cstruct_ptr_c_type(*inner_tid, dep_cdefs)
                            } else {
                                "void*".to_string()
                            };
                            return (8, 8, c_type, IrType::I64);
                        }
                        "Ref" => {
                            // Ref<T> → const T* if T is @:cstruct, else const void*
                            let c_type = if let Some(inner_tid) = type_args.first() {
                                let inner = self.cstruct_ptr_c_type(*inner_tid, dep_cdefs);
                                if inner.ends_with('*') {
                                    format!("const {}", inner)
                                } else {
                                    format!("const {}*", inner)
                                }
                            } else {
                                "const void*".to_string()
                            };
                            return (8, 8, c_type, IrType::I64);
                        }
                        "Box" => {
                            // Box<T> → T* (owned pointer)
                            let c_type = if let Some(inner_tid) = type_args.first() {
                                self.cstruct_ptr_c_type(*inner_tid, dep_cdefs)
                            } else {
                                "void*".to_string()
                            };
                            return (8, 8, c_type, IrType::I64);
                        }
                        "Usize" => {
                            return (8, 8, "size_t".to_string(), IrType::I64);
                        }
                        "CString" => {
                            return (8, 8, "char*".to_string(), IrType::I64);
                        }
                        _ => {} // Fall through to IR-based matching
                    }
                }
                // Class types: check for CString or nested @:cstruct
                TypeKind::Class { symbol_id, .. } => {
                    // Check if this is CString (extern abstract stored as Class)
                    if let Some(sym) = self.symbol_table.get_symbol(*symbol_id) {
                        let is_cstring = sym
                            .qualified_name
                            .and_then(|n| self.string_interner.get(n))
                            .map(|s| s == "rayzor.CString")
                            .unwrap_or(false);
                        if is_cstring {
                            return (8, 8, "char*".to_string(), IrType::I64);
                        }
                    }

                    let is_nested_cstruct = self
                        .symbol_table
                        .get_symbol(*symbol_id)
                        .map(|s| s.flags.is_cstruct())
                        .unwrap_or(false);
                    if is_nested_cstruct {
                        // Recursively compute nested layout
                        if let Some(nested_layout) =
                            self.get_or_compute_cstruct_layout(haxe_type_id)
                        {
                            // Add nested cdef as dependency (if not already present)
                            if !dep_cdefs.contains(&nested_layout.cdef_string) {
                                // Add nested deps first (transitive)
                                for dep in &nested_layout.dep_cdefs {
                                    if !dep_cdefs.contains(dep) {
                                        dep_cdefs.push(dep.clone());
                                    }
                                }
                                // Then add nested struct's own typedef
                                let own_cdef = {
                                    let mut s = format!("typedef struct {{ ");
                                    for f in &nested_layout.fields {
                                        s.push_str(&format!("{} {}; ", f.c_type, f.name));
                                    }
                                    s.push_str(&format!("}} {};\n", nested_layout.c_name));
                                    s
                                };
                                if !dep_cdefs.contains(&own_cdef) {
                                    dep_cdefs.push(own_cdef);
                                }
                            }
                            let c_type = nested_layout.c_name.clone();
                            let size = nested_layout.total_size;
                            let align = nested_layout.alignment;
                            // Nested cstruct is embedded inline — IR type is a byte array
                            return (size, align, c_type, IrType::I64);
                        }
                    }
                }
                _ => {}
            }
        }

        // Fallback: use IR type for primitives
        match &ir_type {
            IrType::F64 => (8, 8, "double".to_string(), ir_type),
            IrType::I64 => (8, 8, "long".to_string(), ir_type),
            IrType::I32 => (8, 8, "long".to_string(), IrType::I64), // Promote to i64
            IrType::Bool => (4, 4, "int".to_string(), ir_type),
            _ => (8, 8, "long".to_string(), ir_type),
        }
    }

    /// Get the C type string for a pointer target type.
    /// If target is @:cstruct, returns "StructName*"; otherwise "void*".
    /// For pointers, we only need the target struct's name, not its full layout,
    /// which avoids infinite recursion for self-referential types like `Ptr<Node>`.
    fn cstruct_ptr_c_type(
        &mut self,
        target_type_id: TypeId,
        dep_cdefs: &mut Vec<String>,
    ) -> String {
        let target_info = {
            let type_table = self.type_table.borrow();
            type_table.get(target_type_id).map(|t| t.kind.clone())
        };
        if let Some(TypeKind::Class { symbol_id, .. }) = target_info {
            let is_cstruct = self
                .symbol_table
                .get_symbol(symbol_id)
                .map(|s| s.flags.is_cstruct())
                .unwrap_or(false);
            if is_cstruct {
                // Get the C name without computing full layout (avoids infinite recursion)
                let no_mangle = self
                    .symbol_table
                    .get_symbol(symbol_id)
                    .map(|s| s.flags.is_no_mangle())
                    .unwrap_or(false);
                let class_name = self
                    .symbol_table
                    .get_symbol(symbol_id)
                    .and_then(|s| self.string_interner.get(s.name))
                    .map(|s| s.to_string())
                    .unwrap_or_default();
                let c_name = if no_mangle {
                    class_name
                } else {
                    class_name.replace('.', "_")
                };

                // If the layout is already computed, use its deps
                if let Some(layout) = self.cstruct_layouts.get(&target_type_id).cloned() {
                    for dep in &layout.dep_cdefs {
                        if !dep_cdefs.contains(dep) {
                            dep_cdefs.push(dep.clone());
                        }
                    }
                    // Add own typedef as dep
                    let own_cdef = {
                        let mut s = format!("typedef struct {{ ");
                        for f in &layout.fields {
                            s.push_str(&format!("{} {}; ", f.c_type, f.name));
                        }
                        s.push_str(&format!("}} {};\n", layout.c_name));
                        s
                    };
                    if !dep_cdefs.contains(&own_cdef) {
                        dep_cdefs.push(own_cdef);
                    }
                }
                // For pointers, a forward declaration is sufficient in C.
                // The struct name is enough — no need to compute full layout.
                return format!("{}*", c_name);
            }
        }
        "void*".to_string()
    }

    /// Check if a class symbol has the @:gpuStruct flag
    fn is_gpu_struct_class(&self, type_id: TypeId) -> bool {
        let type_table = self.type_table.borrow();
        if let Some(type_info) = type_table.get(type_id) {
            if let Some(symbol_id) = type_info.symbol_id() {
                if let Some(sym) = self.symbol_table.get_symbol(symbol_id) {
                    return sym.flags.is_gpu_struct();
                }
            }
        }
        false
    }

    /// Get or compute the GPU struct layout for a @:gpuStruct class type.
    ///
    /// GPU structs use 4-byte floats (not 8-byte like C doubles), 4-byte ints,
    /// and 4-byte bools. This matches Metal/CUDA/WGSL struct layout conventions.
    fn get_or_compute_gpu_struct_layout(&mut self, type_id: TypeId) -> Option<GpuStructLayout> {
        if let Some(layout) = self.gpu_struct_layouts.get(&type_id) {
            return Some(layout.clone());
        }

        // Look up class info from type table
        let (symbol_id, class_name) = {
            let type_table = self.type_table.borrow();
            let type_info = type_table.get(type_id)?;
            let symbol_id = type_info.symbol_id()?;
            let sym = self.symbol_table.get_symbol(symbol_id)?;
            let name = self.string_interner.get(sym.name)?.to_string();
            (symbol_id, name)
        };

        // Get fields from field_index_map (same approach as cstruct)
        let mut fields_with_index: Vec<(SymbolId, u32)> = Vec::new();
        for (field_sym, (class_ty, idx)) in &self.field_index_map {
            if *class_ty == type_id {
                fields_with_index.push((*field_sym, *idx));
            }
        }
        // Fallback: match by class symbol_id via HirTypeDecl
        if fields_with_index.is_empty() {
            let field_class_tys: std::collections::HashSet<TypeId> =
                self.field_index_map.values().map(|(ty, _)| *ty).collect();
            for candidate_ty in &field_class_tys {
                let is_our_class = self.current_hir_types.iter().any(|(tid, decl)| {
                    if *tid != *candidate_ty {
                        return false;
                    }
                    if let HirTypeDecl::Class(c) = decl {
                        c.symbol_id == symbol_id
                    } else {
                        false
                    }
                });
                if is_our_class {
                    for (field_sym, (class_ty, idx)) in &self.field_index_map {
                        if class_ty == candidate_ty {
                            fields_with_index.push((*field_sym, *idx));
                        }
                    }
                    break;
                }
            }
        }
        fields_with_index.sort_by_key(|(_, idx)| *idx);

        // Use simple class name (last segment) for MSL struct name
        let msl_name = class_name
            .split('.')
            .last()
            .unwrap_or(&class_name)
            .to_string();

        let mut byte_offset: u32 = 0;
        let mut max_align: u32 = 1;
        let mut layout_fields = Vec::new();
        let mut dep_typedefs: Vec<String> = Vec::new();

        for (field_sym_id, _idx) in &fields_with_index {
            let sym = self.symbol_table.get_symbol(*field_sym_id)?;
            let field_name = self.string_interner.get(sym.name)?.to_string();
            let ir_type = self.convert_type(sym.type_id);

            let (size, align, msl_type, gpu_ir_type) =
                self.resolve_gpu_struct_field_type(sym.type_id, ir_type, &mut dep_typedefs);

            // Align offset
            if align > 0 {
                byte_offset = (byte_offset + align - 1) & !(align - 1);
            }
            if align > max_align {
                max_align = align;
            }

            layout_fields.push(GpuStructFieldLayout {
                symbol_id: *field_sym_id,
                name: field_name,
                byte_offset,
                ir_type: gpu_ir_type,
                msl_type,
                size,
            });

            byte_offset += size;
        }

        // Pad total size to alignment
        if max_align > 0 {
            byte_offset = (byte_offset + max_align - 1) & !(max_align - 1);
        }

        // Build MSL typedef string
        let mut msl_typedef = format!("struct {} {{ ", msl_name);
        for f in &layout_fields {
            msl_typedef.push_str(&format!("{} {}; ", f.msl_type, f.name));
        }
        msl_typedef.push_str("};\n");

        let layout = GpuStructLayout {
            fields: layout_fields,
            total_size: byte_offset,
            alignment: max_align,
            msl_name,
            msl_typedef,
            dep_typedefs,
        };

        self.gpu_struct_layouts.insert(type_id, layout.clone());
        Some(layout)
    }

    /// Resolve a field's Haxe type to GPU type info for @:gpuStruct layout.
    ///
    /// Key difference from cstruct: Float → f32 (4 bytes), not f64 (8 bytes).
    /// Returns (size_bytes, alignment, msl_type_string, ir_type).
    fn resolve_gpu_struct_field_type(
        &mut self,
        haxe_type_id: TypeId,
        ir_type: IrType,
        dep_typedefs: &mut Vec<String>,
    ) -> (u32, u32, String, IrType) {
        let type_info = {
            let type_table = self.type_table.borrow();
            type_table.get(haxe_type_id).map(|t| (t.kind.clone(), t.id))
        };

        if let Some((kind, _tid)) = type_info {
            match &kind {
                // Nested @:gpuStruct — embed inline
                TypeKind::Class { symbol_id, .. } => {
                    let is_nested_gpu_struct = self
                        .symbol_table
                        .get_symbol(*symbol_id)
                        .map(|s| s.flags.is_gpu_struct())
                        .unwrap_or(false);
                    if is_nested_gpu_struct {
                        if let Some(nested) = self.get_or_compute_gpu_struct_layout(haxe_type_id) {
                            // Add nested typedef as dependency
                            if !dep_typedefs.contains(&nested.msl_typedef) {
                                for dep in &nested.dep_typedefs {
                                    if !dep_typedefs.contains(dep) {
                                        dep_typedefs.push(dep.clone());
                                    }
                                }
                                dep_typedefs.push(nested.msl_typedef.clone());
                            }
                            let msl_type = nested.msl_name.clone();
                            let size = nested.total_size;
                            let align = nested.alignment;
                            return (size, align, msl_type, IrType::I64);
                        }
                    }
                }
                _ => {}
            }
        }

        // GPU type mapping: Float→f32 (4 bytes), Int→i32 (4 bytes), Bool→u32 (4 bytes)
        match &ir_type {
            IrType::F64 => (4, 4, "float".to_string(), IrType::F32), // Float → GPU f32
            IrType::F32 => (4, 4, "float".to_string(), IrType::F32),
            IrType::I64 => (4, 4, "int".to_string(), IrType::I32), // Int → GPU i32
            IrType::I32 => (4, 4, "int".to_string(), IrType::I32),
            IrType::Bool => (4, 4, "uint".to_string(), IrType::I32), // Bool → GPU u32
            _ => (4, 4, "int".to_string(), IrType::I32),
        }
    }

    /// Register a constructor by qualified name for cross-file resolution
    /// This is critical when the TypeId differs between files (e.g., loading StringIteratorUnicode
    /// as a dependency gives it a different TypeId than when StringTools.hx references it)
    fn register_constructor_by_name(&mut self, class_symbol: SymbolId, func_id: IrFunctionId) {
        if let Some(sym_info) = self.symbol_table.get_symbol(class_symbol) {
            if let Some(qual_name) = sym_info
                .qualified_name
                .and_then(|q| self.string_interner.get(q))
            {
                self.constructor_name_map
                    .insert(qual_name.to_string(), func_id);
            } else if let Some(name) = self.string_interner.get(sym_info.name) {
                // Fallback to simple name if no qualified name
                self.constructor_name_map.insert(name.to_string(), func_id);
            }
        }
    }

    /// Extract SSA optimization hints from HIR module metadata
    /// This queries the hints that were previously extracted from DFG/SSA during HIR lowering
    fn extract_ssa_hints_from_hir(&mut self, hir_module: &HirModule) {
        for (symbol_id, func) in &hir_module.functions {
            // Parse optimization hints from function metadata
            for attr in &func.metadata {
                let attr_name = attr.name.to_string();
                match attr_name.as_str() {
                    "inline_candidate" => {
                        self.ssa_hints.inline_candidates.insert(*symbol_id);
                    }
                    "optimization_hint" => {
                        // Check the hint value
                        if let Some(HirAttributeArg::Literal(HirLiteral::String(hint))) =
                            attr.args.first()
                        {
                            match hint.to_string().as_str() {
                                "straight_line_code" => {
                                    self.ssa_hints.straight_line_functions.insert(*symbol_id);
                                }
                                "complex_control_flow" => {
                                    self.ssa_hints
                                        .complex_control_flow_functions
                                        .insert(*symbol_id);
                                }
                                "common_subexpressions" => {
                                    self.ssa_hints.cse_opportunities.insert(*symbol_id);
                                }
                                _ => {}
                            }
                        }
                    }
                    _ => {}
                }
            }
        }
    }

    /// Lower a HIR module to MIR
    pub fn lower_module(&mut self, hir_module: &HirModule) -> Result<IrModule, Vec<LoweringError>> {
        // Extract SSA optimization hints from HIR metadata
        // These were populated during HIR lowering by querying DFG/SSA
        self.extract_ssa_hints_from_hir(hir_module);

        // Set module metadata
        self.builder.module.metadata.language_version =
            hir_module.metadata.language_version.clone();

        // IMPORTANT: Register type metadata FIRST before lowering any functions
        // This populates field_index_map which is needed for field access
        // Two-pass: register interfaces first so interface_method_names is populated
        // before classes try to build vtables.
        // Topological sort: parent interfaces must be registered before children
        // so inherited methods are available when building child method tables.
        {
            let interfaces: Vec<(TypeId, &HirTypeDecl)> = hir_module
                .types
                .iter()
                .filter(|(_, td)| matches!(td, HirTypeDecl::Interface(_)))
                .map(|(tid, td)| (*tid, td))
                .collect();

            let mut registered: std::collections::HashSet<TypeId> =
                std::collections::HashSet::new();
            let mut remaining = interfaces.clone();
            let max_iterations = remaining.len() + 1;
            let mut iteration = 0;
            while !remaining.is_empty() && iteration < max_iterations {
                iteration += 1;
                let mut next_remaining = Vec::new();
                for (type_id, type_decl) in remaining {
                    if let HirTypeDecl::Interface(iface) = type_decl {
                        let parents_ready = iface
                            .extends
                            .iter()
                            .all(|parent_tid| registered.contains(parent_tid));
                        if parents_ready {
                            self.register_type_metadata(type_id, type_decl);
                            registered.insert(type_id);
                        } else {
                            next_remaining.push((type_id, type_decl));
                        }
                    }
                }
                remaining = next_remaining;
            }
            // Register any remaining interfaces (handles cycles gracefully)
            for (type_id, type_decl) in remaining {
                self.register_type_metadata(type_id, type_decl);
            }
        }
        for (type_id, type_decl) in &hir_module.types {
            if !matches!(type_decl, HirTypeDecl::Interface(_)) {
                self.register_type_metadata(*type_id, type_decl);
            }
        }

        // Build class vtables after all type metadata is registered
        self.build_class_vtables();

        // CRITICAL: Two-pass lowering to avoid non-deterministic function ordering issues
        // HashMap iteration over hir_module.types is random, so class methods might be
        // lowered after module functions that call them, causing "function not found" errors.
        //
        // Pass 1: Register ALL function signatures WITHOUT lowering bodies
        // This ensures function_map is fully populated before any calls are made

        // Pass 1a: Register class method signatures
        for (type_id, type_decl) in &hir_module.types {
            match type_decl {
                HirTypeDecl::Class(class) => {
                    // eprintln!(
                    //     "DEBUG Pass1a: Registering methods for class {:?}",
                    //     self.string_interner.get(class.name).unwrap_or("<unknown>")
                    // );
                    for method in &class.methods {
                        let this_type = if !method.is_static {
                            Some(*type_id)
                        } else {
                            None
                        };
                        // Pass class type params for generic class methods
                        self.register_function_signature_with_class_type_params(
                            method.function.symbol_id,
                            &method.function,
                            this_type,
                            &class.type_params,
                        );
                    }

                    // Register constructor signature with class type params
                    if let Some(constructor) = &class.constructor {
                        self.register_constructor_signature_with_class_type_params(
                            class.symbol_id,
                            constructor,
                            *type_id,
                            &class.type_params,
                        );
                    }
                }
                HirTypeDecl::Abstract(abstract_decl) => {
                    // Register abstract method signatures — same as classes but
                    // this_type uses the underlying type (value, not pointer)
                    for method in &abstract_decl.methods {
                        let this_type = if !method.is_static {
                            Some(abstract_decl.underlying)
                        } else {
                            None
                        };
                        self.register_function_signature_with_class_type_params(
                            method.function.symbol_id,
                            &method.function,
                            this_type,
                            &abstract_decl.type_params,
                        );
                    }
                }
                _ => {}
            }
        }

        // Pass 1b: Register module function signatures
        for (symbol_id, hir_func) in &hir_module.functions {
            self.register_function_signature(*symbol_id, hir_func, None);
        }

        // Pass 2: Now lower all function bodies (both class methods and module functions)
        // At this point, function_map is fully populated

        // Pass 2a: Lower class methods and constructors
        for (type_id, type_decl) in &hir_module.types {
            let name_str = if let HirTypeDecl::Class(c) = type_decl {
                let n = self.string_interner.get(c.name).unwrap_or("<unknown>");
                n
            } else {
                "<not-a-class>"
            };
            // debug!("Pass2a: Processing type - TypeId={:?}, name={:?}", type_id, name_str);
            match type_decl {
                HirTypeDecl::Class(class) => {
                    // Get qualified class name for runtime mapping checks
                    // Prefer lowered @:native name (e.g., "rayzor::concurrent::Arc" -> "rayzor_concurrent_Arc")
                    // Fall back to qualified_name with underscores (e.g., "rayzor.Bytes" -> "rayzor_Bytes")
                    let qualified_class_name = self
                        .symbol_table
                        .get_symbol(class.symbol_id)
                        .and_then(|sym| {
                            // Prefer native name if available
                            if let Some(native) = sym.native_name {
                                self.string_interner
                                    .get(native)
                                    .map(|n| n.replace("::", "_"))
                            } else {
                                sym.qualified_name
                                    .and_then(|qn| self.string_interner.get(qn))
                                    .map(|qn| qn.replace(".", "_"))
                            }
                        });

                    // Fallback to simple class name if no qualified name
                    let class_name = self.string_interner.get(class.name);

                    // Lower each method body
                    for method in &class.methods {
                        // SPECIAL CASE: Skip lowering method if this is an extern class
                        // with a runtime mapping for this method. For extern classes like FileSystem,
                        // methods are handled by the runtime mapping system, not by MIR stubs.
                        let should_skip_method = if method.function.body.is_none() {
                            // Method has no body - check if it has a runtime mapping
                            // Try qualified name first (e.g., "rayzor_Bytes"), then fall back to simple name
                            let has_mapping = if let Some(method_name) =
                                self.string_interner.get(method.function.name)
                            {
                                // Try qualified name first
                                let found_in_qualified = qualified_class_name
                                    .as_ref()
                                    .map(|qn| {
                                        self.stdlib_mapping.has_mapping(
                                            qn,
                                            method_name,
                                            method.is_static,
                                        )
                                    })
                                    .unwrap_or(false);

                                if found_in_qualified {
                                    true
                                } else if let Some(class_name_str) = class_name {
                                    // Fall back to simple class name (e.g., "FileSystem" instead of "sys_FileSystem")
                                    self.stdlib_mapping.has_mapping(
                                        class_name_str,
                                        method_name,
                                        method.is_static,
                                    )
                                } else {
                                    false
                                }
                            } else {
                                false
                            };

                            // Also skip if this is an extern class - extern classes have
                            // their methods handled by runtime mappings or MIR wrappers
                            let is_extern_class = self
                                .symbol_table
                                .get_symbol(class.symbol_id)
                                .map(|sym| {
                                    sym.flags
                                        .contains(crate::tast::symbols::SymbolFlags::EXTERN)
                                })
                                .unwrap_or(false);

                            has_mapping || is_extern_class
                        } else {
                            false
                        };

                        if should_skip_method {
                            continue;
                        }

                        // Skip synthetic methods on @:cstruct / @:gpuStruct — handled at call site
                        {
                            let has_no_body = method.function.body.is_none()
                                || method
                                    .function
                                    .body
                                    .as_ref()
                                    .map(|b| b.statements.is_empty())
                                    .unwrap_or(false);
                            if has_no_body {
                                if let Some(method_name) =
                                    self.string_interner.get(method.function.name)
                                {
                                    if method_name == "cdef" {
                                        let is_cstruct = self
                                            .symbol_table
                                            .get_symbol(class.symbol_id)
                                            .map(|sym| sym.flags.is_cstruct())
                                            .unwrap_or(false);
                                        if is_cstruct {
                                            self.get_or_compute_cstruct_layout(*type_id);
                                            continue;
                                        }
                                    }
                                    if matches!(method_name, "gpuDef" | "gpuSize" | "gpuAlignment")
                                    {
                                        let is_gpu_struct = self
                                            .symbol_table
                                            .get_symbol(class.symbol_id)
                                            .map(|sym| sym.flags.is_gpu_struct())
                                            .unwrap_or(false);
                                        if is_gpu_struct {
                                            self.get_or_compute_gpu_struct_layout(*type_id);
                                            continue;
                                        }
                                    }
                                }
                            }
                        }

                        if method.is_static {
                            self.lower_function_body(
                                method.function.symbol_id,
                                &method.function,
                                None,
                            );
                        } else {
                            self.lower_function_body(
                                method.function.symbol_id,
                                &method.function,
                                Some(*type_id),
                            );
                        }
                    }

                    // Lower constructor body
                    if let Some(constructor) = &class.constructor {
                        // SPECIAL CASE: Skip lowering constructor if this is an extern class
                        // with a runtime mapping for "new". For extern classes like Channel, Thread, etc.,
                        // the "new" constructor is handled by the runtime mapping system, not by
                        // generating a MIR constructor function.
                        // Try qualified class name first (e.g., "rayzor_Bytes"), then fall back to simple name
                        let should_skip_constructor = {
                            // Helper to check runtime mapping for a class name
                            let check_class_runtime = |name: &str| -> bool {
                                if let Some(class_name_static) =
                                    self.stdlib_mapping.get_class_static_str(name)
                                {
                                    let method_sig =
                                        crate::stdlib::runtime_mapping::MethodSignature {
                                            class: class_name_static,
                                            method: "new",
                                            is_static: true,
                                            is_constructor: true,
                                            param_count: 0,
                                        };
                                    if self.stdlib_mapping.get(&method_sig).is_some() {
                                        debug!(
                                            "Skipping constructor lowering for extern class '{}' - using runtime mapping",
                                            name
                                        );
                                        return true;
                                    }
                                }
                                false
                            };

                            // Try qualified name first, then fall back to simple name
                            let found_in_qualified = qualified_class_name
                                .as_ref()
                                .map(|qn| check_class_runtime(qn))
                                .unwrap_or(false);

                            if found_in_qualified {
                                true
                            } else if let Some(class_name_str) = class_name {
                                // Fallback to simple class name (e.g., "Thread" instead of "rayzor_concurrent_Thread")
                                if check_class_runtime(class_name_str) {
                                    true
                                } else {
                                    // Also skip if this is an extern class (using TAST flags)
                                    self.symbol_table
                                        .get_symbol(class.symbol_id)
                                        .map(|sym| {
                                            sym.flags
                                                .contains(crate::tast::symbols::SymbolFlags::EXTERN)
                                        })
                                        .unwrap_or(false)
                                }
                            } else {
                                false
                            }
                        };

                        if !should_skip_constructor {
                            // debug!("Lowering constructor for class {:?}", class.name);
                            self.lower_constructor_body(
                                class.symbol_id,
                                constructor,
                                *type_id,
                                class.extends,
                            );
                        }
                    }
                }
                HirTypeDecl::Abstract(abstract_decl) => {
                    // Lower abstract method bodies — same as classes but
                    // this_type uses the underlying type (value, not pointer)
                    for method in &abstract_decl.methods {
                        if method.function.body.is_none() {
                            continue; // Skip extern abstract methods
                        }
                        let this_type = if !method.is_static {
                            Some(abstract_decl.underlying)
                        } else {
                            None
                        };
                        self.lower_function_body(
                            method.function.symbol_id,
                            &method.function,
                            this_type,
                        );
                    }
                }
                _ => {}
            }
        }

        // Pass 2b: Lower module function bodies
        for (symbol_id, hir_func) in &hir_module.functions {
            self.lower_function_body(*symbol_id, hir_func, None);
        }

        // Lower globals
        for (symbol_id, global) in &hir_module.globals {
            self.lower_global(*symbol_id, global);
        }

        // Generate reflective constructor wrappers for Type.createInstance().
        self.generate_constructor_reflect_wrappers();

        // Generate __vtable_init__ function for class virtual dispatch tables
        if !self.class_vtables.is_empty() || !self.constructor_reflect_wrappers.is_empty() {
            self.generate_vtable_init_function();
        }

        // Generate __init__ function for dynamic global initialization
        if !self.dynamic_globals.is_empty() {
            self.generate_module_init_function();
        }

        if self.errors.is_empty() {
            // eprintln!(
            //     "  ℹ️  Returning MIR module with {} functions, {} extern_functions",
            //     self.builder.module.functions.len(),
            //     self.builder.module.extern_functions.len()
            // );

            Ok(std::mem::replace(
                &mut self.builder.module,
                IrModule::new(String::new(), String::new()),
            ))
        } else {
            Err(std::mem::take(&mut self.errors))
        }
    }

    /// Register a function signature without lowering the body (Pass 1)
    /// This creates the function stub and adds it to function_map
    fn register_function_signature(
        &mut self,
        symbol_id: SymbolId,
        hir_func: &HirFunction,
        this_type: Option<TypeId>,
    ) {
        let mut signature = self.build_function_signature(hir_func);

        // For instance methods, add implicit 'this' parameter
        // 'this' is always a pointer to the class instance, regardless of generic parameters
        if let Some(type_id) = this_type {
            let this_type = match self.convert_type(type_id) {
                IrType::Ptr(_) => IrType::Ptr(Box::new(IrType::Void)),
                // If convert_type failed to resolve (e.g., generic class without instantiation),
                // default to pointer since 'this' is always a pointer to instance
                _ => IrType::Ptr(Box::new(IrType::Void)),
            };
            signature.parameters.insert(
                0,
                IrParameter {
                    name: "this".to_string(),
                    ty: this_type,
                    reg: IrId::new(0), // Will be properly assigned when body is lowered
                    by_ref: false,
                },
            );
        }

        let func_name = self
            .string_interner
            .get(hir_func.name)
            .map(|s| s.to_string())
            .unwrap_or_else(|| format!("func_{}", symbol_id.as_raw()));

        let func_id = self.builder.start_function(symbol_id, func_name, signature);
        self.function_map.insert(symbol_id, func_id);

        if hir_func.is_keep {
            if let Some(func) = self.builder.module.functions.get_mut(&func_id) {
                func.attributes
                    .custom
                    .insert("keep".to_string(), "true".to_string());
            }
        }

        // Store default parameter expressions for call-site filling
        let defaults: Vec<Option<HirExpr>> =
            hir_func.params.iter().map(|p| p.default.clone()).collect();
        if defaults.iter().any(|d| d.is_some()) {
            self.function_param_defaults.insert(func_id, defaults);
        }

        // Store parameter HIR types for structural subtyping materialization at call sites
        let param_types: Vec<TypeId> = hir_func.params.iter().map(|p| p.ty).collect();
        self.function_param_hir_types.insert(func_id, param_types);

        // Record constrained type parameter info for call-site fat pointer wrapping
        self.record_constrained_params(func_id, hir_func, this_type.is_some());

        // Respect Haxe `inline` keyword — always inline these functions
        if hir_func.is_inline {
            if let Some(func) = self.builder.module.functions.get_mut(&func_id) {
                func.attributes.inline = super::InlineHint::Always;
            }
        }

        self.builder.finish_function(); // Close to allow next function to start
    }

    /// Register a function signature with class type parameters (for generic class methods)
    /// This version includes the class's type parameters in the function signature
    fn register_function_signature_with_class_type_params(
        &mut self,
        symbol_id: SymbolId,
        hir_func: &HirFunction,
        this_type: Option<TypeId>,
        class_type_params: &[HirTypeParam],
    ) {
        let mut signature =
            self.build_function_signature_with_class_type_params(hir_func, class_type_params);

        // For instance methods, add implicit 'this' parameter
        if let Some(type_id) = this_type {
            // Check the actual HIR TypeKind to distinguish abstracts from classes.
            // convert_type() can misresolve class types to I32 in cross-module
            // compilation when the type table entry is missing. Use TypeKind directly.
            let is_abstract_value_type = {
                let type_table = self.type_table.borrow();
                match type_table.get(type_id).map(|t| &t.kind) {
                    Some(crate::tast::TypeKind::Abstract {
                        underlying: Some(u),
                        ..
                    }) => {
                        let u_ty = self.convert_type(*u);
                        matches!(
                            u_ty,
                            IrType::I8
                                | IrType::I16
                                | IrType::I32
                                | IrType::I64
                                | IrType::U8
                                | IrType::U16
                                | IrType::U32
                                | IrType::U64
                                | IrType::F32
                                | IrType::F64
                                | IrType::Bool
                        )
                    }
                    _ => false, // Classes, interfaces, etc. always use pointer
                }
            };
            let this_ir_type = if is_abstract_value_type {
                self.convert_type(type_id) // Raw value type for abstract underlying types
            } else {
                IrType::Ptr(Box::new(IrType::Void)) // Heap pointer for classes
            };
            signature.parameters.insert(
                0,
                IrParameter {
                    name: "this".to_string(),
                    ty: this_ir_type,
                    reg: IrId::new(0),
                    by_ref: false,
                },
            );
        }

        let func_name = self
            .string_interner
            .get(hir_func.name)
            .map(|s| s.to_string())
            .unwrap_or_else(|| format!("func_{}", symbol_id.as_raw()));

        let func_id = self.builder.start_function(symbol_id, func_name, signature);
        self.function_map.insert(symbol_id, func_id);

        if hir_func.is_keep {
            if let Some(func) = self.builder.module.functions.get_mut(&func_id) {
                func.attributes
                    .custom
                    .insert("keep".to_string(), "true".to_string());
            }
        }

        // Store default parameter expressions for call-site filling
        let defaults: Vec<Option<HirExpr>> =
            hir_func.params.iter().map(|p| p.default.clone()).collect();
        if defaults.iter().any(|d| d.is_some()) {
            self.function_param_defaults.insert(func_id, defaults);
        }

        // Store parameter HIR types for structural subtyping materialization at call sites
        let param_types: Vec<TypeId> = hir_func.params.iter().map(|p| p.ty).collect();
        self.function_param_hir_types.insert(func_id, param_types);

        // Record constrained type parameter info for call-site fat pointer wrapping
        self.record_constrained_params(func_id, hir_func, this_type.is_some());

        // Respect Haxe `inline` keyword — always inline these functions
        if hir_func.is_inline {
            if let Some(func) = self.builder.module.functions.get_mut(&func_id) {
                func.attributes.inline = super::InlineHint::Always;
            }
        }

        self.builder.finish_function();
    }

    /// Register constructor signature with class type params (for generic classes)
    fn register_constructor_signature_with_class_type_params(
        &mut self,
        class_symbol: SymbolId,
        constructor: &HirConstructor,
        type_id: TypeId,
        class_type_params: &[HirTypeParam],
    ) {
        let this_type = match self.convert_type(type_id) {
            IrType::Ptr(_) => IrType::Ptr(Box::new(IrType::Void)),
            _ => IrType::Ptr(Box::new(IrType::Void)),
        };
        let mut sig_builder = FunctionSignatureBuilder::new().param("this".to_string(), this_type);

        // Add class type parameters
        for type_param in class_type_params {
            let param_name = self
                .string_interner
                .get(type_param.name)
                .map(|s| s.to_string())
                .unwrap_or_else(|| format!("T{}", type_param.name.as_raw()));
            sig_builder = sig_builder.type_param(param_name);
        }

        // Add constructor parameters
        for param in &constructor.params {
            let param_name = self
                .string_interner
                .get(param.name)
                .map(|s| s.to_string())
                .unwrap_or_else(|| format!("param_{}", param.symbol_id.as_raw()));
            sig_builder = sig_builder.param(param_name, self.convert_type(param.ty));
        }

        let mut signature = sig_builder.returns(IrType::Void).build();

        // Assign register IDs
        for (i, param) in signature.parameters.iter_mut().enumerate() {
            param.reg = IrId::new(i as u32);
        }

        let func_id = self
            .builder
            .start_function(class_symbol, "new".to_string(), signature);
        self.function_map.insert(class_symbol, func_id);
        self.constructor_map.insert(type_id, func_id);
        self.register_constructor_by_name(class_symbol, func_id);

        // Store default parameter expressions for call-site filling
        let defaults: Vec<Option<HirExpr>> = constructor
            .params
            .iter()
            .map(|p| p.default.clone())
            .collect();
        if defaults.iter().any(|d| d.is_some()) {
            self.function_param_defaults.insert(func_id, defaults);
        }

        // Store parameter HIR types for structural subtyping materialization at call sites
        let param_types: Vec<TypeId> = constructor.params.iter().map(|p| p.ty).collect();
        self.function_param_hir_types.insert(func_id, param_types);

        let fallback_type_id = TypeId::from_raw(class_symbol.as_raw());
        if fallback_type_id != type_id {
            self.constructor_map.insert(fallback_type_id, func_id);
        }

        self.builder.finish_function();
    }

    /// Register constructor signature (Pass 1)
    fn register_constructor_signature(
        &mut self,
        class_symbol: SymbolId,
        constructor: &HirConstructor,
        type_id: TypeId,
    ) {
        // Constructor signature: takes implicit 'this' parameter + constructor params, returns void
        // 'this' is always a pointer to the class instance, regardless of generic parameters
        let this_type = match self.convert_type(type_id) {
            IrType::Ptr(_) => IrType::Ptr(Box::new(IrType::Void)),
            // If convert_type failed to resolve (e.g., generic class without instantiation),
            // default to pointer since 'this' is always a pointer to instance
            _ => IrType::Ptr(Box::new(IrType::Void)),
        };
        let mut sig_builder = FunctionSignatureBuilder::new().param("this".to_string(), this_type);

        // Add constructor parameters
        for param in &constructor.params {
            let param_name = self
                .string_interner
                .get(param.name)
                .map(|s| s.to_string())
                .unwrap_or_else(|| format!("param_{}", param.symbol_id.as_raw()));
            sig_builder = sig_builder.param(param_name, self.convert_type(param.ty));
        }

        let mut signature = sig_builder.returns(IrType::Void).build();

        // Assign register IDs to parameters
        for (i, param) in signature.parameters.iter_mut().enumerate() {
            param.reg = IrId::new(i as u32);
        }

        let func_id = self
            .builder
            .start_function(class_symbol, "new".to_string(), signature);
        self.function_map.insert(class_symbol, func_id);
        self.constructor_map.insert(type_id, func_id);
        self.register_constructor_by_name(class_symbol, func_id);

        // Store default parameter expressions for call-site filling
        let defaults: Vec<Option<HirExpr>> = constructor
            .params
            .iter()
            .map(|p| p.default.clone())
            .collect();
        if defaults.iter().any(|d| d.is_some()) {
            self.function_param_defaults.insert(func_id, defaults);
        }

        // Store parameter HIR types for structural subtyping materialization at call sites
        let param_types: Vec<TypeId> = constructor.params.iter().map(|p| p.ty).collect();
        self.function_param_hir_types.insert(func_id, param_types);

        // Also register with TypeId derived from class SymbolId as a fallback
        let fallback_type_id = TypeId::from_raw(class_symbol.as_raw());
        if fallback_type_id != type_id {
            self.constructor_map.insert(fallback_type_id, func_id);
        }

        self.builder.finish_function(); // Close the stub
    }

    /// Lower a function body after signature is registered (Pass 2)
    /// Reuses the existing function created in Pass 1
    fn lower_function_body(
        &mut self,
        symbol_id: SymbolId,
        hir_func: &HirFunction,
        this_type: Option<TypeId>,
    ) {
        // The function already exists from Pass 1, we just need to fill in the body
        let func_id = self
            .function_map
            .get(&symbol_id)
            .copied()
            .expect("Function should have been registered in Pass 1");

        // Re-open the function for body lowering
        let func = self
            .builder
            .module
            .functions
            .get(&func_id)
            .expect("Function should exist")
            .clone();

        self.builder.current_function = Some(func_id);
        self.builder.current_block = Some(func.entry_block());
        self.current_function_symbol = Some(symbol_id);

        // Set qualified name for stack traces.
        // hir_func.qualified_name is built by build_qualified_name() during TAST lowering
        // and includes the class prefix, e.g. "Main.thrower".
        if let Some(qname_id) = hir_func.qualified_name {
            if let Some(qname_str) = self.string_interner.get(qname_id) {
                let qname = qname_str.to_string();
                if let Some(func_mut) = self.builder.module.functions.get_mut(&func_id) {
                    func_mut.qualified_name = Some(qname);
                }
            }
        } else if let Some(func_mut) = self.builder.module.functions.get_mut(&func_id) {
            // Fallback: build Class.method from this_type or current_module
            if let Some(class_type) = this_type {
                if let Some(class_name) = self
                    .class_type_to_symbol
                    .get(&class_type)
                    .and_then(|&sym| self.symbol_table.get_symbol(sym))
                    .and_then(|s| {
                        s.qualified_name
                            .and_then(|n| self.string_interner.get(n))
                            .or_else(|| self.string_interner.get(s.name))
                    })
                {
                    func_mut.qualified_name = Some(format!("{}.{}", class_name, func_mut.name));
                }
            } else if let Some(module_name) =
                self.current_module.as_deref().filter(|m| !m.is_empty())
            {
                let bare = func_mut.name.clone();
                func_mut.qualified_name = Some(format!("{}.{}", module_name, bare));
            }
        }

        // Set source location from HIR function (propagated from TAST TypedFunction.source_location).
        {
            let loc = hir_func.source_location;
            if loc.is_valid() && loc.line > 0 {
                if let Some(func_mut) = self.builder.module.functions.get_mut(&func_id) {
                    func_mut.source_location = IrSourceLocation {
                        file_id: loc.file_id,
                        line: loc.line,
                        column: loc.column,
                    };
                }
            }
        }

        // Clear per-function drop tracking state
        // Note: We track owned heap values to free them on reassignment (Rust-style drop)
        // This handles the main memory leak case: loop iterations creating new objects
        self.owned_heap_values.clear();
        self.drop_scope_stack.clear();
        self.temp_heap_values.clear();
        self.reassigned_in_scope.clear();

        // Run drop point analysis on the function body to find last-use points
        // This enables precise drop insertion at the exact point a variable is no longer used
        if let Some(body) = &hir_func.body {
            let mut analyzer = DropPointAnalyzer::new();
            self.current_drop_points = Some(analyzer.analyze_function(body));
            self.current_stmt_index = 0;
            trace!(
                "Drop analysis: Found {} heap variables, {} escaping",
                self.current_drop_points
                    .as_ref()
                    .map(|dp| dp.heap_allocated.len())
                    .unwrap_or(0),
                self.current_drop_points
                    .as_ref()
                    .map(|dp| dp.escaping.len())
                    .unwrap_or(0)
            );
        } else {
            self.current_drop_points = None;
            self.current_stmt_index = 0;
        }

        // Set current_this_type for implicit field access resolution
        self.current_this_type = this_type;

        // Track return type for Null<T> boxing in Return handler
        self.current_function_return_type = Some(hir_func.return_type);

        // Map 'this' parameter for instance methods
        if this_type.is_some() {
            // 'this' is parameter 0
            if let Some(this_param) = func.signature.parameters.get(0) {
                // Map 'this' to a special symbol ID (SymbolId(0))
                // This is what HirExprKind::This looks up
                self.symbol_map
                    .insert(SymbolId::from_raw(0), this_param.reg);
            }
        }

        // Map parameters from the function signature (which already has register IDs assigned)
        let param_offset = if this_type.is_some() { 1 } else { 0 };
        for (i, param) in hir_func.params.iter().enumerate() {
            if let Some(sig_param) = func.signature.parameters.get(i + param_offset) {
                self.symbol_map.insert(param.symbol_id, sig_param.reg);
            }
        }

        // Lower body
        let func_name = self
            .string_interner
            .get(hir_func.name)
            .unwrap_or("?")
            .to_string();

        // @:async function transform: wrap body in a closure and return Future handle
        if hir_func.is_async {
            if let Some(body) = &hir_func.body {
                self.lower_async_function_body(func_id, hir_func, body, &func_name);
            } else {
                self.ensure_terminator();
            }
        } else if let Some(body) = &hir_func.body {
            debug!(
                "[lower_function_body]: {} has body with {} statements, expr: {}",
                func_name,
                body.statements.len(),
                body.expr.is_some()
            );
            for (i, stmt) in body.statements.iter().enumerate() {
                debug!(
                    "[lower_function_body]: {} - stmt[{}] = {:?}",
                    func_name,
                    i,
                    std::mem::discriminant(stmt)
                );
            }
            // Enter function-level scope for variables declared at function level
            // This ensures they're freed on function exit via cleanup_all_scopes()
            self.enter_drop_scope();
            self.lower_block(body);
            // For functions that don't explicitly return (void functions without `return`),
            // emit drop() calls for @:derive(Drop) owned values before the implicit return.
            // Note: Functions WITH explicit return handle this in the Return statement handler.
            // We DON'T call cleanup_all_scopes() here because non-Drop allocations are
            // handled by InsertFreePass — calling free unconditionally would cause double-free.
            // Instead, we only emit drop() + free for Drop-class values specifically.
            if !self.is_terminated() && !self.derive_drop_classes.is_empty() {
                self.cleanup_drop_classes_only();
            }
            self.ensure_terminator();
        } else {
            debug!("[lower_function_body]: {} has NO body", func_name);
            // Functions without body (extern, abstract) still need a terminator
            self.ensure_terminator();
        }

        self.builder.finish_function();
        // debug!("  Function finished, context cleared");

        self.symbol_map.clear();
        self.block_map.clear();
        self.current_this_type = None;
    }

    /// Ensure Future runtime extern functions are declared in the current module.
    /// Returns (create_id, await_id, poll_id, is_ready_id).
    fn ensure_future_externs(
        &mut self,
    ) -> (IrFunctionId, IrFunctionId, IrFunctionId, IrFunctionId) {
        use crate::ir::modules::IrExternFunction;

        let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));

        let externs_to_declare: Vec<(&str, Vec<IrType>, IrType)> = vec![
            (
                "rayzor_future_create",
                vec![ptr_u8.clone(), ptr_u8.clone()],
                ptr_u8.clone(),
            ),
            ("rayzor_future_await", vec![ptr_u8.clone()], ptr_u8.clone()),
            ("rayzor_future_poll", vec![ptr_u8.clone()], ptr_u8.clone()),
            ("rayzor_future_is_ready", vec![ptr_u8.clone()], IrType::Bool),
        ];

        let mut ids = Vec::new();
        for (name, params, ret) in externs_to_declare {
            // Check if already declared
            let existing = self
                .builder
                .module
                .extern_functions
                .iter()
                .find(|(_, f)| f.name == name)
                .map(|(id, _)| *id);
            if let Some(id) = existing {
                ids.push(id);
                continue;
            }
            // Declare it
            let id = self.builder.module.alloc_function_id();
            let sig = crate::ir::IrFunctionSignature {
                parameters: params
                    .into_iter()
                    .enumerate()
                    .map(|(i, ty)| crate::ir::functions::IrParameter {
                        name: format!("p{}", i),
                        ty,
                        reg: IrId(i as u32),
                        by_ref: false,
                    })
                    .collect(),
                return_type: ret,
                calling_convention: crate::ir::CallingConvention::C,
                can_throw: false,
                type_params: Vec::new(),
                uses_sret: false,
            };
            self.builder.module.extern_functions.insert(
                id,
                IrExternFunction {
                    id,
                    name: name.to_string(),
                    symbol_id: SymbolId::from_raw(9999),
                    signature: sig,
                    source: "runtime".to_string(),
                },
            );
            ids.push(id);
        }

        (ids[0], ids[1], ids[2], ids[3])
    }

    /// Lower an @:async function body.
    ///
    /// Transforms the function so that:
    /// 1. The original body becomes an inner closure function (env_ptr -> i32)
    /// 2. The outer function allocates an environment, stores params, and calls
    ///    rayzor_future_create(fn_ptr, env_ptr) to return a lazy Future handle.
    fn lower_async_function_body(
        &mut self,
        func_id: IrFunctionId,
        hir_func: &HirFunction,
        body: &HirBlock,
        func_name: &str,
    ) {
        use crate::ir::hir::{HirCapture, HirCaptureMode, HirExprKind};

        debug!(
            "[lower_async_function_body]: transforming {} to return Future",
            func_name
        );

        // 1. Create captures from function params (the inner closure captures all params)
        let captures: Vec<HirCapture> = hir_func
            .params
            .iter()
            .map(|p| HirCapture {
                symbol: p.symbol_id,
                mode: HirCaptureMode::ByValue,
                ty: p.ty,
            })
            .collect();

        // 2. Generate the inner closure function (async body)
        //    Signature: (env_ptr: *u8) -> i32 (JIT closure convention)
        //    The inner function has NO explicit params — all values are loaded from env.
        let inner_context = self.generate_lambda_skeleton(&[], &captures);
        let inner_func_id = inner_context.func_id;

        // 3. Lower the original body into the inner function
        {
            let saved_state = self.save_state();

            self.builder.current_function = Some(inner_context.func_id);
            self.builder.current_block = Some(inner_context.entry_block);
            self.symbol_map.clear();
            self.current_env_layout = inner_context.env_layout.clone();

            // Clear drop tracking for inner function
            self.owned_heap_values.clear();
            self.drop_scope_stack.clear();
            self.temp_heap_values.clear();
            self.reassigned_in_scope.clear();
            self.current_drop_points = None;
            self.current_stmt_index = 0;

            // Load captured params from environment
            if let Some(layout) = &inner_context.env_layout {
                let env_ptr = IrId::new(0); // First parameter
                for field in &layout.fields {
                    if let Some(value_reg) =
                        layout.load_field(&mut self.builder, env_ptr, field.symbol)
                    {
                        self.symbol_map.insert(field.symbol, value_reg);
                        // Register as local for type inference
                        let param_name = self
                            .string_interner
                            .get(
                                self.symbol_table
                                    .get_symbol(field.symbol)
                                    .map(|s| s.name)
                                    .unwrap_or_default(),
                            )
                            .unwrap_or("<capture>")
                            .to_string();
                        let field_type = field.storage_ty.clone();
                        if let Some(func) = self.builder.current_function_mut() {
                            func.locals.insert(
                                value_reg,
                                super::IrLocal {
                                    name: param_name,
                                    ty: field_type,
                                    mutable: false,
                                    source_location: super::IrSourceLocation::unknown(),
                                    allocation: super::AllocationHint::Register,
                                },
                            );
                        }
                    }
                }
            }

            // Lower the function body
            self.enter_drop_scope();
            self.lower_block(body);
            self.ensure_terminator();

            // Fix up return type: inner closure returns I64 (JIT convention)
            if let Some(inner_func) = self
                .builder
                .module
                .functions
                .get_mut(&inner_context.func_id)
            {
                inner_func.signature.return_type = IrType::I64;
            }

            self.current_env_layout = None;
            self.restore_state(saved_state);
        }

        // 4. Back in the outer function: create closure and call rayzor_future_create
        // Collect captured values (param registers from the outer function's symbol_map)
        let captured_values: Vec<IrId> = hir_func
            .params
            .iter()
            .filter_map(|p| self.symbol_map.get(&p.symbol_id).copied())
            .collect();

        // Create closure object (MakeClosure instruction)
        // MakeClosure allocates struct { fn_ptr: i64, env_ptr: i64 } on heap
        let closure_reg = match self
            .builder
            .build_make_closure(inner_func_id, captured_values)
        {
            Some(r) => r,
            None => {
                self.ensure_terminator();
                return;
            }
        };

        // Extract fn_ptr (offset 0) and env_ptr (offset 8) from closure struct
        let ptr_u8_ty = IrType::Ptr(Box::new(IrType::U8));
        let fn_ptr = match self.builder.build_load(closure_reg, ptr_u8_ty.clone()) {
            Some(r) => r,
            None => {
                self.ensure_terminator();
                return;
            }
        };
        // PtrAdd closure_reg + 8 bytes to get env_ptr field address
        let eight = match self.builder.build_const(IrValue::I64(8)) {
            Some(r) => r,
            None => {
                self.ensure_terminator();
                return;
            }
        };
        let env_field_ptr = match self
            .builder
            .build_ptr_add(closure_reg, eight, ptr_u8_ty.clone())
        {
            Some(r) => r,
            None => {
                self.ensure_terminator();
                return;
            }
        };
        let env_ptr = match self.builder.build_load(env_field_ptr, ptr_u8_ty.clone()) {
            Some(r) => r,
            None => {
                self.ensure_terminator();
                return;
            }
        };

        // Ensure all Future runtime externs are declared in this module
        let (create_id, _await_id, _poll_id, _is_ready_id) = self.ensure_future_externs();

        let ptr_u8_ty = IrType::Ptr(Box::new(IrType::U8));
        if let Some(future_handle) =
            self.builder
                .build_call_direct(create_id, vec![fn_ptr, env_ptr], ptr_u8_ty)
        {
            // Return the future handle
            self.builder.build_return(Some(future_handle));

            // Update the outer function's return type to Ptr(U8) (future handle)
            if let Some(outer_func) = self.builder.module.functions.get_mut(&func_id) {
                outer_func.signature.return_type = IrType::Ptr(Box::new(IrType::U8));
            }
        } else {
            self.ensure_terminator();
        }
    }

    /// Lower constructor body (Pass 2)
    fn lower_constructor_body(
        &mut self,
        class_symbol: SymbolId,
        constructor: &HirConstructor,
        type_id: TypeId,
        parent_type: Option<TypeId>,
    ) {
        let func_id = self
            .constructor_map
            .get(&type_id)
            .copied()
            .expect("Constructor should have been registered in Pass 1");

        let func = self
            .builder
            .module
            .functions
            .get(&func_id)
            .expect("Constructor function should exist")
            .clone();

        self.builder.current_function = Some(func_id);
        self.builder.current_block = Some(func.entry_block());

        // 'this' is parameter 0
        let this_reg = IrId::new(0);

        // Map 'this' to symbol map for field access
        self.symbol_map.insert(SymbolId::from_raw(0), this_reg);

        // Map constructor parameters to registers
        for (i, param) in constructor.params.iter().enumerate() {
            let reg = IrId::new((i + 1) as u32); // +1 because 'this' is parameter 0
            self.symbol_map.insert(param.symbol_id, reg);
        }

        // Clear drop tracking state for this function
        self.owned_heap_values.clear();
        self.drop_scope_stack.clear();
        self.temp_heap_values.clear();
        self.reassigned_in_scope.clear();

        // Enter function-level scope for tracking heap allocations
        self.enter_drop_scope();

        // Execute pre-super statements (e.g., field assignments that come before
        // super() in the source code and are needed by virtual methods called from super)
        for stmt in &constructor.pre_super_stmts {
            self.lower_statement(stmt);
        }

        // Handle super() call if present
        if let Some(super_call) = &constructor.super_call {
            if let Some(parent_type_id) = parent_type {
                // Look up parent constructor by TypeId first, then by name as fallback
                let parent_ctor_id =
                    self.constructor_map
                        .get(&parent_type_id)
                        .copied()
                        .or_else(|| {
                            // TypeId mismatch: class.extends uses TAST TypeIds, constructor_map uses MIR TypeIds.
                            // Fall back to looking up by class name via constructor_name_map.
                            // Resolve parent class symbol from the type_table.
                            let type_table = self.type_table.borrow();
                            let parent_symbol = type_table.get(parent_type_id).and_then(|ti| {
                                if let TypeKind::Class { symbol_id, .. } = &ti.kind {
                                    Some(*symbol_id)
                                } else {
                                    None
                                }
                            });
                            drop(type_table);

                            if let Some(parent_sym) = parent_symbol {
                                if let Some(sym_info) = self.symbol_table.get_symbol(parent_sym) {
                                    // Try qualified name first
                                    if let Some(qual_name) = sym_info
                                        .qualified_name
                                        .and_then(|q| self.string_interner.get(q))
                                    {
                                        if let Some(&fid) = self.constructor_name_map.get(qual_name)
                                        {
                                            return Some(fid);
                                        }
                                    }
                                    // Try simple name
                                    if let Some(name) = self.string_interner.get(sym_info.name) {
                                        if let Some(&fid) = self.constructor_name_map.get(name) {
                                            return Some(fid);
                                        }
                                    }
                                }
                            }
                            None
                        });

                if let Some(parent_ctor_id) = parent_ctor_id {
                    // Lower super call arguments
                    let mut arg_regs = vec![this_reg]; // 'this' is first argument
                    for arg in &super_call.args {
                        if let Some(arg_reg) = self.lower_expression(arg) {
                            arg_regs.push(arg_reg);
                        }
                    }

                    // Fill in default values for any missing optional parameters
                    self.fill_default_args(parent_ctor_id, &mut arg_regs, true);

                    // Call parent constructor (returns void)
                    self.builder.build_call_direct(
                        parent_ctor_id,
                        arg_regs,
                        crate::ir::IrType::Void,
                    );
                } else {
                    self.add_error(
                        &format!(
                            "Parent constructor not found for TypeId {:?}",
                            parent_type_id
                        ),
                        crate::tast::SourceLocation::unknown(),
                    );
                }
            }
        }

        // Lower constructor body statements
        for stmt in &constructor.body.statements {
            self.lower_statement(stmt);
        }

        // Constructor implicitly returns void
        self.builder.build_return(None);

        // debug!("===== FINISHING FUNCTION =====");
        // if let Some(func) = self.builder.current_function() {
        //     eprintln!(
        //         "DEBUG   Function '{}' entry block terminator: {:?}",
        //         func.name,
        //         func.cfg
        //             .get_block(func.entry_block())
        //             .map(|b| &b.terminator)
        //     );
        // }
        self.builder.finish_function();
        // debug!("  Function finished, context cleared");

        self.symbol_map.clear();
        self.block_map.clear();
    }

    /// Lower a HIR function to MIR (Legacy - combines Pass 1 and Pass 2)
    fn lower_function(&mut self, symbol_id: SymbolId, hir_func: &HirFunction) {
        let body_stmt_count = hir_func
            .body
            .as_ref()
            .map(|b| b.statements.len())
            .unwrap_or(0);
        // debug!("lower_function - name={:?}, symbol={:?}, has_body={}, stmt_count={}",
        //           self.string_interner.get(hir_func.name),
        //           symbol_id,
        //           hir_func.body.is_some(),
        //           body_stmt_count);

        // Debug: Print each statement kind
        // if let Some(body) = &hir_func.body {
        //     for (i, stmt) in body.statements.iter().enumerate() {
        //         debug!("Statement {}: {:?}", i, std::mem::discriminant(stmt));
        //     }
        // }

        // Build MIR function signature
        let signature = self.build_function_signature(hir_func);

        // Start building the function
        let func_name = self
            .string_interner
            .get(hir_func.name)
            .map(|s| s.to_string())
            .unwrap_or_else(|| format!("func_{}", symbol_id.as_raw()));
        // debug!("===== STARTING FUNCTION: {} (symbol {:?}) =====", func_name, symbol_id);
        let func_id = self.builder.start_function(symbol_id, func_name, signature);

        // Store function mapping for call resolution
        self.function_map.insert(symbol_id, func_id);

        if hir_func.is_keep {
            if let Some(func) = self.builder.module.functions.get_mut(&func_id) {
                func.attributes
                    .custom
                    .insert("keep".to_string(), "true".to_string());
            }
        }

        // Record constrained type parameter info for call-site fat pointer wrapping
        self.record_constrained_params(func_id, hir_func, false);

        // Apply SSA-derived optimization hints to function attributes
        // These hints come from DFG/SSA analysis and guide MIR optimization
        if self.ssa_hints.inline_candidates.contains(&symbol_id) {
            // Mark for aggressive inlining (small function, simple control flow from SSA)
            if let Some(func) = self.builder.module.functions.get_mut(&func_id) {
                func.attributes.inline = super::InlineHint::Always;
            }
        }

        // Respect Haxe `inline` keyword — always inline these functions
        if hir_func.is_inline {
            if let Some(func) = self.builder.module.functions.get_mut(&func_id) {
                func.attributes.inline = super::InlineHint::Always;
            }
        }

        if self.ssa_hints.straight_line_functions.contains(&symbol_id) {
            // Mark for optimization (no branches, from CFG analysis)
            // Straight-line code can be optimized more aggressively
            if let Some(func) = self.builder.module.functions.get_mut(&func_id) {
                func.attributes.pure = true; // Assume pure for straight-line code
            }
        }

        if self
            .ssa_hints
            .complex_control_flow_functions
            .contains(&symbol_id)
        {
            // Don't mark for size optimization if complex control flow
            // Complex phi nodes benefit from full optimization passes
            if let Some(func) = self.builder.module.functions.get_mut(&func_id) {
                func.attributes.optimize_size = false;
            }
        }

        // Note: CSE opportunities don't have a direct attribute mapping yet
        // They will be used by the optimization pass manager

        // Note: qualified_name and source_location are set in lower_function_body (Pass 2).
        // This dead-code path (lower_function is never called) is left for reference.

        // Map parameters to MIR registers
        // Parameters now have symbol IDs (preserved from TAST)!
        /// debug!("Mapping {} parameters", hir_func.params.len());
        for (i, param) in hir_func.params.iter().enumerate() {
            if let Some(func) = self.builder.current_function() {
                if let Some(sig_param) = func.signature.parameters.get(i) {
                    let param_reg = sig_param.reg;
                    /// debug!("Parameter {} symbol {:?} '{}' -> register {:?}", i, param.symbol_id, param.name, param_reg);
                    // Map parameter symbol to its register
                    self.symbol_map.insert(param.symbol_id, param_reg);

                    // Also register parameter as a local so Cranelift can find its type
                    let param_type = self.convert_type(param.ty);
                    let src_loc = IrSourceLocation::unknown();
                    if let Some(func_mut) = self.builder.current_function_mut() {
                        func_mut.locals.insert(
                            param_reg,
                            super::IrLocal {
                                name: param.name.to_string(),
                                ty: param_type,
                                mutable: false, // Parameters are immutable by default
                                source_location: src_loc,
                                allocation: super::AllocationHint::Register,
                            },
                        );
                    }
                }
            }
        }

        // Lower function body if present
        if let Some(body) = &hir_func.body {
            // debug!("Lowering function body for {} (symbol {:?})", hir_func.name, symbol_id);
            let stmt_count = body.statements.len();
            let has_expr = body.expr.is_some();
            // eprintln!("  Body has {} statements, trailing expr: {}", stmt_count, has_expr);

            self.lower_block(body);
            // eprintln!("  After lower_block");

            // Add implicit return if needed
            self.ensure_terminator();
            // eprintln!("  After ensure_terminator");
        } else {
            // debug!("Function {} has no body", hir_func.name);
        }

        // debug!("===== FINISHING FUNCTION =====");
        // // Before finishing, dump the terminator for this function
        // if let Some(func) = self.builder.current_function() {
        //     eprintln!(
        //         "DEBUG   Function '{}' entry block terminator: {:?}",
        //         func.name,
        //         func.cfg
        //             .get_block(func.entry_block())
        //             .map(|b| &b.terminator)
        //     );
        // }
        self.builder.finish_function();
        // debug!("  Function finished, context cleared");

        // Clear per-function state
        self.symbol_map.clear();
        self.block_map.clear();
    }

    /// Lower an instance method (non-static class method) to MIR
    /// Instance methods receive an implicit 'this' parameter as their first argument
    fn lower_instance_method(
        &mut self,
        symbol_id: SymbolId,
        hir_func: &HirFunction,
        class_type_id: TypeId,
    ) {
        // Build MIR function signature with implicit 'this' parameter
        let signature = self.build_instance_method_signature(hir_func, class_type_id);

        // Start building the function
        let func_name = self
            .string_interner
            .get(hir_func.name)
            .map(|s| s.to_string())
            .unwrap_or_else(|| format!("func_{}", symbol_id.as_raw()));
        // eprintln!(
        //     "DEBUG ===== STARTING FUNCTION: {} (symbol {:?}) =====",
        //     func_name, symbol_id
        // );
        let func_id = self.builder.start_function(symbol_id, func_name, signature);
        // debug!("  Function ID: {:?}, Entry block created", func_id);

        // Store function mapping for call resolution
        self.function_map.insert(symbol_id, func_id);

        // Set qualified name for debugging, profiling, and stack traces
        if let Some(qualified_name) = hir_func.qualified_name {
            if let Some(func) = self.builder.module.functions.get_mut(&func_id) {
                func.qualified_name = self
                    .string_interner
                    .get(qualified_name)
                    .map(|s| s.to_string());
            }
        } else if let Some(func) = self.builder.module.functions.get_mut(&func_id) {
            // Build qualified name from class type
            let class_name = self
                .class_type_to_symbol
                .get(&class_type_id)
                .and_then(|&sym| self.symbol_table.get_symbol(sym))
                .and_then(|s| {
                    s.qualified_name
                        .and_then(|n| self.string_interner.get(n))
                        .or_else(|| self.string_interner.get(s.name))
                });
            if let Some(cn) = class_name {
                func.qualified_name = Some(format!("{}.{}", cn, func.name));
            }
        }

        // Set source location from symbol table for stack traces
        if let Some(sym) = self.symbol_table.get_symbol(hir_func.symbol_id) {
            let loc = sym.definition_location;
            if loc.line > 0 {
                if let Some(func) = self.builder.module.functions.get_mut(&func_id) {
                    func.source_location = IrSourceLocation {
                        file_id: loc.file_id,
                        line: loc.line,
                        column: loc.column,
                    };
                }
            }
        }

        // Map parameters to MIR registers
        // The first parameter (index 0) is the implicit 'this'
        // User-defined parameters start at index 1
        if let Some(func) = self.builder.current_function() {
            // Map 'this' parameter - we need a special symbol for it
            // For now, we'll create a synthetic symbol ID for 'this'
            // TODO: This should ideally come from TAST/HIR where 'this' is properly resolved
            if let Some(this_param) = func.signature.parameters.get(0) {
                let this_symbol = SymbolId::from_raw(0); // Synthetic 'this' symbol
                self.symbol_map.insert(this_symbol, this_param.reg);
            }

            // Map regular parameters (offset by 1 due to 'this')
            for (i, param) in hir_func.params.iter().enumerate() {
                if let Some(sig_param) = func.signature.parameters.get(i + 1) {
                    let param_reg = sig_param.reg;
                    // Map parameter symbol to its register
                    self.symbol_map.insert(param.symbol_id, param_reg);
                }
            }
        }

        // Lower the function body
        if let Some(body) = &hir_func.body {
            debug!(
                "lower_instance_method: {} has body with {} statements",
                self.string_interner.get(hir_func.name).unwrap_or("?"),
                body.statements.len()
            );

            // Clear per-function drop tracking state
            self.owned_heap_values.clear();
            self.drop_scope_stack.clear();
            self.temp_heap_values.clear();
            self.reassigned_in_scope.clear();

            // Enter function-level scope for variables declared at function level
            self.enter_drop_scope();
            self.lower_block(body);
            debug!(
                "lower_instance_method: {} - after lower_block",
                self.string_interner.get(hir_func.name).unwrap_or("?")
            );

            // Add implicit return if needed
            self.ensure_terminator();
            debug!(
                "lower_instance_method: {} - after ensure_terminator",
                self.string_interner.get(hir_func.name).unwrap_or("?")
            );
        } else {
            debug!(
                "lower_instance_method: {} has NO body!",
                self.string_interner.get(hir_func.name).unwrap_or("?")
            );
        }

        // Debug: check the function CFG
        if let Some(func) = self.builder.current_function() {
            debug!(
                "lower_instance_method: {} - CFG has {} blocks",
                func.name,
                func.cfg.blocks.len()
            );
            for (block_id, block) in &func.cfg.blocks {
                debug!(
                    "  Block {:?}: {} instructions, terminator: {:?}",
                    block_id,
                    block.instructions.len(),
                    block.terminator
                );
            }
        }

        // debug!("===== FINISHING FUNCTION =====");
        // Before finishing, dump the terminator for this function
        // if let Some(func) = self.builder.current_function() {
        //     eprintln!(
        //         "DEBUG   Function '{}' entry block terminator: {:?}",
        //         func.name,
        //         func.cfg
        //             .get_block(func.entry_block())
        //             .map(|b| &b.terminator)
        //     );
        // }
        self.builder.finish_function();
        // debug!("  Function finished, context cleared");

        // Clear per-function state
        self.symbol_map.clear();
        self.block_map.clear();
    }

    /// Lower a constructor to MIR
    /// Constructors are similar to instance methods but handle field initialization
    fn lower_constructor(
        &mut self,
        class_symbol: SymbolId,
        constructor: &HirConstructor,
        class_type_id: TypeId,
    ) {
        // debug!("lower_constructor - class_symbol={:?}", class_symbol);

        // Build signature using the builder
        // 'this' is always a pointer to the class instance, regardless of generic parameters
        let this_type = match self.convert_type(class_type_id) {
            IrType::Ptr(_) => IrType::Ptr(Box::new(IrType::Void)),
            // If convert_type failed to resolve (e.g., generic class without instantiation),
            // default to pointer since 'this' is always a pointer to instance
            _ => IrType::Ptr(Box::new(IrType::Void)),
        };
        let mut sig_builder = FunctionSignatureBuilder::new().param("this".to_string(), this_type);

        // Add constructor parameters
        for param in &constructor.params {
            let param_name = self
                .string_interner
                .get(param.name)
                .map(|s| s.to_string())
                .unwrap_or_else(|| format!("param_{}", param.symbol_id.as_raw()));
            sig_builder = sig_builder.param(param_name, self.convert_type(param.ty));
        }

        // Constructor returns void
        let signature = sig_builder.returns(IrType::Void).build();

        // Start building the constructor function
        let func_name = "new".to_string();
        let func_id = self
            .builder
            .start_function(class_symbol, func_name, signature);

        // Register this function in the function map
        self.function_map.insert(class_symbol, func_id);

        // Register in constructor_map by TypeId for new expressions
        self.constructor_map.insert(class_type_id, func_id);
        self.register_constructor_by_name(class_symbol, func_id);

        // Also register with TypeId derived from class SymbolId as a fallback
        // This handles cases where expression TypeIds differ from types map TypeIds
        let fallback_type_id = TypeId::from_raw(class_symbol.as_raw());
        if fallback_type_id != class_type_id {
            self.constructor_map.insert(fallback_type_id, func_id);
        }

        // Note: start_function already creates the entry block and switches to it
        // No need to create another block here - just use the current block

        // Map 'this' parameter (IrId(0) is the first parameter)
        let this_reg = IrId::new(0);

        // Register 'this' in symbol_map so implicit this.field access works
        self.symbol_map.insert(SymbolId::from_raw(0), this_reg);

        // Map constructor parameters
        for (i, param) in constructor.params.iter().enumerate() {
            let param_reg = IrId::new((i + 1) as u32); // Parameters start after 'this'
            self.symbol_map.insert(param.symbol_id, param_reg);
        }

        // Clear per-function drop tracking state
        self.owned_heap_values.clear();
        self.drop_scope_stack.clear();
        self.temp_heap_values.clear();
        self.reassigned_in_scope.clear();

        // Enter function-level scope
        self.enter_drop_scope();

        // Lower field initializations
        for field_init in &constructor.field_inits {
            if let Some(value_reg) = self.lower_expression(&field_init.value) {
                // Store to field using field_index_map
                if let Some(&(_class_type, field_index)) =
                    self.field_index_map.get(&field_init.field)
                {
                    if let Some(index_const) =
                        self.builder.build_const(IrValue::I32(field_index as i32))
                    {
                        // Get the actual field type from the symbol table
                        let field_ty = self
                            .symbol_table
                            .get_symbol(field_init.field)
                            .map(|s| self.convert_type(s.type_id))
                            .unwrap_or(IrType::I32);
                        if let Some(field_ptr) =
                            self.builder
                                .build_gep(this_reg, vec![index_const], field_ty)
                        {
                            self.builder.build_store(field_ptr, value_reg);
                        }
                    }
                }
            }
        }

        // Lower constructor body
        // debug!("Constructor body has {} statements", constructor.body.statements.len());
        // for (i, stmt) in constructor.body.statements.iter().enumerate() {
        //     // debug!("Constructor stmt {}: {:?}", i, std::mem::discriminant(stmt));
        // }
        self.lower_block(&constructor.body);

        // Ensure void return
        if !self.is_terminated() {
            self.builder.build_return(None);
        }

        // debug!("===== FINISHING FUNCTION =====");
        // Before finishing, dump the terminator for this function
        // if let Some(func) = self.builder.current_function() {
        //     eprintln!(
        //         "DEBUG   Function '{}' entry block terminator: {:?}",
        //         func.name,
        //         func.cfg
        //             .get_block(func.entry_block())
        //             .map(|b| &b.terminator)
        //     );
        // }
        self.builder.finish_function();
        // debug!("  Function finished, context cleared");

        // Clear per-function state
        self.symbol_map.clear();
        self.block_map.clear();
    }

    /// Lower a HIR block to MIR
    fn lower_block(&mut self, block: &HirBlock) {
        // Process all statements
        for stmt in block.statements.iter() {
            self.lower_statement(stmt);

            // Check if any variables have their last use at this statement
            // and emit Free for them (lifetime-based drop)
            self.check_drop_points_after_statement();

            // Increment statement index for drop point tracking
            self.current_stmt_index += 1;
        }

        // Process trailing expression if present
        if let Some(expr) = &block.expr {
            let _result = self.lower_expression(expr);
            // The result could be used for implicit returns
        }
    }

    /// Lower a HIR block expression to MIR, returning the trailing expression's value
    fn lower_block_expr(&mut self, block: &HirBlock) -> Option<IrId> {
        // Process all statements
        for stmt in block.statements.iter() {
            self.lower_statement(stmt);
            self.check_drop_points_after_statement();
            self.current_stmt_index += 1;
        }

        // Return trailing expression value if present
        if let Some(expr) = &block.expr {
            self.lower_expression(expr)
        } else {
            None
        }
    }

    /// Lower a HIR statement to MIR instructions
    fn lower_statement(&mut self, stmt: &HirStatement) {
        match stmt {
            HirStatement::Let {
                pattern,
                type_hint,
                init,
                is_mutable,
            } => {
                debug!(
                    "[LOWER STMT] Processing Let statement, has_init={}",
                    init.is_some()
                );
                // Lower initialization expression if present
                if let Some(init_expr) = init {
                    debug!(
                        "[LOWER STMT] init_expr.kind = {:?}",
                        std::mem::discriminant(&init_expr.kind)
                    );
                    let init_is_value_type = self.expr_is_value_type_expr(init_expr);

                    // Check for stdlib class method calls like Arc.init() or arc.clone()
                    // These methods return the same stdlib class type (e.g., Arc.init() -> Arc, Arc.clone() -> Arc)
                    let monomorphized_class = if let HirExprKind::Call {
                        callee,
                        args: call_args,
                        is_method,
                        ..
                    } = &init_expr.kind
                    {
                        self.detect_stdlib_class_from_call(callee, call_args)
                            .or_else(|| {
                                // For static calls (is_method=false) with Variable callee,
                                // resolve the method via stdlib mapping to identify the class.
                                // This handles extern class factory methods like GPUCompute.create().
                                if !is_method {
                                    if let HirExprKind::Variable { symbol, .. } = &callee.kind {
                                        self.get_stdlib_runtime_info(
                                            *symbol,
                                            TypeId::invalid(),
                                            Some(call_args.len()),
                                            None,
                                        )
                                        .map(|(class_name, _, _)| class_name.to_string())
                                    } else {
                                        None
                                    }
                                } else {
                                    None
                                }
                            })
                    } else {
                        None
                    };

                    // Track ownership for explicit allocations:
                    // - `new` class expressions (except array literals)
                    // - reflective Type.createInstance/createEmptyInstance calls
                    let mut is_heap_alloc = match &init_expr.kind {
                        HirExprKind::New { .. } => {
                            let type_table = self.type_table.borrow();
                            let is_array = if let Some(type_ref) = type_table.get(init_expr.ty) {
                                matches!(type_ref.kind, crate::tast::TypeKind::Array { .. })
                            } else {
                                false
                            };
                            drop(type_table);
                            !is_array
                        }
                        HirExprKind::Call { callee, args, .. } => {
                            self.type_needs_drop(init_expr.ty)
                                && self.is_reflective_type_alloc_call(callee, args.len())
                        }
                        _ => false,
                    };

                    // @:derive(Copy) — check if RHS is a variable with Copy type
                    let copy_class_sym = if let HirExprKind::Variable { .. } = &init_expr.kind {
                        self.get_copy_class_symbol(init_expr.ty)
                    } else {
                        None
                    };

                    let value = self.lower_expression(init_expr);

                    // If Copy type, emit shallow copy and mark as heap alloc for drop tracking
                    let value = if let (Some(class_sym), Some(val)) = (copy_class_sym, value) {
                        if let Some(copy_ptr) = self.emit_shallow_copy(val, class_sym) {
                            is_heap_alloc = true;
                            Some(copy_ptr)
                        } else {
                            Some(val)
                        }
                    } else {
                        value
                    };

                    // Bind to pattern and register as local
                    if value.is_none() {
                        warn!(
                            "[LET STMT] INIT EXPRESSION FAILED TO LOWER - variable won't be added to symbol_map! pattern={:?}",
                            pattern
                        );
                    }
                    // Track @:async function call results
                    let is_async_call = if let HirExprKind::Call { callee, .. } = &init_expr.kind {
                        match &callee.kind {
                            HirExprKind::Variable { symbol, .. } => self
                                .symbol_table
                                .get_symbol(*symbol)
                                .map(|s| s.flags.contains(SymbolFlags::ASYNC))
                                .unwrap_or(false),
                            // StaticMethodCall produces Field { object: Variable(class), field: method }
                            HirExprKind::Field { field, .. } => self
                                .symbol_table
                                .get_symbol(*field)
                                .map(|s| s.flags.contains(SymbolFlags::ASYNC))
                                .unwrap_or(false),
                            _ => false,
                        }
                    } else {
                        false
                    };

                    if let Some(value_reg) = value {
                        // Mark variable as async result for Future method dispatch
                        if is_async_call {
                            self.async_result_registers.insert(value_reg);
                            if let HirPattern::Variable { symbol, .. } = pattern {
                                // Also mark any register the symbol maps to later
                                self.async_result_registers.insert(value_reg);
                            }
                        }

                        // Track monomorphized class name for this variable (by SymbolId)
                        if let Some(mono_class) = monomorphized_class {
                            if let HirPattern::Variable { symbol, .. } = pattern {
                                self.monomorphized_var_types.insert(*symbol, mono_class);
                            }
                        } else if let HirPattern::Variable { symbol, .. } = pattern {
                            // Fallback: propagate class hint from register (set by
                            // Dynamic/TypeParameter method dispatch) to variable.
                            // This enables disambiguation of chained calls like:
                            //   var guard = mutex.lock(); guard.get(); guard.unlock();
                            if let Some(class_hint) = self.register_class_hints.get(&value_reg) {
                                self.monomorphized_var_types
                                    .insert(*symbol, class_hint.clone());
                            }
                        }

                        // Determine the type for the binding
                        let var_type = type_hint.or(Some(init_expr.ty));

                        // Auto-box if assigning concrete value to Dynamic variable
                        // Auto-unbox if assigning Dynamic value to concrete variable
                        let final_value = if let Some(target_ty) = var_type {
                            // Try boxing first (concrete → Dynamic)
                            let after_box = self
                                .maybe_box_value(value_reg, init_expr.ty, target_ty)
                                .unwrap_or(value_reg);

                            // Track if boxing actually happened (value was boxed into Dynamic)
                            if after_box != value_reg {
                                if let HirPattern::Variable { symbol, .. } = pattern {
                                    self.boxed_dynamic_symbols.insert(*symbol);
                                }
                            } else if let HirPattern::Variable { symbol, .. } = pattern {
                                // No boxing happened. If the register holds a Ptr(U8) value
                                // from a Dynamic-typed expression, it's a raw anon handle
                                // (e.g., from haxe_ereg_matched_pos_anon). Track it so
                                // field access skips haxe_unbox_reference_ptr.
                                let is_dynamic_init = {
                                    let tt = self.type_table.borrow();
                                    tt.get(init_expr.ty)
                                        .map(|t| matches!(t.kind, TypeKind::Dynamic))
                                        .unwrap_or(false)
                                };
                                let is_ptr_u8 = matches!(
                                    self.builder.get_register_type(value_reg),
                                    Some(IrType::Ptr(ref inner)) if matches!(**inner, IrType::U8)
                                );
                                if is_dynamic_init && is_ptr_u8 {
                                    self.raw_anon_symbols.insert(*symbol);
                                }
                            }

                            // Then try unboxing (Dynamic → concrete)
                            self.maybe_unbox_value(after_box, init_expr.ty, target_ty)
                                .unwrap_or(after_box)
                        } else {
                            value_reg
                        };

                        // Auto-box primitive for Null<T> (Optional) assignment
                        let final_value = if let Some(target_ty) = var_type {
                            self.maybe_box_for_optional(final_value, init_expr.ty, target_ty)
                                .unwrap_or(final_value)
                        } else {
                            final_value
                        };

                        // Apply abstract @:from implicit conversion if needed
                        let final_value = if let Some(target_ty) = var_type {
                            self.maybe_abstract_from_convert(final_value, init_expr.ty, target_ty)
                                .unwrap_or(final_value)
                        } else {
                            final_value
                        };

                        // Wrap class instance in interface fat pointer if needed.
                        // Skip for SafeCast results — the SafeCast handler already creates
                        // the fat pointer (or null for failed casts). Cloning a null pointer
                        // from a failed SafeCast would SIGSEGV.
                        let init_is_safe_cast =
                            matches!(&init_expr.kind, HirExprKind::Cast { is_safe: true, .. });
                        let (final_value, wrapped_for_interface) = if let Some(target_ty) = var_type
                        {
                            if init_is_safe_cast {
                                (final_value, false)
                            } else {
                                self.maybe_wrap_for_interface(final_value, init_expr.ty, target_ty)
                            }
                        } else {
                            (final_value, false)
                        };

                        // Structural subtyping: register anon view for class→anon or wider-anon→narrower
                        let is_anon_view =
                            if let (HirPattern::Variable { symbol, .. }, Some(target_ty)) =
                                (pattern, var_type)
                            {
                                self.try_register_anon_view(
                                    *symbol,
                                    final_value,
                                    init_expr.ty,
                                    target_ty,
                                )
                            } else {
                                false
                            };

                        // Propagate existing anon view when copying from a backed variable
                        if !is_anon_view {
                            if let HirExprKind::Variable {
                                symbol: src_symbol, ..
                            } = &init_expr.kind
                            {
                                if let Some(backing) = self.anon_views.get(src_symbol).cloned() {
                                    if let HirPattern::Variable {
                                        symbol: dst_symbol, ..
                                    } = pattern
                                    {
                                        self.anon_views.insert(*dst_symbol, backing);
                                    }
                                }
                            }
                        }

                        // Clone anonymous object handles for COW semantics.
                        // Skip if: object literal (fresh), anon view (backed by class/wider anon),
                        // or copying from a backed variable (shares backing reference).
                        let src_has_view = if let HirExprKind::Variable {
                            symbol: src_sym, ..
                        } = &init_expr.kind
                        {
                            self.anon_views.contains_key(src_sym)
                        } else {
                            false
                        };
                        let final_value = if !is_anon_view
                            && !src_has_view
                            && !matches!(&init_expr.kind, HirExprKind::ObjectLiteral { .. })
                        {
                            self.maybe_clone_anonymous(final_value, init_expr.ty)
                        } else {
                            final_value
                        };

                        self.bind_pattern_with_type(pattern, final_value, var_type, *is_mutable);

                        // Register heap-allocated value for drop tracking
                        // Only register AutoDrop types (user-defined classes), not RuntimeManaged
                        // extern types (Thread, Channel, Arc, Mutex) or NoDrop types
                        if let HirPattern::Variable { symbol, .. } = pattern {
                            if init_is_value_type {
                                self.value_type_symbols.insert(*symbol);
                            } else {
                                self.value_type_symbols.remove(symbol);
                            }
                            if wrapped_for_interface {
                                // Interface assignments allocate a fat pointer wrapper that
                                // must be freed on reassignment/scope-exit.
                                self.register_owned_value(*symbol, final_value);
                                if self.get_class_symbol(init_expr.ty).is_some() {
                                    if let HirExprKind::Variable {
                                        symbol: src_symbol, ..
                                    } = &init_expr.kind
                                    {
                                        // Class -> interface wrapping aliases the class object.
                                        // Stop tracking source as sole owner to avoid premature
                                        // class frees while interface wrappers still reference it.
                                        if self.owned_heap_values.remove(src_symbol).is_some() {
                                            self.reassigned_in_scope.insert(*src_symbol);
                                        }
                                    }
                                }
                            } else if is_heap_alloc {
                                let needs_drop = self.type_needs_drop(init_expr.ty);
                                if needs_drop {
                                    self.register_owned_value(*symbol, final_value);
                                }
                            }
                        }

                        // Ownership transfer: when `var current = n1`, the heap-allocated
                        // value is aliased. Transfer ownership from source to destination
                        // so the drop analysis doesn't free the source while the alias lives.
                        // Skip if interface wrapping already handled the transfer.
                        if !wrapped_for_interface {
                        if let HirPattern::Variable {
                            symbol: dst_symbol, ..
                        } = pattern
                        {
                            let src_symbol = match &init_expr.kind {
                                HirExprKind::Variable { symbol, .. } => Some(*symbol),
                                HirExprKind::Cast {
                                    expr: cast_expr,
                                    is_safe: true,
                                    ..
                                } => {
                                    if let HirExprKind::Variable { symbol, .. } = &cast_expr.kind {
                                        Some(*symbol)
                                    } else {
                                        None
                                    }
                                }
                                _ => None,
                            };
                            if let Some(src_sym) = src_symbol {
                                if let Some(src_ir_id) = self.owned_heap_values.remove(&src_sym) {
                                    self.reassigned_in_scope.insert(src_sym);
                                    self.register_owned_value(*dst_symbol, src_ir_id);
                                }
                            }
                        }
                    }
                    }
                }
            }

            HirStatement::Expr(expr) => {
                // Clear temps before expression
                self.temp_heap_values.clear();

                // Shadow-stack location updates are emitted only at call expressions
                // (in the Call handler) and throw statements — not at every statement.
                // This avoids the overhead of N extra extern calls per function.

                let result = self.lower_expression(expr);

                // Free any temporaries created during expression evaluation
                // The result itself (if heap-allocated) is NOT a temporary if it's
                // being used as a return value, but for bare expression statements
                // like method calls for side effects, we should free the result too
                //
                // IMPORTANT: Don't track method call results for drop because:
                // Track heap-allocated results for cleanup:
                // 1. Direct `new` expressions: `new Complex(...)`
                // 2. Method calls that return class instances: `z.mul(z)` returns new Complex
                //
                // The type_needs_drop check ensures we only track Class instances,
                // not primitives, strings, or Dynamic values from runtime functions.
                // NOTE: We do NOT track the top-level expression result as a temp.
                // Functions like Array.push() may store their argument, and freeing
                // the result would create dangling pointers. Only chained method call
                // receivers are safe to free (tracked at the field-access lowering site).
                let _ = result;

                // Free all temporaries
                self.drop_temps();
            }

            HirStatement::Assign { lhs, rhs, op } => {
                // Check if RHS produces a heap-allocated value
                // This includes:
                // 1. Direct `new` expressions (e.g., `new Point(1, 2)`)
                // 2. Method calls returning class instances (e.g., `z.mul(z).add(c)`)
                // We use type_needs_drop to detect any heap-allocated value, not just `new`
                let rhs_type_needs_drop = self.type_needs_drop(rhs.ty);

                // For simple variable assignment, check if we need to free the old value
                // We do this BEFORE evaluating RHS to avoid double-free if RHS reuses the variable
                let lhs_symbol = match lhs {
                    HirLValue::Variable(symbol) => Some(*symbol),
                    _ => None,
                };

                // If assigning a heap-allocated value to a variable that already owns one,
                // free the old value first (handled by register_owned_value)
                // Note: The actual free happens in register_owned_value after we evaluate RHS

                // Clear temps before RHS evaluation
                self.temp_heap_values.clear();
                let rhs_is_value_type = self.expr_is_value_type_expr(rhs) && op.is_none();

                // @:derive(Copy) — check if RHS is a variable with Copy type
                let assign_copy_class = if op.is_none() {
                    if let HirExprKind::Variable { .. } = &rhs.kind {
                        self.get_copy_class_symbol(rhs.ty)
                    } else {
                        None
                    }
                } else {
                    None
                };

                let rhs_value = self.lower_expression(rhs);

                // If Copy type, emit shallow copy
                let (rhs_value, rhs_was_copied) =
                    if let (Some(class_sym), Some(val)) = (assign_copy_class, rhs_value) {
                        // Guard against self-assignment (a = a)
                        let is_self_assign = if let (
                            Some(lhs_sym),
                            HirExprKind::Variable {
                                symbol: rhs_sym, ..
                            },
                        ) = (lhs_symbol, &rhs.kind)
                        {
                            lhs_sym == *rhs_sym
                        } else {
                            false
                        };
                        if !is_self_assign {
                            if let Some(copy_ptr) = self.emit_shallow_copy(val, class_sym) {
                                (Some(copy_ptr), true)
                            } else {
                                (Some(val), false)
                            }
                        } else {
                            (Some(val), false)
                        }
                    } else {
                        (rhs_value, false)
                    };

                if let Some(rhs_reg) = rhs_value {
                    // Handle compound assignment if present
                    let final_value = if let Some(bin_op) = op {
                        let lhs_value = self.lower_lvalue_read(lhs);
                        lhs_value.and_then(|lhs_reg| {
                            let result_reg = self.builder.build_binop(
                                self.convert_binary_op(*bin_op),
                                lhs_reg,
                                rhs_reg,
                            )?;

                            // Register the result type for Cranelift
                            let result_type = self.convert_type(rhs.ty);
                            if let Some(func) = self.builder.current_function_mut() {
                                func.locals.insert(
                                    result_reg,
                                    super::IrLocal {
                                        name: format!("_binop{}", result_reg.0),
                                        ty: result_type,
                                        mutable: false,
                                        source_location: super::IrSourceLocation {
                                            file_id: 0,
                                            line: 0,
                                            column: 0,
                                        },
                                        allocation: super::AllocationHint::Register,
                                    },
                                );
                            }

                            Some(result_reg)
                        })
                    } else {
                        Some(rhs_reg)
                    };

                    // Store to lvalue
                    if let Some(value) = final_value {
                        // Dynamic↔typed coercion (box concrete→Dynamic, unbox Dynamic→concrete)
                        let value = if let HirLValue::Variable(sym) = lhs {
                            if let Some(sym_info) = self.symbol_table.get_symbol(*sym) {
                                let target_ty = sym_info.type_id;
                                if target_ty != TypeId::invalid() {
                                    let after_box = self
                                        .maybe_box_value(value, rhs.ty, target_ty)
                                        .unwrap_or(value);
                                    // Track boxing for Dynamic arithmetic safety
                                    if after_box != value {
                                        self.boxed_dynamic_symbols.insert(*sym);
                                    }
                                    self.maybe_unbox_value(after_box, rhs.ty, target_ty)
                                        .unwrap_or(after_box)
                                } else {
                                    value
                                }
                            } else {
                                value
                            }
                        } else {
                            value
                        };

                        // Apply abstract @:from implicit conversion if needed
                        let value = if let HirLValue::Variable(sym) = lhs {
                            if let Some(sym_info) = self.symbol_table.get_symbol(*sym) {
                                let target_ty = sym_info.type_id;
                                if target_ty != TypeId::invalid() {
                                    self.maybe_abstract_from_convert(value, rhs.ty, target_ty)
                                        .unwrap_or(value)
                                } else {
                                    value
                                }
                            } else {
                                value
                            }
                        } else {
                            value
                        };

                        // Wrap class instance in interface fat pointer if assigning to interface var
                        let (value, wrapped_for_interface) = if let HirLValue::Variable(sym) = lhs {
                            if let Some(sym_info) = self.symbol_table.get_symbol(*sym) {
                                if sym_info.type_id != TypeId::invalid() {
                                    self.maybe_wrap_for_interface(value, rhs.ty, sym_info.type_id)
                                } else {
                                    (value, false)
                                }
                            } else {
                                (value, false)
                            }
                        } else {
                            (value, false)
                        };

                        // Clone anonymous object handles for COW semantics on reassignment.
                        // Skip for object literals (fresh handles) and compound assignments.
                        let value = if op.is_none()
                            && !matches!(&rhs.kind, HirExprKind::ObjectLiteral { .. })
                        {
                            self.maybe_clone_anonymous(value, rhs.ty)
                        } else {
                            value
                        };

                        self.lower_lvalue_write(lhs, value);

                        // If the LHS is a global variable, the value escapes to global storage
                        // and must NOT be tracked for drop/free. Skip all drop tracking.
                        let lhs_is_global = match lhs {
                            HirLValue::Variable(sym) => self.global_symbol_map.contains_key(sym),
                            _ => false,
                        };

                        // Register heap-allocated value for drop tracking.
                        // Only track when the RHS actually creates a NEW allocation (New or Call).
                        // Field access and variable reads produce borrowed references that must
                        // NOT be freed — they point into existing objects.
                        // Only `new Foo(...)` creates guaranteed owned allocations.
                        // Call results (method returns) are ambiguous — they may return
                        // references to existing objects (e.g., satisfy() returns an existing
                        // constraint). Treating Call as owned causes use-after-free in while
                        // loops where exit_drop_scope frees the value before the back edge.
                        let rhs_is_owned_allocation = rhs_was_copied
                            || matches!(&rhs.kind, HirExprKind::New { .. });

                        // When assigning to a Field/ArrayIndex lvalue, the RHS value escapes
                        // to another object. If the RHS is a variable that we're tracking as
                        // an owned heap allocation, we must STOP tracking it — the pointer now
                        // lives inside another object and must NOT be freed at scope exit.
                        let lhs_is_field =
                            matches!(lhs, HirLValue::Field { .. } | HirLValue::Index { .. });
                        if lhs_is_field {
                            if let HirExprKind::Variable {
                                symbol: rhs_sym, ..
                            } = &rhs.kind
                            {
                                if self.owned_heap_values.remove(rhs_sym).is_some() {
                                    self.reassigned_in_scope.insert(*rhs_sym);
                                }
                            }
                        }

                        let lhs_was_tracked =
                            lhs_symbol.map_or(false, |s| self.owned_heap_values.contains_key(&s));
                        let rhs_needs_tracking = (rhs_is_owned_allocation && rhs_type_needs_drop)
                            || wrapped_for_interface;

                        if wrapped_for_interface && self.get_class_symbol(rhs.ty).is_some() {
                            if let HirExprKind::Variable {
                                symbol: src_symbol, ..
                            } = &rhs.kind
                            {
                                // Class -> interface wrapping aliases the class object.
                                // Don't keep source as sole owner.
                                if self.owned_heap_values.remove(src_symbol).is_some() {
                                    self.reassigned_in_scope.insert(*src_symbol);
                                }
                            }
                        }

                        if !lhs_is_global {
                            if lhs_was_tracked {
                                if let Some(symbol) = lhs_symbol {
                                    if rhs_needs_tracking {
                                        // RHS creates a new allocation → free old, track new
                                        self.register_owned_value(symbol, value);
                                    } else {
                                        // RHS is a borrowed reference (field access, variable, etc.)
                                        // → free old owned value, STOP tracking
                                        if let Some(old_ir_id) = self.owned_heap_values.remove(&symbol)
                                        {
                                            if !self.is_terminated() {
                                                self.builder.build_free(old_ir_id);
                                            }
                                        }
                                        self.reassigned_in_scope.insert(symbol);
                                    }
                                }
                            } else if rhs_needs_tracking {
                                // New allocation assigned to previously-untracked variable
                                if let Some(symbol) = lhs_symbol {
                                    self.register_owned_value(symbol, value);
                                }
                            }
                        }

                        // Remove the assigned value from temps (it's now owned by the variable)
                        self.temp_heap_values.retain(|&id| id != value);
                    }

                    if let Some(symbol) = lhs_symbol {
                        if rhs_is_value_type {
                            self.value_type_symbols.insert(symbol);
                        } else {
                            self.value_type_symbols.remove(&symbol);
                        }
                    }

                    // Free any intermediate temporaries created during RHS evaluation
                    // These are values like the result of z.mul(z) in z = z.mul(z).add(c)
                    self.drop_temps();
                }
            }

            HirStatement::Return(value) => {
                debug!("[Return]: has_value: {}", value.is_some());
                // Identify the returned symbol (if returning a variable) so we can
                // skip freeing its allocation in cleanup
                let returned_symbol = value.as_ref().and_then(|e| {
                    match &e.kind {
                        HirExprKind::Variable { symbol, .. } => Some(*symbol),
                        _ => None,
                    }
                });
                let ret_value = value.as_ref().and_then(|e| {
                    debug!(
                        "[Return]: Lowering return expression, expr kind: {:?}",
                        std::mem::discriminant(&e.kind)
                    );
                    let result = self.lower_expression(e);
                    debug!("[Return]: Return expression lowered to: {:?}", result);
                    if result.is_none() {
                        warn!("ERROR [Return]: Failed to lower return expression!");
                        debug!("ERROR [Return]: Expression was: {:#?}", e);
                    }
                    // Box for Null<T> return type: if function returns Optional{primitive}
                    // but the expression produces a raw primitive, box it.
                    if let (Some(val), Some(fn_ret_ty)) =
                        (result, self.current_function_return_type)
                    {
                        if let Some(boxed) = self.maybe_box_for_optional(val, e.ty, fn_ret_ty) {
                            return Some(boxed);
                        }
                    }
                    result
                });
                // Cleanup all scopes before returning - free all owned heap values
                // BUT skip the returned value (it escapes the function)
                self.cleanup_all_scopes_except_symbol(returned_symbol);
                debug!(
                    "[Return]: Building return instruction with value: {:?}",
                    ret_value
                );
                self.builder.build_return(ret_value);
                // debug!("Return instruction built");
            }

            HirStatement::Break(label) => {
                if let Some(loop_ctx) = self.find_loop_context(label.as_ref()) {
                    let break_block = loop_ctx.break_block;
                    let exit_phi_nodes = loop_ctx.exit_phi_nodes.clone();

                    // Get the current block before branching
                    let current_block = self.builder.current_block().unwrap();

                    // Add incoming edges to exit block phi nodes with current symbol values
                    for (symbol_id, exit_phi_reg) in &exit_phi_nodes {
                        // Get the current value of this symbol
                        let current_value = if let Some(&reg) = self.symbol_map.get(symbol_id) {
                            reg
                        } else {
                            // If symbol not in map, use the phi register itself (shouldn't happen)
                            *exit_phi_reg
                        };

                        // Add incoming edge from current block to exit phi
                        self.builder.add_phi_incoming(
                            break_block,
                            *exit_phi_reg,
                            current_block,
                            current_value,
                        );
                    }

                    // CRITICAL: Save drop state before cleanup. The break path emits Free
                    // instructions and modifies drop_scope_stack/owned_heap_values, but these
                    // mutations must NOT persist for the non-break code path. Without this
                    // save/restore, the scope stack is corrupted: the normal loop exit code
                    // (exit_drop_scope at the back-edge) pops the WRONG scope, causing
                    // variables from outer scopes to be freed prematurely → double-free.
                    let saved_scope_stack = self.drop_scope_stack.clone();
                    let saved_owned = self.owned_heap_values.clone();

                    // Free loop body allocations before breaking out
                    self.exit_drop_scope();
                    self.builder.build_branch(break_block);

                    // Restore drop state for non-break path code generation
                    self.drop_scope_stack = saved_scope_stack;
                    self.owned_heap_values = saved_owned;
                } else {
                    self.add_error("Break outside of loop", SourceLocation::unknown());
                }
            }

            HirStatement::Continue(label) => {
                if let Some(loop_ctx) = self.find_loop_context(label.as_ref()) {
                    // Copy fields before mutable borrow
                    let continue_block = loop_ctx.continue_block;
                    let continue_phi_nodes = loop_ctx.continue_phi_nodes.clone();

                    // Add incoming edges for update block phi nodes (if any).
                    // This is analogous to how break adds edges for exit phi nodes.
                    if !continue_phi_nodes.is_empty() {
                        if let Some(current_block) = self.builder.current_block() {
                            for (symbol_id, upd_phi_reg) in &continue_phi_nodes {
                                let current_value = self
                                    .symbol_map
                                    .get(symbol_id)
                                    .copied()
                                    .unwrap_or(*upd_phi_reg);
                                self.builder.add_phi_incoming(
                                    continue_block,
                                    *upd_phi_reg,
                                    current_block,
                                    current_value,
                                );
                            }
                        }
                    }

                    // CRITICAL: Save drop state before cleanup (same reason as break above).
                    // Continue emits Free instructions for the current scope, but these
                    // mutations must not persist for the non-continue code path.
                    let saved_scope_stack = self.drop_scope_stack.clone();
                    let saved_owned = self.owned_heap_values.clone();

                    // Free loop body allocations before continuing to next iteration
                    self.exit_drop_scope();
                    self.builder.build_branch(continue_block);

                    // Restore drop state for non-continue path code generation
                    self.drop_scope_stack = saved_scope_stack;
                    self.owned_heap_values = saved_owned;
                } else {
                    self.add_error("Continue outside of loop", SourceLocation::unknown());
                }
            }

            HirStatement::Throw(expr) => {
                let thrown_type = expr.ty;
                let throw_loc = expr.source_location;
                if let Some(exception_reg) = self.lower_expression(expr) {
                    // Update the top shadow-stack frame to the exact throw line/col so
                    // the trace snippet points at the throw statement, not the function def.
                    if throw_loc.is_valid() && throw_loc.line > 0 {
                        let update_loc_fn = self.get_or_register_extern_function(
                            "rayzor_update_call_frame_location",
                            vec![IrType::I32, IrType::I32],
                            IrType::Void,
                        );
                        let line_const = self
                            .builder
                            .build_const(IrValue::I32(throw_loc.line as i32))
                            .expect("failed to create throw line const");
                        let col_const = self
                            .builder
                            .build_const(IrValue::I32(throw_loc.column as i32))
                            .expect("failed to create throw col const");
                        self.builder.build_call_direct(
                            update_loc_fn,
                            vec![line_const, col_const],
                            IrType::Void,
                        );
                    }

                    // Populate the exception's `stack` field with the current call stack trace.
                    // This must happen AFTER rayzor_update_call_frame_location (so the
                    // throw location is in the trace) but BEFORE rayzor_throw_typed.
                    // Only for class types (Exception subclasses), not primitive throws.
                    if self.get_class_symbol(thrown_type).is_some() {
                        let stack_name = self.string_interner.intern("stack");
                        let stack_field = self.resolve_field_index_by_name(stack_name, thrown_type);
                        if let Some((_class_ty, field_idx)) = stack_field {
                            let call_stack_fn = self.get_or_register_extern_function(
                                "rayzor_native_stack_trace_call_stack",
                                vec![],
                                IrType::Ptr(Box::new(IrType::U8)),
                            );
                            let stack_str = self
                                .builder
                                .build_call_direct(
                                    call_stack_fn,
                                    vec![],
                                    IrType::Ptr(Box::new(IrType::U8)),
                                )
                                .expect("failed to call rayzor_native_stack_trace_call_stack");

                            let idx_const = self
                                .builder
                                .build_const(IrValue::I32(field_idx as i32))
                                .expect("failed to create stack field index const");
                            let field_ptr = self
                                .builder
                                .build_gep(
                                    exception_reg,
                                    vec![idx_const],
                                    IrType::Ptr(Box::new(IrType::Void)),
                                )
                                .expect("failed to build stack field GEP");
                            self.builder.build_store(field_ptr, stack_str);
                        }
                    }

                    // Cast exception to i64 for uniform storage
                    let reg_type = self
                        .builder
                        .get_register_type(exception_reg)
                        .unwrap_or(IrType::I64);
                    let exc_as_i64 = if reg_type != IrType::I64 {
                        self.builder
                            .build_cast(exception_reg, reg_type, IrType::I64)
                            .unwrap_or(exception_reg)
                    } else {
                        exception_reg
                    };

                    // Call rayzor_throw_typed(exception_value, type_id).
                    // For class throws, derive the raw type id from the object header at runtime,
                    // then add +1000 to match typed-catch encoding.
                    let thrown_type_reg = if self.get_class_symbol(thrown_type).is_some() {
                        let obj_ptr_ty = IrType::Ptr(Box::new(IrType::U8));
                        let obj_ptr = self
                            .builder
                            .build_cast(exc_as_i64, IrType::I64, obj_ptr_ty.clone())
                            .unwrap_or(exception_reg);
                        let idx0 = self
                            .builder
                            .build_const(IrValue::I32(0))
                            .expect("failed to create throw header index const");
                        let header_ptr = self
                            .builder
                            .build_gep(obj_ptr, vec![idx0], IrType::I64)
                            .expect("failed to build throw header gep");
                        let header_raw = self
                            .builder
                            .build_load(header_ptr, IrType::I64)
                            .expect("failed to load throw header type id");
                        let class_offset = self
                            .builder
                            .build_const(IrValue::I64(1000))
                            .expect("failed to create throw class offset const");
                        let encoded = self
                            .builder
                            .build_binop(BinaryOp::Add, header_raw, class_offset)
                            .expect("failed to encode throw class type id");
                        self.builder
                            .build_cast(encoded, IrType::I64, IrType::I32)
                            .expect("failed to cast throw class type id")
                    } else {
                        let thrown_type_id = self.runtime_type_id(expr.ty);
                        self.builder
                            .build_const(IrValue::I32(thrown_type_id as i32))
                            .expect("failed to create throw type_id const")
                    };
                    let throw_fn = self.get_or_register_extern_function(
                        "rayzor_throw_typed",
                        vec![IrType::I64, IrType::I32],
                        IrType::Void,
                    );
                    self.builder.build_call_direct(
                        throw_fn,
                        vec![exc_as_i64, thrown_type_reg],
                        IrType::Void,
                    );
                    self.builder.build_unreachable();
                }
            }

            HirStatement::If {
                condition,
                then_branch,
                else_branch,
            } => {
                // debug!("About to call lower_if_statement, has_else={}", else_branch.is_some());
                self.lower_if_statement(condition, then_branch, else_branch.as_ref());
                // debug!("Returned from lower_if_statement");
            }

            HirStatement::Switch { scrutinee, cases } => {
                self.lower_switch_statement(scrutinee, cases);
            }

            HirStatement::While {
                condition,
                body,
                label,
                continue_update,
            } => {
                self.lower_while_loop(condition, body, label.as_ref(), continue_update.as_ref());
            }

            HirStatement::DoWhile {
                body,
                condition,
                label,
            } => {
                self.lower_do_while_loop(body, condition, label.as_ref());
            }

            HirStatement::ForIn {
                pattern,
                iterator,
                body,
                label,
            } => {
                self.lower_for_in_loop(pattern, iterator, body, label.as_ref());
            }

            HirStatement::TryCatch {
                try_block,
                catches,
                finally_block,
            } => {
                self.lower_try_catch(try_block, catches, finally_block.as_ref());
            }

            HirStatement::Label { symbol, block } => {
                // Labels in MIR become block labels
                let label_block = self
                    .builder
                    .create_block_with_label(format!("label_{}", symbol.as_raw()));
                if let Some(block_id) = label_block {
                    self.builder.build_branch(block_id);
                    self.builder.switch_to_block(block_id);
                    self.lower_block(block);
                }
            }
        }
    }

    /// Detect if a call expression returns a stdlib class type (e.g., Arc.init() -> Arc)
    /// This is used to track monomorphized class names for variables assigned from stdlib calls
    fn detect_stdlib_class_from_call(&self, callee: &HirExpr, args: &[HirExpr]) -> Option<String> {
        // Case 1: Static method call like Arc.init(...)
        // The callee is a Field access on a class type: Arc.init
        if let HirExprKind::Field { object, field, .. } = &callee.kind {
            if let HirExprKind::Variable { symbol, .. } = &object.kind {
                // Check if the variable is a class name (Arc, Mutex, etc.)
                if let Some(sym_info) = self.symbol_table.get_symbol(*symbol) {
                    if let Some(class_name) = self.string_interner.get(sym_info.name) {
                        // Get the method name
                        if let Some(field_sym) = self.symbol_table.get_symbol(*field) {
                            if let Some(method_name) = self.string_interner.get(field_sym.name) {
                                // Check if this is a stdlib class method that returns the same class type
                                // Methods like init, clone, tryLock return the same class or a related type
                                let returns_same_class = matches!(
                                    method_name,
                                    "init"
                                        | "clone"
                                        | "new"
                                        | "zeros"
                                        | "ones"
                                        | "full"
                                        | "fromArray"
                                        | "rand"
                                );
                                if returns_same_class && self.is_stdlib_class_by_symbol(sym_info) {
                                    // For Tensor class, map to runtime class name
                                    let runtime_class_name = if class_name == "Tensor" {
                                        "rayzor_ds_Tensor".to_string()
                                    } else {
                                        class_name.to_string()
                                    };
                                    debug!(
                                        "[STDLIB CLASS DETECT] Static call {}.{}() returns {}",
                                        class_name, method_name, runtime_class_name
                                    );
                                    return Some(runtime_class_name);
                                }
                            }
                        }
                    }
                }
            }
        }

        // Case 2: Instance method call like arc.clone() where arc is already tracked
        // The callee is a Field access on a variable: shared.clone
        if let HirExprKind::Field { object, field, .. } = &callee.kind {
            if let HirExprKind::Variable {
                symbol: receiver_sym,
                ..
            } = &object.kind
            {
                // Check if the receiver variable is already tracked as a stdlib class
                if let Some(tracked_class) = self.monomorphized_var_types.get(receiver_sym) {
                    // Get the method name
                    if let Some(field_sym) = self.symbol_table.get_symbol(*field) {
                        if let Some(method_name) = self.string_interner.get(field_sym.name) {
                            // Methods that return the same class type
                            let returns_same_class = matches!(method_name, "clone");
                            if returns_same_class {
                                debug!(
                                    "[STDLIB CLASS DETECT] Instance call {}.{}() returns {}",
                                    tracked_class, method_name, tracked_class
                                );
                                return Some(tracked_class.clone());
                            }
                        }
                    }
                }
            }
        }

        // Case 3: Direct call where callee is Variable (method reference)
        // This handles both:
        // - Static method calls like Arc.init(data) where init is resolved to a method symbol
        // - Instance method calls like clone(shared) where clone is the method symbol
        if let HirExprKind::Variable { symbol, .. } = &callee.kind {
            if let Some(sym_info) = self.symbol_table.get_symbol(*symbol) {
                if let Some(method_name) = self.string_interner.get(sym_info.name) {
                    // Check if this method name corresponds to a stdlib class factory method
                    // Methods like "init", "new", "clone" that return a stdlib class type
                    let factory_methods = [
                        "init",
                        "new",
                        "clone",
                        "zeros",
                        "ones",
                        "full",
                        "fromArray",
                        "rand",
                    ];
                    if factory_methods.contains(&method_name) {
                        // Try to find which stdlib class has this method
                        let stdlib_classes = self.stdlib_mapping.get_all_classes();
                        for class_name in &stdlib_classes {
                            // Check if this class has the method with appropriate param count
                            let is_static_factory = matches!(
                                method_name,
                                "init" | "new" | "zeros" | "ones" | "full" | "fromArray" | "rand"
                            );
                            if is_static_factory {
                                // Static method - check if class has this static method
                                if let Some((_sig, _)) = self
                                    .stdlib_mapping
                                    .find_static_method(class_name, method_name)
                                {
                                    debug!(
                                        "[DETECT-CLASS Case3] Found {}.{}() -> {}",
                                        class_name, method_name, class_name
                                    );
                                    return Some(class_name.to_string());
                                }
                            } else if method_name == "clone" {
                                // Instance method - check if first arg is a tracked stdlib variable
                                if !args.is_empty() {
                                    if let HirExprKind::Variable {
                                        symbol: receiver_sym,
                                        ..
                                    } = &args[0].kind
                                    {
                                        if let Some(tracked_class) =
                                            self.monomorphized_var_types.get(receiver_sym)
                                        {
                                            return Some(tracked_class.clone());
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }

        None
    }

    /// Given a stdlib class and method name, determine the class of the return value.
    /// This is used to set class hints on result registers for TypeParameter disambiguation.
    /// For most methods, the return value has the same class as the receiver.
    /// Some methods return a different class (e.g., Mutex.lock() -> MutexGuard).
    fn get_return_class_hint<'b>(dispatching_class: &'b str, method: &str) -> &'b str {
        match (dispatching_class, method) {
            // Mutex.lock() and Mutex.tryLock() return MutexGuard
            (c, "lock" | "tryLock") if c.contains("Mutex") && !c.contains("MutexGuard") => {
                "rayzor_concurrent_MutexGuard"
            }
            // Array.iterator() returns ArrayIterator
            ("Array", "iterator") => "ArrayIterator",
            // Array.keyValueIterator() returns ArrayKeyValueIterator
            ("Array", "keyValueIterator") => "ArrayKeyValueIterator",
            // Default: return value is associated with the same class
            _ => dispatching_class,
        }
    }

    /// Find the class name that owns a given method symbol by scanning HIR type declarations.
    /// Returns the normalized class name (e.g., "rayzor_gpu_GPUCompute") if found.
    /// Extract the normalized class name from an HirExpr's type by looking up
    /// the receiver in HIR type declarations. Handles extern classes whose TypeId
    /// may be invalid by checking all HIR types for a class with the method symbol.
    fn find_receiver_class_name(&self, receiver: &crate::ir::hir::HirExpr) -> Option<String> {
        // Strategy 1: Look up receiver.ty directly in current_hir_types
        if let Some(decl) = self.current_hir_types.get(&receiver.ty) {
            if let Some(name) = self.extract_class_native_name(decl) {
                return Some(name);
            }
        }

        // Strategy 2: If the receiver is a variable, get its symbol's type_id
        // and look that up. Extern class variables may have a different TypeId
        // than the class declaration.
        if let crate::ir::hir::HirExprKind::Variable { symbol, .. } = &receiver.kind {
            if let Some(sym) = self.symbol_table.get_symbol(*symbol) {
                // Try the symbol's type_id
                if let Some(decl) = self.current_hir_types.get(&sym.type_id) {
                    if let Some(name) = self.extract_class_native_name(decl) {
                        return Some(name);
                    }
                }
                // Try the symbol's native_name → look for matching class
                if let Some(native) = sym.native_name {
                    if let Some(native_str) = self.string_interner.get(native) {
                        return Some(native_str.replace("::", "_"));
                    }
                }
                // Try qualified_name (e.g. "sys.net.Host" → "sys_net_Host")
                // This covers extern classes where native_name wasn't propagated
                // across compilation contexts but qualified_name was set by the import resolver.
                if let Some(qn) = sym.qualified_name {
                    if let Some(qs) = self.string_interner.get(qn) {
                        // Only use qualified name if it contains a package separator
                        // (avoid turning "Host" into "Host" redundantly)
                        if qs.contains('.') {
                            return Some(qs.replace('.', "_"));
                        }
                    }
                }
            }

            // Strategy 3: Check register_class_hints via symbol_map.
            // This handles runtime-backed types whose stdlib class isn't loaded as HIR
            // (e.g., ArrayIterator from arr.iterator(), ArrayKeyValueIterator).
            if let Some(reg) = self.symbol_map.get(symbol) {
                if let Some(hint) = self.register_class_hints.get(reg) {
                    return Some(hint.clone());
                }
            }
        }

        None
    }

    fn extract_class_native_name(&self, decl: &HirTypeDecl) -> Option<String> {
        if let HirTypeDecl::Class(cls) = decl {
            for attr in &cls.metadata {
                let attr_name = self.string_interner.get(attr.name).unwrap_or("");
                if attr_name == "native" {
                    if let Some(crate::ir::hir::HirAttributeArg::Literal(
                        crate::ir::hir::HirLiteral::String(s),
                    )) = attr.args.first()
                    {
                        if let Some(native_str) = self.string_interner.get(*s) {
                            return Some(native_str.replace("::", "_"));
                        }
                    }
                }
            }
            return self.string_interner.get(cls.name).map(|s| s.to_string());
        }
        None
    }

    /// Check if a method symbol corresponds to a stdlib method with runtime mapping
    ///
    /// Returns (class_name, method_name, runtime_function_name) if this is a stdlib method
    /// If `param_count` is provided, it's used to disambiguate overloaded methods
    /// If `receiver_class_hint` is provided, it's used to disambiguate when multiple classes have the same method
    fn get_stdlib_runtime_info(
        &self,
        method_symbol: SymbolId,
        receiver_type: TypeId,
        param_count: Option<usize>,
        receiver_class_hint: Option<&str>,
    ) -> Option<(
        &'static str,
        &'static str,
        &crate::stdlib::RuntimeFunctionCall,
    )> {
        // Get the method name and optional qualified name from the symbol table
        // Prefer @:native name over Haxe name for runtime mapping lookup
        let (method_name, qualified_name, method_is_extern) =
            if let Some(symbol) = self.symbol_table.get_symbol(method_symbol) {
                let name = self.string_interner.get(symbol.name)?;
                let qname = symbol
                    .qualified_name
                    .and_then(|qn| self.string_interner.get(qn));
                (name, qname, symbol.flags.contains(SymbolFlags::EXTERN))
            } else {
                return None;
            };

        let allow_generic_monomorphization = self
            .resolve_receiver_class_symbol(receiver_type)
            .and_then(|symbol_id| self.symbol_table.get_symbol(symbol_id))
            .map_or(false, |symbol| {
                if !symbol.flags.contains(SymbolFlags::EXTERN) {
                    return false;
                }
                let class_name = match self.string_interner.get(symbol.name) {
                    Some(name) => name,
                    None => return false,
                };
                let has_monomorphized_variants = !self
                    .stdlib_mapping
                    .get_monomorphized_variants(class_name)
                    .is_empty();
                if !has_monomorphized_variants {
                    return false;
                }

                let in_stdlib_namespace = symbol
                    .qualified_name
                    .and_then(|qn| self.string_interner.get(qn))
                    .map_or(false, |qn| {
                        qn.starts_with("rayzor.")
                            || qn.starts_with("sys.")
                            || qn.starts_with("haxe.")
                    });
                in_stdlib_namespace || self.is_stdlib_class_by_symbol(symbol)
            });

        // Get the class name and type args from the receiver type
        let type_table = self.type_table.borrow();
        let type_info = type_table.get(receiver_type);

        debug!(
            "[get_stdlib_runtime_info] method={}, receiver_type={:?}, type_info_exists={}, qualified_name={:?}",
            method_name,
            receiver_type,
            type_info.is_some(),
            qualified_name
        );

        // FALLBACK: If receiver_type is invalid (extern classes like Vec), try to detect class from qualified name
        if type_info.is_none() {
            drop(type_table);
            debug!(
                "[get_stdlib_runtime_info] receiver_type {:?} not in type_table, qualified_name={:?}",
                receiver_type, qualified_name
            );
            if let Some(qname) = qualified_name {
                // Pattern: "rayzor.Vec.get" or "rayzor.concurrent.MutexGuard.get"
                let parts: Vec<&str> = qname.split('.').collect();
                if parts.len() >= 2 {
                    let class_parts = &parts[..parts.len() - 1];
                    let class_name = class_parts[class_parts.len() - 1];
                    let qualified_class_name = class_parts.join("_");

                    if let Some(count) = param_count {
                        if let Some((sig, mapping)) = self.stdlib_mapping.find_by_name_and_params(
                            &qualified_class_name,
                            method_name,
                            count,
                        ) {
                            return Some((sig.class, sig.method, mapping));
                        }
                    }
                    if let Some((sig, mapping)) = self
                        .stdlib_mapping
                        .find_by_name(&qualified_class_name, method_name)
                    {
                        return Some((sig.class, sig.method, mapping));
                    }

                    // For unresolved extern classes in stdlib namespaces, allow a
                    // simple-class fallback as a compatibility path.
                    // Keep this disabled for non-stdlib namespaces to avoid user
                    // class collisions (e.g., test.Vec, test.Thread, ...).
                    let allow_simple_fallback = class_parts.len() == 1
                        || qualified_class_name.starts_with("rayzor_")
                        || qualified_class_name.starts_with("sys_")
                        || qualified_class_name.starts_with("haxe_");
                    if method_is_extern && allow_simple_fallback {
                        if let Some(count) = param_count {
                            if let Some((sig, mapping)) = self
                                .stdlib_mapping
                                .find_by_name_and_params(class_name, method_name, count)
                            {
                                return Some((sig.class, sig.method, mapping));
                            }
                        }
                        if let Some((sig, mapping)) =
                            self.stdlib_mapping.find_by_name(class_name, method_name)
                        {
                            return Some((sig.class, sig.method, mapping));
                        }

                        let variants = self.stdlib_mapping.get_monomorphized_variants(class_name);
                        if !variants.is_empty() {
                            for variant in variants {
                                if let Some(count) = param_count {
                                    if let Some((sig, mapping)) = self
                                        .stdlib_mapping
                                        .find_by_name_and_params(variant, method_name, count)
                                    {
                                        return Some((sig.class, sig.method, mapping));
                                    }
                                }
                                if let Some((sig, mapping)) =
                                    self.stdlib_mapping.find_by_name(variant, method_name)
                                {
                                    return Some((sig.class, sig.method, mapping));
                                }
                            }
                        }
                    }
                }
            }

            // FALLBACK 1.5: Try to get class name from HIR type declarations.
            // This handles extern classes (like Tensor) whose receiver_type isn't in
            // the type_table but IS in current_hir_types.
            if let Some(type_decl) = self.current_hir_types.get(&receiver_type) {
                if let HirTypeDecl::Class(class) = type_decl {
                    let class_name_str = self.string_interner.get(class.name).unwrap_or("");
                    // Try with class name directly (e.g., "Tensor")
                    if let Some((sig, mapping)) = self
                        .stdlib_mapping
                        .find_by_name(class_name_str, method_name)
                    {
                        debug!(
                            "[FALLBACK1.5] Found {}.{} via HIR type decl",
                            class_name_str, method_name
                        );
                        return Some((sig.class, sig.method, mapping));
                    }
                    // Try with native name metadata (e.g., "rayzor::ds::Tensor" -> "rayzor_ds_Tensor")
                    for attr in &class.metadata {
                        let attr_name = self.string_interner.get(attr.name).unwrap_or("");
                        if attr_name == "native" {
                            if let Some(first_arg) = attr.args.first() {
                                if let crate::ir::hir::HirAttributeArg::Literal(
                                    crate::ir::hir::HirLiteral::String(s),
                                ) = first_arg
                                {
                                    let native_str = self.string_interner.get(*s).unwrap_or("");
                                    // Convert "rayzor::ds::Tensor" to "rayzor_ds_Tensor"
                                    let normalized = native_str.replace("::", "_");
                                    if let Some((sig, mapping)) =
                                        self.stdlib_mapping.find_by_name(&normalized, method_name)
                                    {
                                        debug!(
                                            "[FALLBACK1.5] Found {}.{} via @:native class name",
                                            normalized, method_name
                                        );
                                        return Some((sig.class, sig.method, mapping));
                                    }
                                }
                            }
                        }
                    }
                }
            }

            // FALLBACK: Use receiver_class_hint if available.
            // This handles monomorphized extern classes like Vec<Int> -> VecI32 where
            // the receiver TypeId is not in type_table but the New handler stored a
            // class hint on the receiver register.
            if let Some(hint) = receiver_class_hint {
                if let Some(count) = param_count {
                    if let Some((sig, mapping)) =
                        self.stdlib_mapping
                            .find_by_name_and_params(hint, method_name, count)
                    {
                        return Some((sig.class, sig.method, mapping));
                    }
                }
                if let Some((sig, mapping)) = self.stdlib_mapping.find_by_name(hint, method_name) {
                    return Some((sig.class, sig.method, mapping));
                }
            }

            // No qualified name and no valid receiver type — cannot resolve stdlib method.
            // Do NOT brute-force search all stdlib classes by bare method name, as this
            // causes false positives (e.g., user field "current" matching Thread.current).
            return None;
        }

        let type_info = type_info.unwrap();

        // Extract class info from the type, following TypeAlias if needed
        let (base_class_name, qualified_class_name, type_args) = match &type_info.kind {
            TypeKind::String => (Some("String"), None, Vec::new()),
            TypeKind::Array { .. } => (Some("Array"), None, Vec::new()),
            TypeKind::Enum { .. } => (Some("Enum"), None, Vec::new()),
            TypeKind::Map { key_type, .. } => {
                // Map types route to IntMap, StringMap, or ObjectMap based on key type
                let key_kind = type_table.get(*key_type).map(|t| t.kind.clone());
                let class = match key_kind {
                    Some(TypeKind::Int) | Some(TypeKind::Bool) => "IntMap",
                    Some(TypeKind::String) => "StringMap",
                    _ => "ObjectMap",
                };
                (Some(class), None, Vec::new())
            }
            TypeKind::Class {
                symbol_id,
                type_args,
                ..
            } => {
                // Get class name and qualified name from symbol
                let (name, qname) =
                    if let Some(class_info) = self.symbol_table.get_symbol(*symbol_id) {
                        let n = self.string_interner.get(class_info.name);
                        // Prefer lowered @:native name, fall back to qualified name
                        let qn = if let Some(native) = class_info.native_name {
                            self.string_interner
                                .get(native)
                                .map(|n| n.replace("::", "_"))
                        } else {
                            class_info
                                .qualified_name
                                .and_then(|qn| self.string_interner.get(qn))
                                .map(|qn| qn.replace(".", "_"))
                        };
                        (n, qn)
                    } else {
                        (None, None)
                    };
                (name, qname, type_args.clone())
            }
            TypeKind::TypeAlias { target_type, .. } => {
                // For type aliases like `typedef Bytes = rayzor.Bytes`, follow the target type
                if let Some(target_info) = type_table.get(*target_type) {
                    match &target_info.kind {
                        TypeKind::Class {
                            symbol_id,
                            type_args,
                            ..
                        } => {
                            let (name, qname) = if let Some(class_info) =
                                self.symbol_table.get_symbol(*symbol_id)
                            {
                                let n = self.string_interner.get(class_info.name);
                                let qn = if let Some(native) = class_info.native_name {
                                    self.string_interner
                                        .get(native)
                                        .map(|n| n.replace("::", "_"))
                                } else {
                                    class_info
                                        .qualified_name
                                        .and_then(|qn| self.string_interner.get(qn))
                                        .map(|qn| qn.replace(".", "_"))
                                };
                                (n, qn)
                            } else {
                                (None, None)
                            };
                            (name, qname, type_args.clone())
                        }
                        TypeKind::Placeholder {
                            name: placeholder_name,
                        } => {
                            // The typedef target wasn't resolved at compile time - try to look it up by name
                            // This handles cases like `typedef Bytes = rayzor.Bytes` where the target was loaded
                            // after the typedef was initially compiled
                            if let Some(target_name) = self.string_interner.get(*placeholder_name) {
                                // Convert "rayzor.Bytes" to "rayzor_Bytes" for stdlib mapping lookup
                                let qualified_name = target_name.replace(".", "_");
                                if let Some((_sig, mapping)) = self
                                    .stdlib_mapping
                                    .find_by_name(&qualified_name, method_name)
                                {
                                    // Early return with the mapping
                                    drop(type_table);
                                    return Some((_sig.class, _sig.method, mapping));
                                }
                            }
                            (None, None, Vec::new())
                        }
                        _ => (None, None, Vec::new()),
                    }
                } else {
                    (None, None, Vec::new())
                }
            }
            TypeKind::Abstract {
                symbol_id,
                type_args,
                ..
            } => {
                // For abstract types like Ptr<T>, Ref<T>, Box<T>, Usize
                // These are zero-cost abstracts over Int with methods in stdlib_mapping
                let (name, qname) =
                    if let Some(class_info) = self.symbol_table.get_symbol(*symbol_id) {
                        let n = self.string_interner.get(class_info.name);
                        let qn = if let Some(native) = class_info.native_name {
                            self.string_interner
                                .get(native)
                                .map(|n| n.replace("::", "_"))
                        } else {
                            class_info
                                .qualified_name
                                .and_then(|qn| self.string_interner.get(qn))
                                .map(|qn| qn.replace(".", "_"))
                        };
                        (n, qn)
                    } else {
                        (None, None)
                    };
                (name, qname, type_args.clone())
            }
            TypeKind::GenericInstance {
                base_type,
                type_args,
                ..
            } => {
                // For generic instances like Deque<Int>, Channel<String>, Arc<T>
                // Get the base type's class name (e.g., "Deque" from Deque<Int>)
                if let Some(base_info) = type_table.get(*base_type) {
                    // Generic enums (e.g., Option<Int>) resolve to "Enum" class
                    if matches!(&base_info.kind, TypeKind::Enum { .. }) {
                        return self
                            .stdlib_mapping
                            .find_by_name("Enum", method_name)
                            .map(|(sig, mapping)| (sig.class, sig.method, mapping));
                    }
                    let sym_id = match &base_info.kind {
                        TypeKind::Class { symbol_id, .. } => Some(*symbol_id),
                        TypeKind::Abstract { symbol_id, .. } => Some(*symbol_id),
                        _ => None,
                    };
                    if let Some(symbol_id) = sym_id {
                        let (name, qname) =
                            if let Some(class_info) = self.symbol_table.get_symbol(symbol_id) {
                                let n = self.string_interner.get(class_info.name);
                                let qn = if let Some(native) = class_info.native_name {
                                    self.string_interner
                                        .get(native)
                                        .map(|n| n.replace("::", "_"))
                                } else {
                                    class_info
                                        .qualified_name
                                        .and_then(|qn| self.string_interner.get(qn))
                                        .map(|qn| qn.replace(".", "_"))
                                };
                                (n, qn)
                            } else {
                                (None, None)
                            };
                        (name, qname, type_args.clone())
                    } else {
                        (None, None, Vec::new())
                    }
                } else {
                    (None, None, Vec::new())
                }
            }
            // TypeParameter / Dynamic / Placeholder: the receiver type doesn't tell us the class.
            // Return None to let the caller's fallback chain handle resolution.
            // The caller has context-specific handlers (Dynamic method handler, function_map, etc.)
            // that work better than brute-force stdlib search for these cases.
            TypeKind::Placeholder {
                name: placeholder_name,
            } => {
                // Use the Placeholder name to derive the class for stdlib lookup.
                // e.g., "rayzor.Bytes" → try "rayzor_Bytes", "Bytes"
                let ph_name = self
                    .string_interner
                    .get(*placeholder_name)
                    .map(|s| s.to_string());
                drop(type_table);
                if let Some(ref ph) = ph_name {
                    let underscore_name = ph.replace(".", "_");
                    let bare_name = ph.rsplit('.').next().unwrap_or(ph);
                    // Try qualified underscore name (e.g., "rayzor_Bytes")
                    if let Some(count) = param_count {
                        if let Some((sig, mapping)) = self.stdlib_mapping.find_by_name_and_params(
                            &underscore_name,
                            method_name,
                            count,
                        ) {
                            return Some((sig.class, sig.method, mapping));
                        }
                        if let Some((sig, mapping)) = self.stdlib_mapping.find_by_name_and_params(
                            bare_name,
                            method_name,
                            count,
                        ) {
                            return Some((sig.class, sig.method, mapping));
                        }
                    }
                    if let Some((sig, mapping)) = self
                        .stdlib_mapping
                        .find_by_name(&underscore_name, method_name)
                    {
                        return Some((sig.class, sig.method, mapping));
                    }
                    if let Some((sig, mapping)) =
                        self.stdlib_mapping.find_by_name(bare_name, method_name)
                    {
                        return Some((sig.class, sig.method, mapping));
                    }
                }
                // Fall through to qualified_name and hint lookups
                if let Some(qname) = qualified_name {
                    let parts: Vec<&str> = qname.split('.').collect();
                    if parts.len() >= 2 {
                        let class_parts = &parts[..parts.len() - 1];
                        let underscore_class = class_parts.join("_");
                        if let Some((sig, mapping)) = self
                            .stdlib_mapping
                            .find_by_name(&underscore_class, method_name)
                        {
                            return Some((sig.class, sig.method, mapping));
                        }
                    }
                }
                if let Some(hint) = receiver_class_hint {
                    if let Some((sig, mapping)) =
                        self.stdlib_mapping.find_by_name(hint, method_name)
                    {
                        return Some((sig.class, sig.method, mapping));
                    }
                }
                return None;
            }
            TypeKind::TypeParameter { .. } | TypeKind::Dynamic | TypeKind::Unknown => {
                drop(type_table);
                // Try qualified_name if available (e.g., for user-class methods like "test.Counter.increment")
                if let Some(qname) = qualified_name {
                    let parts: Vec<&str> = qname.split('.').collect();
                    if parts.len() >= 2 {
                        let class_parts = &parts[..parts.len() - 1];
                        let underscore_class = class_parts.join("_");
                        if let Some((sig, mapping)) = self
                            .stdlib_mapping
                            .find_by_name(&underscore_class, method_name)
                        {
                            return Some((sig.class, sig.method, mapping));
                        }
                        if let Some(&class_name) = parts.iter().rev().nth(1) {
                            if let Some((sig, mapping)) =
                                self.stdlib_mapping.find_by_name(class_name, method_name)
                            {
                                return Some((sig.class, sig.method, mapping));
                            }
                        }
                    }
                }
                // Try receiver_class_hint for disambiguation (e.g., guard.get() where guard
                // is typed as Dynamic but hint says "rayzor_concurrent_MutexGuard")
                if let Some(hint) = receiver_class_hint {
                    if let Some((sig, mapping)) =
                        self.stdlib_mapping.find_by_name(hint, method_name)
                    {
                        return Some((sig.class, sig.method, mapping));
                    }
                }
                return None;
            }
            _ => (None, None, Vec::new()),
        };

        let base_class_name = base_class_name?;

        // MONOMORPHIZATION: For generic extern classes like Vec<T>, monomorphize the class name
        // based on type arguments. Vec<Int> -> VecI32, Vec<Float> -> VecF64, etc.
        let monomorphized_class_name: Option<String> =
            if allow_generic_monomorphization && !type_args.is_empty() {
                let first_arg = type_args[0];
                let suffix = if let Some(arg_type) = type_table.get(first_arg) {
                    match &arg_type.kind {
                        TypeKind::Int => Some("I32"),
                        TypeKind::Float => Some("F64"),
                        TypeKind::Bool => Some("Bool"),
                        TypeKind::String => Some("Ptr"), // Strings are reference types
                        TypeKind::Class { symbol_id, .. } => {
                            // Check if it's Int64 (a class type representing 64-bit int)
                            if let Some(class_info) = self.symbol_table.get_symbol(*symbol_id) {
                                if let Some(name) = self.string_interner.get(class_info.name) {
                                    if name == "Int64" {
                                        Some("I64")
                                    } else {
                                        Some("Ptr") // Other classes are reference types
                                    }
                                } else {
                                    Some("Ptr")
                                }
                            } else {
                                Some("Ptr")
                            }
                        }
                        _ => Some("Ptr"), // Default to pointer for other types
                    }
                } else {
                    Some("Ptr") // Unknown type, use pointer
                };
                suffix.and_then(|s| {
                    let candidate = format!("{}{}", base_class_name, s);
                    let variants = self
                        .stdlib_mapping
                        .get_monomorphized_variants(base_class_name);
                    if variants.iter().any(|v| *v == candidate) {
                        Some(candidate)
                    } else {
                        None
                    }
                })
            } else {
                None
            };

        drop(type_table);

        // Use monomorphized name if available, then receiver_class_hint, then base name.
        // receiver_class_hint comes from the New handler (e.g., Vec<Int> -> "VecI32") and is
        // needed when allow_generic_monomorphization is false (e.g., qualified_name is "Vec"
        // not "rayzor.Vec" so the stdlib namespace check fails).
        let class_name = monomorphized_class_name
            .as_deref()
            .or(receiver_class_hint)
            .unwrap_or(base_class_name);

        // PRIORITY: If receiver_class_hint is a fully qualified name (contains '.'),
        // normalize it and try exact lookup FIRST. This handles subclass method dispatch
        // (e.g., sys.ssl.Socket.close should call rayzor_ssl_socket_close, not sys_net_Socket_close).
        if let Some(hint) = receiver_class_hint {
            if hint.contains('.') {
                let normalized_hint = hint.replace(".", "_");
                if let Some(count) = param_count {
                    if let Some((sig, mapping)) = self.stdlib_mapping.find_by_name_and_params(
                        &normalized_hint,
                        method_name,
                        count,
                    ) {
                        return Some((sig.class, sig.method, mapping));
                    }
                }
                if let Some((sig, mapping)) = self
                    .stdlib_mapping
                    .find_by_name(&normalized_hint, method_name)
                {
                    return Some((sig.class, sig.method, mapping));
                }
            }
        }

        // Try to find this method in the stdlib mapping
        // First try qualified name (e.g., "rayzor_Bytes"), then fall back to simple name
        if let Some(ref qn) = qualified_class_name {
            // Try with param_count first if available (to disambiguate overloads)
            if let Some(count) = param_count {
                if let Some((sig, mapping)) =
                    self.stdlib_mapping
                        .find_by_name_and_params(qn, method_name, count)
                {
                    debug!(
                        "[get_stdlib_runtime_info] Found {}.{} ({} params) via qualified name -> {}",
                        qn, method_name, count, mapping.runtime_name
                    );
                    return Some((sig.class, sig.method, mapping));
                }
            }
            // Fallback to find_by_name without param count
            if let Some((sig, mapping)) = self.stdlib_mapping.find_by_name(qn, method_name) {
                debug!(
                    "[get_stdlib_runtime_info] Found {}.{} via qualified name -> {}",
                    qn, method_name, mapping.runtime_name
                );
                return Some((sig.class, sig.method, mapping));
            }
        }
        // Try with param_count first if available
        if let Some(count) = param_count {
            if let Some((sig, mapping)) =
                self.stdlib_mapping
                    .find_by_name_and_params(class_name, method_name, count)
            {
                debug!(
                    "[get_stdlib_runtime_info] Found {}.{} ({} params) -> {}",
                    class_name, method_name, count, mapping.runtime_name
                );
                return Some((sig.class, sig.method, mapping));
            }
        }
        // Fallback without param count
        if let Some((sig, mapping)) = self.stdlib_mapping.find_by_name(class_name, method_name) {
            return Some((sig.class, sig.method, mapping));
        }

        // Bare-name fallback: if class_name is qualified (e.g., "haxe.ds.ObjectMap"),
        // try the bare class name (e.g., "ObjectMap") for methods registered with simple names.
        if class_name.contains('.') {
            let bare_name = class_name.rsplit('.').next().unwrap_or(class_name);
            if let Some(count) = param_count {
                if let Some((sig, mapping)) =
                    self.stdlib_mapping
                        .find_by_name_and_params(bare_name, method_name, count)
                {
                    return Some((sig.class, sig.method, mapping));
                }
            }
            if let Some((sig, mapping)) = self.stdlib_mapping.find_by_name(bare_name, method_name) {
                return Some((sig.class, sig.method, mapping));
            }
        }

        // @:forward fallback: if the abstract's own name didn't match, try underlying type
        {
            let type_table = self.type_table.borrow();
            if let Some(type_info) = type_table.get(receiver_type) {
                if let TypeKind::Abstract { symbol_id, .. } = &type_info.kind {
                    if let Some((underlying_type, forward_list)) =
                        self.abstract_forward_rules.get(symbol_id)
                    {
                        let method_interned =
                            self.symbol_table.get_symbol(method_symbol).map(|s| s.name);
                        let is_forwarded = forward_list.is_empty()
                            || method_interned.map_or(false, |n| forward_list.contains(&n));
                        if is_forwarded {
                            let underlying = *underlying_type;
                            drop(type_table);
                            return self.get_stdlib_runtime_info(
                                method_symbol,
                                underlying,
                                param_count,
                                None,
                            );
                        }
                    }
                }
            }
        }

        None
    }

    /// Check if a qualified name + method belongs to rayzor stdlib and return the runtime function name
    ///
    /// For static methods like Thread.spawn, Channel.init, etc.
    /// Uses StdlibMapping as single source of truth - no hardcoded mappings!
    fn get_static_stdlib_runtime_func(
        &self,
        qualified_name: &str,
        method_name: &str,
    ) -> Option<&'static str> {
        self.get_static_stdlib_runtime_func_with_params_internal(qualified_name, method_name, None)
    }

    fn is_class_symbol_expr(&self, expr: &HirExpr) -> bool {
        match &expr.kind {
            HirExprKind::Variable { symbol, .. } => self
                .symbol_table
                .get_symbol(*symbol)
                .map(|sym| {
                    matches!(
                        sym.kind,
                        crate::tast::symbols::SymbolKind::Class
                            | crate::tast::symbols::SymbolKind::Abstract
                            | crate::tast::symbols::SymbolKind::TypeAlias
                    )
                })
                .unwrap_or(false),
            HirExprKind::Cast { expr: inner, .. } => self.is_class_symbol_expr(inner),
            _ => false,
        }
    }

    /// Strip a synthetic class "receiver" from static-call args when present.
    fn effective_static_call_args<'b>(&self, args: &'b [HirExpr]) -> &'b [HirExpr] {
        if args.is_empty() {
            return args;
        }
        if self.is_class_symbol_expr(&args[0]) {
            return &args[1..];
        }
        args
    }

    /// Param-count aware static stdlib lookup.
    ///
    /// Prefer this where call argument count is known to avoid collisions such as
    /// `Std.random(Int)` vs `Math.random()`.
    fn get_static_stdlib_runtime_func_with_params(
        &self,
        qualified_name: &str,
        method_name: &str,
        param_count: usize,
    ) -> Option<&'static str> {
        self.get_static_stdlib_runtime_func_with_params_internal(
            qualified_name,
            method_name,
            Some(param_count),
        )
    }

    fn get_static_stdlib_runtime_func_with_params_internal(
        &self,
        qualified_name: &str,
        method_name: &str,
        param_count: Option<usize>,
    ) -> Option<&'static str> {
        // Parse qualified name to extract class name
        // Patterns: "rayzor.concurrent.Thread.spawn", "test.Thread.spawn", "StringTools.startsWith"
        let parts: Vec<&str> = qualified_name.split('.').collect();
        let class_name = parts.iter().rev().nth(1)?; // Second-to-last part is class name

        // Use StdlibMapping to find the runtime function
        // This is the ONLY source of truth - all mappings come from the actual Rust implementations

        // PRIORITY: First try qualified class name with underscore format (e.g., "sys_thread_Thread")
        // This handles sys.thread.Thread -> sys_thread_Thread mappings and prevents
        // conflicts between sys.thread.Thread and rayzor.concurrent.Thread
        if parts.len() >= 2 {
            // Build qualified class name: all parts except the last (method name), joined with underscore
            let qualified_class_name = parts[..parts.len() - 1].join("_");
            if let Some(count) = param_count {
                if let Some((_sig, mapping)) = self.stdlib_mapping.find_by_name_and_params(
                    &qualified_class_name,
                    method_name,
                    count,
                ) {
                    return Some(mapping.runtime_name);
                }
            }
            if let Some((_sig, mapping)) = self
                .stdlib_mapping
                .find_by_name(&qualified_class_name, method_name)
            {
                return Some(mapping.runtime_name);
            }
        }

        // FALLBACK: Then try simple class name (e.g., "Thread")
        if let Some(count) = param_count {
            if let Some((_sig, mapping)) =
                self.stdlib_mapping
                    .find_by_name_and_params(class_name, method_name, count)
            {
                return Some(mapping.runtime_name);
            }
            // With a known arg count, avoid arity-blind fallback here.
            // Callers can decide whether to do a global static fallback by (name, arity).
            return None;
        }
        if let Some((_sig, mapping)) = self.stdlib_mapping.find_by_name(class_name, method_name) {
            return Some(mapping.runtime_name);
        }

        None
    }

    /// Get the correct signature for a stdlib MIR wrapper function.
    /// These signatures MUST match what's defined in compiler/src/stdlib/{thread,channel,sync}.rs
    /// Returns (param_types, return_type) or None if not a known MIR wrapper.
    fn get_stdlib_mir_wrapper_signature(&self, name: &str) -> Option<(Vec<IrType>, IrType)> {
        // Query the runtime_mapping.rs type registry for explicit type information
        self.stdlib_mapping.get_function_signature(name)
    }

    /// Get known signature for extern runtime functions (not MIR wrappers)
    /// This is used to override inferred types for functions like Math that need f64
    fn get_extern_function_signature(&self, name: &str) -> Option<(Vec<IrType>, IrType)> {
        // Query the runtime_mapping.rs type registry for explicit type information
        self.stdlib_mapping.get_function_signature(name)
    }

    /// Register a forward reference to a stdlib MIR function that will be provided by module merging
    ///
    /// Unlike extern functions (which use C calling convention and are resolved by Cranelift),
    /// stdlib MIR functions use Haxe calling convention and are colocated functions that will
    /// be provided when the stdlib MIR module is merged.
    fn register_stdlib_mir_forward_ref(
        &mut self,
        name: &str,
        mut param_types: Vec<IrType>,
        mut return_type: IrType,
    ) -> IrFunctionId {
        // Check if already registered
        for (func_id, func) in &self.builder.module.functions {
            if func.name == name {
                return *func_id;
            }
        }

        // Override with correct signature if this is a known MIR wrapper
        // This fixes the bug where Thread_spawn gets wrong signature from inferred lambda type
        if let Some((correct_params, correct_return)) = self.get_stdlib_mir_wrapper_signature(name)
        {
            debug!(
                "Using registered signature for {}: {} params -> {:?}",
                name,
                correct_params.len(),
                correct_return
            );
            param_types = correct_params;
            return_type = correct_return;
        }

        // Create forward reference with Haxe calling convention (will be replaced during merge)
        let func_id = IrFunctionId(self.builder.module.next_function_id);
        self.builder.module.next_function_id += 1;

        let params = param_types
            .into_iter()
            .enumerate()
            .map(|(i, ty)| IrParameter {
                name: format!("arg{}", i),
                ty: ty.clone(),
                reg: IrId::new(i as u32),
                by_ref: false,
            })
            .collect();

        // Stdlib MIR wrappers use C calling convention (no env param)
        // This matches the actual definitions in thread.rs, channel.rs, sync.rs
        let signature = IrFunctionSignature {
            parameters: params,
            return_type: return_type.clone(),
            calling_convention: CallingConvention::C, // C calling convention for stdlib MIR wrappers
            can_throw: false,
            type_params: vec![],
            uses_sret: matches!(return_type, IrType::Struct { .. }),
        };

        use crate::ir::{FunctionAttributes, InlineHint, IrControlFlowGraph, Linkage};
        use crate::tast::SymbolId;

        // Create stub function (empty blocks = forward declaration)
        let mut attributes = FunctionAttributes::default();
        attributes.linkage = Linkage::Public;
        attributes.inline = InlineHint::Auto;

        let function = IrFunction {
            id: func_id,
            symbol_id: SymbolId::from_raw(0),
            name: name.to_string(),
            qualified_name: None,
            signature,
            cfg: IrControlFlowGraph::new(), // Empty - will be replaced during merge
            locals: HashMap::new(),
            register_types: HashMap::new(),
            attributes,
            kind: FunctionKind::MirWrapper, // Stdlib MIR function
            source_location: IrSourceLocation::unknown(),
            next_reg_id: 0,
            type_param_tag_fixups: Vec::new(),
        };

        self.builder.module.functions.insert(func_id, function);
        func_id
    }

    /// Get or register an external runtime function, returning its ID
    ///
    /// This allows calling external runtime functions (like haxe_math_abs) from MIR
    fn get_or_register_extern_function(
        &mut self,
        name: &str,
        mut param_types: Vec<IrType>,
        mut return_type: IrType,
    ) -> IrFunctionId {
        // Override with correct signature if this is a known extern function
        // This is critical for Math functions to get f64 types instead of inferred i64
        if let Some((correct_params, correct_return)) = self.get_extern_function_signature(name) {
            param_types = correct_params;
            return_type = correct_return;
        }

        // FIRST: Check if a MIR wrapper with this name already exists (has blocks)
        // If it does, return that instead of creating an extern
        let existing_mir_wrapper: Option<IrFunctionId> = self
            .builder
            .module
            .functions
            .iter()
            .find(|(_, f)| f.name == name && !f.cfg.blocks.is_empty())
            .map(|(id, _)| *id);

        if let Some(func_id) = existing_mir_wrapper {
            return func_id;
        }

        // Check if we already registered this extern function
        // First, find if it exists and collect info (can't mutate while iterating)
        let existing_func: Option<(IrFunctionId, usize)> = self
            .builder
            .module
            .extern_functions
            .iter()
            .find(|(_, ef)| ef.name == name)
            .map(|(id, ef)| (*id, ef.signature.parameters.len()));

        if let Some((func_id, existing_param_count)) = existing_func {
            let new_param_count = param_types.len();

            // If new signature has MORE parameters, update the existing function
            if new_param_count > existing_param_count {
                debug!(
                    "Updating extern '{}' signature: {} params -> {} params",
                    name, existing_param_count, new_param_count
                );

                // Create updated parameters
                let params = param_types
                    .iter()
                    .enumerate()
                    .map(|(i, ty)| IrParameter {
                        name: format!("arg{}", i),
                        ty: ty.clone(),
                        reg: IrId::new(i as u32),
                        by_ref: false,
                    })
                    .collect();

                let new_signature = IrFunctionSignature {
                    parameters: params,
                    return_type: return_type.clone(),
                    calling_convention: CallingConvention::C,
                    can_throw: false,
                    type_params: vec![],
                    uses_sret: false,
                };

                // Update in extern_functions map
                if let Some(ext_func) = self.builder.module.extern_functions.get_mut(&func_id) {
                    ext_func.signature = new_signature.clone();
                }

                // Update in functions map
                if let Some(func) = self.builder.module.functions.get_mut(&func_id) {
                    func.signature = new_signature;
                }
            }

            return func_id;
        }

        // Also check in functions (extern functions have empty blocks)
        let existing_func: Option<(IrFunctionId, usize)> = self
            .builder
            .module
            .functions
            .iter()
            .filter(|(_, f)| f.name == name && f.cfg.blocks.is_empty())
            .map(|(id, f)| (*id, f.signature.parameters.len()))
            .next();

        if let Some((func_id, existing_param_count)) = existing_func {
            let new_param_count = param_types.len();

            if new_param_count > existing_param_count {
                debug!(
                    "Updating function '{}' signature: {} params -> {} params",
                    name, existing_param_count, new_param_count
                );

                // Create updated parameters
                let params = param_types
                    .iter()
                    .enumerate()
                    .map(|(i, ty)| IrParameter {
                        name: format!("arg{}", i),
                        ty: ty.clone(),
                        reg: IrId::new(i as u32),
                        by_ref: false,
                    })
                    .collect();

                let new_signature = IrFunctionSignature {
                    parameters: params,
                    return_type: return_type.clone(),
                    calling_convention: CallingConvention::C,
                    can_throw: false,
                    type_params: vec![],
                    uses_sret: false,
                };

                // Update in functions map
                if let Some(f) = self.builder.module.functions.get_mut(&func_id) {
                    f.signature = new_signature.clone();
                }

                // Also update in extern_functions if present
                if let Some(ext_func) = self.builder.module.extern_functions.get_mut(&func_id) {
                    ext_func.signature = new_signature;
                }
            }

            return func_id;
        }

        // println!("  ℹ️  Registering extern function: {}", name);

        // Create new extern function entry
        let func_id = IrFunctionId(self.builder.module.next_function_id);
        self.builder.module.next_function_id += 1;

        let params = param_types
            .into_iter()
            .enumerate()
            .map(|(i, ty)| IrParameter {
                name: format!("arg{}", i),
                ty: ty.clone(),
                reg: IrId::new(i as u32),
                by_ref: false,
            })
            .collect();

        let signature = IrFunctionSignature {
            parameters: params,
            return_type: return_type.clone(),
            calling_convention: CallingConvention::C, // External functions use C calling convention
            can_throw: false,
            type_params: vec![],
            uses_sret: false, // No struct return for C functions
        };

        // Create the IrFunction with empty blocks (extern marker)
        let func = crate::ir::functions::IrFunction {
            id: func_id,
            symbol_id: SymbolId::from_raw(0),
            name: name.to_string(),
            qualified_name: None,
            signature: signature.clone(),
            cfg: crate::ir::blocks::IrControlFlowGraph {
                blocks: std::collections::BTreeMap::new(), // Empty blocks = extern
                entry_block: IrBlockId(0),
                next_block_id: 0,
            },
            locals: std::collections::HashMap::new(),
            register_types: std::collections::HashMap::new(),
            attributes: crate::ir::functions::FunctionAttributes::default(),
            kind: crate::ir::functions::FunctionKind::ExternC, // Extern C function
            source_location: IrSourceLocation::unknown(),
            next_reg_id: 0,
            type_param_tag_fixups: Vec::new(),
        };

        // Add to both functions and extern_functions maps
        self.builder.module.functions.insert(func_id, func);

        let extern_func = crate::ir::modules::IrExternFunction {
            id: func_id,
            name: name.to_string(),
            symbol_id: SymbolId::from_raw(0), // Placeholder
            signature,
            source: "rayzor_runtime".to_string(),
        };

        self.builder
            .module
            .extern_functions
            .insert(func_id, extern_func);

        // eprintln!(
        //     "  ℹ️  After registration: module has {} functions, {} extern_functions",
        //     self.builder.module.functions.len(),
        //     self.builder.module.extern_functions.len()
        // );

        func_id
    }

    /// Record an enum for RTTI registration
    /// This collects enum metadata during lowering so it can be registered at module init
    fn record_enum_for_registration(&mut self, enum_symbol_id: SymbolId, type_id: TypeId) {
        // Skip if already recorded
        if self.enums_for_registration.contains_key(&enum_symbol_id) {
            return;
        }

        // Calculate runtime type ID (TypeId + 1000 offset)
        let runtime_type_id = type_id.as_raw() + 1000;

        // Get enum name from symbol table
        let enum_name = self
            .symbol_table
            .get_symbol(enum_symbol_id)
            .and_then(|s| self.string_interner.get(s.name))
            .map(|s| s.to_string())
            .unwrap_or_else(|| format!("Enum_{}", enum_symbol_id.as_raw()));

        // Get variant names from the symbol table's enum_variants map
        let variant_names: Vec<String> =
            if let Some(variant_ids) = self.symbol_table.get_enum_variants(enum_symbol_id) {
                variant_ids
                    .iter()
                    .filter_map(|&var_id| {
                        self.symbol_table
                            .get_symbol(var_id)
                            .and_then(|sym| self.string_interner.get(sym.name))
                            .map(|s| s.to_string())
                    })
                    .collect()
            } else {
                Vec::new()
            };

        debug!(
            "[RTTI] Recording enum '{}' (type_id={}) with variants: {:?}",
            enum_name, runtime_type_id, variant_names
        );

        self.enums_for_registration
            .insert(enum_symbol_id, (runtime_type_id, enum_name, variant_names));
    }

    /// Get collected enum RTTI data for registration
    pub fn get_enums_for_registration(&self) -> &BTreeMap<SymbolId, (u32, String, Vec<String>)> {
        &self.enums_for_registration
    }

    /// Get the number of fields for a specific enum variant
    /// Resolve the discriminant value for an enum variant by name.
    /// Looks up the enum type → symbol → variants, then finds the matching variant index.
    fn resolve_enum_variant_discriminant(
        &self,
        enum_type: TypeId,
        variant_name: InternedString,
    ) -> Option<i64> {
        // Get the enum symbol from the type
        let enum_symbol = self
            .symbol_table
            .get_symbol_from_type(enum_type)
            .or_else(|| {
                // Try unwrapping GenericInstance or Enum type
                let type_table = self.type_table.borrow();
                if let Some(type_info) = type_table.get(enum_type) {
                    match &type_info.kind {
                        crate::tast::TypeKind::GenericInstance { base_type, .. } => {
                            return self.symbol_table.get_symbol_from_type(*base_type);
                        }
                        crate::tast::TypeKind::Enum { symbol_id, .. } => {
                            return Some(*symbol_id);
                        }
                        _ => {}
                    }
                }
                None
            });

        if let Some(enum_sym) = enum_symbol {
            if let Some(variants) = self.symbol_table.get_enum_variants(enum_sym) {
                for (idx, &variant_id) in variants.iter().enumerate() {
                    if let Some(variant_sym) = self.symbol_table.get_symbol(variant_id) {
                        if variant_sym.name == variant_name {
                            return Some(idx as i64);
                        }
                    }
                }
            }
        }

        // Fallback: search ALL enums in symbol table for this variant name
        // This handles cases where the enum_type doesn't map directly to a symbol
        let variant_name_str = self.string_interner.get(variant_name)?;
        for sym in self.symbol_table.all_symbols() {
            if sym.kind == crate::tast::symbols::SymbolKind::EnumVariant {
                let sym_name = self.string_interner.get(sym.name).unwrap_or("");
                if sym_name == variant_name_str {
                    // Found the variant — get its parent enum and find the index
                    if let Some(parent_id) =
                        self.symbol_table.find_parent_enum_for_constructor(sym.id)
                    {
                        if let Some(variants) = self.symbol_table.get_enum_variants(parent_id) {
                            for (idx, &vid) in variants.iter().enumerate() {
                                if vid == sym.id {
                                    return Some(idx as i64);
                                }
                            }
                        }
                    }
                }
            }
        }

        None
    }

    /// Resolve an enum TypeId to its SymbolId
    fn resolve_enum_symbol(&self, enum_type: TypeId) -> Option<SymbolId> {
        self.symbol_table
            .get_symbol_from_type(enum_type)
            .or_else(|| {
                let type_table = self.type_table.borrow();
                if let Some(type_info) = type_table.get(enum_type) {
                    match &type_info.kind {
                        crate::tast::TypeKind::GenericInstance { base_type, .. } => {
                            return self.symbol_table.get_symbol_from_type(*base_type);
                        }
                        crate::tast::TypeKind::Enum { symbol_id, .. } => {
                            return Some(*symbol_id);
                        }
                        _ => {}
                    }
                }
                None
            })
    }

    /// Allocate a boxed enum struct with only a tag (no fields).
    /// Used for parameterless variants of enums that have other parameterized variants.
    /// Layout: [tag:i32][pad:i32] = 8 bytes, returned as ptr bitcast to i64.
    fn build_boxed_enum_tag_only(&mut self, tag_idx: i32) -> Option<IrId> {
        let size_const = self.builder.build_const(IrValue::I64(8))?;
        let alloc_func = self.get_or_register_extern_function(
            "malloc",
            vec![IrType::I64],
            IrType::Ptr(Box::new(IrType::I8)),
        );
        let ptr = self.builder.build_call_direct(
            alloc_func,
            vec![size_const],
            IrType::Ptr(Box::new(IrType::I8)),
        )?;
        let zero_offset = self.builder.build_const(IrValue::I64(0))?;
        let tag_gep =
            self.builder
                .build_gep(ptr, vec![zero_offset], IrType::Ptr(Box::new(IrType::I8)))?;
        let tag_ptr = self
            .builder
            .build_bitcast(tag_gep, IrType::Ptr(Box::new(IrType::I32)))?;
        let tag_val = self.builder.build_const(IrValue::I32(tag_idx))?;
        self.builder.build_store(tag_ptr, tag_val)?;
        self.builder.build_bitcast(ptr, IrType::I64)
    }

    /// Resolve the concrete IrTypes and TypeIds for an enum variant's fields.
    /// Handles generic type parameter substitution (e.g., Result<Int,String>.Ok → [(I32, IntTypeId)]).
    fn get_enum_variant_field_types(
        &self,
        enum_type: TypeId,
        variant_name: InternedString,
    ) -> Vec<(IrType, TypeId)> {
        // Step 1: Resolve enum_type to base enum SymbolId and optional generic type_args
        let (enum_symbol, generic_type_args) = {
            let type_table = self.type_table.borrow();
            if let Some(type_info) = type_table.get(enum_type) {
                match &type_info.kind {
                    crate::tast::TypeKind::GenericInstance {
                        base_type,
                        type_args,
                        ..
                    } => {
                        // Generic enum: Result<Int, String>
                        let base_sym =
                            self.symbol_table
                                .get_symbol_from_type(*base_type)
                                .or_else(|| {
                                    if let Some(base_info) = type_table.get(*base_type) {
                                        if let crate::tast::TypeKind::Enum { symbol_id, .. } =
                                            &base_info.kind
                                        {
                                            return Some(*symbol_id);
                                        }
                                    }
                                    None
                                });
                        (base_sym, Some((*base_type, type_args.clone())))
                    }
                    crate::tast::TypeKind::Enum {
                        symbol_id,
                        type_args,
                        ..
                    } => {
                        // Check if type_args contain concrete types (not TypeParameters)
                        // If so, this IS the concrete instance and we need to find the base enum
                        let has_concrete_args = !type_args.is_empty()
                            && type_args.iter().any(|ta| {
                                type_table
                                    .get(*ta)
                                    .map(|ti| {
                                        !matches!(
                                            ti.kind,
                                            crate::tast::TypeKind::TypeParameter { .. }
                                        )
                                    })
                                    .unwrap_or(false)
                            });
                        if has_concrete_args {
                            // Find the base enum type (with TypeParameter type_args) via symbol
                            let base_type = self
                                .symbol_table
                                .get_symbol(*symbol_id)
                                .map(|sym| sym.type_id)
                                .unwrap_or(enum_type);
                            (Some(*symbol_id), Some((base_type, type_args.clone())))
                        } else {
                            (Some(*symbol_id), None)
                        }
                    }
                    _ => {
                        let sym = self.symbol_table.get_symbol_from_type(enum_type);
                        (sym, None)
                    }
                }
            } else {
                (self.symbol_table.get_symbol_from_type(enum_type), None)
            }
        };

        let enum_sym = match enum_symbol {
            Some(s) => s,
            None => {
                return vec![];
            }
        };

        // Step 2: Find the variant by name and get its field TypeIds from HIR
        let variant_name_str = self.string_interner.get(variant_name).unwrap_or("");
        for (_type_id, type_decl) in self.current_hir_types.iter() {
            if let HirTypeDecl::Enum(enum_decl) = type_decl {
                if enum_decl.symbol_id == enum_sym {
                    for variant in &enum_decl.variants {
                        let vname = self.string_interner.get(variant.name).unwrap_or("");
                        if vname == variant_name_str {
                            return variant
                                .fields
                                .iter()
                                .map(|field| {
                                    let ir_type =
                                        self.resolve_field_type(field.ty, &generic_type_args);
                                    let type_id =
                                        self.resolve_field_type_id(field.ty, &generic_type_args);
                                    (ir_type, type_id)
                                })
                                .collect();
                        }
                    }
                }
            }
        }

        // Step 3: Fallback — symbol table lookup for imported enums
        if let Some(variants) = self.symbol_table.get_enum_variants(enum_sym) {
            for &variant_id in variants.iter() {
                if let Some(variant_sym) = self.symbol_table.get_symbol(variant_id) {
                    if variant_sym.name == variant_name {
                        let type_table = self.type_table.borrow();
                        if let Some(type_info) = type_table.get(variant_sym.type_id) {
                            if let crate::tast::core::TypeKind::Function { params, .. } =
                                &type_info.kind
                            {
                                return params
                                    .iter()
                                    .map(|p| {
                                        let ir_type =
                                            self.resolve_field_type(*p, &generic_type_args);
                                        let type_id =
                                            self.resolve_field_type_id(*p, &generic_type_args);
                                        (ir_type, type_id)
                                    })
                                    .collect();
                            }
                        }
                    }
                }
            }
        }

        vec![]
    }

    /// Resolve a field's TypeId to an IrType, substituting generic type parameters
    /// if generic_info is provided (base_type + concrete type_args).
    fn resolve_field_type(
        &self,
        field_type_id: TypeId,
        generic_info: &Option<(TypeId, Vec<TypeId>)>,
    ) -> IrType {
        let type_table = self.type_table.borrow();

        // Check if this TypeId is a type parameter that needs substitution
        if let Some(type_info) = type_table.get(field_type_id) {
            if let crate::tast::TypeKind::TypeParameter { symbol_id, .. } = &type_info.kind {
                if let Some((base_type, concrete_args)) = generic_info {
                    // Find which index this type parameter corresponds to in the base enum's type_args
                    if let Some(base_info) = type_table.get(*base_type) {
                        let base_type_args = match &base_info.kind {
                            crate::tast::TypeKind::Enum { type_args, .. } => type_args,
                            _ => return IrType::I64,
                        };
                        for (idx, &param_type_id) in base_type_args.iter().enumerate() {
                            if let Some(param_info) = type_table.get(param_type_id) {
                                if let crate::tast::TypeKind::TypeParameter {
                                    symbol_id: param_sym,
                                    ..
                                } = &param_info.kind
                                {
                                    if param_sym == symbol_id {
                                        // Found match — substitute with concrete type
                                        if let Some(&concrete_type_id) = concrete_args.get(idx) {
                                            drop(type_table);
                                            return self.convert_type(concrete_type_id);
                                        }
                                    }
                                }
                            }
                        }
                        // Positional lookup failed (concrete_args may be shorter than base type_args).
                        // If there's exactly 1 concrete arg, use it as the substitution.
                        if concrete_args.len() == 1 {
                            let concrete_id = concrete_args[0];
                            if let Some(ci) = type_table.get(concrete_id) {
                                if !matches!(ci.kind, crate::tast::TypeKind::TypeParameter { .. }) {
                                    drop(type_table);
                                    return self.convert_type(concrete_id);
                                }
                            }
                        }
                    }
                }
                // Unresolved type parameter — treat as I64
                return IrType::I64;
            }
        }

        // Not a type parameter — convert directly
        drop(type_table);
        self.convert_type(field_type_id)
    }

    /// Like resolve_field_type but returns the concrete TypeId instead of IrType.
    fn resolve_field_type_id(
        &self,
        field_type_id: TypeId,
        generic_info: &Option<(TypeId, Vec<TypeId>)>,
    ) -> TypeId {
        let type_table = self.type_table.borrow();
        if let Some(type_info) = type_table.get(field_type_id) {
            if let crate::tast::TypeKind::TypeParameter { symbol_id, .. } = &type_info.kind {
                if let Some((base_type, concrete_args)) = generic_info {
                    if let Some(base_info) = type_table.get(*base_type) {
                        let base_type_args = match &base_info.kind {
                            crate::tast::TypeKind::Enum { type_args, .. } => type_args,
                            _ => return field_type_id,
                        };
                        for (idx, &param_type_id) in base_type_args.iter().enumerate() {
                            if let Some(param_info) = type_table.get(param_type_id) {
                                if let crate::tast::TypeKind::TypeParameter {
                                    symbol_id: param_sym,
                                    ..
                                } = &param_info.kind
                                {
                                    if param_sym == symbol_id {
                                        if let Some(&concrete_type_id) = concrete_args.get(idx) {
                                            return concrete_type_id;
                                        }
                                    }
                                }
                            }
                        }
                        if concrete_args.len() == 1 {
                            let concrete_id = concrete_args[0];
                            if let Some(ci) = type_table.get(concrete_id) {
                                if !matches!(ci.kind, crate::tast::TypeKind::TypeParameter { .. }) {
                                    return concrete_id;
                                }
                            }
                        }
                    }
                }
            }
        }
        field_type_id
    }

    fn get_enum_variant_field_count(&self, enum_symbol: SymbolId, variant_idx: usize) -> usize {
        // First check current module's HIR types
        for (_type_id, type_decl) in self.current_hir_types.iter() {
            if let HirTypeDecl::Enum(enum_decl) = type_decl {
                if enum_decl.symbol_id == enum_symbol {
                    if let Some(variant) = enum_decl.variants.get(variant_idx) {
                        return variant.fields.len();
                    }
                }
            }
        }
        // Fallback: check symbol table for enums from other modules (e.g. StdTypes.hx)
        if let Some(variants) = self.symbol_table.get_enum_variants(enum_symbol) {
            if let Some(&variant_id) = variants.get(variant_idx) {
                if let Some(variant_sym) = self.symbol_table.get_symbol(variant_id) {
                    let type_table = self.type_table.borrow();
                    if let Some(type_info) = type_table.get(variant_sym.type_id) {
                        if let crate::tast::core::TypeKind::Function { params, .. } =
                            &type_info.kind
                        {
                            return params.len();
                        }
                    }
                }
            }
        }
        0 // Default: no fields
    }

    /// Check if an enum has any parameterized variants (requires boxed representation)
    fn enum_is_boxed(&self, enum_symbol: SymbolId) -> bool {
        // First check current module's HIR types
        for (_type_id, type_decl) in self.current_hir_types.iter() {
            if let HirTypeDecl::Enum(enum_decl) = type_decl {
                if enum_decl.symbol_id == enum_symbol {
                    return enum_decl.variants.iter().any(|v| !v.fields.is_empty());
                }
            }
        }
        // Also check by name — generic instantiation may create different SymbolIds
        if let Some(sym) = self.symbol_table.get_symbol(enum_symbol) {
            let enum_name = self.string_interner.get(sym.name).unwrap_or("");
            for (_type_id, type_decl) in self.current_hir_types.iter() {
                if let HirTypeDecl::Enum(enum_decl) = type_decl {
                    let decl_name = self.string_interner.get(enum_decl.name).unwrap_or("");
                    if decl_name == enum_name {
                        return enum_decl.variants.iter().any(|v| !v.fields.is_empty());
                    }
                }
            }
        }
        // Fallback: check symbol table for enums from other modules (e.g. StdTypes.hx)
        if let Some(variants) = self.symbol_table.get_enum_variants(enum_symbol) {
            let type_table = self.type_table.borrow();
            for &variant_id in variants {
                if let Some(variant_sym) = self.symbol_table.get_symbol(variant_id) {
                    // A variant with parameters has a Function type
                    if let Some(type_info) = type_table.get(variant_sym.type_id) {
                        if matches!(type_info.kind, crate::tast::core::TypeKind::Function { .. }) {
                            return true;
                        }
                    }
                }
            }
        }
        false
    }

    /// Extract the runtime type_id (as u32) from an expression that represents an enum value.
    /// Inspects the expression to find the enum variant symbol, then looks up the parent enum.
    fn extract_enum_type_id_from_expr(&self, expr: &HirExpr) -> Option<u32> {
        // First, try to resolve from the expression's type
        let enum_sym = self.resolve_enum_symbol(expr.ty);
        if let Some(sym_id) = enum_sym {
            if let Some(sym) = self.symbol_table.get_symbol(sym_id) {
                return Some(sym.type_id.0);
            }
        }

        // Try to find enum type from the expression kind
        match &expr.kind {
            HirExprKind::Variable { symbol, .. } => {
                if let Some(sym) = self.symbol_table.get_symbol(*symbol) {
                    if sym.kind == crate::tast::SymbolKind::EnumVariant {
                        // Find parent enum
                        if let Some(parent) =
                            self.symbol_table.find_parent_enum_for_constructor(*symbol)
                        {
                            if let Some(parent_sym) = self.symbol_table.get_symbol(parent) {
                                return Some(parent_sym.type_id.0);
                            }
                        }
                    }
                }
            }
            HirExprKind::Field { field, .. } => {
                if let Some(sym) = self.symbol_table.get_symbol(*field) {
                    if sym.kind == crate::tast::SymbolKind::EnumVariant {
                        if let Some(parent) =
                            self.symbol_table.find_parent_enum_for_constructor(*field)
                        {
                            if let Some(parent_sym) = self.symbol_table.get_symbol(parent) {
                                return Some(parent_sym.type_id.0);
                            }
                        }
                    }
                }
            }
            _ => {}
        }

        None
    }

    /// Return true for runtime functions that expect a hidden enum `type_id: i32`.
    fn runtime_func_needs_enum_type_id(runtime_func: &str) -> bool {
        matches!(
            runtime_func,
            "haxe_type_enum_constructor"
                | "haxe_type_enum_parameters"
                | "haxe_type_get_enum"
                | "haxe_type_enum_eq"
        )
    }

    /// Try to resolve enum type id from call arguments for runtime enum helpers.
    /// For `enumEq(a, b)`, prefer the first arg then second arg.
    fn extract_enum_type_id_from_args(&self, runtime_func: &str, args: &[HirExpr]) -> Option<u32> {
        if args.is_empty() {
            return None;
        }

        let preferred_indices: &[usize] = if runtime_func == "haxe_type_enum_eq" {
            &[0, 1]
        } else {
            &[0]
        };

        for &idx in preferred_indices {
            if let Some(arg) = args.get(idx) {
                if let Some(type_id) = self.extract_enum_type_id_from_expr(arg) {
                    return Some(type_id);
                }
            }
        }

        for arg in args {
            if let Some(type_id) = self.extract_enum_type_id_from_expr(arg) {
                return Some(type_id);
            }
        }

        None
    }

    /// Append hidden enum type id to runtime enum helper calls.
    /// Falls back to `0` when type inference fails to preserve ABI parity (no arg-count mismatch).
    fn inject_hidden_enum_type_id_arg(
        &mut self,
        runtime_func: &str,
        args: &[HirExpr],
        arg_regs: &mut Vec<IrId>,
    ) {
        if !Self::runtime_func_needs_enum_type_id(runtime_func) {
            return;
        }

        let type_id = self.extract_enum_type_id_from_args(runtime_func, args);
        let tid_reg = match type_id {
            Some(type_id) => self.builder.build_const(IrValue::I32(type_id as i32)),
            None => {
                debug!(
                    "[ENUM TYPE_ID] Could not resolve hidden enum type_id for {}, using 0 fallback",
                    runtime_func
                );
                self.builder.build_const(IrValue::I32(0))
            }
        };

        if let Some(tid_reg) = tid_reg {
            arg_regs.push(tid_reg);
        }
    }

    /// Resolve function parameter/return TypeIds from a function-like TypeId.
    /// Follows type aliases until a concrete `TypeKind::Function` is found.
    fn resolve_function_type_signature(&self, type_id: TypeId) -> Option<(Vec<TypeId>, TypeId)> {
        use crate::tast::TypeKind;

        let type_table = self.type_table.borrow();
        let mut current = type_id;
        let mut visited = BTreeSet::new();
        loop {
            if !visited.insert(current) {
                // Alias cycle detected.
                return None;
            }
            let type_info = type_table.get(current)?;
            match &type_info.kind {
                TypeKind::Function {
                    params,
                    return_type,
                    ..
                } => return Some((params.clone(), *return_type)),
                TypeKind::TypeAlias { target_type, .. } => current = *target_type,
                _ => return None,
            }
        }
    }

    /// Lower a synthetic Reflect.makeVarArgs bridge.
    /// Current parity path preserves the original function value so it can
    /// still be invoked via Reflect.callMethod(args-array form).
    fn lower_reflect_make_var_args(
        &mut self,
        args: &[HirExpr],
        _result_type: IrType,
        location: SourceLocation,
    ) -> Option<IrId> {
        let Some(func_expr) = args.first() else {
            self.add_error("Reflect.makeVarArgs requires one argument", location);
            return None;
        };

        let func_val = self.lower_expression(func_expr)?;
        // Reflect.makeVarArgs returns Dynamic in stdlib API.
        // Box function/closure values as TYPE_FUNCTION for Reflect.isFunction parity.
        self.box_value_for_dynamic(func_val, func_expr.ty)
            .or(Some(func_val))
    }

    /// Lower Reflect.callMethod(o, func, argsArray) without a runtime trampoline by
    /// generating an indirect call from compile-time function type information.
    fn lower_reflect_call_method(
        &mut self,
        args: &[HirExpr],
        result_type: IrType,
        location: SourceLocation,
    ) -> Option<IrId> {
        if args.len() < 3 {
            self.add_error(
                "Reflect.callMethod requires (object, function, argsArray)",
                location,
            );
            return None;
        }

        let func_expr = &args[1];
        let args_array_expr = &args[2];
        let func_ptr = if let HirExprKind::Variable { symbol, .. } = &func_expr.kind {
            let resolved_func = self.get_function_id(symbol).or_else(|| {
                self.symbol_table
                    .get_symbol(*symbol)
                    .and_then(|sym| self.string_interner.get(sym.name))
                    .and_then(|name| {
                        self.find_function_by_name(name)
                            .or_else(|| self.find_external_function_by_name(name))
                    })
            });

            if let Some(func_id) = resolved_func {
                // CallIndirect expects a closure object {fn_ptr, env_ptr}, not a raw fn address.
                self.builder
                    .build_function_ref(func_id)
                    .or_else(|| self.lower_expression(func_expr))?
            } else {
                self.lower_expression(func_expr)?
            }
        } else {
            self.lower_expression(func_expr)?
        };

        // Fallback path for makeVarArgs-style functions where the function type is
        // erased/dynamic: call with a single Array argument.
        let fallback_single_array_call = |this: &mut Self| -> Option<IrId> {
            let arr_arg = this.lower_expression(args_array_expr)?;
            let sig = IrType::Function {
                params: vec![this.convert_type(args_array_expr.ty)],
                return_type: Box::new(result_type.clone()),
                varargs: false,
            };
            this.builder
                .build_call_indirect(func_ptr, vec![arr_arg], sig)
        };

        let lower_with_ir_signature = |this: &mut Self,
                                       param_ir_types: Vec<IrType>,
                                       return_ir: IrType|
         -> Option<IrId> {
            let args_array_reg = this.lower_expression(args_array_expr)?;
            let args_array_ptr =
                if let Some(actual_ty) = this.builder.get_register_type(args_array_reg) {
                    if actual_ty == IrType::Ptr(Box::new(IrType::Void)) {
                        args_array_reg
                    } else {
                        this.builder
                            .build_cast(
                                args_array_reg,
                                actual_ty,
                                IrType::Ptr(Box::new(IrType::Void)),
                            )
                            .unwrap_or(args_array_reg)
                    }
                } else {
                    args_array_reg
                };

            let call_args: Vec<IrId> = if param_ir_types.len() == 1 {
                // makeVarArgs-style callback: pass args array directly.
                let target_ty = param_ir_types[0].clone();
                let arr_arg =
                    if let Some(actual_ty) = this.builder.get_register_type(args_array_ptr) {
                        if actual_ty == target_ty {
                            args_array_ptr
                        } else {
                            this.builder
                                .build_cast(args_array_ptr, actual_ty, target_ty.clone())
                                .unwrap_or(args_array_ptr)
                        }
                    } else {
                        args_array_ptr
                    };
                vec![arr_arg]
            } else {
                let array_get_i64_fn = this.get_or_register_extern_function(
                    "haxe_array_get_i64",
                    vec![IrType::Ptr(Box::new(IrType::Void)), IrType::I64],
                    IrType::I64,
                );

                let mut unpacked = Vec::with_capacity(param_ir_types.len());
                for (idx, target_ty) in param_ir_types.iter().enumerate() {
                    let index_reg = this.builder.build_const(IrValue::I64(idx as i64))?;
                    let raw_val = this.builder.build_call_direct(
                        array_get_i64_fn,
                        vec![args_array_ptr, index_reg],
                        IrType::I64,
                    )?;
                    let coerced = match target_ty {
                        IrType::I64 => Some(raw_val),
                        IrType::F64 => this.builder.build_bitcast(raw_val, IrType::F64),
                        IrType::F32 => {
                            let as_i32 =
                                this.builder.build_cast(raw_val, IrType::I64, IrType::I32)?;
                            this.builder.build_bitcast(as_i32, IrType::F32)
                        }
                        _ => this
                            .builder
                            .build_cast(raw_val, IrType::I64, target_ty.clone()),
                    }
                    .unwrap_or(raw_val);
                    unpacked.push(coerced);
                }
                unpacked
            };

            let call_sig = IrType::Function {
                params: param_ir_types,
                return_type: Box::new(return_ir.clone()),
                varargs: false,
            };
            let call_result = this
                .builder
                .build_call_indirect(func_ptr, call_args, call_sig)?;

            if return_ir == result_type {
                return Some(call_result);
            }

            if matches!(result_type, IrType::Ptr(ref inner) if matches!(inner.as_ref(), IrType::Void))
            {
                if let Some(boxed) = this.box_primitive_to_dynamic(call_result, return_ir.clone()) {
                    return Some(boxed);
                }
            }

            if let Some(casted) =
                this.builder
                    .build_cast(call_result, return_ir.clone(), result_type.clone())
            {
                return Some(casted);
            }

            Some(call_result)
        };

        if let Some(IrType::Function {
            params,
            return_type,
            ..
        }) = self.builder.get_register_type(func_ptr)
        {
            return lower_with_ir_signature(self, params, *return_type);
        }

        let Some((param_type_ids, return_type_id)) =
            self.resolve_function_type_signature(func_expr.ty)
        else {
            return fallback_single_array_call(self);
        };

        // Special-case Array<Dynamic> callback shape (used by makeVarArgs): pass args array directly.
        if param_type_ids.len() == 1 {
            let type_table = self.type_table.borrow();
            let takes_array = type_table
                .get(param_type_ids[0])
                .map(|ti| matches!(ti.kind, crate::tast::TypeKind::Array { .. }))
                .unwrap_or(false);
            drop(type_table);
            if takes_array {
                let arr_arg = self.lower_expression(args_array_expr)?;
                let call_sig = IrType::Function {
                    params: vec![self.convert_type(param_type_ids[0])],
                    return_type: Box::new(self.convert_type(return_type_id)),
                    varargs: false,
                };
                let result = self
                    .builder
                    .build_call_indirect(func_ptr, vec![arr_arg], call_sig)?;
                if self.convert_type(return_type_id) == result_type {
                    return Some(result);
                }
                if matches!(result_type, IrType::Ptr(ref inner) if matches!(inner.as_ref(), IrType::Void))
                {
                    if let Some(boxed) = self.box_value_for_dynamic(result, return_type_id) {
                        return Some(boxed);
                    }
                }
                if let Some(casted) = self.builder.build_cast(
                    result,
                    self.convert_type(return_type_id),
                    result_type.clone(),
                ) {
                    return Some(casted);
                }
                return Some(result);
            }
        }

        // General typed path: unpack argsArray[i] as raw i64 slots then coerce into parameter types.
        let mut call_args: Vec<IrId> = Vec::new();
        let args_array_reg = self.lower_expression(args_array_expr)?;
        let args_array_ptr = if let Some(actual_ty) = self.builder.get_register_type(args_array_reg)
        {
            if actual_ty == IrType::Ptr(Box::new(IrType::Void)) {
                args_array_reg
            } else {
                self.builder
                    .build_cast(
                        args_array_reg,
                        actual_ty,
                        IrType::Ptr(Box::new(IrType::Void)),
                    )
                    .unwrap_or(args_array_reg)
            }
        } else {
            args_array_reg
        };

        let array_get_i64_fn = self.get_or_register_extern_function(
            "haxe_array_get_i64",
            vec![IrType::Ptr(Box::new(IrType::Void)), IrType::I64],
            IrType::I64,
        );

        for (idx, param_ty_id) in param_type_ids.iter().enumerate() {
            let index_reg = self.builder.build_const(IrValue::I64(idx as i64))?;
            let raw_val = self.builder.build_call_direct(
                array_get_i64_fn,
                vec![args_array_ptr, index_reg],
                IrType::I64,
            )?;
            let coerced = self
                .coerce_from_i64(raw_val, *param_ty_id)
                .unwrap_or(raw_val);
            call_args.push(coerced);
        }

        let func_signature = IrType::Function {
            params: param_type_ids
                .iter()
                .map(|ty| self.convert_type(*ty))
                .collect(),
            return_type: Box::new(self.convert_type(return_type_id)),
            varargs: false,
        };

        let call_result = self
            .builder
            .build_call_indirect(func_ptr, call_args, func_signature)?;

        let actual_return_ir = self.convert_type(return_type_id);
        if actual_return_ir == result_type {
            return Some(call_result);
        }

        // callMethod returns Dynamic in stdlib API; ensure primitive returns are boxed.
        if matches!(result_type, IrType::Ptr(ref inner) if matches!(inner.as_ref(), IrType::Void)) {
            if let Some(boxed) = self.box_value_for_dynamic(call_result, return_type_id) {
                return Some(boxed);
            }
        }

        if let Some(casted) =
            self.builder
                .build_cast(call_result, actual_return_ir, result_type.clone())
        {
            return Some(casted);
        }

        Some(call_result)
    }

    /// Lower `Type.typeof(v)` with ValueType parity.
    ///
    /// Runtime `haxe_type_typeof` returns an ordinal (`i32`). When the call
    /// result is used as `ValueType`, we build the actual enum value through
    /// `haxe_type_typeof_value`.
    fn lower_type_typeof_call(&mut self, args: &[HirExpr], _result_type: IrType) -> Option<IrId> {
        if args.len() != 1 {
            return None;
        }
        let value_reg = self.lower_expression(&args[0])?;
        let actual_ty = self
            .builder
            .get_register_type(value_reg)
            .unwrap_or_else(|| self.convert_type(args[0].ty));
        let dynamic_ptr_ty = IrType::Ptr(Box::new(IrType::U8));
        let value_dyn = if actual_ty == dynamic_ptr_ty {
            value_reg
        } else {
            self.box_value_for_dynamic(value_reg, args[0].ty)?
        };

        // Always use the boxed ValueType path (haxe_type_typeof_value) so that
        // parameterized variants like TClass(c) and TEnum(e) carry their type_id
        // payload. The I32 ordinal path loses this information, causing pattern
        // matching like `case TEnum(_):` to fail.
        let value_fn = self.get_or_register_extern_function(
            "haxe_type_typeof_value",
            vec![dynamic_ptr_ty.clone()],
            IrType::I64,
        );
        let result = self
            .builder
            .build_call_direct(value_fn, vec![value_dyn], IrType::I64)?;
        // The I64 return is actually a pointer to a heap-allocated boxed enum.
        // Cast to Ptr(U8) so pattern matching treats it as a boxed enum pointer
        // rather than a plain integer (which would skip the tag-load path).
        self.builder.build_cast(result, IrType::I64, dynamic_ptr_ty)
    }

    fn is_type_typeof_symbol(&self, symbol_id: SymbolId) -> bool {
        let Some(sym) = self.symbol_table.get_symbol(symbol_id) else {
            return false;
        };

        let name = self.string_interner.get(sym.name);
        if name == Some("haxe_type_typeof") {
            return true;
        }

        if let Some(native) = sym.native_name.and_then(|n| self.string_interner.get(n)) {
            if native == "haxe_type_typeof" {
                return true;
            }
        }

        if name != Some("typeof") {
            return false;
        }

        if let Some(qn) = sym
            .qualified_name
            .and_then(|qn| self.string_interner.get(qn))
        {
            if qn == "Type.typeof" || qn.ends_with(".Type.typeof") {
                return true;
            }
        }

        // Some lowering paths keep only the bare method name.
        true
    }

    fn is_type_typeof_callee_expr(&self, expr: &HirExpr) -> bool {
        match &expr.kind {
            HirExprKind::Variable { symbol, .. } => self.is_type_typeof_symbol(*symbol),
            HirExprKind::Field { field, .. } => self.is_type_typeof_symbol(*field),
            HirExprKind::Cast { expr, .. } => self.is_type_typeof_callee_expr(expr),
            _ => false,
        }
    }

    fn is_value_type_type_id(&self, type_id: TypeId) -> bool {
        let resolved = self.resolve_through_aliases(type_id);
        let type_table = self.type_table.borrow();
        let Some(type_info) = type_table.get(resolved) else {
            return false;
        };
        let TypeKind::Enum { symbol_id, .. } = type_info.kind else {
            return false;
        };
        drop(type_table);

        let Some(sym) = self.symbol_table.get_symbol(symbol_id) else {
            return false;
        };
        let name = self.string_interner.get(sym.name);
        if name == Some("ValueType") {
            return true;
        }
        if let Some(qn) = sym
            .qualified_name
            .and_then(|qn| self.string_interner.get(qn))
        {
            return qn == "ValueType" || qn.ends_with(".ValueType");
        }
        false
    }

    fn trace_typeof_inner_arg<'b>(&self, expr: &'b HirExpr) -> Option<&'b HirExpr> {
        match &expr.kind {
            HirExprKind::Cast { expr: inner, .. } => self.trace_typeof_inner_arg(inner),
            HirExprKind::Call { callee, args, .. } => {
                if args.len() == 1 && self.is_type_typeof_callee_expr(callee) {
                    return args.first();
                }
                None
            }
            _ => None,
        }
    }

    fn expr_is_value_type_expr(&self, expr: &HirExpr) -> bool {
        if self.trace_typeof_inner_arg(expr).is_some() {
            return true;
        }

        match &expr.kind {
            HirExprKind::Cast { expr: inner, .. } => self.expr_is_value_type_expr(inner),
            HirExprKind::Variable { symbol, .. } => {
                self.value_type_symbols.contains(symbol) || self.is_value_type_type_id(expr.ty)
            }
            _ => self.is_value_type_type_id(expr.ty),
        }
    }

    /// Infer type info for Reflect.compare args.
    /// Returns:
    /// - `Some(Ok(tag))` for concrete types (Int=1, Bool=2, Float=4, String=5)
    /// - `Some(Err(type_param_name))` for generic type parameters (needs fixup)
    /// - `None` for Dynamic/unknown (fall through to boxing path)
    fn infer_reflect_compare_type_info(&self, args: &[HirExpr]) -> Option<Result<i32, String>> {
        use crate::tast::core::TypeKind;
        let first = &args[0];
        let type_table = self.type_table.borrow();
        debug!(
            "[REFLECT_COMPARE_TYPE] first arg ty={:?}, type_info={:?}",
            first.ty,
            type_table.get(first.ty).map(|ti| format!("{:?}", ti.kind))
        );
        if let Some(ti) = type_table.get(first.ty) {
            match &ti.kind {
                TypeKind::Int => return Some(Ok(1)),
                TypeKind::Float => return Some(Ok(4)),
                TypeKind::Bool => return Some(Ok(2)),
                TypeKind::String => return Some(Ok(5)),
                TypeKind::TypeParameter { symbol_id, .. } => {
                    if let Some(sym) = self.symbol_table.get_symbol(*symbol_id) {
                        if let Some(name_str) = self.string_interner.get(sym.name) {
                            return Some(Err(name_str.to_string()));
                        }
                    }
                    return Some(Err("T".to_string()));
                }
                TypeKind::Dynamic => {
                    // Params are Dynamic — infer from expression kind
                    if let HirExprKind::Literal(crate::ir::hir::HirLiteral::String(_)) = &first.kind
                    {
                        return Some(Ok(5));
                    }
                    // Check if the expression is a variable with a known concrete type
                    if let HirExprKind::Variable { symbol, .. } = &first.kind {
                        if let Some(sym) = self.symbol_table.get_symbol(*symbol) {
                            if let Some(sym_ti) = type_table.get(sym.type_id) {
                                match &sym_ti.kind {
                                    TypeKind::Int => return Some(Ok(1)),
                                    TypeKind::Float => return Some(Ok(4)),
                                    TypeKind::Bool => return Some(Ok(2)),
                                    TypeKind::String => return Some(Ok(5)),
                                    _ => {}
                                }
                            }
                        }
                    }
                }
                _ => {}
            }
        }
        None
    }

    fn convert_value_type_to_string(&mut self, value: IrId) -> Option<IrId> {
        let string_ptr_ty = IrType::Ptr(Box::new(IrType::String));
        let conv_fn = self.get_or_register_extern_function(
            "haxe_string_from_value_type",
            vec![IrType::I64],
            string_ptr_ty.clone(),
        );
        self.builder
            .build_call_direct(conv_fn, vec![value], string_ptr_ty)
    }

    fn try_lower_special_runtime_call(
        &mut self,
        runtime_func: &str,
        args: &[HirExpr],
        result_type: IrType,
        location: SourceLocation,
    ) -> Option<Option<IrId>> {
        match runtime_func {
            "haxe_reflect_call_method" | "Reflect.callMethod" => {
                Some(self.lower_reflect_call_method(args, result_type, location))
            }
            "haxe_reflect_make_var_args" | "Reflect.makeVarArgs" => {
                Some(self.lower_reflect_make_var_args(args, result_type, location))
            }
            "haxe_type_typeof" | "Type.typeof" => {
                Some(self.lower_type_typeof_call(args, result_type))
            }
            // Reflect.isFunction / Reflect.isObject need boxed DynamicValue* args
            // to inspect the type_id tag. Raw function/class pointers lack this tag,
            // so we must box via box_value_for_dynamic (same as Type.typeof).
            "haxe_reflect_is_function" | "haxe_reflect_is_object" => {
                if args.len() != 1 {
                    return None;
                }
                let value_reg = self.lower_expression(&args[0])?;
                let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                let value_dyn = if matches!(
                    self.builder.get_register_type(value_reg),
                    Some(IrType::Ptr(ref inner)) if matches!(**inner, IrType::U8)
                ) {
                    // Already a PtrU8 (likely already boxed Dynamic) — pass through
                    value_reg
                } else {
                    self.box_value_for_dynamic(value_reg, args[0].ty)?
                };
                let func_id = self.get_or_register_extern_function(
                    runtime_func,
                    vec![ptr_u8.clone()],
                    IrType::Bool,
                );
                Some(
                    self.builder
                        .build_call_direct(func_id, vec![value_dyn], IrType::Bool),
                )
            }
            // Reflect.compare: use haxe_reflect_compare_typed with a type tag
            // to avoid boxing-based comparison (which loses type info for generics)
            "haxe_reflect_compare" => {
                if args.len() >= 2 {
                    let type_info = self.infer_reflect_compare_type_info(args);
                    if let Some(info) = type_info {
                        let mut arg_regs = Vec::new();
                        for arg in args.iter() {
                            if let Some(reg) = self.lower_expression(arg) {
                                let reg_ty =
                                    self.builder.get_register_type(reg).unwrap_or(IrType::I64);
                                let final_reg = if reg_ty != IrType::I64 {
                                    self.builder
                                        .build_cast(reg, reg_ty, IrType::I64)
                                        .unwrap_or(reg)
                                } else {
                                    reg
                                };
                                arg_regs.push(final_reg);
                            }
                        }
                        let tag_reg = match info {
                            Ok(tag_value) => self.builder.build_const(IrValue::I32(tag_value))?,
                            Err(type_param_name) => {
                                let tag = self.builder.build_const(IrValue::I32(0))?;
                                if let Some(func) = self.builder.current_function_mut() {
                                    func.type_param_tag_fixups.push((tag, type_param_name));
                                }
                                tag
                            }
                        };
                        arg_regs.push(tag_reg);
                        let extern_func_id = self.get_or_register_extern_function(
                            "haxe_reflect_compare_typed",
                            vec![IrType::I64, IrType::I64, IrType::I32],
                            result_type.clone(),
                        );
                        return Some(self.builder.build_call_direct(
                            extern_func_id,
                            arg_regs,
                            result_type,
                        ));
                    }
                }
                None
            }
            _ => None,
        }
    }

    /// Try to dispatch an enum built-in method (getIndex, getName, getParameters).
    /// Uses runtime mapping registered in runtime_mapping.rs.
    /// Injects compile-time constants (type_id, is_boxed) as extra params.
    fn try_dispatch_enum_method(
        &mut self,
        method_symbol: SymbolId,
        args: &[HirExpr],
    ) -> Option<Option<IrId>> {
        let receiver = &args[0];
        let enum_sym_id = self.resolve_enum_symbol(receiver.ty)?;

        // Look up the method in stdlib mapping under "Enum" class
        let method_name = self
            .symbol_table
            .get_symbol(method_symbol)
            .and_then(|s| self.string_interner.get(s.name))
            .map(|s| s.to_string())?;

        let (_, runtime_func) = self
            .stdlib_mapping
            .find_by_name("Enum", &method_name)
            .map(|(sig, call)| (sig.method, call.runtime_name))?;

        // Gather compile-time enum metadata
        let is_boxed = self.enum_is_boxed(enum_sym_id);
        let enum_type_id = self
            .symbol_table
            .get_symbol(enum_sym_id)
            .map(|s| s.type_id.0 as i32)
            .unwrap_or(0);

        // Lower the receiver (the enum value)
        let receiver_reg = self.lower_expression(receiver)?;
        let is_boxed_const =
            self.builder
                .build_const(IrValue::I32(if is_boxed { 1 } else { 0 }))?;

        // Build args and return type from the runtime mapping's param_types/return_type.
        // getIndex takes (value, is_boxed), getName/getParameters take (type_id, value, is_boxed).
        let (call_args, param_types, return_type) = if runtime_func == "haxe_enum_get_index" {
            (
                vec![receiver_reg, is_boxed_const],
                vec![IrType::I64, IrType::I32],
                IrType::I64,
            )
        } else {
            let type_id_const = self.builder.build_const(IrValue::I32(enum_type_id))?;
            let ret_ty = if runtime_func == "haxe_enum_get_name" {
                IrType::Ptr(Box::new(IrType::String))
            } else {
                // getParameters returns opaque array pointer
                IrType::Ptr(Box::new(IrType::Void))
            };
            (
                vec![type_id_const, receiver_reg, is_boxed_const],
                vec![IrType::I32, IrType::I64, IrType::I32],
                ret_ty,
            )
        };

        let func_id =
            self.get_or_register_extern_function(runtime_func, param_types, return_type.clone());
        let result = self
            .builder
            .build_call_direct(func_id, call_args, return_type)?;
        Some(Some(result))
    }

    /// Lower a HIR expression to MIR value
    fn lower_expression(&mut self, expr: &HirExpr) -> Option<IrId> {
        // DEBUG: Check if this is Field expression being lowered
        if matches!(&expr.kind, HirExprKind::Field { .. }) {
            debug!("[lower_expression] START - Field expression");
        }

        // Set source location for debugging
        self.builder
            .set_source_location(self.convert_source_location(&expr.source_location));

        let result = match &expr.kind {
            HirExprKind::Literal(lit) => self.lower_literal(lit, expr.ty),

            HirExprKind::Variable { symbol, .. } => {
                // Check if this is a class/enum used as a value (e.g., Type.getClassName(Animal))
                // Must be before function reference check since class symbols may also map to constructors
                if let Some(sym) = self.symbol_table.get_symbol(*symbol) {
                    use crate::tast::SymbolKind;
                    if sym.kind == SymbolKind::Class {
                        // Class runtime type_id = SymbolId.as_raw() (matches TypeId::from_raw in tast_to_hir)
                        let runtime_type_id = sym.id.as_raw() as i64;
                        return self.builder.build_const(IrValue::I64(runtime_type_id));
                    }
                    if sym.kind == SymbolKind::Enum {
                        // Enum runtime type_id = sym.type_id (matches register_enum_metadata)
                        let runtime_type_id = sym.type_id.0 as i64;
                        return self.builder.build_const(IrValue::I64(runtime_type_id));
                    }
                }

                // Check if this symbol is a function reference (local or external)
                if let Some(func_id) = self.get_function_id(symbol) {
                    // Create a function pointer constant for static methods
                    return self.builder.build_function_ptr(func_id);
                }

                // IMPORTANT: If we're inside a lambda and this is a captured variable,
                // we must RELOAD from the environment on each access. This ensures that:
                // 1. Updates from other threads (e.g., main thread setting `ready = true`)
                //    are visible to the lambda (thread reading `ready` in a while loop)
                // 2. Mutable captured variables have proper by-reference semantics
                //
                // Without this reload, the captured variable would be cached in an SSA register
                // at lambda entry and never refreshed, causing hangs in condition variable patterns.
                if let Some(ref env_layout) = self.current_env_layout {
                    if let Some(_field) = env_layout.find_field(*symbol) {
                        // This is a captured variable - reload from environment
                        let env_ptr = IrId::new(0); // First parameter in lambda is environment pointer
                        let loaded = env_layout.load_field(&mut self.builder, env_ptr, *symbol)?;
                        debug!(
                            "Reloading captured variable {:?} from environment, got {:?}",
                            symbol, loaded
                        );
                        // Update symbol_map so subsequent operations use the new value
                        self.symbol_map.insert(*symbol, loaded);
                        return Some(loaded);
                    }
                }

                // Try to get from symbol_map first (local variables, parameters)
                // SPECIAL CASE: If this is a "this" variable by name but not by the synthetic SymbolId(0),
                // redirect the lookup to use the synthetic `this` symbol. This handles implicit `this`
                // references created during AST lowering for field access in class methods/constructors.
                let lookup_symbol = if let Some(sym_info) = self.symbol_table.get_symbol(*symbol) {
                    if let Some(name) = self.string_interner.get(sym_info.name) {
                        if name == "this" && *symbol != SymbolId::from_raw(0) {
                            // Redirect to synthetic `this` symbol
                            SymbolId::from_raw(0)
                        } else {
                            *symbol
                        }
                    } else {
                        *symbol
                    }
                } else {
                    *symbol
                };

                // Check direct SymbolId match against global_symbol_map first
                if let Some(&gid) = self.global_symbol_map.get(&lookup_symbol) {
                    let global_type = self
                        .builder
                        .module
                        .globals
                        .get(&gid)
                        .map(|g| g.ty.clone())
                        .unwrap_or(IrType::Any);
                    return self.builder.build_load_global(gid, global_type);
                }

                if let Some(&reg) = self.symbol_map.get(&lookup_symbol) {
                    {
                        let _n = self.symbol_table.get_symbol(lookup_symbol).and_then(|s| self.string_interner.get(s.name));
                        if _n == Some("counter") {
                            eprintln!("[COUNTER_SYMBOL_MAP] counter {:?} found in symbol_map as reg {:?}", lookup_symbol, reg);
                        }
                    }
                    // Check if we need to convert the type
                    // This handles cases where captured variables are stored as i64 in closure environment
                    // but need to be used as their original type (e.g., i32)
                    if let Some(actual_type) = self.builder.get_register_type(reg) {
                        let expected_type = self.convert_type(expr.ty);

                        // If types don't match, consider adding a cast instruction
                        // CRITICAL: Do NOT cast from Ptr to smaller types (I32, etc.)
                        // This can happen when generic type resolution fails (e.g., Thread<T> where T is unresolved)
                        // and the type system incorrectly infers I32 for a class instance pointer
                        if actual_type != expected_type {
                            // Skip casts in these cases to preserve actual type:
                            // 1. Actual is pointer, expected is scalar (would truncate pointer)
                            // 2. Actual is String, expected is Ptr(Void) (would lose string data)
                            // 3. Actual is more specific than Ptr(Void)
                            // 4. Actual is Ptr(String), expected is Ptr(Void) - preserve String type info for trace
                            let actual_is_ptr = matches!(&actual_type, IrType::Ptr(_));
                            let expected_is_ptr = matches!(&expected_type, IrType::Ptr(_));
                            let expected_is_void_ptr = matches!(&expected_type, IrType::Ptr(inner) if matches!(**inner, IrType::Void));
                            let actual_is_specific = matches!(
                                &actual_type,
                                IrType::String
                                    | IrType::I32
                                    | IrType::I64
                                    | IrType::F32
                                    | IrType::F64
                                    | IrType::Bool
                                    | IrType::Function { .. }
                            );
                            // Only skip cast for Ptr(String) specifically - NOT for other pointer types like Ptr(U8)
                            // which are used by concurrency primitives (Mutex, Thread, Channel, etc.)
                            let actual_is_string_ptr = matches!(&actual_type, IrType::Ptr(inner) if matches!(**inner, IrType::String));

                            let actual_is_vector = actual_type.is_vector();

                            // Skip casts that lose semantic type info due to TypeParameter erasure.
                            // TypeParameter converts to I64 via convert_type(), but the Let handler
                            // may have resolved the concrete type (String, F64, F32) from the
                            // GenericInstance return type. Casting back to I64 destroys that info,
                            // which is needed by trace dispatch and other type-aware operations.
                            let actual_loses_info_to_i64 =
                                matches!(&actual_type, IrType::String | IrType::F64 | IrType::F32)
                                    && expected_type == IrType::I64;

                            // I64→I32 narrowing would truncate high bits (e.g., function pointers
                            // from CC.getSymbol on 64-bit platforms). Extern functions return I64
                            // but Haxe `Int` maps to I32; preserve the full I64 value.
                            let actual_i64_expected_i32 =
                                actual_type == IrType::I64 && expected_type == IrType::I32;

                            let should_skip_cast = (actual_is_ptr && !expected_is_ptr)  // pointer to scalar
                                || (actual_is_specific && expected_is_void_ptr)          // specific type to void pointer
                                || (actual_is_string_ptr && expected_is_void_ptr)        // Ptr(String) to Ptr(Void)
                                || actual_is_vector // vector types (SIMD) should never be cast
                                || actual_loses_info_to_i64 // TypeParameter erasure would lose concrete type
                                || actual_i64_expected_i32; // I64→I32 truncation would lose high bits

                            if should_skip_cast {
                                debug!(
                                    "Variable type mismatch - symbol={:?}, actual: {:?}, expected: {:?}, SKIPPING cast (would lose type info)",
                                    symbol, actual_type, expected_type
                                );
                                Some(reg)
                            } else {
                                debug!(
                                    "Variable type mismatch - symbol={:?}, actual: {:?}, expected: {:?}, inserting cast",
                                    symbol, actual_type, expected_type
                                );
                                let cast_reg =
                                    self.builder.build_cast(reg, actual_type, expected_type);
                                // Propagate class hint from source to cast register
                                if let Some(cast_id) = cast_reg {
                                    if let Some(hint) = self.register_class_hints.get(&reg).cloned()
                                    {
                                        self.register_class_hints.insert(cast_id, hint);
                                    }
                                }
                                cast_reg
                            }
                        } else {
                            Some(reg)
                        }
                    } else {
                        // No type info, return as-is
                        Some(reg)
                    }
                } else {
                    // Symbol not in local scope - check if it's a class field
                    // If so, we need to access it via 'this' pointer

                    // First check field_index_map - this is more reliable than SymbolKind::Field
                    // because field symbols may be registered with SymbolKind::Variable
                    let field_entry = self.field_index_map.get(symbol).copied().or_else(|| {
                        // Name-based fallback: SymbolIds differ between compilation contexts
                        // (e.g., ArrayIterator.current in stdlib vs user code)
                        if let Some(sym_info) = self.symbol_table.get_symbol(*symbol) {
                            if let Some(this_type) = self.current_this_type {
                                let field_name = sym_info.name;
                                self.resolve_field_index_by_name(field_name, this_type)
                            } else {
                                None
                            }
                        } else {
                            None
                        }
                    });
                    if let Some((field_class_type, _field_idx)) = field_entry {
                        // Get 'this' pointer (SymbolId(0) is the special 'this' mapping)
                        if let Some(&this_reg) = self.symbol_map.get(&SymbolId::from_raw(0)) {
                            // Use current_this_type if available, otherwise use field_class_type
                            let owner_type = self.current_this_type.unwrap_or(field_class_type);
                            return self.lower_field_access(this_reg, *symbol, owner_type, expr.ty);
                        }
                    }

                    // Fallback: check if symbol table says it's a field or enum variant
                    if let Some(sym) = self.symbol_table.get_symbol(*symbol) {
                        use crate::tast::SymbolKind;
                        if sym.kind == SymbolKind::Field {
                            if let Some(&this_reg) = self.symbol_map.get(&SymbolId::from_raw(0)) {
                                if let Some(owner_type) = self.current_this_type {
                                    return self.lower_field_access(
                                        this_reg, *symbol, owner_type, expr.ty,
                                    );
                                }
                            }
                        } else if sym.kind == SymbolKind::EnumVariant {
                            // Enum variant without parameters - return its discriminant value.
                            // Use expr.ty to resolve the parent enum — symbol-based lookup
                            // can match the wrong parent when multiple enums share variant names
                            // (e.g., Option.None vs DisplayMode.None).
                            let parent_enum_id = self.resolve_enum_symbol(expr.ty).or_else(|| {
                                self.symbol_table.find_parent_enum_for_constructor(*symbol)
                            });
                            if let Some(parent_enum_id) = parent_enum_id {
                                if let Some(variants) =
                                    self.symbol_table.get_enum_variants(parent_enum_id)
                                {
                                    // Find the index of this variant by SymbolId or by name
                                    // (generic instantiation may create different SymbolIds)
                                    let variant_name =
                                        self.string_interner.get(sym.name).unwrap_or("");
                                    for (idx, variant_id) in variants.iter().enumerate() {
                                        let id_match = *variant_id == *symbol;
                                        let name_match = !id_match
                                            && self
                                                .symbol_table
                                                .get_symbol(*variant_id)
                                                .and_then(|vs| self.string_interner.get(vs.name))
                                                .map_or(false, |vn| vn == variant_name);
                                        if id_match || name_match {
                                            // If enum has parameterized variants, all variants must be boxed
                                            if self.enum_is_boxed(parent_enum_id) {
                                                return self.build_boxed_enum_tag_only(idx as i32);
                                            }
                                            return self
                                                .builder
                                                .build_const(IrValue::I64(idx as i64));
                                        }
                                    }
                                }
                            }
                            // If we can't find the variant info, try to get the discriminant from the type
                            debug!("EnumVariant {:?} - could not find discriminant", symbol);
                        }
                    }

                    // Check if this is a global variable (static class field, module-level var)
                    if let Some(&global_id) = self.global_symbol_map.get(symbol) {
                        debug!(
                            "[GLOBAL ACCESS] Found global {:?} -> {:?}",
                            symbol, global_id
                        );
                        // Load the global variable's value
                        // First get the global's type from the module
                        let global_type = self
                            .builder
                            .module
                            .globals
                            .get(&global_id)
                            .map(|g| g.ty.clone())
                            .unwrap_or(IrType::Any);
                        return self.builder.build_load_global(global_id, global_type);
                    }

                    // If we get here, we couldn't resolve the variable
                    let sym_name = self
                        .symbol_table
                        .get_symbol(*symbol)
                        .and_then(|s| self.string_interner.get(s.name));
                    // Try name-based global lookup as fallback (SymbolIds may differ)
                    eprintln!("[UNRESOLVED] {:?} name={:?} global_map_size={}", symbol, sym_name, self.global_symbol_map.len());
                    if let Some(name_str) = sym_name {
                        for (&gsym, &gid) in &self.global_symbol_map {
                            if let Some(gsym_info) = self.symbol_table.get_symbol(gsym) {
                                if let Some(gname) = self.string_interner.get(gsym_info.name) {
                                    if gname == name_str {
                                        let global_type = self
                                            .builder
                                            .module
                                            .globals
                                            .get(&gid)
                                            .map(|g| g.ty.clone())
                                            .unwrap_or(IrType::Any);
                                        return self.builder.build_load_global(gid, global_type);
                                    }
                                }
                            }
                        }
                        // Also try searching globals by name suffix
                        for global in self.builder.module.globals.values() {
                            if global.name.ends_with(&format!(".{}", name_str)) || global.name == name_str {
                                return self.builder.build_load_global(global.id, global.ty.clone());
                            }
                        }
                    }
                    debug!(
                        "[UNRESOLVED_VAR] Could not resolve variable {:?} (name={:?})",
                        symbol, sym_name
                    );
                    None
                }
            }

            HirExprKind::Field { object, field } => {
                // Check if this is an enum variant access (e.g., Color.Red)
                // In that case, the object is an Enum type symbol, not a value
                if let HirExprKind::Variable { symbol, .. } = &object.kind {
                    if let Some(sym) = self.symbol_table.get_symbol(*symbol) {
                        use crate::tast::SymbolKind;
                        if sym.kind == SymbolKind::Enum {
                            // This is an enum variant access - get the variant discriminant
                            let enum_name =
                                self.string_interner.get(sym.name).unwrap_or("<unknown>");
                            let field_sym = self.symbol_table.get_symbol(*field);
                            let field_name = field_sym
                                .and_then(|s| self.string_interner.get(s.name))
                                .unwrap_or("<unknown>");

                            if let Some(variants) = self.symbol_table.get_enum_variants(*symbol) {
                                for (idx, variant_id) in variants.iter().enumerate() {
                                    let variant_sym = self.symbol_table.get_symbol(*variant_id);
                                    let variant_name = variant_sym
                                        .and_then(|s| self.string_interner.get(s.name))
                                        .unwrap_or("<unknown>");
                                    // Compare by name since the field symbol might be different from the variant symbol
                                    if *variant_id == *field || variant_name == field_name {
                                        // If enum has parameterized variants, all variants must be boxed
                                        if self.enum_is_boxed(*symbol) {
                                            return self.build_boxed_enum_tag_only(idx as i32);
                                        }
                                        return self.builder.build_const(IrValue::I64(idx as i64));
                                    }
                                }
                            }
                            // If field is not a variant, fall through to regular field access
                        }
                    }
                }

                // Regular field access
                debug!("[Field expression] About to lower object");
                let obj_reg = self.lower_expression(object)?;
                debug!(
                    "[Field expression] Object lowered to reg={}, now calling lower_field_access",
                    obj_reg
                );

                // Track object as temp if it's an OWNED heap-allocated value
                // This includes:
                // 1. Direct `new` expressions: `new Complex(...)`
                // 2. Method calls that return class instances: `z.mul(z)` returns new Complex
                //
                // We check if the return type is a Class (heap-allocated via malloc).
                // Runtime/extern functions typically return primitives, strings, or Dynamic,
                // not Class instances, so this heuristic is safe.
                let is_owned_heap_value = matches!(
                    &object.kind,
                    HirExprKind::New { .. } | HirExprKind::Call { .. }
                ) && self.get_drop_behavior(object.ty)
                    == DropBehavior::AutoDrop;

                // Only register NEW expressions as temporaries, not method Call results.
                // Method calls (getObj(), input(), etc.) often return references to existing
                // objects — freeing these would corrupt the heap. Only `new Foo(...)` creates
                // a genuinely owned temporary that must be freed after the field access chain.
                let is_new_expr = matches!(&object.kind, HirExprKind::New { .. });
                if is_owned_heap_value && is_new_expr {
                    self.temp_heap_values.push(obj_reg);
                }

                let receiver_ty = object.ty; // The type of the object being accessed

                // Structural subtyping: if object is a variable with an anon view,
                // redirect field access to the backing representation
                if let HirExprKind::Variable {
                    symbol: obj_sym, ..
                } = &object.kind
                {
                    if let Some(backing) = self.anon_views.get(obj_sym).cloned() {
                        let field_name = self
                            .symbol_table
                            .get_symbol(*field)
                            .and_then(|s| self.string_interner.get(s.name))
                            .map(|s| s.to_string());

                        if let Some(field_name) = field_name {
                            match &backing {
                                AnonBacking::Class { field_map, .. } => {
                                    if let Some((_, gep_idx, field_type_id)) =
                                        field_map.iter().find(|(n, ..)| *n == field_name)
                                    {
                                        let field_ir_ty = self.convert_type(*field_type_id);
                                        let idx_const = self
                                            .builder
                                            .build_const(IrValue::I64(*gep_idx as i64))?;
                                        let field_ptr = self.builder.build_gep(
                                            obj_reg,
                                            vec![idx_const],
                                            field_ir_ty.clone(),
                                        )?;
                                        return Some(
                                            self.builder.build_load(field_ptr, field_ir_ty)?,
                                        );
                                    }
                                }
                                AnonBacking::WiderAnon { field_map, .. } => {
                                    if let Some((_, src_idx, field_type_id)) =
                                        field_map.iter().find(|(n, ..)| *n == field_name)
                                    {
                                        let anon_get_id = self.get_or_register_extern_function(
                                            "rayzor_anon_get_field_by_index",
                                            vec![IrType::Ptr(Box::new(IrType::U8)), IrType::I32],
                                            IrType::I64,
                                        );
                                        let idx_val = self
                                            .builder
                                            .build_const(IrValue::I32(*src_idx as i32))?;
                                        let raw_val = self.builder.build_call_direct(
                                            anon_get_id,
                                            vec![obj_reg, idx_val],
                                            IrType::I64,
                                        )?;
                                        return self.coerce_from_i64(raw_val, *field_type_id);
                                    }
                                }
                            }
                        }
                    }
                }

                // Raw anonymous object handle: use haxe_reflect_field directly
                // without haxe_unbox_reference_ptr (the handle is NOT a boxed DynamicValue*)
                if let HirExprKind::Variable {
                    symbol: obj_sym, ..
                } = &object.kind
                {
                    // Skip raw_anon path if variable has a class hint (e.g., from @:derive(Clone))
                    if self.raw_anon_symbols.contains(obj_sym)
                        && !self.register_class_hints.contains_key(&obj_reg)
                        && !self.monomorphized_var_types.contains_key(obj_sym)
                    {
                        return self.raw_anon_reflect_field_read(obj_reg, *field, expr.ty);
                    }
                }

                // When receiver is Dynamic but has a class hint (e.g., from @:derive(Clone)),
                // resolve receiver_ty to the actual class type for correct GEP field access.
                let receiver_ty = {
                    let is_dynamic = {
                        let type_table = self.type_table.borrow();
                        type_table
                            .get(receiver_ty)
                            .map_or(false, |t| matches!(t.kind, TypeKind::Dynamic))
                    };
                    if is_dynamic {
                        if let Some(class_hint) = self.register_class_hints.get(&obj_reg) {
                            // Find the class type by name
                            let class_type = self
                                .class_type_to_symbol
                                .iter()
                                .find(|(_ty, sym)| {
                                    self.symbol_table
                                        .get_symbol(**sym)
                                        .and_then(|s| self.string_interner.get(s.name))
                                        == Some(class_hint.as_str())
                                })
                                .map(|(ty, _)| *ty);
                            class_type.unwrap_or(receiver_ty)
                        } else {
                            receiver_ty
                        }
                    } else {
                        receiver_ty
                    }
                };

                let result = self.lower_field_access(obj_reg, *field, receiver_ty, expr.ty);
                debug!(
                    "[Field expression] lower_field_access returned {:?}",
                    result
                );
                result
            }

            HirExprKind::Index { object, index } => {
                let obj_reg = self.lower_expression(object)?;
                let idx_reg = self.lower_expression(index)?;
                self.lower_index_access(obj_reg, idx_reg, expr.ty)
            }

            HirExprKind::Call {
                callee,
                args,
                is_method,
                type_args: hir_type_args,
            } => {
                // Reset call_label for tracing which path generates the call
                self.builder.call_label = Some("CALL_START".to_string());
                let result_type = self.convert_type(expr.ty);

                // Update the caller's shadow-stack frame to this call-site line/col so
                // the trace shows WHERE the call was made, not the function definition line.
                let call_loc = expr.source_location;
                if call_loc.is_valid() && call_loc.line > 0 {
                    let update_loc_fn = self.get_or_register_extern_function(
                        "rayzor_update_call_frame_location",
                        vec![IrType::I32, IrType::I32],
                        IrType::Void,
                    );
                    if let (Some(line_c), Some(col_c)) = (
                        self.builder.build_const(IrValue::I32(call_loc.line as i32)),
                        self.builder
                            .build_const(IrValue::I32(call_loc.column as i32)),
                    ) {
                        self.builder.build_call_direct(
                            update_loc_fn,
                            vec![line_c, col_c],
                            IrType::Void,
                        );
                    }
                }

                // Convert HIR type_args to IrType for use in CallDirect
                let converted_hir_type_args: Vec<IrType> = hir_type_args
                    .iter()
                    .map(|&ty_id| self.convert_type(ty_id))
                    .collect();

                debug!(
                    "[CALL] expr.ty={:?}, result_type={:?}, is_method={}",
                    expr.ty, result_type, is_method
                );

                // @:async method dispatch: .await(), .poll(), .isReady()
                // on registers known to hold Future handles from async function calls.
                // MethodCall pattern: callee = Variable(method_symbol), args[0] = receiver
                if *is_method {
                    // Get method name from callee symbol
                    let async_method_sym = match &callee.kind {
                        HirExprKind::Variable { symbol, .. } => Some(*symbol),
                        HirExprKind::Field { field, .. } => Some(*field),
                        _ => None,
                    };
                    // Get receiver symbol from first arg (MethodCall puts receiver as args[0])
                    let receiver_sym_from_args = args.first().and_then(|a| {
                        if let HirExprKind::Variable { symbol, .. } = &a.kind {
                            Some(*symbol)
                        } else {
                            None
                        }
                    });
                    if let (Some(method_sym), Some(recv_sym)) =
                        (async_method_sym, receiver_sym_from_args)
                    {
                        let receiver_reg = self.symbol_map.get(&recv_sym).copied();
                        if let Some(recv_reg) = receiver_reg {
                            if self.async_result_registers.contains(&recv_reg) {
                                let method_name = self
                                    .symbol_table
                                    .get_symbol(method_sym)
                                    .and_then(|s| self.string_interner.get(s.name));
                                if let Some(method) = method_name {
                                    let ext_name = match method {
                                        "await" => Some("rayzor_future_await"),
                                        "poll" => Some("rayzor_future_poll"),
                                        "isReady" => Some("rayzor_future_is_ready"),
                                        _ => None,
                                    };
                                    if let Some(extern_name) = ext_name {
                                        // Look up the extern directly (declared by ensure_future_externs)
                                        let func_id = self
                                            .builder
                                            .module
                                            .extern_functions
                                            .iter()
                                            .find(|(_, f)| f.name == extern_name)
                                            .map(|(id, _)| *id);
                                        if let Some(func_id) = func_id {
                                            let ret_ty = if method == "isReady" {
                                                IrType::Bool
                                            } else {
                                                IrType::Ptr(Box::new(IrType::U8))
                                            };
                                            return self.builder.build_call_direct(
                                                func_id,
                                                vec![recv_reg],
                                                ret_ty,
                                            );
                                        }
                                    }
                                }
                            }
                        }
                    }
                }

                // Static synthetic calls resolved as Variable — find parent class
                if let HirExprKind::Variable { symbol, .. } = &callee.kind {
                    let callee_name = self
                        .symbol_table
                        .get_symbol(*symbol)
                        .and_then(|s| self.string_interner.get(s.name))
                        .map(|s| s.to_string());
                    // @:gpuStruct synthetic static methods: gpuDef/gpuSize/gpuAlignment
                    if matches!(
                        callee_name.as_deref(),
                        Some("gpuDef") | Some("gpuSize") | Some("gpuAlignment")
                    ) {
                        for (tid, decl) in self.current_hir_types.iter() {
                            if let crate::ir::hir::HirTypeDecl::Class(c) = decl {
                                let is_gpu_struct = self
                                    .symbol_table
                                    .get_symbol(c.symbol_id)
                                    .map(|s| s.flags.is_gpu_struct())
                                    .unwrap_or(false);
                                if !is_gpu_struct {
                                    continue;
                                }
                                let has_method =
                                    c.methods.iter().any(|m| m.function.symbol_id == *symbol);
                                if has_method {
                                    // Find canonical TypeId
                                    let canonical_tid = {
                                        let type_table = self.type_table.borrow();
                                        type_table.get(*tid).and_then(|_| Some(*tid)).or_else(
                                            || {
                                                type_table.iter().find_map(|(_, t)| {
                                                    if let crate::tast::core::TypeKind::Class {
                                                        symbol_id: sid,
                                                        ..
                                                    } = &t.kind
                                                    {
                                                        if *sid == c.symbol_id {
                                                            return Some(t.id);
                                                        }
                                                    }
                                                    None
                                                })
                                            },
                                        )
                                    };
                                    if let Some(real_tid) = canonical_tid {
                                        if let Some(layout) =
                                            self.get_or_compute_gpu_struct_layout(real_tid)
                                        {
                                            match callee_name.as_deref().unwrap() {
                                                "gpuDef" => {
                                                    let mut full = String::new();
                                                    for dep in &layout.dep_typedefs {
                                                        full.push_str(dep);
                                                    }
                                                    full.push_str(&layout.msl_typedef);
                                                    return self
                                                        .builder
                                                        .build_const(IrValue::String(full));
                                                }
                                                "gpuSize" => {
                                                    return self.builder.build_const(IrValue::I64(
                                                        layout.total_size as i64,
                                                    ));
                                                }
                                                "gpuAlignment" => {
                                                    return self.builder.build_const(IrValue::I64(
                                                        layout.alignment as i64,
                                                    ));
                                                }
                                                _ => {}
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }

                    if callee_name.as_deref() == Some("cdef") {
                        // Find the @:cstruct class that has this cdef method
                        for (tid, decl) in self.current_hir_types.iter() {
                            if let crate::ir::hir::HirTypeDecl::Class(c) = decl {
                                let is_cstruct = self
                                    .symbol_table
                                    .get_symbol(c.symbol_id)
                                    .map(|s| s.flags.is_cstruct())
                                    .unwrap_or(false);
                                if !is_cstruct {
                                    continue;
                                }
                                // Check if this class has a method with our cdef symbol
                                let has_cdef =
                                    c.methods.iter().any(|m| m.function.symbol_id == *symbol);
                                if has_cdef {
                                    // HIR TypeId may not be in type_table — find canonical TypeId by symbol
                                    let canonical_tid = {
                                        let type_table = self.type_table.borrow();
                                        type_table.get(*tid).and_then(|_| Some(*tid)).or_else(
                                            || {
                                                // Scan type_table for a Class with matching symbol_id
                                                type_table.iter().find_map(|(_, t)| {
                                                    if let crate::tast::core::TypeKind::Class {
                                                        symbol_id: sid,
                                                        ..
                                                    } = &t.kind
                                                    {
                                                        if *sid == c.symbol_id {
                                                            return Some(t.id);
                                                        }
                                                    }
                                                    None
                                                })
                                            },
                                        )
                                    };
                                    if let Some(real_tid) = canonical_tid {
                                        if let Some(layout) =
                                            self.get_or_compute_cstruct_layout(real_tid)
                                        {
                                            return self
                                                .builder
                                                .build_const(IrValue::String(layout.cdef_string));
                                        }
                                    }
                                }
                            }
                        }
                    }
                }

                if let HirExprKind::Variable { symbol, .. } = &callee.kind {
                    let vname = self
                        .symbol_table
                        .get_symbol(*symbol)
                        .and_then(|s| self.string_interner.get(s.name))
                        .unwrap_or("?");
                    debug!(
                        "[CALL-VAR] callee='{}', is_method={}, args.len()={}",
                        vname,
                        is_method,
                        args.len()
                    );

                    // @:derive(Hash) synthetic hashCode() — intercept Variable callee path
                    // Instance method calls are desugared to Variable callee with receiver as first arg
                    if vname == "hashCode" && *is_method && args.len() == 1 {
                        let receiver = &args[0];
                        let class_sym = {
                            let type_table = self.type_table.borrow();
                            type_table.get(receiver.ty).and_then(|t| {
                                if let TypeKind::Class { symbol_id, .. } = &t.kind {
                                    if self.derive_hash_classes.contains(symbol_id) {
                                        Some(*symbol_id)
                                    } else {
                                        None
                                    }
                                } else {
                                    None
                                }
                            })
                        };
                        if let Some(sym) = class_sym {
                            return self.lower_derived_hash_code(receiver, sym);
                        }
                    }

                    // @:derive(Clone) synthetic clone() — deep copy
                    if vname == "clone" && *is_method && args.len() == 1 {
                        let receiver = &args[0];
                        let class_sym = {
                            let type_table = self.type_table.borrow();
                            type_table.get(receiver.ty).and_then(|t| {
                                if let TypeKind::Class { symbol_id, .. } = &t.kind {
                                    if self.derive_clone_classes.contains(symbol_id) {
                                        Some(*symbol_id)
                                    } else {
                                        None
                                    }
                                } else {
                                    None
                                }
                            })
                        };
                        if let Some(sym) = class_sym {
                            return self.lower_derived_clone(receiver, sym);
                        }
                    }

                    // @:derive(Debug) synthetic toString()
                    if vname == "toString" && *is_method && args.len() == 1 {
                        let receiver = &args[0];
                        let class_sym = {
                            let type_table = self.type_table.borrow();
                            type_table.get(receiver.ty).and_then(|t| {
                                if let TypeKind::Class { symbol_id, .. } = &t.kind {
                                    if self.derive_debug_classes.contains(symbol_id) {
                                        Some(*symbol_id)
                                    } else {
                                        None
                                    }
                                } else {
                                    None
                                }
                            })
                        };
                        if let Some(sym) = class_sym {
                            return self.lower_derived_to_string(receiver, sym);
                        }
                    }
                }
                {
                    // DEBUG: check callee kind for localhost
                }
                if let HirExprKind::Field { object, field } = &callee.kind {
                    // This is a method call: object.method(args)
                    // The method symbol should be in our function_map (local or external)
                    let method_name_interned = self.symbol_table.get_symbol(*field).map(|s| s.name);
                    let method_name =
                        method_name_interned.and_then(|name| self.string_interner.get(name));
                    let in_local = self.function_map.contains_key(field);
                    let in_external = self.external_function_map.contains_key(field);
                    debug!(
                        "[Method call] method={:?}, field={:?}, in_local={}, in_external={}",
                        method_name, field, in_local, in_external
                    );

                    // @:cstruct synthetic cdef() method — return C typedef string
                    if method_name == Some("cdef") {
                        let obj_type = object.ty;
                        if self.is_cstruct_class(obj_type) {
                            if let Some(layout) = self.get_or_compute_cstruct_layout(obj_type) {
                                return self
                                    .builder
                                    .build_const(IrValue::String(layout.cdef_string));
                            }
                        }
                        // Fallback: for static calls, obj_type may differ from cached TypeId.
                        // Extract symbol_id from obj_type, find matching layout.
                        let obj_sym_id = {
                            let type_table = self.type_table.borrow();
                            type_table.get(obj_type).and_then(|t| {
                                if let crate::tast::core::TypeKind::Class { symbol_id, .. } =
                                    &t.kind
                                {
                                    Some(*symbol_id)
                                } else {
                                    None
                                }
                            })
                        };
                        if let Some(sym_id) = obj_sym_id {
                            // Find the cached layout whose class has this symbol_id
                            let cdef_str = self.cstruct_layouts.iter().find_map(|(tid, layout)| {
                                // Check if this type_id's class matches our symbol
                                let type_table = self.type_table.borrow();
                                if let Some(t) = type_table.get(*tid) {
                                    if let crate::tast::core::TypeKind::Class {
                                        symbol_id, ..
                                    } = &t.kind
                                    {
                                        if *symbol_id == sym_id {
                                            return Some(layout.cdef_string.clone());
                                        }
                                    }
                                }
                                // Also check via HirTypeDecl
                                for (htid, decl) in self.current_hir_types.iter() {
                                    if *htid == *tid {
                                        if let crate::ir::hir::HirTypeDecl::Class(c) = decl {
                                            if c.symbol_id == sym_id {
                                                return Some(layout.cdef_string.clone());
                                            }
                                        }
                                    }
                                }
                                None
                            });
                            if let Some(cdef) = cdef_str {
                                return self.builder.build_const(IrValue::String(cdef));
                            }
                        }
                    }

                    // Clone/Debug interceptions are in the Variable callee path above

                    // @:derive(Hash) synthetic hashCode() — inline field-based hash computation
                    if method_name == Some("hashCode") && args.is_empty() {
                        let class_sym = {
                            let type_table = self.type_table.borrow();
                            type_table.get(object.ty).and_then(|t| {
                                if let TypeKind::Class { symbol_id, .. } = &t.kind {
                                    if self.derive_hash_classes.contains(symbol_id) {
                                        Some(*symbol_id)
                                    } else {
                                        None
                                    }
                                } else {
                                    None
                                }
                            })
                        };
                        if let Some(sym) = class_sym {
                            return self.lower_derived_hash_code(object, sym);
                        }
                    }

                    // @:gpuStruct synthetic methods — gpuDef/gpuSize/gpuAlignment
                    if matches!(
                        method_name,
                        Some("gpuDef") | Some("gpuSize") | Some("gpuAlignment")
                    ) {
                        let obj_type = object.ty;
                        // Try direct type check first, then fallback via symbol_id
                        let gpu_layout = if self.is_gpu_struct_class(obj_type) {
                            self.get_or_compute_gpu_struct_layout(obj_type)
                        } else {
                            // Static call: obj_type may differ from cached TypeId
                            let obj_sym_id = {
                                let type_table = self.type_table.borrow();
                                type_table.get(obj_type).and_then(|t| {
                                    if let crate::tast::core::TypeKind::Class {
                                        symbol_id, ..
                                    } = &t.kind
                                    {
                                        Some(*symbol_id)
                                    } else {
                                        None
                                    }
                                })
                            };
                            obj_sym_id.and_then(|sym_id| {
                                self.gpu_struct_layouts.iter().find_map(|(tid, layout)| {
                                    let type_table = self.type_table.borrow();
                                    if let Some(t) = type_table.get(*tid) {
                                        if let crate::tast::core::TypeKind::Class {
                                            symbol_id,
                                            ..
                                        } = &t.kind
                                        {
                                            if *symbol_id == sym_id {
                                                return Some(layout.clone());
                                            }
                                        }
                                    }
                                    for (htid, decl) in self.current_hir_types.iter() {
                                        if *htid == *tid {
                                            if let crate::ir::hir::HirTypeDecl::Class(c) = decl {
                                                if c.symbol_id == sym_id {
                                                    return Some(layout.clone());
                                                }
                                            }
                                        }
                                    }
                                    None
                                })
                            })
                        };
                        if let Some(layout) = gpu_layout {
                            match method_name.unwrap() {
                                "gpuDef" => {
                                    // Return full MSL typedef (deps + own)
                                    let mut full = String::new();
                                    for dep in &layout.dep_typedefs {
                                        full.push_str(dep);
                                    }
                                    full.push_str(&layout.msl_typedef);
                                    return self.builder.build_const(IrValue::String(full));
                                }
                                "gpuSize" => {
                                    return self
                                        .builder
                                        .build_const(IrValue::I64(layout.total_size as i64));
                                }
                                "gpuAlignment" => {
                                    return self
                                        .builder
                                        .build_const(IrValue::I64(layout.alignment as i64));
                                }
                                _ => {}
                            }
                        }
                    }

                    // Check for interface dispatch: if object has interface type,
                    // load the method function pointer from the fat pointer and call indirectly
                    if let Some(iface_sym) = self.get_interface_symbol(object.ty) {
                        let method_name_interned =
                            self.symbol_table.get_symbol(*field).map(|s| s.name);

                        if let Some(method_name_i) = method_name_interned {
                            // Find the method's index in the interface
                            let method_index = self
                                .interface_method_names
                                .get(&iface_sym)
                                .and_then(|names| names.iter().position(|n| *n == method_name_i));

                            if let Some(idx) = method_index {
                                // Lower the object (fat pointer)
                                let fat_ptr = self.lower_expression(object)?;

                                // Lower arguments
                                let arg_regs: Vec<_> = args
                                    .iter()
                                    .filter_map(|a| self.lower_expression(a))
                                    .collect();

                                // Load object pointer from fat_ptr[0]
                                let obj_ptr = self.builder.build_load(fat_ptr, IrType::I64)?;

                                // Load function pointer from fat_ptr[(idx+1)*8]
                                let fn_offset = self
                                    .builder
                                    .build_const(IrValue::I64(((idx + 1) * 8) as i64))?;
                                let fn_slot = self.builder.build_ptr_add(
                                    fat_ptr,
                                    fn_offset,
                                    IrType::Ptr(Box::new(IrType::U8)),
                                )?;
                                let fn_ptr = self.builder.build_load(fn_slot, IrType::I64)?;

                                // Build call args: self (obj_ptr) + user args
                                let mut call_args = vec![obj_ptr];
                                call_args.extend(arg_regs);

                                // Build signature: (self: Ptr, args...) -> return_type
                                let param_types = {
                                    let mut types = vec![IrType::Ptr(Box::new(IrType::Void))]; // self
                                    for arg in args {
                                        types.push(self.convert_type(arg.ty));
                                    }
                                    types
                                };
                                // Resolve return type from the method's symbol type,
                                // not expr.ty (which may be the interface type instead
                                // of the method's return type in some TAST configurations)
                                let return_ir_type =
                                    self.resolve_interface_method_return_type(*field, expr.ty);
                                let return_type = Box::new(return_ir_type);
                                let func_signature = IrType::Function {
                                    params: param_types,
                                    return_type,
                                    varargs: false,
                                };

                                return self.builder.build_call_indirect(
                                    fn_ptr,
                                    call_args,
                                    func_signature,
                                );
                            }
                        }
                    }

                    let maybe_func_id = self
                        .resolve_function_id_with_qualified_fallback(*field)
                        .or_else(|| {
                            method_name_interned
                                .and_then(|name| self.resolve_method_function_id(object.ty, name))
                        });
                    if let Some(func_id) = maybe_func_id {
                        // FIRST: Try to route through runtime mapping for extern class methods
                        // Check if there's a runtime mapping using the standard approach
                        // BUT: for String methods with optional params, use param-count-aware lookup
                        let stdlib_info = {
                            let method_name_str = self
                                .symbol_table
                                .get_symbol(*field)
                                .and_then(|s| self.string_interner.get(s.name));

                            // Check if this is a method with optional params that needs param-count-aware lookup
                            if let Some(mn) = method_name_str {
                                if (mn == "indexOf" || mn == "lastIndexOf") {
                                    // Use param-count-aware lookup for indexOf/lastIndexOf
                                    let arg_count = args.len();
                                    debug!(
                                        "[indexOf/lastIndexOf lookup] method={}, arg_count={}",
                                        mn, arg_count
                                    );
                                    self.stdlib_mapping
                                        .find_by_name_and_params("String", mn, arg_count)
                                        .map(|(sig, mapping)| (sig.class, sig.method, mapping))
                                } else if mn == "wait" {
                                    // Lock.wait() has overloads: 0 params (blocking) vs 1 param (with timeout)
                                    let arg_count = args.len();
                                    debug!("[wait lookup] method={}, arg_count={}", mn, arg_count);
                                    self.stdlib_mapping
                                        .find_by_name_and_params("sys_thread_Lock", mn, arg_count)
                                        .or_else(|| {
                                            self.stdlib_mapping.find_by_name_and_params(
                                                "sys_thread_Condition",
                                                mn,
                                                arg_count,
                                            )
                                        })
                                        .map(|(sig, mapping)| (sig.class, sig.method, mapping))
                                        .or_else(|| {
                                            self.get_stdlib_runtime_info(
                                                *field,
                                                object.ty,
                                                Some(arg_count),
                                                None,
                                            )
                                        })
                                } else if mn == "tryAcquire" {
                                    // Semaphore.tryAcquire() has overloads: 0 params vs 1 param (with timeout)
                                    let arg_count = args.len();
                                    debug!(
                                        "[tryAcquire lookup] method={}, arg_count={}",
                                        mn, arg_count
                                    );
                                    self.stdlib_mapping
                                        .find_by_name_and_params(
                                            "sys_thread_Semaphore",
                                            mn,
                                            arg_count,
                                        )
                                        .map(|(sig, mapping)| (sig.class, sig.method, mapping))
                                        .or_else(|| {
                                            self.get_stdlib_runtime_info(
                                                *field,
                                                object.ty,
                                                Some(arg_count),
                                                None,
                                            )
                                        })
                                } else {
                                    // Extract receiver class hint by finding which class owns this method symbol
                                    let receiver_hint: Option<String> =
                                        self.find_receiver_class_name(object);
                                    let hint_ref = receiver_hint.as_deref();
                                    self.get_stdlib_runtime_info(
                                        *field,
                                        object.ty,
                                        Some(args.len()),
                                        hint_ref,
                                    )
                                }
                            } else {
                                self.get_stdlib_runtime_info(
                                    *field,
                                    object.ty,
                                    Some(args.len()),
                                    None,
                                )
                            }
                        };

                        if let Some((class_name, method_name, runtime_call)) = stdlib_info {
                            let runtime_func_owned = runtime_call.runtime_name.to_string();
                            let is_mir_wrapper = runtime_call.is_mir_wrapper;
                            let raw_value_params = runtime_call.raw_value_params;
                            let extend_to_i64_params = runtime_call.extend_to_i64_params;
                            let returns_raw_value = runtime_call.returns_raw_value;
                            let has_return = runtime_call.has_return;
                            let explicit_return_type =
                                runtime_call.return_type.map(|rt| rt.to_ir_type());
                            let has_self_param = runtime_call.has_self_param;
                            let runtime_func: &str = &runtime_func_owned;

                            // Try special runtime calls that need custom MIR lowering
                            // (e.g., Type.typeof needs to return boxed ValueType enum)
                            if let Some(special_result) = self.try_lower_special_runtime_call(
                                runtime_func,
                                args,
                                result_type.clone(),
                                expr.source_location,
                            ) {
                                return special_result;
                            }
                            // Method redirected via runtime mapping

                            // Reflect.compare: redirect to haxe_reflect_compare_typed with type tag
                            // Must be done before the generic arg boxing loop below.
                            if runtime_func == "haxe_reflect_compare" && args.len() >= 2 {
                                let type_info = self.infer_reflect_compare_type_info(args);
                                if let Some(info) = type_info {
                                    let mut typed_args = Vec::new();
                                    for arg in args.iter() {
                                        if let Some(reg) = self.lower_expression(arg) {
                                            let reg_ty = self
                                                .builder
                                                .get_register_type(reg)
                                                .unwrap_or(IrType::I64);
                                            let final_reg = if reg_ty != IrType::I64 {
                                                self.builder
                                                    .build_cast(reg, reg_ty, IrType::I64)
                                                    .unwrap_or(reg)
                                            } else {
                                                reg
                                            };
                                            typed_args.push(final_reg);
                                        }
                                    }
                                    let tag_reg = match info {
                                        Ok(tag_value) => {
                                            self.builder.build_const(IrValue::I32(tag_value))?
                                        }
                                        Err(type_param_name) => {
                                            let tag = self.builder.build_const(IrValue::I32(0))?;
                                            if let Some(func) = self.builder.current_function_mut()
                                            {
                                                func.type_param_tag_fixups
                                                    .push((tag, type_param_name));
                                            }
                                            tag
                                        }
                                    };
                                    typed_args.push(tag_reg);
                                    let extern_func_id = self.get_or_register_extern_function(
                                        "haxe_reflect_compare_typed",
                                        vec![IrType::I64, IrType::I64, IrType::I32],
                                        IrType::I64,
                                    );
                                    let call_result = self.builder.build_call_direct(
                                        extern_func_id,
                                        typed_args,
                                        IrType::I64,
                                    )?;
                                    if result_type == IrType::I32 {
                                        return self.builder.build_cast(
                                            call_result,
                                            IrType::I64,
                                            IrType::I32,
                                        );
                                    }
                                    return Some(call_result);
                                }
                            }

                            // Get expected parameter types from the extern function signature
                            // This is critical for generic classes like Deque<T> where the runtime
                            // expects boxed pointers but HIR types may be primitives
                            let (expected_param_types, actual_return_type) = self
                                .get_stdlib_mir_wrapper_signature(runtime_func)
                                .map(|(params, ret)| (params, ret))
                                .unwrap_or_else(|| {
                                    // Fallback: derive from arguments, using stdlib mapping hints
                                    let mut params = vec![IrType::Ptr(Box::new(IrType::U8))];
                                    for (i, arg) in args.iter().enumerate() {
                                        // Check raw_value_params bitmask: bit (i+1) means param i+1
                                        // (bit 0 is self, bit 1 is first user arg, etc.)
                                        let param_bit = 1u32 << (i + 1);
                                        if raw_value_params & param_bit != 0 {
                                            params.push(IrType::U64);
                                        } else if extend_to_i64_params & param_bit != 0 {
                                            params.push(IrType::I64);
                                        } else {
                                            params.push(self.convert_type(arg.ty));
                                        }
                                    }
                                    // Use explicit return type from types: descriptor when available,
                                    // otherwise fall back to legacy inference
                                    let ret_type = if let Some(ref rt) = explicit_return_type {
                                        rt.clone()
                                    } else if returns_raw_value {
                                        IrType::U64
                                    } else if has_return {
                                        result_type.clone()
                                    } else {
                                        IrType::Void
                                    };
                                    (params, ret_type)
                                });
                            debug!(
                                "[Extern method redirect] expected params: {:?}, return type: {:?}",
                                expected_param_types, actual_return_type
                            );

                            // For static stdlib methods (e.g., StringTools.startsWith via `using`),
                            // the object is a class reference, NOT an instance receiver.
                            // The args already include the real receiver (first arg from `using` desugaring).
                            // Don't prepend the class reference as 'this'.
                            let is_static_stdlib = !has_self_param;

                            let mut arg_regs = if is_static_stdlib {
                                Vec::new()
                            } else {
                                // Lower the object (this will be the first parameter)
                                let obj_reg = self.lower_expression(object)?;
                                vec![obj_reg] // 'this' as first arg
                            };
                            for (i, arg) in args.iter().enumerate() {
                                let arg_reg = self.lower_expression(arg)?;
                                let actual_ty = self.convert_type(arg.ty);

                                // Get expected type for this argument
                                // For instance methods, offset by 1 for 'this'
                                let param_idx = if is_static_stdlib { i } else { i + 1 };
                                let expected_ty = expected_param_types
                                    .get(param_idx)
                                    .cloned()
                                    .unwrap_or_else(|| actual_ty.clone());

                                // Auto-box if needed (e.g., Int -> Ptr(U8) for Deque<Int>.add())
                                let final_reg = self.maybe_box_for_extern_call(
                                    arg_reg,
                                    &actual_ty,
                                    &expected_ty,
                                )?;
                                arg_regs.push(final_reg);
                            }

                            // Inject hidden enum type_id arg for runtime enum helpers
                            // (enumEq, enumConstructor, enumParameters, getEnum)
                            self.inject_hidden_enum_type_id_arg(runtime_func, args, &mut arg_regs);

                            // Use the expected parameter types for the extern function registration
                            // This ensures the signature matches what the runtime expects
                            let param_types = if expected_param_types.len() == arg_regs.len() {
                                expected_param_types.clone()
                            } else {
                                // Fallback if lengths don't match
                                let mut params = if is_static_stdlib {
                                    Vec::new()
                                } else {
                                    vec![IrType::Ptr(Box::new(IrType::U8))]
                                };
                                for arg in args {
                                    params.push(self.convert_type(arg.ty));
                                }
                                params
                            };

                            // Register and call the function (MIR wrapper or extern)
                            let call_result = if is_mir_wrapper {
                                let mir_func_id = self.register_stdlib_mir_forward_ref(
                                    runtime_func,
                                    param_types,
                                    actual_return_type.clone(),
                                );
                                self.builder.build_call_direct(
                                    mir_func_id,
                                    arg_regs,
                                    actual_return_type.clone(),
                                )?
                            } else {
                                let extern_func_id = self.get_or_register_extern_function(
                                    runtime_func,
                                    param_types,
                                    actual_return_type.clone(),
                                );
                                self.builder.build_call_direct(
                                    extern_func_id,
                                    arg_regs,
                                    actual_return_type.clone(),
                                )?
                            };

                            // Auto-unbox if runtime returns Ptr(U8) but HIR expects primitive
                            // (e.g., Deque<Int>.pop() returns boxed int that needs unboxing)
                            // For generic classes like Channel<Int>, resolve T from receiver type args
                            let resolved_expected = {
                                let needs_resolve = result_type == IrType::Any
                                    || matches!(&result_type, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::Void))
                                    || result_type == IrType::I64;
                                if needs_resolve {
                                    let type_table = self.type_table.borrow();
                                    type_table
                                        .get(object.ty)
                                        .and_then(|ti| match &ti.kind {
                                            crate::tast::TypeKind::Class { type_args, .. }
                                            | crate::tast::TypeKind::GenericInstance {
                                                type_args,
                                                ..
                                            } => {
                                                if !type_args.is_empty() {
                                                    Some(self.convert_type(type_args[0]))
                                                } else {
                                                    None
                                                }
                                            }
                                            _ => None,
                                        })
                                        .unwrap_or_else(|| result_type.clone())
                                } else {
                                    result_type.clone()
                                }
                            };
                            // Store class hint on result register for subsequent method dispatch.
                            // E.g., Array.iterator() returns ArrayIterator — tag the result so
                            // it.hasNext()/it.next() can find the correct stdlib mapping.
                            //
                            // MIR wrappers return values in their declared type directly —
                            // they don't return boxed DynamicValue* pointers. Skip unboxing
                            // for MIR wrapper calls to avoid spurious dereferences
                            // (e.g., Host.localhost() returns a raw string pointer, not a boxed value).
                            let final_result = if is_mir_wrapper {
                                // MIR wrappers return values in their declared type directly.
                                // array_pop returns raw I64 — cast to Ptr(Void) for class types.
                                let expects_class_ptr = matches!(&resolved_expected, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::Void));
                                if actual_return_type == IrType::I64 && expects_class_ptr {
                                    // Raw I64 → Ptr(Void) cast
                                    self.builder.build_cast(
                                        call_result,
                                        IrType::I64,
                                        IrType::Ptr(Box::new(IrType::Void)),
                                    )
                                } else {
                                    Some(call_result)
                                }
                            } else {
                                self.maybe_unbox_for_extern_return(
                                    call_result,
                                    &actual_return_type,
                                    &resolved_expected,
                                )
                            };
                            if let Some(result_reg) = final_result {
                                let return_class =
                                    Self::get_return_class_hint(class_name, method_name);
                                self.register_class_hints
                                    .insert(result_reg, return_class.to_string());
                            }
                            return final_result;
                        }

                        // FALLBACK: For extern classes not in type_table (like rayzor.Bytes),
                        // try to extract class name from the MIR function's qualified_name
                        debug!(
                            "[FALLBACK check] func_id={:?}, in module={}",
                            func_id,
                            self.builder.module.functions.contains_key(&func_id)
                        );
                        if let Some(func) = self.builder.module.functions.get(&func_id) {
                            debug!(
                                "[FALLBACK] MIR function '{}' has qualified_name: {:?}",
                                func.name, func.qualified_name
                            );
                            if let Some(ref qn) = func.qualified_name {
                                // Pattern: "rayzor.Bytes.set" -> class="rayzor_Bytes", method="set"
                                let parts: Vec<&str> = qn.split('.').collect();
                                if parts.len() >= 2 {
                                    // Get method name (last part) and class name (all but last, joined with underscore)
                                    let mir_method_name = *parts.last().unwrap();
                                    let class_parts = &parts[..parts.len() - 1];
                                    let qualified_class = class_parts.join("_");

                                    // Try to find in stdlib mapping
                                    if let Some((_sig, mapping)) = self
                                        .stdlib_mapping
                                        .find_by_name(&qualified_class, mir_method_name)
                                    {
                                        let runtime_func = mapping.runtime_name;
                                        debug!(
                                            "[Extern method redirect via qualified_name] {}.{} -> {}",
                                            qualified_class, mir_method_name, runtime_func
                                        );

                                        // Get expected parameter types from the extern function signature
                                        let (expected_param_types, actual_return_type) = self
                                            .get_stdlib_mir_wrapper_signature(runtime_func)
                                            .map(|(params, ret)| (params, ret))
                                            .unwrap_or_else(|| {
                                                let mut params =
                                                    vec![IrType::Ptr(Box::new(IrType::U8))];
                                                for arg in args {
                                                    params.push(self.convert_type(arg.ty));
                                                }
                                                // Use explicit return type from types: descriptor when available
                                                let ret_type =
                                                    if let Some(ref rt) = mapping.return_type {
                                                        rt.to_ir_type()
                                                    } else if mapping.has_return {
                                                        result_type.clone()
                                                    } else {
                                                        IrType::Void
                                                    };
                                                (params, ret_type)
                                            });

                                        // Lower the object (this will be the first parameter)
                                        let obj_reg = self.lower_expression(object)?;

                                        // Lower the arguments and auto-box if needed
                                        let mut arg_regs = vec![obj_reg];
                                        for (i, arg) in args.iter().enumerate() {
                                            let arg_reg = self.lower_expression(arg)?;
                                            let actual_ty = self.convert_type(arg.ty);
                                            let expected_ty = expected_param_types
                                                .get(i + 1)
                                                .cloned()
                                                .unwrap_or_else(|| actual_ty.clone());
                                            let final_reg = self.maybe_box_for_extern_call(
                                                arg_reg,
                                                &actual_ty,
                                                &expected_ty,
                                            )?;
                                            arg_regs.push(final_reg);
                                        }

                                        // Use expected parameter types for registration
                                        let param_types =
                                            if expected_param_types.len() == arg_regs.len() {
                                                expected_param_types.clone()
                                            } else {
                                                let mut params =
                                                    vec![IrType::Ptr(Box::new(IrType::U8))];
                                                for arg in args {
                                                    params.push(self.convert_type(arg.ty));
                                                }
                                                params
                                            };

                                        // Register the extern function
                                        let extern_func_id = self.get_or_register_extern_function(
                                            runtime_func,
                                            param_types,
                                            actual_return_type.clone(),
                                        );

                                        // Call the extern function
                                        let call_result = self.builder.build_call_direct(
                                            extern_func_id,
                                            arg_regs,
                                            actual_return_type.clone(),
                                        )?;

                                        // Auto-unbox if runtime returns Ptr(U8) but HIR expects primitive
                                        return self.maybe_unbox_for_extern_return(
                                            call_result,
                                            &actual_return_type,
                                            &result_type,
                                        );
                                    }
                                }
                            }
                        }

                        // Check for virtual dispatch: if the method is in a class hierarchy
                        // with overrides, dispatch through the vtable instead of calling directly.
                        // Skip vtable for super.method() — must call parent directly.
                        let object_is_super = matches!(object.kind, HirExprKind::Super);
                        let vtable_lookup = if object_is_super { None } else { self.virtual_dispatch_info.get(field).copied()
                            .or_else(|| {
                                let method_name = self.symbol_table.get_symbol(*field).map(|s| s.name);
                                if let Some(method_name) = method_name {
                                    let receiver_class_sym = {
                                        let type_table = self.type_table.borrow();
                                        type_table.get(object.ty).and_then(|t| {
                                            match &t.kind {
                                                TypeKind::Class { symbol_id, .. } => Some(*symbol_id),
                                                _ => None,
                                            }
                                        })
                                    };
                                    if let Some(class_sym) = receiver_class_sym {
                                        if let Some(&method_sym) = self.class_method_by_name.get(&(class_sym, method_name)) {
                                            return self.virtual_dispatch_info.get(&method_sym).copied();
                                        }
                                        let mut current = class_sym;
                                        while let Some(&parent) = self.class_parent_map.get(&current) {
                                            if let Some(&method_sym) = self.class_method_by_name.get(&(parent, method_name)) {
                                                return self.virtual_dispatch_info.get(&method_sym).copied();
                                            }
                                            current = parent;
                                        }
                                    }
                                }
                                None
                            })
                        };
                        if let Some((slot_index, _)) = vtable_lookup {
                            let obj_reg = self.lower_expression(object)?;

                            // If Dynamic-typed, unbox to get raw object pointer
                            let obj_reg = {
                                let is_dynamic = {
                                    let type_table = self.type_table.borrow();
                                    type_table
                                        .get(object.ty)
                                        .map(|t| matches!(t.kind, TypeKind::Dynamic))
                                        .unwrap_or(false)
                                };
                                if is_dynamic {
                                    let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                                    let unbox_func_id = self.get_or_register_extern_function(
                                        "haxe_unbox_reference_ptr",
                                        vec![ptr_u8.clone()],
                                        ptr_u8.clone(),
                                    );
                                    self.builder.build_call_direct(
                                        unbox_func_id,
                                        vec![obj_reg],
                                        ptr_u8,
                                    )?
                                } else {
                                    obj_reg
                                }
                            };

                            // Lower arguments
                            let mut call_args = vec![obj_reg];
                            for arg in args.iter() {
                                if let Some(reg) = self.lower_expression(arg) {
                                    call_args.push(reg);
                                }
                            }

                            // haxe_vtable_lookup(obj, slot) -> closure_ptr (i64)
                            let lookup_fn = self.get_or_register_extern_function(
                                "haxe_vtable_lookup",
                                vec![IrType::Ptr(Box::new(IrType::U8)), IrType::I32],
                                IrType::I64,
                            );
                            let slot_reg =
                                self.builder.build_const(IrValue::I32(slot_index as i32))?;
                            let closure_ptr = self.builder.build_call_direct(
                                lookup_fn,
                                vec![obj_reg, slot_reg],
                                IrType::I64,
                            )?;

                            // Build the function signature for the indirect call
                            let mut param_types = vec![IrType::Ptr(Box::new(IrType::Void))]; // self
                            for arg in args {
                                param_types.push(self.convert_type(arg.ty));
                            }
                            let return_type = Box::new(self.convert_type(expr.ty));
                            let func_signature = IrType::Function {
                                params: param_types,
                                return_type,
                                varargs: false,
                            };

                            return self.builder.build_call_indirect(
                                closure_ptr,
                                call_args,
                                func_signature,
                            );
                        }

                        // super.method() — resolve to parent class method directly
                        if object_is_super {
                            if let Some(method_name_i) = method_name_interned {
                                // Find current class → parent via class_parent_map
                                let current_class = self.builder.current_function()
                                    .and_then(|f| {
                                        self.class_method_by_name.iter()
                                            .find(|(_, &method_sym)| {
                                                self.function_map.get(&method_sym) == Some(&f.id)
                                            })
                                            .map(|((class_sym, _), _)| *class_sym)
                                    });
                                let parent_class = current_class
                                    .and_then(|cls| self.class_parent_map.get(&cls).copied());
                                let parent_method_func_id = parent_class.and_then(|pc| {
                                    self.class_method_by_name.get(&(pc, method_name_i))
                                        .and_then(|&sym| self.resolve_function_id_with_qualified_fallback(sym))
                                }).or_else(|| {
                                    self.resolve_function_id_with_qualified_fallback(*field)
                                });
                                if let Some(func_id) = parent_method_func_id {
                                    let obj_reg = self.lower_expression(object)?;
                                    let mut call_args = vec![obj_reg];
                                    for arg in args {
                                        if let Some(reg) = self.lower_expression(arg) {
                                            call_args.push(reg);
                                        }
                                    }
                                    let ret = self.convert_type(expr.ty);
                                    return self.builder.build_call_direct(func_id, call_args, ret);
                                }
                            }
                        }

                        // Regular method call (not extern or no runtime mapping)
                        // Detect static calls: if the object is a class/abstract symbol
                        // reference (not an instance), this is a static method call and
                        // the object should NOT be passed as 'this'.
                        let is_static_class_call = if let HirExprKind::Variable {
                            symbol: obj_sym,
                            ..
                        } = &object.kind
                        {
                            let kind = self.symbol_table.get_symbol(*obj_sym).map(|s| s.kind);
                            kind.map(|k| {
                                matches!(
                                    k,
                                    crate::tast::symbols::SymbolKind::Class
                                        | crate::tast::symbols::SymbolKind::Abstract
                                        | crate::tast::symbols::SymbolKind::TypeAlias
                                )
                            })
                            .unwrap_or(false)
                        } else {
                            false
                        };

                        // @:derive(Default) synthetic static createDefault() — zero-initialized instance
                        if is_static_class_call
                            && method_name == Some("createDefault")
                            && args.is_empty()
                        {
                            if let HirExprKind::Variable {
                                symbol: obj_sym, ..
                            } = &object.kind
                            {
                                // For static calls, obj_sym is the class symbol itself.
                                // Also try resolving through type_id → TypeKind::Class → symbol_id.
                                let class_sym = self
                                    .symbol_table
                                    .get_symbol(*obj_sym)
                                    .and_then(|s| {
                                        let type_table = self.type_table.borrow();
                                        type_table.get(s.type_id).and_then(|t| {
                                            if let TypeKind::Class { symbol_id, .. } = &t.kind {
                                                Some(*symbol_id)
                                            } else {
                                                None
                                            }
                                        })
                                    })
                                    .or(Some(*obj_sym))
                                    .filter(|sym| self.derive_default_classes.contains(sym));
                                if let Some(sym) = class_sym {
                                    return self.lower_derived_default(sym);
                                }
                            }
                        }

                        if is_static_class_call {
                            // Check if this static call has a stdlib runtime mapping.
                            // Static method calls (e.g., Reflect.hasField, Type.typeof, Std.string)
                            // arrive here as Field { object: ClassVar, field: method } and the
                            // stdlib_info lookup above may have failed because the class variable's
                            // TypeId isn't in type_table. Route through the extern function.
                            let static_class_name = self.find_receiver_class_name(object);
                            let static_method_name = self
                                .symbol_table
                                .get_symbol(*field)
                                .and_then(|s| self.string_interner.get(s.name))
                                .map(|s| s.to_string());

                            // Also try to get class name from the object symbol directly.
                            // Prefer native_name or qualified_name (fully qualified) over
                            // bare name so that extern classes like sys.net.Host resolve to
                            // "sys_net_Host" instead of just "Host".
                            let static_class_name = static_class_name.or_else(|| {
                                if let HirExprKind::Variable {
                                    symbol: obj_sym, ..
                                } = &object.kind
                                {
                                    let sym = self.symbol_table.get_symbol(*obj_sym)?;
                                    // 1) native_name  (e.g. "sys::net::Host" → "sys_net_Host")
                                    if let Some(native) = sym.native_name {
                                        if let Some(ns) = self.string_interner.get(native) {
                                            return Some(ns.replace("::", "_"));
                                        }
                                    }
                                    // 2) qualified_name  (e.g. "sys.net.Host" → "sys_net_Host")
                                    if let Some(qn) = sym.qualified_name {
                                        if let Some(qs) = self.string_interner.get(qn) {
                                            return Some(qs.replace('.', "_"));
                                        }
                                    }
                                    // 3) bare name fallback
                                    self.string_interner.get(sym.name).map(|s| s.to_string())
                                } else {
                                    None
                                }
                            });

                            if let (Some(ref cls), Some(ref mn)) =
                                (&static_class_name, &static_method_name)
                            {
                                let static_stdlib_info = self
                                    .stdlib_mapping
                                    .find_by_name_and_params(cls, mn, args.len())
                                    .or_else(|| self.stdlib_mapping.find_by_name(cls, mn))
                                    .map(|(sig, mapping)| (sig.class, sig.method, mapping));

                                if let Some((sc_class_name, sc_method_name, runtime_call)) =
                                    static_stdlib_info
                                {
                                    let runtime_func = runtime_call.runtime_name;
                                    let is_mir_wrapper = runtime_call.is_mir_wrapper;
                                    let returns_raw_value = runtime_call.returns_raw_value;
                                    let has_return = runtime_call.has_return;
                                    let raw_value_params = runtime_call.raw_value_params;
                                    let extend_to_i64_params = runtime_call.extend_to_i64_params;
                                    let explicit_return_type =
                                        runtime_call.return_type.map(|rt| rt.to_ir_type());

                                    // First, try special runtime calls that need custom MIR lowering
                                    // (e.g., Reflect.callMethod, Reflect.makeVarArgs, Type.typeof)
                                    if let Some(special_result) = self
                                        .try_lower_special_runtime_call(
                                            runtime_func,
                                            args,
                                            result_type.clone(),
                                            expr.source_location,
                                        )
                                    {
                                        return special_result;
                                    }

                                    // Get expected parameter types from the mapping
                                    let (expected_param_types, actual_return_type) = self
                                        .get_stdlib_mir_wrapper_signature(runtime_func)
                                        .unwrap_or_else(|| {
                                            let mut params = Vec::new();
                                            for (i, arg) in args.iter().enumerate() {
                                                let param_bit = 1u32 << i;
                                                if raw_value_params & param_bit != 0 {
                                                    params.push(IrType::U64);
                                                } else if extend_to_i64_params & param_bit != 0 {
                                                    params.push(IrType::I64);
                                                } else {
                                                    params.push(self.convert_type(arg.ty));
                                                }
                                            }
                                            let ret_type =
                                                if let Some(ref ert) = explicit_return_type {
                                                    ert.clone()
                                                } else if returns_raw_value {
                                                    IrType::U64
                                                } else if has_return {
                                                    result_type.clone()
                                                } else {
                                                    IrType::Void
                                                };
                                            (params, ret_type)
                                        });

                                    // Lower arguments (no 'this' for static methods)
                                    let mut arg_regs = Vec::new();
                                    for (i, arg) in args.iter().enumerate() {
                                        let arg_reg = self.lower_expression(arg)?;
                                        let actual_ty = self.convert_type(arg.ty);
                                        let expected_ty = expected_param_types
                                            .get(i)
                                            .cloned()
                                            .unwrap_or_else(|| actual_ty.clone());
                                        let final_reg = self.maybe_box_for_extern_call(
                                            arg_reg,
                                            &actual_ty,
                                            &expected_ty,
                                        )?;
                                        arg_regs.push(final_reg);
                                    }

                                    if is_mir_wrapper {
                                        let param_types: Vec<_> = arg_regs
                                            .iter()
                                            .map(|r| {
                                                self.builder
                                                    .get_register_type(*r)
                                                    .unwrap_or(IrType::I64)
                                            })
                                            .collect();
                                        let mir_func_id = self.register_stdlib_mir_forward_ref(
                                            runtime_func,
                                            param_types,
                                            actual_return_type.clone(),
                                        );
                                        return self.builder.build_call_direct(
                                            mir_func_id,
                                            arg_regs,
                                            actual_return_type,
                                        );
                                    }

                                    // Inject hidden enum type_id arg for runtime enum helpers
                                    // (enumEq, enumConstructor, enumParameters, getEnum)
                                    self.inject_hidden_enum_type_id_arg(
                                        runtime_func,
                                        args,
                                        &mut arg_regs,
                                    );

                                    let param_types: Vec<_> = arg_regs
                                        .iter()
                                        .map(|r| {
                                            self.builder
                                                .get_register_type(*r)
                                                .unwrap_or(IrType::I64)
                                        })
                                        .collect();
                                    let extern_func_id = self.get_or_register_extern_function(
                                        runtime_func,
                                        param_types,
                                        actual_return_type.clone(),
                                    );

                                    let call_result = self.builder.build_call_direct(
                                        extern_func_id,
                                        arg_regs,
                                        actual_return_type.clone(),
                                    );

                                    // Handle returns_raw_value: cast raw U64 to appropriate type
                                    if returns_raw_value {
                                        if let Some(raw_reg) = call_result {
                                            return match &result_type {
                                                IrType::I32 => self.builder.build_cast(
                                                    raw_reg,
                                                    IrType::U64,
                                                    IrType::I32,
                                                ),
                                                IrType::Bool => self.builder.build_cast(
                                                    raw_reg,
                                                    IrType::U64,
                                                    IrType::Bool,
                                                ),
                                                _ => Some(raw_reg),
                                            };
                                        }
                                    }

                                    return call_result;
                                }
                            }

                            // Static call: do NOT include the class reference as 'this'
                            let callee_is_user_defined = self
                                .builder
                                .module
                                .functions
                                .get(&func_id)
                                .map(|f| f.kind == crate::ir::functions::FunctionKind::UserDefined)
                                .unwrap_or(false);

                            let mut arg_regs = Vec::new();
                            for (param_idx, arg) in args.iter().enumerate() {
                                if let Some(reg) = self.lower_expression(arg) {
                                    // Materialize anon-backed variables at call boundary
                                    let reg = self.maybe_materialize_for_call(
                                        arg,
                                        reg,
                                        Some(func_id),
                                        param_idx,
                                    );
                                    // @:derive(Copy): copy variable args at call boundary
                                    let reg = if let HirExprKind::Variable { .. } = &arg.kind {
                                        if let Some(class_sym) = self.get_copy_class_symbol(arg.ty)
                                        {
                                            self.emit_shallow_copy(reg, class_sym).unwrap_or(reg)
                                        } else {
                                            reg
                                        }
                                    } else {
                                        reg
                                    };
                                    if callee_is_user_defined {
                                        let is_heap_intermediate = matches!(
                                            &arg.kind,
                                            HirExprKind::New { .. } | HirExprKind::Call { .. }
                                        ) && self
                                            .get_drop_behavior(arg.ty)
                                            == DropBehavior::AutoDrop;
                                        if is_heap_intermediate {
                                            self.temp_heap_values.push(reg);
                                        }
                                    }
                                    arg_regs.push(reg);
                                }
                            }

                            self.fill_default_args(func_id, &mut arg_regs, false);

                            let actual_return_type =
                                if let Some(func) = self.builder.module.functions.get(&func_id) {
                                    func.signature.return_type.clone()
                                } else {
                                    result_type.clone()
                                };

                            return self.builder.build_call_direct(
                                func_id,
                                arg_regs,
                                actual_return_type,
                            );
                        }

                        // Lower the object (this will be the first parameter)
                        let obj_reg = self.lower_expression(object)?;

                        // If the object is Dynamic-typed, unbox it to get the raw object pointer.
                        // Dynamic variables store a boxed DynamicValue*, but the method expects
                        // a raw class pointer as 'this'.
                        let obj_reg = {
                            let is_dynamic = {
                                let type_table = self.type_table.borrow();
                                type_table
                                    .get(object.ty)
                                    .map(|t| matches!(t.kind, TypeKind::Dynamic))
                                    .unwrap_or(false)
                            };
                            if is_dynamic {
                                let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                                let unbox_func_id = self.get_or_register_extern_function(
                                    "haxe_unbox_reference_ptr",
                                    vec![ptr_u8.clone()],
                                    ptr_u8.clone(),
                                );
                                self.builder.build_call_direct(
                                    unbox_func_id,
                                    vec![obj_reg],
                                    ptr_u8,
                                )?
                            } else {
                                obj_reg
                            }
                        };

                        // Track NEW expressions as temps (not Call results — they may be references)
                        let is_new_temp = matches!(&object.kind, HirExprKind::New { .. })
                            && self.get_drop_behavior(object.ty) == DropBehavior::AutoDrop;
                        if is_new_temp {
                            self.temp_heap_values.push(obj_reg);
                        }

                        // Lower the arguments — track heap intermediates only for user-defined callees
                        let callee_is_user_defined = self
                            .builder
                            .module
                            .functions
                            .get(&func_id)
                            .map(|f| f.kind == crate::ir::functions::FunctionKind::UserDefined)
                            .unwrap_or(false);

                        let mut method_arg_regs = vec![obj_reg]; // 'this' as first arg
                        for arg in args.iter() {
                            if let Some(reg) = self.lower_expression(arg) {
                                if callee_is_user_defined {
                                    let is_heap_intermediate = matches!(
                                        &arg.kind,
                                        HirExprKind::New { .. } | HirExprKind::Call { .. }
                                    ) && self.get_drop_behavior(arg.ty)
                                        == DropBehavior::AutoDrop;
                                    if is_heap_intermediate {
                                        self.temp_heap_values.push(reg);
                                    }
                                }
                                method_arg_regs.push(reg);
                            }
                        }
                        let arg_regs = method_arg_regs;

                        // IMPORTANT: Use the function's actual return type, not expr.ty
                        // expr.ty can be incorrect (e.g., unresolved TypeParameter or wrong type)
                        let actual_return_type = if let Some(func) =
                            self.builder.module.functions.get(&func_id)
                        {
                            debug!(
                                "[Field method] Using actual return type {:?} for function {:?}",
                                func.signature.return_type, func.name
                            );
                            func.signature.return_type.clone()
                        } else {
                            debug!(
                                "[Field method] Function not found in module, using expr return type {:?}",
                                result_type
                            );
                            result_type.clone()
                        };

                        // debug!("Calling method with {} args (including this)", arg_regs.len());
                        let call_result = self.builder.build_call_direct(
                            func_id,
                            arg_regs,
                            actual_return_type.clone(),
                        )?;

                        // Auto-unbox for generic stdlib methods (e.g., Channel<Int>.tryReceive())
                        // When the function returns Ptr(U8) but the caller expects a resolved generic type,
                        // we need to unbox. Resolve T from the receiver object's type arguments.
                        let actual_is_ptr = matches!(&actual_return_type, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::U8 | IrType::Void));
                        if actual_is_ptr && actual_return_type != IrType::Void {
                            let resolved_type = {
                                let type_table = self.type_table.borrow();
                                type_table.get(object.ty).and_then(|ti| {
                                    match &ti.kind {
                                        crate::tast::TypeKind::Class { type_args, .. }
                                        | crate::tast::TypeKind::GenericInstance {
                                            type_args,
                                            ..
                                        } => {
                                            if !type_args.is_empty() {
                                                let t = self.convert_type(type_args[0]);
                                                // Only unbox if resolved to a concrete primitive
                                                if matches!(
                                                    t,
                                                    IrType::I32
                                                        | IrType::I64
                                                        | IrType::F32
                                                        | IrType::F64
                                                        | IrType::Bool
                                                ) {
                                                    Some(t)
                                                } else {
                                                    None
                                                }
                                            } else {
                                                None
                                            }
                                        }
                                        _ => None,
                                    }
                                })
                            };
                            if let Some(ref resolved) = resolved_type {
                                return self.maybe_unbox_for_extern_return(
                                    call_result,
                                    &actual_return_type,
                                    resolved,
                                );
                            }
                        }
                        return Some(call_result);
                    } else {
                        // Method not found by direct symbol lookup
                        // Check if this is a Dynamic method call or stdlib method
                        let object_type = object.ty;

                        // Check if the object is a stdlib class (including extern abstracts like Ptr, Ref, Box, Usize)
                        // These should resolve via stdlib_mapping without any Dynamic unboxing
                        debug!(
                            "[FIELDACCESS] Entering stdlib class check for object_type={:?}",
                            object_type
                        );
                        {
                            let type_table = self.type_table.borrow();
                            let class_symbol_id =
                                if let Some(type_info) = type_table.get(object_type) {
                                    match &type_info.kind {
                                        TypeKind::Class { symbol_id, .. } => Some(*symbol_id),
                                        TypeKind::Abstract { symbol_id, .. } => Some(*symbol_id),
                                        TypeKind::GenericInstance { base_type, .. } => {
                                            // For GenericInstance like ObjectMap<Point, Int>,
                                            // resolve the base class/abstract symbol
                                            if let Some(base_info) = type_table.get(*base_type) {
                                                match &base_info.kind {
                                                    TypeKind::Class { symbol_id, .. } => {
                                                        Some(*symbol_id)
                                                    }
                                                    TypeKind::Abstract { symbol_id, .. } => {
                                                        Some(*symbol_id)
                                                    }
                                                    _ => None,
                                                }
                                            } else {
                                                None
                                            }
                                        }
                                        _ => None,
                                    }
                                } else {
                                    None
                                };

                            // Also try HIR type declarations for extern classes not in type_table
                            let class_symbol_id = class_symbol_id.or_else(|| {
                                if let Some(type_decl) = self.current_hir_types.get(&object_type) {
                                    if let HirTypeDecl::Class(class) = type_decl {
                                        return Some(class.symbol_id);
                                    }
                                }
                                None
                            });

                            // For static class calls where object.ty is invalid (TypeId::MAX),
                            // extract the class symbol directly from the object Variable expression
                            let class_symbol_id = class_symbol_id.or_else(|| {
                                if let HirExprKind::Variable {
                                    symbol: obj_sym, ..
                                } = &object.kind
                                {
                                    let sym = self.symbol_table.get_symbol(*obj_sym)?;
                                    if matches!(
                                        sym.kind,
                                        crate::tast::SymbolKind::Class
                                            | crate::tast::SymbolKind::Abstract
                                            | crate::tast::SymbolKind::TypeAlias
                                    ) {
                                        return Some(*obj_sym);
                                    }
                                }
                                None
                            });

                            if let Some(sym_id) = class_symbol_id {
                                // Get the class name from qualified_name or native_name
                                let class_name_from_obj =
                                    self.symbol_table.get_symbol(sym_id).and_then(|s| {
                                        // Prefer native_name (from @:native annotation)
                                        s.native_name
                                            .and_then(|nn| self.string_interner.get(nn))
                                            .map(|ns| ns.replace("::", "_"))
                                            .or_else(|| {
                                                s.qualified_name
                                                    .and_then(|qn| self.string_interner.get(qn))
                                                    .map(|s| s.replace(".", "_"))
                                            })
                                    });

                                let method_name_opt = self
                                    .symbol_table
                                    .get_symbol(*field)
                                    .and_then(|s| self.string_interner.get(s.name));

                                // PRIORITY: Use the field's qualified name to derive the class,
                                // since the field symbol knows which package it belongs to.
                                // This prevents sys.thread.Thread.sleep from being resolved
                                // via rayzor.concurrent.Thread when the class symbol is shared.
                                let class_name_from_field = self
                                    .symbol_table
                                    .get_symbol(*field)
                                    .and_then(|s| s.qualified_name)
                                    .and_then(|qn| self.string_interner.get(qn))
                                    .and_then(|qn_str| {
                                        let parts: Vec<&str> = qn_str.split('.').collect();
                                        if parts.len() >= 2 {
                                            Some(parts[..parts.len() - 1].join("_"))
                                        } else {
                                            None
                                        }
                                    });

                                let class_name_opt = class_name_from_field.or(class_name_from_obj);

                                // Also try bare class name as final fallback
                                let class_name_opt = class_name_opt.or_else(|| {
                                    self.symbol_table
                                        .get_symbol(sym_id)
                                        .and_then(|s| self.string_interner.get(s.name))
                                        .map(|s| s.to_string())
                                });

                                if let (Some(class_name), Some(method_name)) =
                                    (class_name_opt, method_name_opt)
                                {
                                    // Look up in stdlib_mapping (try abstract's own name first, then @:forward underlying)
                                    let stdlib_result = self
                                        .stdlib_mapping
                                        .find_by_name(&class_name, method_name)
                                        .map(|(sig, m)| (sig.clone(), m.clone()))
                                        .or_else(|| {
                                            // @:forward fallback: check if method should be forwarded to underlying type
                                            let (underlying_type, forward_list) =
                                                self.abstract_forward_rules.get(&sym_id)?;
                                            // Check if this method is in the forward list (empty = forward all)
                                            let method_interned = self
                                                .symbol_table
                                                .get_symbol(*field)
                                                .map(|s| s.name);
                                            let is_forwarded = forward_list.is_empty()
                                                || method_interned
                                                    .map_or(false, |n| forward_list.contains(&n));
                                            if !is_forwarded {
                                                return None;
                                            }
                                            // Resolve underlying type's class name
                                            let underlying_class = self
                                                .resolve_type_class_name_with(
                                                    &type_table,
                                                    *underlying_type,
                                                )?;
                                            self.stdlib_mapping
                                                .find_by_name(&underlying_class, method_name)
                                                .map(|(sig, m)| (sig.clone(), m.clone()))
                                        });

                                    if let Some((sig, mapping)) = stdlib_result {
                                        // Extract data before dropping borrows
                                        let is_mir_wrapper = mapping.is_mir_wrapper;
                                        let runtime_name = mapping.runtime_name.to_string();
                                        let has_return = mapping.has_return;
                                        let returns_raw_value = mapping.returns_raw_value;
                                        let raw_value_params = mapping.raw_value_params;
                                        let extend_to_i64_params = mapping.extend_to_i64_params;
                                        let explicit_return_type =
                                            mapping.return_type.map(|rt| rt.to_ir_type());
                                        let mapping_is_static = sig.is_static;
                                        drop(type_table);

                                        // First, try special runtime calls that need custom MIR lowering
                                        // (e.g., Reflect.callMethod, Reflect.makeVarArgs, Type.typeof)
                                        if let Some(special_result) = self
                                            .try_lower_special_runtime_call(
                                                &runtime_name,
                                                args,
                                                result_type.clone(),
                                                expr.source_location,
                                            )
                                        {
                                            return special_result;
                                        }

                                        // Std.string on ValueType enum values needs special routing
                                        // (same check that trace/interpolation paths do)
                                        if runtime_name == "haxe_std_string_ptr" && args.len() == 1
                                        {
                                            if self.expr_is_value_type_expr(&args[0]) {
                                                let arg_reg = self.lower_expression(&args[0])?;
                                                return self.convert_value_type_to_string(arg_reg);
                                            }
                                        }

                                        // Reflect.compare: detect arg types from expressions and
                                        // route to haxe_reflect_compare_typed. This avoids boxing
                                        // and ensures string comparison works correctly.
                                        // Must be done before the arg boxing loop below.
                                        if runtime_name == "haxe_reflect_compare" && args.len() >= 2
                                        {
                                            let type_info =
                                                self.infer_reflect_compare_type_info(args);
                                            if let Some(info) = type_info {
                                                let mut arg_regs = Vec::new();
                                                for arg in args.iter() {
                                                    if let Some(reg) = self.lower_expression(arg) {
                                                        let reg_ty = self
                                                            .builder
                                                            .get_register_type(reg)
                                                            .unwrap_or(IrType::I64);
                                                        let final_reg = if reg_ty != IrType::I64 {
                                                            self.builder
                                                                .build_cast(
                                                                    reg,
                                                                    reg_ty,
                                                                    IrType::I64,
                                                                )
                                                                .unwrap_or(reg)
                                                        } else {
                                                            reg
                                                        };
                                                        arg_regs.push(final_reg);
                                                    }
                                                }
                                                let tag_reg = match info {
                                                    Ok(tag_value) => self
                                                        .builder
                                                        .build_const(IrValue::I32(tag_value))?,
                                                    Err(type_param_name) => {
                                                        // Generic: placeholder tag with fixup
                                                        let tag = self
                                                            .builder
                                                            .build_const(IrValue::I32(0))?;
                                                        if let Some(func) =
                                                            self.builder.current_function_mut()
                                                        {
                                                            func.type_param_tag_fixups
                                                                .push((tag, type_param_name));
                                                        }
                                                        tag
                                                    }
                                                };
                                                arg_regs.push(tag_reg);
                                                let extern_func_id = self
                                                    .get_or_register_extern_function(
                                                        "haxe_reflect_compare_typed",
                                                        vec![IrType::I64, IrType::I64, IrType::I32],
                                                        IrType::I64,
                                                    );
                                                let call_result = self.builder.build_call_direct(
                                                    extern_func_id,
                                                    arg_regs,
                                                    IrType::I64,
                                                )?;
                                                if result_type == IrType::I32 {
                                                    return self.builder.build_cast(
                                                        call_result,
                                                        IrType::I64,
                                                        IrType::I32,
                                                    );
                                                }
                                                return Some(call_result);
                                            }
                                        }

                                        // Lower args, auto-boxing primitives when the MIR wrapper
                                        // expects Ptr(U8) (e.g., Channel<Int>.send(42)).
                                        // For instance methods, prepend object as receiver (param 0).
                                        // For static methods, skip the object — it's just a class ref.
                                        let mir_wrapper_sig =
                                            self.get_stdlib_mir_wrapper_signature(&runtime_name);
                                        let is_static_call = mapping_is_static || !*is_method;
                                        let mut arg_regs = Vec::new();
                                        if !is_static_call {
                                            let obj_reg = self.lower_expression(object)?;
                                            arg_regs.push(obj_reg);
                                        }
                                        for (i, arg) in args.iter().enumerate() {
                                            if let Some(reg) = self.lower_expression(arg) {
                                                let actual_ty = self.convert_type(arg.ty);
                                                // For instance methods, param 0 = receiver, user args start at i+1
                                                // For static methods, no receiver, user args start at i
                                                let param_idx =
                                                    if is_static_call { i } else { i + 1 };
                                                let expected_ty = mir_wrapper_sig
                                                    .as_ref()
                                                    .and_then(|(params, _)| {
                                                        params.get(param_idx).cloned()
                                                    })
                                                    .unwrap_or_else(|| actual_ty.clone());
                                                let final_reg = self.maybe_box_for_extern_call(
                                                    reg,
                                                    &actual_ty,
                                                    &expected_ty,
                                                )?;
                                                arg_regs.push(final_reg);
                                            }
                                        }

                                        if is_mir_wrapper {
                                            let param_types: Vec<_> = mir_wrapper_sig
                                                .as_ref()
                                                .map(|(params, _)| params.clone())
                                                .unwrap_or_else(|| {
                                                    arg_regs
                                                        .iter()
                                                        .map(|r| {
                                                            self.builder
                                                                .get_register_type(*r)
                                                                .unwrap_or(IrType::I64)
                                                        })
                                                        .collect()
                                                });

                                            let mir_return_type = mir_wrapper_sig
                                                .as_ref()
                                                .map(|(_, ret)| ret.clone())
                                                .unwrap_or_else(|| result_type.clone());

                                            let mir_func_id = self.register_stdlib_mir_forward_ref(
                                                &runtime_name,
                                                param_types,
                                                mir_return_type.clone(),
                                            );

                                            let call_result = self.builder.build_call_direct(
                                                mir_func_id,
                                                arg_regs,
                                                mir_return_type.clone(),
                                            )?;

                                            // Resolve generic return type from receiver's type arguments
                                            // For Channel<Int>.tryReceive() -> Null<Int>, result_type may be
                                            // Ptr(Void) (Dynamic) because the generic T is not resolved.
                                            // We resolve T from the receiver object's actual type args.
                                            let resolved_result = {
                                                let needs_resolve = result_type == IrType::Any
                                                    || matches!(&result_type, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::Void))
                                                    || result_type == IrType::I64;
                                                if needs_resolve {
                                                    let type_table = self.type_table.borrow();
                                                    type_table.get(object.ty).and_then(|ti| {
                                                        if let crate::tast::TypeKind::Class { type_args, .. } = &ti.kind {
                                                            if !type_args.is_empty() {
                                                                Some(self.convert_type(type_args[0]))
                                                            } else {
                                                                None
                                                            }
                                                        } else if let crate::tast::TypeKind::GenericInstance { type_args, .. } = &ti.kind {
                                                            if !type_args.is_empty() {
                                                                Some(self.convert_type(type_args[0]))
                                                            } else {
                                                                None
                                                            }
                                                        } else {
                                                            None
                                                        }
                                                    }).unwrap_or_else(|| result_type.clone())
                                                } else {
                                                    result_type.clone()
                                                }
                                            };

                                            // MIR wrappers return values in their declared type directly —
                                            // no unboxing needed (they don't return boxed DynamicValue*).
                                            return Some(call_result);
                                        } else {
                                            // Inject hidden enum type_id arg for runtime enum helpers
                                            let pre = arg_regs.len();
                                            self.inject_hidden_enum_type_id_arg(
                                                &runtime_name,
                                                args,
                                                &mut arg_regs,
                                            );

                                            // Use explicit types from the types: descriptor when available
                                            let (param_types, return_type) = self
                                                .get_stdlib_mir_wrapper_signature(&runtime_name)
                                                .unwrap_or_else(|| {
                                                    let params: Vec<_> = arg_regs
                                                        .iter()
                                                        .enumerate()
                                                        .map(|(i, r)| {
                                                            let param_bit = 1u32 << i;
                                                            if raw_value_params & param_bit != 0 {
                                                                IrType::U64
                                                            } else if extend_to_i64_params
                                                                & param_bit
                                                                != 0
                                                            {
                                                                IrType::I64
                                                            } else {
                                                                self.builder
                                                                    .get_register_type(*r)
                                                                    .unwrap_or(IrType::I64)
                                                            }
                                                        })
                                                        .collect();
                                                    let ret = if let Some(ref ert) =
                                                        explicit_return_type
                                                    {
                                                        ert.clone()
                                                    } else if returns_raw_value {
                                                        IrType::U64
                                                    } else if has_return {
                                                        result_type.clone()
                                                    } else {
                                                        IrType::Void
                                                    };
                                                    (params, ret)
                                                });

                                            let extern_func_id = self
                                                .get_or_register_extern_function(
                                                    &runtime_name,
                                                    param_types,
                                                    return_type.clone(),
                                                );

                                            let call_result = self.builder.build_call_direct(
                                                extern_func_id,
                                                arg_regs,
                                                return_type.clone(),
                                            );

                                            // Auto-unbox if runtime returns Ptr(U8) but HIR expects primitive
                                            if let Some(call_reg) = call_result {
                                                return self.maybe_unbox_for_extern_return(
                                                    call_reg,
                                                    &return_type,
                                                    &result_type,
                                                );
                                            }
                                            return call_result;
                                        }
                                    }
                                }
                            }
                        }

                        // First check if the object is Dynamic - handle auto-unbox for method calls
                        let type_table = self.type_table.borrow();
                        if let Some(type_info) = type_table.get(object_type) {
                            if matches!(type_info.kind, TypeKind::Dynamic) {
                                // Dynamic method call - need to resolve method by name
                                drop(type_table);

                                let method_name =
                                    self.symbol_table.get_symbol(*field).map(|s| s.name);
                                if let Some(name) = method_name {
                                    // Look up function by name in function_map
                                    let mut found_func = None;
                                    for (sym, &func_id) in &self.function_map {
                                        if let Some(sym_info) = self.symbol_table.get_symbol(*sym) {
                                            if sym_info.name == name {
                                                found_func = Some(func_id);
                                                break;
                                            }
                                        }
                                    }

                                    if let Some(func_id) = found_func {
                                        // Lower the object and unbox it
                                        let obj_reg = self.lower_expression(object)?;

                                        // Unbox the Dynamic to get the actual object pointer
                                        let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                                        let unbox_func_id = self.get_or_register_extern_function(
                                            "haxe_unbox_reference_ptr",
                                            vec![ptr_u8.clone()],
                                            ptr_u8.clone(),
                                        );
                                        let unboxed_obj = self.builder.build_call_direct(
                                            unbox_func_id,
                                            vec![obj_reg],
                                            ptr_u8,
                                        )?;

                                        // Lower the arguments
                                        let arg_regs: Vec<_> =
                                            std::iter::once(unboxed_obj) // Add unboxed 'this' as first arg
                                                .chain(
                                                    args.iter()
                                                        .filter_map(|a| self.lower_expression(a)),
                                                )
                                                .collect();

                                        // Get the function's actual return type
                                        let actual_return_type = if let Some(func) =
                                            self.builder.module.functions.get(&func_id)
                                        {
                                            func.signature.return_type.clone()
                                        } else {
                                            result_type.clone()
                                        };

                                        return self.builder.build_call_direct(
                                            func_id,
                                            arg_regs,
                                            actual_return_type,
                                        );
                                    }
                                }
                            }
                        }

                        // Check if the object type is a String - handle String method calls
                        {
                            let type_table = self.type_table.borrow();
                            if let Some(type_info) = type_table.get(object_type) {
                                debug!(
                                    "[CHECK STRING] object_type={:?}, kind={:?}",
                                    object_type, type_info.kind
                                );
                                if matches!(type_info.kind, TypeKind::String) {
                                    // Get the method name from the field symbol
                                    let method_name = self
                                        .symbol_table
                                        .get_symbol(*field)
                                        .and_then(|s| self.string_interner.get(s.name));

                                    if let Some(method_name) = method_name {
                                        // For String methods with optional params (indexOf, lastIndexOf),
                                        // look up the mapping by param count to get the right variant
                                        let arg_count = args.len();
                                        let mapping_opt = self
                                            .stdlib_mapping
                                            .find_by_name_and_params(
                                                "String",
                                                method_name,
                                                arg_count,
                                            )
                                            .or_else(|| {
                                                self.stdlib_mapping
                                                    .find_by_name("String", method_name)
                                            });

                                        // Look up the runtime function for this String method
                                        if let Some((_sig, mapping)) = mapping_opt {
                                            let runtime_func = mapping.runtime_name;

                                            debug!(
                                                "[STRING METHOD] Found String.{} with {} args -> {}",
                                                method_name, arg_count, runtime_func
                                            );

                                            drop(type_table);

                                            // Lower the object (the String pointer)
                                            let obj_reg = self.lower_expression(object)?;

                                            // Lower the method arguments
                                            let method_arg_regs: Vec<_> = args
                                                .iter()
                                                .filter_map(|a| self.lower_expression(a))
                                                .collect();

                                            // Build param types: string_ptr, ...args
                                            let string_ptr_ty =
                                                IrType::Ptr(Box::new(IrType::String));
                                            let mut param_types = vec![string_ptr_ty.clone()];
                                            for arg in &method_arg_regs {
                                                // Haxe Int is i32, default to I32 for integer args
                                                let arg_ty = self
                                                    .builder
                                                    .get_register_type(*arg)
                                                    .unwrap_or(IrType::I32);
                                                param_types.push(arg_ty);
                                            }

                                            // Determine return type - for String methods returning String,
                                            // they return a pointer to HaxeString
                                            let return_type = if result_type == IrType::String {
                                                string_ptr_ty.clone()
                                            } else {
                                                result_type.clone()
                                            };

                                            let runtime_func_id = self
                                                .get_or_register_extern_function(
                                                    runtime_func,
                                                    param_types,
                                                    return_type.clone(),
                                                );

                                            let mut call_args = vec![obj_reg];
                                            call_args.extend(method_arg_regs);

                                            return self.builder.build_call_direct(
                                                runtime_func_id,
                                                call_args,
                                                return_type,
                                            );
                                        }
                                    }
                                }
                            }
                        }

                        // Check if the object type is a rayzor stdlib class (or GenericInstance like Deque<Int>)
                        let type_table = self.type_table.borrow();
                        let mut class_symbol_id = if let Some(type_info) =
                            type_table.get(object_type)
                        {
                            match &type_info.kind {
                                TypeKind::Class { symbol_id, .. } => Some(*symbol_id),
                                TypeKind::Abstract { symbol_id, .. } => Some(*symbol_id),
                                TypeKind::GenericInstance { base_type, .. } => {
                                    // For GenericInstance like Deque<Int>, get the base class/abstract symbol
                                    if let Some(base_info) = type_table.get(*base_type) {
                                        match &base_info.kind {
                                            TypeKind::Class { symbol_id, .. } => {
                                                debug!(
                                                    "[STDLIB FALLBACK] GenericInstance base class symbol_id={:?}",
                                                    symbol_id
                                                );
                                                Some(*symbol_id)
                                            }
                                            TypeKind::Abstract { symbol_id, .. } => {
                                                debug!(
                                                    "[STDLIB FALLBACK] GenericInstance base abstract symbol_id={:?}",
                                                    symbol_id
                                                );
                                                Some(*symbol_id)
                                            }
                                            _ => None,
                                        }
                                    } else {
                                        None
                                    }
                                }
                                _ => None,
                            }
                        } else {
                            None
                        };

                        // Fallback for static class references where object_type is not concrete
                        // (e.g., extern class identifiers like Std/Math).
                        if class_symbol_id.is_none() {
                            if let HirExprKind::Variable {
                                symbol: object_symbol,
                                ..
                            } = &object.kind
                            {
                                if let Some(sym) = self.symbol_table.get_symbol(*object_symbol) {
                                    if matches!(
                                        sym.kind,
                                        crate::tast::symbols::SymbolKind::Class
                                            | crate::tast::symbols::SymbolKind::Abstract
                                            | crate::tast::symbols::SymbolKind::TypeAlias
                                    ) {
                                        class_symbol_id = Some(sym.id);
                                    }
                                }
                            }
                        }

                        if let Some(symbol_id) = class_symbol_id {
                            if let Some(class_symbol) = self.symbol_table.get_symbol(symbol_id) {
                                if let Some(class_name) =
                                    self.string_interner.get(class_symbol.name)
                                {
                                    debug!(
                                        "[STDLIB FALLBACK] Found class '{}', checking for stdlib method",
                                        class_name
                                    );

                                    // Check if it's a rayzor stdlib class by using native name or qualified name
                                    let qualified_name_opt = class_symbol
                                        .native_name
                                        .and_then(|nn| self.string_interner.get(nn))
                                        .map(|n| n.replace("::", "_"))
                                        .or_else(|| {
                                            class_symbol
                                                .qualified_name
                                                .and_then(|qn| self.string_interner.get(qn))
                                                .map(|s| s.to_string())
                                        });

                                    // Try to get the method name from the field symbol
                                    let method_name = if let Some(field_sym) =
                                        self.symbol_table.get_symbol(*field)
                                    {
                                        self.string_interner.get(field_sym.name)
                                    } else {
                                        None
                                    };

                                    if let Some(method_name) = method_name {
                                        let static_args = self.effective_static_call_args(args);
                                        let object_qualified_name_opt =
                                            if let HirExprKind::Variable {
                                                symbol: object_symbol,
                                                ..
                                            } = &object.kind
                                            {
                                                self.symbol_table
                                                    .get_symbol(*object_symbol)
                                                    .and_then(|s| s.qualified_name)
                                                    .and_then(|qn| self.string_interner.get(qn))
                                                    .map(|s| s.to_string())
                                            } else {
                                                None
                                            };

                                        // Prefer class-qualified lookup when a qualified class name
                                        // exists, but always keep a global static fallback.
                                        // Some extern classes (e.g. Math) may not carry
                                        // qualified/native names on the symbol.
                                        let runtime_func_opt = qualified_name_opt
                                            .as_deref()
                                            .and_then(|class_qualified_name| {
                                                let lookup =
                                                    format!("{}.{}", class_qualified_name, method_name);
                                                self.get_static_stdlib_runtime_func_with_params(
                                                    &lookup,
                                                    method_name,
                                                    static_args.len(),
                                                )
                                            })
                                            .or_else(|| {
                                                object_qualified_name_opt
                                                    .as_deref()
                                                    .and_then(|class_qualified_name| {
                                                        let lookup = format!(
                                                            "{}.{}",
                                                            class_qualified_name, method_name
                                                        );
                                                        self.get_static_stdlib_runtime_func_with_params(
                                                            &lookup,
                                                            method_name,
                                                            static_args.len(),
                                                        )
                                                    })
                                            })
                                            .or_else(|| {
                                                let lookup =
                                                    format!("{}.{}", class_name, method_name);
                                                self.get_static_stdlib_runtime_func_with_params(
                                                    &lookup,
                                                    method_name,
                                                    static_args.len(),
                                                )
                                            })
                                            .or_else(|| {
                                                self.stdlib_mapping
                                                    .find_static_method_by_name_and_params(
                                                        method_name,
                                                        static_args.len(),
                                                    )
                                                    .map(|(_, mapping)| mapping.runtime_name)
                                            });

                                        if let Some(runtime_func) = runtime_func_opt {
                                            // println!("✅ Generating runtime call to {} for {}.{}", runtime_func, class_name, method_name);
                                            drop(type_table);

                                            // Lower all arguments (don't include object for static methods like spawn)
                                            let arg_regs: Vec<_> = static_args
                                                .iter()
                                                .filter_map(|a| self.lower_expression(a))
                                                .collect();
                                            debug!(
                                                "[FIELD-PATH STATIC] Dispatching {}.{} -> {}, arg_count={}",
                                                class_name,
                                                method_name,
                                                runtime_func,
                                                arg_regs.len()
                                            );

                                            // Use the function signature from the mapping (hlp_* introspection)
                                            // if available; this is the authoritative source of type info.
                                            let (expected_param_types, expected_return_type) = self
                                                .get_extern_function_signature(&runtime_func)
                                                .unwrap_or_else(|| {
                                                    let param_types: Vec<IrType> = arg_regs
                                                        .iter()
                                                        .map(|reg| {
                                                            self.builder
                                                                .get_register_type(*reg)
                                                                .unwrap_or(IrType::Any)
                                                        })
                                                        .collect();
                                                    (param_types, result_type.clone())
                                                });

                                            // Cast/box arguments to expected types
                                            let final_arg_regs: Vec<_> = arg_regs.iter().enumerate()
                                                    .map(|(i, &reg)| {
                                                        if let (Some(expected_ty), Some(actual_ty)) = (
                                                            expected_param_types.get(i),
                                                            self.builder.get_register_type(reg)
                                                        ) {
                                                            if *expected_ty != actual_ty {
                                                                let is_ptr_u8 = matches!(expected_ty, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::U8));
                                                                if is_ptr_u8 && i < args.len() {
                                                                    if let Some(boxed) = self.box_value_for_dynamic(reg, args[i].ty) {
                                                                        return boxed;
                                                                    }
                                                                }
                                                                if let Some(casted) = self.builder.build_cast(reg, actual_ty.clone(), expected_ty.clone()) {
                                                                    return casted;
                                                                }
                                                            }
                                                        }
                                                        reg
                                                    })
                                                    .collect();

                                            let runtime_func_id = self
                                                .get_or_register_extern_function(
                                                    &runtime_func,
                                                    expected_param_types,
                                                    expected_return_type.clone(),
                                                );

                                            // Generate the call to the runtime function
                                            let call_result = self.builder.build_call_direct(
                                                runtime_func_id,
                                                final_arg_regs,
                                                expected_return_type.clone(),
                                            );
                                            return call_result;
                                        }
                                    }
                                }
                            }
                        }
                        drop(type_table);
                    }
                }

                // Check if callee is an enum constructor (EnumVariant symbol kind)
                // Handle enum constructors with parameters like MyResult.Ok(42)
                if let HirExprKind::Variable { symbol, .. } = &callee.kind {
                    if let Some(sym) = self.symbol_table.get_symbol(*symbol) {
                        use crate::tast::SymbolKind;
                        if sym.kind == SymbolKind::EnumVariant
                            || (sym.kind == SymbolKind::Function
                                && self
                                    .symbol_table
                                    .find_parent_enum_for_constructor(*symbol)
                                    .is_some())
                        {
                            // Find the parent enum and variant index
                            if let Some(parent_enum_id) =
                                self.symbol_table.find_parent_enum_for_constructor(*symbol)
                            {
                                if let Some(variants) =
                                    self.symbol_table.get_enum_variants(parent_enum_id)
                                {
                                    for (idx, variant_id) in variants.iter().enumerate() {
                                        if *variant_id == *symbol {
                                            // Get variant field count from HIR
                                            let field_count = self
                                                .get_enum_variant_field_count(parent_enum_id, idx);

                                            if field_count == 0 {
                                                // If enum has parameterized variants, all variants must be boxed
                                                if self.enum_is_boxed(parent_enum_id) {
                                                    return self
                                                        .build_boxed_enum_tag_only(idx as i32);
                                                }
                                                // Pure discriminant enum - return index directly
                                                return self
                                                    .builder
                                                    .build_const(IrValue::I64(idx as i64));
                                            }

                                            // Has parameters - allocate boxed enum struct
                                            // Layout: [tag:i32][pad:i32][field0:i64][field1:i64]...
                                            let struct_size = 8 + 8 * field_count; // 8 for tag+pad, 8 per field

                                            // Allocate memory
                                            let size_const = self
                                                .builder
                                                .build_const(IrValue::I64(struct_size as i64))?;
                                            let alloc_func = self.get_or_register_extern_function(
                                                "malloc",
                                                vec![IrType::I64],
                                                IrType::Ptr(Box::new(IrType::I8)),
                                            );
                                            let ptr = self.builder.build_call_direct(
                                                alloc_func,
                                                vec![size_const],
                                                IrType::Ptr(Box::new(IrType::I8)),
                                            )?;

                                            // Store tag at offset 0 (as i32)
                                            // Note: GEP multiplies index by element size, so we use I8 elements
                                            // for byte-based addressing, then bitcast to the target type
                                            let zero_offset =
                                                self.builder.build_const(IrValue::I64(0))?;
                                            let tag_ptr = self.builder.build_gep(
                                                ptr,
                                                vec![zero_offset],
                                                IrType::Ptr(Box::new(IrType::I8)), // Byte-based
                                            )?;
                                            let tag_ptr_i32 = self.builder.build_bitcast(
                                                tag_ptr,
                                                IrType::Ptr(Box::new(IrType::I32)),
                                            )?;
                                            let tag_val = self
                                                .builder
                                                .build_const(IrValue::I32(idx as i32))?;
                                            self.builder.build_store(tag_ptr_i32, tag_val)?;

                                            // Store each parameter at byte offset 8 + i*8
                                            // When is_method=true, args[0] is the enum class reference
                                            // (receiver), not a constructor field. Skip it.
                                            let constructor_args: &[HirExpr] = if *is_method {
                                                if args.len() > 1 {
                                                    &args[1..]
                                                } else {
                                                    &[]
                                                }
                                            } else {
                                                args
                                            };
                                            for (i, arg) in constructor_args.iter().enumerate() {
                                                let arg_reg = self.lower_expression(arg)?;
                                                let field_offset = self.builder.build_const(
                                                    IrValue::I64((8 + i * 8) as i64),
                                                )?;
                                                // Use I8 element type for byte-based addressing
                                                let field_ptr = self.builder.build_gep(
                                                    ptr,
                                                    vec![field_offset],
                                                    IrType::Ptr(Box::new(IrType::I8)),
                                                )?;
                                                // Bitcast to i64 ptr for the store
                                                let field_ptr_i64 = self.builder.build_bitcast(
                                                    field_ptr,
                                                    IrType::Ptr(Box::new(IrType::I64)),
                                                )?;
                                                self.builder.build_store(field_ptr_i64, arg_reg)?;
                                            }

                                            // Return pointer as i64 for uniform handling
                                            // (bitcast pointer to i64)
                                            return self.builder.build_bitcast(ptr, IrType::I64);
                                        }
                                    }
                                }
                            }
                        }
                    }
                }

                // Check if callee is a direct function reference
                if let HirExprKind::Variable { symbol, .. } = &callee.kind {
                    // Virtual dispatch for instance method calls (is_method=true):
                    // Skip vtable dispatch for super.method() calls — these must call
                    // the parent's implementation directly, not the overridden version.
                    let receiver_is_super = !args.is_empty()
                        && matches!(args[0].kind, HirExprKind::Super);
                    // super.method() — bypass vtable AND resolve to parent's implementation.
                    if receiver_is_super {
                        let method_name = self.symbol_table.get_symbol(*symbol).map(|s| s.name);
                        if let Some(method_name) = method_name {
                            // Find parent class: determine which class the current function
                            // belongs to, then look up its parent via class_parent_map.
                            let current_class = self.builder.current_function()
                                .and_then(|f| {
                                    // Find the class this function is a method of
                                    self.class_method_by_name.iter()
                                        .find(|(_, &method_sym)| {
                                            self.function_map.get(&method_sym) == Some(&f.id)
                                        })
                                        .map(|((class_sym, _), _)| *class_sym)
                                });
                            let parent_class = current_class
                                .and_then(|cls| self.class_parent_map.get(&cls).copied());
                            // Resolve parent's method by name
                            let super_func_id = parent_class.and_then(|pc| {
                                self.class_method_by_name.get(&(pc, method_name))
                                    .and_then(|&sym| self.resolve_function_id_with_qualified_fallback(sym))
                            }).or_else(|| {
                                // Fallback: direct symbol resolution
                                self.resolve_function_id_with_qualified_fallback(*symbol)
                            });
                            if let Some(func_id) = super_func_id {
                                let obj_reg = self.lower_expression(&args[0])?;
                                let mut call_args = vec![obj_reg];
                                for arg in args.iter().skip(1) {
                                    if let Some(reg) = self.lower_expression(arg) {
                                        call_args.push(reg);
                                    }
                                }
                                let ret_type = self.convert_type(expr.ty);
                                return self.builder.build_call_direct(func_id, call_args, ret_type);
                            }
                        }
                    }
                    if *is_method && !args.is_empty() && !receiver_is_super {
                        let vtable_slot = self.virtual_dispatch_info.get(symbol).copied()
                            .or_else(|| {
                                let method_name = self.symbol_table.get_symbol(*symbol).map(|s| s.name)?;
                                let receiver_type = self.resolve_through_aliases(args[0].ty);
                                let type_table = self.type_table.borrow();
                                let class_sym = match &type_table.get(receiver_type)?.kind {
                                    TypeKind::Class { symbol_id, .. } => Some(*symbol_id),
                                    _ => None,
                                }?;
                                drop(type_table);
                                let mut current = Some(class_sym);
                                while let Some(cls) = current {
                                    if let Some(&method_sym) = self.class_method_by_name.get(&(cls, method_name)) {
                                        if let Some(info) = self.virtual_dispatch_info.get(&method_sym) {
                                            return Some(*info);
                                        }
                                    }
                                    current = self.class_parent_map.get(&cls).copied();
                                }
                                None
                            });

                        if let Some((slot_index, _defining_class)) = vtable_slot {
                            let obj_reg = self.lower_expression(&args[0])?;
                            let mut call_args = vec![obj_reg];
                            for arg in args.iter().skip(1) {
                                if let Some(reg) = self.lower_expression(arg) {
                                    call_args.push(reg);
                                }
                            }
                            let lookup_fn = self.get_or_register_extern_function(
                                "haxe_vtable_lookup",
                                vec![IrType::Ptr(Box::new(IrType::U8)), IrType::I32],
                                IrType::I64,
                            );
                            let slot_reg = self.builder.build_const(IrValue::I32(slot_index as i32))?;
                            let fn_ptr = self.builder.build_call_direct(
                                lookup_fn,
                                vec![obj_reg, slot_reg],
                                IrType::I64,
                            )?;
                            let mut param_types = vec![IrType::Ptr(Box::new(IrType::Void))];
                            for arg in args.iter().skip(1) {
                                param_types.push(self.convert_type(arg.ty));
                            }
                            let return_type = Box::new(self.convert_type(expr.ty));
                            let func_signature = IrType::Function {
                                params: param_types,
                                return_type,
                                varargs: false,
                            };
                            return self.builder.build_call_indirect(
                                fn_ptr,
                                call_args,
                                func_signature,
                            );
                        }
                    }

                    let symbol_name = self
                        .symbol_table
                        .get_symbol(*symbol)
                        .and_then(|s| self.string_interner.get(s.name))
                        .unwrap_or("<unknown>");
                    debug!(
                        "DEBUG: Callee is Variable, symbol={:?} ({}), is_method={}, args.len()={}",
                        symbol,
                        symbol_name,
                        is_method,
                        args.len()
                    );

                    // DIRECT SYMBOL RESOLUTION:
                    // For static extension methods (using IntTools; → x.add(3)) and
                    // other user-defined method calls, try resolving the function by symbol ID first.
                    // This avoids bare-name collisions (e.g., user "add" vs "rayzor_ssl_cert_add").
                    // Only intercept for user-defined functions — extern/stdlib methods need the
                    // more specific handlers below (auto-boxing, runtime mapping, etc.).
                    //
                    // IMPORTANT: Skip this fast path when the receiver is Dynamic or Interface-typed,
                    // because those need special dispatch (unboxing / fat pointer extraction) handled below.
                    if let Some(func_id) = self.resolve_function_id_with_qualified_fallback(*symbol)
                    {
                        let is_user_defined = self
                            .builder
                            .module
                            .functions
                            .get(&func_id)
                            .map(|f| f.kind == crate::ir::functions::FunctionKind::UserDefined)
                            .unwrap_or(false);

                        // Check if receiver needs special dispatch (Dynamic unbox or Interface fat pointer)
                        let receiver_needs_special_dispatch = if *is_method && !args.is_empty() {
                            let receiver_type = self.resolve_through_aliases(args[0].ty);
                            let type_table = self.type_table.borrow();
                            type_table
                                .get(receiver_type)
                                .map(|t| {
                                    matches!(
                                        t.kind,
                                        TypeKind::Dynamic
                                            | TypeKind::Interface { .. }
                                            | TypeKind::TypeParameter { .. }
                                            | TypeKind::Placeholder { .. }
                                            | TypeKind::Unknown
                                    )
                                })
                                .unwrap_or(false)
                        } else {
                            false
                        };

                        if is_user_defined && !receiver_needs_special_dispatch {
                            let arg_regs: Vec<_> = args
                                .iter()
                                .filter_map(|a| self.lower_expression(a))
                                .collect();

                            let actual_return_type =
                                if let Some(func) = self.builder.module.functions.get(&func_id) {
                                    func.signature.return_type.clone()
                                } else {
                                    result_type.clone()
                                };

                            // For generic class method calls, extract concrete type args
                            // from the receiver's type (e.g., Container<String>.get() → type_args=[String]).
                            // This enables the monomorphizer to specialize the function.
                            let has_type_params = self
                                .builder
                                .module
                                .functions
                                .get(&func_id)
                                .map(|f| !f.signature.type_params.is_empty())
                                .unwrap_or(false);

                            // Gather type_args: first from HIR call-site type_args, then from receiver's
                            // generic instance type_args, then from the converted HIR type_args computed
                            // earlier in the Call handler.
                            let call_type_args = if has_type_params {
                                if !converted_hir_type_args.is_empty() {
                                    converted_hir_type_args.clone()
                                } else if *is_method && !args.is_empty() {
                                    // Extract from receiver's GenericInstance / Class type_args
                                    let receiver_type = self.resolve_through_aliases(args[0].ty);
                                    let type_table = self.type_table.borrow();
                                    type_table
                                        .get(receiver_type)
                                        .and_then(|t| match &t.kind {
                                            TypeKind::GenericInstance { type_args, .. }
                                            | TypeKind::Class { type_args, .. } => {
                                                if type_args.is_empty() {
                                                    None
                                                } else {
                                                    Some(
                                                        type_args
                                                            .iter()
                                                            .map(|&ta| self.convert_type(ta))
                                                            .collect::<Vec<_>>(),
                                                    )
                                                }
                                            }
                                            _ => None,
                                        })
                                        .unwrap_or_default()
                                } else {
                                    vec![]
                                }
                            } else {
                                vec![]
                            };

                            if !call_type_args.is_empty() {
                                let result = self.builder.build_call_direct_with_type_args(
                                    func_id,
                                    arg_regs,
                                    actual_return_type,
                                    call_type_args,
                                );
                                // The function body uses type-erased I64 for all type param values.
                                // When the resolved concrete type differs (F64, I32, String, etc.),
                                // the caller's register has the right TYPE but the value is still
                                // the I64 bit pattern. After inlining + SRA, this becomes visible.
                                // Insert a bitcast for float types where i64→f64 reinterpretation
                                // is needed at the calling convention level.
                                if let Some(reg) = result {
                                    let reg_type =
                                        self.builder.get_register_type(reg).unwrap_or(IrType::I64);
                                    if matches!(reg_type, IrType::F64 | IrType::F32) {
                                        // Bitcast from i64 to f64 to ensure calling convention
                                        // uses the float register file
                                        return self.builder.build_bitcast(reg, reg_type);
                                    }
                                }
                                return result;
                            }
                            return self.builder.build_call_direct(
                                func_id,
                                arg_regs,
                                actual_return_type,
                            );
                        }
                    }

                    // INTERFACE DISPATCH:
                    // When is_method=true, args[0] is the receiver. If the receiver has
                    // an interface type, dispatch through the fat pointer vtable.
                    if *is_method && !args.is_empty() {
                        let receiver = &args[0];
                        let receiver_type = receiver.ty;

                        if let Some(iface_sym) = self.get_interface_symbol(receiver_type) {
                            let method_name_interned =
                                self.symbol_table.get_symbol(*symbol).map(|s| s.name);

                            if let Some(method_name_i) = method_name_interned {
                                let method_index = self
                                    .interface_method_names
                                    .get(&iface_sym)
                                    .and_then(|names| {
                                        names.iter().position(|n| *n == method_name_i)
                                    });

                                if let Some(idx) = method_index {
                                    // Lower the receiver (fat pointer)
                                    let fat_ptr_raw = self.lower_expression(receiver)?;

                                    // The fat pointer may be stored as I64 - bitcast to Ptr if needed
                                    let fat_ptr_ty = self
                                        .builder
                                        .get_register_type(fat_ptr_raw)
                                        .unwrap_or(IrType::I64);
                                    let fat_ptr = if !matches!(fat_ptr_ty, IrType::Ptr(_)) {
                                        self.builder.build_bitcast(
                                            fat_ptr_raw,
                                            IrType::Ptr(Box::new(IrType::I64)),
                                        )?
                                    } else {
                                        fat_ptr_raw
                                    };

                                    // Lower the actual arguments (skip args[0] which is receiver)
                                    let arg_regs: Vec<_> = args[1..]
                                        .iter()
                                        .filter_map(|a| self.lower_expression(a))
                                        .collect();

                                    // Load object pointer from fat_ptr[0]
                                    let obj_ptr = self.builder.build_load(fat_ptr, IrType::I64)?;

                                    // Load function pointer from fat_ptr[(idx+1)*8]
                                    let fn_offset = self
                                        .builder
                                        .build_const(IrValue::I64(((idx + 1) * 8) as i64))?;
                                    let fn_slot = self.builder.build_ptr_add(
                                        fat_ptr,
                                        fn_offset,
                                        IrType::Ptr(Box::new(IrType::U8)),
                                    )?;
                                    let fn_ptr = self.builder.build_load(fn_slot, IrType::I64)?;

                                    // Build call args: self (obj_ptr) + user args
                                    let mut call_args = vec![obj_ptr];
                                    call_args.extend(arg_regs);

                                    // Build signature: (self: Ptr, args...) -> return_type
                                    let param_types = {
                                        let mut types = vec![IrType::Ptr(Box::new(IrType::Void))]; // self
                                        for arg in args[1..].iter() {
                                            types.push(self.convert_type(arg.ty));
                                        }
                                        types
                                    };
                                    // Resolve return type from the method's symbol type,
                                    // not expr.ty (which may be the interface type instead
                                    // of the method's return type in some TAST configurations)
                                    let return_ir_type =
                                        self.resolve_interface_method_return_type(*symbol, expr.ty);
                                    let return_type = Box::new(return_ir_type);
                                    let func_signature = IrType::Function {
                                        params: param_types,
                                        return_type,
                                        varargs: false,
                                    };

                                    return self.builder.build_call_indirect(
                                        fn_ptr,
                                        call_args,
                                        func_signature,
                                    );
                                }
                            }
                        }
                    }

                    // ENUM INSTANCE METHOD DISPATCH:
                    // Delegates to runtime functions registered in runtime_mapping.rs.
                    // Injects compile-time constants (type_id, is_boxed) as extra params.
                    if *is_method && !args.is_empty() {
                        if let Some(Some(result)) = self.try_dispatch_enum_method(*symbol, args) {
                            return Some(result);
                        }
                    }

                    // EXTERN CLASS METHOD HANDLING:
                    // When MethodCall is desugared to Call with Variable callee,
                    // is_method=true and args[0] is the receiver (for instance methods).
                    // For static methods, there is no receiver - all args are actual arguments.
                    // We need to check if this is an extern class method and redirect to runtime.
                    if *is_method && !args.is_empty() {
                        let receiver = &args[0];
                        // Resolve TypeAlias to get the actual receiver type
                        // (e.g., List<Int> may be wrapped in TypeAlias)
                        let receiver_type = self.resolve_through_aliases(receiver.ty);

                        // Extract receiver class hint for disambiguation (e.g., "rayzor_ds_Tensor")
                        let receiver_class_hint_owned: Option<String> =
                            if let HirExprKind::Variable {
                                symbol: recv_sym, ..
                            } = &receiver.kind
                            {
                                self.monomorphized_var_types
                                    .get(recv_sym)
                                    .map(|s| s.to_string())
                            } else {
                                None
                            };
                        // Fallback: use find_receiver_class_name if monomorphized_var_types didn't have it
                        let receiver_class_hint_owned = receiver_class_hint_owned
                            .or_else(|| self.find_receiver_class_name(receiver))
                            .or_else(|| {
                                // Fallback: check register_class_hints for the receiver's MIR register.
                                // This resolves class names for variables assigned from extern class
                                // constructors (e.g., `var map = new ObjectMap<K,V>()`), where the
                                // New handler stored a class hint on the result register.
                                if let HirExprKind::Variable {
                                    symbol: recv_sym, ..
                                } = &receiver.kind
                                {
                                    self.symbol_map
                                        .get(recv_sym)
                                        .and_then(|reg| self.register_class_hints.get(reg).cloned())
                                } else {
                                    None
                                }
                            });

                        // SIMD4f detection: If the receiver type converts to VecF32x4, force
                        // the class hint to "rayzor_SIMD4f". This prevents the FALLBACK2 brute-force
                        // search from matching Tensor methods (which share names like sum, dot, sqrt).
                        //
                        // Two-stage detection:
                        // 1. Check convert_type(receiver_type) — works when HIR type is SIMD4f abstract
                        // 2. Check receiver variable's register type — works for chained calls like
                        //    b.sum() where b = a.sqrt(), because build_call_direct sets the register
                        //    type from the function's actual return type (VecF32x4), even though
                        //    the HIR expression type might be Dynamic (TypeId(5)).
                        let receiver_class_hint_owned = if receiver_class_hint_owned.is_none() {
                            let ir_ty = self.convert_type(receiver_type);
                            if ir_ty.is_vector() {
                                Some("rayzor_SIMD4f".to_string())
                            } else if let crate::ir::hir::HirExprKind::Variable {
                                symbol: recv_sym,
                                ..
                            } = &receiver.kind
                            {
                                // Fallback: check the register type of the receiver variable.
                                // This catches chained calls where the receiver's HIR type is Dynamic
                                // but its register was typed as VecF32x4 by a previous SIMD4f call.
                                self.symbol_map
                                    .get(recv_sym)
                                    .and_then(|reg| self.builder.get_register_type(*reg))
                                    .filter(|ty| ty.is_vector())
                                    .map(|_| "rayzor_SIMD4f".to_string())
                            } else {
                                None
                            }
                        } else {
                            receiver_class_hint_owned
                        };
                        let receiver_class_hint = receiver_class_hint_owned.as_deref();

                        // Calculate actual param count (excluding the receiver) for overload disambiguation
                        // e.g., s.indexOf("World", 0) has args=[s, "World", 0], param_count=2
                        let param_count = args.len().saturating_sub(1);

                        // SIMD4f direct lookup: When receiver is known to be SIMD4f, bypass
                        // get_stdlib_runtime_info (whose FALLBACK2 excludes SIMD matches).
                        let runtime_info = if receiver_class_hint == Some("rayzor_SIMD4f") {
                            let method_name_str = self
                                .symbol_table
                                .get_symbol(*symbol)
                                .and_then(|s| self.string_interner.get(s.name));
                            if let Some(mn) = method_name_str {
                                self.stdlib_mapping
                                    .find_by_name_and_params("rayzor_SIMD4f", mn, param_count)
                                    .or_else(|| {
                                        self.stdlib_mapping.find_by_name("rayzor_SIMD4f", mn)
                                    })
                                    .map(|(sig, mapping)| (sig.class, sig.method, mapping))
                            } else {
                                None
                            }
                        } else {
                            // Try to find stdlib runtime mapping for this method
                            self.get_stdlib_runtime_info(
                                *symbol,
                                receiver_type,
                                Some(param_count),
                                receiver_class_hint,
                            )
                        };
                        if let Some((class_name, method_name, runtime_call)) = runtime_info {
                            // Skip methods that need ptr_conversion - let them fall through to
                            // the existing handler which properly handles params_need_ptr_conversion
                            if runtime_call.params_need_ptr_conversion != 0 {
                                debug!(
                                    "[EXTERN METHOD VAR] Skipping {} - has ptr_conversion, using fallback path",
                                    runtime_call.runtime_name
                                );
                            } else {
                                let runtime_func = runtime_call.runtime_name;
                                let is_instance_method = runtime_call.has_self_param;
                                let is_mir_wrapper = runtime_call.is_mir_wrapper;
                                let returns_raw_value = runtime_call.returns_raw_value;
                                let raw_value_params = runtime_call.raw_value_params;
                                let extend_to_i64_params = runtime_call.extend_to_i64_params;
                                let has_return = runtime_call.has_return;
                                let explicit_return_type =
                                    runtime_call.return_type.map(|t| t.to_ir_type());
                                debug!(
                                    "[EXTERN METHOD VAR] Redirecting {}.{} -> {} (instance={}, mir_wrapper={})",
                                    class_name,
                                    method_name,
                                    runtime_func,
                                    is_instance_method,
                                    is_mir_wrapper
                                );

                                // MIR wrapper path: use register_stdlib_mir_forward_ref
                                // MIR wrappers (SIMD4f, Thread, Channel, etc.) are compiled by
                                // Cranelift alongside user code. They must NOT be registered as
                                // extern C functions.
                                if is_mir_wrapper {
                                    self.builder.call_label =
                                        Some(format!("MIR_WRAPPER:{}", runtime_func));

                                    // Get the MIR wrapper's expected signature for auto-boxing/unboxing
                                    let mir_wrapper_sig =
                                        self.get_stdlib_mir_wrapper_signature(runtime_func);

                                    // Lower receiver + args with auto-boxing
                                    // When MIR wrapper expects Ptr(U8) but arg is a concrete primitive
                                    // (I32, F64, Bool from Channel<Int>.send(42)), box the value.
                                    // But for type-erased pointers (I64 from TypeParameter), just cast.
                                    let mut arg_regs = Vec::new();
                                    let mut param_types = Vec::new();
                                    for (i, arg) in args.iter().enumerate() {
                                        if i == 0 && !is_instance_method {
                                            continue; // Skip class receiver for static methods
                                        }
                                        if let Some(reg) = self.lower_expression(arg) {
                                            let actual_ty = self
                                                .builder
                                                .get_register_type(reg)
                                                .unwrap_or(IrType::I64);
                                            let param_idx =
                                                if is_instance_method { i } else { i - 1 };
                                            let expected_ty = mir_wrapper_sig
                                                .as_ref()
                                                .and_then(|(params, _)| {
                                                    params.get(param_idx).cloned()
                                                })
                                                .unwrap_or_else(|| actual_ty.clone());

                                            // Check if this arg is a type-erased pointer (I64 from
                                            // TypeParameter/class/GenericInstance/Array) vs a concrete
                                            // primitive (I32/F64/Bool). Type-erased pointers should
                                            // be CAST to Ptr(U8), not BOXED as integers.
                                            let is_type_erased_ptr =
                                                matches!(actual_ty, IrType::I64) && {
                                                    let type_table = self.type_table.borrow();
                                                    type_table
                                                        .get(arg.ty)
                                                        .map(|ti| {
                                                            matches!(
                                                    ti.kind,
                                                    crate::tast::TypeKind::TypeParameter { .. }
                                                    | crate::tast::TypeKind::Class { .. }
                                                    | crate::tast::TypeKind::GenericInstance { .. }
                                                    | crate::tast::TypeKind::Interface { .. }
                                                    | crate::tast::TypeKind::Dynamic
                                                    | crate::tast::TypeKind::Placeholder { .. }
                                                    | crate::tast::TypeKind::Array { .. }
                                                    | crate::tast::TypeKind::Abstract { .. }
                                                    | crate::tast::TypeKind::Function { .. }
                                                )
                                                        })
                                                        .unwrap_or(false)
                                                };

                                            let final_reg = if is_type_erased_ptr
                                                && matches!(&expected_ty, IrType::Ptr(_))
                                            {
                                                // Cast I64 → Ptr(U8) for type-erased pointers
                                                self.builder
                                                    .build_cast(
                                                        reg,
                                                        IrType::I64,
                                                        expected_ty.clone(),
                                                    )
                                                    .unwrap_or(reg)
                                            } else {
                                                self.maybe_box_for_extern_call(
                                                    reg,
                                                    &actual_ty,
                                                    &expected_ty,
                                                )?
                                            };
                                            arg_regs.push(final_reg);
                                            param_types.push(expected_ty);
                                        }
                                    }

                                    // Use the MIR wrapper's actual return type instead of the
                                    // erased HIR type. For Dynamic/TypeParameter returns, the HIR
                                    // type erases to Ptr(Void) or I64, but the MIR wrapper returns
                                    // a concrete type (e.g., Ptr(U8)). Using the concrete type
                                    // prevents spurious unboxing in downstream field access.
                                    let mir_return_type = mir_wrapper_sig
                                        .map(|(_, ret)| ret)
                                        .unwrap_or_else(|| result_type.clone());

                                    let mir_func_id = self.register_stdlib_mir_forward_ref(
                                        runtime_func,
                                        param_types,
                                        mir_return_type.clone(),
                                    );

                                    let call_result = self.builder.build_call_direct(
                                        mir_func_id,
                                        arg_regs,
                                        mir_return_type.clone(),
                                    )?;

                                    // Store class hint for result to enable disambiguation
                                    // of subsequent method calls on TypeParameter receivers
                                    {
                                        let return_class =
                                            Self::get_return_class_hint(class_name, method_name);
                                        self.register_class_hints
                                            .insert(call_result, return_class.to_string());
                                    }

                                    // Auto-unbox if MIR wrapper returns Ptr(U8) but HIR expects primitive
                                    // (e.g., Thread<Int>.join() returns boxed int, Channel<Int>.tryReceive()
                                    // returns boxed int). Resolve T from receiver's generic type_args.
                                    let resolved_expected = {
                                        let needs_resolve = result_type == IrType::Any
                                            || matches!(&result_type, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::Void))
                                            || result_type == IrType::I64;
                                        if needs_resolve {
                                            let type_table = self.type_table.borrow();
                                            type_table
                                                .get(receiver_type)
                                                .and_then(|ti| match &ti.kind {
                                                    crate::tast::TypeKind::Class {
                                                        type_args,
                                                        ..
                                                    }
                                                    | crate::tast::TypeKind::GenericInstance {
                                                        type_args,
                                                        ..
                                                    } => {
                                                        if !type_args.is_empty() {
                                                            Some(self.convert_type(type_args[0]))
                                                        } else {
                                                            None
                                                        }
                                                    }
                                                    _ => None,
                                                })
                                                .unwrap_or_else(|| result_type.clone())
                                        } else {
                                            result_type.clone()
                                        }
                                    };

                                    return self.maybe_unbox_for_extern_return(
                                        call_result,
                                        &mir_return_type,
                                        &resolved_expected,
                                    );
                                }

                                // Extern C path: register as extern function
                                // Get expected parameter types from the extern function signature
                                let (expected_param_types, actual_return_type) = self
                                    .get_stdlib_mir_wrapper_signature(runtime_func)
                                    .map(|(params, ret)| (params, ret))
                                    .unwrap_or_else(|| {
                                        // When is_method=true, args[0] is always receiver/class - skip it
                                        // For instance methods, add self param first
                                        let mut params = if is_instance_method {
                                            vec![IrType::Ptr(Box::new(IrType::U8))]
                                        } else {
                                            vec![]
                                        };
                                        // Always skip args[0] since is_method=true
                                        // Use stdlib mapping hints for param types
                                        for (i, arg) in args.iter().skip(1).enumerate() {
                                            // raw_value_params: bit 0 = self, bit 1 = first user param, etc.
                                            let user_bit = 1u32 << (i + 1);
                                            if raw_value_params & user_bit != 0 {
                                                params.push(IrType::U64);
                                            } else if extend_to_i64_params & user_bit != 0 {
                                                params.push(IrType::I64);
                                            } else {
                                                params.push(self.convert_type(arg.ty));
                                            }
                                        }
                                        // Use explicit return type from mapping if available,
                                        // otherwise fall back to HIR-inferred result_type
                                        let ret_type = if returns_raw_value {
                                            IrType::U64
                                        } else if let Some(ref ert) = explicit_return_type {
                                            ert.clone()
                                        } else if has_return {
                                            result_type.clone()
                                        } else {
                                            IrType::Void
                                        };
                                        (params, ret_type)
                                    });

                                self.builder.call_label =
                                    Some(format!("EXTERN_C:{}", runtime_func));
                                // Build argument list based on whether this is instance or static method
                                let mut arg_regs = Vec::new();
                                let args_to_process: &[HirExpr] = if is_instance_method {
                                    let receiver_reg = self.lower_expression(receiver)?;
                                    arg_regs.push(receiver_reg);
                                    &args[1..]
                                } else {
                                    &args[1..]
                                };

                                // Lower the arguments and auto-box if needed
                                let param_offset = if is_instance_method { 1 } else { 0 };
                                for (i, arg) in args_to_process.iter().enumerate() {
                                    let arg_reg = self.lower_expression(arg)?;
                                    let actual_ty = self.convert_type(arg.ty);
                                    let expected_ty = expected_param_types
                                        .get(i + param_offset)
                                        .cloned()
                                        .unwrap_or_else(|| actual_ty.clone());
                                    let final_reg = self.maybe_box_for_extern_call(
                                        arg_reg,
                                        &actual_ty,
                                        &expected_ty,
                                    )?;
                                    arg_regs.push(final_reg);
                                }

                                // Use expected parameter types for registration
                                let param_types = if expected_param_types.len() == arg_regs.len() {
                                    expected_param_types.clone()
                                } else {
                                    let mut params = if is_instance_method {
                                        vec![IrType::Ptr(Box::new(IrType::U8))]
                                    } else {
                                        vec![]
                                    };
                                    for arg in args.iter().skip(1) {
                                        params.push(self.convert_type(arg.ty));
                                    }
                                    params
                                };

                                let extern_func_id = self.get_or_register_extern_function(
                                    runtime_func,
                                    param_types,
                                    actual_return_type.clone(),
                                );

                                let call_result = self.builder.build_call_direct(
                                    extern_func_id,
                                    arg_regs,
                                    actual_return_type.clone(),
                                )?;

                                // Handle returns_raw_value: cast raw U64 to the appropriate type
                                if returns_raw_value {
                                    let final_result = match &result_type {
                                        IrType::I32 => self.builder.build_cast(
                                            call_result,
                                            IrType::U64,
                                            IrType::I32,
                                        ),
                                        IrType::I64 => self.builder.build_cast(
                                            call_result,
                                            IrType::U64,
                                            IrType::I64,
                                        ),
                                        IrType::F64 => {
                                            self.builder.build_bitcast(call_result, IrType::F64)
                                        }
                                        IrType::F32 => {
                                            if let Some(f64_reg) =
                                                self.builder.build_bitcast(call_result, IrType::F64)
                                            {
                                                self.builder.build_cast(
                                                    f64_reg,
                                                    IrType::F64,
                                                    IrType::F32,
                                                )
                                            } else {
                                                None
                                            }
                                        }
                                        IrType::Bool => self.builder.build_cast(
                                            call_result,
                                            IrType::U64,
                                            IrType::Bool,
                                        ),
                                        IrType::Ptr(ref inner)
                                            if matches!(inner.as_ref(), IrType::String) =>
                                        {
                                            // Concrete pointer type (e.g., Ptr(String))
                                            self.builder.build_cast(
                                                call_result,
                                                IrType::U64,
                                                result_type.clone(),
                                            )
                                        }
                                        _ => {
                                            // Unresolved T or Dynamic: keep as I64
                                            self.builder.build_cast(
                                                call_result,
                                                IrType::U64,
                                                IrType::I64,
                                            )
                                        }
                                    };
                                    return final_result;
                                }

                                // Auto-unbox if runtime returns Ptr(U8) but HIR expects primitive
                                let unboxed = self.maybe_unbox_for_extern_return(
                                    call_result,
                                    &actual_return_type,
                                    &result_type,
                                );
                                return unboxed;
                            } // end else (no ptr_conversion needed)
                        }
                    }
                    // SPECIAL CASE: Handle global trace() function
                    // Route to type-specific trace functions based on argument type
                    if symbol_name == "trace" && args.len() == 1 {
                        let arg = &args[0];

                        // Route trace(Type.typeof(x)) to enum tracing directly.
                        // This preserves parity even when the call-site type was widened.
                        if let Some(typeof_arg) = self.trace_typeof_inner_arg(arg) {
                            let value_reg = self.lower_type_typeof_call(
                                std::slice::from_ref(typeof_arg),
                                IrType::I64,
                            )?;
                            let trace_typeof_id = self.get_or_register_extern_function(
                                "haxe_trace_value_type",
                                vec![IrType::I64],
                                IrType::Void,
                            );
                            return self.builder.build_call_direct(
                                trace_typeof_id,
                                vec![value_reg],
                                IrType::Void,
                            );
                        }

                        // Handle ValueType values that were previously produced/stored.
                        if self.expr_is_value_type_expr(arg) {
                            let arg_reg = self.lower_expression(arg)?;
                            let trace_typeof_id = self.get_or_register_extern_function(
                                "haxe_trace_value_type",
                                vec![IrType::I64],
                                IrType::Void,
                            );
                            return self.builder.build_call_direct(
                                trace_typeof_id,
                                vec![arg_reg],
                                IrType::Void,
                            );
                        }

                        // Check if arg is a class or enum type
                        // For classes: try to call toString() method
                        // For enums: for now, fall through to traceAny (enum toString not yet implemented)
                        let type_table = self.type_table.borrow();
                        let type_kind = type_table.get(arg.ty).map(|ti| ti.kind.clone());
                        drop(type_table);

                        debug!(
                            "[TRACE ARG TYPE] arg.ty={:?}, type_kind={:?}",
                            arg.ty, type_kind
                        );

                        let class_info =
                            if let Some(crate::tast::core::TypeKind::Class { symbol_id, .. }) =
                                &type_kind
                            {
                                // Skip extern abstracts (CString, Usize, Ptr, etc.)
                                // — they appear as Class in the type table but don't have toString()
                                // Get class name for stdlib lookup
                                let class_name_str = self
                                    .symbol_table
                                    .get_symbol(*symbol_id)
                                    .and_then(|s| self.string_interner.get(s.name))
                                    .unwrap_or("");

                                let is_extern = self
                                    .symbol_table
                                    .get_symbol(*symbol_id)
                                    .map(|s| {
                                        s.flags.contains(crate::tast::symbols::SymbolFlags::EXTERN)
                                    })
                                    .unwrap_or(false);

                                // Skip extern classes UNLESS they have a toString in stdlib_mapping
                                // (e.g., StringMap, IntMap, Date have stdlib toString methods)
                                let has_stdlib_tostring = self
                                    .stdlib_mapping
                                    .find_by_name(class_name_str, "toString")
                                    .is_some();

                                if is_extern && !has_stdlib_tostring {
                                    None
                                } else {
                                    Some(class_name_str.to_string())
                                }
                            } else {
                                None
                            };

                        // Check if the trace argument is an enum variant expression (e.g., Color.Red)
                        // If so, we can print the variant name directly
                        if let HirExprKind::Field { object, field } = &arg.kind {
                            if let HirExprKind::Variable {
                                symbol: enum_symbol,
                                ..
                            } = &object.kind
                            {
                                if let Some(enum_sym) = self.symbol_table.get_symbol(*enum_symbol) {
                                    use crate::tast::SymbolKind;
                                    if enum_sym.kind == SymbolKind::Enum {
                                        // Get the variant name
                                        let field_sym = self.symbol_table.get_symbol(*field);
                                        if let Some(variant_name) =
                                            field_sym.and_then(|s| self.string_interner.get(s.name))
                                        {
                                            // Create a string constant with the variant name
                                            // IrValue::String will be converted by Cranelift to call haxe_string_literal
                                            // which returns a *mut HaxeString pointer
                                            let variant_name_str = variant_name.to_string();
                                            let string_ptr = self
                                                .builder
                                                .build_const(IrValue::String(variant_name_str))?;

                                            // Get or create the string trace function
                                            let string_ptr_ty =
                                                IrType::Ptr(Box::new(IrType::String));
                                            let string_trace_id = self
                                                .get_or_register_extern_function(
                                                    "haxe_trace_string_struct",
                                                    vec![string_ptr_ty],
                                                    IrType::Void,
                                                );

                                            // Trace the string
                                            return self.builder.build_call_direct(
                                                string_trace_id,
                                                vec![string_ptr],
                                                IrType::Void,
                                            );
                                        }
                                    }
                                }
                            }
                        }

                        // Check if it's an enum variable - print discriminant for now
                        // Full variant name lookup for variables would require runtime RTTI
                        // Direct enum variant expressions (Color.Red) are handled above

                        // If this is a class type, try to call toString() on it
                        if class_info.is_some() {
                            let obj_reg = self.lower_expression(arg)?;
                            if let Some(string_reg) = self.try_call_tostring(obj_reg, arg.ty)? {
                                let string_ptr_ty = IrType::Ptr(Box::new(IrType::String));
                                let string_trace_id = self.get_or_register_extern_function(
                                    "haxe_trace_string_struct",
                                    vec![string_ptr_ty],
                                    IrType::Void,
                                );
                                return self.builder.build_call_direct(
                                    string_trace_id,
                                    vec![string_reg],
                                    IrType::Void,
                                );
                            }
                        }

                        // Lower the argument first to get the actual MIR register
                        // Check if this is a field access
                        let is_field = matches!(&arg.kind, HirExprKind::Field { .. });
                        if is_field {
                            if let HirExprKind::Field { object, field } = &arg.kind {
                                let field_sym = self.symbol_table.get_symbol(*field);
                                let field_name = field_sym
                                    .and_then(|s| self.string_interner.get(s.name))
                                    .unwrap_or("<unknown>");
                                debug!("[TRACE] Argument is Field access: field={}", field_name);

                                // Check what the object is
                                if let HirExprKind::Variable { symbol, .. } = &object.kind {
                                    let var_sym = self.symbol_table.get_symbol(*symbol);
                                    let var_name = var_sym
                                        .and_then(|s| self.string_interner.get(s.name))
                                        .unwrap_or("<unknown>");
                                    debug!("[TRACE] Field object is Variable: {}", var_name);
                                }
                            }
                        }
                        let arg_reg = self.lower_expression(arg)?;
                        debug!(
                            "[TRACE] After lowering, arg_reg={}, checking type...",
                            arg_reg
                        );
                        if let Some(ty) = self.builder.get_register_type(arg_reg) {
                            debug!("[TRACE] arg_reg type from builder: {:?}", ty);
                        }

                        // Check if the HIR type is an enum
                        // Also check if the arg is a variable and look up its declared type
                        // (trace() takes Dynamic, so arg.ty might be Dynamic even if the variable is an enum)
                        let type_table = self.type_table.borrow();
                        let mut hir_type_kind = type_table.get(arg.ty).map(|ti| ti.kind.clone());

                        // If arg.ty is Dynamic but the argument is a variable, look up the variable's declared type
                        // This is needed because trace() accepts Dynamic, so the expression type might be Dynamic
                        // even when the underlying variable has a more specific type (like an enum)
                        if matches!(
                            &hir_type_kind,
                            Some(crate::tast::core::TypeKind::Dynamic) | None
                        ) {
                            if let HirExprKind::Variable { symbol, .. } = &arg.kind {
                                if let Some(sym) = self.symbol_table.get_symbol(*symbol) {
                                    let var_type_kind =
                                        type_table.get(sym.type_id).map(|ti| ti.kind.clone());
                                    if var_type_kind.is_some() {
                                        hir_type_kind = var_type_kind;
                                    }
                                }
                            }
                        }
                        drop(type_table);

                        // Handle enum variables - use RTTI-based trace with compile-time type_id
                        // Direct enum variant expressions (Color.Red) are handled above and print variant names
                        if let Some(crate::tast::core::TypeKind::Enum {
                            symbol_id,
                            ref type_args,
                        }) = hir_type_kind
                        {
                            // Get the enum's TypeId from its symbol
                            if let Some(enum_sym) = self.symbol_table.get_symbol(symbol_id) {
                                let enum_type_id = enum_sym.type_id;

                                // Build type_id constant (u32)
                                let type_id_const = self
                                    .builder
                                    .build_const(IrValue::I32(enum_type_id.0 as i32))?;

                                // Check if enum is boxed (has parameterized variants)
                                // Boxed enums store a pointer to heap-allocated struct
                                // Unboxed enums store just the discriminant as i64
                                if self.enum_is_boxed(symbol_id) {
                                    // Resolve concrete param types from type_args (type inference)
                                    // type_args maps type parameters to concrete types
                                    let concrete_type_args: Vec<u8> = {
                                        let type_table = self.type_table.borrow();
                                        type_args.iter().map(|&ta| {
                                            match type_table.get(ta).map(|ti| &ti.kind) {
                                                Some(crate::tast::core::TypeKind::Int) => 0u8,
                                                Some(crate::tast::core::TypeKind::Float) => 1u8,
                                                Some(crate::tast::core::TypeKind::Bool) => 2u8,
                                                Some(crate::tast::core::TypeKind::String) => 3u8,
                                                Some(crate::tast::core::TypeKind::TypeParameter { .. }) => 5u8,
                                                Some(crate::tast::core::TypeKind::Dynamic) => 5u8,
                                                _ => 4u8,
                                            }
                                        }).collect()
                                    };

                                    // If we have concrete type args, use the typed trace
                                    if !concrete_type_args.is_empty()
                                        && concrete_type_args.iter().any(|&t| t != 5)
                                    {
                                        let trace_typed_id = self.get_or_register_extern_function(
                                            "haxe_trace_enum_boxed_typed",
                                            vec![
                                                IrType::I32,
                                                IrType::Ptr(Box::new(IrType::I8)),
                                                IrType::Ptr(Box::new(IrType::I8)),
                                                IrType::I64,
                                            ],
                                            IrType::Void,
                                        );

                                        let ptr_reg = self.builder.build_bitcast(
                                            arg_reg,
                                            IrType::Ptr(Box::new(IrType::I8)),
                                        )?;

                                        // Build param types data via heap alloc + stores
                                        let alloc_size = self.builder.build_const(IrValue::I64(
                                            concrete_type_args.len() as i64,
                                        ))?;
                                        let alloc_func = self.get_or_register_extern_function(
                                            "malloc",
                                            vec![IrType::I64],
                                            IrType::Ptr(Box::new(IrType::I8)),
                                        );
                                        let param_types_data = self.builder.build_call_direct(
                                            alloc_func,
                                            vec![alloc_size],
                                            IrType::Ptr(Box::new(IrType::I8)),
                                        )?;
                                        for (i, &ptype) in concrete_type_args.iter().enumerate() {
                                            let offset =
                                                self.builder.build_const(IrValue::I64(i as i64))?;
                                            let elem_ptr = self.builder.build_gep(
                                                param_types_data,
                                                vec![offset],
                                                IrType::Ptr(Box::new(IrType::I8)),
                                            )?;
                                            let val = self
                                                .builder
                                                .build_const(IrValue::I8(ptype as i8))?;
                                            self.builder.build_store(elem_ptr, val);
                                        }
                                        let param_count = self.builder.build_const(
                                            IrValue::I64(concrete_type_args.len() as i64),
                                        )?;

                                        return self.builder.build_call_direct(
                                            trace_typed_id,
                                            vec![
                                                type_id_const,
                                                ptr_reg,
                                                param_types_data,
                                                param_count,
                                            ],
                                            IrType::Void,
                                        );
                                    }

                                    // Fallback: use untyped boxed trace
                                    let trace_enum_boxed_id = self.get_or_register_extern_function(
                                        "haxe_trace_enum_boxed",
                                        vec![IrType::I32, IrType::Ptr(Box::new(IrType::I8))],
                                        IrType::Void,
                                    );

                                    let ptr_reg = self.builder.build_bitcast(
                                        arg_reg,
                                        IrType::Ptr(Box::new(IrType::I8)),
                                    )?;

                                    return self.builder.build_call_direct(
                                        trace_enum_boxed_id,
                                        vec![type_id_const, ptr_reg],
                                        IrType::Void,
                                    );
                                } else {
                                    // Unboxed enum: arg_reg holds the discriminant (i64)
                                    // Call haxe_trace_enum(type_id: u32, discriminant: i64)
                                    let trace_enum_id = self.get_or_register_extern_function(
                                        "haxe_trace_enum",
                                        vec![IrType::I32, IrType::I64],
                                        IrType::Void,
                                    );

                                    return self.builder.build_call_direct(
                                        trace_enum_id,
                                        vec![type_id_const, arg_reg],
                                        IrType::Void,
                                    );
                                }
                            }
                        }

                        // Get the actual MIR type from the register (not the HIR type)
                        // This is important because HIR types may be vague (Ptr(Void)) but
                        // MIR registers have the actual type (String, etc.)
                        let actual_reg_type = self
                            .builder
                            .get_register_type(arg_reg)
                            .unwrap_or_else(|| self.convert_type(arg.ty));

                        let mut arg_type = actual_reg_type.clone();
                        // If the MIR type is Ptr(Void) but we have better type info from the symbol,
                        // use the symbol's type instead. This handles cases like trace(t) where t is
                        // a float from Sys.time() but the trace() signature says Dynamic.
                        // BUT: don't override Ptr(U8) — that means a boxed DynamicValue* (e.g., from
                        // Array.pop() returning Null<T>), which traceAny can properly unbox.
                        let is_boxed_dynamic = matches!(&arg_type, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::U8));
                        if matches!(arg_type, IrType::Ptr(_)) && !is_boxed_dynamic {
                            if let Some(ref type_kind) = hir_type_kind {
                                let better_type = match type_kind {
                                    crate::tast::core::TypeKind::Float => Some(IrType::F64),
                                    crate::tast::core::TypeKind::Int => Some(IrType::I64),
                                    crate::tast::core::TypeKind::Bool => Some(IrType::Bool),
                                    crate::tast::core::TypeKind::String => Some(IrType::String),
                                    _ => None,
                                };
                                if let Some(better) = better_type {
                                    arg_type = better;
                                }
                            }
                        }

                        // Check if this is an Array type from HIR type info
                        let is_array_type = matches!(
                            &hir_type_kind,
                            Some(crate::tast::core::TypeKind::Array { .. })
                        );

                        // For Array types, call haxe_trace_array directly
                        if is_array_type {
                            let trace_array_id = self.get_or_register_extern_function(
                                "haxe_trace_array",
                                vec![IrType::Ptr(Box::new(IrType::Void))],
                                IrType::Void,
                            );
                            return self.builder.build_call_direct(
                                trace_array_id,
                                vec![arg_reg],
                                IrType::Void,
                            );
                        }

                        // Handle TypeParameter types that are still type-erased (I64).
                        // Only activate when the register type didn't reveal the concrete type.
                        // Inside generic functions, emit a fixup for the monomorphize pass.
                        // Outside generic functions (shouldn't normally happen with proper type
                        // resolution), fall through to traceInt.
                        if matches!(arg_type, IrType::I64 | IrType::I32)
                            && matches!(
                                &hir_type_kind,
                                Some(crate::tast::core::TypeKind::TypeParameter { .. })
                            )
                        {
                            if let Some(crate::tast::core::TypeKind::TypeParameter {
                                symbol_id,
                                ..
                            }) = &hir_type_kind
                            {
                                let type_param_name = self
                                    .symbol_table
                                    .get_symbol(*symbol_id)
                                    .and_then(|sym| self.string_interner.get(sym.name))
                                    .map(|s| s.to_string());

                                if let Some(ref tp_name) = type_param_name {
                                    // Only emit a tag fixup if the current function actually
                                    // has this type parameter (i.e., we're inside a generic function).
                                    // If not, the fixup would never be resolved, so fall through
                                    // to normal trace dispatch instead.
                                    let current_func_has_param = self
                                        .builder
                                        .current_function()
                                        .map(|f| {
                                            f.signature
                                                .type_params
                                                .iter()
                                                .any(|tp| tp.name == *tp_name)
                                        })
                                        .unwrap_or(false);

                                    if current_func_has_param {
                                        let tag_reg = self.builder.build_const(IrValue::I32(0))?;
                                        if let Some(func) = self.builder.current_function_mut() {
                                            func.type_param_tag_fixups
                                                .push((tag_reg, tp_name.clone()));
                                        }

                                        let trace_typed_id = self.get_or_register_extern_function(
                                            "haxe_trace_typed",
                                            vec![IrType::I64, IrType::I32],
                                            IrType::Void,
                                        );

                                        return self.builder.build_call_direct(
                                            trace_typed_id,
                                            vec![arg_reg, tag_reg],
                                            IrType::Void,
                                        );
                                    }
                                    // If not in a generic function, fall through to normal dispatch.
                                }
                            }
                        }

                        // Special case: Optional<primitive> returned from MIR wrappers (e.g. array pop/shift)
                        // MIR wrappers cast DynamicValue* to IrType::Any (I64), but the value is still a boxed pointer.
                        // Detect via hir_type_kind and route to traceAny for proper unboxing.
                        // BUT: extern functions with returns_raw_value (e.g., StringMap.get) return the
                        // actual value bits as I64, NOT a boxed pointer. Nested Call expressions produce
                        // these raw values, so skip is_optional_boxed for Call args.
                        let is_optional_boxed = matches!(&arg_type, IrType::I64 | IrType::I32)
                            && matches!(
                                &hir_type_kind,
                                Some(crate::tast::core::TypeKind::Optional { .. })
                            )
                            && !matches!(&arg.kind, HirExprKind::Call { .. });

                        let trace_method = {
                            match &arg_type {
                                IrType::I32 | IrType::I64 | IrType::U64 if is_optional_boxed => {
                                    "traceAny"
                                }
                                IrType::I32 | IrType::I64 | IrType::U64 => "traceInt",
                                IrType::F32 | IrType::F64 => "traceFloat",
                                IrType::Bool => "traceBool",
                                IrType::String => "traceString", // String is ptr+len struct
                                // Also handle Ptr(String) - returned by String methods like toUpperCase()
                                IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::String) => {
                                    "traceString"
                                }
                                // Ptr(U8) when HIR type is String — from MIR wrappers returning raw string pointers
                                IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::U8) => {
                                    let is_hir_string = matches!(
                                        &hir_type_kind,
                                        Some(crate::tast::core::TypeKind::String)
                                    );
                                    if is_hir_string {
                                        "traceString"
                                    } else {
                                        "traceAny"
                                    }
                                }
                                IrType::TypeVar(_) => "traceTypedGeneric", // tag-based dispatch
                                _ => "traceAny", // Fallback for Dynamic or unknown types
                            }
                        };

                        // Debug: Print trace method selection
                        debug!(
                            "[DEBUG trace] arg_reg={}, arg_type={:?}, trace_method={}",
                            arg_reg, arg_type, trace_method
                        );

                        // Build the qualified name for the trace function
                        let trace_func_name = format!("rayzor.Trace.{}", trace_method);

                        // Look up the runtime function name
                        // For now, manually map to the runtime function
                        let runtime_func = match trace_method {
                            "traceInt" => "haxe_trace_int",
                            "traceFloat" => "haxe_trace_float",
                            "traceBool" => "haxe_trace_bool",
                            "traceString" => "haxe_trace_string",
                            "traceAny" => "haxe_trace_any",
                            _ => "haxe_trace_any",
                        };

                        // Special handling for String: use haxe_trace_string_struct that takes a pointer
                        if trace_method == "traceString" {
                            // String is represented as a pointer to HaxeString struct
                            let param_types = vec![IrType::Ptr(Box::new(IrType::String))];
                            let string_trace_id = self.get_or_register_extern_function(
                                "haxe_trace_string_struct",
                                param_types,
                                IrType::Void,
                            );
                            return self.builder.build_call_direct(
                                string_trace_id,
                                vec![arg_reg],
                                IrType::Void,
                            );
                        }

                        // TypeVar trace: use haxe_trace_typed with tag fixup.
                        // Bitcast value to I64 (TypeVar is pointer-sized) to avoid
                        // Cranelift type mismatch when inlining resolves to F64.
                        if trace_method == "traceTypedGeneric" {
                            let tag_reg = self.builder.build_const(IrValue::I32(0))?;
                            if let IrType::TypeVar(ref name) = arg_type {
                                if let Some(func) = self.builder.current_function_mut() {
                                    func.type_param_tag_fixups.push((tag_reg, name.clone()));
                                }
                            }
                            let val_as_i64 = self
                                .builder
                                .build_bitcast(arg_reg, IrType::I64)
                                .unwrap_or(arg_reg);
                            let trace_typed_id = self.get_or_register_extern_function(
                                "haxe_trace_typed",
                                vec![IrType::I64, IrType::I32],
                                IrType::Void,
                            );
                            return self.builder.build_call_direct(
                                trace_typed_id,
                                vec![val_as_i64, tag_reg],
                                IrType::Void,
                            );
                        }

                        // Get or register the extern runtime function
                        // Note: Runtime trace functions expect specific types:
                        // - haxe_trace_int expects i64
                        // - haxe_trace_float expects f64
                        // We need to cast arguments to match
                        // Note: We don't need to cast arguments here - the Cranelift backend
                        // handles signature-aware type conversion automatically (see cranelift_backend.rs:1487-1491)
                        // It will insert sextend for i32->i64, fcvt for f32->f64, etc.
                        let param_types = match trace_method {
                            "traceInt" => vec![IrType::I64],
                            "traceFloat" => vec![IrType::F64],
                            "traceBool" => vec![IrType::Bool],
                            _ => vec![arg_type.clone()],
                        };

                        // If Optional boxed value routed to traceAny, cast I64 back to pointer
                        let final_arg_reg = if is_optional_boxed && trace_method == "traceAny" {
                            let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                            self.builder.build_cast(arg_reg, IrType::I64, ptr_u8)?
                        } else {
                            arg_reg
                        };

                        let final_param_types = if is_optional_boxed && trace_method == "traceAny" {
                            vec![IrType::Ptr(Box::new(IrType::U8))]
                        } else {
                            param_types
                        };

                        let runtime_func_id = self.get_or_register_extern_function(
                            runtime_func,
                            final_param_types,
                            IrType::Void,
                        );

                        // Generate the call
                        return self.builder.build_call_direct(
                            runtime_func_id,
                            vec![final_arg_reg],
                            IrType::Void,
                        );
                    }

                    // SPECIAL CASE: Handle Std.string() function
                    // Route to type-specific string conversion functions based on argument type
                    // Note: Std.string() comes as a static method call with 2 args (Std class + actual arg)
                    if symbol_name == "string"
                        && (args.len() == 1 || (args.len() == 2 && *is_method))
                    {
                        debug!(
                            "[STD.STRING CHECK] Found 'string' call, is_method={}, args.len()={}",
                            is_method,
                            args.len()
                        );

                        // For static method calls, the actual argument is the second one (skip Std class)
                        let arg = if *is_method && args.len() == 2 {
                            &args[1]
                        } else {
                            &args[0]
                        };
                        let arg_is_value_type = self.expr_is_value_type_expr(arg);

                        // ValueType pretty-print parity path
                        if arg_is_value_type {
                            let arg_reg = self.lower_expression(arg)?;
                            return self.convert_value_type_to_string(arg_reg);
                        }

                        let arg_type = self.convert_type(arg.ty);

                        // Determine which MIR wrapper function to call based on type
                        // These wrappers call the extern runtime functions
                        let mir_wrapper = match arg_type {
                            IrType::I32 | IrType::I64 => "int_to_string",
                            IrType::F32 | IrType::F64 => "float_to_string",
                            IrType::Bool => "bool_to_string",
                            IrType::String => "string_to_string",
                            // TODO: Handle null explicitly, handle Dynamic with runtime dispatch
                            _ => "int_to_string", // Fallback - will need Dynamic support later
                        };

                        debug!(
                            "[STD.STRING] Routing Std.string() call to {} for type {:?}",
                            mir_wrapper, arg_type
                        );

                        // Lower the argument
                        let arg_reg = self.lower_expression(arg)?;

                        // Get or register the MIR wrapper function
                        // These return String (a struct with ptr + len)
                        let param_types = vec![arg_type.clone()];
                        let return_type = IrType::String; // String is represented as ptr+len
                        let mir_wrapper_id = self.get_or_register_extern_function(
                            mir_wrapper,
                            param_types,
                            return_type.clone(),
                        );

                        // Generate the call to MIR wrapper
                        return self.builder.build_call_direct(
                            mir_wrapper_id,
                            vec![arg_reg],
                            return_type,
                        );
                    }

                    // For instance method calls, check if this is a stdlib method or Dynamic method
                    // Note: Static methods like Thread.spawn() can also come through here with is_method=true
                    if *is_method && !args.is_empty() {
                        // The first arg is the receiver for instance method calls
                        // Resolve TypeAlias to get the actual receiver type
                        let receiver_type = self.resolve_through_aliases(args[0].ty);

                        {
                            let type_table = self.type_table.borrow();
                            if let Some(type_info) = type_table.get(receiver_type) {
                                debug!(
                                    "[METHOD CALL] receiver_type={:?}, kind={:?}",
                                    receiver_type, type_info.kind
                                );
                            } else {
                                // Print method name for calls with invalid receiver type
                                let method_name = self
                                    .symbol_table
                                    .get_symbol(*symbol)
                                    .map(|s| self.string_interner.get(s.name));
                                debug!(
                                    "[METHOD CALL] receiver_type={:?} NOT IN TYPE TABLE, method={:?}",
                                    receiver_type, method_name
                                );
                            }
                        }

                        // SPECIAL CASE: Handle Dynamic and TypeParameter method calls
                        // When receiver is Dynamic or TypeParameter (unresolved generic), resolve method by name
                        // TypeParameter arises from chained calls on generic types like Arc<T>.get().lock()
                        // where the return type of get() is TypeParameter T
                        {
                            let type_table = self.type_table.borrow();
                            if let Some(type_info) = type_table.get(receiver_type) {
                                if matches!(
                                    type_info.kind,
                                    TypeKind::Dynamic
                                        | TypeKind::TypeParameter { .. }
                                        | TypeKind::Placeholder { .. }
                                        | TypeKind::Unknown
                                ) {
                                    drop(type_table);

                                    // First, check if this might be a stdlib method call
                                    // by checking if the receiver expression comes from a stdlib function
                                    // (i.e., its result type would be Ptr(Void) for MIR wrappers)
                                    let method_name_str = self
                                        .symbol_table
                                        .get_symbol(*symbol)
                                        .and_then(|s| self.string_interner.get(s.name));

                                    // Check if any stdlib class has this method - use the mapping dynamically
                                    // instead of hardcoding method names. This handles cases like:
                                    // - MutexGuard.get() vs Arc.get() - both have "get" but are different
                                    // - Mutex.lock() returning Dynamic typed as MutexGuard
                                    // For Dynamic receivers, check user-defined methods FIRST.
                                    // Stdlib has common names like "sum", "get", "set" that
                                    // collide with user methods on Dynamic-typed objects.
                                    let receiver_is_dynamic = {
                                        let type_table = self.type_table.borrow();
                                        type_table
                                            .get(receiver_type)
                                            .map(|t| matches!(t.kind, TypeKind::Dynamic))
                                            .unwrap_or(false)
                                    };
                                    let user_func_for_dynamic = if receiver_is_dynamic {
                                        let method_name_is =
                                            self.symbol_table.get_symbol(*symbol).map(|s| s.name);
                                        if let Some(name) = method_name_is {
                                            let mut found = None;
                                            for (sym, &fid) in &self.function_map {
                                                if let Some(si) = self.symbol_table.get_symbol(*sym)
                                                {
                                                    if si.name == name {
                                                        found = Some(fid);
                                                        break;
                                                    }
                                                }
                                            }
                                            found
                                        } else {
                                            None
                                        }
                                    } else {
                                        None
                                    };

                                    if let Some(func_id) = user_func_for_dynamic {
                                        // User-defined method found for Dynamic receiver — use it with unboxing
                                        let receiver_reg = self.lower_expression(&args[0])?;

                                        // Dynamic receivers are always boxed (from haxe_box_reference_ptr),
                                        // even if the MIR register type shows Ptr(Void) due to cast.
                                        // Always unbox unless receiver has a class hint (stdlib container).
                                        let has_class_hint =
                                            self.register_class_hints.contains_key(&receiver_reg);
                                        let should_unbox = !has_class_hint;
                                        let actual_receiver = if should_unbox {
                                            let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                                            let unbox_func_id = self
                                                .get_or_register_extern_function(
                                                    "haxe_unbox_reference_ptr",
                                                    vec![ptr_u8.clone()],
                                                    ptr_u8.clone(),
                                                );
                                            self.builder.build_call_direct(
                                                unbox_func_id,
                                                vec![receiver_reg],
                                                ptr_u8,
                                            )?
                                        } else {
                                            receiver_reg
                                        };

                                        // Lower remaining args
                                        let arg_regs: Vec<_> = std::iter::once(actual_receiver)
                                            .chain(
                                                args[1..]
                                                    .iter()
                                                    .filter_map(|a| self.lower_expression(a)),
                                            )
                                            .collect();

                                        let actual_return_type = if let Some(func) =
                                            self.builder.module.functions.get(&func_id)
                                        {
                                            func.signature.return_type.clone()
                                        } else {
                                            result_type.clone()
                                        };

                                        return self.builder.build_call_direct(
                                            func_id,
                                            arg_regs,
                                            actual_return_type,
                                        );
                                    }

                                    let is_stdlib_method = method_name_str
                                        .map(|m| self.stdlib_mapping.any_class_has_method(m))
                                        .unwrap_or(false);
                                    if is_stdlib_method {
                                        let method_name = method_name_str.unwrap();
                                        // Calculate actual param count (exclude receiver for instance methods)
                                        let actual_param_count = args.len().saturating_sub(1);
                                        debug!(
                                            "[DYNAMIC METHOD] Found stdlib method '{}' in mapping, param_count={}",
                                            method_name, actual_param_count
                                        );

                                        // Query the stdlib mapping for all classes that have this method.
                                        // Results are sorted by priority (MutexGuard before Arc, etc.)
                                        let matching_classes = self
                                            .stdlib_mapping
                                            .find_classes_with_method(method_name);
                                        debug!(
                                            "[DYNAMIC STDLIB] {} classes have method '{}' (before param count filter)",
                                            matching_classes.len(),
                                            method_name
                                        );

                                        // Filter by param count to disambiguate overloaded methods
                                        // e.g., Array.join(sep) with 1 param vs Thread.join() with 0 params
                                        let mut filtered_classes: Vec<_> = matching_classes
                                            .into_iter()
                                            .filter(|(_, _, call)| {
                                                call.param_count == actual_param_count
                                            })
                                            .collect();
                                        debug!(
                                            "[DYNAMIC STDLIB] {} classes after param count filter",
                                            filtered_classes.len()
                                        );

                                        // Disambiguate using class hints when multiple classes match
                                        // (e.g., Arc.get vs MutexGuard.get — both have 0 params)
                                        if filtered_classes.len() > 1 {
                                            // Check if the receiver variable has a class hint
                                            let receiver_hint = if let HirExprKind::Variable {
                                                symbol: recv_sym,
                                                ..
                                            } = &args[0].kind
                                            {
                                                self.monomorphized_var_types.get(&recv_sym).cloned()
                                            } else {
                                                None
                                            };

                                            if let Some(hint) = &receiver_hint {
                                                let hinted: Vec<_> = filtered_classes
                                                    .iter()
                                                    .filter(|(class, _, _)| {
                                                        *class == hint.as_str()
                                                            || class
                                                                .ends_with(&format!("_{}", hint))
                                                            || hint
                                                                .ends_with(&format!("_{}", class))
                                                    })
                                                    .copied()
                                                    .collect();
                                                if !hinted.is_empty() {
                                                    debug!(
                                                        "[DYNAMIC STDLIB] Disambiguated by class hint '{}': {} -> {} matches",
                                                        hint,
                                                        filtered_classes.len(),
                                                        hinted.len()
                                                    );
                                                    filtered_classes = hinted;
                                                }
                                            }
                                        }

                                        // Take the first match (highest priority class)
                                        if let Some(&(class_name, _sig, runtime_call)) =
                                            filtered_classes.first()
                                        {
                                            debug!(
                                                "[DYNAMIC STDLIB] Using {}.{} -> {}",
                                                class_name, method_name, runtime_call.runtime_name
                                            );
                                            let runtime_func = runtime_call.runtime_name;

                                            // Check if this is a MIR wrapper class
                                            if self.stdlib_mapping.is_mir_wrapper_class(class_name)
                                            {
                                                // Use runtime_name directly as the MIR wrapper function name
                                                // (e.g., "Arc_init" not "rayzor_concurrent_Arc_init")
                                                let mir_func_name = runtime_func.to_string();
                                                debug!(
                                                    "[DYNAMIC STDLIB MIR] Using MIR wrapper: {}",
                                                    mir_func_name
                                                );

                                                // Lower all arguments with auto-boxing
                                                // CRITICAL: If the receiver (args[0]) can't be lowered, skip this handler
                                                // to prevent generating 0-arg calls for instance methods that expect self.
                                                let mir_wrapper_sig = self
                                                    .get_stdlib_mir_wrapper_signature(
                                                        &mir_func_name,
                                                    );
                                                let mut arg_regs = Vec::new();
                                                let mut param_types = Vec::new();
                                                let mut receiver_failed = false;
                                                for (i, arg) in args.iter().enumerate() {
                                                    if let Some(reg) = self.lower_expression(arg) {
                                                        let actual_ty = self.convert_type(arg.ty);
                                                        let expected_ty = mir_wrapper_sig
                                                            .as_ref()
                                                            .and_then(|(params, _)| {
                                                                params.get(i).cloned()
                                                            })
                                                            .unwrap_or_else(|| actual_ty.clone());

                                                        // TypeParameter/Dynamic/Placeholder args erased to I64
                                                        // should be CAST to Ptr(U8), not BOXED — but ONLY
                                                        // when the actual register value is a pointer (I64).
                                                        // For concrete primitives (I32, F64, Bool from Channel<Int>),
                                                        // the value must be BOXED, not cast.
                                                        let is_erased_type_param = {
                                                            let type_table =
                                                                self.type_table.borrow();
                                                            type_table
                                                                .get(arg.ty)
                                                                .map(|ti| {
                                                                    matches!(
                                                                ti.kind,
                                                                TypeKind::TypeParameter { .. }
                                                                | TypeKind::Dynamic
                                                                | TypeKind::Placeholder { .. }
                                                            )
                                                                })
                                                                .unwrap_or(false)
                                                        };
                                                        // Check if register holds a concrete primitive
                                                        // (e.g., Channel<Int>.send(42) → reg is I32, not a pointer)
                                                        let reg_ir_type =
                                                            self.builder.get_register_type(reg);
                                                        let is_concrete_primitive = matches!(
                                                            reg_ir_type,
                                                            Some(IrType::I32)
                                                                | Some(IrType::F32)
                                                                | Some(IrType::F64)
                                                                | Some(IrType::Bool)
                                                        );
                                                        let final_reg = if is_erased_type_param
                                                            && matches!(actual_ty, IrType::I64)
                                                            && matches!(
                                                                &expected_ty,
                                                                IrType::Ptr(_)
                                                            )
                                                            && !is_concrete_primitive
                                                        {
                                                            // Cast I64 → Ptr(U8) — the I64 is actually a pointer
                                                            self.builder
                                                                .build_cast(
                                                                    reg,
                                                                    IrType::I64,
                                                                    expected_ty.clone(),
                                                                )
                                                                .unwrap_or(reg)
                                                        } else if is_concrete_primitive
                                                            && matches!(
                                                                &expected_ty,
                                                                IrType::Ptr(_)
                                                            )
                                                        {
                                                            // Box concrete primitive for generic param
                                                            let box_ty = reg_ir_type.unwrap();
                                                            self.maybe_box_for_extern_call(
                                                                reg,
                                                                &box_ty,
                                                                &expected_ty,
                                                            )?
                                                        } else {
                                                            self.maybe_box_for_extern_call(
                                                                reg,
                                                                &actual_ty,
                                                                &expected_ty,
                                                            )?
                                                        };
                                                        arg_regs.push(final_reg);
                                                        param_types.push(expected_ty);
                                                    } else if i == 0 {
                                                        // Receiver failed to lower — can't call instance method
                                                        receiver_failed = true;
                                                        break;
                                                    }
                                                }

                                                // If receiver failed to lower, skip this handler
                                                // and let the general fallback chain handle it
                                                if receiver_failed {
                                                    // Don't generate a broken call; fall through
                                                } else {
                                                    // Get MIR wrapper return type
                                                    let mir_return_type = mir_wrapper_sig
                                                        .as_ref()
                                                        .map(|(_, ret)| ret.clone())
                                                        .unwrap_or_else(|| result_type.clone());

                                                    // Register forward reference
                                                    let mir_func_id = self
                                                        .register_stdlib_mir_forward_ref(
                                                            &mir_func_name,
                                                            param_types,
                                                            mir_return_type.clone(),
                                                        );

                                                    let call_result =
                                                        self.builder.build_call_direct(
                                                            mir_func_id,
                                                            arg_regs,
                                                            mir_return_type.clone(),
                                                        )?;

                                                    // Auto-unbox: resolve generic T from receiver type args
                                                    // e.g., Channel<Int>.tryReceive() returns Ptr(U8) but should produce I32
                                                    let resolved_expected = {
                                                        let type_table = self.type_table.borrow();
                                                        // The receiver is args[0] - check its type for generic args
                                                        let from_receiver = if !args.is_empty() {
                                                            type_table.get(args[0].ty).and_then(|ti| {
                                                            match &ti.kind {
                                                                crate::tast::TypeKind::Class { type_args, .. }
                                                                | crate::tast::TypeKind::GenericInstance { type_args, .. } => {
                                                                    if !type_args.is_empty() {
                                                                        let t = self.convert_type(type_args[0]);
                                                                        if matches!(t, IrType::I32 | IrType::I64 | IrType::F32 | IrType::F64 | IrType::Bool) {
                                                                            Some(t)
                                                                        } else {
                                                                            None
                                                                        }
                                                                    } else { None }
                                                                }
                                                                _ => None,
                                                            }
                                                        })
                                                        } else {
                                                            None
                                                        };
                                                        // Also check if return type is Optional{primitive} (Null<T>)
                                                        // and resolve to the inner primitive for unboxing
                                                        let from_optional = type_table.get(expr.ty).and_then(|ti| {
                                                            if let crate::tast::TypeKind::Optional { inner_type } = &ti.kind {
                                                                let t = self.convert_type(*inner_type);
                                                                if matches!(t, IrType::I32 | IrType::I64 | IrType::F32 | IrType::F64 | IrType::Bool) {
                                                                    Some(t)
                                                                } else {
                                                                    None
                                                                }
                                                            } else {
                                                                None
                                                            }
                                                        });
                                                        drop(type_table);
                                                        from_receiver
                                                            .or(from_optional)
                                                            .unwrap_or_else(|| result_type.clone())
                                                    };
                                                    let final_result = self
                                                        .maybe_unbox_for_extern_return(
                                                            call_result,
                                                            &mir_return_type,
                                                            &resolved_expected,
                                                        );

                                                    // Store class hint for the result register to enable
                                                    // disambiguation of subsequent method calls on this value.
                                                    // E.g., Mutex.lock() returns MutexGuard, so the result
                                                    // should be tagged as MutexGuard for .get()/.unlock() dispatch.
                                                    if let Some(result_reg) = final_result {
                                                        let return_class =
                                                            Self::get_return_class_hint(
                                                                class_name,
                                                                method_name,
                                                            );
                                                        self.register_class_hints.insert(
                                                            result_reg,
                                                            return_class.to_string(),
                                                        );
                                                    }

                                                    return final_result;
                                                } // end else !receiver_failed
                                            } else {
                                                // Direct extern call
                                                let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));

                                                // Extract runtime_call data before borrowing self mutably
                                                let has_return = runtime_call.has_return;

                                                // Lower all arguments using a for loop (not a closure)
                                                // to avoid borrow conflict with stdlib_mapping
                                                let mut arg_regs = Vec::new();
                                                for arg in args {
                                                    if let Some(reg) = self.lower_expression(arg) {
                                                        arg_regs.push(reg);
                                                    }
                                                }

                                                // Build param types
                                                let param_types: Vec<_> = arg_regs
                                                    .iter()
                                                    .map(|_| ptr_u8.clone())
                                                    .collect();

                                                // Determine return type: Void if function doesn't return, otherwise ptr
                                                let return_type = if has_return {
                                                    ptr_u8.clone()
                                                } else {
                                                    IrType::Void
                                                };

                                                let extern_func_id = self
                                                    .get_or_register_extern_function(
                                                        runtime_func,
                                                        param_types,
                                                        return_type.clone(),
                                                    );

                                                return self.builder.build_call_direct(
                                                    extern_func_id,
                                                    arg_regs,
                                                    return_type,
                                                );
                                            }
                                        }
                                        // If no mapping found, fall through to regular dispatch
                                    } else {
                                        // Look up method by name in function_map (generic Dynamic dispatch)
                                        let method_name =
                                            self.symbol_table.get_symbol(*symbol).map(|s| s.name);
                                        if let Some(name) = method_name {
                                            let mut found_func = None;
                                            for (sym, &func_id) in &self.function_map {
                                                if let Some(sym_info) =
                                                    self.symbol_table.get_symbol(*sym)
                                                {
                                                    if sym_info.name == name {
                                                        found_func = Some(func_id);
                                                        break;
                                                    }
                                                }
                                            }

                                            if let Some(func_id) = found_func {
                                                // Lower the receiver
                                                let receiver_reg =
                                                    self.lower_expression(&args[0])?;

                                                // Check if the receiver was boxed by examining its MIR register type.
                                                // Boxing creates a Ptr(U8) value. If the receiver has a different
                                                // pointer type (like Ptr(Void) from a stdlib function return),
                                                // it wasn't boxed and shouldn't be unboxed.
                                                //
                                                // IMPORTANT: If the receiver has a class hint (set by stdlib MIR
                                                // wrapper dispatch), it's a raw class pointer from a method like
                                                // MutexGuard_get — NOT a boxed DynamicValue. Don't unbox it.
                                                let has_class_hint = self
                                                    .register_class_hints
                                                    .contains_key(&receiver_reg);
                                                let receiver_mir_type =
                                                    self.builder.get_register_type(receiver_reg);
                                                // Dynamic receivers are always boxed (from haxe_box_reference_ptr),
                                                // even if MIR register type shows Ptr(Void) due to cast.
                                                // Always unbox for Dynamic unless it has a class hint.
                                                let should_unbox = !has_class_hint;

                                                let actual_receiver = if should_unbox {
                                                    // Unbox the Dynamic to get the actual object pointer
                                                    let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                                                    let unbox_func_id = self
                                                        .get_or_register_extern_function(
                                                            "haxe_unbox_reference_ptr",
                                                            vec![ptr_u8.clone()],
                                                            ptr_u8.clone(),
                                                        );
                                                    self.builder.build_call_direct(
                                                        unbox_func_id,
                                                        vec![receiver_reg],
                                                        ptr_u8,
                                                    )?
                                                } else {
                                                    debug!(
                                                        "[DYNAMIC METHOD] Skipping unbox - stdlib container method"
                                                    );
                                                    receiver_reg
                                                };

                                                // Lower the rest of arguments (skip receiver at index 0)
                                                let arg_regs: Vec<_> =
                                                    std::iter::once(actual_receiver)
                                                        .chain(args[1..].iter().filter_map(|a| {
                                                            self.lower_expression(a)
                                                        }))
                                                        .collect();

                                                // Get the function's actual return type
                                                let actual_return_type = if let Some(func) =
                                                    self.builder.module.functions.get(&func_id)
                                                {
                                                    func.signature.return_type.clone()
                                                } else {
                                                    result_type.clone()
                                                };

                                                return self.builder.build_call_direct(
                                                    func_id,
                                                    arg_regs,
                                                    actual_return_type,
                                                );
                                            }
                                        }
                                    }
                                }
                            }
                        }

                        // NOTE: MutexGuard method calls are handled through the general stdlib mechanism:
                        // 1. Dynamic dispatch uses find_classes_with_method() with dynamic priority
                        // 2. MutexGuard is prioritized (return-only type with no constructor)
                        // 3. MutexGuard_get MIR wrapper is called via stdlib_mapping

                        // NOTE: String method calls are handled through the general stdlib mechanism:
                        // 1. get_stdlib_runtime_info() maps TypeKind::String to class name "String"
                        // 2. stdlib_mapping lookup finds the correct runtime function
                        // 3. The general path handles param types and return types

                        // PRIORITY CHECK: For extern generic classes like Vec<T>, the receiver type
                        // may be TypeId::MAX (invalid). In this case, try to use the tracked
                        // monomorphized class from variable assignment.
                        if receiver_type == TypeId::from_raw(u32::MAX) {
                            debug!(
                                "[MONO VAR CHECK] receiver_type is MAX, checking monomorphized_var_types ({} entries)",
                                self.monomorphized_var_types.len()
                            );

                            // Try to extract the SymbolId from the receiver expression
                            // The receiver (args[0]) should be a variable reference like HirExprKind::Variable
                            let receiver_symbol = match &args[0].kind {
                                HirExprKind::Variable { symbol, .. } => Some(*symbol),
                                HirExprKind::Field { field, .. } => Some(*field),
                                _ => None,
                            };
                            debug!(
                                "[MONO VAR CHECK] Receiver expression symbol: {:?}",
                                receiver_symbol
                            );

                            if let Some(var_symbol) = receiver_symbol {
                                // Check if this variable has a tracked monomorphized class
                                if let Some(mono_class) =
                                    self.monomorphized_var_types.get(&var_symbol).cloned()
                                {
                                    // Get the method name
                                    if let Some(method_sym) = self.symbol_table.get_symbol(*symbol)
                                    {
                                        if let Some(method_name) =
                                            self.string_interner.get(method_sym.name)
                                        {
                                            debug!(
                                                "[MONO VAR DISPATCH] Found tracked class '{}' for variable {:?}, method '{}'",
                                                mono_class, var_symbol, method_name
                                            );

                                            // Build the MIR wrapper function name: VecI32_push, VecF64_get, etc.
                                            let mir_func_name =
                                                format!("{}_{}", mono_class, method_name);

                                            // Get the signature from get_stdlib_mir_wrapper_signature
                                            if let Some((mir_param_types, mir_return_type)) = self
                                                .get_stdlib_mir_wrapper_signature(&mir_func_name)
                                            {
                                                debug!(
                                                    "[MONO VAR DISPATCH] Using MIR wrapper: {}",
                                                    mir_func_name
                                                );

                                                // Lower all arguments (including receiver)
                                                let mut arg_regs = Vec::new();
                                                for arg in args {
                                                    if let Some(reg) = self.lower_expression(arg) {
                                                        arg_regs.push(reg);
                                                    }
                                                }

                                                // Register forward reference
                                                let mir_func_id = self
                                                    .register_stdlib_mir_forward_ref(
                                                        &mir_func_name,
                                                        mir_param_types.clone(),
                                                        mir_return_type.clone(),
                                                    );

                                                debug!(
                                                    "[MONO VAR DISPATCH] Registered forward ref to {} with ID {:?}",
                                                    mir_func_name, mir_func_id
                                                );

                                                // Generate the call
                                                let result = self.builder.build_call_direct(
                                                    mir_func_id,
                                                    arg_regs,
                                                    mir_return_type,
                                                );
                                                debug!(
                                                    "[MONO VAR DISPATCH] Generated call, result: {:?}",
                                                    result
                                                );
                                                return result;
                                            }
                                        }
                                    }
                                }
                            }
                        }

                        // GUARD: Skip instance method handling if receiver is a Class type itself
                        // This can happen when static method calls come through with is_method=true
                        // e.g., Thread.spawn(closure) might be seen as Thread(receiver).spawn(closure)
                        let receiver_is_class_type = {
                            let type_table = self.type_table.borrow();
                            type_table.get(receiver_type)
                                .map(|ti| {
                                    // Check if the type is a class AND matches one of our MIR wrapper classes
                                    if let crate::tast::core::TypeKind::Class { symbol_id, .. } = &ti.kind {
                                        self.symbol_table.get_symbol(*symbol_id)
                                            .and_then(|s| self.string_interner.get(s.name))
                                            .map(|name| {
                                                // Use dynamic check via stdlib_mapping instead of hardcoded list
                                                let is_mir_wrapper = self.stdlib_mapping.is_mir_wrapper_class(name);
                                                if is_mir_wrapper {
                                                    debug!("[GUARD] Receiver type is {} class (MIR wrapper), skipping instance method path", name);
                                                }
                                                is_mir_wrapper
                                            })
                                            .unwrap_or(false)
                                    } else {
                                        false
                                    }
                                })
                                .unwrap_or(false)
                        };

                        // Try the receiver type path first (for true instance methods)
                        // Skip if receiver is a MIR wrapper class type (those are static methods)
                        {
                            let sym_name = self
                                .symbol_table
                                .get_symbol(*symbol)
                                .and_then(|s| self.string_interner.get(s.name))
                                .unwrap_or("?");
                            if matches!(
                                sym_name,
                                "balance"
                                    | "setLoop"
                                    | "compare"
                                    | "merge"
                                    | "minBinding"
                                    | "removeMinBinding"
                            ) {
                                debug!(
                                    "[DISPATCH_TRACE] '{}' receiver_is_class_type={}, receiver_type={:?}",
                                    sym_name, receiver_is_class_type, receiver_type
                                );
                            }
                        }
                        if !receiver_is_class_type {
                            // Calculate param_count for overload disambiguation: args[0] is receiver, rest are params
                            let method_param_count =
                                if args.len() > 1 { args.len() - 1 } else { 0 };
                            if let Some((class_name, method_name, runtime_call)) = self
                                .get_stdlib_runtime_info(
                                    *symbol,
                                    receiver_type,
                                    Some(method_param_count),
                                    None,
                                )
                            {
                                let runtime_func = runtime_call.runtime_name;
                                let ptr_conversion_mask = runtime_call.params_need_ptr_conversion;
                                let raw_value_mask = runtime_call.raw_value_params;
                                let returns_raw_value = runtime_call.returns_raw_value;
                                let extend_i64_mask = runtime_call.extend_to_i64_params;
                                let needs_out_param = runtime_call.needs_out_param;
                                let has_return = runtime_call.has_return; // Copy for use in fallback closure

                                // SPECIAL CASE: Instance methods that need out parameter (like Array.slice, String.split)
                                // These have void return but write result to first out parameter
                                // Generate inline wrapper: allocate + call runtime + return pointer
                                if needs_out_param {
                                    debug!(
                                        "[OUT PARAM] Instance method {}.{} needs out param inline wrapper",
                                        class_name, method_name
                                    );

                                    // Lower all arguments (receiver + method args)
                                    let mut call_arg_regs = Vec::new();
                                    for arg in args {
                                        if let Some(reg) = self.lower_expression(arg) {
                                            call_arg_regs.push(reg);
                                        }
                                    }

                                    // Allocate space for the result object
                                    // For arrays/strings, allocate an opaque pointer-sized value
                                    let out_ptr_ty = IrType::Ptr(Box::new(IrType::Void));
                                    let out_ptr =
                                        self.builder.build_alloc(out_ptr_ty.clone(), None)?;

                                    // Register the extern runtime function
                                    // Signature: void runtime_func(out: *Ptr(Void), receiver: Ptr(Void), ...params)
                                    let mut extern_param_types = vec![out_ptr_ty.clone()]; // out parameter
                                    for arg in args {
                                        extern_param_types.push(self.convert_type(arg.ty));
                                    }

                                    let extern_func_id = self.get_or_register_extern_function(
                                        runtime_func,
                                        extern_param_types,
                                        IrType::Void,
                                    );

                                    // Call runtime function: runtime_func(out_ptr, receiver, ...args)
                                    let mut runtime_args = vec![out_ptr];
                                    runtime_args.extend(call_arg_regs);

                                    self.builder.build_call_direct(
                                        extern_func_id,
                                        runtime_args,
                                        IrType::Void,
                                    );

                                    // Load the result pointer from the out parameter
                                    let result_ptr =
                                        self.builder.build_load(out_ptr, out_ptr_ty)?;

                                    debug!(
                                        "[OUT PARAM] Generated inline wrapper for {}, result_ptr: {:?}",
                                        runtime_func, result_ptr
                                    );

                                    return Some(result_ptr);
                                }

                                // SPECIAL CASE: Check if this is a stdlib MIR wrapper function
                                // MIR wrappers are functions that forward to extern runtime functions.
                                // The wrappers handle calling convention differences and provide default arguments.
                                // NOTE: We check runtime_call.is_mir_wrapper, not just is_mir_wrapper_class(),
                                // because some methods on MIR wrapper classes (e.g., String.split) are
                                // direct extern calls without wrappers.
                                if runtime_call.is_mir_wrapper {
                                    // Use the runtime function name from the mapping to handle overloaded methods
                                    // For example, String.indexOf can map to String_indexOf (1-arg) or String_indexOf_2 (2-arg)
                                    let mir_func_name = runtime_func.to_string();
                                    debug!(
                                        "[STDLIB MIR] Detected stdlib MIR wrapper function (instance): {}",
                                        mir_func_name
                                    );

                                    // Lower all arguments and collect their types
                                    // Auto-box primitive args when MIR wrapper expects Ptr(U8)
                                    // (e.g., Channel<Int>.send(42) needs to box the Int)
                                    let mir_wrapper_params = self
                                        .get_stdlib_mir_wrapper_signature(&mir_func_name)
                                        .map(|(params, _)| params);
                                    let mut arg_regs = Vec::new();
                                    let mut param_types = Vec::new();
                                    for (i, arg) in args.iter().enumerate() {
                                        if let Some(reg) = self.lower_expression(arg) {
                                            let actual_ty = self.convert_type(arg.ty);
                                            // Check if MIR wrapper expects a different type (e.g., Ptr(U8) for boxed value)
                                            let expected_ty = mir_wrapper_params
                                                .as_ref()
                                                .and_then(|params| params.get(i).cloned())
                                                .unwrap_or_else(|| actual_ty.clone());
                                            let final_reg = self.maybe_box_for_extern_call(
                                                reg,
                                                &actual_ty,
                                                &expected_ty,
                                            )?;
                                            arg_regs.push(final_reg);
                                            param_types.push(expected_ty);
                                        }
                                    }

                                    // SPECIAL: For generic methods that return T (like Thread<T>.join() -> T,
                                    // Channel<T>.tryReceive() -> Null<T>), we need to resolve the type parameter
                                    // from the receiver's generic arguments.
                                    // Also resolve when result_type is Ptr(Void) which comes from Dynamic/unresolved generics.
                                    let needs_generic_resolve = result_type == IrType::Any
                                        || matches!(&result_type, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::Void))
                                        || result_type == IrType::I64;
                                    let resolved_result_type = if needs_generic_resolve {
                                        // Check if the receiver is a generic class with type parameters
                                        let type_table = self.type_table.borrow();
                                        if let Some(receiver_info) = type_table.get(receiver_type) {
                                            if let crate::tast::TypeKind::Class {
                                                type_args, ..
                                            } = &receiver_info.kind
                                            {
                                                // For Thread<T>.join(), type_args[0] is T
                                                if !type_args.is_empty() {
                                                    let concrete_type =
                                                        self.convert_type(type_args[0]);
                                                    debug!(
                                                        "[GENERIC RESOLVE] Resolved return type from {:?} to {:?}",
                                                        result_type, concrete_type
                                                    );
                                                    concrete_type
                                                } else {
                                                    result_type.clone()
                                                }
                                            } else {
                                                result_type.clone()
                                            }
                                        } else {
                                            result_type.clone()
                                        }
                                    } else {
                                        result_type.clone()
                                    };

                                    // Register forward reference - will be provided by merged stdlib module
                                    let mir_func_id = self.register_stdlib_mir_forward_ref(
                                        &mir_func_name,
                                        param_types,
                                        resolved_result_type.clone(),
                                    );

                                    // IMPORTANT: For Void-returning functions, use the function's ACTUAL return type.
                                    // For non-void functions, trust resolved_result_type (which handles generics correctly).
                                    // This fixes the bug where void functions like Channel.send incorrectly get dest registers.
                                    let final_return_type = if let Some(func) =
                                        self.builder.module.functions.get(&mir_func_id)
                                    {
                                        if func.signature.return_type == IrType::Void {
                                            debug!(
                                                "[STDLIB MIR] Function {} returns Void, using actual signature",
                                                mir_func_name
                                            );
                                            IrType::Void
                                        } else if resolved_result_type == IrType::Any
                                            || matches!(resolved_result_type, IrType::Ptr(ref inner) if **inner == IrType::Void)
                                        {
                                            debug!(
                                                "[STDLIB MIR] resolved_result_type is Any/Ptr(Void), using function signature {:?}",
                                                func.signature.return_type
                                            );
                                            func.signature.return_type.clone()
                                        } else {
                                            debug!(
                                                "[STDLIB MIR] Using resolved_result_type {:?} (handles generics)",
                                                resolved_result_type
                                            );
                                            resolved_result_type.clone()
                                        }
                                    } else {
                                        resolved_result_type.clone()
                                    };

                                    debug!(
                                        "[STDLIB MIR] Registered forward ref (instance) to {} with ID {:?}, final return type: {:?}",
                                        mir_func_name, mir_func_id, final_return_type
                                    );

                                    // Generate the call with the MIR wrapper's actual return type
                                    // (which may be Ptr(U8) for generic methods returning T)
                                    let mir_actual_return = self
                                        .get_stdlib_mir_wrapper_signature(&mir_func_name)
                                        .map(|(_, ret)| ret)
                                        .unwrap_or_else(|| final_return_type.clone());
                                    let call_result = self.builder.build_call_direct(
                                        mir_func_id,
                                        arg_regs,
                                        mir_actual_return.clone(),
                                    )?;

                                    // Auto-unbox if MIR wrapper returns Ptr(U8) but caller expects primitive
                                    // (e.g., Channel<Int>.tryReceive() returns boxed int that needs unboxing)
                                    let final_result = self.maybe_unbox_for_extern_return(
                                        call_result,
                                        &mir_actual_return,
                                        &resolved_result_type,
                                    );

                                    // Set class hint on the FINAL result register (after potential unboxing)
                                    // to enable disambiguation of subsequent method calls.
                                    // E.g., Array.iterator() returns ArrayIterator, so subsequent
                                    // .hasNext()/.next() calls dispatch to ArrayIterator methods.
                                    if let Some(result_reg) = final_result {
                                        let return_class =
                                            Self::get_return_class_hint(class_name, method_name);
                                        self.register_class_hints
                                            .insert(result_reg, return_class.to_string());
                                    }

                                    return final_result;
                                }

                                // println!(
                                //     "✅ Generating runtime call to {} (receiver type path)",
                                //     runtime_func
                                // );

                                // Lower all arguments
                                let arg_regs: Vec<_> = args
                                    .iter()
                                    .filter_map(|a| self.lower_expression(a))
                                    .collect();

                                // Apply raw value conversion for high-performance inline storage (StringMap, IntMap)
                                // Values are cast to u64 raw bits - no boxing, no heap allocation
                                let mut final_arg_regs = arg_regs.clone();
                                if raw_value_mask != 0 {
                                    for i in 0..arg_regs.len() {
                                        if (raw_value_mask & (1 << i)) != 0 {
                                            let arg_reg = arg_regs[i];
                                            let arg_type = self
                                                .builder
                                                .get_register_type(arg_reg)
                                                .unwrap_or(IrType::I64);

                                            // Cast value to U64 raw bits - zero-cost for same-size types
                                            let raw_reg = match &arg_type {
                                                IrType::I32 => {
                                                    // Zero-extend i32 to u64
                                                    self.builder.build_cast(
                                                        arg_reg,
                                                        IrType::I32,
                                                        IrType::U64,
                                                    )
                                                }
                                                IrType::I64 => {
                                                    // Reinterpret i64 as u64 (same bits) - use cast
                                                    self.builder.build_cast(
                                                        arg_reg,
                                                        IrType::I64,
                                                        IrType::U64,
                                                    )
                                                }
                                                IrType::F64 => {
                                                    // Reinterpret f64 bits as u64 - use BitCast instruction
                                                    self.builder.build_bitcast(arg_reg, IrType::U64)
                                                }
                                                IrType::F32 => {
                                                    // Extend f32 to f64, then reinterpret as u64
                                                    let f64_reg = self
                                                        .builder
                                                        .build_cast(
                                                            arg_reg,
                                                            IrType::F32,
                                                            IrType::F64,
                                                        )
                                                        .unwrap_or(arg_reg);
                                                    self.builder.build_bitcast(f64_reg, IrType::U64)
                                                }
                                                IrType::Bool => {
                                                    // Zero-extend bool to u64
                                                    self.builder.build_cast(
                                                        arg_reg,
                                                        IrType::Bool,
                                                        IrType::U64,
                                                    )
                                                }
                                                IrType::Ptr(_) => {
                                                    // Pointer to u64 (address as integer)
                                                    self.builder.build_cast(
                                                        arg_reg,
                                                        arg_type.clone(),
                                                        IrType::U64,
                                                    )
                                                }
                                                _ => {
                                                    // For other types, try direct cast to U64
                                                    self.builder.build_cast(
                                                        arg_reg,
                                                        arg_type.clone(),
                                                        IrType::U64,
                                                    )
                                                }
                                            };

                                            if let Some(raw) = raw_reg {
                                                final_arg_regs[i] = raw;
                                            }
                                        }
                                    }
                                }
                                // Apply pointer conversion for parameters that need it (DEPRECATED - use raw_value_params)
                                // This creates boxed Dynamic values for legacy runtime functions.
                                else if ptr_conversion_mask != 0 {
                                    for i in 0..arg_regs.len() {
                                        // Check if bit i is set in the mask
                                        if (ptr_conversion_mask & (1 << i)) != 0 {
                                            let arg_reg = arg_regs[i];
                                            let arg_type = self
                                                .builder
                                                .get_register_type(arg_reg)
                                                .unwrap_or(IrType::I64);

                                            // Use proper Dynamic boxing based on the argument type
                                            // This creates a tagged Dynamic value that can be unboxed later
                                            // Use the haxe_box_*_ptr wrapper functions which handle type conversion internally
                                            let boxed_reg = match &arg_type {
                                                IrType::I32 => {
                                                    // Box int using haxe_box_int_ptr wrapper (which handles i32->i64 cast)
                                                    let box_func = self
                                                        .get_or_register_extern_function(
                                                            "haxe_box_int_ptr",
                                                            vec![IrType::I32],
                                                            IrType::Ptr(Box::new(IrType::U8)),
                                                        );
                                                    self.builder.build_call_direct(
                                                        box_func,
                                                        vec![arg_reg],
                                                        IrType::Ptr(Box::new(IrType::U8)),
                                                    )
                                                }
                                                IrType::I64 => {
                                                    // Box int64 - truncate to i32 and use haxe_box_int_ptr wrapper
                                                    let truncated = self
                                                        .builder
                                                        .build_cast(
                                                            arg_reg,
                                                            IrType::I64,
                                                            IrType::I32,
                                                        )
                                                        .unwrap_or(arg_reg);
                                                    let box_func = self
                                                        .get_or_register_extern_function(
                                                            "haxe_box_int_ptr",
                                                            vec![IrType::I32],
                                                            IrType::Ptr(Box::new(IrType::U8)),
                                                        );
                                                    self.builder.build_call_direct(
                                                        box_func,
                                                        vec![truncated],
                                                        IrType::Ptr(Box::new(IrType::U8)),
                                                    )
                                                }
                                                IrType::F32 | IrType::F64 => {
                                                    // Box float using haxe_box_float_ptr wrapper
                                                    let float_val = if arg_type == IrType::F32 {
                                                        self.builder
                                                            .build_cast(
                                                                arg_reg,
                                                                IrType::F32,
                                                                IrType::F64,
                                                            )
                                                            .unwrap_or(arg_reg)
                                                    } else {
                                                        arg_reg
                                                    };
                                                    let box_func = self
                                                        .get_or_register_extern_function(
                                                            "haxe_box_float_ptr",
                                                            vec![IrType::F64],
                                                            IrType::Ptr(Box::new(IrType::U8)),
                                                        );
                                                    self.builder.build_call_direct(
                                                        box_func,
                                                        vec![float_val],
                                                        IrType::Ptr(Box::new(IrType::U8)),
                                                    )
                                                }
                                                IrType::Bool => {
                                                    // Box bool using haxe_box_bool_ptr wrapper
                                                    let box_func = self
                                                        .get_or_register_extern_function(
                                                            "haxe_box_bool_ptr",
                                                            vec![IrType::Bool],
                                                            IrType::Ptr(Box::new(IrType::U8)),
                                                        );
                                                    self.builder.build_call_direct(
                                                        box_func,
                                                        vec![arg_reg],
                                                        IrType::Ptr(Box::new(IrType::U8)),
                                                    )
                                                }
                                                IrType::Ptr(_) | IrType::Struct { .. } => {
                                                    // Pointer/reference types still need stack allocation for ptr_params
                                                    // because the runtime function expects a pointer TO the value,
                                                    // and the value itself is a pointer we need to pass BY REFERENCE.
                                                    // Example: haxe_array_push(arr, data) where data = &value
                                                    // For Array<Thread>, value is a pointer, so data = &pointer
                                                    if let Some(stack_slot) = self
                                                        .builder
                                                        .build_alloc(arg_type.clone(), None)
                                                    {
                                                        self.builder
                                                            .build_store(stack_slot, arg_reg);
                                                        Some(stack_slot)
                                                    } else {
                                                        Some(arg_reg)
                                                    }
                                                }
                                                _ => {
                                                    // For other types, fallback to stack allocation
                                                    // (This preserves the old behavior for edge cases)
                                                    if let Some(stack_slot) = self
                                                        .builder
                                                        .build_alloc(arg_type.clone(), None)
                                                    {
                                                        self.builder
                                                            .build_store(stack_slot, arg_reg);
                                                        Some(stack_slot)
                                                    } else {
                                                        Some(arg_reg)
                                                    }
                                                }
                                            };

                                            if let Some(boxed) = boxed_reg {
                                                final_arg_regs[i] = boxed;
                                            }
                                        }
                                    }
                                }

                                // Apply i32 -> i64 extension for IntMap key parameters
                                // This is needed because Haxe Int is 32-bit but the runtime uses 64-bit keys
                                if extend_i64_mask != 0 {
                                    for i in 0..final_arg_regs.len() {
                                        if (extend_i64_mask & (1 << i)) != 0 {
                                            let arg_reg = final_arg_regs[i];
                                            let arg_type = self
                                                .builder
                                                .get_register_type(arg_reg)
                                                .unwrap_or(IrType::I32);

                                            // Only extend i32 to i64, skip if already i64
                                            if arg_type == IrType::I32 {
                                                if let Some(extended) = self.builder.build_cast(
                                                    arg_reg,
                                                    IrType::I32,
                                                    IrType::I64,
                                                ) {
                                                    final_arg_regs[i] = extended;
                                                }
                                            }
                                        }
                                    }
                                }

                                // Get or register the extern runtime function
                                // Use actual argument types from TAST, applying type conversion where needed
                                let param_types: Vec<IrType> = args
                                    .iter()
                                    .enumerate()
                                    .map(|(i, arg)| {
                                        // Raw value params are passed as U64 (high-performance inline storage)
                                        if raw_value_mask != 0 && (raw_value_mask & (1 << i)) != 0 {
                                            IrType::U64
                                        }
                                        // Extended i64 params need i64 type in signature
                                        else if extend_i64_mask != 0
                                            && (extend_i64_mask & (1 << i)) != 0
                                        {
                                            IrType::I64
                                        }
                                        // Legacy ptr_conversion params are passed as Ptr (boxed Dynamic)
                                        else if ptr_conversion_mask != 0
                                            && (ptr_conversion_mask & (1 << i)) != 0
                                        {
                                            IrType::Ptr(Box::new(IrType::U8))
                                        } else {
                                            self.convert_type(arg.ty)
                                        }
                                    })
                                    .collect();

                                // For functions that return raw values (u64), we need to:
                                // 1. Resolve the actual type parameter T from the receiver's generic args
                                // 2. Call with U64 return type
                                // 3. Cast the result to the resolved type
                                let resolved_return_type = if returns_raw_value {
                                    // Try to resolve T from receiver's generic arguments
                                    let type_table = self.type_table.borrow();
                                    if let Some(receiver_info) = type_table.get(receiver_type) {
                                        if let crate::tast::TypeKind::Class { type_args, .. } =
                                            &receiver_info.kind
                                        {
                                            if !type_args.is_empty() {
                                                let concrete_type = self.convert_type(type_args[0]);
                                                concrete_type
                                            } else {
                                                result_type.clone()
                                            }
                                        } else {
                                            result_type.clone()
                                        }
                                    } else {
                                        result_type.clone()
                                    }
                                } else {
                                    // IMPORTANT: For MIR wrappers, use their actual return type instead of HIR type
                                    // HIR type may be Dynamic/Ptr(Void) but the wrapper returns a concrete type (e.g., Bool)
                                    self.get_stdlib_mir_wrapper_signature(&runtime_func)
                                        .map(|(_, ret_ty)| ret_ty)
                                        .unwrap_or_else(|| {
                                            // If no explicit signature, check has_return flag
                                            // This fixes array.push() returning void but being tracked for drop
                                            if has_return {
                                                result_type.clone()
                                            } else {
                                                IrType::Void
                                            }
                                        })
                                };
                                debug!(
                                    "[RESOLVED RETURN TYPE] runtime_func={}, result_type={:?}, resolved={:?}",
                                    runtime_func, result_type, resolved_return_type
                                );

                                let call_return_type = if returns_raw_value {
                                    IrType::U64
                                } else {
                                    resolved_return_type.clone()
                                };

                                let runtime_func_id = self.get_or_register_extern_function(
                                    &runtime_func,
                                    param_types,
                                    call_return_type.clone(),
                                );

                                // Generate the call to the runtime function
                                let call_result = self.builder.build_call_direct(
                                    runtime_func_id,
                                    final_arg_regs,
                                    call_return_type,
                                );

                                // If this returns raw value, cast U64 back to the resolved type parameter
                                if returns_raw_value {
                                    if let Some(raw_reg) = call_result {
                                        // Cast U64 to the resolved type parameter
                                        let final_result = match &resolved_return_type {
                                            IrType::I32 => self.builder.build_cast(
                                                raw_reg,
                                                IrType::U64,
                                                IrType::I32,
                                            ),
                                            IrType::I64 => self.builder.build_cast(
                                                raw_reg,
                                                IrType::U64,
                                                IrType::I64,
                                            ),
                                            IrType::F64 => {
                                                self.builder.build_bitcast(raw_reg, IrType::F64)
                                            }
                                            IrType::F32 => {
                                                // Bitcast to F64, then convert to F32
                                                if let Some(f64_reg) =
                                                    self.builder.build_bitcast(raw_reg, IrType::F64)
                                                {
                                                    self.builder.build_cast(
                                                        f64_reg,
                                                        IrType::F64,
                                                        IrType::F32,
                                                    )
                                                } else {
                                                    None
                                                }
                                            }
                                            IrType::Bool => self.builder.build_cast(
                                                raw_reg,
                                                IrType::U64,
                                                IrType::Bool,
                                            ),
                                            IrType::Ptr(ref inner)
                                                if !matches!(inner.as_ref(), IrType::Void) =>
                                            {
                                                // Concrete pointer type (e.g., Ptr(String))
                                                self.builder.build_cast(
                                                    raw_reg,
                                                    IrType::U64,
                                                    resolved_return_type.clone(),
                                                )
                                            }
                                            _ => {
                                                // Unresolved T (Ptr(Void)/Dynamic) or unknown: keep as I64
                                                // so the raw value isn't misinterpreted as a pointer
                                                self.builder.build_cast(
                                                    raw_reg,
                                                    IrType::U64,
                                                    IrType::I64,
                                                )
                                            }
                                        };
                                        return final_result;
                                    }
                                }

                                return call_result;
                            }

                            // GUARD: Check if receiver is a user-defined class (not stdlib)
                            // If so, skip all stdlib fallbacks - they would incorrectly match stdlib methods
                            let receiver_is_user_class = {
                                let type_table = self.type_table.borrow();
                                type_table
                                    .get(receiver_type)
                                    .map(|ti| {
                                        match &ti.kind {
                                            crate::tast::core::TypeKind::Class {
                                                symbol_id,
                                                ..
                                            } => {
                                                // Check if this is a stdlib class
                                                self.symbol_table
                                                    .get_symbol(*symbol_id)
                                                    .map(|s| !self.is_stdlib_class_by_symbol(s))
                                                    .unwrap_or(false)
                                            }
                                            // TypeParameter receivers always come from user-defined generics.
                                            // Method calls on T should resolve through function_map, not stdlib.
                                            // (Constrained T:Interface is handled earlier by interface dispatch.)
                                            crate::tast::core::TypeKind::TypeParameter {
                                                ..
                                            } => true,
                                            // GenericInstance: check if the base type is a user class
                                            crate::tast::core::TypeKind::GenericInstance {
                                                base_type,
                                                ..
                                            } => type_table
                                                .get(*base_type)
                                                .map(|bt| {
                                                    if let crate::tast::core::TypeKind::Class {
                                                        symbol_id,
                                                        ..
                                                    } = &bt.kind
                                                    {
                                                        self.symbol_table
                                                            .get_symbol(*symbol_id)
                                                            .map(|s| {
                                                                !self.is_stdlib_class_by_symbol(s)
                                                            })
                                                            .unwrap_or(false)
                                                    } else {
                                                        false
                                                    }
                                                })
                                                .unwrap_or(false),
                                            // Abstract types with user-defined methods
                                            crate::tast::core::TypeKind::Abstract {
                                                symbol_id,
                                                ..
                                            } => self
                                                .symbol_table
                                                .get_symbol(*symbol_id)
                                                .map(|s| !self.is_stdlib_class_by_symbol(s))
                                                .unwrap_or(false),
                                            _ => false,
                                        }
                                    })
                                    .unwrap_or(false)
                            };

                            // Skip stdlib fallbacks for user-defined classes
                            if receiver_is_user_class {
                                // For user-defined classes, the method should be in function_map
                                // Don't try to match stdlib methods
                            } else {
                                // Fallback: Use stdlib mapping to try all possible class/method combinations
                                // This is necessary when qualified names aren't set properly
                                if let Some(method_sym) = self.symbol_table.get_symbol(*symbol) {
                                    if let Some(method_name) =
                                        self.string_interner.get(method_sym.name)
                                    {
                                        let static_args = self.effective_static_call_args(args);
                                        // First try to use the qualified name if available
                                        if let Some(qual_name) = method_sym
                                            .qualified_name
                                            .and_then(|qn| self.string_interner.get(qn))
                                        {
                                            if let Some(runtime_func) = self
                                                .get_static_stdlib_runtime_func_with_params(
                                                    qual_name,
                                                    method_name,
                                                    static_args.len(),
                                                )
                                            {
                                                // CHECK: Is this a MIR wrapper function or a true extern?
                                                // We check this by asking get_stdlib_mir_wrapper_signature - if it knows about
                                                // this function, it's a MIR wrapper. If not, it's an extern.
                                                // This keeps all the knowledge about MIR wrappers centralized.
                                                if let Some((mir_param_types, mir_return_type)) =
                                                    self.get_stdlib_mir_wrapper_signature(
                                                        runtime_func,
                                                    )
                                                {
                                                    debug!(
                                                        "[QUALIFIED NAME PATH] Detected MIR wrapper: {}",
                                                        runtime_func
                                                    );

                                                    // Lower all arguments and collect their types
                                                    let mut arg_regs = Vec::new();
                                                    let mut param_types = Vec::new();
                                                    for arg in static_args {
                                                        if let Some(reg) =
                                                            self.lower_expression(arg)
                                                        {
                                                            arg_regs.push(reg);
                                                            param_types
                                                                .push(self.convert_type(arg.ty));
                                                        }
                                                    }

                                                    // Register forward reference - will be provided by merged stdlib module
                                                    let mir_func_id = self
                                                        .register_stdlib_mir_forward_ref(
                                                            runtime_func,
                                                            param_types,
                                                            result_type.clone(),
                                                        );

                                                    debug!(
                                                        "[QUALIFIED NAME PATH] Registered forward ref to {} with ID {:?}",
                                                        runtime_func, mir_func_id
                                                    );

                                                    // Generate the call
                                                    let result = self.builder.build_call_direct(
                                                        mir_func_id,
                                                        arg_regs,
                                                        result_type,
                                                    );
                                                    debug!(
                                                        "[QUALIFIED NAME PATH] Generated call, result: {:?}",
                                                        result
                                                    );
                                                    return result;
                                                }

                                                // Lower all arguments
                                                let arg_regs: Vec<_> = static_args
                                                    .iter()
                                                    .filter_map(|a| self.lower_expression(a))
                                                    .collect();

                                                // Get expected types FIRST so we can auto-box before ptr_conversion
                                                let (
                                                    expected_param_types_qn,
                                                    expected_return_type_qn,
                                                ) = self
                                                    .get_extern_function_signature(&runtime_func)
                                                    .unwrap_or_else(|| {
                                                        let param_types: Vec<IrType> = static_args
                                                            .iter()
                                                            .map(|arg| self.convert_type(arg.ty))
                                                            .collect();
                                                        (param_types, result_type.clone())
                                                    });

                                                // Auto-box arguments when expected type is Ptr(U8) (Dynamic)
                                                let mut final_arg_regs: Vec<_> = arg_regs.iter().enumerate()
                                                    .map(|(i, &reg)| {
                                                        if let (Some(expected_ty), Some(actual_ty)) = (
                                                            expected_param_types_qn.get(i),
                                                            self.builder.get_register_type(reg)
                                                        ) {
                                                            if *expected_ty != actual_ty {
                                                                let is_ptr_u8 = matches!(expected_ty, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::U8));
                                                                if is_ptr_u8 && i < static_args.len() {
                                                                    if let Some(boxed) = self.box_value_for_dynamic(reg, static_args[i].ty) {
                                                                        return boxed;
                                                                    }
                                                                }
                                                                if let Some(casted) = self.builder.build_cast(reg, actual_ty.clone(), expected_ty.clone()) {
                                                                    return casted;
                                                                }
                                                            }
                                                        }
                                                        reg
                                                    })
                                                    .collect();

                                                let runtime_func_id_qn = self
                                                    .get_or_register_extern_function(
                                                        &runtime_func,
                                                        expected_param_types_qn,
                                                        expected_return_type_qn.clone(),
                                                    );

                                                // Generate the call to the runtime function
                                                return self.builder.build_call_direct(
                                                    runtime_func_id_qn,
                                                    final_arg_regs,
                                                    expected_return_type_qn,
                                                );

                                                // DEAD CODE below (kept for reference): old ptr_conversion path
                                                #[allow(unreachable_code)]
                                                let _unused_final_arg_regs = arg_regs.clone();
                                                #[allow(unreachable_code)]
                                                let mut final_arg_regs = arg_regs.clone();
                                                let ptr_conversion_mask = self
                                                    .stdlib_mapping
                                                    .find_by_runtime_name(&runtime_func)
                                                    .map(|m| m.params_need_ptr_conversion)
                                                    .unwrap_or(0);
                                                if ptr_conversion_mask != 0 {
                                                    for i in 0..arg_regs.len() {
                                                        // Check if bit i is set in the mask
                                                        if (ptr_conversion_mask & (1 << i)) != 0 {
                                                            let arg_reg = arg_regs[i];
                                                            // Default to I64 (pointer-sized) if type is unknown.
                                                            // This is safer than I32 since pointers and most values are 64-bit.
                                                            let arg_type = self
                                                                .builder
                                                                .get_register_type(arg_reg)
                                                                .unwrap_or(IrType::I64);

                                                            // For array operations, always allocate 8 bytes (elem_size is always 8)
                                                            // and extend smaller values to 64-bit
                                                            let (alloc_type, value_to_store) =
                                                                match arg_type {
                                                                    IrType::I32 => {
                                                                        let ext_val = self
                                                                            .builder
                                                                            .build_cast(
                                                                                arg_reg,
                                                                                IrType::I32,
                                                                                IrType::I64,
                                                                            );
                                                                        (
                                                                            IrType::I64,
                                                                            ext_val
                                                                                .unwrap_or(arg_reg),
                                                                        )
                                                                    }
                                                                    IrType::F32 => {
                                                                        let ext_val = self
                                                                            .builder
                                                                            .build_cast(
                                                                                arg_reg,
                                                                                IrType::F32,
                                                                                IrType::F64,
                                                                            );
                                                                        (
                                                                            IrType::F64,
                                                                            ext_val
                                                                                .unwrap_or(arg_reg),
                                                                        )
                                                                    }
                                                                    _ => {
                                                                        (arg_type.clone(), arg_reg)
                                                                    }
                                                                };

                                                            // Allocate stack space and pass a pointer to the value.
                                                            if let Some(stack_slot) =
                                                                self.builder.build_alloc(
                                                                    alloc_type.clone(),
                                                                    None,
                                                                )
                                                            {
                                                                // Store the value into the stack slot
                                                                self.builder.build_store(
                                                                    stack_slot,
                                                                    value_to_store,
                                                                );
                                                                // Use the pointer for the call
                                                                final_arg_regs[i] = stack_slot;
                                                            }
                                                        }
                                                    }
                                                }

                                                // Use the function signature from the mapping (hlp_* introspection)
                                                // if available; this is the authoritative source of type info.
                                                let (expected_param_types, expected_return_type) =
                                                    self.get_extern_function_signature(
                                                        &runtime_func,
                                                    )
                                                    .unwrap_or_else(|| {
                                                        let param_types: Vec<IrType> = args
                                                            .iter()
                                                            .enumerate()
                                                            .map(|(i, arg)| {
                                                                if ptr_conversion_mask != 0
                                                                    && (ptr_conversion_mask
                                                                        & (1 << i))
                                                                        != 0
                                                                {
                                                                    IrType::Ptr(Box::new(
                                                                        IrType::U8,
                                                                    ))
                                                                } else {
                                                                    self.convert_type(arg.ty)
                                                                }
                                                            })
                                                            .collect();
                                                        (param_types, result_type.clone())
                                                    });
                                                let runtime_func_id = self
                                                    .get_or_register_extern_function(
                                                        &runtime_func,
                                                        expected_param_types,
                                                        expected_return_type.clone(),
                                                    );

                                                // Generate the call to the runtime function
                                                return self.builder.build_call_direct(
                                                    runtime_func_id,
                                                    final_arg_regs,
                                                    expected_return_type,
                                                );
                                            }
                                        }

                                        // Fallback: try each possible stdlib class (only if qualified name didn't work)
                                        // For static methods like Arc.init, Mutex.init, etc, try to infer the class from the return type
                                        // debug!("Qualified name not available, trying to infer class from return type={:?}", expr.ty);

                                        let inferred_class = {
                                            let type_table = self.type_table.borrow();
                                            debug!(
                                                "[INFER CLASS] Checking return type expr.ty={:?}",
                                                expr.ty
                                            );
                                            if let Some(type_info) = type_table.get(expr.ty) {
                                                debug!(
                                                    "[INFER CLASS] Return type kind={:?}",
                                                    type_info.kind
                                                );
                                                if let TypeKind::Class { symbol_id, .. } =
                                                    &type_info.kind
                                                {
                                                    if let Some(class_sym) =
                                                        self.symbol_table.get_symbol(*symbol_id)
                                                    {
                                                        let class_name = self
                                                            .string_interner
                                                            .get(class_sym.name);
                                                        debug!(
                                                            "[INFER CLASS] Inferred class from return type: {:?}",
                                                            class_name
                                                        );
                                                        class_name
                                                    } else {
                                                        debug!(
                                                            "[INFER CLASS] Class symbol not found"
                                                        );
                                                        None
                                                    }
                                                } else {
                                                    debug!(
                                                        "[INFER CLASS] Return type is not a class"
                                                    );
                                                    None
                                                }
                                            } else {
                                                debug!(
                                                    "[INFER CLASS] Type info not found for expr.ty={:?}",
                                                    expr.ty
                                                );
                                                None
                                            }
                                        };

                                        if let Some(class_name) = inferred_class {
                                            // SPECIAL CASE: Check if this is a stdlib MIR function
                                            if self.stdlib_mapping.is_mir_wrapper_class(class_name)
                                            {
                                                // Use lowercase class name to match stdlib MIR wrapper naming convention
                                                let mir_func_name = format!(
                                                    "{}_{}",
                                                    class_name.to_lowercase(),
                                                    method_name
                                                );
                                                debug!(
                                                    "[STDLIB MIR] Detected stdlib MIR function: {}",
                                                    mir_func_name
                                                );

                                                // Lower all arguments and collect their types
                                                let mut arg_regs = Vec::new();
                                                let mut param_types = Vec::new();
                                                for arg in static_args {
                                                    if let Some(reg) = self.lower_expression(arg) {
                                                        arg_regs.push(reg);
                                                        param_types.push(self.convert_type(arg.ty));
                                                    }
                                                }

                                                // Register forward reference - will be provided by merged stdlib module
                                                let mir_func_id = self
                                                    .register_stdlib_mir_forward_ref(
                                                        &mir_func_name,
                                                        param_types,
                                                        result_type.clone(),
                                                    );

                                                debug!(
                                                    "[STDLIB MIR] Registered forward ref to {} with ID {:?}",
                                                    mir_func_name, mir_func_id
                                                );

                                                // Generate the call
                                                let result = self.builder.build_call_direct(
                                                    mir_func_id,
                                                    arg_regs,
                                                    result_type,
                                                );
                                                debug!(
                                                    "[STDLIB MIR] Generated call, result: {:?}",
                                                    result
                                                );
                                                return result;
                                            }

                                            // Try the inferred class first
                                            let fake_qual_name = format!(
                                                "rayzor.concurrent.{}.{}",
                                                class_name, method_name
                                            );
                                            if let Some(runtime_func) = self
                                                .get_static_stdlib_runtime_func_with_params(
                                                    &fake_qual_name,
                                                    method_name,
                                                    static_args.len(),
                                                )
                                            {
                                                debug!(
                                                    "[INFERRED CLASS PATH] Got runtime_func='{}' for class={}, method={}",
                                                    runtime_func, class_name, method_name
                                                );
                                                // println!("✅ Generating runtime call to {} for {}.{} (inferred from return type)", runtime_func, class_name, method_name);

                                                // Lower all arguments
                                                let arg_regs: Vec<_> = static_args
                                                    .iter()
                                                    .filter_map(|a| self.lower_expression(a))
                                                    .collect();

                                                // Apply pointer conversion for parameters that need it (metadata-driven)
                                                // Look up the RuntimeFunctionCall metadata by runtime function name
                                                // This means the runtime function expects a POINTER TO the value, not the value directly.
                                                let mut final_arg_regs = arg_regs.clone();
                                                let ptr_conversion_mask = self
                                                    .stdlib_mapping
                                                    .find_by_runtime_name(&runtime_func)
                                                    .map(|m| m.params_need_ptr_conversion)
                                                    .unwrap_or(0);
                                                if ptr_conversion_mask != 0 {
                                                    for i in 0..arg_regs.len() {
                                                        // Check if bit i is set in the mask
                                                        if (ptr_conversion_mask & (1 << i)) != 0 {
                                                            let arg_reg = arg_regs[i];
                                                            // Default to I64 (pointer-sized) if type is unknown.
                                                            // This is safer than I32 since pointers and most values are 64-bit.
                                                            let arg_type = self
                                                                .builder
                                                                .get_register_type(arg_reg)
                                                                .unwrap_or(IrType::I64);

                                                            // For array operations, always allocate 8 bytes (elem_size is always 8)
                                                            // and extend smaller values to 64-bit
                                                            let (alloc_type, value_to_store) =
                                                                match arg_type {
                                                                    IrType::I32 => {
                                                                        let ext_val = self
                                                                            .builder
                                                                            .build_cast(
                                                                                arg_reg,
                                                                                IrType::I32,
                                                                                IrType::I64,
                                                                            );
                                                                        (
                                                                            IrType::I64,
                                                                            ext_val
                                                                                .unwrap_or(arg_reg),
                                                                        )
                                                                    }
                                                                    IrType::F32 => {
                                                                        let ext_val = self
                                                                            .builder
                                                                            .build_cast(
                                                                                arg_reg,
                                                                                IrType::F32,
                                                                                IrType::F64,
                                                                            );
                                                                        (
                                                                            IrType::F64,
                                                                            ext_val
                                                                                .unwrap_or(arg_reg),
                                                                        )
                                                                    }
                                                                    _ => {
                                                                        (arg_type.clone(), arg_reg)
                                                                    }
                                                                };

                                                            // Allocate stack space and pass a pointer to the value.
                                                            if let Some(stack_slot) =
                                                                self.builder.build_alloc(
                                                                    alloc_type.clone(),
                                                                    None,
                                                                )
                                                            {
                                                                // Store the value into the stack slot
                                                                self.builder.build_store(
                                                                    stack_slot,
                                                                    value_to_store,
                                                                );
                                                                // Use the pointer for the call
                                                                final_arg_regs[i] = stack_slot;
                                                            }
                                                        }
                                                    }
                                                }

                                                // Use the function signature from the mapping (hlp_* introspection)
                                                // if available; this is the authoritative source of type info.
                                                let (expected_param_types, expected_return_type) =
                                                    self.get_extern_function_signature(
                                                        &runtime_func,
                                                    )
                                                    .unwrap_or_else(|| {
                                                        let param_types: Vec<IrType> = args
                                                            .iter()
                                                            .enumerate()
                                                            .map(|(i, arg)| {
                                                                if ptr_conversion_mask != 0
                                                                    && (ptr_conversion_mask
                                                                        & (1 << i))
                                                                        != 0
                                                                {
                                                                    IrType::Ptr(Box::new(
                                                                        IrType::U8,
                                                                    ))
                                                                } else {
                                                                    self.convert_type(arg.ty)
                                                                }
                                                            })
                                                            .collect();
                                                        (param_types, result_type.clone())
                                                    });
                                                let runtime_func_id = self
                                                    .get_or_register_extern_function(
                                                        &runtime_func,
                                                        expected_param_types,
                                                        expected_return_type.clone(),
                                                    );

                                                // Generate the call to the runtime function
                                                return self.builder.build_call_direct(
                                                    runtime_func_id,
                                                    final_arg_regs,
                                                    expected_return_type,
                                                );
                                            }
                                        }

                                        // Last resort: try all stdlib classes with param count matching
                                        // NOTE: We must match by param count to disambiguate overloaded methods
                                        // (e.g., Array.join(sep) with 1 param vs Thread.join() with 0 params)
                                        let actual_arg_count = args.len().saturating_sub(1); // Subtract 1 for receiver (self)
                                        debug!(
                                            "[LAST RESORT] Could not infer class for method '{}' with {} args, trying all stdlib classes",
                                            method_name, actual_arg_count
                                        );
                                        // Get all stdlib classes dynamically from the mapping
                                        // NOTE: We do NOT add stdlib MIR detection here because we don't know which class
                                        // to use - the fallback tries all classes and would match the wrong one
                                        let stdlib_classes = self.stdlib_mapping.get_all_classes();
                                        for class_name in &stdlib_classes {
                                            // Use find_by_name_and_params to ensure param count matches
                                            // This prevents Array.join(1 param) from matching Thread.join(0 params)
                                            if let Some((sig, mapping)) =
                                                self.stdlib_mapping.find_by_name_and_params(
                                                    class_name,
                                                    method_name,
                                                    actual_arg_count,
                                                )
                                            {
                                                let runtime_func = mapping.runtime_name;

                                                // CHECK: Is this a MIR wrapper or an extern?
                                                if let Some((mir_param_types, mir_return_type)) =
                                                    self.get_stdlib_mir_wrapper_signature(
                                                        &runtime_func,
                                                    )
                                                {
                                                    debug!(
                                                        "[FALLBACK PATH] Detected MIR wrapper: {}",
                                                        runtime_func
                                                    );

                                                    // Lower all arguments
                                                    let mut arg_regs = Vec::new();
                                                    for arg in args {
                                                        if let Some(reg) =
                                                            self.lower_expression(arg)
                                                        {
                                                            arg_regs.push(reg);
                                                        }
                                                    }

                                                    // Register forward reference - signature comes from get_stdlib_mir_wrapper_signature
                                                    let mir_func_id = self
                                                        .register_stdlib_mir_forward_ref(
                                                            &runtime_func,
                                                            mir_param_types,
                                                            mir_return_type,
                                                        );

                                                    debug!(
                                                        "[FALLBACK PATH] Registered forward ref to {} with ID {:?}",
                                                        runtime_func, mir_func_id
                                                    );

                                                    // Generate the call
                                                    let result = self.builder.build_call_direct(
                                                        mir_func_id,
                                                        arg_regs,
                                                        result_type,
                                                    );
                                                    debug!(
                                                        "[FALLBACK PATH] Generated call, result: {:?}",
                                                        result
                                                    );
                                                    return result;
                                                }

                                                // Lower all arguments
                                                let arg_regs: Vec<_> = args
                                                    .iter()
                                                    .filter_map(|a| self.lower_expression(a))
                                                    .collect();

                                                // Apply pointer conversion for parameters that need it (metadata-driven)
                                                // Look up the RuntimeFunctionCall metadata by runtime function name
                                                // This means the runtime function expects a POINTER TO the value, not the value directly.
                                                let mut final_arg_regs = arg_regs.clone();
                                                let ptr_conversion_mask = self
                                                    .stdlib_mapping
                                                    .find_by_runtime_name(&runtime_func)
                                                    .map(|m| m.params_need_ptr_conversion)
                                                    .unwrap_or(0);
                                                if ptr_conversion_mask != 0 {
                                                    for i in 0..arg_regs.len() {
                                                        // Check if bit i is set in the mask
                                                        if (ptr_conversion_mask & (1 << i)) != 0 {
                                                            let arg_reg = arg_regs[i];
                                                            // Default to I64 (pointer-sized) if type is unknown.
                                                            // This is safer than I32 since pointers and most values are 64-bit.
                                                            let arg_type = self
                                                                .builder
                                                                .get_register_type(arg_reg)
                                                                .unwrap_or(IrType::I64);

                                                            // For array operations, always allocate 8 bytes (elem_size is always 8)
                                                            // and extend smaller values to 64-bit
                                                            let (alloc_type, value_to_store) =
                                                                match arg_type {
                                                                    IrType::I32 => {
                                                                        let ext_val = self
                                                                            .builder
                                                                            .build_cast(
                                                                                arg_reg,
                                                                                IrType::I32,
                                                                                IrType::I64,
                                                                            );
                                                                        (
                                                                            IrType::I64,
                                                                            ext_val
                                                                                .unwrap_or(arg_reg),
                                                                        )
                                                                    }
                                                                    IrType::F32 => {
                                                                        let ext_val = self
                                                                            .builder
                                                                            .build_cast(
                                                                                arg_reg,
                                                                                IrType::F32,
                                                                                IrType::F64,
                                                                            );
                                                                        (
                                                                            IrType::F64,
                                                                            ext_val
                                                                                .unwrap_or(arg_reg),
                                                                        )
                                                                    }
                                                                    _ => {
                                                                        (arg_type.clone(), arg_reg)
                                                                    }
                                                                };

                                                            // Allocate stack space and pass a pointer to the value.
                                                            if let Some(stack_slot) =
                                                                self.builder.build_alloc(
                                                                    alloc_type.clone(),
                                                                    None,
                                                                )
                                                            {
                                                                // Store the value into the stack slot
                                                                self.builder.build_store(
                                                                    stack_slot,
                                                                    value_to_store,
                                                                );
                                                                // Use the pointer for the call
                                                                final_arg_regs[i] = stack_slot;
                                                            }
                                                        }
                                                    }
                                                }

                                                // Get or register the extern runtime function
                                                // Use actual argument types from TAST, applying ptr conversion where needed
                                                let param_types: Vec<IrType> = args
                                                    .iter()
                                                    .enumerate()
                                                    .map(|(i, arg)| {
                                                        // If this param was converted to a pointer, the type is Ptr
                                                        if ptr_conversion_mask != 0
                                                            && (ptr_conversion_mask & (1 << i)) != 0
                                                        {
                                                            IrType::Ptr(Box::new(IrType::U8))
                                                        } else {
                                                            self.convert_type(arg.ty)
                                                        }
                                                    })
                                                    .collect();
                                                let runtime_func_id = self
                                                    .get_or_register_extern_function(
                                                        &runtime_func,
                                                        param_types,
                                                        result_type.clone(),
                                                    );

                                                // Generate the call to the runtime function
                                                return self.builder.build_call_direct(
                                                    runtime_func_id,
                                                    final_arg_regs,
                                                    result_type,
                                                );
                                            }
                                        }
                                    }
                                }
                            } // end of else block for receiver_is_user_class
                        } else {
                            // receiver_is_class_type == true
                            // This is an instance method call on a MIR wrapper class (Thread, Channel, etc.)
                            // Route to the MIR wrapper function (Thread_join, Channel_send, etc.)
                            let receiver_is_synthetic_class = args
                                .first()
                                .map(|arg| self.is_class_symbol_expr(arg))
                                .unwrap_or(false);
                            if !receiver_is_synthetic_class {
                                if let Some(sym_info) = self.symbol_table.get_symbol(*symbol) {
                                    if let Some(method_name) =
                                        self.string_interner.get(sym_info.name)
                                    {
                                        // Get the class name from the receiver type
                                        let class_name = {
                                            let type_table = self.type_table.borrow();
                                            type_table.get(receiver_type).and_then(|ti| {
                                                if let crate::tast::core::TypeKind::Class {
                                                    symbol_id,
                                                    ..
                                                } = &ti.kind
                                                {
                                                    self.symbol_table
                                                        .get_symbol(*symbol_id)
                                                        .and_then(|s| {
                                                            self.string_interner.get(s.name)
                                                        })
                                                        .map(|s| s.to_string())
                                                } else {
                                                    None
                                                }
                                            })
                                        };

                                        if let Some(class_name) = class_name {
                                            // Build MIR wrapper function name: Thread_join, Channel_send, etc.
                                            let mir_func_name =
                                                format!("{}_{}", class_name, method_name);
                                            debug!(
                                                "[MIR WRAPPER INSTANCE] Routing {}.{} to {}",
                                                class_name, method_name, mir_func_name
                                            );

                                            // Get the registered signature for this MIR wrapper
                                            if let Some((mir_param_types, mir_return_type)) = self
                                                .get_stdlib_mir_wrapper_signature(&mir_func_name)
                                            {
                                                let call_args = if args.len()
                                                    == mir_param_types.len() + 1
                                                    && !args.is_empty()
                                                {
                                                    &args[1..]
                                                } else {
                                                    &args[..]
                                                };
                                                // Lower all arguments (first arg is receiver/self)
                                                // Auto-box primitive args when MIR wrapper expects Ptr(U8)
                                                // (e.g., Channel<Int>.send(42) needs to box the Int)
                                                let mut arg_regs = Vec::new();
                                                for (i, arg) in call_args.iter().enumerate() {
                                                    if let Some(reg) = self.lower_expression(arg) {
                                                        let actual_ty = self.convert_type(arg.ty);
                                                        let expected_ty = mir_param_types
                                                            .get(i)
                                                            .cloned()
                                                            .unwrap_or_else(|| actual_ty.clone());

                                                        // Auto-box if MIR wrapper expects Ptr(U8) but arg is primitive
                                                        let final_reg = self
                                                            .maybe_box_for_extern_call(
                                                                reg,
                                                                &actual_ty,
                                                                &expected_ty,
                                                            )?;
                                                        arg_regs.push(final_reg);
                                                    }
                                                }

                                                // Register forward reference to MIR wrapper
                                                let mir_func_id = self
                                                    .register_stdlib_mir_forward_ref(
                                                        &mir_func_name,
                                                        mir_param_types,
                                                        mir_return_type.clone(),
                                                    );

                                                debug!(
                                                "[MIR WRAPPER INSTANCE] Registered forward ref to {} with ID {:?}",
                                                mir_func_name, mir_func_id
                                            );

                                                // Generate the call with the MIR wrapper's return type
                                                let call_result = self.builder.build_call_direct(
                                                    mir_func_id,
                                                    arg_regs,
                                                    mir_return_type.clone(),
                                                )?;

                                                // Auto-unbox if MIR wrapper returns Ptr(U8) but HIR expects primitive
                                                // (e.g., Channel<Int>.tryReceive() returns boxed int)
                                                debug!(
                                                "[MIR WRAPPER INSTANCE] call_result={:?}, mir_return_type={:?}, result_type={:?}",
                                                call_result, mir_return_type, result_type
                                            );
                                                return self.maybe_unbox_for_extern_return(
                                                    call_result,
                                                    &mir_return_type,
                                                    &result_type,
                                                );
                                            } else {
                                                debug!(
                                                "[MIR WRAPPER INSTANCE] No signature found for {}, falling through",
                                                mir_func_name
                                            );
                                            }
                                        }
                                    }
                                }
                            } else {
                                debug!(
                                    "[MIR WRAPPER INSTANCE] Skipping instance-wrapper dispatch for synthetic class receiver"
                                );
                            }
                        } // end if receiver_is_class_type else block
                    }
                    // For static methods, check if it's a stdlib static method
                    if !*is_method || self.effective_static_call_args(args).len() != args.len() {
                        if let Some(sym_info) = self.symbol_table.get_symbol(*symbol) {
                            if let Some(method_name) = self.string_interner.get(sym_info.name) {
                                let static_args = self.effective_static_call_args(args);
                                debug!(
                                    "[STATIC-PATH] method_name='{}', symbol={:?}, has_qualified_name={}",
                                    method_name,
                                    symbol,
                                    sym_info.qualified_name.is_some()
                                );

                                // Try to get the qualified name to determine the class
                                if let Some(qual_name) = sym_info.qualified_name {
                                    if let Some(qual_name_str) = self.string_interner.get(qual_name)
                                    {
                                        debug!("[PRE-CHECK] Qualified name: '{}'", qual_name_str);

                                        // SPECIAL CASE: Thread/Channel/Mutex/Arc methods are MIR wrappers, not runtime_mapping
                                        // These are implemented in stdlib MIR (thread.rs, channel.rs, etc.)
                                        // Pattern: "rayzor.concurrent.Thread.spawn" -> "Thread_spawn"
                                        // NOTE: This only applies to rayzor.concurrent.*, NOT sys.thread.*
                                        let parts: Vec<&str> = qual_name_str.split('.').collect();
                                        if parts.len() >= 2 {
                                            let class_name = parts[parts.len() - 2];

                                            // Check if this is a rayzor.concurrent.* class (NOT sys.thread.*)
                                            // sys.thread.Thread uses runtime mapping directly, not MIR wrappers
                                            // Use dynamic check via stdlib_mapping instead of hardcoded list
                                            let is_rayzor_concurrent =
                                                qual_name_str.starts_with("rayzor.concurrent.");
                                            if is_rayzor_concurrent
                                                && self
                                                    .stdlib_mapping
                                                    .is_mir_wrapper_class(class_name)
                                            {
                                                // Use capitalized class names for rayzor.concurrent (Thread, Channel, etc.)
                                                let mir_func_name =
                                                    format!("{}_{}", class_name, method_name);
                                                debug!(
                                                    "[STDLIB MIR] Detected stdlib MIR function: {}, args.len()={}",
                                                    mir_func_name,
                                                    static_args.len()
                                                );
                                                for (idx, arg) in static_args.iter().enumerate() {
                                                    debug!(
                                                        "[STDLIB MIR PRE] arg[{}] kind={:?}, ty={:?}",
                                                        idx,
                                                        std::mem::discriminant(&arg.kind),
                                                        arg.ty
                                                    );
                                                }

                                                // WORKAROUND: static calls may carry a synthetic
                                                // class receiver argument. Prefer the mapping
                                                // signature arity to trim that argument.
                                                let mut actual_args = static_args;
                                                if let Some((expected_params, _)) = self
                                                    .get_stdlib_mir_wrapper_signature(
                                                        &mir_func_name,
                                                    )
                                                {
                                                    if actual_args.len() != expected_params.len()
                                                        && static_args.len()
                                                            == expected_params.len() + 1
                                                        && !static_args.is_empty()
                                                    {
                                                        debug!(
                                                            "[STDLIB MIR FIX] Arity-based static receiver trim for {}: {} -> {} args",
                                                            mir_func_name,
                                                            static_args.len(),
                                                            expected_params.len()
                                                        );
                                                        actual_args = &static_args[1..];
                                                    }
                                                }

                                                // Lower all arguments and collect their types
                                                let mut arg_regs = Vec::new();
                                                let mut param_types = Vec::new();
                                                for (idx, arg) in actual_args.iter().enumerate() {
                                                    debug!(
                                                        "[STDLIB MIR] arg[{}] ty={:?}",
                                                        idx, arg.ty
                                                    );
                                                    if let Some(reg) = self.lower_expression(arg) {
                                                        arg_regs.push(reg);
                                                        param_types.push(self.convert_type(arg.ty));
                                                    }
                                                }
                                                if mir_func_name == "Thread_sleep" {
                                                    eprintln!(
                                                        "[DBG STATIC MIR Thread_sleep] args_len={} static_args_len={} actual_args_len={}",
                                                        args.len(),
                                                        static_args.len(),
                                                        actual_args.len()
                                                    );
                                                }

                                                // Register forward reference - will be provided by merged stdlib module
                                                // We infer the signature from the call site arguments
                                                let mir_func_id = self
                                                    .register_stdlib_mir_forward_ref(
                                                        &mir_func_name,
                                                        param_types,
                                                        result_type.clone(),
                                                    );

                                                debug!(
                                                    "[STDLIB MIR] Registered forward ref to {} with ID {:?}",
                                                    mir_func_name, mir_func_id
                                                );

                                                // Generate the call
                                                let result = self.builder.build_call_direct(
                                                    mir_func_id,
                                                    arg_regs,
                                                    result_type,
                                                );
                                                debug!(
                                                    "[STDLIB MIR] Generated call, result: {:?}",
                                                    result
                                                );
                                                return result;
                                            }
                                        }

                                        // Check if this is a stdlib class method by looking at qualified name
                                        // e.g., "rayzor.concurrent.Thread.spawn" or "test.Thread.spawn"
                                        let lookup_result = self
                                            .get_static_stdlib_runtime_func_with_params(
                                                qual_name_str,
                                                method_name,
                                                static_args.len(),
                                            );
                                        debug!(
                                            "[PRE-CHECK] get_static_stdlib_runtime_func returned: {:?}",
                                            lookup_result
                                        );

                                        if let Some(runtime_func) = lookup_result {
                                            debug!(
                                                "[STATIC METHOD] Found stdlib runtime func: {}.{} -> {}, args.len()={}",
                                                qual_name_str,
                                                method_name,
                                                runtime_func,
                                                static_args.len()
                                            );

                                            if let Some(result) = self
                                                .try_lower_special_runtime_call(
                                                    &runtime_func,
                                                    static_args,
                                                    result_type.clone(),
                                                    expr.source_location.clone(),
                                                )
                                            {
                                                return result;
                                            }

                                            // Get the expected signature from our registered extern functions
                                            // This ensures we use the correct types (e.g., I64 for Std.random)
                                            let (expected_param_types, expected_return_type) = self
                                                .get_extern_function_signature(&runtime_func)
                                                .unwrap_or_else(|| {
                                                    // Fall back to inferred types from TAST
                                                    let string_ptr_ty =
                                                        IrType::Ptr(Box::new(IrType::String));
                                                    let param_types: Vec<IrType> = static_args
                                                        .iter()
                                                        .map(|a| {
                                                            let arg_ty = self.convert_type(a.ty);
                                                            if arg_ty == IrType::String {
                                                                string_ptr_ty.clone()
                                                            } else {
                                                                arg_ty
                                                            }
                                                        })
                                                        .collect();
                                                    (param_types, result_type.clone())
                                                });

                                            let runtime_call_args = if static_args.len()
                                                == expected_param_types.len() + 1
                                                && !static_args.is_empty()
                                            {
                                                &static_args[1..]
                                            } else {
                                                static_args
                                            };

                                            // Lower all arguments
                                            let arg_regs: Vec<_> = runtime_call_args
                                                .iter()
                                                .filter_map(|a| self.lower_expression(a))
                                                .collect();

                                            debug!(
                                                "[STATIC METHOD] Lowered {} args: {:?}",
                                                arg_regs.len(),
                                                arg_regs
                                            );

                                            // Cast/box arguments to expected types if needed
                                            let final_arg_regs: Vec<_> = arg_regs.iter().enumerate()
                                                .map(|(i, &reg)| {
                                                    if let (Some(expected_ty), Some(actual_ty)) = (
                                                        expected_param_types.get(i),
                                                        self.builder.get_register_type(reg)
                                                    ) {
                                                        // If types differ, insert a cast or box
                                                        if *expected_ty != actual_ty {
                                                            // When expected is Ptr(U8) (Dynamic/boxed), auto-box the value
                                                            let is_ptr_u8 = matches!(expected_ty, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::U8));
                                                            if is_ptr_u8 && i < runtime_call_args.len() {
                                                                debug!("[STATIC METHOD BOX] Attempting auto-box for arg {} with type {:?}", i, runtime_call_args[i].ty);
                                                                // Use box_value_for_dynamic to properly box based on HIR type
                                                                if let Some(boxed) = self.box_value_for_dynamic(reg, runtime_call_args[i].ty) {
                                                                    debug!("[STATIC METHOD BOX] Auto-boxed arg {} for Dynamic param", i);
                                                                    return boxed;
                                                                }
                                                                debug!("[STATIC METHOD BOX] box_value_for_dynamic returned None for arg {}", i);
                                                            }
                                                            debug!("[STATIC METHOD] Casting arg {} from {:?} to {:?}", i, actual_ty, expected_ty);
                                                            if let Some(casted) = self.builder.build_cast(reg, actual_ty.clone(), expected_ty.clone()) {
                                                                return casted;
                                                            }
                                                        }
                                                    }
                                                    reg
                                                })
                                                .collect();

                                            // Inject hidden enum type_id for enum helper runtime calls.
                                            let mut final_arg_regs = final_arg_regs;
                                            self.inject_hidden_enum_type_id_arg(
                                                &runtime_func,
                                                runtime_call_args,
                                                &mut final_arg_regs,
                                            );

                                            let runtime_func_id = self
                                                .get_or_register_extern_function(
                                                    &runtime_func,
                                                    expected_param_types,
                                                    expected_return_type.clone(),
                                                );

                                            debug!(
                                                "[STATIC METHOD] Registered runtime func {} with ID {:?}",
                                                runtime_func, runtime_func_id
                                            );

                                            // Generate the call to the runtime function
                                            let result = self.builder.build_call_direct(
                                                runtime_func_id,
                                                final_arg_regs,
                                                expected_return_type,
                                            );
                                            if runtime_func == "Thread_sleep" {
                                                eprintln!(
                                                    "[DBG STATIC RUNTIME Thread_sleep] args_len={} static_args_len={} final_args={}",
                                                    args.len(),
                                                    static_args.len(),
                                                    result.as_ref().map(|_| 0).unwrap_or(0)
                                                );
                                            }
                                            debug!(
                                                "[STATIC METHOD] Generated call, result: {:?}",
                                                result
                                            );
                                            return result;
                                        }
                                    }
                                }

                                // Fallback: still inside method_name scope.
                                // If qualified_name is not set (e.g., Reflect.compare from import files),
                                // try to find a matching static stdlib method by scanning all known classes.
                                // Only match static methods to avoid false positives.
                                // If qualified_name is available, prefer class-qualified lookup
                                // before doing a global static-name fallback.
                                let mut static_fallback = None;
                                if let Some(qual_name_str) = sym_info
                                    .qualified_name
                                    .and_then(|q| self.string_interner.get(q))
                                {
                                    let parts: Vec<&str> = qual_name_str.split('.').collect();
                                    if parts.len() >= 2 {
                                        let mut class_candidates: Vec<String> = Vec::new();
                                        // Fully-qualified class form used in runtime mapping
                                        class_candidates.push(parts[..parts.len() - 1].join("_"));
                                        // Simple class name fallback
                                        class_candidates.push(parts[parts.len() - 2].to_string());

                                        for class_name in class_candidates {
                                            if let Some(found) =
                                                self.stdlib_mapping.find_by_name_and_params(
                                                    &class_name,
                                                    method_name,
                                                    static_args.len(),
                                                )
                                            {
                                                static_fallback = Some(found);
                                                break;
                                            }
                                        }
                                    }
                                }

                                if static_fallback.is_none() {
                                    debug!(
                                        "[STATIC-FALLBACK] Trying global find_static_method_by_name_and_params('{}', {})...",
                                        method_name,
                                        static_args.len()
                                    );
                                    static_fallback =
                                        self.stdlib_mapping.find_static_method_by_name_and_params(
                                            method_name,
                                            static_args.len(),
                                        );
                                }

                                if let Some((_sig, mapping)) = static_fallback {
                                    let runtime_func_name = mapping.runtime_name.to_string();
                                    debug!(
                                        "[STATIC FALLBACK] Found static {}.{} -> {} via name scan",
                                        _sig.class, method_name, runtime_func_name
                                    );

                                    if let Some(result) = self.try_lower_special_runtime_call(
                                        &runtime_func_name,
                                        static_args,
                                        result_type.clone(),
                                        expr.source_location.clone(),
                                    ) {
                                        return result;
                                    }

                                    // Lower all arguments first
                                    let mut arg_regs: Vec<IrId> = Vec::new();
                                    let mut arg_types: Vec<IrType> = Vec::new();
                                    for arg in static_args.iter() {
                                        if let Some(reg) = self.lower_expression(arg) {
                                            arg_regs.push(reg);
                                            arg_types.push(self.convert_type(arg.ty));
                                        }
                                    }

                                    // Special case: Reflect.compare → haxe_reflect_compare_typed
                                    // Same logic as the qualified-name path: detect argument type and
                                    // append a type_tag parameter to avoid boxing.
                                    if runtime_func_name == "haxe_reflect_compare" {
                                        let mut known_type_tag: Option<i32> = None;
                                        let mut type_param_name: Option<String> = None;
                                        let mut use_typed = false;

                                        if let Some(first_arg) = static_args.first() {
                                            let type_table = self.type_table.borrow();
                                            if let Some(ti) = type_table.get(first_arg.ty) {
                                                use crate::tast::core::TypeKind;
                                                match &ti.kind {
                                                    TypeKind::TypeParameter {
                                                        symbol_id, ..
                                                    } => {
                                                        use_typed = true;
                                                        if let Some(sym) =
                                                            self.symbol_table.get_symbol(*symbol_id)
                                                        {
                                                            if let Some(name_str) =
                                                                self.string_interner.get(sym.name)
                                                            {
                                                                type_param_name =
                                                                    Some(name_str.to_string());
                                                            }
                                                        }
                                                    }
                                                    TypeKind::Int => {
                                                        use_typed = true;
                                                        known_type_tag = Some(1);
                                                    }
                                                    TypeKind::Float => {
                                                        use_typed = true;
                                                        known_type_tag = Some(4);
                                                    }
                                                    TypeKind::Bool => {
                                                        use_typed = true;
                                                        known_type_tag = Some(2);
                                                    }
                                                    TypeKind::String => {
                                                        use_typed = true;
                                                        known_type_tag = Some(5);
                                                    }
                                                    _ => {}
                                                }
                                            }
                                        }

                                        if use_typed {
                                            // Cast value args to I64 — haxe_reflect_compare_typed
                                            // takes type-erased i64 values, not typed structs
                                            for i in 0..arg_regs.len().min(2) {
                                                let reg_ty = self
                                                    .builder
                                                    .get_register_type(arg_regs[i])
                                                    .unwrap_or(IrType::I64);
                                                if reg_ty != IrType::I64 {
                                                    if let Some(cast) = self.builder.build_cast(
                                                        arg_regs[i],
                                                        reg_ty,
                                                        IrType::I64,
                                                    ) {
                                                        arg_regs[i] = cast;
                                                    }
                                                }
                                                arg_types[i] = IrType::I64;
                                            }

                                            let tag_reg = if let Some(tp_name) = type_param_name {
                                                let tag =
                                                    self.builder.build_const(IrValue::I32(0))?;
                                                if let Some(func) =
                                                    self.builder.current_function_mut()
                                                {
                                                    func.type_param_tag_fixups.push((tag, tp_name));
                                                }
                                                tag
                                            } else {
                                                self.builder.build_const(IrValue::I32(
                                                    known_type_tag.unwrap_or(1),
                                                ))?
                                            };
                                            arg_regs.push(tag_reg);
                                            arg_types.push(IrType::I32);

                                            let extern_func_id = self
                                                .get_or_register_extern_function(
                                                    "haxe_reflect_compare_typed",
                                                    arg_types,
                                                    result_type.clone(),
                                                );
                                            return self.builder.build_call_direct(
                                                extern_func_id,
                                                arg_regs,
                                                result_type,
                                            );
                                        }
                                    }

                                    // General case: call the runtime function directly
                                    let (expected_param_types, expected_return_type) = self
                                        .get_extern_function_signature(&runtime_func_name)
                                        .unwrap_or_else(|| (arg_types, result_type.clone()));

                                    let final_arg_regs: Vec<_> = arg_regs
                                        .iter()
                                        .enumerate()
                                        .map(|(i, &reg)| {
                                            if let (Some(expected_ty), Some(actual_ty)) = (
                                                expected_param_types.get(i),
                                                self.builder.get_register_type(reg),
                                            ) {
                                                if *expected_ty != actual_ty {
                                                    if let Some(casted) = self.builder.build_cast(
                                                        reg,
                                                        actual_ty.clone(),
                                                        expected_ty.clone(),
                                                    ) {
                                                        return casted;
                                                    }
                                                }
                                            }
                                            reg
                                        })
                                        .collect();

                                    // Inject hidden enum type_id for enum helper runtime calls.
                                    let mut final_arg_regs = final_arg_regs;
                                    self.inject_hidden_enum_type_id_arg(
                                        &runtime_func_name,
                                        args,
                                        &mut final_arg_regs,
                                    );

                                    let runtime_func_id = self.get_or_register_extern_function(
                                        &runtime_func_name,
                                        expected_param_types,
                                        expected_return_type.clone(),
                                    );

                                    return self.builder.build_call_direct(
                                        runtime_func_id,
                                        final_arg_regs,
                                        expected_return_type,
                                    );
                                }
                            } // end of if let Some(method_name)
                        }
                    }

                    // Check if this symbol is a function (local or external)
                    // First try direct symbol ID lookup
                    let method_name_interned =
                        self.symbol_table.get_symbol(*symbol).map(|s| s.name);
                    let mut func_id_opt = self.get_function_id(symbol);
                    let has_synthetic_static_receiver =
                        *is_method && self.effective_static_call_args(args).len() != args.len();

                    if func_id_opt.is_none()
                        && *is_method
                        && !has_synthetic_static_receiver
                        && !args.is_empty()
                    {
                        if let Some(method_name) = method_name_interned {
                            func_id_opt = self.resolve_method_function_id(args[0].ty, method_name);
                        }
                    }

                    // If not found by symbol ID, try lookup by qualified name
                    // This handles cross-module calls where symbol IDs differ between modules,
                    // and also intra-module static method calls where the call site symbol
                    // differs from the method definition symbol (e.g., Body.Sun() in nbody)
                    if func_id_opt.is_none() {
                        if let Some(sym_info) = self.symbol_table.get_symbol(*symbol) {
                            if let Some(qual_name) = sym_info.qualified_name {
                                if let Some(qual_name_str) = self.string_interner.get(qual_name) {
                                    // Search local function_map by qualified name first
                                    for (local_sym, &local_func_id) in &self.function_map {
                                        if let Some(local_sym_info) =
                                            self.symbol_table.get_symbol(*local_sym)
                                        {
                                            if let Some(local_qual) = local_sym_info.qualified_name
                                            {
                                                if let Some(local_qual_str) =
                                                    self.string_interner.get(local_qual)
                                                {
                                                    if local_qual_str == qual_name_str {
                                                        debug!(
                                                            "[QUAL-NAME LOCAL] Found function by qualified name '{}': symbol {:?} -> func_id={:?}",
                                                            qual_name_str, local_sym, local_func_id
                                                        );
                                                        func_id_opt = Some(local_func_id);
                                                        break;
                                                    }
                                                }
                                            }
                                        }
                                    }

                                    // If not found locally, search external_function_map
                                    if func_id_opt.is_none() {
                                        for (ext_sym, &ext_func_id) in &self.external_function_map {
                                            if let Some(ext_sym_info) =
                                                self.symbol_table.get_symbol(*ext_sym)
                                            {
                                                if let Some(ext_qual) = ext_sym_info.qualified_name
                                                {
                                                    if let Some(ext_qual_str) =
                                                        self.string_interner.get(ext_qual)
                                                    {
                                                        if ext_qual_str == qual_name_str {
                                                            debug!(
                                                                "[CROSS-MODULE] Found function by qualified name '{}': symbol {:?} -> func_id={:?}",
                                                                qual_name_str, ext_sym, ext_func_id
                                                            );
                                                            func_id_opt = Some(ext_func_id);
                                                            break;
                                                        }
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }
                            } else {
                                // Call-site symbol has no qualified name (common for cross-class
                                // static method calls in multi-class files, e.g., Body.Jupiter()).
                                // Fall back to searching function_map by bare name.
                                if let Some(func_name) = self.string_interner.get(sym_info.name) {
                                    for (func_sym, &func_id) in &self.function_map {
                                        if *func_sym == *symbol {
                                            continue;
                                        }
                                        if let Some(func_sym_info) =
                                            self.symbol_table.get_symbol(*func_sym)
                                        {
                                            if let Some(fm_name) =
                                                self.string_interner.get(func_sym_info.name)
                                            {
                                                if fm_name == func_name {
                                                    debug!(
                                                        "[BARE-NAME LOCAL] Found function by bare name '{}': sym {:?} -> func_id={:?}",
                                                        func_name, func_sym, func_id
                                                    );
                                                    func_id_opt = Some(func_id);
                                                    break;
                                                }
                                            }
                                        }
                                    }
                                    // NOTE: Removed bare-name search in external_function_map.
                                    // Bare-name matching across modules causes false positives
                                    // (e.g., ListNode.create() -> rayzor_tcc_create).
                                    // Cross-module calls must use qualified name matching.
                                }
                            }
                        }
                    }

                    // If still not found, try lookup by function name in function_map
                    // This handles cases where method calls use different symbol IDs than the definition
                    // (e.g., chained method calls like z.mul(z).add(c) where add has a different symbol)
                    //
                    // IMPORTANT: When matching by bare name, also verify the function belongs to
                    // the receiver's class (via qualified name). Without this, common names like
                    // "get", "set", "toString" could match wrong stdlib functions.
                    if func_id_opt.is_none() && *is_method && !has_synthetic_static_receiver {
                        if let Some(sym_info) = self.symbol_table.get_symbol(*symbol) {
                            if let Some(method_name) = self.string_interner.get(sym_info.name) {
                                debug!(
                                    "[NAME-FALLBACK] Searching for method '{}' sym={:?}",
                                    method_name, symbol
                                );
                                // Get receiver's class name for disambiguation
                                let receiver_class_name = if !args.is_empty() {
                                    let type_table = self.type_table.borrow();
                                    let class_sym =
                                        type_table.get(args[0].ty).and_then(|ti| match &ti.kind {
                                            TypeKind::Class { symbol_id, .. } => Some(*symbol_id),
                                            TypeKind::GenericInstance { base_type, .. } => {
                                                type_table.get(*base_type).and_then(|bt| match &bt
                                                    .kind
                                                {
                                                    TypeKind::Class { symbol_id, .. } => {
                                                        Some(*symbol_id)
                                                    }
                                                    _ => None,
                                                })
                                            }
                                            _ => None,
                                        });
                                    let name = class_sym.and_then(|sid| {
                                        self.symbol_table
                                            .get_symbol(sid)
                                            .and_then(|s| self.string_interner.get(s.name))
                                            .map(|s| s.to_string())
                                    });
                                    drop(type_table);
                                    name
                                } else {
                                    None
                                };

                                debug!(
                                    "[NAME-FALLBACK] receiver_class_name={:?}",
                                    receiver_class_name
                                );
                                // Search function_map by name, preferring qualified name match
                                // Pass 1: strict class name matching
                                for (func_sym, &func_id) in &self.function_map {
                                    if let Some(func_sym_info) =
                                        self.symbol_table.get_symbol(*func_sym)
                                    {
                                        if let Some(func_name) =
                                            self.string_interner.get(func_sym_info.name)
                                        {
                                            if func_name == method_name {
                                                // If we know the receiver class, verify via qualified name
                                                if let Some(ref class_name) = receiver_class_name {
                                                    let qual_match = func_sym_info
                                                        .qualified_name
                                                        .and_then(|qn| self.string_interner.get(qn))
                                                        .map(|qn| qn.contains(class_name.as_str()))
                                                        .unwrap_or(false);
                                                    if !qual_match {
                                                        continue; // Skip — wrong class
                                                    }
                                                }
                                                debug!(
                                                    "[NAME FALLBACK] Found method '{}' by name: {:?} -> {:?}",
                                                    method_name, func_sym, func_id
                                                );
                                                func_id_opt = Some(func_id);
                                                break;
                                            }
                                        }
                                    }
                                }

                                // NOTE: Removed bare-name Pass 2 search in external_function_map.
                                // Bare-name matching across modules causes false positives.
                                // Inherited method dispatch should use class hierarchy resolution instead.
                            }
                        }
                    }

                    // Guard against short-name symbol collisions for static calls:
                    // if the resolved function signature arity does not match this call site,
                    // drop it so static runtime fallback can re-resolve by (name, arity).
                    if func_id_opt.is_some() && (!*is_method || has_synthetic_static_receiver) {
                        let static_arg_count = self.effective_static_call_args(args).len();
                        if let Some(func_id) = func_id_opt {
                            let expected_params_opt = self
                                .builder
                                .module
                                .functions
                                .get(&func_id)
                                .map(|func| func.signature.parameters.len())
                                .or_else(|| {
                                    self.symbol_table.get_symbol(*symbol).and_then(|sym| {
                                        let type_table = self.type_table.borrow();
                                        type_table.get(sym.type_id).and_then(|ti| {
                                            if let TypeKind::Function { params, .. } = &ti.kind {
                                                Some(params.len())
                                            } else {
                                                None
                                            }
                                        })
                                    })
                                });

                            if let Some(expected_params) = expected_params_opt {
                                if expected_params != static_arg_count {
                                    debug!(
                                        "[STATIC ARITY MISMATCH] symbol={:?} resolved func_id={:?} expected_params={} call_args={} -> fallback",
                                        symbol, func_id, expected_params, static_arg_count
                                    );
                                    func_id_opt = None;
                                }
                            }
                        }
                    }

                    // Fallback for extern class static methods (e.g. NativeStackTrace.exceptionStack()).
                    // StaticFieldAccess becomes Variable in HIR, bypassing the Field-callee stdlib
                    // dispatch. Prefer symbol qualified_name, then class-less name fallback.
                    if func_id_opt.is_none() {
                        if let Some(sym_info) = self.symbol_table.get_symbol(*symbol) {
                            if let Some(method_name) = self.string_interner.get(sym_info.name) {
                                let static_args = self.effective_static_call_args(args);
                                let mut runtime_func_name: Option<String> = None;

                                // Prefer class-qualified dispatch if present on the symbol.
                                if let Some(qual_name_str) = sym_info
                                    .qualified_name
                                    .and_then(|qn| self.string_interner.get(qn))
                                {
                                    if let Some(found) = self
                                        .get_static_stdlib_runtime_func_with_params(
                                            qual_name_str,
                                            method_name,
                                            static_args.len(),
                                        )
                                    {
                                        runtime_func_name = Some(found.to_string());
                                    }
                                }

                                // True last resort: class-less static method lookup.
                                if runtime_func_name.is_none() {
                                    if let Some((_sig, mapping)) =
                                        self.stdlib_mapping.find_static_method_by_name_and_params(
                                            method_name,
                                            static_args.len(),
                                        )
                                    {
                                        runtime_func_name = Some(mapping.runtime_name.to_string());
                                    }
                                }

                                if let Some(runtime_func_name) = runtime_func_name {
                                    let mut arg_regs: Vec<IrId> = Vec::new();
                                    let mut arg_types: Vec<IrType> = Vec::new();
                                    for arg in static_args.iter() {
                                        if let Some(reg) = self.lower_expression(arg) {
                                            arg_regs.push(reg);
                                            arg_types.push(self.convert_type(arg.ty));
                                        }
                                    }
                                    let (expected_param_types, expected_return_type) = self
                                        .get_extern_function_signature(&runtime_func_name)
                                        .unwrap_or_else(|| (arg_types, result_type.clone()));
                                    let runtime_func_id = self.get_or_register_extern_function(
                                        &runtime_func_name,
                                        expected_param_types,
                                        expected_return_type.clone(),
                                    );
                                    return self.builder.build_call_direct(
                                        runtime_func_id,
                                        arg_regs,
                                        expected_return_type,
                                    );
                                }
                            }
                        }
                    }

                    if let Some(func_id) = func_id_opt {
                        let sym_name = self
                            .symbol_table
                            .get_symbol(*symbol)
                            .and_then(|s| self.string_interner.get(s.name))
                            .unwrap_or("<unknown>");
                        self.builder.call_label = Some(format!("FUNC_MAP:{}", sym_name));
                        let qual_name = self
                            .symbol_table
                            .get_symbol(*symbol)
                            .and_then(|s| s.qualified_name)
                            .and_then(|qn| self.string_interner.get(qn))
                            .unwrap_or("<none>");
                        let is_external = self.external_function_map.contains_key(symbol);

                        debug!(
                            "[FUNCTION_MAP LOOKUP] Found symbol {:?} '{}' (qual: '{}') -> func_id={:?}, is_method={}, external={}",
                            symbol, sym_name, qual_name, func_id, is_method, is_external
                        );

                        // IMPORTANT: Use the function's actual return type, not expr.ty
                        // Check both functions (local) and extern_functions (forward refs to stdlib)
                        let actual_return_type = if let Some(func) =
                            self.builder.module.functions.get(&func_id)
                        {
                            debug!(
                                "[FUNCTION_MAP] Using actual return type {:?} for function {:?}",
                                func.signature.return_type, func.name
                            );
                            func.signature.return_type.clone()
                        } else if let Some(func) =
                            self.builder.module.extern_functions.get(&func_id)
                        {
                            debug!(
                                "[FUNCTION_MAP] Using extern_functions return type {:?} for {:?}",
                                func.signature.return_type, func_id
                            );
                            func.signature.return_type.clone()
                        } else {
                            // Function not in module yet (probably forward ref to stdlib MIR wrapper)
                            // Try to look up the correct signature by function name
                            debug!(
                                "[FUNCTION_MAP] Function {:?} not found in module, checking stdlib signatures",
                                func_id
                            );
                            if let Some((_params, ret_ty)) =
                                self.get_stdlib_mir_wrapper_signature(&sym_name)
                            {
                                debug!(
                                    "[FUNCTION_MAP] Found stdlib signature for '{}': returns {:?}",
                                    sym_name, ret_ty
                                );
                                ret_ty
                            } else {
                                debug!(
                                    "[FUNCTION_MAP] No stdlib signature found, using expr return type {:?}",
                                    result_type
                                );
                                result_type.clone()
                            }
                        };
                        let function_param_count = self
                            .builder
                            .module
                            .functions
                            .get(&func_id)
                            .map(|f| f.signature.parameters.len())
                            .or_else(|| {
                                self.builder
                                    .module
                                    .extern_functions
                                    .get(&func_id)
                                    .map(|f| f.signature.parameters.len())
                            });
                        let has_arity_static_receiver = *is_method
                            && function_param_count
                                .map(|param_count| args.len() == param_count + 1)
                                .unwrap_or(false);
                        let treat_as_static_call =
                            has_synthetic_static_receiver || has_arity_static_receiver;
                        if self
                            .builder
                            .module
                            .functions
                            .get(&func_id)
                            .map(|f| f.name == "Thread_sleep")
                            .unwrap_or(false)
                        {
                            eprintln!(
                                "[DBG Thread_sleep] is_method={} has_synth={} has_arity={} treat_static={} args_len={} param_count={:?}",
                                is_method,
                                has_synthetic_static_receiver,
                                has_arity_static_receiver,
                                treat_as_static_call,
                                args.len(),
                                function_param_count
                            );
                        }
                        if has_arity_static_receiver {
                            debug!(
                                "[STATIC-RECEIVER ARITY] Treating method call as static: symbol={:?}, func_id={:?}, args={}, params={:?}",
                                symbol,
                                func_id,
                                args.len(),
                                function_param_count
                            );
                        }

                        // Handle method calls where the object is passed as first argument
                        if *is_method && !treat_as_static_call {
                            // For method calls, args already includes the object as first arg.
                            // Track non-receiver args as temps ONLY if the callee is user-defined.
                            // Stdlib/runtime methods (e.g., Array.push) may store arguments.
                            let callee_is_user_defined = self
                                .builder
                                .module
                                .functions
                                .get(&func_id)
                                .map(|f| f.kind == crate::ir::functions::FunctionKind::UserDefined)
                                .unwrap_or(false);

                            let mut arg_regs = Vec::new();

                            // Check if receiver (args[0]) is Dynamic-typed — needs unboxing
                            let receiver_is_dynamic = if !args.is_empty() {
                                let type_table = self.type_table.borrow();
                                type_table
                                    .get(args[0].ty)
                                    .map(|t| matches!(t.kind, TypeKind::Dynamic))
                                    .unwrap_or(false)
                            } else {
                                false
                            };

                            for (i, arg) in args.iter().enumerate() {
                                if let Some(reg) = self.lower_expression(arg) {
                                    // Materialize anon-backed variables at call boundary (skip receiver)
                                    // For method calls, args[0] is receiver, args[1..] are params
                                    // HIR param_types don't include `this`, so param_index = i - 1
                                    let reg = if i > 0 {
                                        self.maybe_materialize_for_call(
                                            arg,
                                            reg,
                                            Some(func_id),
                                            i - 1,
                                        )
                                    } else {
                                        reg
                                    };
                                    if i == 0 && receiver_is_dynamic && callee_is_user_defined {
                                        // Dynamic receiver: unbox DynamicValue* to get raw object pointer
                                        let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                                        let unbox_func_id = self.get_or_register_extern_function(
                                            "haxe_unbox_reference_ptr",
                                            vec![ptr_u8.clone()],
                                            ptr_u8.clone(),
                                        );
                                        if let Some(unboxed) = self.builder.build_call_direct(
                                            unbox_func_id,
                                            vec![reg],
                                            ptr_u8,
                                        ) {
                                            arg_regs.push(unboxed);
                                        } else {
                                            arg_regs.push(reg);
                                        }
                                    } else {
                                        // @:derive(Copy): copy variable args at call boundary
                                        let reg = if i > 0 {
                                            if let HirExprKind::Variable { .. } = &arg.kind {
                                                if let Some(class_sym) =
                                                    self.get_copy_class_symbol(arg.ty)
                                                {
                                                    self.emit_shallow_copy(reg, class_sym)
                                                        .unwrap_or(reg)
                                                } else {
                                                    reg
                                                }
                                            } else {
                                                reg
                                            }
                                        } else {
                                            reg
                                        };
                                        if i > 0 && callee_is_user_defined {
                                            let is_heap_intermediate = matches!(
                                                &arg.kind,
                                                HirExprKind::New { .. } | HirExprKind::Call { .. }
                                            ) && self
                                                .get_drop_behavior(arg.ty)
                                                == DropBehavior::AutoDrop;
                                            if is_heap_intermediate {
                                                self.temp_heap_values.push(reg);
                                            }
                                        }
                                        arg_regs.push(reg);
                                    }
                                }
                            }

                            // Fill in default values for any missing optional parameters
                            self.fill_default_args(func_id, &mut arg_regs, true);

                            // Extract type_args for generic method calls.
                            // Priority: 1) HIR type_args, 2) class type_args, 3) infer from args
                            let ir_type_args = if !converted_hir_type_args.is_empty() {
                                // Method-level type args from HIR (e.g., explicitly specified)
                                converted_hir_type_args.clone()
                            } else if !args.is_empty() {
                                let receiver_type = args[0].ty;
                                let class_type_args = {
                                    let type_table = self.type_table.borrow();
                                    if let Some(receiver_info) = type_table.get(receiver_type) {
                                        if let crate::tast::TypeKind::Class { type_args, .. } =
                                            &receiver_info.kind
                                        {
                                            type_args.clone()
                                        } else {
                                            Vec::new()
                                        }
                                    } else {
                                        Vec::new()
                                    }
                                };
                                if !class_type_args.is_empty() {
                                    class_type_args
                                        .iter()
                                        .map(|&ty_id| self.convert_type(ty_id))
                                        .collect::<Vec<_>>()
                                } else {
                                    // Infer method's own type params from argument types
                                    // (e.g., add<T>(x:T) called with String → T=String)
                                    if let Some(func) = self.builder.module.functions.get(&func_id)
                                    {
                                        if !func.signature.type_params.is_empty() {
                                            let mut inferred: Vec<IrType> = Vec::new();
                                            for type_param in &func.signature.type_params {
                                                let mut found = false;
                                                for (i, sig_param) in
                                                    func.signature.parameters.iter().enumerate()
                                                {
                                                    if let IrType::TypeVar(ref name) = sig_param.ty
                                                    {
                                                        if name == &type_param.name
                                                            && i < args.len()
                                                        {
                                                            let arg_type =
                                                                self.convert_type(args[i].ty);
                                                            inferred.push(arg_type);
                                                            found = true;
                                                            break;
                                                        }
                                                    }
                                                }
                                                if !found
                                                    && func.signature.type_params.len() == 1
                                                    && args.len() > 1
                                                {
                                                    // Single type param, infer from first non-this arg
                                                    let arg_type = self.convert_type(args[1].ty);
                                                    inferred.push(arg_type);
                                                }
                                            }
                                            inferred
                                        } else {
                                            Vec::new()
                                        }
                                    } else {
                                        Vec::new()
                                    }
                                }
                            } else {
                                Vec::new()
                            };

                            debug!(
                                "[FUNCTION_MAP] Method call lowered {} args: {:?}, type_args: {:?}",
                                arg_regs.len(),
                                arg_regs,
                                ir_type_args
                            );

                            // Virtual dispatch: if this method is in a class hierarchy
                            // with overrides, dispatch through the vtable.
                            if let Some(&(slot_index, _)) = self.virtual_dispatch_info.get(symbol) {
                                if !arg_regs.is_empty() {
                                    let receiver_reg = arg_regs[0];
                                    let lookup_fn = self.get_or_register_extern_function(
                                        "haxe_vtable_lookup",
                                        vec![IrType::Ptr(Box::new(IrType::U8)), IrType::I32],
                                        IrType::I64,
                                    );
                                    let slot_reg =
                                        self.builder.build_const(IrValue::I32(slot_index as i32));
                                    if let Some(slot_r) = slot_reg {
                                        if let Some(closure_ptr) = self.builder.build_call_direct(
                                            lookup_fn,
                                            vec![receiver_reg, slot_r],
                                            IrType::I64,
                                        ) {
                                            let mut param_types =
                                                vec![IrType::Ptr(Box::new(IrType::Void))];
                                            for arg in args.iter().skip(1) {
                                                param_types.push(self.convert_type(arg.ty));
                                            }
                                            let return_type = Box::new(actual_return_type.clone());
                                            let func_signature = IrType::Function {
                                                params: param_types,
                                                return_type,
                                                varargs: false,
                                            };
                                            return self.builder.build_call_indirect(
                                                closure_ptr,
                                                arg_regs,
                                                func_signature,
                                            );
                                        }
                                    }
                                }
                            }

                            let result = if ir_type_args.is_empty() {
                                self.builder.build_call_direct(
                                    func_id,
                                    arg_regs,
                                    actual_return_type.clone(),
                                )
                            } else {
                                self.builder.build_call_direct_with_type_args(
                                    func_id,
                                    arg_regs,
                                    actual_return_type.clone(),
                                    ir_type_args,
                                )
                            };
                            debug!("[FUNCTION_MAP] Result: {:?}", result);

                            // Type erasure coercion for generic method returns:
                            // The function returns I64 (type-erased), but the concrete
                            // return type may differ. Only apply to methods on generic classes —
                            // non-generic classes (Thread, Bytes, etc.) must NOT be coerced.
                            let receiver_is_generic = if !args.is_empty() {
                                let type_table = self.type_table.borrow();
                                type_table
                                    .get(args[0].ty)
                                    .map(|ti| match &ti.kind {
                                        TypeKind::Class { type_args, .. } => !type_args.is_empty(),
                                        TypeKind::GenericInstance { .. } => true,
                                        TypeKind::TypeParameter { .. } => true,
                                        _ => false,
                                    })
                                    .unwrap_or(false)
                            } else {
                                false
                            };

                            if receiver_is_generic {
                                if let Some(call_result) = result {
                                    if actual_return_type == IrType::I64 {
                                        let expected_ir_type = self.convert_type(expr.ty);
                                        if expected_ir_type != IrType::I64 {
                                            // Path 1: AST resolved type (e.g., Box<Int> → Ptr)
                                            return self.coerce_from_i64(call_result, expr.ty);
                                        }
                                        // Path 2: expr.ty is still TypeParameter → resolve via receiver's type_args
                                        if !args.is_empty() {
                                            if let Some(concrete_ty_id) = self
                                                .resolve_type_param_from_receiver(
                                                    expr.ty, args[0].ty,
                                                )
                                            {
                                                let concrete_ir_type =
                                                    self.convert_type(concrete_ty_id);
                                                if concrete_ir_type != IrType::I64 {
                                                    return self.coerce_from_i64(
                                                        call_result,
                                                        concrete_ty_id,
                                                    );
                                                }
                                            }
                                        }
                                    }
                                }
                            }

                            return result;
                        } else {
                            // Direct function call (static method or free function)
                            // Track heap-allocated intermediates passed as arguments,
                            // but ONLY if the callee is a user-defined function.
                            // Stdlib/runtime functions (MirWrapper, ExternC) may store
                            // arguments (e.g., Array.push), so freeing would cause
                            // dangling pointers.
                            let callee_is_user_defined = self
                                .builder
                                .module
                                .functions
                                .get(&func_id)
                                .map(|f| f.kind == crate::ir::functions::FunctionKind::UserDefined)
                                .unwrap_or(false);

                            let mut call_args = self.effective_static_call_args(args);
                            if call_args.len() == args.len() {
                                if let Some(param_count) = function_param_count {
                                    if args.len() == param_count + 1 && !args.is_empty() {
                                        call_args = &args[1..];
                                    }
                                }
                            }
                            if self
                                .builder
                                .module
                                .functions
                                .get(&func_id)
                                .map(|f| f.name == "Thread_sleep")
                                .unwrap_or(false)
                            {
                                eprintln!(
                                    "[DBG Thread_sleep direct] args_len={} call_args_len={} param_count={:?}",
                                    args.len(),
                                    call_args.len(),
                                    function_param_count
                                );
                            }
                            let mut arg_regs = Vec::new();
                            for (param_idx, arg) in call_args.iter().enumerate() {
                                if let Some(reg) = self.lower_expression(arg) {
                                    // Materialize anon-backed variables at call boundary
                                    let reg = self.maybe_materialize_for_call(
                                        arg,
                                        reg,
                                        Some(func_id),
                                        param_idx,
                                    );
                                    // @:derive(Copy): copy variable args at call boundary
                                    let reg = if let HirExprKind::Variable { .. } = &arg.kind {
                                        if let Some(class_sym) = self.get_copy_class_symbol(arg.ty)
                                        {
                                            self.emit_shallow_copy(reg, class_sym).unwrap_or(reg)
                                        } else {
                                            reg
                                        }
                                    } else {
                                        reg
                                    };
                                    if callee_is_user_defined {
                                        let is_heap_intermediate = matches!(
                                            &arg.kind,
                                            HirExprKind::New { .. } | HirExprKind::Call { .. }
                                        ) && self
                                            .get_drop_behavior(arg.ty)
                                            == DropBehavior::AutoDrop;
                                        if is_heap_intermediate {
                                            self.temp_heap_values.push(reg);
                                        }
                                    }
                                    arg_regs.push(reg);
                                }
                            }

                            // Fill in default values for any missing optional parameters
                            self.fill_default_args(func_id, &mut arg_regs, false);

                            // Last-chance parity guard for static-call symbol collisions:
                            // if the resolved function arity still does not match the call site,
                            // re-resolve by (method_name, arity) through stdlib static mapping.
                            if let Some(expected_params) = self
                                .builder
                                .module
                                .functions
                                .get(&func_id)
                                .map(|f| f.signature.parameters.len())
                            {
                                if expected_params != arg_regs.len() {
                                    if let Some(sym_info) = self.symbol_table.get_symbol(*symbol) {
                                        if let Some(method_name) =
                                            self.string_interner.get(sym_info.name)
                                        {
                                            if let Some((_sig, mapping)) = self
                                                .stdlib_mapping
                                                .find_static_method_by_name_and_params(
                                                    method_name,
                                                    call_args.len(),
                                                )
                                            {
                                                let runtime_func_name =
                                                    mapping.runtime_name.to_string();
                                                let mut fallback_arg_regs: Vec<IrId> = Vec::new();
                                                let mut fallback_arg_types: Vec<IrType> =
                                                    Vec::new();
                                                for arg in call_args.iter() {
                                                    if let Some(reg) = self.lower_expression(arg) {
                                                        fallback_arg_regs.push(reg);
                                                        fallback_arg_types
                                                            .push(self.convert_type(arg.ty));
                                                    }
                                                }
                                                let (expected_param_types, expected_return_type) =
                                                    self.get_extern_function_signature(
                                                        &runtime_func_name,
                                                    )
                                                    .unwrap_or_else(|| {
                                                        (
                                                            fallback_arg_types,
                                                            actual_return_type.clone(),
                                                        )
                                                    });
                                                let runtime_func_id = self
                                                    .get_or_register_extern_function(
                                                        &runtime_func_name,
                                                        expected_param_types,
                                                        expected_return_type.clone(),
                                                    );
                                                return self.builder.build_call_direct(
                                                    runtime_func_id,
                                                    fallback_arg_regs,
                                                    expected_return_type,
                                                );
                                            }
                                        }
                                    }
                                }
                            }

                            // Auto-box arguments when expected type is Ptr(U8) but actual is primitive
                            // This handles cases like Type.enumIndex(Color.Red) where the enum discriminant
                            // (raw i64) needs to be boxed as DynamicValue* for the runtime function.
                            if let Some(func) = self.builder.module.functions.get(&func_id) {
                                let expected_types: Vec<IrType> = func
                                    .signature
                                    .parameters
                                    .iter()
                                    .map(|p| p.ty.clone())
                                    .collect();
                                for (i, expected_ty) in expected_types.iter().enumerate() {
                                    if i < arg_regs.len() {
                                        let is_ptr_u8 = matches!(expected_ty, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::U8));
                                        if is_ptr_u8 {
                                            if let Some(actual_ty) =
                                                self.builder.get_register_type(arg_regs[i])
                                            {
                                                if !matches!(actual_ty, IrType::Ptr(_))
                                                    && i < call_args.len()
                                                {
                                                    if let Some(boxed) = self.box_value_for_dynamic(
                                                        arg_regs[i],
                                                        call_args[i].ty,
                                                    ) {
                                                        arg_regs[i] = boxed;
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }
                            }

                            // Inject hidden enum type_id for enum helper runtime calls.
                            {
                                let func_name = self
                                    .builder
                                    .module
                                    .functions
                                    .get(&func_id)
                                    .map(|f| f.name.clone())
                                    .or_else(|| {
                                        self.builder
                                            .module
                                            .extern_functions
                                            .get(&func_id)
                                            .map(|f| f.name.clone())
                                    })
                                    .unwrap_or_default();
                                if let Some(result) = self.try_lower_special_runtime_call(
                                    &func_name,
                                    call_args,
                                    result_type.clone(),
                                    expr.source_location.clone(),
                                ) {
                                    return result;
                                }
                                self.inject_hidden_enum_type_id_arg(
                                    &func_name,
                                    call_args,
                                    &mut arg_regs,
                                );
                            }

                            // Infer type_args for static generic calls if not already provided
                            let final_type_args = if converted_hir_type_args.is_empty() {
                                // Check if the function has type parameters
                                if let Some(func) = self.builder.module.functions.get(&func_id) {
                                    if !func.signature.type_params.is_empty()
                                        && !call_args.is_empty()
                                    {
                                        // Try to infer type_args from argument types
                                        debug!(
                                            "[TYPE INFERENCE] Function {} has type_params: {:?}",
                                            func.name, func.signature.type_params
                                        );
                                        debug!(
                                            "[TYPE INFERENCE] Function params: {:?}",
                                            func.signature
                                                .parameters
                                                .iter()
                                                .map(|p| (&p.name, &p.ty))
                                                .collect::<Vec<_>>()
                                        );

                                        let mut inferred: Vec<IrType> = Vec::new();
                                        for (_param_idx, type_param) in
                                            func.signature.type_params.iter().enumerate()
                                        {
                                            // Look for a parameter using this type variable
                                            let mut found = false;
                                            for (i, sig_param) in
                                                func.signature.parameters.iter().enumerate()
                                            {
                                                debug!(
                                                    "[TYPE INFERENCE] Checking param {} type {:?} against type_param {}",
                                                    sig_param.name, sig_param.ty, type_param.name
                                                );
                                                if let IrType::TypeVar(ref name) = sig_param.ty {
                                                    if name == &type_param.name
                                                        && i < call_args.len()
                                                    {
                                                        // Use the concrete type of the corresponding argument
                                                        let arg_type =
                                                            self.convert_type(call_args[i].ty);
                                                        debug!(
                                                            "[TYPE INFERENCE] Inferred {}={:?} from arg {}",
                                                            type_param.name, arg_type, i
                                                        );
                                                        inferred.push(arg_type);
                                                        found = true;
                                                        break;
                                                    }
                                                }
                                            }
                                            if !found {
                                                // Couldn't infer this type param from signature params
                                                // Try using the first argument's type as a fallback for single type param
                                                if func.signature.type_params.len() == 1
                                                    && !call_args.is_empty()
                                                {
                                                    let arg_type =
                                                        self.convert_type(call_args[0].ty);
                                                    debug!(
                                                        "[TYPE INFERENCE] Fallback: Inferred {}={:?} from first arg",
                                                        type_param.name, arg_type
                                                    );
                                                    inferred.push(arg_type);
                                                } else {
                                                    debug!(
                                                        "[TYPE INFERENCE] Could not infer {}, using Any",
                                                        type_param.name
                                                    );
                                                    inferred.push(IrType::Any);
                                                }
                                            }
                                        }
                                        inferred
                                    } else {
                                        Vec::new()
                                    }
                                } else {
                                    Vec::new()
                                }
                            } else {
                                converted_hir_type_args.clone()
                            };

                            // Wrap arguments for constrained type parameters (T:Interface)
                            // If a parameter expects a fat pointer (constrained TypeParam),
                            // wrap the class argument in a fat pointer with the interface's vtable.
                            if let Some(constrained) =
                                self.constrained_param_interfaces.get(&func_id).cloned()
                            {
                                for (param_idx, iface_sym) in &constrained {
                                    if *param_idx < arg_regs.len() && *param_idx < call_args.len() {
                                        let arg_type = call_args[*param_idx].ty;
                                        if let Some(class_sym) = self.get_class_symbol(arg_type) {
                                            if self
                                                .interface_vtables
                                                .contains_key(&(class_sym, *iface_sym))
                                            {
                                                if let Some(wrapped) = self
                                                    .wrap_in_interface_fat_ptr(
                                                        arg_regs[*param_idx],
                                                        class_sym,
                                                        *iface_sym,
                                                    )
                                                {
                                                    arg_regs[*param_idx] = wrapped;
                                                }
                                            }
                                        }
                                    }
                                }
                            }

                            // Use HIR type_args or inferred type_args for static generic calls
                            debug!(
                                "[FUNCTION_MAP] Direct call lowered {} args: {:?}, final_type_args: {:?}",
                                arg_regs.len(),
                                arg_regs,
                                final_type_args
                            );
                            let result = if final_type_args.is_empty() {
                                self.builder.build_call_direct(
                                    func_id,
                                    arg_regs,
                                    actual_return_type,
                                )
                            } else {
                                self.builder.build_call_direct_with_type_args(
                                    func_id,
                                    arg_regs,
                                    actual_return_type,
                                    final_type_args,
                                )
                            };
                            debug!("[FUNCTION_MAP] Result: {:?}", result);
                            return result;
                        }
                    } else {
                        // Function not in function_map - might be an extern/stdlib function
                        // Check if it's a stdlib static method (like Math.sin, Sys.println)
                        if let Some(sym_info) = self.symbol_table.get_symbol(*symbol) {
                            if let Some(method_name) = self.string_interner.get(sym_info.name) {
                                let static_args = self.effective_static_call_args(args);
                                // Check if method name matches known Math/Sys methods
                                // Try to find this method in ANY stdlib class with static methods
                                // This replaces the hardcoded is_math_method and is_sys_method checks
                                let method_static: &'static str =
                                    Box::leak(method_name.to_string().into_boxed_str());

                                // Try all stdlib classes that have static methods
                                let mut found_mapping = None;
                                for class_name in self.stdlib_mapping.get_all_classes() {
                                    if self.stdlib_mapping.class_has_static_methods(class_name) {
                                        let sig = crate::stdlib::MethodSignature {
                                            class: class_name,
                                            method: method_static,
                                            is_static: true,
                                            is_constructor: false, // Normal static method, not constructor
                                            param_count: static_args.len(),
                                        };
                                        if let Some(mapping) = self.stdlib_mapping.get(&sig) {
                                            found_mapping = Some((class_name, mapping));
                                            break;
                                        }
                                    }
                                }

                                if let Some((class_name, mapping)) = found_mapping {
                                    self.builder.call_label =
                                        Some(format!("STATIC_SEARCH:{}", class_name));
                                    let runtime_name = mapping.runtime_name;
                                    // eprintln!(
                                    //     "INFO: {} static method detected: {} (runtime: {})",
                                    //     class_name, method_name, runtime_name
                                    // );

                                    // Lower arguments and get their types
                                    let mut arg_regs = Vec::new();
                                    let mut arg_types = Vec::new();
                                    for arg in static_args {
                                        if let Some(reg) = self.lower_expression(arg) {
                                            arg_regs.push(reg);
                                            arg_types.push(self.convert_type(arg.ty));
                                        }
                                    }

                                    // Reflect.compare: use haxe_reflect_compare_typed which accepts
                                    // raw type-erased i64 values + a type tag, avoiding boxing.
                                    // For generic code, the type tag is a placeholder resolved at
                                    // monomorphization time.
                                    if runtime_name == "haxe_reflect_compare" {
                                        let mut type_param_name: Option<String> = None;
                                        let mut known_type_tag: Option<i32> = None;
                                        let mut use_typed_compare = false;

                                        if let Some(first_arg) = static_args.first() {
                                            let type_table = self.type_table.borrow();
                                            if let Some(ti) = type_table.get(first_arg.ty) {
                                                match &ti.kind {
                                                    TypeKind::TypeParameter {
                                                        symbol_id, ..
                                                    } => {
                                                        use_typed_compare = true;
                                                        // Get type param name from symbol table
                                                        if let Some(sym) =
                                                            self.symbol_table.get_symbol(*symbol_id)
                                                        {
                                                            if let Some(name_str) =
                                                                self.string_interner.get(sym.name)
                                                            {
                                                                type_param_name =
                                                                    Some(name_str.to_string());
                                                            }
                                                        }
                                                    }
                                                    TypeKind::Int => {
                                                        use_typed_compare = true;
                                                        known_type_tag = Some(1);
                                                    }
                                                    TypeKind::Float => {
                                                        use_typed_compare = true;
                                                        known_type_tag = Some(4);
                                                    }
                                                    TypeKind::Bool => {
                                                        use_typed_compare = true;
                                                        known_type_tag = Some(2);
                                                    }
                                                    TypeKind::String => {
                                                        use_typed_compare = true;
                                                        known_type_tag = Some(5);
                                                    }
                                                    _ => {} // Dynamic/other: fall through to boxing path
                                                }
                                            }
                                        }

                                        if use_typed_compare {
                                            // Cast value args to I64 — haxe_reflect_compare_typed
                                            // takes type-erased i64 values, not typed structs
                                            for i in 0..arg_regs.len().min(2) {
                                                let reg_ty = self
                                                    .builder
                                                    .get_register_type(arg_regs[i])
                                                    .unwrap_or(IrType::I64);
                                                if reg_ty != IrType::I64 {
                                                    if let Some(cast) = self.builder.build_cast(
                                                        arg_regs[i],
                                                        reg_ty,
                                                        IrType::I64,
                                                    ) {
                                                        arg_regs[i] = cast;
                                                    }
                                                }
                                                arg_types[i] = IrType::I64;
                                            }

                                            // Emit type tag constant (placeholder 0 for generics, real value for concrete)
                                            let tag_reg = if let Some(tp_name) = type_param_name {
                                                let tag =
                                                    self.builder.build_const(IrValue::I32(0))?;
                                                // Record fixup for the monomorphize pass to resolve
                                                if let Some(func) =
                                                    self.builder.current_function_mut()
                                                {
                                                    func.type_param_tag_fixups.push((tag, tp_name));
                                                }
                                                tag
                                            } else {
                                                self.builder.build_const(IrValue::I32(
                                                    known_type_tag.unwrap_or(1),
                                                ))?
                                            };

                                            arg_regs.push(tag_reg);
                                            arg_types.push(IrType::I32);

                                            let extern_func_id = self
                                                .get_or_register_extern_function(
                                                    "haxe_reflect_compare_typed",
                                                    arg_types,
                                                    result_type.clone(),
                                                );

                                            return self.builder.build_call_direct(
                                                extern_func_id,
                                                arg_regs,
                                                result_type,
                                            );
                                        } else {
                                            // Dynamic case: box arguments for haxe_reflect_compare
                                            let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                                            for (i, arg) in static_args.iter().enumerate() {
                                                if i >= arg_regs.len() {
                                                    break;
                                                }
                                                if let Some(boxed) =
                                                    self.box_value_for_dynamic(arg_regs[i], arg.ty)
                                                {
                                                    arg_regs[i] = boxed;
                                                    arg_types[i] = ptr_u8.clone();
                                                }
                                            }
                                        }
                                    }

                                    // Register the external runtime function
                                    let extern_func_id = self.get_or_register_extern_function(
                                        runtime_name,
                                        arg_types,
                                        result_type.clone(),
                                    );

                                    // Generate call to external function
                                    return self.builder.build_call_direct(
                                        extern_func_id,
                                        arg_regs,
                                        result_type,
                                    );
                                }
                            }
                        }
                    }
                }

                // Before falling through to indirect call, try to look up by name or register a forward reference
                // for unresolved static method calls (cross-module dependencies during stdlib compilation)
                if let HirExprKind::Variable { symbol, .. } = &callee.kind {
                    let unresolved_call_args = if !*is_method {
                        self.effective_static_call_args(args)
                    } else {
                        args
                    };
                    if let Some(sym_info) = self.symbol_table.get_symbol(*symbol) {
                        if let Some(qual_name) = sym_info.qualified_name {
                            if let Some(qual_name_str) = self.string_interner.get(qual_name) {
                                let _method_name = self
                                    .string_interner
                                    .get(sym_info.name)
                                    .unwrap_or("<unknown>");
                                debug!("[PRE-CHECK] Qualified name: '{}'", qual_name_str);

                                // FIRST: Check if this function is already compiled and in the name map
                                if let Some(&existing_func_id) =
                                    self.external_function_name_map.get(qual_name_str)
                                {
                                    self.builder.call_label =
                                        Some(format!("NAME_MAP_HIT:{}", qual_name_str));
                                    debug!(
                                        "[NAME MAP HIT] Found '{}' in external_function_name_map -> {:?}",
                                        qual_name_str, existing_func_id
                                    );

                                    // Lower arguments
                                    let arg_regs: Vec<_> = unresolved_call_args
                                        .iter()
                                        .filter_map(|a| self.lower_expression(a))
                                        .collect();

                                    // Generate the call to the external function
                                    return self.builder.build_call_direct(
                                        existing_func_id,
                                        arg_regs,
                                        result_type,
                                    );
                                }

                                self.builder.call_label =
                                    Some(format!("FORWARD_REF:{}", qual_name_str));
                                debug!(
                                    "[FORWARD REF] Registering forward reference for unresolved call to '{}'",
                                    qual_name_str
                                );

                                // Lower arguments and collect their types
                                let mut arg_regs = Vec::new();
                                let mut param_types = Vec::new();
                                for arg in unresolved_call_args {
                                    if let Some(reg) = self.lower_expression(arg) {
                                        arg_regs.push(reg);
                                        param_types.push(self.convert_type(arg.ty));
                                    }
                                }

                                // Register as a forward reference using qualified name
                                // This will be resolved later during module linking
                                let forward_func_id = self.register_stdlib_mir_forward_ref(
                                    qual_name_str,
                                    param_types,
                                    result_type.clone(),
                                );

                                debug!(
                                    "[FORWARD REF] Registered forward ref to '{}' with ID {:?}",
                                    qual_name_str, forward_func_id
                                );

                                // Generate the call to the forward reference
                                return self.builder.build_call_direct(
                                    forward_func_id,
                                    arg_regs,
                                    result_type,
                                );
                            }
                        }
                    }
                }

                // Indirect function call (function pointer)
                // TODO: Get the full function signature from the callee's type
                // For now, we'll infer it from the arguments and return type
                // This is a temporary workaround until we pass type_table to HIR→MIR
                self.builder.call_label = Some("INDIRECT_CALL".to_string());

                debug!(
                    "Taking indirect function call path - callee kind={:?}, args.len()={}",
                    std::mem::discriminant(&callee.kind),
                    args.len()
                );

                // Lower arguments FIRST, before trying to lower the callee
                // This ensures lambdas in arguments get generated even if callee lowering fails
                debug!("About to lower {} indirect call arguments", args.len());
                for (i, a) in args.iter().enumerate() {
                    debug!("  arg[{}] kind={:?}", i, std::mem::discriminant(&a.kind));
                }
                let arg_regs: Vec<_> = args
                    .iter()
                    .filter_map(|a| {
                        debug!(
                            "NOW lowering arg with kind={:?}",
                            std::mem::discriminant(&a.kind)
                        );
                        self.lower_expression(a)
                    })
                    .collect();
                debug!(
                    "Lowered {} indirect call arguments successfully",
                    arg_regs.len()
                );

                // Now try to lower the callee - if this fails, the call won't be generated
                // but the lambda functions in arguments will have been created
                let func_ptr = self.lower_expression(callee)?;

                // Build function signature from callee type or argument types
                let param_types: Vec<IrType> = {
                    // Try to get param types from callee's function type
                    let type_table = self.type_table.borrow();
                    let callee_type = type_table.get(callee.ty);
                    if let Some(type_ref) = callee_type {
                        if let crate::tast::TypeKind::Function { params, .. } = &type_ref.kind {
                            params.iter().map(|p| self.convert_type(*p)).collect()
                        } else {
                            // Fallback: infer from actual argument types
                            args.iter().map(|a| self.convert_type(a.ty)).collect()
                        }
                    } else {
                        args.iter().map(|a| self.convert_type(a.ty)).collect()
                    }
                };
                let return_type = Box::new(self.convert_type(expr.ty));

                let func_signature = IrType::Function {
                    params: param_types,
                    return_type,
                    varargs: false,
                };

                self.builder
                    .build_call_indirect(func_ptr, arg_regs, func_signature)
            }

            HirExprKind::New {
                class_type,
                type_args: hir_type_args,
                args,
                class_name: hir_class_name,
                ..
            } => {
                let debug_class_name =
                    hir_class_name.and_then(|interned| self.string_interner.get(interned));
                debug!(
                    "[NEW EXPR]: class_type={:?}, args.len={}, hir_class_name={:?}, hir_type_args={:?}",
                    class_type,
                    args.len(),
                    debug_class_name,
                    hir_type_args
                );

                // Check if this is an abstract type
                let type_table = self.type_table.borrow();
                let (is_abstract, actual_symbol_id) = if let Some(type_ref) =
                    type_table.get(*class_type)
                {
                    let symbol_id = match &type_ref.kind {
                        crate::tast::TypeKind::Class { symbol_id, .. } => Some(*symbol_id),
                        crate::tast::TypeKind::Abstract { symbol_id, .. } => Some(*symbol_id),
                        crate::tast::TypeKind::GenericInstance { base_type, .. } => {
                            // Unwrap GenericInstance to find base class symbol_id
                            if let Some(base_info) = type_table.get(*base_type) {
                                match &base_info.kind {
                                    crate::tast::TypeKind::Class { symbol_id, .. } => {
                                        Some(*symbol_id)
                                    }
                                    _ => None,
                                }
                            } else {
                                None
                            }
                        }
                        crate::tast::TypeKind::TypeAlias {
                            symbol_id,
                            target_type,
                            ..
                        } => {
                            // Resolve TypeAlias to find the actual class symbol
                            // For user classes, the TypeAlias symbol_id IS the class symbol
                            let mut resolved = Some(*symbol_id);
                            // Also try resolving through target_type for deeper aliases
                            if let Some(target) = type_table.get(*target_type) {
                                if let crate::tast::TypeKind::Class {
                                    symbol_id: class_sym,
                                    ..
                                } = &target.kind
                                {
                                    resolved = Some(*class_sym);
                                }
                            }
                            resolved
                        }
                        _ => None,
                    };
                    let is_abs = matches!(type_ref.kind, crate::tast::TypeKind::Abstract { .. });
                    (is_abs, symbol_id)
                } else {
                    (false, None)
                };
                drop(type_table);

                // SPECIAL CASE: Abstract type constructors
                // If this is an abstract type, treat this as a simple value wrap (no allocation).
                if is_abstract {
                    // Before treating as abstract value-wrap, check if there's a user-defined
                    // class with the same name that has a constructor registered. User classes
                    // should override stdlib abstract types with the same short name
                    // (e.g., user's `class Box<T>` vs stdlib `rayzor.Box<T>` abstract).
                    let has_user_constructor = hir_class_name
                        .and_then(|interned| self.string_interner.get(interned))
                        .map(|name| self.constructor_name_map.contains_key(name))
                        .unwrap_or(false)
                        || actual_symbol_id
                            .and_then(|sid| self.symbol_table.get_symbol(sid))
                            .and_then(|s| s.qualified_name)
                            .and_then(|qn| self.string_interner.get(qn))
                            .map(|qn| self.constructor_name_map.contains_key(qn))
                            .unwrap_or(false);

                    if !has_user_constructor {
                        if args.len() == 1 {
                            return self.lower_expression(&args[0]);
                        } else if args.is_empty() {
                            return self.builder.build_const(IrValue::I32(0));
                        } else {
                            return self.lower_expression(&args[0]);
                        }
                    }
                    // User constructor exists - fall through to normal class construction
                }

                // SPECIAL CASE: Check if this is an extern stdlib class constructor BEFORE fallback
                // For extern stdlib classes (Channel, Thread, Arc, Mutex), we call the MIR wrapper
                // function (e.g., Channel_init) instead of allocating and calling a constructor.
                // This MUST come before the value-wrap fallback to prevent returning the argument value!

                // PRIORITY #1: Use class_name from HIR if available (preserves actual class name even when TypeId is invalid)
                let mut class_name =
                    hir_class_name.and_then(|interned| self.string_interner.get(interned));

                // FALLBACK #1: Try to get class name from TypeId if HIR didn't have it
                if class_name.is_none() {
                    let type_table = self.type_table.borrow();
                    class_name = if let Some(type_ref) = type_table.get(*class_type) {
                        match &type_ref.kind {
                            crate::tast::TypeKind::Class { symbol_id, .. } => self
                                .symbol_table
                                .get_symbol(*symbol_id)
                                .and_then(|sym| self.string_interner.get(sym.name)),
                            crate::tast::TypeKind::GenericInstance { base_type, .. } => {
                                // Unwrap GenericInstance to get base class name
                                if let Some(base_info) = type_table.get(*base_type) {
                                    if let crate::tast::TypeKind::Class { symbol_id, .. } =
                                        &base_info.kind
                                    {
                                        self.symbol_table
                                            .get_symbol(*symbol_id)
                                            .and_then(|sym| self.string_interner.get(sym.name))
                                    } else {
                                        None
                                    }
                                } else {
                                    None
                                }
                            }
                            _ => None,
                        }
                    } else {
                        None
                    };
                    drop(type_table);
                }

                // FALLBACK #2: If TypeId lookup failed (e.g., for extern stdlib classes that aren't
                // pre-registered because Channel.hx is skipped), try getting class name from the
                // actual_symbol_id which comes from the HIR New expression
                if class_name.is_none() {
                    if let Some(sym_id) = actual_symbol_id {
                        class_name = self
                            .symbol_table
                            .get_symbol(sym_id)
                            .and_then(|sym| self.string_interner.get(sym.name));
                    }
                }

                // FALLBACK #3: If still no class name and TypeId is invalid (u32::MAX),
                // try checking all stdlib registered class names to see if ANY constructor matches
                // This is a last resort for extern stdlib classes that weren't pre-registered
                if class_name.is_none() && *class_type == TypeId::from_raw(u32::MAX) {
                    // Get ALL classes that have registered constructors from the stdlib mapping
                    let constructor_classes = self.stdlib_mapping.get_constructor_classes();

                    // Try each registered constructor class
                    for potential_class in constructor_classes {
                        let method_sig = crate::stdlib::runtime_mapping::MethodSignature {
                            class: potential_class,
                            method: "new",
                            is_static: true,
                            is_constructor: true,
                            param_count: 0,
                        };
                        if self.stdlib_mapping.get(&method_sig).is_some() {
                            class_name = Some(potential_class);
                            break;
                        }
                    }
                }

                // MONOMORPHIZATION: For generic extern classes like Vec<T>, monomorphize the class name
                // based on type arguments. Vec<Int> -> VecI32, Vec<Float> -> VecF64, etc.
                // Use hir_type_args directly (from HIR) instead of type_table lookup (which may fail for extern classes)
                let monomorphized_class_name: Option<String> = if let Some(base_name) = class_name {
                    if base_name == "Vec" && !hir_type_args.is_empty() {
                        // Get the first type argument and determine the monomorphized suffix
                        let first_arg = hir_type_args[0];
                        let type_table = self.type_table.borrow();
                        let suffix = if let Some(arg_type) = type_table.get(first_arg) {
                            match &arg_type.kind {
                                crate::tast::TypeKind::Int => Some("I32"),
                                crate::tast::TypeKind::Float => Some("F64"),
                                crate::tast::TypeKind::Bool => Some("Bool"),
                                crate::tast::TypeKind::String => Some("Ptr"),
                                crate::tast::TypeKind::Class { symbol_id, .. } => {
                                    // Check if it's Int64 (a class type representing 64-bit int)
                                    if let Some(class_info) =
                                        self.symbol_table.get_symbol(*symbol_id)
                                    {
                                        if let Some(name) =
                                            self.string_interner.get(class_info.name)
                                        {
                                            if name == "Int64" {
                                                Some("I64")
                                            } else {
                                                Some("Ptr") // Other classes are reference types
                                            }
                                        } else {
                                            Some("Ptr")
                                        }
                                    } else {
                                        Some("Ptr")
                                    }
                                }
                                _ => Some("Ptr"),
                            }
                        } else {
                            Some("Ptr") // If type not found, default to Ptr variant
                        };
                        drop(type_table);
                        suffix.map(|s| format!("Vec{}", s))
                    } else {
                        None
                    }
                } else {
                    None
                };

                // Use monomorphized name if available, otherwise use original class name
                let final_class_name = monomorphized_class_name.as_deref().or(class_name);
                debug!(
                    "[NEW EXPR]: final_class_name={:?} (monomorphized from {:?})",
                    final_class_name, class_name
                );

                if let Some(class_name) = final_class_name {
                    // Check if this class has a "new" constructor registered in the runtime mapping
                    // Use find_constructor to look up the registered constructor mapping
                    // This returns both the MethodSignature and RuntimeFunctionCall from the registry
                    // PRIORITY: Try HIR class name first (may be fully qualified, e.g., "sys.ssl.Socket")
                    // This is critical for subclasses like sys.ssl.Socket that extend sys.net.Socket,
                    // because the symbol's qualified_name resolves to the parent class.
                    // Look up constructor: extract needed data (Copy types) to avoid holding
                    // a borrow on self.stdlib_mapping while calling self.lower_expression later.
                    let arg_count = args.len();
                    let constructor_info: Option<(&'static str, bool, bool)> = {
                        let mut found = None;

                        // Helper: try constructor lookup with param count first, then without.
                        // This ensures overloaded constructors (e.g., Uncompress with 0 or 1 args)
                        // select the correct overload.
                        macro_rules! try_find_ctor {
                            ($name:expr) => {
                                if found.is_none() {
                                    // Try param-count-aware lookup first
                                    if let Some((_, rc)) = self
                                        .stdlib_mapping
                                        .find_constructor_with_params($name, arg_count)
                                    {
                                        found = Some((
                                            rc.runtime_name,
                                            rc.needs_out_param,
                                            rc.is_mir_wrapper,
                                        ));
                                    }
                                    // Fall back to any-param lookup
                                    else if let Some((_, rc)) =
                                        self.stdlib_mapping.find_constructor($name)
                                    {
                                        found = Some((
                                            rc.runtime_name,
                                            rc.needs_out_param,
                                            rc.is_mir_wrapper,
                                        ));
                                    }
                                }
                            };
                        }

                        // PRIORITY #0: Try HIR class name as qualified (e.g., "sys.ssl.Socket" -> "sys_ssl_Socket")
                        // This handles subclass constructors before the symbol-based lookup (which may
                        // resolve to the parent class due to class inheritance).
                        if class_name.contains('.') {
                            let qualified_hir = class_name.replace(".", "_");
                            try_find_ctor!(&qualified_hir);
                        }
                        if found.is_none() {
                            if let Some(sym_id) = actual_symbol_id {
                                if let Some(sym) = self.symbol_table.get_symbol(sym_id) {
                                    // Try lowered @:native name first
                                    if let Some(native) = sym.native_name {
                                        if let Some(native_str) = self.string_interner.get(native) {
                                            let native_class_name = native_str.replace("::", "_");
                                            try_find_ctor!(&native_class_name);
                                        }
                                    }
                                    // Fall back to qualified name
                                    if found.is_none() {
                                        if let Some(qn) = sym.qualified_name {
                                            if let Some(qual_name) = self.string_interner.get(qn) {
                                                let qualified_class_name =
                                                    qual_name.replace(".", "_");
                                                try_find_ctor!(&qualified_class_name);
                                            }
                                        }
                                    }
                                }
                            }
                            // FALLBACK: Try simple class name
                            try_find_ctor!(class_name);

                            // FALLBACK #2: Try bare class name for qualified paths
                            // (e.g., "haxe.ds.ObjectMap" -> "ObjectMap")
                            if found.is_none() && class_name.contains('.') {
                                let bare_name = class_name.rsplit('.').next().unwrap_or(class_name);
                                try_find_ctor!(bare_name);
                            }
                        } // close PRIORITY #0 if found.is_none()
                        found
                    };
                    if let Some((wrapper_name, needs_out_param, is_mir_wrapper)) = constructor_info
                    {
                        // Lower arguments
                        let arg_regs: Vec<_> = args
                            .iter()
                            .filter_map(|a| self.lower_expression(a))
                            .collect();

                        // Register forward ref if not already present
                        let param_types: Vec<IrType> = arg_regs
                            .iter()
                            .map(|reg| self.builder.get_register_type(*reg).unwrap_or(IrType::Any))
                            .collect();

                        // For extern classes, the return type should be a pointer (opaque handle),
                        // not the class struct itself
                        let result_type = IrType::Ptr(Box::new(IrType::U8));

                        // MIR wrappers are compiled by Cranelift alongside user code -> use forward ref
                        // needs_out_param constructors also use MIR forward refs (legacy path)
                        // Direct extern calls are for non-wrapper, non-out-param constructors
                        let wrapper_func_id = if is_mir_wrapper || needs_out_param {
                            self.register_stdlib_mir_forward_ref(
                                wrapper_name,
                                param_types,
                                result_type.clone(),
                            )
                        } else {
                            // Simple constructors are direct extern calls
                            self.get_or_register_extern_function(
                                wrapper_name,
                                param_types,
                                result_type.clone(),
                            )
                        };

                        // Call the wrapper and return the result
                        let result =
                            self.builder
                                .build_call_direct(wrapper_func_id, arg_regs, result_type);
                        if let Some(reg) = result {
                            self.register_class_hints
                                .insert(reg, class_name.to_string());
                        }
                        return result;
                    }
                }

                // Check if constructor exists - try both TypeId and TypeId derived from SymbolId
                let mut constructor_type_id = *class_type;
                let mut has_constructor = self.constructor_map.contains_key(class_type);

                // If not found and we have a SymbolId, try TypeId derived from SymbolId as fallback
                if !has_constructor {
                    if let Some(sym_id) = actual_symbol_id {
                        let type_id_from_symbol = TypeId::from_raw(sym_id.as_raw());
                        if self.constructor_map.contains_key(&type_id_from_symbol) {
                            constructor_type_id = type_id_from_symbol;
                            has_constructor = true;
                        }
                    }
                }

                // If not found and this is a GenericInstance, try the base class TypeId
                if !has_constructor {
                    let type_table = self.type_table.borrow();
                    if let Some(type_info) = type_table.get(*class_type) {
                        if let crate::tast::TypeKind::GenericInstance { base_type, .. } =
                            &type_info.kind
                        {
                            if self.constructor_map.contains_key(base_type) {
                                constructor_type_id = *base_type;
                                has_constructor = true;
                            }
                        }
                    }
                }

                // Try constructor_name_map as final fallback before value wrap
                // Check bare name first, then qualified name from symbol table
                if !has_constructor {
                    if let Some(class_name) = final_class_name {
                        if let Some(&func_id) = self.constructor_name_map.get(class_name) {
                            constructor_type_id = *class_type;
                            has_constructor = true;
                            self.constructor_map.insert(*class_type, func_id);
                        }
                    }
                    // Also try qualified name (e.g., "haxe.ds.List" vs bare "List")
                    if !has_constructor {
                        if let Some(sym_id) = actual_symbol_id {
                            if let Some(sym) = self.symbol_table.get_symbol(sym_id) {
                                if let Some(qn) = sym.qualified_name {
                                    if let Some(qual_name) = self.string_interner.get(qn) {
                                        if let Some(&func_id) =
                                            self.constructor_name_map.get(qual_name)
                                        {
                                            constructor_type_id = *class_type;
                                            has_constructor = true;
                                            self.constructor_map.insert(*class_type, func_id);
                                        }
                                    }
                                }
                            }
                        }
                    }
                }

                // If no constructor exists and we have exactly one argument, treat as value wrap
                // This handles abstract types that weren't properly detected above
                if !has_constructor && args.len() == 1 {
                    let result = self.lower_expression(&args[0]);
                    return result;
                }

                // SPECIAL CASE: Array constructor (@:coreType extern class)
                // Array needs special handling - call haxe_array_new() runtime function
                let type_table = self.type_table.borrow();
                let is_array = if let Some(type_ref) = type_table.get(*class_type) {
                    matches!(type_ref.kind, crate::tast::TypeKind::Array { .. })
                } else {
                    false
                };
                drop(type_table);

                if is_array {
                    // Allocate HaxeArray struct on heap (32 bytes = 4 x 8 for ptr, len, cap, elem_size)
                    // Must be heap-allocated because array pointers can escape the creating function
                    // (e.g., stored in class fields, returned from functions)
                    let array_ptr = self.build_heap_alloc(32)?;

                    // Zero-initialize the HaxeArray struct (ptr=null, len=0, cap=0, elem_size=8)
                    // This represents an empty uninitialized array
                    if let Some(zero_i64) = self.builder.build_const(IrValue::I64(0)) {
                        // Zero out ptr field (offset 0)
                        if let Some(index_0) = self.builder.build_const(IrValue::I32(0)) {
                            if let Some(ptr_field) =
                                self.builder
                                    .build_gep(array_ptr, vec![index_0], IrType::I64)
                            {
                                self.builder.build_store(ptr_field, zero_i64);
                            }
                        }
                        // Zero out len field (offset 8)
                        if let Some(index_1) = self.builder.build_const(IrValue::I32(1)) {
                            if let Some(len_field) =
                                self.builder
                                    .build_gep(array_ptr, vec![index_1], IrType::I64)
                            {
                                self.builder.build_store(len_field, zero_i64);
                            }
                        }
                        // Zero out cap field (offset 16)
                        if let Some(index_2) = self.builder.build_const(IrValue::I32(2)) {
                            if let Some(cap_field) =
                                self.builder
                                    .build_gep(array_ptr, vec![index_2], IrType::I64)
                            {
                                self.builder.build_store(cap_field, zero_i64);
                            }
                        }
                        // Set elem_size field to 8 bytes (offset 24) - assume pointer size for now
                        if let Some(elem_size_val) = self.builder.build_const(IrValue::I64(8)) {
                            if let Some(index_3) = self.builder.build_const(IrValue::I32(3)) {
                                if let Some(elem_size_field) =
                                    self.builder
                                        .build_gep(array_ptr, vec![index_3], IrType::I64)
                                {
                                    self.builder.build_store(elem_size_field, elem_size_val);
                                }
                            }
                        }
                    }

                    // Return the zero-initialized array pointer
                    return Some(array_ptr);
                }

                // @:cstruct CLASS: flat C-compatible allocation (no object header)
                if self.is_cstruct_class(*class_type) {
                    if let Some(layout) = self.get_or_compute_cstruct_layout(*class_type) {
                        let obj_ptr = self.build_heap_alloc(layout.total_size as u64)?;

                        // Zero-initialize all bytes via first field store of 0
                        // (memset-style zero init would be better but this works)
                        if let Some(zero) = self.builder.build_const(IrValue::I64(0)) {
                            for field in &layout.fields {
                                let offset_const = self
                                    .builder
                                    .build_const(IrValue::I64(field.byte_offset as i64))?;
                                let field_ptr = self.builder.build_ptr_add(
                                    obj_ptr,
                                    offset_const,
                                    IrType::Ptr(Box::new(IrType::U8)),
                                )?;
                                let zero_val = match &field.ir_type {
                                    IrType::F64 => self.builder.build_const(IrValue::F64(0.0))?,
                                    IrType::I64 => self.builder.build_const(IrValue::I64(0))?,
                                    IrType::I32 => self.builder.build_const(IrValue::I32(0))?,
                                    IrType::Bool => {
                                        self.builder.build_const(IrValue::Bool(false))?
                                    }
                                    _ => self.builder.build_const(IrValue::I64(0))?,
                                };
                                self.builder.build_store(field_ptr, zero_val);
                            }
                        }

                        // Call constructor if exists
                        let constructor_func_id =
                            self.constructor_map.get(&constructor_type_id).copied();
                        if let Some(constructor_func_id) = constructor_func_id {
                            let arg_regs: Vec<_> = std::iter::once(obj_ptr)
                                .chain(args.iter().filter_map(|a| self.lower_expression(a)))
                                .collect();
                            self.builder.build_call_direct(
                                constructor_func_id,
                                arg_regs,
                                IrType::Void,
                            );
                        }

                        return Some(obj_ptr);
                    }
                }

                // @:gpuStruct CLASS: GPU-compatible flat allocation (no object header)
                // Uses 4-byte floats, 4-byte ints — matches Metal/CUDA struct layout
                if self.is_gpu_struct_class(*class_type) {
                    if let Some(layout) = self.get_or_compute_gpu_struct_layout(*class_type) {
                        let obj_ptr = self.build_heap_alloc(layout.total_size as u64)?;

                        // Zero-initialize all fields
                        if let Some(_zero) = self.builder.build_const(IrValue::I32(0)) {
                            for field in &layout.fields {
                                let offset_const = self
                                    .builder
                                    .build_const(IrValue::I64(field.byte_offset as i64))?;
                                let field_ptr = self.builder.build_ptr_add(
                                    obj_ptr,
                                    offset_const,
                                    IrType::Ptr(Box::new(IrType::U8)),
                                )?;
                                let zero_val = match &field.ir_type {
                                    IrType::F32 => self.builder.build_const(IrValue::F32(0.0))?,
                                    IrType::I32 => self.builder.build_const(IrValue::I32(0))?,
                                    _ => self.builder.build_const(IrValue::I32(0))?,
                                };
                                self.builder.build_store(field_ptr, zero_val);
                            }
                        }

                        // Call constructor if exists
                        let constructor_func_id =
                            self.constructor_map.get(&constructor_type_id).copied();
                        if let Some(constructor_func_id) = constructor_func_id {
                            let arg_regs: Vec<_> = std::iter::once(obj_ptr)
                                .chain(args.iter().filter_map(|a| self.lower_expression(a)))
                                .collect();
                            self.builder.build_call_direct(
                                constructor_func_id,
                                arg_regs,
                                IrType::Void,
                            );
                        }

                        return Some(obj_ptr);
                    }
                }

                // CLASS TYPE CONSTRUCTOR:
                // Allocate object on HEAP (not stack) since objects may escape the current function
                // When a method returns `new Foo()`, the object must outlive the callee's stack frame
                let _class_mir_type = self.convert_type(*class_type);

                // Look up pre-computed allocation size from register_class_metadata.
                // The HIR type registry uses TypeId::from_raw(symbol_id), so convert
                // the TAST class_type via its symbol_id for the lookup.
                let registry_type_id = actual_symbol_id.map(|sid| TypeId::from_raw(sid.as_raw()));
                let obj_size: u64 = registry_type_id
                    .and_then(|tid| self.class_alloc_sizes.get(&tid).copied())
                    // Also try the TAST class_type directly — the hir_module.types key may differ
                    // from TypeId::from_raw(symbol_id) for stdlib classes (e.g., Exception).
                    .or_else(|| self.class_alloc_sizes.get(class_type).copied())
                    // Fallback: derive from field_index_map, since class_alloc_sizes TypeIds
                    // differ across compilation contexts but field_index_map uses SymbolIds.
                    // alloc_size = (max_slot + 1) * 8 (header at slot 0, user fields at 1+).
                    .or_else(|| {
                        let target_sym = actual_symbol_id?;
                        let mut max_idx = 0u32;
                        let mut found = false;
                        for &(class_ty, idx) in self.field_index_map.values() {
                            let owner =
                                self.class_type_to_symbol
                                    .get(&class_ty)
                                    .copied()
                                    .or_else(|| {
                                        if class_ty == *class_type {
                                            actual_symbol_id
                                        } else {
                                            None
                                        }
                                    });
                            if owner == Some(target_sym) {
                                if idx > max_idx {
                                    max_idx = idx;
                                }
                                found = true;
                            }
                        }
                        if found {
                            Some((max_idx as u64 + 1) * 8)
                        } else {
                            None
                        }
                    })
                    // Fallback: look up by class name (stable across compilation contexts)
                    .or_else(|| {
                        let sym_id = actual_symbol_id?;
                        let class_name = self.symbol_table.get_symbol(sym_id).and_then(|sym| {
                            sym.qualified_name
                                .and_then(|n| self.string_interner.get(n))
                                .or_else(|| self.string_interner.get(sym.name))
                        })?;
                        self.class_alloc_sizes_by_name.get(class_name).copied()
                    })
                    .unwrap_or_else(|| ((args.len() as u64 + 1) * 8).max(16));
                {
                    let cn = actual_symbol_id.and_then(|sid| self.symbol_table.get_symbol(sid).and_then(|sym| self.string_interner.get(sym.name))).unwrap_or("?");
                    if cn.contains("Scale") {
                    }
                }
                // Use heap allocation (malloc) for class instances
                let obj_ptr = self.build_heap_alloc(obj_size);
                let obj_ptr = obj_ptr?;

                // Store object header: runtime type_id at GEP index 0.
                // Use the same class-id resolver as typed throw/catch (without +1000).
                {
                    let encoded_type_id = self.runtime_type_id(*class_type);
                    let runtime_type_id = if encoded_type_id >= 1000 {
                        (encoded_type_id - 1000) as i64
                    } else {
                        encoded_type_id as i64
                    };
                    if let Some(type_id_const) =
                        self.builder.build_const(IrValue::I64(runtime_type_id))
                    {
                        if let Some(index_0) = self.builder.build_const(IrValue::I32(0)) {
                            if let Some(header_ptr) =
                                self.builder.build_gep(obj_ptr, vec![index_0], IrType::I64)
                            {
                                self.builder.build_store(header_ptr, type_id_const);
                            }
                        }
                    }
                }

                // @:derive(Default): initialize all fields before constructor call.
                // Uses @:default(value) metadata if present, else type-based defaults.
                if let Some(class_sym) = actual_symbol_id {
                    if self.derive_default_classes.contains(&class_sym) {
                        if let Some(fields) = self.class_instance_fields.get(&class_sym).cloned() {
                            // Pre-collect field defaults to avoid borrow issues
                            let field_defaults: Vec<_> = fields
                                .iter()
                                .map(|&(field_sym, _, _)| {
                                    self.field_default_exprs.get(&field_sym).cloned()
                                })
                                .collect();

                            for (i, &(_field_sym, field_type_id, gep_idx)) in
                                fields.iter().enumerate()
                            {
                                let field_ir_type = self.convert_type(field_type_id);
                                let default_val = if let Some(ref default_expr) = field_defaults[i]
                                {
                                    self.lower_expression(default_expr)
                                        .or_else(|| self.build_type_default(field_type_id))
                                } else {
                                    self.build_type_default(field_type_id)
                                };
                                if let Some(val) = default_val {
                                    let idx =
                                        self.builder.build_const(IrValue::I32(gep_idx as i32));
                                    if let Some(idx) = idx {
                                        let ptr = self.builder.build_gep(
                                            obj_ptr,
                                            vec![idx],
                                            field_ir_type,
                                        );
                                        if let Some(ptr) = ptr {
                                            self.builder.build_store(ptr, val);
                                        }
                                    }
                                }
                            }
                        }
                    }
                }

                // Look up constructor by TypeId - use the resolved constructor_type_id
                let constructor_func_id = self.constructor_map.get(&constructor_type_id).copied();

                if let Some(constructor_func_id) = constructor_func_id {
                    // Call constructor with object as first argument
                    let mut arg_regs: Vec<_> = std::iter::once(obj_ptr)
                        .chain(args.iter().filter_map(|a| self.lower_expression(a)))
                        .collect();

                    let pre_fill = arg_regs.len();
                    // Fill in default values for any missing optional parameters
                    self.fill_default_args(constructor_func_id, &mut arg_regs, true);
                    let post_fill = arg_regs.len();
                    let sig_params = self
                        .builder
                        .module
                        .functions
                        .get(&constructor_func_id)
                        .map(|f| f.signature.parameters.len())
                        .unwrap_or(0);

                    // Constructor returns void, so we ignore the result
                    self.builder
                        .build_call_direct(constructor_func_id, arg_regs, IrType::Void);

                    // Transfer ownership: constructor args that are heap-allocated
                    // are now owned by the new object (stored in its fields).
                    // Remove them from drop tracking to prevent premature free.
                    for arg in args.iter() {
                        if let HirExprKind::Variable { symbol, .. } = &arg.kind {
                            if self.owned_heap_values.contains_key(symbol) {
                                self.owned_heap_values.remove(symbol);
                            }
                        }
                    }
                } else {
                    // eprintln!("WARNING: Constructor not found for TypeId {:?}", class_type);
                }

                if let Some(class_name) = final_class_name {
                    self.register_class_hints
                        .insert(obj_ptr, class_name.to_string());
                }
                Some(obj_ptr)
            }

            HirExprKind::Unary { op, operand } => {
                // Handle increment/decrement operators specially
                match op {
                    HirUnaryOp::PostIncr
                    | HirUnaryOp::PreIncr
                    | HirUnaryOp::PostDecr
                    | HirUnaryOp::PreDecr => {
                        // For increment/decrement, we need to:
                        // 1. Load the current value
                        // 2. Compute new value (old ± 1)
                        // 3. Store the new value back
                        // 4. Return old value (post) or new value (pre)

                        let old_value = self.lower_expression(operand)?;
                        let one = self.builder.build_const(IrValue::I32(1))?;

                        let is_increment = matches!(op, HirUnaryOp::PostIncr | HirUnaryOp::PreIncr);
                        let new_value = if is_increment {
                            self.builder.build_binop(BinaryOp::Add, old_value, one)?
                        } else {
                            self.builder.build_binop(BinaryOp::Sub, old_value, one)?
                        };

                        // Register the new_value with its type
                        let result_type = self.convert_type(expr.ty);
                        let src_loc = self.convert_source_location(&expr.source_location);
                        if let Some(func) = self.builder.current_function_mut() {
                            func.locals.insert(
                                new_value,
                                super::IrLocal {
                                    name: format!("_incr{}", new_value.0),
                                    ty: result_type.clone(),
                                    mutable: false,
                                    source_location: src_loc.clone(),
                                    allocation: super::AllocationHint::Stack,
                                },
                            );
                        }

                        // Store the new value back to the operand
                        match &operand.kind {
                            HirExprKind::Variable { symbol, .. } => {
                                // If we're inside a lambda with captured variables, also store back to environment
                                if let Some(ref env_layout) = self.current_env_layout {
                                    if env_layout.find_field(*symbol).is_some() {
                                        // This is a captured variable - store it back to environment
                                        let env_ptr = IrId::new(0); // First parameter in lambda is environment pointer
                                        env_layout.store_field(
                                            &mut self.builder,
                                            env_ptr,
                                            *symbol,
                                            new_value,
                                        );
                                    }
                                }

                                self.symbol_map.insert(*symbol, new_value);
                            }
                            HirExprKind::Field { object, field } => {
                                // Field access (e.g., this.length++) — store new value back
                                // via GEP + Store, same as field assignment
                                if let Some(obj_reg) = self.lower_expression(object) {
                                    // Look up field index (with receiver-type disambiguation)
                                    let field_idx = self
                                        .field_index_map
                                        .get(field)
                                        .map(|&(_, idx)| idx)
                                        .or_else(|| {
                                            let field_name = self
                                                .symbol_table
                                                .get_symbol(*field)
                                                .map(|s| s.name)?;
                                            let receiver_ty = object.ty;
                                            self.resolve_field_index_by_name(
                                                field_name,
                                                receiver_ty,
                                            )
                                            .map(|(_, idx)| idx)
                                        });
                                    if let Some(idx) = field_idx {
                                        let idx_const =
                                            self.builder.build_const(IrValue::I32(idx as i32));
                                        if let Some(idx_reg) = idx_const {
                                            let field_ty = result_type.clone();
                                            let field_ptr = self.builder.build_gep(
                                                obj_reg,
                                                vec![idx_reg],
                                                field_ty.clone(),
                                            );
                                            if let Some(ptr) = field_ptr {
                                                self.builder.build_store(ptr, new_value);
                                            }
                                        }
                                    }
                                }
                            }
                            _ => {}
                        }

                        // Return appropriate value
                        let result_reg = match op {
                            HirUnaryOp::PostIncr | HirUnaryOp::PostDecr => old_value, // Post: return old value
                            HirUnaryOp::PreIncr | HirUnaryOp::PreDecr => new_value, // Pre: return new value
                            _ => unreachable!(),
                        };

                        Some(result_reg)
                    }
                    _ => {
                        // Handle other unary operators normally
                        let operand_reg = self.lower_expression(operand)?;
                        let result_reg = self
                            .builder
                            .build_unop(self.convert_unary_op(*op), operand_reg)?;

                        // Register the result with its type so Cranelift can find it
                        let result_type = self.convert_type(expr.ty);
                        let src_loc = self.convert_source_location(&expr.source_location);
                        if let Some(func) = self.builder.current_function_mut() {
                            func.locals.insert(
                                result_reg,
                                super::IrLocal {
                                    name: format!("_temp{}", result_reg.0),
                                    ty: result_type,
                                    mutable: false,
                                    source_location: src_loc,
                                    allocation: super::AllocationHint::Stack,
                                },
                            );
                        }

                        Some(result_reg)
                    }
                }
            }

            HirExprKind::Binary { op, lhs, rhs } => {
                // Handle short-circuit operators specially
                match op {
                    HirBinaryOp::And => return self.lower_logical_and(lhs, rhs),
                    HirBinaryOp::Or => return self.lower_logical_or(lhs, rhs),
                    HirBinaryOp::NullCoalesce => return self.lower_null_coalesce(lhs, rhs),
                    _ => {}
                }

                // Special handling for string concatenation with +
                if matches!(op, HirBinaryOp::Add) {
                    let lhs_type_raw = self.convert_type(lhs.ty);
                    let rhs_type_raw = self.convert_type(rhs.ty);

                    // Override types with resolved IR types for pattern-bound variables
                    let lhs_type = self.resolve_expr_ir_type(lhs, lhs_type_raw);
                    let rhs_type = self.resolve_expr_ir_type(rhs, rhs_type_raw);

                    let lhs_is_string = matches!(&lhs_type, IrType::String)
                        || matches!(&lhs_type, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::String));
                    let rhs_is_string = matches!(&rhs_type, IrType::String)
                        || matches!(&rhs_type, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::String));

                    if lhs_is_string || rhs_is_string {
                        // Lower both operands
                        let lhs_reg = self.lower_expression(lhs)?;
                        let rhs_reg = self.lower_expression(rhs)?;

                        // Use MIR register types (from runtime mapping) instead of HIR types,
                        // which may be unresolved generics (e.g. Ptr(Void) for Vec<Int>.length())
                        let lhs_mir_type = self
                            .builder
                            .get_register_type(lhs_reg)
                            .unwrap_or(lhs_type.clone());
                        let rhs_mir_type = self
                            .builder
                            .get_register_type(rhs_reg)
                            .unwrap_or(rhs_type.clone());

                        let lhs_is_string_mir = matches!(&lhs_mir_type, IrType::String)
                            || matches!(&lhs_mir_type, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::String))
                            // Defensive: if HIR type says String but MIR register is Ptr(Void)
                            // (e.g. extern/stdlib string returns), trust the HIR type
                            || (lhs_is_string && matches!(&lhs_mir_type, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::Void)));
                        let rhs_is_string_mir = matches!(&rhs_mir_type, IrType::String)
                            || matches!(&rhs_mir_type, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::String))
                            || (rhs_is_string
                                && matches!(&rhs_mir_type, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::Void)));

                        // Convert non-string operand to string if needed
                        // For class instances with toString(), call it directly at compile time
                        let lhs_str_val = if !lhs_is_string_mir {
                            if self.expr_is_value_type_expr(lhs) {
                                self.convert_value_type_to_string(lhs_reg)?
                            } else if let Some(reg) =
                                self.try_call_tostring(lhs_reg, self.resolve_expr_type_id(lhs))?
                            {
                                reg
                            } else {
                                self.convert_to_string_with_hint(
                                    lhs_reg,
                                    &lhs_mir_type,
                                    Some(lhs.ty),
                                )?
                            }
                        } else {
                            lhs_reg
                        };

                        let rhs_str_val = if !rhs_is_string_mir {
                            if self.expr_is_value_type_expr(rhs) {
                                self.convert_value_type_to_string(rhs_reg)?
                            } else if let Some(reg) =
                                self.try_call_tostring(rhs_reg, self.resolve_expr_type_id(rhs))?
                            {
                                reg
                            } else {
                                self.convert_to_string_with_hint(
                                    rhs_reg,
                                    &rhs_mir_type,
                                    Some(rhs.ty),
                                )?
                            }
                        } else {
                            rhs_reg
                        };

                        // String values are already pointers (*HaxeString):
                        // - string literals from haxe_string_literal return *mut HaxeString
                        // - conversion functions like int_to_string also return pointers
                        // Pass them directly to string_concat which expects *HaxeString args
                        let string_ptr_ty = IrType::Ptr(Box::new(IrType::String));
                        let concat_func_id = self.register_stdlib_mir_forward_ref(
                            "string_concat",
                            vec![string_ptr_ty.clone(), string_ptr_ty.clone()],
                            string_ptr_ty.clone(),
                        );

                        return self.builder.build_call_direct(
                            concat_func_id,
                            vec![lhs_str_val, rhs_str_val],
                            string_ptr_ty,
                        );
                    }
                }

                // String comparison: Eq/Ne/Lt/Le/Gt/Ge on strings need content comparison
                if matches!(
                    op,
                    HirBinaryOp::Eq
                        | HirBinaryOp::Ne
                        | HirBinaryOp::Lt
                        | HirBinaryOp::Le
                        | HirBinaryOp::Gt
                        | HirBinaryOp::Ge
                ) {
                    let lhs_type_raw = self.convert_type(lhs.ty);
                    let rhs_type_raw = self.convert_type(rhs.ty);
                    let lhs_type = self.resolve_expr_ir_type(lhs, lhs_type_raw);
                    let rhs_type = self.resolve_expr_ir_type(rhs, rhs_type_raw);

                    let lhs_is_string = matches!(&lhs_type, IrType::String)
                        || matches!(&lhs_type, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::String));
                    let rhs_is_string = matches!(&rhs_type, IrType::String)
                        || matches!(&rhs_type, IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::String));

                    if lhs_is_string && rhs_is_string {
                        let lhs_reg = self.lower_expression(lhs)?;
                        let rhs_reg = self.lower_expression(rhs)?;
                        let string_ptr_ty = IrType::Ptr(Box::new(IrType::String));
                        let cmp_func = self.get_or_register_extern_function(
                            "haxe_string_compare",
                            vec![string_ptr_ty.clone(), string_ptr_ty.clone()],
                            IrType::I32,
                        );
                        let cmp_result = self.builder.build_call_direct(
                            cmp_func,
                            vec![lhs_reg, rhs_reg],
                            IrType::I32,
                        )?;
                        let zero = self.builder.build_const(IrValue::I32(0))?;
                        let cmp_op = match op {
                            HirBinaryOp::Eq => CompareOp::Eq,
                            HirBinaryOp::Ne => CompareOp::Ne,
                            HirBinaryOp::Lt => CompareOp::Lt,
                            HirBinaryOp::Le => CompareOp::Le,
                            HirBinaryOp::Gt => CompareOp::Gt,
                            HirBinaryOp::Ge => CompareOp::Ge,
                            _ => unreachable!(),
                        };
                        return self.builder.build_cmp(cmp_op, cmp_result, zero);
                    }
                }

                // @:derive(PartialEq) field-by-field equality for class instances
                if matches!(op, HirBinaryOp::Eq | HirBinaryOp::Ne) {
                    let class_sym = {
                        let type_table = self.type_table.borrow();
                        let lhs_sym = type_table.get(lhs.ty).and_then(|t| {
                            if let TypeKind::Class { symbol_id, .. } = &t.kind {
                                Some(*symbol_id)
                            } else {
                                None
                            }
                        });
                        let rhs_sym = type_table.get(rhs.ty).and_then(|t| {
                            if let TypeKind::Class { symbol_id, .. } = &t.kind {
                                Some(*symbol_id)
                            } else {
                                None
                            }
                        });
                        match (lhs_sym, rhs_sym) {
                            (Some(l), Some(r))
                                if l == r && self.derive_partial_eq_classes.contains(&l) =>
                            {
                                Some(l)
                            }
                            _ => None,
                        }
                    };
                    if let Some(sym) = class_sym {
                        return self.lower_derived_equality(op, lhs, rhs, sym);
                    }
                }

                // @:derive(PartialOrd) lexicographic ordering for class instances
                if matches!(
                    op,
                    HirBinaryOp::Lt | HirBinaryOp::Le | HirBinaryOp::Gt | HirBinaryOp::Ge
                ) {
                    let class_sym = {
                        let type_table = self.type_table.borrow();
                        let lhs_sym = type_table.get(lhs.ty).and_then(|t| {
                            if let TypeKind::Class { symbol_id, .. } = &t.kind {
                                Some(*symbol_id)
                            } else {
                                None
                            }
                        });
                        let rhs_sym = type_table.get(rhs.ty).and_then(|t| {
                            if let TypeKind::Class { symbol_id, .. } = &t.kind {
                                Some(*symbol_id)
                            } else {
                                None
                            }
                        });
                        match (lhs_sym, rhs_sym) {
                            (Some(l), Some(r))
                                if l == r && self.derive_partial_ord_classes.contains(&l) =>
                            {
                                Some(l)
                            }
                            _ => None,
                        }
                    };
                    if let Some(sym) = class_sym {
                        return self.lower_derived_ordering(op, lhs, rhs, sym);
                    }
                }

                // Dynamic arithmetic: when both HIR types are actually Dynamic, check actual
                // MIR register types after lowering to determine if values are truly boxed
                // DynamicValue pointers vs raw concrete values (e.g., class field access on
                // Dynamic-typed object, or integer arithmetic result with Dynamic HIR type).
                // NOTE: We check the actual HIR TypeKind, not just MIR Ptr(Void), because
                // class types also lower to Ptr(Void) but are NOT boxed DynamicValues.
                {
                    let (lhs_is_dyn, rhs_is_dyn) = {
                        let type_table = self.type_table.borrow();
                        let lhs_dyn = type_table
                            .get(lhs.ty)
                            .map(|t| matches!(t.kind, TypeKind::Dynamic))
                            .unwrap_or(false);
                        let rhs_dyn = type_table
                            .get(rhs.ty)
                            .map(|t| matches!(t.kind, TypeKind::Dynamic))
                            .unwrap_or(false);
                        (lhs_dyn, rhs_dyn)
                    };

                    if lhs_is_dyn && rhs_is_dyn {
                        let is_supported = matches!(
                            op,
                            HirBinaryOp::Add
                                | HirBinaryOp::Sub
                                | HirBinaryOp::Mul
                                | HirBinaryOp::Div
                                | HirBinaryOp::Mod
                                | HirBinaryOp::Eq
                                | HirBinaryOp::Lt
                                | HirBinaryOp::Gt
                                | HirBinaryOp::Le
                                | HirBinaryOp::Ge
                                | HirBinaryOp::Ne
                        );
                        if is_supported {
                            // Lower operands first, then check actual register types
                            let lhs_reg = self.lower_expression(lhs)?;
                            let rhs_reg = self.lower_expression(rhs)?;

                            // Determine if each operand is actually a boxed DynamicValue:
                            // - Variables: use boxed_dynamic_symbols tracking (handles lambda
                            //   params that have Dynamic type but hold raw i64 values)
                            // - Other expressions: check actual MIR register type — concrete
                            //   types (I32, F64, etc.) are definitely not boxed pointers
                            let is_concrete_ir_type = |ty: &IrType| -> bool {
                                matches!(
                                    ty,
                                    IrType::I8
                                        | IrType::I16
                                        | IrType::I32
                                        | IrType::I64
                                        | IrType::U8
                                        | IrType::U16
                                        | IrType::U32
                                        | IrType::U64
                                        | IrType::F32
                                        | IrType::F64
                                        | IrType::Bool
                                )
                            };

                            let lhs_boxed = match &lhs.kind {
                                HirExprKind::Variable { symbol, .. } => {
                                    self.boxed_dynamic_symbols.contains(symbol)
                                }
                                _ => {
                                    let ty = self.builder.get_register_type(lhs_reg);
                                    !ty.as_ref().map(|t| is_concrete_ir_type(t)).unwrap_or(false)
                                }
                            };
                            let rhs_boxed = match &rhs.kind {
                                HirExprKind::Variable { symbol, .. } => {
                                    self.boxed_dynamic_symbols.contains(symbol)
                                }
                                _ => {
                                    let ty = self.builder.get_register_type(rhs_reg);
                                    !ty.as_ref().map(|t| is_concrete_ir_type(t)).unwrap_or(false)
                                }
                            };

                            if lhs_boxed && rhs_boxed {
                                // Both are actually boxed DynamicValue pointers.
                                // Unbox to f64, operate, rebox.
                                let ptr_void = IrType::Ptr(Box::new(IrType::Void));
                                let unbox_func = self.get_or_register_extern_function(
                                    "haxe_unbox_float_ptr",
                                    vec![ptr_void.clone()],
                                    IrType::F64,
                                );
                                let lhs_f64 = self.builder.build_call_direct(
                                    unbox_func,
                                    vec![lhs_reg],
                                    IrType::F64,
                                )?;
                                let rhs_f64 = self.builder.build_call_direct(
                                    unbox_func,
                                    vec![rhs_reg],
                                    IrType::F64,
                                )?;

                                let is_comparison = matches!(
                                    op,
                                    HirBinaryOp::Eq
                                        | HirBinaryOp::Ne
                                        | HirBinaryOp::Lt
                                        | HirBinaryOp::Le
                                        | HirBinaryOp::Gt
                                        | HirBinaryOp::Ge
                                );

                                if is_comparison {
                                    let cmp_op = match op {
                                        HirBinaryOp::Eq => CompareOp::Eq,
                                        HirBinaryOp::Ne => CompareOp::Ne,
                                        HirBinaryOp::Lt => CompareOp::Lt,
                                        HirBinaryOp::Le => CompareOp::Le,
                                        HirBinaryOp::Gt => CompareOp::Gt,
                                        HirBinaryOp::Ge => CompareOp::Ge,
                                        _ => unreachable!(),
                                    };
                                    return self.builder.build_cmp(cmp_op, lhs_f64, rhs_f64);
                                } else {
                                    let bin_op = match op {
                                        HirBinaryOp::Add => BinaryOp::FAdd,
                                        HirBinaryOp::Sub => BinaryOp::FSub,
                                        HirBinaryOp::Mul => BinaryOp::FMul,
                                        HirBinaryOp::Div => BinaryOp::FDiv,
                                        HirBinaryOp::Mod => BinaryOp::FRem,
                                        _ => unreachable!(),
                                    };
                                    let result_f64 =
                                        self.builder.build_binop(bin_op, lhs_f64, rhs_f64)?;

                                    let box_func = self.get_or_register_extern_function(
                                        "haxe_box_float_ptr",
                                        vec![IrType::F64],
                                        IrType::Ptr(Box::new(IrType::U8)),
                                    );
                                    return self.builder.build_call_direct(
                                        box_func,
                                        vec![result_f64],
                                        IrType::Ptr(Box::new(IrType::U8)),
                                    );
                                }
                            }

                            // At least one operand is NOT boxed — it's a raw concrete value
                            // with Dynamic HIR type (e.g., class field access, integer arithmetic).
                            // Handle mixed boxed+concrete and fully concrete cases.
                            let mut effective_lhs = lhs_reg;
                            let mut effective_rhs = rhs_reg;

                            // Unbox boxed side if mixed (one boxed, one concrete)
                            if lhs_boxed && !rhs_boxed {
                                let rhs_ty = self
                                    .builder
                                    .get_register_type(rhs_reg)
                                    .unwrap_or(IrType::I64);
                                let ptr_void = IrType::Ptr(Box::new(IrType::Void));
                                if matches!(rhs_ty, IrType::F32 | IrType::F64) {
                                    let unbox = self.get_or_register_extern_function(
                                        "haxe_unbox_float_ptr",
                                        vec![ptr_void],
                                        IrType::F64,
                                    );
                                    effective_lhs = self.builder.build_call_direct(
                                        unbox,
                                        vec![lhs_reg],
                                        IrType::F64,
                                    )?;
                                } else {
                                    let unbox = self.get_or_register_extern_function(
                                        "haxe_unbox_int_ptr",
                                        vec![ptr_void],
                                        IrType::I64,
                                    );
                                    effective_lhs = self.builder.build_call_direct(
                                        unbox,
                                        vec![lhs_reg],
                                        IrType::I64,
                                    )?;
                                }
                            } else if !lhs_boxed && rhs_boxed {
                                let lhs_ty = self
                                    .builder
                                    .get_register_type(lhs_reg)
                                    .unwrap_or(IrType::I64);
                                let ptr_void = IrType::Ptr(Box::new(IrType::Void));
                                if matches!(lhs_ty, IrType::F32 | IrType::F64) {
                                    let unbox = self.get_or_register_extern_function(
                                        "haxe_unbox_float_ptr",
                                        vec![ptr_void],
                                        IrType::F64,
                                    );
                                    effective_rhs = self.builder.build_call_direct(
                                        unbox,
                                        vec![rhs_reg],
                                        IrType::F64,
                                    )?;
                                } else {
                                    let unbox = self.get_or_register_extern_function(
                                        "haxe_unbox_int_ptr",
                                        vec![ptr_void],
                                        IrType::I64,
                                    );
                                    effective_rhs = self.builder.build_call_direct(
                                        unbox,
                                        vec![rhs_reg],
                                        IrType::I64,
                                    )?;
                                }
                            }

                            // Use actual register types for type coercion
                            let eff_lhs_ty = self
                                .builder
                                .get_register_type(effective_lhs)
                                .unwrap_or(IrType::I64);
                            let eff_rhs_ty = self
                                .builder
                                .get_register_type(effective_rhs)
                                .unwrap_or(IrType::I64);

                            let l_is_int = matches!(
                                eff_lhs_ty,
                                IrType::I8
                                    | IrType::I16
                                    | IrType::I32
                                    | IrType::I64
                                    | IrType::U8
                                    | IrType::U16
                                    | IrType::U32
                                    | IrType::U64
                            );
                            let r_is_int = matches!(
                                eff_rhs_ty,
                                IrType::I8
                                    | IrType::I16
                                    | IrType::I32
                                    | IrType::I64
                                    | IrType::U8
                                    | IrType::U16
                                    | IrType::U32
                                    | IrType::U64
                            );
                            let l_is_float = matches!(eff_lhs_ty, IrType::F32 | IrType::F64);
                            let r_is_float = matches!(eff_rhs_ty, IrType::F32 | IrType::F64);

                            if l_is_int && r_is_float {
                                effective_lhs = self.builder.build_cast(
                                    effective_lhs,
                                    eff_lhs_ty.clone(),
                                    IrType::F64,
                                )?;
                            }
                            if r_is_int && l_is_float {
                                effective_rhs = self.builder.build_cast(
                                    effective_rhs,
                                    eff_rhs_ty.clone(),
                                    IrType::F64,
                                )?;
                            }
                            if matches!(op, HirBinaryOp::Div) && l_is_int && r_is_int {
                                effective_lhs = self.builder.build_cast(
                                    effective_lhs,
                                    eff_lhs_ty.clone(),
                                    IrType::F64,
                                )?;
                                effective_rhs = self.builder.build_cast(
                                    effective_rhs,
                                    eff_rhs_ty.clone(),
                                    IrType::F64,
                                )?;
                            }

                            let result_reg = match self.convert_binary_op_to_mir(*op) {
                                MirBinaryOp::Binary(bin_op) => self.builder.build_binop(
                                    bin_op,
                                    effective_lhs,
                                    effective_rhs,
                                )?,
                                MirBinaryOp::Compare(cmp_op) => {
                                    self.builder
                                        .build_cmp(cmp_op, effective_lhs, effective_rhs)?
                                }
                            };
                            return Some(result_reg);
                        }
                    }

                    // Mixed Dynamic + concrete arithmetic:
                    // One operand is Dynamic, the other is a concrete primitive.
                    // Distinguish boxed DynamicValue* (Ptr(U8)) from type-erased raw values
                    // (Ptr(Void)). Only unbox Ptr(U8); cast Ptr(Void) to integer.
                    if (lhs_is_dyn || rhs_is_dyn) && !(lhs_is_dyn && rhs_is_dyn) {
                        let is_arith = matches!(
                            op,
                            HirBinaryOp::Add
                                | HirBinaryOp::Sub
                                | HirBinaryOp::Mul
                                | HirBinaryOp::Div
                                | HirBinaryOp::Mod
                                | HirBinaryOp::Eq
                                | HirBinaryOp::Lt
                                | HirBinaryOp::Gt
                                | HirBinaryOp::Le
                                | HirBinaryOp::Ge
                                | HirBinaryOp::Ne
                        );
                        if is_arith {
                            let mut lhs_reg = self.lower_expression(lhs)?;
                            let mut rhs_reg = self.lower_expression(rhs)?;

                            // Determine concrete type from the non-Dynamic side
                            let concrete_ty = if lhs_is_dyn {
                                self.builder
                                    .get_register_type(rhs_reg)
                                    .unwrap_or(IrType::I32)
                            } else {
                                self.builder
                                    .get_register_type(lhs_reg)
                                    .unwrap_or(IrType::I32)
                            };

                            let is_float = matches!(concrete_ty, IrType::F32 | IrType::F64);

                            // Coerce the Dynamic-side register to match the concrete type.
                            // Uses haxe_coerce_dynamic_to_int/float which handles both
                            // boxed DynamicValue* and type-erased raw integers at runtime.
                            let coerce_dyn = |s: &mut Self, reg: IrId| -> Option<IrId> {
                                let reg_ty = s.builder.get_register_type(reg);
                                // Already concrete? No coercion needed.
                                if reg_ty
                                    .as_ref()
                                    .map(|t| {
                                        matches!(
                                            t,
                                            IrType::I32
                                                | IrType::I64
                                                | IrType::F32
                                                | IrType::F64
                                                | IrType::Bool
                                        )
                                    })
                                    .unwrap_or(false)
                                {
                                    return Some(reg);
                                }
                                let ptr_void = IrType::Ptr(Box::new(IrType::Void));
                                if is_float {
                                    let f = s.get_or_register_extern_function(
                                        "haxe_coerce_dynamic_to_float",
                                        vec![ptr_void],
                                        IrType::F64,
                                    );
                                    s.builder.build_call_direct(f, vec![reg], IrType::F64)
                                } else {
                                    let f = s.get_or_register_extern_function(
                                        "haxe_coerce_dynamic_to_int",
                                        vec![ptr_void],
                                        IrType::I64,
                                    );
                                    let v =
                                        s.builder.build_call_direct(f, vec![reg], IrType::I64)?;
                                    Some(
                                        s.builder
                                            .build_cast(v, IrType::I64, concrete_ty.clone())
                                            .unwrap_or(v),
                                    )
                                }
                            };

                            if lhs_is_dyn {
                                lhs_reg = coerce_dyn(self, lhs_reg)?;
                            } else {
                                rhs_reg = coerce_dyn(self, rhs_reg)?;
                            }

                            let mir_op = self.convert_binary_op_to_mir(*op);
                            let result_reg = match mir_op {
                                MirBinaryOp::Binary(arith_op) => {
                                    self.builder.build_binop(arith_op, lhs_reg, rhs_reg)?
                                }
                                MirBinaryOp::Compare(cmp_op) => {
                                    self.builder.build_cmp(cmp_op, lhs_reg, rhs_reg)?
                                }
                            };
                            return Some(result_reg);
                        }
                    }
                }

                let mut lhs_reg = self.lower_expression(lhs)?;
                let mut rhs_reg = self.lower_expression(rhs)?;

                let lhs_type = self.convert_type(lhs.ty);
                let rhs_type = self.convert_type(rhs.ty);

                // Type coercion for mixed int/float operations
                // When one operand is float and the other is int, cast int to float
                let lhs_is_int = matches!(
                    lhs_type,
                    IrType::I8
                        | IrType::I16
                        | IrType::I32
                        | IrType::I64
                        | IrType::U8
                        | IrType::U16
                        | IrType::U32
                        | IrType::U64
                );
                let rhs_is_int = matches!(
                    rhs_type,
                    IrType::I8
                        | IrType::I16
                        | IrType::I32
                        | IrType::I64
                        | IrType::U8
                        | IrType::U16
                        | IrType::U32
                        | IrType::U64
                );
                let lhs_is_float = matches!(lhs_type, IrType::F32 | IrType::F64);
                let rhs_is_float = matches!(rhs_type, IrType::F32 | IrType::F64);

                // Cast int to float when mixing types (promotes to F64)
                if lhs_is_int && rhs_is_float {
                    lhs_reg = self
                        .builder
                        .build_cast(lhs_reg, lhs_type.clone(), IrType::F64)?;
                }
                if rhs_is_int && lhs_is_float {
                    rhs_reg = self
                        .builder
                        .build_cast(rhs_reg, rhs_type.clone(), IrType::F64)?;
                }

                // Special handling for division: Haxe always returns Float from division
                // If operands are integers, convert them to float first
                if matches!(op, HirBinaryOp::Div) && lhs_is_int && rhs_is_int {
                    lhs_reg = self
                        .builder
                        .build_cast(lhs_reg, lhs_type.clone(), IrType::F64)?;
                    rhs_reg = self
                        .builder
                        .build_cast(rhs_reg, rhs_type.clone(), IrType::F64)?;
                }

                // Check if result is a SIMD vector type — emit VectorBinOp directly (zero overhead)
                // We check operand types (from register_types) rather than convert_type(expr.ty)
                // because @:coreType abstracts may not resolve correctly through convert_type.
                let lhs_actual_type = self
                    .builder
                    .get_register_type(lhs_reg)
                    .unwrap_or(IrType::I64);
                let result_type = if lhs_actual_type.is_vector() {
                    lhs_actual_type.clone()
                } else {
                    self.convert_type(expr.ty)
                };
                let result_reg = if result_type.is_vector() {
                    let bin_op = match op {
                        HirBinaryOp::Add => BinaryOp::Add,
                        HirBinaryOp::Sub => BinaryOp::Sub,
                        HirBinaryOp::Mul => BinaryOp::Mul,
                        HirBinaryOp::Div => BinaryOp::Div,
                        _ => {
                            debug!("Unsupported vector binary op: {:?}", op);
                            return None;
                        }
                    };
                    self.builder.build_vector_binop(
                        bin_op,
                        lhs_reg,
                        rhs_reg,
                        result_type.clone(),
                    )?
                } else {
                    match self.convert_binary_op_to_mir(*op) {
                        MirBinaryOp::Binary(bin_op) => {
                            self.builder.build_binop(bin_op, lhs_reg, rhs_reg)?
                        }
                        MirBinaryOp::Compare(cmp_op) => {
                            self.builder.build_cmp(cmp_op, lhs_reg, rhs_reg)?
                        }
                    }
                };
                let src_loc = self.convert_source_location(&expr.source_location);
                if let Some(func) = self.builder.current_function_mut() {
                    func.locals.insert(
                        result_reg,
                        super::IrLocal {
                            name: format!("_temp{}", result_reg.0),
                            ty: result_type,
                            mutable: false,
                            source_location: src_loc,
                            allocation: super::AllocationHint::Stack,
                        },
                    );
                }

                Some(result_reg)
            }

            HirExprKind::Cast {
                expr,
                target,
                is_safe,
            } => {
                // Collapse double-cast pattern from abstract methods:
                // Cast(safe, target=Int) { Cast(unsafe, target=Dynamic) { This/Variable } }
                // This pattern comes from `(cast this : Int)` syntax in abstract methods.
                // The inner `cast this` (→Dynamic) is a no-op for abstract types, and the
                // outer `(... : Int)` extracts the underlying value. Collapse to just the
                // innermost expression.
                if let HirExprKind::Cast {
                    expr: inner_expr,
                    target: inner_target,
                    is_safe: false,
                } = &expr.kind
                {
                    let inner_target_is_dynamic = {
                        let type_table = self.type_table.borrow();
                        type_table
                            .get(*inner_target)
                            .map(|t| matches!(t.kind, TypeKind::Dynamic))
                            .unwrap_or(false)
                    };
                    let inner_source_is_abstract = {
                        let type_table = self.type_table.borrow();
                        type_table
                            .get(inner_expr.ty)
                            .map(|t| matches!(t.kind, TypeKind::Abstract { .. }))
                            .unwrap_or(false)
                    };
                    if inner_target_is_dynamic && inner_source_is_abstract {
                        // The whole double-cast is an identity: abstract → dynamic → underlying
                        // Just lower the innermost expression directly
                        return self.lower_expression(inner_expr);
                    }
                }

                // Check if target is an abstract type with @:from conversion rules
                // This generalizes the SIMD4f path to work with any abstract
                if let Some(converted) = self.try_abstract_from_cast(expr, *target) {
                    return Some(converted);
                }

                let from_type = self.convert_type(expr.ty);
                let to_type = self.convert_type(*target);

                // For abstract types, the cast between abstract and underlying is a no-op
                // (they share the same MIR type).
                // BUT: for safe casts between class types, we must NOT skip — even though
                // both are Ptr(Void), the runtime needs to verify the class hierarchy.
                if from_type == to_type && !*is_safe {
                    return self.lower_expression(expr);
                }
                if from_type == to_type && *is_safe {
                    // Same MIR type — but for class/interface types, fall through to
                    // the type-kind handlers for runtime verification and fat pointer wrapping.
                    let type_table = self.type_table.borrow();
                    let src_kind = type_table.get(expr.ty).map(|t| &t.kind).cloned();
                    let tgt_kind = type_table.get(*target).map(|t| &t.kind).cloned();
                    drop(type_table);
                    let needs_runtime_check = matches!(
                        (&src_kind, &tgt_kind),
                        (Some(TypeKind::Class { .. }), Some(TypeKind::Class { .. }))
                            | (
                                Some(TypeKind::Class { .. }),
                                Some(TypeKind::Interface { .. })
                            )
                            | (
                                Some(TypeKind::Interface { .. }),
                                Some(TypeKind::Class { .. })
                            )
                            | (
                                Some(TypeKind::Interface { .. }),
                                Some(TypeKind::Interface { .. })
                            )
                    );
                    if !needs_runtime_check {
                        return self.lower_expression(expr);
                    }
                    // Fall through to Class→Class safe cast handler
                }

                // For `cast this` in abstract methods: the source is Abstract (resolves to
                // underlying e.g. I32) but target is Dynamic (Ptr(U8)). This is NOT a real
                // Dynamic boxing — it's just the Haxe syntax for extracting the underlying
                // value. Skip the cast to avoid reinterpreting integers as pointers.
                // Also handle the case where `cast this` target is Dynamic and the source
                // is a primitive type (the underlying type of the abstract).
                {
                    let type_table = self.type_table.borrow();
                    let source_kind = type_table.get(expr.ty).map(|t| t.kind.clone());
                    let target_kind = type_table.get(*target).map(|t| t.kind.clone());
                    drop(type_table);

                    let source_is_abstract =
                        matches!(&source_kind, Some(TypeKind::Abstract { .. }));
                    let target_is_dynamic = matches!(&target_kind, Some(TypeKind::Dynamic));

                    if source_is_abstract && target_is_dynamic {
                        return self.lower_expression(expr);
                    }

                    // Also handle: source is concrete primitive, target is Dynamic,
                    // inside an abstract method body where `this` was registered as
                    // the underlying type. `cast this` produces
                    // Cast(This(underlying_type) → Dynamic), which is a no-op.
                    if target_is_dynamic
                        && !*is_safe
                        && matches!(
                            &source_kind,
                            Some(TypeKind::Int)
                                | Some(TypeKind::Float)
                                | Some(TypeKind::Bool)
                                | Some(TypeKind::String)
                        )
                        && matches!(&expr.kind, HirExprKind::This)
                    {
                        return self.lower_expression(expr);
                    }
                }

                // For unsafe casts, emit a direct cast instruction (no runtime check).
                // For safe casts, we need to fall through to the type-specific
                // handling even when MIR types match (e.g., Class→Class are both
                // Ptr(U8) but need runtime hierarchy verification).
                if !*is_safe {
                    let value_reg = self.lower_expression(expr)?;
                    return self.builder.build_cast(value_reg, from_type, to_type);
                }

                // Safe cast: resolve at compile time based on source/target type kinds
                let source_kind = {
                    let type_table = self.type_table.borrow();
                    type_table.get(expr.ty).map(|ti| ti.kind.clone())
                };
                let target_kind = {
                    let type_table = self.type_table.borrow();
                    type_table.get(*target).map(|ti| ti.kind.clone())
                };

                match (&source_kind, &target_kind) {
                    // Primitive-to-primitive: always succeeds, emit static conversion
                    (Some(TypeKind::Int), Some(TypeKind::Float))
                    | (Some(TypeKind::Float), Some(TypeKind::Int))
                    | (Some(TypeKind::Int), Some(TypeKind::Bool))
                    | (Some(TypeKind::Bool), Some(TypeKind::Int))
                    | (Some(TypeKind::Float), Some(TypeKind::Bool))
                    | (Some(TypeKind::Bool), Some(TypeKind::Float)) => {
                        let value_reg = self.lower_expression(expr)?;
                        self.builder.build_cast(value_reg, from_type, to_type)
                    }

                    // Dynamic → primitive type: unbox the DynamicValue
                    // But skip unboxing if the source register is already a raw
                    // primitive (e.g., `cast this` in enum abstract methods where
                    // `this` is the underlying Int value, not a boxed DynamicValue*).
                    (Some(TypeKind::Dynamic), Some(TypeKind::Int)) => {
                        let value_reg = self.lower_expression(expr)?;
                        let reg_ty = self.builder.get_register_type(value_reg);
                        if matches!(
                            reg_ty,
                            Some(IrType::I32) | Some(IrType::I64) | Some(IrType::U32)
                        ) {
                            // Already a raw integer — cast to I32 if needed
                            if matches!(reg_ty, Some(IrType::I32)) {
                                Some(value_reg)
                            } else {
                                self.builder
                                    .build_cast(value_reg, reg_ty.unwrap(), IrType::I32)
                            }
                        } else {
                            let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                            let unbox_id = self.get_or_register_extern_function(
                                "haxe_unbox_int_ptr",
                                vec![ptr_u8],
                                IrType::I32,
                            );
                            self.builder
                                .build_call_direct(unbox_id, vec![value_reg], IrType::I32)
                        }
                    }
                    (Some(TypeKind::Dynamic), Some(TypeKind::Float)) => {
                        let value_reg = self.lower_expression(expr)?;
                        let reg_ty = self.builder.get_register_type(value_reg);
                        if matches!(reg_ty, Some(IrType::F32) | Some(IrType::F64)) {
                            if matches!(reg_ty, Some(IrType::F64)) {
                                Some(value_reg)
                            } else {
                                self.builder.build_cast(value_reg, IrType::F32, IrType::F64)
                            }
                        } else {
                            let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                            let unbox_id = self.get_or_register_extern_function(
                                "haxe_unbox_float_ptr",
                                vec![ptr_u8],
                                IrType::F64,
                            );
                            self.builder
                                .build_call_direct(unbox_id, vec![value_reg], IrType::F64)
                        }
                    }
                    (Some(TypeKind::Dynamic), Some(TypeKind::Bool)) => {
                        let value_reg = self.lower_expression(expr)?;
                        let reg_ty = self.builder.get_register_type(value_reg);
                        if matches!(reg_ty, Some(IrType::Bool)) {
                            Some(value_reg)
                        } else {
                            let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                            let unbox_id = self.get_or_register_extern_function(
                                "haxe_unbox_bool_ptr",
                                vec![ptr_u8],
                                IrType::Bool,
                            );
                            self.builder
                                .build_call_direct(unbox_id, vec![value_reg], IrType::Bool)
                        }
                    }
                    // Dynamic → non-primitive type: runtime downcast (null on failure)
                    (Some(TypeKind::Dynamic), _)
                        if !matches!(&target_kind, Some(TypeKind::Dynamic)) =>
                    {
                        let value_reg = self.lower_expression(expr)?;
                        // DynamicValue boxing uses TAST TypeId (value_ty.as_raw()),
                        // so downcast comparison must also use TAST TypeId for consistency.
                        let type_id_const = self
                            .builder
                            .build_const(IrValue::I64(target.as_raw() as i64))?;
                        let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                        let downcast_id = self.get_or_register_extern_function(
                            "haxe_std_downcast",
                            vec![ptr_u8.clone(), IrType::I64],
                            ptr_u8.clone(),
                        );
                        self.builder.build_call_direct(
                            downcast_id,
                            vec![value_reg, type_id_const],
                            ptr_u8,
                        )
                    }

                    // Concrete → Dynamic: box the value
                    (_, Some(TypeKind::Dynamic)) => {
                        let value_reg = self.lower_expression(expr)?;
                        self.maybe_box_value(value_reg, expr.ty, *target)
                            .or(Some(value_reg))
                    }

                    // Class → Class safe cast: runtime downcast via object header
                    (
                        Some(TypeKind::Class {
                            symbol_id: src_sym, ..
                        }),
                        Some(TypeKind::Class {
                            symbol_id: tgt_sym, ..
                        }),
                    ) => {
                        let src_sym = *src_sym;
                        let tgt_sym = *tgt_sym;
                        let value_reg = self.lower_expression(expr)?;

                        if src_sym == tgt_sym || self.is_subclass_of(expr.ty, *target) {
                            // Same class or upcast: always succeeds
                            self.builder.build_cast(value_reg, from_type, to_type)
                        } else {
                            // Downcast or unrelated: runtime check via object header.
                            // haxe_safe_downcast_class reads raw TypeId from offset 0,
                            // walks hierarchy, and returns obj_ptr or null.
                            // Must resolve MIR runtime type_id to match object headers.
                            // Object headers store resolve_runtime_class_type_id().as_raw()
                            // (the New handler subtracts 1000 from runtime_type_id()).
                            let resolved = self.resolve_runtime_class_type_id(*target, tgt_sym);
                            let target_type_id = resolved.as_raw() as i64;
                            let type_id_const =
                                self.builder.build_const(IrValue::I64(target_type_id))?;
                            let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                            let downcast_func = self.get_or_register_extern_function(
                                "haxe_safe_downcast_class",
                                vec![ptr_u8.clone(), IrType::I64],
                                ptr_u8.clone(),
                            );
                            self.builder.build_call_direct(
                                downcast_func,
                                vec![value_reg, type_id_const],
                                ptr_u8,
                            )
                        }
                    }

                    // Class → Interface safe cast: wrap in fat pointer if implements, null if not
                    (
                        Some(TypeKind::Class {
                            symbol_id: src_sym, ..
                        }),
                        Some(TypeKind::Interface {
                            symbol_id: tgt_sym, ..
                        }),
                    ) => {
                        let src_sym = *src_sym;
                        let tgt_sym = *tgt_sym;

                        // Check at compile time if this class implements the interface
                        if self.interface_vtables.contains_key(&(src_sym, tgt_sym)) {
                            // Known to implement — wrap in fat pointer here.
                            // Cannot defer to Let handler because SafeCast's result type
                            // is the interface type, so Let would see Interface→Interface
                            // instead of Class→Interface.
                            let value_reg = self.lower_expression(expr)?;
                            match self.wrap_in_interface_fat_ptr(value_reg, src_sym, tgt_sym) {
                                Some(fat_ptr) => Some(fat_ptr),
                                None => Some(value_reg),
                            }
                        } else {
                            // Not known to implement at compile time — return null
                            self.builder.build_const(IrValue::Null)
                        }
                    }

                    // Interface → Class safe cast: extract raw obj + downcast
                    (
                        Some(TypeKind::Interface { .. }),
                        Some(TypeKind::Class {
                            symbol_id: tgt_sym, ..
                        }),
                    ) => {
                        let tgt_sym = *tgt_sym;
                        let value_reg = self.lower_expression(expr)?;

                        // Load raw object pointer from fat pointer offset 0
                        let raw_obj = self
                            .builder
                            .build_load(value_reg, IrType::Ptr(Box::new(IrType::U8)))?;

                        // Downcast via object header type_id check
                        let resolved = self.resolve_runtime_class_type_id(*target, tgt_sym);
                        let target_type_id = resolved.as_raw() as i64;
                        let type_id_const =
                            self.builder.build_const(IrValue::I64(target_type_id))?;
                        let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                        let downcast_func = self.get_or_register_extern_function(
                            "haxe_safe_downcast_class",
                            vec![ptr_u8.clone(), IrType::I64],
                            ptr_u8.clone(),
                        );
                        self.builder.build_call_direct(
                            downcast_func,
                            vec![raw_obj, type_id_const],
                            ptr_u8,
                        )
                    }

                    // Interface → Interface: pass-through cast (both are fat pointers)
                    (Some(TypeKind::Interface { .. }), Some(TypeKind::Interface { .. })) => {
                        let value_reg = self.lower_expression(expr)?;
                        self.builder.build_cast(value_reg, from_type, to_type)
                    }

                    // Fallback: emit raw cast (same as unsafe)
                    _ => {
                        let value_reg = self.lower_expression(expr)?;
                        self.builder.build_cast(value_reg, from_type, to_type)
                    }
                }
            }

            HirExprKind::TypeCheck { expr, expected } => {
                // (expr is Type) — compile-time type check for statically-typed code
                let source_kind = {
                    let type_table = self.type_table.borrow();
                    type_table.get(expr.ty).map(|ti| ti.kind.clone())
                };
                let target_kind = {
                    let type_table = self.type_table.borrow();
                    type_table.get(*expected).map(|ti| ti.kind.clone())
                };

                // For statically-typed code, resolve at compile time
                let result = match (&source_kind, &target_kind) {
                    // Dynamic source: runtime type check via haxe_std_is
                    (Some(TypeKind::Dynamic), _) => {
                        let value_reg = self.lower_expression(expr)?;
                        let rt_type_id = self.runtime_type_id(*expected);
                        let type_id_const =
                            self.builder.build_const(IrValue::I64(rt_type_id as i64))?;
                        let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                        let is_func_id = self.get_or_register_extern_function(
                            "haxe_std_is",
                            vec![ptr_u8, IrType::I64],
                            IrType::Bool,
                        );
                        self.builder.build_call_direct(
                            is_func_id,
                            vec![value_reg, type_id_const],
                            IrType::Bool,
                        )
                    }
                    // Same type kind → always true (but null check needed for refs)
                    _ if expr.ty == *expected => {
                        // Exact same type → true
                        self.builder.build_const(IrValue::Bool(true))
                    }
                    // Primitive type checks
                    (Some(TypeKind::Int), Some(TypeKind::Int))
                    | (Some(TypeKind::Float), Some(TypeKind::Float))
                    | (Some(TypeKind::Bool), Some(TypeKind::Bool))
                    | (Some(TypeKind::String), Some(TypeKind::String)) => {
                        self.builder.build_const(IrValue::Bool(true))
                    }
                    // Cross-primitive: always false
                    (Some(TypeKind::Int), Some(TypeKind::Float))
                    | (Some(TypeKind::Float), Some(TypeKind::Int))
                    | (Some(TypeKind::Int), Some(TypeKind::String))
                    | (Some(TypeKind::String), Some(TypeKind::Int))
                    | (Some(TypeKind::Float), Some(TypeKind::String))
                    | (Some(TypeKind::String), Some(TypeKind::Float))
                    | (Some(TypeKind::Bool), Some(TypeKind::Int))
                    | (Some(TypeKind::Int), Some(TypeKind::Bool))
                    | (Some(TypeKind::Bool), Some(TypeKind::Float))
                    | (Some(TypeKind::Float), Some(TypeKind::Bool)) => {
                        self.builder.build_const(IrValue::Bool(false))
                    }
                    // Class-to-class: check class hierarchy at compile time
                    (
                        Some(TypeKind::Class {
                            symbol_id: src_sym, ..
                        }),
                        Some(TypeKind::Class {
                            symbol_id: tgt_sym, ..
                        }),
                    ) => {
                        let src_sym = *src_sym;
                        let tgt_sym = *tgt_sym;
                        if src_sym == tgt_sym {
                            // Same class → true
                            let _value = self.lower_expression(expr);
                            self.builder.build_const(IrValue::Bool(true))
                        } else if self.is_subclass_of(expr.ty, *expected) {
                            // Source is subclass of target (upcast) → always true
                            let _value = self.lower_expression(expr);
                            self.builder.build_const(IrValue::Bool(true))
                        } else if self.is_subclass_of(*expected, expr.ty) {
                            // Target is subclass of source (downcast) →
                            // runtime check via object header
                            let value_reg = self.lower_expression(expr)?;
                            let target_type_id = tgt_sym.as_raw() as i64;
                            let type_id_const =
                                self.builder.build_const(IrValue::I64(target_type_id))?;
                            let ptr_void = IrType::Ptr(Box::new(IrType::Void));
                            let is_func = self.get_or_register_extern_function(
                                "haxe_object_is_instance",
                                vec![ptr_void, IrType::I64],
                                IrType::I64,
                            );
                            let result_i64 = self.builder.build_call_direct(
                                is_func,
                                vec![value_reg, type_id_const],
                                IrType::I64,
                            )?;
                            // Convert i64 (0/1) to Bool
                            let zero = self.builder.build_const(IrValue::I64(0))?;
                            self.builder.build_cmp(CompareOp::Ne, result_i64, zero)
                        } else {
                            // Unrelated classes → false
                            let _value = self.lower_expression(expr);
                            self.builder.build_const(IrValue::Bool(false))
                        }
                    }
                    // Class -> Interface: runtime check against registered interface impl map.
                    (Some(TypeKind::Class { .. }), Some(TypeKind::Interface { .. })) => {
                        let value_reg = self.lower_expression(expr)?;
                        let target_type_id = self.runtime_type_id(*expected) as i64;
                        let type_id_const =
                            self.builder.build_const(IrValue::I64(target_type_id))?;
                        let ptr_void = IrType::Ptr(Box::new(IrType::Void));
                        let is_func = self.get_or_register_extern_function(
                            "haxe_object_is_instance",
                            vec![ptr_void, IrType::I64],
                            IrType::I64,
                        );
                        let result_i64 = self.builder.build_call_direct(
                            is_func,
                            vec![value_reg, type_id_const],
                            IrType::I64,
                        )?;
                        let zero = self.builder.build_const(IrValue::I64(0))?;
                        self.builder.build_cmp(CompareOp::Ne, result_i64, zero)
                    }
                    // Class vs primitive or other unrelated → false
                    (Some(TypeKind::Class { .. }), Some(TypeKind::Int))
                    | (Some(TypeKind::Class { .. }), Some(TypeKind::Float))
                    | (Some(TypeKind::Class { .. }), Some(TypeKind::Bool))
                    | (Some(TypeKind::Class { .. }), Some(TypeKind::String))
                    | (Some(TypeKind::Int), Some(TypeKind::Class { .. }))
                    | (Some(TypeKind::Float), Some(TypeKind::Class { .. }))
                    | (Some(TypeKind::Bool), Some(TypeKind::Class { .. }))
                    | (Some(TypeKind::String), Some(TypeKind::Class { .. })) => {
                        let _value = self.lower_expression(expr);
                        self.builder.build_const(IrValue::Bool(false))
                    }
                    // Fallback: lower the expression (for side effects) and return true
                    // (trust static types — proper runtime checks need object headers)
                    _ => {
                        let _value = self.lower_expression(expr);
                        self.builder.build_const(IrValue::Bool(true))
                    }
                };
                result
            }

            HirExprKind::If {
                condition,
                then_expr,
                else_expr,
            } => self.lower_conditional_typed(condition, then_expr, else_expr, Some(expr.ty)),

            HirExprKind::Block(block) => self.lower_block_expr(block),

            HirExprKind::Lambda {
                params,
                body,
                captures,
            } => {
                debug!(
                    "Lowering lambda with {} params, {} captures",
                    params.len(),
                    captures.len()
                );
                self.lower_lambda(params, body, captures, expr.ty)
            }

            HirExprKind::Array { elements } => self.lower_array_literal(elements),

            HirExprKind::Map { entries } => self.lower_map_literal(entries),

            HirExprKind::ObjectLiteral { fields } => self.lower_object_literal(fields, expr.ty),

            HirExprKind::ArrayComprehension { .. } => {
                // Array comprehensions are desugared to loops
                self.add_error(
                    "Array comprehensions not yet implemented in MIR",
                    expr.source_location,
                );
                None
            }

            HirExprKind::StringInterpolation { parts } => self.lower_string_interpolation(parts),

            HirExprKind::This => {
                // 'this' is typically passed as first parameter
                self.symbol_map.get(&SymbolId::from_raw(0)).copied()
            }

            HirExprKind::Super => {
                // 'super' should only appear in constructor super calls, which are handled
                // specially in lower_constructor_body. If we reach here, it's likely being
                // used incorrectly (e.g., super.method() which isn't supported yet)
                // eprintln!("WARNING: HirExprKind::Super encountered in expression lowering");
                // eprintln!("  This might be super.field or super.method() which isn't implemented yet");
                // For now, treat it like 'this' (same object, but calling parent methods)
                self.symbol_map.get(&SymbolId::from_raw(0)).copied()
            }

            HirExprKind::Null => self.builder.build_null(),

            HirExprKind::Untyped(inner) => {
                // Untyped expressions bypass type checking
                self.lower_expression(inner)
            }

            HirExprKind::InlineCode { target, code, args } => {
                // Platform-specific inline code (__c__, __js__, etc.)
                self.lower_inline_code(target, code, args)
            }

            HirExprKind::TryCatch {
                try_expr,
                catch_handlers,
                finally_expr,
            } => {
                // Exception handling via setjmp/longjmp (expression form).
                // try { body } catch (e) { handler } finally { cleanup }

                let normal_path_block = self.builder.create_block()?;
                let landing_pad_block = self.builder.create_block()?;
                let continuation_block = self.builder.create_block()?;

                // --- Setup: push handler and call _setjmp ---
                let push_fn = self.get_or_register_extern_function(
                    "rayzor_exception_push_handler",
                    vec![],
                    IrType::Ptr(Box::new(IrType::Void)),
                );
                let jmp_buf = self.builder.build_call_direct(
                    push_fn,
                    vec![],
                    IrType::Ptr(Box::new(IrType::Void)),
                );

                let setjmp_fn = self.get_or_register_extern_function(
                    "_setjmp",
                    vec![IrType::Ptr(Box::new(IrType::Void))],
                    IrType::I32,
                );
                let jmp_buf_reg = jmp_buf
                    .unwrap_or_else(|| self.builder.build_const(IrValue::I64(0)).expect("const"));
                let setjmp_result =
                    self.builder
                        .build_call_direct(setjmp_fn, vec![jmp_buf_reg], IrType::I32);

                let zero = self.builder.build_const(IrValue::I32(0)).expect("const");
                let setjmp_reg = setjmp_result.unwrap_or(zero);
                let cmp = self.builder.build_cmp(CompareOp::Eq, setjmp_reg, zero)?;
                self.builder
                    .build_cond_branch(cmp, normal_path_block, landing_pad_block);

                // --- normal_path: execute try body ---
                self.builder.switch_to_block(normal_path_block);
                self.lower_expression(try_expr);

                let pop_fn = self.get_or_register_extern_function(
                    "rayzor_exception_pop_handler",
                    vec![],
                    IrType::Void,
                );
                self.builder.build_call_direct(pop_fn, vec![], IrType::Void);

                if let Some(finally_body) = &finally_expr {
                    self.lower_expression(finally_body);
                }

                self.builder.build_branch(continuation_block);

                // --- landing_pad: exception was thrown ---
                self.builder.switch_to_block(landing_pad_block);

                let pop_fn2 = self.get_or_register_extern_function(
                    "rayzor_exception_pop_handler",
                    vec![],
                    IrType::Void,
                );
                self.builder
                    .build_call_direct(pop_fn2, vec![], IrType::Void);

                let get_exc_fn = self.get_or_register_extern_function(
                    "rayzor_get_exception",
                    vec![],
                    IrType::I64,
                );
                let exception_id = self
                    .builder
                    .build_call_direct(get_exc_fn, vec![], IrType::I64)
                    .unwrap_or_else(|| self.builder.build_const(IrValue::I64(0)).expect("const"));

                let get_exc_type_fn = self.get_or_register_extern_function(
                    "rayzor_get_exception_type_id",
                    vec![],
                    IrType::I32,
                );
                let exc_type_id = self
                    .builder
                    .build_call_direct(get_exc_type_fn, vec![], IrType::I32)
                    .unwrap_or_else(|| self.builder.build_const(IrValue::I32(0)).expect("const"));

                // Type-based dispatch across catch handlers
                if !catch_handlers.is_empty() {
                    let mut next_test_block: Option<IrBlockId> = None;

                    for (i, handler) in catch_handlers.iter().enumerate() {
                        let catch_type_kind = {
                            let type_table = self.type_table.borrow();
                            type_table
                                .get(handler.exception_type)
                                .map(|t| t.kind.clone())
                        };
                        let is_dynamic =
                            matches!(catch_type_kind, Some(crate::tast::TypeKind::Dynamic));

                        let catch_body_block = match self.builder.create_block() {
                            Some(b) => b,
                            None => return None,
                        };

                        if let Some(test_block) = next_test_block {
                            self.builder.switch_to_block(test_block);
                        }

                        if is_dynamic || i == catch_handlers.len() - 1 {
                            self.builder.build_branch(catch_body_block);
                            next_test_block = None;
                        } else {
                            let expected_type_id = self.runtime_type_id(handler.exception_type);
                            let expected_const = self
                                .builder
                                .build_const(IrValue::I32(expected_type_id as i32))
                                .expect("const");

                            // Use polymorphic matching for class types (walks inheritance),
                            // exact match for primitives
                            let is_class_type = matches!(
                                catch_type_kind,
                                Some(crate::tast::TypeKind::Class { .. })
                            );

                            let type_match = if is_class_type {
                                let match_fn = self.get_or_register_extern_function(
                                    "rayzor_exception_type_matches",
                                    vec![IrType::I32, IrType::I32],
                                    IrType::I32,
                                );
                                let result = self
                                    .builder
                                    .build_call_direct(
                                        match_fn,
                                        vec![exc_type_id, expected_const],
                                        IrType::I32,
                                    )
                                    .unwrap_or_else(|| {
                                        self.builder.build_const(IrValue::I32(0)).expect("const")
                                    });
                                let zero_val =
                                    self.builder.build_const(IrValue::I32(0)).expect("const");
                                self.builder
                                    .build_cmp(CompareOp::Ne, result, zero_val)
                                    .expect("cmp")
                            } else {
                                self.builder
                                    .build_cmp(CompareOp::Eq, exc_type_id, expected_const)
                                    .expect("cmp")
                            };

                            let next_block = self.builder.create_block().expect("create block");
                            self.builder.build_cond_branch(
                                type_match,
                                catch_body_block,
                                next_block,
                            );
                            next_test_block = Some(next_block);
                        }

                        // --- catch body ---
                        self.builder.switch_to_block(catch_body_block);
                        self.symbol_map.insert(handler.exception_var, exception_id);
                        self.lower_expression(&handler.body);

                        if let Some(finally_body) = &finally_expr {
                            self.lower_expression(finally_body);
                        }
                        self.builder.build_branch(continuation_block);
                    }

                    // Fallthrough if no catch matched
                    if let Some(fallthrough_block) = next_test_block {
                        self.builder.switch_to_block(fallthrough_block);
                        if let Some(finally_body) = &finally_expr {
                            self.lower_expression(finally_body);
                        }
                        self.builder.build_branch(continuation_block);
                    }
                } else {
                    if let Some(finally_body) = &finally_expr {
                        self.lower_expression(finally_body);
                    }
                    self.builder.build_branch(continuation_block);
                }

                // --- continuation ---
                self.builder.switch_to_block(continuation_block);
                None // try/catch as statement has no return value
            }

            _ => {
                self.add_error("Unsupported expression type in MIR", expr.source_location);
                None
            }
        };

        // debug!("lower_expression result: {:?}", result);
        result
    }

    /// Lower if statement/expression
    fn lower_if_statement(
        &mut self,
        condition: &HirExpr,
        then_branch: &HirBlock,
        else_branch: Option<&HirBlock>,
    ) {
        debug!(
            "lower_if_statement called, has_else={}",
            else_branch.is_some()
        );
        let Some(then_block) = self.builder.create_block() else {
            return;
        };
        let Some(merge_block) = self.builder.create_block() else {
            return;
        };

        let else_block = if else_branch.is_some() {
            self.builder.create_block().unwrap_or(merge_block)
        } else {
            merge_block
        };

        // Get the current block before branching
        let entry_block = if let Some(block_id) = self.builder.current_block() {
            block_id
        } else {
            return;
        };

        // Find all variables that are modified in either branch
        let mut modified_vars = std::collections::HashSet::new();
        for stmt in &then_branch.statements {
            self.find_modified_variables_in_statement(stmt, &mut modified_vars);
        }
        if let Some(else_br) = else_branch {
            for stmt in &else_br.statements {
                self.find_modified_variables_in_statement(stmt, &mut modified_vars);
            }
        }

        debug!("modified_vars.len() = {}", modified_vars.len());

        // Save initial values of variables that will be modified
        let mut var_initial_values: HashMap<SymbolId, (IrId, IrType)> = HashMap::new();
        for symbol_id in &modified_vars {
            if let Some(&reg) = self.symbol_map.get(symbol_id) {
                // Get the type from the locals table
                if let Some(func) = self.builder.current_function() {
                    if let Some(local) = func.locals.get(&reg) {
                        debug!("var {:?} has initial value {:?}", symbol_id, reg);
                        var_initial_values.insert(*symbol_id, (reg, local.ty.clone()));
                    }
                }
            } else {
                debug!("var {:?} NOT in symbol_map (new in branch)", symbol_id);
            }
        }

        debug!("var_initial_values.len() = {}", var_initial_values.len());

        // Evaluate condition
        if let Some(cond_reg) = self.lower_expression(condition) {
            self.builder
                .build_cond_branch(cond_reg, then_block, else_block);

            // Lower then branch
            self.builder.switch_to_block(then_block);
            self.lower_block(then_branch);
            let then_end_block = if !self.is_terminated() {
                let current = self.builder.current_block();
                self.builder.build_branch(merge_block);
                current
            } else {
                None
            };

            // Save values after then branch
            let mut then_values: BTreeMap<SymbolId, IrId> = BTreeMap::new();
            if then_end_block.is_some() {
                // Only collect values for variables that existed BEFORE the if/else
                // Variables defined within the then branch should not be added
                for symbol_id in var_initial_values.keys() {
                    if let Some(&reg) = self.symbol_map.get(symbol_id) {
                        then_values.insert(*symbol_id, reg);
                    }
                }
            }

            // Lower else branch if present
            let mut else_values: BTreeMap<SymbolId, IrId> = BTreeMap::new();
            let else_end_block = if let Some(else_branch) = else_branch {
                self.builder.switch_to_block(else_block);
                self.lower_block(else_branch);
                if !self.is_terminated() {
                    let current = self.builder.current_block();
                    self.builder.build_branch(merge_block);

                    // Save values after else branch
                    // Only collect values for variables that existed BEFORE the if/else
                    // Variables defined within one branch should not leak into the other
                    for symbol_id in var_initial_values.keys() {
                        if let Some(&reg) = self.symbol_map.get(symbol_id) {
                            else_values.insert(*symbol_id, reg);
                        }
                    }
                    current
                } else {
                    None
                }
            } else {
                // If no else branch, the else path just falls through to merge
                // with the original values
                for (symbol_id, (initial_reg, _)) in &var_initial_values {
                    else_values.insert(*symbol_id, *initial_reg);
                }
                Some(entry_block)
            };

            // Continue in merge block and create phi nodes
            self.builder.switch_to_block(merge_block);

            // Create phi nodes for modified variables
            debug!("var_initial_values.len() = {}", var_initial_values.len());
            for (symbol_id, (initial_reg, var_type)) in &var_initial_values {
                debug!("Checking var {:?} for phi node", symbol_id);
                // Only create phi if at least one branch modified the variable
                let then_val = then_values.get(symbol_id).copied().unwrap_or(*initial_reg);
                let else_val = else_values.get(symbol_id).copied().unwrap_or(*initial_reg);

                debug!("  then_val {:?}, else_val {:?}", then_val, else_val);

                // If both branches lead to the same value, no phi needed
                if then_val == else_val {
                    debug!("  Skipping phi - same value");
                    continue;
                }

                // Only create phi if we have valid incoming blocks
                if then_end_block.is_none() && else_end_block.is_none() {
                    debug!("  Skipping phi - no valid incoming blocks");
                    continue;
                }

                debug!(
                    "Creating phi for symbol {:?}, then_val {:?}, else_val {:?}",
                    symbol_id, then_val, else_val
                );
                debug!(
                    "  then_end_block {:?}, else_end_block {:?}",
                    then_end_block, else_end_block
                );

                // Create phi node
                if let Some(phi_reg) = self.builder.build_phi(merge_block, var_type.clone()) {
                    debug!(
                        "  Created phi node {:?} in merge block {:?}",
                        phi_reg, merge_block
                    );

                    // Add incoming values from both branches
                    if let Some(then_blk) = then_end_block {
                        debug!(
                            "  Adding phi incoming from then block {:?}, value {:?}",
                            then_blk, then_val
                        );
                        self.builder
                            .add_phi_incoming(merge_block, phi_reg, then_blk, then_val);
                    }
                    if let Some(else_blk) = else_end_block {
                        debug!(
                            "  Adding phi incoming from else block {:?}, value {:?}",
                            else_blk, else_val
                        );
                        self.builder
                            .add_phi_incoming(merge_block, phi_reg, else_blk, else_val);
                    }

                    // Register the phi node as a local
                    if let Some(func) = self.builder.current_function_mut() {
                        if let Some(local) = func.locals.get(initial_reg).cloned() {
                            func.locals.insert(
                                phi_reg,
                                super::IrLocal {
                                    name: format!("{}_phi", local.name),
                                    ty: var_type.clone(),
                                    mutable: true,
                                    source_location: local.source_location,
                                    allocation: super::AllocationHint::Register,
                                },
                            );
                        }
                    }

                    // Update symbol map to use phi node
                    self.symbol_map.insert(*symbol_id, phi_reg);
                }
            }
        }
    }

    /// Lower while loop
    fn lower_while_loop(
        &mut self,
        condition: &HirExpr,
        body: &HirBlock,
        label: Option<&SymbolId>,
        continue_update: Option<&HirBlock>,
    ) {
        debug!("[lower_while_loop] ENTERED");
        let Some(cond_block) = self.builder.create_block() else {
            debug!("[lower_while_loop] FAILED to create cond_block");
            return;
        };
        let Some(body_block) = self.builder.create_block() else {
            debug!("[lower_while_loop] FAILED to create body_block");
            return;
        };
        let Some(exit_block) = self.builder.create_block() else {
            debug!("[lower_while_loop] FAILED to create exit_block");
            return;
        };
        // Create update block if there's a continue_update (for range/for loops)
        let update_block = if continue_update.is_some() {
            self.builder.create_block()
        } else {
            None
        };
        debug!(
            "[lower_while_loop] Created blocks: cond={:?}, body={:?}, exit={:?}",
            cond_block, body_block, exit_block
        );

        // Save the entry block (current block before loop)
        let entry_block = if let Some(block_id) = self.builder.current_block() {
            block_id
        } else {
            return;
        };

        // Find all variables that are referenced in the loop
        // For now, use a simple heuristic: any variable in the symbol_map
        // that is referenced in the condition or body is a potential loop variable
        //    // debug!("Loop body has {} statements", body.statements.len());
        //     for (i, stmt) in body.statements.iter().enumerate() {
        //        // debug!("Statement {}: {:?}", i, std::mem::discriminant(stmt));
        //     }

        // Collect all variables referenced in condition
        let mut referenced_vars = std::collections::HashSet::new();
        self.collect_referenced_variables_in_expr(condition, &mut referenced_vars);

        // Collect all variables referenced in body
        self.collect_referenced_variables_in_block(body, &mut referenced_vars);

        // Also collect variables referenced in continue_update if present
        if let Some(upd) = continue_update {
            self.collect_referenced_variables_in_block(upd, &mut referenced_vars);
        }

        // Only include variables that were declared before the loop
        // (i.e., they're already in the symbol_map)
        // Exclude function parameters since they're immutable
        let modified_vars: std::collections::HashSet<SymbolId> = referenced_vars
            .into_iter()
            .filter(|sym| {
                let in_map = self.symbol_map.contains_key(sym);
                // Check if this is a function parameter by seeing if it's in the current function's parameters
                let is_param = if let Some(func) = self.builder.current_function() {
                    func.signature.parameters.iter().any(|p| {
                        // Check if the symbol maps to this parameter's register
                        self.symbol_map.get(sym) == Some(&p.reg)
                    })
                } else {
                    false
                };
                in_map && !is_param
            })
            .collect();

        // Save initial values of loop variables before jumping to condition
        let mut loop_var_initial_values: BTreeMap<SymbolId, (IrId, IrType)> = BTreeMap::new();
        for symbol_id in &modified_vars {
            if let Some(&reg) = self.symbol_map.get(symbol_id) {
                // Get the type from the locals table
                if let Some(func) = self.builder.current_function() {
                    if let Some(local) = func.locals.get(&reg) {
                        loop_var_initial_values.insert(*symbol_id, (reg, local.ty.clone()));
                    }
                }
            }
        }

        // Jump to condition block
        self.builder.build_branch(cond_block);

        // Condition block - create phi nodes for loop variables
        self.builder.switch_to_block(cond_block);

        // Create phi nodes for all loop variables
        let mut phi_nodes: BTreeMap<SymbolId, IrId> = BTreeMap::new();
        for (symbol_id, (initial_reg, var_type)) in &loop_var_initial_values {
            // debug!("Creating phi for symbol {:?}, initial reg {:?}", symbol_id, initial_reg);
            if let Some(phi_reg) = self.builder.build_phi(cond_block, var_type.clone()) {
                // debug!("Created phi node with dest {:?}", phi_reg);
                // Add incoming value from entry block
                self.builder
                    .add_phi_incoming(cond_block, phi_reg, entry_block, *initial_reg);
                // debug!("Added incoming edge from entry block {:?}", entry_block);

                // Register the phi node as a local so Cranelift can find its type
                if let Some(func) = self.builder.current_function_mut() {
                    if let Some(local) = func.locals.get(initial_reg).cloned() {
                        func.locals.insert(
                            phi_reg,
                            super::IrLocal {
                                name: format!("{}_phi", local.name),
                                ty: var_type.clone(),
                                mutable: true,
                                source_location: local.source_location,
                                allocation: super::AllocationHint::Register,
                            },
                        );
                    }
                }

                // Update symbol map to use phi node
                phi_nodes.insert(*symbol_id, phi_reg);
                self.symbol_map.insert(*symbol_id, phi_reg);

                // Also update owned_heap_values so drop tracking uses the phi result
                // This ensures that when a loop variable is reassigned, we free the
                // current iteration's value (from phi), not the initial value
                if self.owned_heap_values.contains_key(symbol_id) {
                    self.owned_heap_values.insert(*symbol_id, phi_reg);
                }
            }
        }
        // debug!("Created {} phi nodes", phi_nodes.len());

        // Create phi nodes in update_block for all loop variables (if update block exists).
        // These are needed because the update block can be reached from both:
        //   1. Normal body end (variables may have been modified in body)
        //   2. Continue statements (variables at their pre-body-modification values)
        // Without these phis, we'd use the wrong value on one of the paths.
        let mut continue_phi_nodes: BTreeMap<SymbolId, IrId> = BTreeMap::new();
        if let Some(upd_block) = update_block {
            // Temporarily switch to the update block to create phi nodes
            // (We'll switch back and lower the body first)
            let saved_block = self.builder.current_block();
            self.builder.switch_to_block(upd_block);
            for (symbol_id, (_, var_type)) in &loop_var_initial_values {
                if let Some(upd_phi_reg) = self.builder.build_phi(upd_block, var_type.clone()) {
                    // Register as a local
                    if let Some(func) = self.builder.current_function_mut() {
                        func.locals.insert(
                            upd_phi_reg,
                            super::IrLocal {
                                name: format!("update_phi_{}", symbol_id.as_raw()),
                                ty: var_type.clone(),
                                mutable: true,
                                source_location: super::IrSourceLocation::unknown(),
                                allocation: super::AllocationHint::Register,
                            },
                        );
                    }
                    continue_phi_nodes.insert(*symbol_id, upd_phi_reg);
                }
            }
            // Switch back to entry block
            if let Some(saved) = saved_block {
                self.builder.switch_to_block(saved);
            }
        }

        // Push loop context (exit phi nodes will be added after condition evaluation)
        // We need to evaluate the condition FIRST to know which block we're actually in
        // (short-circuit operators like && create additional blocks)
        // When there's a continue_update block, continue should jump there (not cond_block)
        // so the loop counter increment always executes.
        self.loop_stack.push(LoopContext {
            continue_block: update_block.unwrap_or(cond_block),
            break_block: exit_block,
            label: label.cloned(),
            exit_phi_nodes: BTreeMap::new(), // Will be populated after condition eval
            continue_phi_nodes: continue_phi_nodes.clone(),
        });

        // Evaluate condition - this may create additional blocks for short-circuit operators!
        // After this, we may be in a different block than cond_block
        debug!(
            "[lower_while_loop] Lowering condition expression, kind={:?}",
            std::mem::discriminant(&condition.kind)
        );
        let cond_result = self.lower_expression(condition);
        debug!("[lower_while_loop] Condition result: {:?}", cond_result);
        if cond_result.is_none() {
            debug!(
                "[lower_while_loop] DETAILED: condition.kind = {:?}",
                condition.kind
            );
        }

        // Capture the block we're actually in AFTER condition evaluation
        // This is where the conditional branch to body/exit will happen
        let cond_end_block = self.builder.current_block().unwrap_or(cond_block);

        // Now create exit block phi nodes with the correct predecessor block
        let mut exit_phi_nodes: BTreeMap<SymbolId, IrId> = BTreeMap::new();
        for (symbol_id, loop_phi_reg) in &phi_nodes {
            if let Some((_, var_type)) = loop_var_initial_values.get(symbol_id) {
                // Allocate a new register for the exit block parameter
                let exit_param_reg = self.builder.alloc_reg().unwrap();

                // Create the phi node in the exit block with incoming edge from the ACTUAL
                // block that branches to exit (cond_end_block, not necessarily cond_block)
                if let Some(func) = self.builder.current_function_mut() {
                    if let Some(exit_block_data) = func.cfg.get_block_mut(exit_block) {
                        let exit_phi = super::IrPhiNode {
                            dest: exit_param_reg,
                            incoming: vec![(cond_end_block, *loop_phi_reg)],
                            ty: var_type.clone(),
                        };
                        exit_block_data.add_phi(exit_phi);

                        // Register as a local
                        func.locals.insert(
                            exit_param_reg,
                            super::IrLocal {
                                name: format!("loop_exit_{}", symbol_id.as_raw()),
                                ty: var_type.clone(),
                                mutable: false,
                                source_location: super::IrSourceLocation::unknown(),
                                allocation: super::AllocationHint::Register,
                            },
                        );
                    }
                }

                exit_phi_nodes.insert(*symbol_id, exit_param_reg);
            }
        }

        // Update loop context with the exit phi nodes
        if let Some(loop_ctx) = self.loop_stack.last_mut() {
            loop_ctx.exit_phi_nodes = exit_phi_nodes.clone();
        }

        // Build conditional branch from the block we're actually in
        if let Some(cond_reg) = cond_result {
            debug!(
                "[lower_while_loop] Building cond_branch with cond_reg={:?}",
                cond_reg
            );
            self.builder
                .build_cond_branch(cond_reg, body_block, exit_block);
        } else {
            warn!("[lower_while_loop] CONDITION FAILED TO LOWER - no branch built!");
        }

        // Body block
        debug!(
            "[lower_while_loop] Switching to body_block and lowering body ({} statements)",
            body.statements.len()
        );
        self.builder.switch_to_block(body_block);
        self.enter_drop_scope(); // Enter scope for loop body allocations
        self.lower_block(body);
        debug!("[lower_while_loop] Body lowered");

        // Get the end block of the loop body (might be different if there are nested blocks)
        let body_end_block = if let Some(block_id) = self.builder.current_block() {
            debug!("[lower_while_loop] body_end_block={:?}", block_id);
            block_id
        } else {
            warn!("[lower_while_loop] NO CURRENT BLOCK after body lowering - early return!");
            return;
        };

        if update_block.is_some() {
            // When there's an update block, add incoming edges to the UPDATE block's
            // phis from the body end. The update block will then provide the back-edge
            // to cond_block.
            for (symbol_id, upd_phi_reg) in &continue_phi_nodes {
                let body_end_value = if let Some(&updated_reg) = self.symbol_map.get(symbol_id) {
                    updated_reg
                } else if let Some(&cond_phi) = phi_nodes.get(symbol_id) {
                    cond_phi
                } else {
                    continue;
                };
                self.builder.add_phi_incoming(
                    update_block.unwrap(),
                    *upd_phi_reg,
                    body_end_block,
                    body_end_value,
                );
            }
        } else {
            // Plain while loop: add back-edge directly from body to cond_block.
            for (symbol_id, phi_reg) in &phi_nodes {
                let back_edge_value = if let Some(&updated_reg) = self.symbol_map.get(symbol_id) {
                    updated_reg
                } else {
                    *phi_reg
                };
                self.builder.add_phi_incoming(
                    cond_block,
                    *phi_reg,
                    body_end_block,
                    back_edge_value,
                );
            }
        }

        // Branch to update block (or directly to cond_block) if body didn't terminate
        if !self.is_terminated() {
            self.exit_drop_scope(); // Free loop body allocations before next iteration
            if let Some(upd_block) = update_block {
                self.builder.build_branch(upd_block);
            } else {
                self.builder.build_branch(cond_block);
            }
        }

        // Lower the update block (e.g., i++ for range loops)
        if let (Some(upd_block), Some(upd_body)) = (update_block, continue_update) {
            self.builder.switch_to_block(upd_block);

            // Point symbol_map to the update block's phi nodes so the update code
            // uses the merged values (from both body-end and continue paths).
            for (symbol_id, upd_phi_reg) in &continue_phi_nodes {
                self.symbol_map.insert(*symbol_id, *upd_phi_reg);
            }

            self.lower_block(upd_body);

            // Get the block we're in after lowering the update
            let update_end_block = self.builder.current_block().unwrap_or(upd_block);

            // Add phi incoming edges from the update block end to cond_block
            for (symbol_id, phi_reg) in &phi_nodes {
                let back_edge_value = if let Some(&updated_reg) = self.symbol_map.get(symbol_id) {
                    updated_reg
                } else {
                    *phi_reg
                };
                self.builder.add_phi_incoming(
                    cond_block,
                    *phi_reg,
                    update_end_block,
                    back_edge_value,
                );
            }

            if !self.is_terminated() {
                self.builder.build_branch(cond_block);
            }
        }

        // Pop loop context
        self.loop_stack.pop();

        // Continue in exit block
        // The exit block will receive loop-carried values as block parameters when
        // the conditional branch from the loop header takes the false path
        self.builder.switch_to_block(exit_block);

        // Update symbol map to use exit phi nodes (already created before loop body)
        for (symbol_id, exit_param_reg) in &exit_phi_nodes {
            self.symbol_map.insert(*symbol_id, *exit_param_reg);
        }

        // CRITICAL: Also update owned_heap_values to use exit phi values.
        // Without this, owned_heap_values retains IrIds from the loop body block
        // that don't dominate post-loop blocks. When an outer scope's exit_drop_scope
        // later emits Free instructions using these stale IrIds, it creates an SSA
        // dominance violation — at runtime, this causes double-free crashes because
        // the stale register may hold an already-freed pointer.
        for (symbol_id, exit_param_reg) in &exit_phi_nodes {
            if self.owned_heap_values.contains_key(symbol_id) {
                self.owned_heap_values.insert(*symbol_id, *exit_param_reg);
            }
        }
    }

    // Helper methods...

    /// Collect all variables referenced in a block
    fn collect_referenced_variables_in_block(
        &self,
        block: &HirBlock,
        vars: &mut std::collections::HashSet<SymbolId>,
    ) {
        for stmt in &block.statements {
            self.collect_referenced_variables_in_stmt(stmt, vars);
        }
        // Also check the block's trailing expression (block-as-value)
        if let Some(expr) = &block.expr {
            self.collect_referenced_variables_in_expr(expr, vars);
        }
    }

    /// Collect all variables referenced in a statement
    fn collect_referenced_variables_in_stmt(
        &self,
        stmt: &HirStatement,
        vars: &mut std::collections::HashSet<SymbolId>,
    ) {
        match stmt {
            HirStatement::Let { init, .. } => {
                if let Some(expr) = init {
                    self.collect_referenced_variables_in_expr(expr, vars);
                }
            }
            HirStatement::Expr(expr) => {
                self.collect_referenced_variables_in_expr(expr, vars);
            }
            HirStatement::Assign { lhs, rhs, .. } => {
                match lhs {
                    HirLValue::Variable(sym) => {
                        vars.insert(*sym);
                    }
                    HirLValue::Field { object, .. } => {
                        self.collect_referenced_variables_in_expr(object, vars);
                    }
                    HirLValue::Index { object, index } => {
                        self.collect_referenced_variables_in_expr(object, vars);
                        self.collect_referenced_variables_in_expr(index, vars);
                    }
                }
                self.collect_referenced_variables_in_expr(rhs, vars);
            }
            HirStatement::Return(Some(expr)) => {
                self.collect_referenced_variables_in_expr(expr, vars);
            }
            HirStatement::If {
                condition,
                then_branch,
                else_branch,
                ..
            } => {
                self.collect_referenced_variables_in_expr(condition, vars);
                self.collect_referenced_variables_in_block(then_branch, vars);
                if let Some(else_blk) = else_branch {
                    self.collect_referenced_variables_in_block(else_blk, vars);
                }
            }
            HirStatement::While {
                condition, body, ..
            }
            | HirStatement::DoWhile {
                condition, body, ..
            } => {
                self.collect_referenced_variables_in_expr(condition, vars);
                self.collect_referenced_variables_in_block(body, vars);
            }
            _ => {}
        }
    }

    /// Collect all variables referenced in an expression
    fn collect_referenced_variables_in_expr(
        &self,
        expr: &HirExpr,
        vars: &mut std::collections::HashSet<SymbolId>,
    ) {
        match &expr.kind {
            HirExprKind::Variable { symbol, .. } => {
                vars.insert(*symbol);
            }
            HirExprKind::Binary { lhs, rhs, .. } => {
                self.collect_referenced_variables_in_expr(lhs, vars);
                self.collect_referenced_variables_in_expr(rhs, vars);
            }
            HirExprKind::Unary { operand, .. } => {
                self.collect_referenced_variables_in_expr(operand, vars);
            }
            HirExprKind::If {
                condition,
                then_expr,
                else_expr,
                ..
            } => {
                self.collect_referenced_variables_in_expr(condition, vars);
                self.collect_referenced_variables_in_expr(then_expr, vars);
                self.collect_referenced_variables_in_expr(else_expr, vars);
            }
            HirExprKind::Call { callee, args, .. } => {
                self.collect_referenced_variables_in_expr(callee, vars);
                for arg in args {
                    self.collect_referenced_variables_in_expr(arg, vars);
                }
            }
            HirExprKind::Block(block) => {
                // Recursively collect variables from block expressions
                self.collect_referenced_variables_in_block(block, vars);
            }
            _ => {}
        }
    }

    /// Find all variables that are modified (assigned) in a block
    /// This is used for SSA phi node insertion in loops
    fn find_modified_variables_in_block(
        &self,
        block: &HirBlock,
    ) -> std::collections::HashSet<SymbolId> {
        let mut modified = std::collections::HashSet::new();

        for stmt in &block.statements {
            self.find_modified_variables_in_statement(stmt, &mut modified);
        }
        // Also check the block's trailing expression (block-as-value)
        if let Some(expr) = &block.expr {
            self.find_modified_variables_in_expression(expr, &mut modified);
        }

        modified
    }

    /// Recursively find modified variables in a statement
    fn find_modified_variables_in_statement(
        &self,
        stmt: &HirStatement,
        modified: &mut std::collections::HashSet<SymbolId>,
    ) {
        match stmt {
            HirStatement::Let { pattern, .. } => {
                // Variable declarations are modifications
                // debug!("Found Let statement");
                self.collect_pattern_variables(pattern, modified);
            }
            HirStatement::Expr(expr) => {
                // debug!("Found Expr statement with kind: {:?}", std::mem::discriminant(&expr.kind));
                self.find_modified_variables_in_expression(expr, modified);
            }
            HirStatement::Assign { lhs, rhs, .. } => {
                // Assignments modify the left-hand side
                match lhs {
                    HirLValue::Variable(symbol) => {
                        modified.insert(*symbol);
                    }
                    _ => {}
                }
                self.find_modified_variables_in_expression(rhs, modified);
            }
            HirStatement::If {
                then_branch,
                else_branch,
                ..
            } => {
                for stmt in &then_branch.statements {
                    self.find_modified_variables_in_statement(stmt, modified);
                }
                if let Some(else_blk) = else_branch {
                    for stmt in &else_blk.statements {
                        self.find_modified_variables_in_statement(stmt, modified);
                    }
                }
            }
            HirStatement::While { body, .. } | HirStatement::DoWhile { body, .. } => {
                for stmt in &body.statements {
                    self.find_modified_variables_in_statement(stmt, modified);
                }
            }
            HirStatement::ForIn { body, .. } => {
                for stmt in &body.statements {
                    self.find_modified_variables_in_statement(stmt, modified);
                }
            }
            HirStatement::Label { block, .. } => {
                for stmt in &block.statements {
                    self.find_modified_variables_in_statement(stmt, modified);
                }
            }
            _ => {}
        }
    }

    /// Find modified variables in an expression (assignments)
    fn find_modified_variables_in_expression(
        &self,
        expr: &HirExpr,
        modified: &mut std::collections::HashSet<SymbolId>,
    ) {
        match &expr.kind {
            HirExprKind::Binary { lhs, rhs, .. } => {
                self.find_modified_variables_in_expression(lhs, modified);
                self.find_modified_variables_in_expression(rhs, modified);
            }
            HirExprKind::Unary { operand, .. } => {
                self.find_modified_variables_in_expression(operand, modified);
            }
            HirExprKind::If {
                then_expr,
                else_expr,
                ..
            } => {
                self.find_modified_variables_in_expression(then_expr, modified);
                self.find_modified_variables_in_expression(else_expr, modified);
            }
            HirExprKind::Call { args, .. } => {
                for arg in args {
                    self.find_modified_variables_in_expression(arg, modified);
                }
            }
            HirExprKind::Block(block) => {
                for stmt in &block.statements {
                    self.find_modified_variables_in_statement(stmt, modified);
                }
            }
            _ => {}
        }
    }

    /// Collect all variable symbols from a pattern
    fn collect_pattern_variables(
        &self,
        pattern: &HirPattern,
        variables: &mut std::collections::HashSet<SymbolId>,
    ) {
        match pattern {
            HirPattern::Variable { symbol, .. } => {
                variables.insert(*symbol);
            }
            HirPattern::Tuple(patterns) => {
                for p in patterns {
                    self.collect_pattern_variables(p, variables);
                }
            }
            HirPattern::Constructor { fields, .. } => {
                for p in fields {
                    self.collect_pattern_variables(p, variables);
                }
            }
            HirPattern::Array { elements, rest } => {
                for p in elements {
                    self.collect_pattern_variables(p, variables);
                }
                if let Some(rest_pat) = rest {
                    self.collect_pattern_variables(rest_pat, variables);
                }
            }
            _ => {}
        }
    }

    fn convert_binary_op(&self, op: HirBinaryOp) -> BinaryOp {
        match op {
            HirBinaryOp::Add => BinaryOp::Add,
            HirBinaryOp::Sub => BinaryOp::Sub,
            HirBinaryOp::Mul => BinaryOp::Mul,
            HirBinaryOp::Div => BinaryOp::Div,
            HirBinaryOp::Mod => BinaryOp::Rem,
            HirBinaryOp::BitAnd => BinaryOp::And,
            HirBinaryOp::BitOr => BinaryOp::Or,
            HirBinaryOp::BitXor => BinaryOp::Xor,
            HirBinaryOp::Shl => BinaryOp::Shl,
            HirBinaryOp::Shr => BinaryOp::Shr,
            HirBinaryOp::Ushr => BinaryOp::Ushr,
            _ => BinaryOp::Add, // Default fallback
        }
    }

    fn convert_binary_op_to_mir(&self, op: HirBinaryOp) -> MirBinaryOp {
        match op {
            HirBinaryOp::Add => MirBinaryOp::Binary(BinaryOp::Add),
            HirBinaryOp::Sub => MirBinaryOp::Binary(BinaryOp::Sub),
            HirBinaryOp::Mul => MirBinaryOp::Binary(BinaryOp::Mul),
            HirBinaryOp::Div => MirBinaryOp::Binary(BinaryOp::Div),
            HirBinaryOp::Mod => MirBinaryOp::Binary(BinaryOp::Rem),
            HirBinaryOp::Eq => MirBinaryOp::Compare(CompareOp::Eq),
            HirBinaryOp::Ne => MirBinaryOp::Compare(CompareOp::Ne),
            HirBinaryOp::Lt => MirBinaryOp::Compare(CompareOp::Lt),
            HirBinaryOp::Le => MirBinaryOp::Compare(CompareOp::Le),
            HirBinaryOp::Gt => MirBinaryOp::Compare(CompareOp::Gt),
            HirBinaryOp::Ge => MirBinaryOp::Compare(CompareOp::Ge),
            HirBinaryOp::BitAnd => MirBinaryOp::Binary(BinaryOp::And),
            HirBinaryOp::BitOr => MirBinaryOp::Binary(BinaryOp::Or),
            HirBinaryOp::BitXor => MirBinaryOp::Binary(BinaryOp::Xor),
            HirBinaryOp::Shl => MirBinaryOp::Binary(BinaryOp::Shl),
            HirBinaryOp::Shr => MirBinaryOp::Binary(BinaryOp::Shr),
            HirBinaryOp::Ushr => MirBinaryOp::Binary(BinaryOp::Ushr),
            _ => MirBinaryOp::Binary(BinaryOp::Add), // Default
        }
    }

    fn convert_unary_op(&self, op: HirUnaryOp) -> UnaryOp {
        match op {
            HirUnaryOp::Not => UnaryOp::Not,
            HirUnaryOp::Neg => UnaryOp::Neg,
            HirUnaryOp::BitNot => UnaryOp::Not, // Reuse Not for bit not
            _ => UnaryOp::Neg,                  // Default
        }
    }

    fn convert_type(&self, type_id: TypeId) -> IrType {
        use crate::tast::TypeKind;

        // Look up the type in the type table
        let type_table = self.type_table.borrow();
        let type_ref = type_table.get(type_id);

        // DEBUG: Trace type conversion
        // debug!("[convert_type] type_id={:?}, type_kind={:?}", type_id, type_ref.as_ref().map(|t| &t.kind));

        match type_ref.as_ref().map(|t| &t.kind) {
            // Primitive types
            Some(TypeKind::Int) => IrType::I32,
            Some(TypeKind::Float) => IrType::F64,
            Some(TypeKind::Bool) => IrType::Bool,
            Some(TypeKind::Void) => IrType::Void,
            Some(TypeKind::String) => IrType::String,

            // Function types - represented as function pointers (i64)
            Some(TypeKind::Function {
                params,
                return_type,
                ..
            }) => {
                // Convert parameter types
                let param_types: Vec<IrType> =
                    params.iter().map(|p| self.convert_type(*p)).collect();

                // Convert return type
                let ret_type = Box::new(self.convert_type(*return_type));

                IrType::Function {
                    params: param_types,
                    return_type: ret_type,
                    varargs: false,
                }
            }

            // Complex types - represented as pointers (i64)
            Some(TypeKind::Class { .. }) => IrType::Ptr(Box::new(IrType::Void)),
            Some(TypeKind::Interface { .. }) => IrType::Ptr(Box::new(IrType::Void)),
            Some(TypeKind::Enum { .. }) => IrType::I64, // Enums as discriminant values (i64 to match Haxe Int)
            Some(TypeKind::Array { element_type, .. }) => {
                // HaxeArray is an opaque runtime structure, represented as Ptr(Void)
                // regardless of element type. Element type information is tracked at runtime.
                IrType::Ptr(Box::new(IrType::Void))
            }
            Some(TypeKind::Optional { inner_type }) => {
                // Null<T>: primitives need boxing to distinguish null from 0/0.0/false.
                // Reference types are already nullable pointers — no boxing needed.
                let inner_ir = self.convert_type(*inner_type);
                match inner_ir {
                    IrType::I32 | IrType::I64 | IrType::F64 | IrType::F32 | IrType::Bool => {
                        IrType::Ptr(Box::new(IrType::U8)) // Boxed DynamicValue*
                    }
                    _ => inner_ir,
                }
            }

            // Abstract types - use their underlying type
            Some(TypeKind::Abstract {
                underlying,
                symbol_id,
                ..
            }) => {
                if let Some(underlying_type) = underlying {
                    // If underlying type is specified, use it
                    self.convert_type(*underlying_type)
                } else {
                    // No underlying type specified — check for SIMD vector types first
                    let native_name = self.symbol_table.get_symbol(*symbol_id).and_then(|sym| {
                        sym.native_name
                            .and_then(|nn| self.string_interner.get(nn))
                            .map(|s| s.to_string())
                    });
                    if let Some(ref nn) = native_name {
                        match nn.as_str() {
                            "rayzor::SIMD4f" => return IrType::vector(IrType::F32, 4),
                            _ => {}
                        }
                    }

                    // Check if this is a systems type
                    // (Ptr, Ref, Box, Usize) which are all i64 (pointer-sized) abstracts over Int
                    let is_systems_type = self
                        .symbol_table
                        .get_symbol(*symbol_id)
                        .and_then(|sym| {
                            let qn = sym
                                .qualified_name
                                .and_then(|qn| self.string_interner.get(qn))
                                .map(|qn| qn.replace(".", "_"))
                                .or_else(|| {
                                    sym.native_name
                                        .and_then(|nn| self.string_interner.get(nn))
                                        .map(|nn| nn.replace("::", "_"))
                                });
                            qn.filter(|name| self.stdlib_mapping.is_mir_wrapper_class(name))
                        })
                        .is_some();
                    if is_systems_type {
                        IrType::I64
                    } else {
                        IrType::I32
                    }
                }
            }

            // Type parameters — type erasure: all type params are pointer-sized (8 bytes).
            // This allows ONE struct layout per generic class for all instantiations.
            // Coercion to/from concrete types happens at generic boundaries (field access, calls).
            // Exception: constrained type params (T:Interface) become Ptr(Void) — fat pointer
            // for vtable-based dispatch on interface methods.
            // NOTE: Functions that need TypeVar for generic dispatch (convert_to_string,
            // trace handler) extract the type param name separately via resolve_type_param_name().
            Some(TypeKind::TypeParameter { constraints, .. }) => {
                if !constraints.is_empty() && self.has_interface_constraint(&constraints) {
                    IrType::Ptr(Box::new(IrType::Void))
                } else {
                    IrType::I64
                }
            }
            Some(TypeKind::Dynamic) => {
                // Dynamic type is used as a placeholder for unresolved generic type parameters
                // in stdlib (e.g., ArrayIterator<T>.next() where T is unresolved).
                // Since dynamic values can be any type including objects/pointers, we treat
                // them as pointer-sized values to avoid truncation bugs.
                IrType::Ptr(Box::new(IrType::Void))
            }

            // Unknown or error types
            Some(TypeKind::Unknown) | Some(TypeKind::Error) => {
                // Unknown or error types - treat as pointer-sized values to avoid truncation.
                // These may be unresolved generic class instances that need full 64-bit values.
                warn!("Unknown/Error type {:?}, defaulting to Ptr(Void)", type_id);
                IrType::Ptr(Box::new(IrType::Void))
            }

            // Generic instance types (ArrayIterator<T>, Map<K,V>, etc.) - pointer to instantiated class
            Some(TypeKind::GenericInstance { .. }) => IrType::Ptr(Box::new(IrType::Void)),

            // Map type - pointer to map structure
            Some(TypeKind::Map { .. }) => IrType::Ptr(Box::new(IrType::Void)),

            // Anonymous structure type - pointer to struct
            Some(TypeKind::Anonymous { .. }) => IrType::Ptr(Box::new(IrType::Void)),

            // Union type - pointer (can hold any of the union members)
            Some(TypeKind::Union { .. }) => IrType::Ptr(Box::new(IrType::Void)),

            // Intersection type - pointer to combined type
            Some(TypeKind::Intersection { .. }) => IrType::Ptr(Box::new(IrType::Void)),

            // Type alias - resolve to target type
            Some(TypeKind::TypeAlias { target_type, .. }) => self.convert_type(*target_type),

            // Placeholder type - treat as pointer (will be resolved later)
            Some(TypeKind::Placeholder { .. }) => IrType::Ptr(Box::new(IrType::Void)),

            // Char type - single character, represented as i32
            Some(TypeKind::Char) => IrType::I32,

            None => {
                // Type not found in type table
                // This often happens for generic type parameters that weren't resolved,
                // like T in ArrayIterator<T>.next() returning array[current++].
                // Use Ptr(Void) to avoid truncation when these are actually pointers/objects.
                // TODO: Properly resolve generic type parameters from instantiation context.
                warn!(
                    "Type {:?} not found in type table, defaulting to Ptr(Void)",
                    type_id
                );
                IrType::Ptr(Box::new(IrType::Void))
            }

            // Catch-all for other types
            Some(other) => {
                warn!(
                    "Unhandled type kind for {:?}: {:?}, defaulting to Ptr(Void)",
                    type_id, other
                );
                IrType::Ptr(Box::new(IrType::Void))
            }
        }
    }

    /// Extract the element type from an Array type.
    /// If the type is Array<T>, returns Some(T). Otherwise returns None.
    fn get_array_element_type(&self, type_id: TypeId) -> Option<TypeId> {
        use crate::tast::TypeKind;
        let type_table = self.type_table.borrow();
        let type_ref = type_table.get(type_id)?;
        match &type_ref.kind {
            TypeKind::Array { element_type, .. } => Some(*element_type),
            _ => None,
        }
    }

    fn convert_source_location(&self, loc: &SourceLocation) -> IrSourceLocation {
        IrSourceLocation {
            file_id: loc.file_id,
            line: loc.line,
            column: loc.column,
        }
    }

    fn lower_literal(&mut self, lit: &HirLiteral, type_id: TypeId) -> Option<IrId> {
        match lit {
            HirLiteral::Int(i) => {
                // Use the actual type from type checking instead of always using I64
                let ir_type = self.convert_type(type_id);
                let result = self.builder.build_int(*i, ir_type);
                if result.is_none() {
                    // Fallback to I32 if the type is unrecognized (e.g., Ptr(Void) from inlined static fields)
                    return self.builder.build_int(*i, IrType::I32);
                }
                result
            }
            HirLiteral::Float(f) => {
                let ir_type = self.convert_type(type_id);
                match ir_type {
                    IrType::F32 => self.builder.build_const(IrValue::F32(*f as f32)),
                    IrType::F64 => self.builder.build_const(IrValue::F64(*f)),
                    _ => self.builder.build_const(IrValue::F64(*f)), // Default to F64
                }
            }
            HirLiteral::String(s) => {
                // Resolve the interned string to get the actual content
                let string_content = self
                    .string_interner
                    .get(*s)
                    .map(|s| s.to_string())
                    .unwrap_or_else(|| String::new());
                self.builder.build_string(string_content)
            }
            HirLiteral::Bool(b) => self.builder.build_bool(*b),
            HirLiteral::Regex { pattern, flags } => {
                // ~/pattern/flags => haxe_ereg_new("pattern", "flags")
                let pattern_str = self
                    .string_interner
                    .get(*pattern)
                    .map(|s| s.to_string())
                    .unwrap_or_default();
                let flags_str = self
                    .string_interner
                    .get(*flags)
                    .map(|s| s.to_string())
                    .unwrap_or_default();
                let pattern_val = self.builder.build_string(pattern_str)?;
                let flags_val = self.builder.build_string(flags_str)?;
                let ereg_new = self.get_or_register_extern_function(
                    "haxe_ereg_new",
                    vec![IrType::String, IrType::String],
                    IrType::Ptr(Box::new(IrType::U8)),
                );
                self.builder.build_call_direct(
                    ereg_new,
                    vec![pattern_val, flags_val],
                    IrType::Ptr(Box::new(IrType::U8)),
                )
            }
        }
    }

    /// Fill in default argument values for a function call when fewer args are provided
    /// than the function expects. `arg_regs` already contains the lowered arguments
    /// (possibly including implicit 'this' for methods/constructors).
    /// `has_implicit_this` indicates whether arg_regs[0] is an implicit 'this' pointer
    /// that is NOT part of the user-visible params.
    fn fill_default_args(
        &mut self,
        func_id: IrFunctionId,
        arg_regs: &mut Vec<IrId>,
        has_implicit_this: bool,
    ) {
        let user_arg_count = if has_implicit_this {
            arg_regs.len().saturating_sub(1)
        } else {
            arg_regs.len()
        };

        // Try HIR-level defaults first (available for freshly compiled functions)
        if let Some(defaults) = self.function_param_defaults.get(&func_id).cloned() {
            if user_arg_count >= defaults.len() {
                return; // All args provided
            }
            for i in user_arg_count..defaults.len() {
                if let Some(ref default_expr) = defaults[i] {
                    if let Some(reg) = self.lower_expression(default_expr) {
                        arg_regs.push(reg);
                    }
                }
            }
            return;
        }

        // Fallback for BLADE-cached or cross-module functions: HIR defaults aren't available.
        // Fill missing params with null/zero using the correct type from the signature.
        // Check both local functions and extern function declarations (cross-module calls).
        let sig_params: Vec<IrType> = self
            .builder
            .module
            .functions
            .get(&func_id)
            .map(|f| {
                f.signature
                    .parameters
                    .iter()
                    .map(|p| p.ty.clone())
                    .collect()
            })
            .or_else(|| {
                self.builder.module.extern_functions.get(&func_id).map(|f| {
                    f.signature
                        .parameters
                        .iter()
                        .map(|p| p.ty.clone())
                        .collect()
                })
            })
            .or_else(|| self.external_function_param_types.get(&func_id).cloned())
            .unwrap_or_default();

        let sig_param_count = if sig_params.is_empty() {
            self.external_constructor_param_counts
                .get(&func_id)
                .copied()
                .unwrap_or(0)
        } else {
            sig_params.len()
        };

        let total_provided = arg_regs.len();
        if total_provided < sig_param_count {
            for i in total_provided..sig_param_count {
                // Use the correct type from the function signature
                let default_val = if i < sig_params.len() {
                    match &sig_params[i] {
                        IrType::I32 | IrType::U32 => IrValue::I32(0),
                        IrType::F32 => IrValue::F32(0.0),
                        IrType::F64 => IrValue::F64(0.0),
                        IrType::Bool => IrValue::Bool(false),
                        _ => IrValue::I64(0), // pointers, strings, etc.
                    }
                } else {
                    IrValue::I64(0)
                };
                if let Some(reg) = self.builder.build_const(default_val) {
                    arg_regs.push(reg);
                }
            }
        }
    }

    fn build_function_signature(&self, func: &HirFunction) -> super::IrFunctionSignature {
        let mut builder = FunctionSignatureBuilder::new();

        // Add type parameters from the HIR function (for generic functions)
        for type_param in &func.type_params {
            let param_name = self
                .string_interner
                .get(type_param.name)
                .map(|s| s.to_string())
                .unwrap_or_else(|| format!("T{}", type_param.name.as_raw()));
            builder = builder.type_param(param_name);
        }

        for param in &func.params {
            let param_type = self.convert_type(param.ty);
            builder = builder.param(param.name.to_string(), param_type);
        }

        let return_type = self.convert_type(func.return_type);
        builder = builder.returns(return_type);

        if func.is_extern {
            builder = builder.calling_convention(CallingConvention::C);
        }

        builder.build()
    }

    /// Build function signature with class type parameters (for generic class methods)
    fn build_function_signature_with_class_type_params(
        &self,
        func: &HirFunction,
        class_type_params: &[HirTypeParam],
    ) -> super::IrFunctionSignature {
        let mut builder = FunctionSignatureBuilder::new();

        // Collect all type param names (class + method) for TypeVar resolution
        let mut type_param_names: Vec<String> = Vec::new();

        // Add class type parameters first (T, U, etc from the generic class)
        for type_param in class_type_params {
            let param_name = self
                .string_interner
                .get(type_param.name)
                .map(|s| s.to_string())
                .unwrap_or_else(|| format!("T{}", type_param.name.as_raw()));
            type_param_names.push(param_name.clone());
            builder = builder.type_param(param_name);
        }

        // Add method's own type parameters (if any)
        for type_param in &func.type_params {
            let param_name = self
                .string_interner
                .get(type_param.name)
                .map(|s| s.to_string())
                .unwrap_or_else(|| format!("T{}", type_param.name.as_raw()));
            type_param_names.push(param_name.clone());
            builder = builder.type_param(param_name);
        }

        for param in &func.params {
            let param_type = self.convert_type(param.ty);
            builder = builder.param(param.name.to_string(), param_type);
        }

        // Use TypeVar only for return type so the monomorphizer and call-site
        // can resolve the concrete return type. Parameters stay I64 (type-erased)
        // to keep the function body compilable as a generic template.
        let return_type = self.convert_type_or_type_var(func.return_type, &type_param_names);
        builder = builder.returns(return_type);

        if func.is_extern {
            builder = builder.calling_convention(CallingConvention::C);
        }

        builder.build()
    }

    /// Like convert_type but returns TypeVar for TypeParameter types that match
    /// a known type param name. This preserves generic type info in function signatures
    /// so the monomorphizer can specialize them.
    fn convert_type_or_type_var(
        &self,
        type_id: crate::tast::TypeId,
        type_param_names: &[String],
    ) -> IrType {
        if !type_param_names.is_empty() {
            if let Some(name) = self.resolve_type_param_name(type_id) {
                if type_param_names.contains(&name) {
                    return IrType::TypeVar(name);
                }
            }
        }
        self.convert_type(type_id)
    }

    /// Build function signature for an instance method with implicit 'this' parameter
    fn build_instance_method_signature(
        &self,
        func: &HirFunction,
        class_type_id: TypeId,
    ) -> super::IrFunctionSignature {
        let mut builder = FunctionSignatureBuilder::new();

        // Add type parameters from the HIR function (for generic methods)
        for type_param in &func.type_params {
            let param_name = self
                .string_interner
                .get(type_param.name)
                .map(|s| s.to_string())
                .unwrap_or_else(|| format!("T{}", type_param.name.as_raw()));
            builder = builder.type_param(param_name);
        }

        // Add implicit 'this' parameter as first parameter
        // 'this' is always a pointer to the class instance, regardless of generic parameters
        let this_type = match self.convert_type(class_type_id) {
            IrType::Ptr(_) => IrType::Ptr(Box::new(IrType::Void)),
            // If convert_type failed to resolve (e.g., generic class without instantiation),
            // default to pointer since 'this' is always a pointer to instance
            _ => IrType::Ptr(Box::new(IrType::Void)),
        };

        builder = builder.param("this".to_string(), this_type);

        // Add regular parameters
        for param in &func.params {
            let param_name = self
                .string_interner
                .get(param.name)
                .map(|s| s.to_string())
                .unwrap_or_else(|| format!("param_{}", param.symbol_id.as_raw()));
            let param_type = self.convert_type(param.ty);
            builder = builder.param(param_name, param_type);
        }

        let return_type = self.convert_type(func.return_type);
        builder = builder.returns(return_type);

        if func.is_extern {
            builder = builder.calling_convention(CallingConvention::C);
        }

        builder.build()
    }

    fn is_terminated(&self) -> bool {
        let block_id = match self.builder.current_block() {
            Some(id) => id,
            None => return false,
        };

        self.builder
            .current_function()
            .and_then(|func| func.cfg.get_block(block_id))
            .map(|block| block.is_terminated())
            .unwrap_or(false)
    }

    fn ensure_terminator(&mut self) {
        let is_term = self.is_terminated();
        // eprintln!(
        //     "DEBUG ensure_terminator: is_terminated={}, current_func={:?}",
        //     is_term,
        //     self.builder.current_function().map(|f| &f.name)
        // );
        if !is_term {
            // debug!("ensure_terminator: Adding implicit return(None)");
            self.builder.build_return(None);
        }
    }

    fn find_loop_context(&self, label: Option<&SymbolId>) -> Option<&LoopContext> {
        if let Some(label) = label {
            self.loop_stack
                .iter()
                .rev()
                .find(|ctx| ctx.label.as_ref() == Some(label))
        } else {
            self.loop_stack.last()
        }
    }

    /// If `type_id` resolves to a Class with a `toString()` in the current module,
    /// call `obj.toString()` and return the resulting `*HaxeString` register.
    /// Returns `Some(string_reg)` on success, `None` if not a class or toString not found.
    fn try_call_tostring(&mut self, obj_reg: IrId, type_id: TypeId) -> Option<Option<IrId>> {
        // Get the class symbol_id from the type_table
        let class_symbol = {
            let type_table = self.type_table.borrow();
            type_table.get(type_id).and_then(|ti| {
                if let TypeKind::Class { symbol_id, .. } = &ti.kind {
                    Some(*symbol_id)
                } else {
                    None
                }
            })
        };

        let class_symbol = match class_symbol {
            Some(s) => s,
            None => return Some(None), // Not a class type
        };

        // Find the toString method symbol for THIS specific class by scanning HIR type declarations
        let mut tostring_symbol = None;
        for (_tid, type_decl) in self.current_hir_types.iter() {
            if let HirTypeDecl::Class(class) = type_decl {
                if class.symbol_id == class_symbol {
                    // Found the class — look for a toString method
                    for method in &class.methods {
                        let method_name =
                            self.string_interner.get(method.function.name).unwrap_or("");
                        if method_name == "toString" && !method.is_static {
                            tostring_symbol = Some(method.function.symbol_id);
                            break;
                        }
                    }
                    break;
                }
            }
        }

        if let Some(tostring_symbol) = tostring_symbol {
            // User class with toString() in HIR — look up compiled function
            if let Some(tostring_id) = self.function_map.get(&tostring_symbol).copied() {
                let string_ptr_ty = IrType::Ptr(Box::new(IrType::String));
                let string_reg =
                    self.builder
                        .build_call_direct(tostring_id, vec![obj_reg], string_ptr_ty)?;
                return Some(Some(string_reg));
            }
        }

        // Fallback: check stdlib_mapping for a registered toString() method
        // This handles stdlib classes (StringMap, IntMap, Date, Bytes, etc.)
        let class_name = self
            .symbol_table
            .get_symbol(class_symbol)
            .and_then(|s| self.string_interner.get(s.name))
            .unwrap_or("")
            .to_string();

        if let Some((_sig, mapping)) = self.stdlib_mapping.find_by_name(&class_name, "toString") {
            let runtime_name = mapping.runtime_name;
            let is_mir_wrapper = mapping.is_mir_wrapper;
            let ptr_void = IrType::Ptr(Box::new(IrType::Void));

            let func_id = if is_mir_wrapper {
                self.register_stdlib_mir_forward_ref(runtime_name, vec![ptr_void.clone()], ptr_void)
            } else {
                self.get_or_register_extern_function(runtime_name, vec![ptr_void.clone()], ptr_void)
            };

            let string_ptr_ty = IrType::Ptr(Box::new(IrType::String));
            if let Some(str_ptr) = self.builder.build_call_direct(
                func_id,
                vec![obj_reg],
                IrType::Ptr(Box::new(IrType::Void)),
            ) {
                // Cast from Ptr(Void) to Ptr(String) for trace
                let string_reg = self
                    .builder
                    .build_cast(str_ptr, IrType::Ptr(Box::new(IrType::Void)), string_ptr_ty)
                    .unwrap_or(str_ptr);
                return Some(Some(string_reg));
            }
        }

        Some(None) // No toString() found
    }

    /// Check if a TypeId refers to a TypeParameter in the type table.
    /// If so, returns the type param name for tag-based generic dispatch.
    fn resolve_type_param_name(&self, type_id: crate::tast::TypeId) -> Option<String> {
        let type_table = self.type_table.borrow();
        if let Some(ti) = type_table.get(type_id) {
            if let crate::tast::TypeKind::TypeParameter {
                symbol_id,
                constraints,
                ..
            } = &ti.kind
            {
                if constraints.is_empty() || !self.has_interface_constraint(constraints) {
                    return self
                        .symbol_table
                        .get_symbol(*symbol_id)
                        .and_then(|s| self.string_interner.get(s.name))
                        .map(|s| s.to_string());
                }
            }
        }
        None
    }

    /// Convert a value to a string pointer
    /// Uses the appropriate *_to_string MIR wrapper based on the source type.
    /// If hir_type_id is provided and is a TypeParameter, uses tag-based generic dispatch.
    fn convert_to_string_with_hint(
        &mut self,
        value: IrId,
        from_type: &IrType,
        hir_type_id: Option<crate::tast::TypeId>,
    ) -> Option<IrId> {
        // Check if the HIR type is a TypeParameter — if so, use tag-based dispatch
        // even though the MIR type is I64 (type-erased).
        if let Some(type_id) = hir_type_id {
            if let Some(type_param_name) = self.resolve_type_param_name(type_id) {
                let tag_reg = self.builder.build_const(IrValue::I32(0))?;
                if let Some(func) = self.builder.current_function_mut() {
                    func.type_param_tag_fixups.push((tag_reg, type_param_name));
                }
                let func_id = self.get_or_register_extern_function(
                    "haxe_value_to_string_by_tag",
                    vec![IrType::I64, IrType::I32],
                    IrType::Ptr(Box::new(IrType::String)),
                );
                let val_as_i64 = self
                    .builder
                    .build_bitcast(value, IrType::I64)
                    .unwrap_or(value);
                return self.builder.build_call_direct(
                    func_id,
                    vec![val_as_i64, tag_reg],
                    IrType::String,
                );
            }
        }
        self.convert_to_string(value, from_type)
    }

    /// Convert a value to a string pointer
    /// Uses the appropriate *_to_string MIR wrapper based on the source type
    fn convert_to_string(&mut self, value: IrId, from_type: &IrType) -> Option<IrId> {
        let mir_wrapper = match from_type {
            IrType::I32 | IrType::I64 => "int_to_string",
            IrType::F32 | IrType::F64 => "float_to_string",
            IrType::Bool => "bool_to_string",
            IrType::String => {
                // Already a string
                return Some(value);
            }
            IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::String) => {
                // Pointer to string - already a string pointer
                return Some(value);
            }
            IrType::Ptr(inner) if matches!(inner.as_ref(), IrType::Void) => {
                // Ptr(Void) is often an unresolved generic / DynBox - use runtime dispatch
                debug!("[CONVERT TO STRING] Ptr(Void) detected, using runtime dispatch");
                return self.convert_dynamic_to_string(value);
            }
            IrType::Ptr(_) => {
                // Other pointer types - use runtime dispatch via DynBox to_string
                return self.convert_dynamic_to_string(value);
            }
            IrType::TypeVar(ref type_param_name) => {
                // Generic type parameter — use type-tag-aware conversion.
                // The tag is a placeholder (0) that gets resolved during
                // inlining or monomorphization via type_param_tag_fixups.
                let tag_reg = self.builder.build_const(IrValue::I32(0))?;
                if let Some(func) = self.builder.current_function_mut() {
                    func.type_param_tag_fixups
                        .push((tag_reg, type_param_name.clone()));
                }
                let func_id = self.get_or_register_extern_function(
                    "haxe_value_to_string_by_tag",
                    vec![IrType::I64, IrType::I32],
                    IrType::Ptr(Box::new(IrType::String)),
                );
                // Bitcast value to I64 for the generic call
                let val_as_i64 = self
                    .builder
                    .build_bitcast(value, IrType::I64)
                    .unwrap_or(value);
                return self.builder.build_call_direct(
                    func_id,
                    vec![val_as_i64, tag_reg],
                    IrType::String,
                );
            }
            IrType::Any => {
                // Unknown types - use runtime dispatch
                return self.convert_dynamic_to_string(value);
            }
            _ => "int_to_string", // Fallback
        };

        debug!(
            "[CONVERT TO STRING] Using {} for type {:?}",
            mir_wrapper, from_type
        );

        // Resolve the MIR wrapper's signature — int_to_string takes I64 (matching runtime),
        // float_to_string takes F64, bool_to_string takes Bool.
        // The Cranelift backend's C ABI auto-cast handles any I32↔I64 promotion
        // at the call site, so no manual casting is needed here.
        let func_id = self.register_stdlib_mir_forward_ref(
            mir_wrapper,
            vec![from_type.clone()],
            IrType::String,
        );

        self.builder
            .build_call_direct(func_id, vec![value], IrType::String)
    }

    /// Get the effective IR type for an expression, checking symbol_ir_types for pattern-bound variables.
    fn resolve_expr_ir_type(&self, expr: &HirExpr, default_type: IrType) -> IrType {
        if let HirExprKind::Variable { symbol, .. } = &expr.kind {
            if let Some(resolved) = self.symbol_ir_types.get(symbol) {
                return resolved.clone();
            }
        }
        default_type
    }

    /// Get the effective TypeId for an expression, checking symbol_type_ids for pattern-bound variables.
    fn resolve_expr_type_id(&self, expr: &HirExpr) -> TypeId {
        if let HirExprKind::Variable { symbol, .. } = &expr.kind {
            if let Some(resolved) = self.symbol_type_ids.get(symbol) {
                return *resolved;
            }
        }
        expr.ty
    }

    /// Convert a dynamic/unknown-type value to string using runtime dispatch.
    /// Calls haxe_std_string_ptr(ptr) which reads DynBox and dispatches to_string.
    fn convert_dynamic_to_string(&mut self, value: IrId) -> Option<IrId> {
        let func_id = self.get_or_register_extern_function(
            "haxe_std_string_ptr",
            vec![IrType::Ptr(Box::new(IrType::U8))],
            IrType::Ptr(Box::new(IrType::String)),
        );

        // Bitcast value to *mut u8 for the runtime call
        let ptr_val = self
            .builder
            .build_bitcast(value, IrType::Ptr(Box::new(IrType::U8)))
            .unwrap_or(value);

        self.builder.build_call_direct(
            func_id,
            vec![ptr_val],
            IrType::Ptr(Box::new(IrType::String)),
        )
    }

    /// Resolve a TypeId to the abstract's qualified name, for looking up @:from/@:to rules.
    /// Uses qualified_name for user-defined abstracts, native_name for extern abstracts (e.g., SIMD4f).
    /// Returns None if the TypeId is not an abstract type.
    fn resolve_abstract_name(&self, type_id: TypeId) -> Option<InternedString> {
        let type_table = self.type_table.borrow();
        if let Some(ti) = type_table.get(type_id) {
            if let TypeKind::Abstract { symbol_id, .. } = &ti.kind {
                if let Some(sym) = self.symbol_table.get_symbol(*symbol_id) {
                    return sym.qualified_name.or(sym.native_name).or(Some(sym.name));
                }
            }
        }
        None
    }

    /// Resolve a TypeId to its stdlib class name (e.g., "Array", "String").
    /// Takes a borrowed type_table to avoid double-borrow issues.
    fn resolve_type_class_name_with(
        &self,
        type_table: &TypeTable,
        type_id: TypeId,
    ) -> Option<String> {
        let type_info = type_table.get(type_id)?;
        match &type_info.kind {
            TypeKind::Class { symbol_id, .. } | TypeKind::Abstract { symbol_id, .. } => {
                self.symbol_table.get_symbol(*symbol_id).and_then(|s| {
                    s.qualified_name
                        .or(Some(s.name))
                        .and_then(|n| self.string_interner.get(n))
                        .map(|s| s.replace(".", "_"))
                })
            }
            TypeKind::GenericInstance { base_type, .. } => {
                self.resolve_type_class_name_with(type_table, *base_type)
            }
            TypeKind::TypeAlias { target_type, .. } => {
                self.resolve_type_class_name_with(type_table, *target_type)
            }
            _ => None,
        }
    }

    /// Try to apply an abstract @:from conversion in a Cast expression.
    /// Returns Some(result_reg) if a matching @:from rule was found, None otherwise.
    fn try_abstract_from_cast(&mut self, expr: &HirExpr, target: TypeId) -> Option<IrId> {
        let source_type = expr.ty;
        let abs_name = self.resolve_abstract_name(target)?;

        // Look up @:from rules for the target abstract
        let matching_rule = self
            .abstract_from_rules
            .get(&abs_name)
            .and_then(|rules| rules.iter().find(|r| r.from_type == source_type))
            .cloned();

        if let Some(rule) = matching_rule {
            if let Some(cast_func_sym) = rule.cast_function {
                // Has a conversion function — resolve and call it
                let value_reg = self.lower_expression(expr)?;
                let func_id = self.resolve_abstract_conversion_function(cast_func_sym, target)?;
                let result_type = self.convert_type(target);
                self.builder
                    .build_call_direct(func_id, vec![value_reg], result_type)
            } else {
                // No conversion function — keyword from (identity conversion)
                let value_reg = self.lower_expression(expr)?;
                let from_type = self.convert_type(source_type);
                let to_type = self.convert_type(target);
                if from_type == to_type {
                    Some(value_reg)
                } else {
                    self.builder.build_cast(value_reg, from_type, to_type)
                }
            }
        } else {
            // Fallback: for extern/imported abstracts (e.g., SIMD4f) whose @:from rules
            // weren't populated (not in file.abstracts), try stdlib mapping directly.
            self.try_stdlib_from_cast(expr, target, &abs_name)
        }
    }

    /// Fallback @:from conversion for extern abstracts via stdlib mapping.
    /// Searches for a static "fromArray"/"fromXxx" method in the abstract's stdlib class.
    fn try_stdlib_from_cast(
        &mut self,
        expr: &HirExpr,
        target: TypeId,
        abs_name: &InternedString,
    ) -> Option<IrId> {
        // Resolve abstract's stdlib class name (e.g., "rayzor_SIMD4f")
        let class_name = {
            let type_table = self.type_table.borrow();
            let ti = type_table.get(target)?;
            if let TypeKind::Abstract { symbol_id, .. } = &ti.kind {
                let sym = self.symbol_table.get_symbol(*symbol_id)?;
                sym.native_name
                    .and_then(|nn| self.string_interner.get(nn))
                    .map(|n| n.replace("::", "_"))
                    .or_else(|| {
                        self.string_interner
                            .get(sym.name)
                            .map(|n| format!("rayzor_{}", n))
                    })
            } else {
                None
            }
        }?;

        // Search stdlib mapping for a static @:from method (e.g., "fromArray")
        let mapping_info = self
            .stdlib_mapping
            .find_by_name(&class_name, "fromArray")
            .map(|(_, m)| (m.runtime_name.to_string(), m.is_mir_wrapper));

        let (runtime_func, is_mir_wrapper) = mapping_info?;

        let value_reg = self.lower_expression(expr)?;
        let result_type = self.convert_type(target);
        let param_types = vec![IrType::Ptr(Box::new(IrType::Void))];

        let func_id = if is_mir_wrapper {
            self.register_stdlib_mir_forward_ref(&runtime_func, param_types, result_type.clone())
        } else {
            self.get_or_register_extern_function(&runtime_func, param_types, result_type.clone())
        };

        self.builder
            .build_call_direct(func_id, vec![value_reg], result_type)
    }

    /// Resolve an abstract @:from/@:to conversion function to an IrFunctionId.
    /// Tries function_map (user-defined), external_function_map, then stdlib_mapping.
    fn resolve_abstract_conversion_function(
        &mut self,
        symbol: SymbolId,
        target_type: TypeId,
    ) -> Option<IrFunctionId> {
        // 1. Check function_map (user-defined abstract methods)
        if let Some(&func_id) = self.function_map.get(&symbol) {
            return Some(func_id);
        }
        // 2. Check external_function_map
        if let Some(&func_id) = self.external_function_map.get(&symbol) {
            return Some(func_id);
        }
        // 3. Fallback: look up by qualified name
        if let Some(sym_info) = self.symbol_table.get_symbol(symbol) {
            if let Some(qn) = sym_info.qualified_name {
                if let Some(qualified) = self.string_interner.get(qn) {
                    if let Some(&func_id) = self.external_function_name_map.get(qualified) {
                        return Some(func_id);
                    }
                }
            }
            // 4. Try stdlib mapping by method name for @:coreType abstracts
            if let Some(method_name) = self.string_interner.get(sym_info.name) {
                // Check if this is a stdlib abstract (e.g., SIMD4f)
                let type_table = self.type_table.borrow();
                if let Some(ti) = type_table.get(target_type) {
                    if let TypeKind::Abstract { symbol_id, .. } = &ti.kind {
                        if let Some(abs_sym) = self.symbol_table.get_symbol(*symbol_id) {
                            let class_name = abs_sym
                                .native_name
                                .and_then(|nn| self.string_interner.get(nn))
                                .map(|n| n.replace("::", "_"))
                                .or_else(|| {
                                    self.string_interner
                                        .get(abs_sym.name)
                                        .map(|n| format!("rayzor_{}", n))
                                });
                            drop(type_table);
                            if let Some(class) = class_name {
                                // Try stdlib mapping (e.g., rayzor_SIMD4f + fromArray)
                                if let Some((_, mapping)) =
                                    self.stdlib_mapping.find_by_name(&class, method_name)
                                {
                                    let runtime_func = mapping.runtime_name;
                                    let result_type = self.convert_type(target_type);
                                    if mapping.is_mir_wrapper {
                                        // MIR wrapper — register as forward ref
                                        let func_id = self.register_stdlib_mir_forward_ref(
                                            runtime_func,
                                            vec![IrType::Ptr(Box::new(IrType::Void))],
                                            result_type,
                                        );
                                        return Some(func_id);
                                    } else {
                                        let func_id = self.get_or_register_extern_function(
                                            runtime_func,
                                            vec![IrType::Ptr(Box::new(IrType::Void))],
                                            result_type,
                                        );
                                        return Some(func_id);
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
        None
    }

    /// Try to apply an abstract @:from conversion in Let/Assign context.
    /// Returns Some(converted_reg) if a matching @:from rule was found, None otherwise.
    fn maybe_abstract_from_convert(
        &mut self,
        value: IrId,
        source_type: TypeId,
        target_type: TypeId,
    ) -> Option<IrId> {
        let abs_name = self.resolve_abstract_name(target_type)?;

        let matching_rule = self
            .abstract_from_rules
            .get(&abs_name)
            .and_then(|rules| rules.iter().find(|r| r.from_type == source_type))
            .cloned();

        let rule = matching_rule?;

        if let Some(cast_func_sym) = rule.cast_function {
            let func_id = self.resolve_abstract_conversion_function(cast_func_sym, target_type)?;
            let result_type = self.convert_type(target_type);
            self.builder
                .build_call_direct(func_id, vec![value], result_type)
        } else {
            // No conversion function — keyword from, value passes through
            None
        }
    }

    fn maybe_box_value(
        &mut self,
        value: IrId,
        value_ty: TypeId,
        target_ty: TypeId,
    ) -> Option<IrId> {
        use crate::tast::TypeKind;

        // Check if target is Dynamic and value is concrete
        // Clone TypeKind to avoid borrow checker issues
        let (target_is_dynamic, value_kind_cloned) = {
            let type_table = self.type_table.borrow();
            let target_is_dyn = matches!(
                type_table.get(target_ty).map(|t| &t.kind),
                Some(TypeKind::Dynamic)
            );
            let value_kind = type_table.get(value_ty).map(|t| t.kind.clone());
            (target_is_dyn, value_kind)
        };

        let value_is_dynamic = matches!(&value_kind_cloned, Some(TypeKind::Dynamic));
        let needs_boxing = target_is_dynamic && !value_is_dynamic;

        if !needs_boxing {
            return Some(value);
        }

        // Determine which boxing function to call based on value type
        match &value_kind_cloned {
            // Value types (need malloc + copy)
            Some(TypeKind::Int) => {
                debug!("[BOXING] Auto-boxing Int to Dynamic using haxe_box_int_ptr");
                let value_mir_type = self
                    .builder
                    .get_register_type(value)
                    .unwrap_or_else(|| self.convert_type(value_ty));
                let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                let box_func_id = self.get_or_register_extern_function(
                    "haxe_box_int_ptr",
                    vec![value_mir_type],
                    ptr_u8,
                );
                self.builder.build_call_direct(
                    box_func_id,
                    vec![value],
                    IrType::Ptr(Box::new(IrType::U8)),
                )
            }
            Some(TypeKind::Float) => {
                debug!("[BOXING] Auto-boxing Float to Dynamic using haxe_box_float_ptr");
                let value_mir_type = self
                    .builder
                    .get_register_type(value)
                    .unwrap_or_else(|| self.convert_type(value_ty));
                let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                let box_func_id = self.get_or_register_extern_function(
                    "haxe_box_float_ptr",
                    vec![value_mir_type],
                    ptr_u8,
                );
                self.builder.build_call_direct(
                    box_func_id,
                    vec![value],
                    IrType::Ptr(Box::new(IrType::U8)),
                )
            }
            Some(TypeKind::Bool) => {
                debug!("[BOXING] Auto-boxing Bool to Dynamic using haxe_box_bool_ptr");
                let value_mir_type = self
                    .builder
                    .get_register_type(value)
                    .unwrap_or_else(|| self.convert_type(value_ty));
                let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                let box_func_id = self.get_or_register_extern_function(
                    "haxe_box_bool_ptr",
                    vec![value_mir_type],
                    ptr_u8,
                );
                self.builder.build_call_direct(
                    box_func_id,
                    vec![value],
                    IrType::Ptr(Box::new(IrType::U8)),
                )
            }

            // Reference types (already pointers, just wrap with type_id)
            Some(TypeKind::Class { .. })
            | Some(TypeKind::Enum { .. })
            | Some(TypeKind::Interface { .. })
            | Some(TypeKind::Anonymous { .. })
            | Some(TypeKind::Array { .. }) => {
                debug!(
                    "[BOXING] Auto-boxing reference type {:?} to Dynamic using box_reference",
                    value_kind_cloned
                );

                // Get TypeId as u32
                let type_id_u32 = value_ty.as_raw();

                // Create constant for type_id
                let type_id_const = self.builder.build_const(IrValue::U32(type_id_u32))?;

                // Get pointer type
                let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));

                // Call box_reference_ptr(value_ptr, type_id)
                let box_func_id = self.get_or_register_extern_function(
                    "haxe_box_reference_ptr",
                    vec![ptr_u8.clone(), IrType::U32],
                    ptr_u8.clone(),
                );

                self.builder
                    .build_call_direct(box_func_id, vec![value, type_id_const], ptr_u8)
            }

            Some(TypeKind::Function { .. }) => {
                debug!("[BOXING] Auto-boxing Function to Dynamic using haxe_box_function_ptr");
                self.box_value_for_dynamic(value, value_ty)
            }

            Some(TypeKind::String) => {
                debug!("[BOXING] Auto-boxing String to Dynamic using haxe_box_string_ptr");
                let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                let box_func_id = self.get_or_register_extern_function(
                    "haxe_box_string_ptr",
                    vec![IrType::String],
                    ptr_u8.clone(),
                );
                self.builder
                    .build_call_direct(box_func_id, vec![value], ptr_u8)
            }

            // Abstract, TypeParam, etc. — skip boxing for unsupported types
            _ => {
                debug!(
                    "[BOXING] Unsupported type for boxing: {:?}",
                    value_kind_cloned
                );
                Some(value) // Skip boxing for unsupported types
            }
        }
    }

    /// Box a primitive MIR value to a DynamicValue pointer.
    /// Used for type harmonization in conditional expressions (e.g., null vs i64 in phi).
    fn box_primitive_to_dynamic(&mut self, value: IrId, reg_ty: IrType) -> Option<IrId> {
        let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
        match reg_ty {
            IrType::I32 | IrType::I64 => {
                let v64 = if matches!(reg_ty, IrType::I32) {
                    self.builder.build_cast(value, IrType::I32, IrType::I64)?
                } else {
                    value
                };
                let box_func = self.get_or_register_extern_function(
                    "haxe_box_int_ptr",
                    vec![IrType::I64],
                    ptr_u8.clone(),
                );
                self.builder.build_call_direct(box_func, vec![v64], ptr_u8)
            }
            IrType::F64 | IrType::F32 => {
                let v64 = if matches!(reg_ty, IrType::F32) {
                    self.builder.build_cast(value, IrType::F32, IrType::F64)?
                } else {
                    value
                };
                let box_func = self.get_or_register_extern_function(
                    "haxe_box_float_ptr",
                    vec![IrType::F64],
                    ptr_u8.clone(),
                );
                self.builder.build_call_direct(box_func, vec![v64], ptr_u8)
            }
            IrType::Bool => {
                let v64 = self.builder.build_cast(value, IrType::Bool, IrType::I64)?;
                let box_func = self.get_or_register_extern_function(
                    "haxe_box_bool_ptr",
                    vec![IrType::I64],
                    ptr_u8.clone(),
                );
                self.builder.build_call_direct(box_func, vec![v64], ptr_u8)
            }
            _ => None,
        }
    }

    /// Auto-box a primitive value when assigning to a Null<T> (Optional{primitive}) variable.
    /// Returns Some(boxed_ptr) if boxing was performed, None if not needed.
    fn maybe_box_for_optional(
        &mut self,
        value: IrId,
        value_ty: TypeId,
        target_ty: TypeId,
    ) -> Option<IrId> {
        use crate::tast::TypeKind;

        // Check if target is Optional with a primitive inner type
        let inner_type = {
            let type_table = self.type_table.borrow();
            match type_table.get(target_ty).map(|t| &t.kind) {
                Some(TypeKind::Optional { inner_type }) => Some(*inner_type),
                _ => return None,
            }
        };
        let inner_type = inner_type?;

        // Check if inner type is a TypeParameter — use typed boxing with fixup
        let is_type_param = {
            let type_table = self.type_table.borrow();
            match type_table.get(inner_type).map(|t| &t.kind) {
                Some(TypeKind::TypeParameter { symbol_id, .. }) => {
                    let tp_name = self
                        .symbol_table
                        .get_symbol(*symbol_id)
                        .and_then(|sym| self.string_interner.get(sym.name))
                        .map(|s| s.to_string());
                    tp_name
                }
                _ => None,
            }
        };

        if let Some(tp_name) = is_type_param {
            // TypeParameter inner type: use haxe_box_typed_ptr with a fixup
            // The monomorphizer will replace the type_tag with the correct value
            let val_ir = self.builder.get_register_type(value);
            match val_ir {
                Some(IrType::Ptr(_)) => return None, // Already a pointer
                _ => {}
            }

            let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));

            // Ensure value is I64
            let v64 = match val_ir {
                Some(IrType::I32) => self.builder.build_cast(value, IrType::I32, IrType::I64)?,
                Some(IrType::Bool) => self.builder.build_cast(value, IrType::Bool, IrType::I64)?,
                _ => value,
            };

            // Create type_tag constant with fixup (placeholder 0, monomorphizer fills in)
            let tag_reg = self.builder.build_const(IrValue::I32(0))?;
            if let Some(func) = self.builder.current_function_mut() {
                func.type_param_tag_fixups.push((tag_reg, tp_name));
            }

            let box_func = self.get_or_register_extern_function(
                "haxe_box_typed_ptr",
                vec![IrType::I64, IrType::I32],
                ptr_u8.clone(),
            );
            return self
                .builder
                .build_call_direct(box_func, vec![v64, tag_reg], ptr_u8);
        }

        let inner_ir = self.convert_type(inner_type);
        // Only box primitives — reference types in Optional are already nullable
        if !matches!(
            inner_ir,
            IrType::I32 | IrType::I64 | IrType::F64 | IrType::F32 | IrType::Bool
        ) {
            return None;
        }

        // Check if source is already a pointer (already boxed, or null literal)
        let val_ir = self.builder.get_register_type(value);
        match val_ir {
            Some(IrType::Ptr(_)) => return None, // Already a pointer, no boxing needed
            _ => {}
        }

        let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));

        // Check if value is the null literal (I64(0) or I32(0)) — cast to null pointer
        // We can't easily detect null literals, but if source type is Dynamic/Unknown
        // and register type is I64, it's likely a null literal or dynamic value.
        let source_is_null_literal = {
            let type_table = self.type_table.borrow();
            matches!(
                type_table.get(value_ty).map(|t| &t.kind),
                Some(TypeKind::Dynamic) | Some(TypeKind::Unknown) | None
            )
        };
        if source_is_null_literal && matches!(val_ir, Some(IrType::I64)) {
            // Cast null (i64 0) to Ptr(U8) null pointer
            return self.builder.build_cast(value, IrType::I64, ptr_u8);
        }

        // Box the primitive value
        match &inner_ir {
            IrType::I32 | IrType::I64 => {
                // Ensure value is I64 for haxe_box_int_ptr
                let v64 = if matches!(val_ir, Some(IrType::I32)) {
                    self.builder.build_cast(value, IrType::I32, IrType::I64)?
                } else {
                    value
                };
                let box_func = self.get_or_register_extern_function(
                    "haxe_box_int_ptr",
                    vec![IrType::I64],
                    ptr_u8.clone(),
                );
                self.builder.build_call_direct(box_func, vec![v64], ptr_u8)
            }
            IrType::F64 | IrType::F32 => {
                let v64 = if matches!(val_ir, Some(IrType::F32)) {
                    self.builder.build_cast(value, IrType::F32, IrType::F64)?
                } else {
                    value
                };
                let box_func = self.get_or_register_extern_function(
                    "haxe_box_float_ptr",
                    vec![IrType::F64],
                    ptr_u8.clone(),
                );
                self.builder.build_call_direct(box_func, vec![v64], ptr_u8)
            }
            IrType::Bool => {
                let v64 = self.builder.build_cast(value, IrType::Bool, IrType::I64)?;
                let box_func = self.get_or_register_extern_function(
                    "haxe_box_bool_ptr",
                    vec![IrType::I64],
                    ptr_u8.clone(),
                );
                self.builder.build_call_direct(box_func, vec![v64], ptr_u8)
            }
            _ => None,
        }
    }

    /// Auto-unbox a Null<T> (Optional{primitive}) value to its inner primitive type.
    /// Returns Some(unboxed_val) if unboxing was performed, None if not needed.
    fn maybe_unbox_optional(
        &mut self,
        value: IrId,
        source_ty: TypeId,
        target_ty: TypeId,
    ) -> Option<IrId> {
        use crate::tast::TypeKind;

        // Check if source is Optional with a primitive inner type
        let inner_type = {
            let type_table = self.type_table.borrow();
            match type_table.get(source_ty).map(|t| &t.kind) {
                Some(TypeKind::Optional { inner_type }) => Some(*inner_type),
                _ => return None,
            }
        };
        let inner_type = inner_type?;

        let inner_ir = self.convert_type(inner_type);
        let target_ir = self.convert_type(target_ty);

        // Only unbox when target is the matching primitive type
        let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
        match (&inner_ir, &target_ir) {
            (IrType::I32, IrType::I32) => {
                let unbox_func = self.get_or_register_extern_function(
                    "haxe_unbox_int_ptr",
                    vec![ptr_u8],
                    IrType::I64,
                );
                let result =
                    self.builder
                        .build_call_direct(unbox_func, vec![value], IrType::I64)?;
                self.builder.build_cast(result, IrType::I64, IrType::I32)
            }
            (IrType::F64, IrType::F64) => {
                let unbox_func = self.get_or_register_extern_function(
                    "haxe_unbox_float_ptr",
                    vec![ptr_u8],
                    IrType::F64,
                );
                self.builder
                    .build_call_direct(unbox_func, vec![value], IrType::F64)
            }
            (IrType::Bool, IrType::Bool) => {
                let unbox_func = self.get_or_register_extern_function(
                    "haxe_unbox_bool_ptr",
                    vec![ptr_u8],
                    IrType::I64,
                );
                let result =
                    self.builder
                        .build_call_direct(unbox_func, vec![value], IrType::I64)?;
                self.builder.build_cast(result, IrType::I64, IrType::Bool)
            }
            _ => None,
        }
    }

    /// Check if a TypeId is Optional{primitive} (Null<Int>, Null<Float>, Null<Bool>).
    fn is_optional_primitive(&self, type_id: TypeId) -> bool {
        use crate::tast::TypeKind;
        let type_table = self.type_table.borrow();
        if let Some(TypeKind::Optional { inner_type }) = type_table.get(type_id).map(|t| &t.kind) {
            let inner_ir = self.convert_type(*inner_type);
            matches!(
                inner_ir,
                IrType::I32 | IrType::I64 | IrType::F64 | IrType::F32 | IrType::Bool
            )
        } else {
            false
        }
    }

    /// Clone an anonymous object handle if the value type is Anonymous.
    /// This ensures each variable gets its own Box<Arc<AnonObject>> for proper COW semantics.
    /// Returns the cloned handle, or the original value if not anonymous.
    fn maybe_clone_anonymous(&mut self, value: IrId, value_ty: TypeId) -> IrId {
        use crate::tast::TypeKind;

        let is_anon = {
            let type_table = self.type_table.borrow();
            matches!(
                type_table.get(value_ty).map(|t| &t.kind),
                Some(TypeKind::Anonymous { .. })
            )
        };

        if !is_anon {
            return value;
        }

        let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
        let clone_func_id =
            self.get_or_register_extern_function("rayzor_anon_clone", vec![ptr_u8.clone()], ptr_u8);

        self.builder
            .build_call_direct(
                clone_func_id,
                vec![value],
                IrType::Ptr(Box::new(IrType::U8)),
            )
            .unwrap_or(value)
    }

    /// Try to register a structural subtyping view for an anonymous-typed variable.
    /// If source is a class or wider anon and target is a narrower anonymous type,
    /// records an AnonBacking so field access can be redirected at compile time.
    /// Returns true if a view was registered (caller should skip clone).
    fn try_register_anon_view(
        &mut self,
        symbol: SymbolId,
        _value: IrId,
        source_type: TypeId,
        target_type: TypeId,
    ) -> bool {
        let resolved_source = self.resolve_through_aliases(source_type);
        let resolved_target = self.resolve_through_aliases(target_type);

        // Target must be Anonymous
        let target_fields = {
            let type_table = self.type_table.borrow();
            if let Some(ty_info) = type_table.get(resolved_target) {
                if let TypeKind::Anonymous { fields } = &ty_info.kind {
                    let mut named: Vec<(String, TypeId)> = fields
                        .iter()
                        .filter_map(|f| {
                            self.string_interner
                                .get(f.name)
                                .map(|s| (s.to_string(), f.type_id))
                        })
                        .collect();
                    named.sort_by(|a, b| a.0.cmp(&b.0));
                    named
                } else {
                    return false;
                }
            } else {
                return false;
            }
        };

        if target_fields.is_empty() {
            return false;
        }

        // Check source kind
        let source_kind = {
            let type_table = self.type_table.borrow();
            type_table.get(resolved_source).map(|t| t.kind.clone())
        };

        // Extract class symbol if source is a class or generic instance of a class
        let class_symbol_opt = match &source_kind {
            Some(TypeKind::Class { symbol_id, .. }) => Some(*symbol_id),
            Some(TypeKind::GenericInstance { base_type, .. }) => {
                let type_table = self.type_table.borrow();
                if let Some(base_info) = type_table.get(*base_type) {
                    if let TypeKind::Class { symbol_id, .. } = &base_info.kind {
                        Some(*symbol_id)
                    } else {
                        None
                    }
                } else {
                    None
                }
            }
            _ => None,
        };

        if let Some(class_symbol) = class_symbol_opt {
            // Source is a class — build name → (gep_index, type) map from field_index_map
            let mut class_field_by_name: BTreeMap<String, (u32, TypeId)> = BTreeMap::new();
            for (field_sym, (class_ty, idx)) in &self.field_index_map {
                // Match by class type_id or by class symbol
                let matches = *class_ty == resolved_source || {
                    self.class_type_to_symbol
                        .get(class_ty)
                        .map_or(false, |s| *s == class_symbol)
                };
                if matches {
                    if let Some(sym) = self.symbol_table.get_symbol(*field_sym) {
                        if let Some(name) = self.string_interner.get(sym.name) {
                            class_field_by_name.insert(name.to_string(), (*idx, sym.type_id));
                        }
                    }
                }
            }

            // Check all target fields exist in the class
            let mut field_map = Vec::new();
            for (tgt_name, tgt_ty) in &target_fields {
                if let Some((gep_idx, _field_ty)) = class_field_by_name.get(tgt_name) {
                    field_map.push((tgt_name.clone(), *gep_idx, *tgt_ty));
                } else {
                    return false; // Target field not found in class
                }
            }

            self.anon_views.insert(
                symbol,
                AnonBacking::Class {
                    class_symbol,
                    class_type: resolved_source,
                    field_map,
                },
            );
            return true;
        }

        // Source is anonymous — check for wider-to-narrower
        if let Some(TypeKind::Anonymous { fields: src_fields }) = source_kind {
            let mut src_named: Vec<(String, TypeId)> = src_fields
                .iter()
                .filter_map(|f| {
                    self.string_interner
                        .get(f.name)
                        .map(|s| (s.to_string(), f.type_id))
                })
                .collect();
            src_named.sort_by(|a, b| a.0.cmp(&b.0));

            // If same field names, no remapping needed
            let src_names: Vec<&str> = src_named.iter().map(|(n, _)| n.as_str()).collect();
            let tgt_names: Vec<&str> = target_fields.iter().map(|(n, _)| n.as_str()).collect();
            if src_names == tgt_names {
                return false;
            }

            // Check all target fields exist in source, build remap
            let mut field_map = Vec::new();
            for (tgt_name, tgt_ty) in &target_fields {
                if let Some(src_idx) = src_named.iter().position(|(n, _)| n == tgt_name) {
                    field_map.push((tgt_name.clone(), src_idx, *tgt_ty));
                } else {
                    return false; // Target field not found in source
                }
            }

            self.anon_views.insert(
                symbol,
                AnonBacking::WiderAnon {
                    source_type: resolved_source,
                    field_map,
                },
            );
            return true;
        }

        false
    }

    /// Materialize an anon-backed variable into a real AnonObject handle.
    /// Called at escape points (function call args, return) where the callee
    /// expects a real `rayzor_anon_*`-compatible handle.
    fn materialize_anon_view(
        &mut self,
        value: IrId,
        symbol: SymbolId,
        target_type: TypeId,
    ) -> Option<IrId> {
        let backing = self.anon_views.get(&symbol)?.clone();

        // Get target anonymous fields sorted alphabetically
        let resolved_target = self.resolve_through_aliases(target_type);
        let target_fields = {
            let type_table = self.type_table.borrow();
            if let Some(ty_info) = type_table.get(resolved_target) {
                if let TypeKind::Anonymous { fields } = &ty_info.kind {
                    let mut named: Vec<(String, TypeId)> = fields
                        .iter()
                        .filter_map(|f| {
                            self.string_interner
                                .get(f.name)
                                .map(|s| (s.to_string(), f.type_id))
                        })
                        .collect();
                    named.sort_by(|a, b| a.0.cmp(&b.0));
                    named
                } else {
                    return None;
                }
            } else {
                return None;
            }
        };

        let total_field_count = target_fields.len();

        // Build shape key and get/create shape ID
        let shape_key: String = target_fields
            .iter()
            .map(|(name, _)| name.as_str())
            .collect::<Vec<_>>()
            .join(",");

        let shape_id = if let Some(&existing_id) = self.anonymous_shapes.get(&shape_key) {
            existing_id
        } else {
            let id = self.next_anon_shape_id;
            self.next_anon_shape_id += 1;
            self.anonymous_shapes.insert(shape_key, id);
            id
        };

        // Build descriptor string
        let descriptor = {
            let mut parts = Vec::with_capacity(target_fields.len());
            for (name, type_id) in &target_fields {
                let runtime_tid = self.runtime_type_id(*type_id);
                parts.push(format!("{}:{}", name, runtime_tid));
            }
            parts.join(",")
        };

        // Emit rayzor_ensure_shape + rayzor_anon_new
        let ensure_shape_id = self.get_or_register_extern_function(
            "rayzor_ensure_shape",
            vec![IrType::I32, IrType::String],
            IrType::Void,
        );
        let anon_new_id = self.get_or_register_extern_function(
            "rayzor_anon_new",
            vec![IrType::I32, IrType::I32],
            IrType::Ptr(Box::new(IrType::U8)),
        );
        let anon_set_id = self.get_or_register_extern_function(
            "rayzor_anon_set_field_by_index",
            vec![IrType::Ptr(Box::new(IrType::U8)), IrType::I32, IrType::I64],
            IrType::Void,
        );

        let shape_id_const = self.builder.build_const(IrValue::I32(shape_id as i32))?;
        let desc_str = self.builder.build_const(IrValue::String(descriptor))?;
        self.builder.build_call_direct(
            ensure_shape_id,
            vec![shape_id_const, desc_str],
            IrType::Void,
        );

        let shape_id_val = self.builder.build_const(IrValue::I32(shape_id as i32))?;
        let field_count_val = self
            .builder
            .build_const(IrValue::I32(total_field_count as i32))?;
        let handle = self.builder.build_call_direct(
            anon_new_id,
            vec![shape_id_val, field_count_val],
            IrType::Ptr(Box::new(IrType::U8)),
        )?;

        // Copy fields from backing source into the new AnonObject
        match &backing {
            AnonBacking::Class { field_map, .. } => {
                for (sorted_idx, (name, _)) in target_fields.iter().enumerate() {
                    if let Some((_, gep_idx, field_type_id)) =
                        field_map.iter().find(|(n, ..)| n == name)
                    {
                        let field_ir_ty = self.convert_type(*field_type_id);
                        let idx_const = self.builder.build_const(IrValue::I64(*gep_idx as i64))?;
                        let field_ptr =
                            self.builder
                                .build_gep(value, vec![idx_const], field_ir_ty.clone())?;
                        let field_val = self.builder.build_load(field_ptr, field_ir_ty)?;
                        let val_as_i64 = self.coerce_to_i64(field_val, *field_type_id)?;
                        let idx_val = self.builder.build_const(IrValue::I32(sorted_idx as i32))?;
                        self.builder.build_call_direct(
                            anon_set_id,
                            vec![handle, idx_val, val_as_i64],
                            IrType::Void,
                        );
                    }
                }
            }
            AnonBacking::WiderAnon { field_map, .. } => {
                let anon_get_id = self.get_or_register_extern_function(
                    "rayzor_anon_get_field_by_index",
                    vec![IrType::Ptr(Box::new(IrType::U8)), IrType::I32],
                    IrType::I64,
                );
                for (sorted_idx, (name, _)) in target_fields.iter().enumerate() {
                    if let Some((_, src_idx, _field_type_id)) =
                        field_map.iter().find(|(n, ..)| n == name)
                    {
                        let src_idx_val =
                            self.builder.build_const(IrValue::I32(*src_idx as i32))?;
                        let raw_val = self.builder.build_call_direct(
                            anon_get_id,
                            vec![value, src_idx_val],
                            IrType::I64,
                        )?;
                        let idx_val = self.builder.build_const(IrValue::I32(sorted_idx as i32))?;
                        self.builder.build_call_direct(
                            anon_set_id,
                            vec![handle, idx_val, raw_val],
                            IrType::Void,
                        );
                    }
                }
            }
        }

        Some(handle)
    }

    /// Check if an expression produces a value backed by an anon view, and if so,
    /// materialize it into a real AnonObject handle. Used at escape points (call args).
    /// Also handles direct class→anon or wider-anon→anon conversion at call boundaries
    /// when the callee expects an anonymous-typed parameter.
    fn maybe_materialize_for_call(
        &mut self,
        arg_expr: &HirExpr,
        arg_reg: IrId,
        callee_func_id: Option<IrFunctionId>,
        param_index: usize,
    ) -> IrId {
        // Path 1: Variable with existing anon_views entry → materialize from backing
        if let HirExprKind::Variable { symbol, .. } = &arg_expr.kind {
            if self.anon_views.contains_key(symbol) {
                if let Some(materialized) =
                    self.materialize_anon_view(arg_reg, *symbol, arg_expr.ty)
                {
                    return materialized;
                }
            }
        }

        // Path 2: Direct class→anon or wider-anon→anon conversion at call boundary
        // Check if callee parameter expects anonymous type but arg provides class/wider-anon
        if let Some(func_id) = callee_func_id {
            if let Some(param_types) = self.function_param_hir_types.get(&func_id).cloned() {
                if let Some(&param_type_id) = param_types.get(param_index) {
                    let resolved_param = self.resolve_through_aliases(param_type_id);
                    let resolved_arg = self.resolve_through_aliases(arg_expr.ty);

                    let param_is_anon = {
                        let type_table = self.type_table.borrow();
                        type_table
                            .get(resolved_param)
                            .map(|t| matches!(t.kind, TypeKind::Anonymous { .. }))
                            .unwrap_or(false)
                    };

                    if param_is_anon {
                        let arg_kind = {
                            let type_table = self.type_table.borrow();
                            type_table.get(resolved_arg).map(|t| t.kind.clone())
                        };

                        match arg_kind {
                            Some(TypeKind::Class { .. }) => {
                                // Class→anon: build temporary AnonBacking::Class and materialize
                                if let Some(handle) = self.materialize_class_to_anon(
                                    arg_reg,
                                    resolved_arg,
                                    resolved_param,
                                ) {
                                    return handle;
                                }
                            }
                            Some(TypeKind::Anonymous { .. }) => {
                                // Wider-anon→narrower-anon: materialize with index remapping
                                if resolved_arg != resolved_param {
                                    if let Some(handle) = self.materialize_wider_anon_to_anon(
                                        arg_reg,
                                        resolved_arg,
                                        resolved_param,
                                    ) {
                                        return handle;
                                    }
                                }
                            }
                            _ => {}
                        }
                    }
                }
            }
        }

        arg_reg
    }

    /// Materialize a class-typed value into an AnonObject for a callee that expects anonymous type.
    fn materialize_class_to_anon(
        &mut self,
        class_ptr: IrId,
        class_type: TypeId,
        target_anon_type: TypeId,
    ) -> Option<IrId> {
        // Get class symbol to look up fields
        let class_symbol = {
            let type_table = self.type_table.borrow();
            if let Some(ty_info) = type_table.get(class_type) {
                match &ty_info.kind {
                    TypeKind::Class { symbol_id, .. } => Some(*symbol_id),
                    TypeKind::GenericInstance { base_type, .. } => {
                        if let Some(base_info) = type_table.get(*base_type) {
                            if let TypeKind::Class { symbol_id, .. } = &base_info.kind {
                                Some(*symbol_id)
                            } else {
                                None
                            }
                        } else {
                            None
                        }
                    }
                    _ => None,
                }
            } else {
                None
            }
        }?;

        // Get target anonymous fields
        let target_fields = {
            let type_table = self.type_table.borrow();
            if let Some(ty_info) = type_table.get(target_anon_type) {
                if let TypeKind::Anonymous { fields } = &ty_info.kind {
                    let mut named: Vec<(String, TypeId)> = fields
                        .iter()
                        .filter_map(|f| {
                            self.string_interner
                                .get(f.name)
                                .map(|s| (s.to_string(), f.type_id))
                        })
                        .collect();
                    named.sort_by(|a, b| a.0.cmp(&b.0));
                    named
                } else {
                    return None;
                }
            } else {
                return None;
            }
        };

        // Build field_map from field_index_map (same approach as try_register_anon_view)
        let mut class_field_by_name: BTreeMap<String, (u32, TypeId)> = BTreeMap::new();
        for (field_sym, (fclass_ty, idx)) in &self.field_index_map {
            let matches = *fclass_ty == class_type || {
                self.class_type_to_symbol
                    .get(fclass_ty)
                    .map_or(false, |s| *s == class_symbol)
            };
            if matches {
                if let Some(sym) = self.symbol_table.get_symbol(*field_sym) {
                    if let Some(name) = self.string_interner.get(sym.name) {
                        class_field_by_name.insert(name.to_string(), (*idx, sym.type_id));
                    }
                }
            }
        }

        let mut field_map: Vec<(String, u32, TypeId)> = Vec::new();
        for (name, target_field_ty) in &target_fields {
            if let Some((gep_idx, _field_ty)) = class_field_by_name.get(name) {
                field_map.push((name.clone(), *gep_idx, *target_field_ty));
            } else {
                return None; // Target field not found in class
            }
        }

        // Now build a temporary AnonBacking::Class and call materialize_anon_view logic
        // We'll inline the materialization here to avoid needing a temporary symbol
        let total_field_count = target_fields.len();

        let shape_key: String = target_fields
            .iter()
            .map(|(name, _)| name.as_str())
            .collect::<Vec<_>>()
            .join(",");

        let shape_id = if let Some(&existing_id) = self.anonymous_shapes.get(&shape_key) {
            existing_id
        } else {
            let id = self.next_anon_shape_id;
            self.next_anon_shape_id += 1;
            self.anonymous_shapes.insert(shape_key, id);
            id
        };

        let descriptor = {
            let mut parts = Vec::with_capacity(target_fields.len());
            for (name, type_id) in &target_fields {
                let runtime_tid = self.runtime_type_id(*type_id);
                parts.push(format!("{}:{}", name, runtime_tid));
            }
            parts.join(",")
        };

        let ensure_shape_id = self.get_or_register_extern_function(
            "rayzor_ensure_shape",
            vec![IrType::I32, IrType::String],
            IrType::Void,
        );
        let anon_new_id = self.get_or_register_extern_function(
            "rayzor_anon_new",
            vec![IrType::I32, IrType::I32],
            IrType::Ptr(Box::new(IrType::U8)),
        );
        let anon_set_id = self.get_or_register_extern_function(
            "rayzor_anon_set_field_by_index",
            vec![IrType::Ptr(Box::new(IrType::U8)), IrType::I32, IrType::I64],
            IrType::Void,
        );

        let shape_id_const = self.builder.build_const(IrValue::I32(shape_id as i32))?;
        let desc_str = self.builder.build_const(IrValue::String(descriptor))?;
        self.builder.build_call_direct(
            ensure_shape_id,
            vec![shape_id_const, desc_str],
            IrType::Void,
        );

        let shape_id_val = self.builder.build_const(IrValue::I32(shape_id as i32))?;
        let field_count_val = self
            .builder
            .build_const(IrValue::I32(total_field_count as i32))?;
        let handle = self.builder.build_call_direct(
            anon_new_id,
            vec![shape_id_val, field_count_val],
            IrType::Ptr(Box::new(IrType::U8)),
        )?;

        // Copy fields from class via GEP+Load
        for (sorted_idx, (name, _)) in target_fields.iter().enumerate() {
            if let Some((_, gep_idx, field_type_id)) = field_map.iter().find(|(n, ..)| n == name) {
                let field_ir_ty = self.convert_type(*field_type_id);
                let idx_const = self.builder.build_const(IrValue::I64(*gep_idx as i64))?;
                let field_ptr =
                    self.builder
                        .build_gep(class_ptr, vec![idx_const], field_ir_ty.clone())?;
                let field_val = self.builder.build_load(field_ptr, field_ir_ty)?;
                let val_as_i64 = self.coerce_to_i64(field_val, *field_type_id)?;
                let idx_val = self.builder.build_const(IrValue::I32(sorted_idx as i32))?;
                self.builder.build_call_direct(
                    anon_set_id,
                    vec![handle, idx_val, val_as_i64],
                    IrType::Void,
                );
            }
        }

        Some(handle)
    }

    /// Materialize a wider anonymous object into a narrower anonymous object.
    fn materialize_wider_anon_to_anon(
        &mut self,
        source_handle: IrId,
        source_type: TypeId,
        target_anon_type: TypeId,
    ) -> Option<IrId> {
        // Get source fields sorted alphabetically
        let source_fields = {
            let type_table = self.type_table.borrow();
            if let Some(ty_info) = type_table.get(source_type) {
                if let TypeKind::Anonymous { fields } = &ty_info.kind {
                    let mut named: Vec<(String, TypeId)> = fields
                        .iter()
                        .filter_map(|f| {
                            self.string_interner
                                .get(f.name)
                                .map(|s| (s.to_string(), f.type_id))
                        })
                        .collect();
                    named.sort_by(|a, b| a.0.cmp(&b.0));
                    named
                } else {
                    return None;
                }
            } else {
                return None;
            }
        };

        // Get target fields sorted alphabetically
        let target_fields = {
            let type_table = self.type_table.borrow();
            if let Some(ty_info) = type_table.get(target_anon_type) {
                if let TypeKind::Anonymous { fields } = &ty_info.kind {
                    let mut named: Vec<(String, TypeId)> = fields
                        .iter()
                        .filter_map(|f| {
                            self.string_interner
                                .get(f.name)
                                .map(|s| (s.to_string(), f.type_id))
                        })
                        .collect();
                    named.sort_by(|a, b| a.0.cmp(&b.0));
                    named
                } else {
                    return None;
                }
            } else {
                return None;
            }
        };

        // Build source index map: field_name → sorted index in source
        let source_index_map: std::collections::HashMap<&str, usize> = source_fields
            .iter()
            .enumerate()
            .map(|(i, (name, _))| (name.as_str(), i))
            .collect();

        // Verify all target fields exist in source
        for (name, _) in &target_fields {
            if !source_index_map.contains_key(name.as_str()) {
                return None;
            }
        }

        let total_field_count = target_fields.len();

        let shape_key: String = target_fields
            .iter()
            .map(|(name, _)| name.as_str())
            .collect::<Vec<_>>()
            .join(",");

        let shape_id = if let Some(&existing_id) = self.anonymous_shapes.get(&shape_key) {
            existing_id
        } else {
            let id = self.next_anon_shape_id;
            self.next_anon_shape_id += 1;
            self.anonymous_shapes.insert(shape_key, id);
            id
        };

        let descriptor = {
            let mut parts = Vec::with_capacity(target_fields.len());
            for (name, type_id) in &target_fields {
                let runtime_tid = self.runtime_type_id(*type_id);
                parts.push(format!("{}:{}", name, runtime_tid));
            }
            parts.join(",")
        };

        let ensure_shape_id = self.get_or_register_extern_function(
            "rayzor_ensure_shape",
            vec![IrType::I32, IrType::String],
            IrType::Void,
        );
        let anon_new_id = self.get_or_register_extern_function(
            "rayzor_anon_new",
            vec![IrType::I32, IrType::I32],
            IrType::Ptr(Box::new(IrType::U8)),
        );
        let anon_set_id = self.get_or_register_extern_function(
            "rayzor_anon_set_field_by_index",
            vec![IrType::Ptr(Box::new(IrType::U8)), IrType::I32, IrType::I64],
            IrType::Void,
        );
        let anon_get_id = self.get_or_register_extern_function(
            "rayzor_anon_get_field_by_index",
            vec![IrType::Ptr(Box::new(IrType::U8)), IrType::I32],
            IrType::I64,
        );

        let shape_id_const = self.builder.build_const(IrValue::I32(shape_id as i32))?;
        let desc_str = self.builder.build_const(IrValue::String(descriptor))?;
        self.builder.build_call_direct(
            ensure_shape_id,
            vec![shape_id_const, desc_str],
            IrType::Void,
        );

        let shape_id_val = self.builder.build_const(IrValue::I32(shape_id as i32))?;
        let field_count_val = self
            .builder
            .build_const(IrValue::I32(total_field_count as i32))?;
        let handle = self.builder.build_call_direct(
            anon_new_id,
            vec![shape_id_val, field_count_val],
            IrType::Ptr(Box::new(IrType::U8)),
        )?;

        // Copy fields from source anon with remapped indices
        for (sorted_idx, (name, _)) in target_fields.iter().enumerate() {
            if let Some(&src_idx) = source_index_map.get(name.as_str()) {
                let src_idx_val = self.builder.build_const(IrValue::I32(src_idx as i32))?;
                let raw_val = self.builder.build_call_direct(
                    anon_get_id,
                    vec![source_handle, src_idx_val],
                    IrType::I64,
                )?;
                let idx_val = self.builder.build_const(IrValue::I32(sorted_idx as i32))?;
                self.builder.build_call_direct(
                    anon_set_id,
                    vec![handle, idx_val, raw_val],
                    IrType::Void,
                );
            }
        }

        Some(handle)
    }

    /// Insert automatic unboxing if needed when reading from Dynamic
    /// Returns the (potentially unboxed) value
    fn maybe_unbox_value(
        &mut self,
        value: IrId,
        value_ty: TypeId,
        target_ty: TypeId,
    ) -> Option<IrId> {
        use crate::tast::TypeKind;

        // Check if value is Dynamic and target is concrete
        // Clone TypeKind to avoid borrow checker issues
        let (value_is_dynamic, target_kind_cloned) = {
            let type_table = self.type_table.borrow();
            let value_is_dyn = matches!(
                type_table.get(value_ty).map(|t| &t.kind),
                Some(TypeKind::Dynamic)
            );
            let target_kind = type_table.get(target_ty).map(|t| t.kind.clone());
            (value_is_dyn, target_kind)
        };

        let target_is_dynamic = matches!(&target_kind_cloned, Some(TypeKind::Dynamic));
        let needs_unboxing = value_is_dynamic && !target_is_dynamic;

        if !needs_unboxing {
            return Some(value);
        }

        // Check the actual MIR register type of the value.
        // If it's already a primitive (I64, I32, F64, Bool) rather than a pointer (Ptr(U8)),
        // then it's NOT a boxed Dynamic value — skip unboxing.
        // This handles MIR wrapper returns (e.g., Usize ops return I64 typed as Dynamic in HIR).
        let actual_mir_type = self.builder.get_register_type(value);
        if let Some(ref mir_ty) = actual_mir_type {
            let is_already_unboxed = matches!(
                mir_ty,
                IrType::I64 | IrType::I32 | IrType::F64 | IrType::Bool
            );
            if is_already_unboxed {
                debug!(
                    "[UNBOXING] Skipping unbox — value MIR type {:?} is already a primitive",
                    mir_ty
                );
                return Some(value);
            }
        }

        // Determine which unboxing function to call based on target type
        match &target_kind_cloned {
            // Value types (need to extract from heap)
            Some(TypeKind::Int) => {
                debug!("[UNBOXING] Auto-unboxing Dynamic to Int using haxe_unbox_int_ptr");
                let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                let unbox_func_id = self.get_or_register_extern_function(
                    "haxe_unbox_int_ptr",
                    vec![ptr_u8],
                    IrType::I32,
                );
                self.builder
                    .build_call_direct(unbox_func_id, vec![value], IrType::I32)
            }
            Some(TypeKind::Float) => {
                debug!("[UNBOXING] Auto-unboxing Dynamic to Float using haxe_unbox_float_ptr");
                let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                let unbox_func_id = self.get_or_register_extern_function(
                    "haxe_unbox_float_ptr",
                    vec![ptr_u8],
                    IrType::F64,
                );
                self.builder
                    .build_call_direct(unbox_func_id, vec![value], IrType::F64)
            }
            Some(TypeKind::Bool) => {
                debug!("[UNBOXING] Auto-unboxing Dynamic to Bool using haxe_unbox_bool_ptr");
                let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                let unbox_func_id = self.get_or_register_extern_function(
                    "haxe_unbox_bool_ptr",
                    vec![ptr_u8],
                    IrType::Bool,
                );
                self.builder
                    .build_call_direct(unbox_func_id, vec![value], IrType::Bool)
            }

            // Enums: Check if this is actually an enum discriminant (i64) rather than a boxed value
            // When accessing Color.Green, the HIR may incorrectly type it as Dynamic,
            // but the actual MIR value is an i64 discriminant, not a boxed pointer
            Some(TypeKind::Enum { .. }) => {
                // Check the actual register type - if it's i64, don't unbox
                let actual_type = self.builder.get_register_type(value);
                if matches!(actual_type, Some(IrType::I64) | Some(IrType::I32)) {
                    debug!(
                        "[UNBOXING] Skipping unbox for enum - value is already i64 discriminant"
                    );
                    return Some(value);
                }
                debug!("[UNBOXING] Auto-unboxing Dynamic to Enum using unbox_reference");

                // Call haxe_unbox_reference_ptr to extract the pointer
                let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                let unbox_func_id = self.get_or_register_extern_function(
                    "haxe_unbox_reference_ptr",
                    vec![ptr_u8.clone()],
                    ptr_u8.clone(),
                );
                self.builder
                    .build_call_direct(unbox_func_id, vec![value], ptr_u8)
            }

            // Abstract types (like Ptr<T>, Ref<T>, Box<T>, Usize) — zero-cost over Int
            // These are NOT heap-boxed, they're just i64 values. Skip unboxing.
            Some(TypeKind::Abstract { .. }) => {
                debug!("[UNBOXING] Skipping unbox for Abstract type (zero-cost over Int)");
                Some(value)
            }

            // Reference types (just extract the pointer)
            Some(TypeKind::Class { symbol_id, .. }) => {
                // Check if this is a MIR wrapper class (extern abstract like Ptr, Ref, Box, Usize)
                // These are zero-cost abstracts over Int — NOT heap-boxed, skip unboxing
                if let Some(sym) = self.symbol_table.get_symbol(*symbol_id) {
                    // Try qualified name (e.g., "rayzor.Ptr" → "rayzor_Ptr"), then native name
                    let class_name = sym
                        .qualified_name
                        .and_then(|qn| self.string_interner.get(qn))
                        .map(|qn| qn.replace(".", "_"))
                        .or_else(|| {
                            sym.native_name
                                .and_then(|nn| self.string_interner.get(nn))
                                .map(|nn| nn.replace("::", "_"))
                        });
                    if let Some(cn) = &class_name {
                        if self.stdlib_mapping.is_mir_wrapper_class(cn) {
                            debug!(
                                "[UNBOXING] Skipping unbox for MIR wrapper class '{}' (extern abstract)",
                                cn
                            );
                            return Some(value);
                        }
                    }
                }

                debug!(
                    "[UNBOXING] Auto-unboxing Dynamic to reference type {:?} using unbox_reference",
                    target_kind_cloned
                );

                // Call haxe_unbox_reference_ptr to extract the pointer
                let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                let unbox_func_id = self.get_or_register_extern_function(
                    "haxe_unbox_reference_ptr",
                    vec![ptr_u8.clone()],
                    ptr_u8.clone(),
                );

                self.builder
                    .build_call_direct(unbox_func_id, vec![value], ptr_u8)
            }
            Some(TypeKind::Interface { .. })
            | Some(TypeKind::Anonymous { .. })
            | Some(TypeKind::Array { .. }) => {
                debug!(
                    "[UNBOXING] Auto-unboxing Dynamic to reference type {:?} using unbox_reference",
                    target_kind_cloned
                );

                let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                let unbox_func_id = self.get_or_register_extern_function(
                    "haxe_unbox_reference_ptr",
                    vec![ptr_u8.clone()],
                    ptr_u8.clone(),
                );

                self.builder
                    .build_call_direct(unbox_func_id, vec![value], ptr_u8)
            }

            // TODO: String (special struct handling), Abstract (depends on underlying type)
            _ => {
                debug!(
                    "[UNBOXING] Unsupported type for unboxing: {:?}",
                    target_kind_cloned
                );
                Some(value) // Skip unboxing for unsupported types
            }
        }
    }

    /// Box a value for extern function calls when the expected type is a pointer but the actual type is a primitive.
    /// This is needed for generic extern classes like Deque<T> where the runtime expects boxed pointers
    /// but the compiler generates primitive values for concrete type parameters like Int.
    ///
    /// Returns the (potentially boxed) value register.
    fn maybe_box_for_extern_call(
        &mut self,
        value: IrId,
        actual_ty: &IrType,
        expected_ty: &IrType,
    ) -> Option<IrId> {
        // Only box if expected is Ptr(U8) and actual is a primitive
        let expected_is_ptr_u8 = matches!(expected_ty, IrType::Ptr(inner) if matches!(**inner, IrType::U8 | IrType::Void));

        if !expected_is_ptr_u8 {
            return Some(value);
        }

        // Check if actual type is a primitive that needs boxing
        let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));

        match actual_ty {
            IrType::I32 => {
                debug!("[EXTERN BOXING] Boxing I32 to Ptr(U8) for extern call");
                // First sign-extend i32 to i64, then call haxe_box_int_ptr
                let extended = self.builder.build_cast(value, IrType::I32, IrType::I64)?;
                let box_func_id = self.get_or_register_extern_function(
                    "haxe_box_int_ptr",
                    vec![IrType::I64],
                    ptr_u8.clone(),
                );
                self.builder
                    .build_call_direct(box_func_id, vec![extended], ptr_u8)
            }
            IrType::I64 => {
                debug!("[EXTERN BOXING] Boxing I64 to Ptr(U8) for extern call");
                let box_func_id = self.get_or_register_extern_function(
                    "haxe_box_int_ptr",
                    vec![IrType::I64],
                    ptr_u8.clone(),
                );
                self.builder
                    .build_call_direct(box_func_id, vec![value], ptr_u8)
            }
            IrType::Bool => {
                debug!("[EXTERN BOXING] Boxing Bool to Ptr(U8) for extern call");
                let box_func_id = self.get_or_register_extern_function(
                    "haxe_box_bool_ptr",
                    vec![IrType::Bool],
                    ptr_u8.clone(),
                );
                self.builder
                    .build_call_direct(box_func_id, vec![value], ptr_u8)
            }
            IrType::F32 => {
                debug!("[EXTERN BOXING] Boxing F32 to Ptr(U8) for extern call");
                // Promote f32 to f64
                let promoted = self.builder.build_cast(value, IrType::F32, IrType::F64)?;
                let box_func_id = self.get_or_register_extern_function(
                    "haxe_box_float_ptr",
                    vec![IrType::F64],
                    ptr_u8.clone(),
                );
                self.builder
                    .build_call_direct(box_func_id, vec![promoted], ptr_u8)
            }
            IrType::F64 => {
                debug!("[EXTERN BOXING] Boxing F64 to Ptr(U8) for extern call");
                let box_func_id = self.get_or_register_extern_function(
                    "haxe_box_float_ptr",
                    vec![IrType::F64],
                    ptr_u8.clone(),
                );
                self.builder
                    .build_call_direct(box_func_id, vec![value], ptr_u8)
            }
            // Already a pointer type (including function pointers) - no boxing needed.
            // Function types also pass through: most callees (Thread.spawn, array.map)
            // expect raw closure pointers, not boxed DynamicValue. Reflection APIs that
            // need boxed functions (Reflect.isFunction) handle boxing at their call sites.
            IrType::Function { .. } | IrType::Ptr(_) | IrType::String | IrType::Any => Some(value),
            // Other types - pass through without boxing (may cause issues, but let's see)
            _ => {
                debug!("[EXTERN BOXING] Skipping boxing for type {:?}", actual_ty);
                Some(value)
            }
        }
    }

    /// Auto-unbox return values from extern calls when runtime returns Ptr(U8) but HIR expects a primitive
    ///
    /// This is the inverse of `maybe_box_for_extern_call`. Generic extern classes like Deque<Int>
    /// store elements as boxed pointers (Ptr(U8)), so when calling pop() the runtime returns
    /// a boxed pointer that needs to be unboxed to the actual type T.
    ///
    /// Also handles nullable types: Null<Int> (Ptr(I32)) - we need to unbox the inner type.
    fn maybe_unbox_for_extern_return(
        &mut self,
        value: IrId,
        actual_ty: &IrType,
        expected_ty: &IrType,
    ) -> Option<IrId> {
        // Only unbox if actual is Ptr(U8) and expected is a primitive
        let actual_is_ptr_u8 =
            matches!(actual_ty, IrType::Ptr(inner) if matches!(**inner, IrType::U8 | IrType::Void));

        if !actual_is_ptr_u8 {
            return Some(value);
        }

        let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));

        // Check if expected type is nullable (Ptr(primitive)) - if so, unbox to the inner primitive type
        // Null<Int> becomes Ptr(I32), we need to unbox to I32
        let target_type = match expected_ty {
            IrType::Ptr(inner) => match inner.as_ref() {
                IrType::I32 | IrType::I64 | IrType::Bool | IrType::F32 | IrType::F64 => {
                    debug!(
                        "[EXTERN UNBOXING] Nullable primitive detected: Ptr({:?}) -> {:?}",
                        inner, inner
                    );
                    inner.as_ref()
                }
                _ => expected_ty,
            },
            _ => expected_ty,
        };

        match target_type {
            IrType::I32 => {
                debug!("[EXTERN UNBOXING] Unboxing Ptr(U8) return to I32");
                // haxe_unbox_int_ptr returns i64, need to truncate to i32
                let unbox_func_id = self.get_or_register_extern_function(
                    "haxe_unbox_int_ptr",
                    vec![ptr_u8],
                    IrType::I64,
                );
                let i64_val =
                    self.builder
                        .build_call_direct(unbox_func_id, vec![value], IrType::I64)?;
                self.builder.build_cast(i64_val, IrType::I64, IrType::I32)
            }
            IrType::I64 => {
                // I64 expected type comes from TypeParameter via type erasure.
                // The Ptr(U8) IS the raw i64 value (not a boxed DynamicValue*).
                // Just cast ptr→i64 instead of trying to dereference as DynamicValue.
                debug!("[EXTERN UNBOXING] Type-erased Ptr(U8) to I64 — casting (not unboxing)");
                self.builder
                    .build_cast(value, IrType::Ptr(Box::new(IrType::U8)), IrType::I64)
            }
            IrType::Bool => {
                debug!("[EXTERN UNBOXING] Unboxing Ptr(U8) return to Bool");
                let unbox_func_id = self.get_or_register_extern_function(
                    "haxe_unbox_bool_ptr",
                    vec![ptr_u8],
                    IrType::Bool,
                );
                self.builder
                    .build_call_direct(unbox_func_id, vec![value], IrType::Bool)
            }
            IrType::F32 => {
                debug!("[EXTERN UNBOXING] Unboxing Ptr(U8) return to F32");
                let unbox_func_id = self.get_or_register_extern_function(
                    "haxe_unbox_float_ptr",
                    vec![ptr_u8],
                    IrType::F64,
                );
                let f64_val =
                    self.builder
                        .build_call_direct(unbox_func_id, vec![value], IrType::F64)?;
                self.builder.build_cast(f64_val, IrType::F64, IrType::F32)
            }
            IrType::F64 => {
                debug!("[EXTERN UNBOXING] Unboxing Ptr(U8) return to F64");
                let unbox_func_id = self.get_or_register_extern_function(
                    "haxe_unbox_float_ptr",
                    vec![ptr_u8],
                    IrType::F64,
                );
                self.builder
                    .build_call_direct(unbox_func_id, vec![value], IrType::F64)
            }
            IrType::String => {
                debug!("[EXTERN UNBOXING] String type - using reference unboxing");
                // Use haxe_unbox_reference_ptr for strings (returns the pointer directly)
                let unbox_func_id = self.get_or_register_extern_function(
                    "haxe_unbox_reference_ptr",
                    vec![ptr_u8],
                    IrType::String,
                );
                self.builder
                    .build_call_direct(unbox_func_id, vec![value], IrType::String)
            }
            // Already a pointer type or other complex type - no unboxing needed
            _ => {
                debug!(
                    "[EXTERN UNBOXING] No unboxing needed for expected type {:?}",
                    expected_ty
                );
                Some(value)
            }
        }
    }

    /// Bind a pattern with type information (registers locals for Cranelift)
    fn bind_pattern_with_type(
        &mut self,
        pattern: &HirPattern,
        value: IrId,
        ty: Option<TypeId>,
        is_mutable: bool,
    ) {
        match pattern {
            HirPattern::Variable { name, symbol } => {
                // Bind the value to the symbol
                self.symbol_map.insert(*symbol, value);

                // Register as local so Cranelift can find the type
                if let Some(type_id) = ty {
                    let var_type_from_hint = self.convert_type(type_id);

                    // Check if the actual register type is more specific than the hint
                    // This can happen when:
                    // - Generic method return types aren't properly resolved (Thread<T>)
                    // - HIR type is vague (Ptr(Void)) but actual MIR type is specific (String)
                    let actual_reg_type = self.builder.get_register_type(value);
                    let var_type = if let Some(ref actual_type) = actual_reg_type {
                        // If hint is Ptr(Void) but actual type is more specific, use actual type
                        let hint_is_void_ptr = matches!(&var_type_from_hint, IrType::Ptr(inner) if matches!(**inner, IrType::Void));
                        let actual_is_specific = !matches!(actual_type, IrType::Ptr(inner) if matches!(**inner, IrType::Void));

                        // Also handle case where actual is pointer but hint is scalar
                        let actual_is_ptr = matches!(actual_type, IrType::Ptr(_));
                        let hint_is_scalar = matches!(
                            &var_type_from_hint,
                            IrType::I32 | IrType::I64 | IrType::Bool | IrType::F32 | IrType::F64
                        );

                        if (hint_is_void_ptr && actual_is_specific)
                            || (actual_is_ptr && hint_is_scalar)
                        {
                            actual_type.clone()
                        } else {
                            var_type_from_hint
                        }
                    } else {
                        var_type_from_hint
                    };

                    if let Some(func) = self.builder.current_function_mut() {
                        func.locals.insert(
                            value,
                            super::IrLocal {
                                name: name.to_string(),
                                ty: var_type.clone(),
                                mutable: is_mutable,
                                source_location: IrSourceLocation::unknown(),
                                allocation: super::AllocationHint::Stack,
                            },
                        );
                    }
                }
            }
            _ => {
                // For other patterns, fall back to old behavior
                self.bind_pattern(pattern, value);
            }
        }
    }

    fn bind_pattern(&mut self, pattern: &HirPattern, value: IrId) {
        self.bind_pattern_with_scrutinee_type(pattern, value, None);
    }

    fn bind_pattern_with_scrutinee_type(
        &mut self,
        pattern: &HirPattern,
        value: IrId,
        scrutinee_type: Option<TypeId>,
    ) {
        match pattern {
            HirPattern::Variable { symbol, .. } => {
                // Bind the value to the symbol
                self.symbol_map.insert(*symbol, value);
            }
            HirPattern::Wildcard => {
                // Wildcard doesn't bind anything
            }
            HirPattern::Tuple(patterns) => {
                // Extract tuple elements and bind recursively
                for (i, p) in patterns.iter().enumerate() {
                    // Use ExtractValue instruction to get tuple element
                    if let Some(elem) = self.builder.build_extract_value(value, vec![i as u32]) {
                        self.bind_pattern(p, elem);
                    }
                }
            }
            HirPattern::Literal(_) => {
                // Literals in patterns are used for matching, not binding
                // The matching logic should be handled elsewhere
            }
            HirPattern::Constructor {
                enum_type,
                variant,
                fields,
            } => {
                // Use scrutinee type if valid (has concrete generic args), otherwise fall back to pattern's enum_type
                // Use scrutinee type if it resolves to an enum, otherwise pattern's enum_type
                let effective_type = scrutinee_type
                    .filter(|t| *t != TypeId::invalid())
                    .filter(|t| self.resolve_enum_symbol(*t).is_some())
                    .unwrap_or(*enum_type);
                let field_types = self.get_enum_variant_field_types(effective_type, *variant);

                // Resolve whether this enum is boxed
                // Try effective_type first, fall back to pattern's enum_type if unresolvable
                let enum_symbol = self
                    .resolve_enum_symbol(effective_type)
                    .or_else(|| self.resolve_enum_symbol(*enum_type));
                let is_boxed = enum_symbol.map_or(false, |s| self.enum_is_boxed(s));
                if !is_boxed || fields.is_empty() {
                    // Unboxed enum or no fields to bind
                    return;
                }

                // Boxed enum: bitcast value (i64) to pointer for GEP
                let enum_ptr = match self
                    .builder
                    .build_bitcast(value, IrType::Ptr(Box::new(IrType::I8)))
                {
                    Some(p) => p,
                    None => return,
                };

                // Extract fields from enum data area and bind sub-patterns
                for (i, field_pattern) in fields.iter().enumerate() {
                    if matches!(field_pattern, HirPattern::Wildcard) {
                        continue;
                    }
                    // Field at byte offset 8 + i*8 (tag is at offset 0, 8 bytes with padding)
                    let field_offset = (8 + i * 8) as i64;
                    if let Some(offset_val) = self.builder.build_int(field_offset, IrType::I64) {
                        if let Some(field_ptr) = self.builder.build_gep(
                            enum_ptr,
                            vec![offset_val],
                            IrType::Ptr(Box::new(IrType::I8)),
                        ) {
                            let (resolved_type, resolved_type_id) = field_types
                                .get(i)
                                .cloned()
                                .unwrap_or((IrType::I64, TypeId::invalid()));

                            // Determine load strategy based on resolved type
                            let (load_type, needs_bitcast_after) = match &resolved_type {
                                // Pointer types: load as raw I64, then bitcast to pointer
                                IrType::Ptr(_) | IrType::String => {
                                    (IrType::I64, Some(resolved_type.clone()))
                                }
                                // Value types stored in 8 bytes
                                IrType::I32 | IrType::Bool => (IrType::I64, None),
                                IrType::I64 | IrType::F64 => (resolved_type.clone(), None),
                                // Unknown/Any: load as I64 for runtime dispatch
                                _ => (IrType::I64, None),
                            };

                            let field_ptr_typed = self
                                .builder
                                .build_bitcast(field_ptr, IrType::Ptr(Box::new(load_type.clone())));
                            if let Some(fpt) = field_ptr_typed {
                                if let Some(mut field_val) = self.builder.build_load(fpt, load_type)
                                {
                                    // Bitcast to pointer type if needed
                                    if let Some(target_type) = needs_bitcast_after {
                                        if let Some(cast_val) =
                                            self.builder.build_bitcast(field_val, target_type)
                                        {
                                            field_val = cast_val;
                                        }
                                    }
                                    // Record the resolved IR type and TypeId for this variable
                                    if let HirPattern::Variable { symbol, .. } = field_pattern {
                                        self.symbol_ir_types.insert(*symbol, resolved_type.clone());
                                        if resolved_type_id != TypeId::invalid() {
                                            self.symbol_type_ids.insert(*symbol, resolved_type_id);
                                        }
                                    }
                                    self.bind_pattern(field_pattern, field_val);
                                }
                            }
                        }
                    }
                }
            }
            HirPattern::Array { .. } => {
                // Array patterns need runtime length checks
                self.add_error(
                    "Array patterns not yet supported in MIR lowering",
                    SourceLocation::unknown(),
                );
            }
            HirPattern::Object { .. } => {
                // Object patterns need field extraction
                self.add_error(
                    "Object patterns not yet supported in MIR lowering",
                    SourceLocation::unknown(),
                );
            }
            HirPattern::Typed { pattern, .. } => {
                // Type annotations in patterns don't affect binding
                self.bind_pattern(pattern, value);
            }
            HirPattern::Guard { pattern, .. } => {
                // Guards are conditions, not bindings
                self.bind_pattern(pattern, value);
            }
            HirPattern::Or(patterns) => {
                // Or patterns need special handling - bind to all alternatives
                // For now, just bind the first pattern
                if let Some(first) = patterns.first() {
                    self.bind_pattern(first, value);
                }
            }
        }
    }

    fn lower_lvalue_read(&mut self, lvalue: &HirLValue) -> Option<IrId> {
        match lvalue {
            HirLValue::Variable(symbol) => {
                // Look up the variable in our symbol map
                self.symbol_map.get(symbol).copied()
            }
            HirLValue::Field { object, field } => {
                // Read object.field
                if let Some(obj_reg) = self.lower_expression(object) {
                    let receiver_ty = object.ty; // The type of the object being accessed
                                                 // TODO: Look up field type from symbol table
                                                 // For now, use invalid TypeId - runtime call path doesn't need it
                    let field_ty = TypeId(u32::MAX); // Field's result type (placeholder)
                    self.lower_field_access(obj_reg, *field, receiver_ty, field_ty)
                } else {
                    None
                }
            }
            HirLValue::Index { object, index } => {
                // Read object[index]
                if let Some(obj_reg) = self.lower_expression(object) {
                    if let Some(idx_reg) = self.lower_expression(index) {
                        let elem_ty = object.ty; // Use object's type for now
                        self.lower_index_access(obj_reg, idx_reg, elem_ty)
                    } else {
                        None
                    }
                } else {
                    None
                }
            }
        }
    }

    fn lower_lvalue_write(&mut self, lvalue: &HirLValue, value: IrId) {
        match lvalue {
            HirLValue::Variable(symbol) => {
                // Check if this is a global variable first
                let global_id = self.global_symbol_map.get(symbol).copied()
                    .or_else(|| {
                        // Name-based fallback: SymbolIds may differ between contexts
                        let sym_name = self.symbol_table.get_symbol(*symbol)
                            .and_then(|s| self.string_interner.get(s.name))?;
                        for (&gsym, &gid) in &self.global_symbol_map {
                            if let Some(gsym_info) = self.symbol_table.get_symbol(gsym) {
                                if let Some(gname) = self.string_interner.get(gsym_info.name) {
                                    if gname == sym_name {
                                        return Some(gid);
                                    }
                                }
                            }
                        }
                        // Also search module globals by name suffix
                        for global in self.builder.module.globals.values() {
                            if global.name.ends_with(&format!(".{}", sym_name)) || global.name == sym_name {
                                return Some(global.id);
                            }
                        }
                        None
                    });
                if let Some(global_id) = global_id {
                    self.builder.build_store_global(global_id, value);
                    // Untrack from drop system — value escapes to global storage
                    self.owned_heap_values.remove(symbol);
                    return;
                }

                // Get the old register before updating (for type inference)
                let old_reg = self.symbol_map.get(symbol).copied();

                // Update the variable binding
                self.symbol_map.insert(*symbol, value);

                // Ensure the new value register has a local entry for phi node tracking
                // Get the existing local type from the symbol, or infer from value
                if let Some(func) = self.builder.current_function_mut() {
                    // Only add if not already present
                    if !func.locals.contains_key(&value) {
                        // Try to get the type from an existing binding of this symbol
                        let var_type = old_reg
                            .and_then(|r| func.locals.get(&r))
                            .map(|local| local.ty.clone())
                            .unwrap_or(IrType::Ptr(Box::new(IrType::Void)));

                        let var_name = self
                            .symbol_table
                            .get_symbol(*symbol)
                            .and_then(|s| self.string_interner.get(s.name))
                            .map(|s| s.to_string())
                            .unwrap_or_else(|| format!("var_{}", symbol.as_raw()));

                        func.locals.insert(
                            value,
                            super::IrLocal {
                                name: format!("{}_v{}", var_name, value.0),
                                ty: var_type,
                                mutable: true,
                                source_location: super::IrSourceLocation::unknown(),
                                allocation: super::AllocationHint::Register,
                            },
                        );
                    }
                }
            }
            HirLValue::Field { object, field } => {
                // Write object.field = value
                if let Some(obj_reg) = self.lower_expression(object) {
                    // Check if this is a property with a custom setter
                    if let Some(property_info) = self.property_access_map.get(field) {
                        match &property_info.setter {
                            crate::tast::PropertyAccessor::Method(setter_method_name) => {
                                // Look up the setter method by name in function_map
                                let setter_func_id = self
                                    .function_map
                                    .iter()
                                    .find(|(sym_id, _)| {
                                        if let Some(symbol) = self.symbol_table.get_symbol(**sym_id)
                                        {
                                            symbol.name == *setter_method_name
                                        } else {
                                            false
                                        }
                                    })
                                    .map(|(_, func_id)| *func_id);

                                if let Some(func_id) = setter_func_id {
                                    // Generate a call to the setter method
                                    // Setters are called with: (this, value)
                                    // and return the value that was set
                                    let return_type =
                                        if let Some(func) = self.builder.current_function() {
                                            func.locals
                                                .get(&value)
                                                .map(|local| local.ty.clone())
                                                .unwrap_or(IrType::I32)
                                        } else {
                                            IrType::I32
                                        };

                                    self.builder.build_call_direct(
                                        func_id,
                                        vec![obj_reg, value], // Pass object as 'this', value as parameter
                                        return_type,
                                    );
                                    return; // Setter called successfully
                                } else {
                                    // Setter method not found - this is an error
                                    let method_name_str = self
                                        .string_interner
                                        .get(*setter_method_name)
                                        .unwrap_or("<unknown>");
                                    self.add_error(
                                        &format!(
                                            "Property setter method '{}' not found",
                                            method_name_str
                                        ),
                                        SourceLocation::unknown(),
                                    );
                                    return;
                                }
                            }
                            crate::tast::PropertyAccessor::Null => {
                                // `null` setter = writable from inside the class only.
                                // Access control is enforced at the type-checker (TAST) level.
                                // At MIR lowering, fall through to direct field access.
                            }
                            crate::tast::PropertyAccessor::Never => {
                                self.add_error(
                                    "Cannot write to read-only property (never setter)",
                                    SourceLocation::unknown(),
                                );
                                return;
                            }
                            crate::tast::PropertyAccessor::Default
                            | crate::tast::PropertyAccessor::Dynamic => {
                                // Fall through to direct field access
                            }
                        }
                    }

                    // Structural subtyping: if object is a variable with an anon view,
                    // redirect field store to the backing representation
                    if let HirExprKind::Variable {
                        symbol: obj_sym, ..
                    } = &object.kind
                    {
                        if let Some(backing) = self.anon_views.get(obj_sym).cloned() {
                            let field_name = self
                                .symbol_table
                                .get_symbol(*field)
                                .and_then(|s| self.string_interner.get(s.name))
                                .map(|s| s.to_string());

                            if let Some(field_name) = field_name {
                                match &backing {
                                    AnonBacking::Class { field_map, .. } => {
                                        if let Some((_, gep_idx, field_type_id)) =
                                            field_map.iter().find(|(n, ..)| *n == field_name)
                                        {
                                            let field_ir_ty = self.convert_type(*field_type_id);
                                            let idx_const = self
                                                .builder
                                                .build_const(IrValue::I64(*gep_idx as i64));
                                            if let Some(idx_c) = idx_const {
                                                let field_ptr = self.builder.build_gep(
                                                    obj_reg,
                                                    vec![idx_c],
                                                    field_ir_ty.clone(),
                                                );
                                                if let Some(fp) = field_ptr {
                                                    self.builder.build_store(fp, value);
                                                    return;
                                                }
                                            }
                                        }
                                    }
                                    AnonBacking::WiderAnon { field_map, .. } => {
                                        if let Some((_, src_idx, field_type_id)) =
                                            field_map.iter().find(|(n, ..)| *n == field_name)
                                        {
                                            let anon_set_id = self.get_or_register_extern_function(
                                                "rayzor_anon_set_field_by_index",
                                                vec![
                                                    IrType::Ptr(Box::new(IrType::U8)),
                                                    IrType::I32,
                                                    IrType::I64,
                                                ],
                                                IrType::Void,
                                            );
                                            let coerced = self.coerce_to_i64(value, *field_type_id);
                                            let idx_val = self
                                                .builder
                                                .build_const(IrValue::I32(*src_idx as i32));
                                            if let (Some(cv), Some(iv)) = (coerced, idx_val) {
                                                self.builder.build_call_direct(
                                                    anon_set_id,
                                                    vec![obj_reg, iv, cv],
                                                    IrType::Void,
                                                );
                                                return;
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }

                    // ANONYMOUS OBJECT FIELD STORE
                    // If object is an anonymous type (or typedef alias to one),
                    // use rayzor_anon_set_field_by_index
                    {
                        let resolved_obj_ty = self.resolve_through_aliases(object.ty);
                        let is_anon = {
                            let type_table = self.type_table.borrow();
                            if let Some(ty_info) = type_table.get(resolved_obj_ty) {
                                matches!(ty_info.kind, TypeKind::Anonymous { .. })
                            } else {
                                false
                            }
                        };

                        if is_anon {
                            let field_name = self
                                .symbol_table
                                .get_symbol(*field)
                                .and_then(|s| self.string_interner.get(s.name))
                                .map(|s| s.to_string());

                            if let Some(field_name) = field_name {
                                let sorted_index = {
                                    let type_table = self.type_table.borrow();
                                    if let Some(ty_info) = type_table.get(resolved_obj_ty) {
                                        if let TypeKind::Anonymous {
                                            fields: anon_fields,
                                        } = &ty_info.kind
                                        {
                                            let mut field_names: Vec<String> = anon_fields
                                                .iter()
                                                .filter_map(|f| {
                                                    self.string_interner
                                                        .get(f.name)
                                                        .map(|s| s.to_string())
                                                })
                                                .collect();
                                            field_names.sort();
                                            field_names.iter().position(|n| *n == field_name)
                                        } else {
                                            None
                                        }
                                    } else {
                                        None
                                    }
                                };

                                if let Some(sorted_idx) = sorted_index {
                                    let anon_set_id = self.get_or_register_extern_function(
                                        "rayzor_anon_set_field_by_index",
                                        vec![
                                            IrType::Ptr(Box::new(IrType::U8)),
                                            IrType::I32,
                                            IrType::I64,
                                        ],
                                        IrType::Void,
                                    );

                                    // Coerce value to i64 for storage
                                    // Use the field symbol's type if available, fall back to I64
                                    let field_type_id = self
                                        .symbol_table
                                        .get_symbol(*field)
                                        .map(|s| s.type_id)
                                        .unwrap_or(TypeId(u32::MAX));
                                    let val_i64 =
                                        self.coerce_to_i64(value, field_type_id).unwrap_or(value);

                                    let idx_val =
                                        self.builder.build_const(IrValue::I32(sorted_idx as i32));
                                    if let Some(idx_val) = idx_val {
                                        self.builder.build_call_direct(
                                            anon_set_id,
                                            vec![obj_reg, idx_val, val_i64],
                                            IrType::Void,
                                        );
                                    }
                                    return;
                                }
                            }
                        }
                    }

                    // Look up the field index (with fallback to name lookup)
                    let field_index_opt = self
                        .field_index_map
                        .get(field)
                        .map(|&(_, idx)| idx)
                        .or_else(|| {
                            // Fallback: disambiguate by receiver type when multiple classes
                            // have the same field name (e.g., StringBuf.length vs List.length)
                            let field_name =
                                self.symbol_table.get_symbol(*field).map(|s| s.name)?;
                            let receiver_ty = object.ty;
                            self.resolve_field_index_by_name(field_name, receiver_ty)
                                .map(|(_, idx)| idx)
                        });

                    if let Some(field_index) = field_index_opt {
                        // @:cstruct: use byte-offset PtrAdd instead of GEP
                        let obj_type_id = object.ty;
                        if self.is_cstruct_class(obj_type_id) {
                            if let Some(layout) = self.get_or_compute_cstruct_layout(obj_type_id) {
                                let field_layout = layout
                                    .fields
                                    .iter()
                                    .find(|f| f.symbol_id == *field)
                                    .or_else(|| {
                                        let fname = self
                                            .symbol_table
                                            .get_symbol(*field)
                                            .and_then(|s| self.string_interner.get(s.name));
                                        fname.and_then(|n| {
                                            layout.fields.iter().find(|f| f.name == n)
                                        })
                                    });
                                if let Some(fl) = field_layout {
                                    let offset_const = self
                                        .builder
                                        .build_const(IrValue::I64(fl.byte_offset as i64));
                                    if let Some(offset_const) = offset_const {
                                        let field_ptr = self.builder.build_ptr_add(
                                            obj_reg,
                                            offset_const,
                                            IrType::Ptr(Box::new(IrType::U8)),
                                        );
                                        if let Some(field_ptr) = field_ptr {
                                            self.builder.build_store(field_ptr, value);
                                        }
                                    }
                                    return;
                                }
                            }
                        }

                        // @:gpuStruct: byte-offset PtrAdd with f64→f32 truncation on write
                        if self.is_gpu_struct_class(obj_type_id) {
                            if let Some(layout) = self.get_or_compute_gpu_struct_layout(obj_type_id)
                            {
                                let field_layout = layout
                                    .fields
                                    .iter()
                                    .find(|f| f.symbol_id == *field)
                                    .or_else(|| {
                                        let fname = self
                                            .symbol_table
                                            .get_symbol(*field)
                                            .and_then(|s| self.string_interner.get(s.name));
                                        fname.and_then(|n| {
                                            layout.fields.iter().find(|f| f.name == n)
                                        })
                                    })
                                    .cloned();
                                if let Some(fl) = field_layout {
                                    let offset_const = self
                                        .builder
                                        .build_const(IrValue::I64(fl.byte_offset as i64));
                                    if let Some(offset_const) = offset_const {
                                        let field_ptr = self.builder.build_ptr_add(
                                            obj_reg,
                                            offset_const,
                                            IrType::Ptr(Box::new(IrType::U8)),
                                        );
                                        if let Some(field_ptr) = field_ptr {
                                            // GPU structs use f32 for Float — truncate f64→f32 on write
                                            let store_val = if fl.ir_type == IrType::F32 {
                                                // Value may be f64, cast to f32
                                                self.builder
                                                    .build_cast(value, IrType::F64, IrType::F32)
                                                    .unwrap_or(value)
                                            } else if fl.ir_type == IrType::I32 {
                                                // Value may be i64, cast to i32
                                                self.builder
                                                    .build_cast(value, IrType::I64, IrType::I32)
                                                    .unwrap_or(value)
                                            } else {
                                                value
                                            };
                                            self.builder.build_store(field_ptr, store_val);
                                        }
                                    }
                                    return;
                                }
                            }
                        }

                        // Create constant for field index
                        if let Some(index_const) =
                            self.builder.build_const(IrValue::I32(field_index as i32))
                        {
                            // Get the type of the field from the FIELD'S DECLARED TYPE in symbol table
                            let field_ty = self.symbol_table.get_symbol(*field)
                                .and_then(|s| {
                                    let converted = self.convert_type(s.type_id);
                                    if matches!(&converted, IrType::Ptr(inner) if matches!(**inner, IrType::Void)) {
                                        None
                                    } else {
                                        Some(converted)
                                    }
                                })
                                .unwrap_or_else(|| {
                                    let field_name = self.symbol_table.get_symbol(*field).map(|s| s.name);
                                    for (sym, _) in &self.field_index_map {
                                        if let Some(sym_info) = self.symbol_table.get_symbol(*sym) {
                                            if field_name == Some(sym_info.name) {
                                                return self.convert_type(sym_info.type_id);
                                            }
                                        }
                                    }
                                    IrType::I32
                                });

                            // Use GEP to get field pointer, then store
                            if let Some(field_ptr) =
                                self.builder
                                    .build_gep(obj_reg, vec![index_const], field_ty.clone())
                            {
                                // Type erasure coercion: if field is I64 (erased type param)
                                // but value is a concrete type, coerce before storing
                                let store_value = if field_ty == IrType::I64 {
                                    if let Some(val_ty) = self.builder.get_register_type(value) {
                                        if val_ty != IrType::I64 {
                                            match val_ty {
                                                IrType::F64 | IrType::F32 => self
                                                    .builder
                                                    .build_bitcast(value, IrType::I64)
                                                    .unwrap_or(value),
                                                _ => self
                                                    .builder
                                                    .build_cast(value, val_ty, IrType::I64)
                                                    .unwrap_or(value),
                                            }
                                        } else {
                                            value
                                        }
                                    } else {
                                        value
                                    }
                                } else {
                                    value
                                };
                                self.builder.build_store(field_ptr, store_value);
                            }
                        }
                    } else {
                        // Dynamic field WRITE fallback via Reflect API.
                        // If the object is Dynamic (anonymous object boxed as Dynamic),
                        // unbox and use haxe_reflect_set_field.
                        let is_dynamic = {
                            let type_table = self.type_table.borrow();
                            type_table
                                .get(object.ty)
                                .map(|t| matches!(t.kind, TypeKind::Dynamic))
                                .unwrap_or(false)
                        };
                        if is_dynamic {
                            let field_name_str = self
                                .symbol_table
                                .get_symbol(*field)
                                .and_then(|s| self.string_interner.get(s.name))
                                .map(|s| s.to_string());
                            if let Some(fname) = field_name_str {
                                let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                                // Unbox Dynamic to get the anonymous object handle.
                                let unbox_ref_id = self.get_or_register_extern_function(
                                    "haxe_unbox_reference_ptr",
                                    vec![ptr_u8.clone()],
                                    ptr_u8.clone(),
                                );
                                if let Some(handle) = self.builder.build_call_direct(
                                    unbox_ref_id,
                                    vec![obj_reg],
                                    ptr_u8.clone(),
                                ) {
                                    // Box the value based on its IR type
                                    let value_ir_type = self.builder.get_register_type(value);
                                    let boxed_value = match &value_ir_type {
                                        Some(IrType::F64) | Some(IrType::F32) => {
                                            let box_id = self.get_or_register_extern_function(
                                                "haxe_box_float_ptr",
                                                vec![IrType::F64],
                                                ptr_u8.clone(),
                                            );
                                            self.builder.build_call_direct(
                                                box_id,
                                                vec![value],
                                                ptr_u8.clone(),
                                            )
                                        }
                                        Some(IrType::Bool) => {
                                            let box_id = self.get_or_register_extern_function(
                                                "haxe_box_bool_ptr",
                                                vec![IrType::Bool],
                                                ptr_u8.clone(),
                                            );
                                            self.builder.build_call_direct(
                                                box_id,
                                                vec![value],
                                                ptr_u8.clone(),
                                            )
                                        }
                                        Some(IrType::Ptr(_)) => {
                                            // Already a pointer — pass through as-is
                                            Some(value)
                                        }
                                        _ => {
                                            // Int or other integer types
                                            let box_id = self.get_or_register_extern_function(
                                                "haxe_box_int_ptr",
                                                vec![IrType::I64],
                                                ptr_u8.clone(),
                                            );
                                            self.builder.build_call_direct(
                                                box_id,
                                                vec![value],
                                                ptr_u8.clone(),
                                            )
                                        }
                                    };
                                    if let Some(boxed) = boxed_value {
                                        let field_name_reg =
                                            self.builder.build_const(IrValue::String(fname));
                                        if let Some(field_name_reg) = field_name_reg {
                                            let set_field_id = self
                                                .get_or_register_extern_function(
                                                    "haxe_reflect_set_field",
                                                    vec![ptr_u8.clone(), ptr_u8.clone(), ptr_u8],
                                                    IrType::Void,
                                                );
                                            self.builder.build_call_direct(
                                                set_field_id,
                                                vec![handle, field_name_reg, boxed],
                                                IrType::Void,
                                            );
                                        }
                                    }
                                }
                                return;
                            }
                        }
                        // Check if this is a static field that should be written as a global
                        let field_name_str = self
                            .symbol_table
                            .get_symbol(*field)
                            .and_then(|s| self.string_interner.get(s.name))
                            .unwrap_or("<unknown>");
                        let global_lookup = self.global_symbol_map.get(field).copied()
                            .or_else(|| {
                                self.builder.module.globals.values()
                                    .find(|g| g.name.ends_with(&format!(".{}", field_name_str)))
                                    .map(|g| g.id)
                            });
                        if let Some(global_id) = global_lookup {
                            self.builder.build_store_global(global_id, value);
                            return;
                        }
                        let field_name = self
                            .symbol_table
                            .get_symbol(*field)
                            .map(|s| format!("{}", s.name))
                            .unwrap_or_else(|| format!("{:?}", field));
                        self.add_error(
                            &format!("Field '{}' ({:?}) index not found for write - class may not be registered", field_name, field),
                            SourceLocation::unknown()
                        );
                    }
                }
            }
            HirLValue::Index { object, index } => {
                // Write object[index] = value
                // Use typed array set functions to pass values directly,
                // avoiding DynamicValue boxing via haxe_box_*_ptr which
                // would corrupt array storage (DynamicValue.type_id stored instead of value)
                if let Some(obj_reg) = self.lower_expression(object) {
                    if let Some(idx_reg) = self.lower_expression(index) {
                        let idx_i64 = {
                            let idx_ty = self.builder.get_register_type(idx_reg);
                            match idx_ty {
                                Some(IrType::I64) => idx_reg,
                                Some(IrType::I32) => self
                                    .builder
                                    .build_cast(idx_reg, IrType::I32, IrType::I64)
                                    .unwrap_or(idx_reg),
                                Some(IrType::Bool) => self
                                    .builder
                                    .build_cast(idx_reg, IrType::Bool, IrType::I64)
                                    .unwrap_or(idx_reg),
                                Some(IrType::Ptr(_)) => self
                                    .builder
                                    .build_bitcast(idx_reg, IrType::I64)
                                    .unwrap_or(idx_reg),
                                Some(other) => self
                                    .builder
                                    .build_cast(idx_reg, other, IrType::I64)
                                    .unwrap_or(idx_reg),
                                None => idx_reg,
                            }
                        };

                        let value_ir_type = self.builder.get_register_type(value);
                        match &value_ir_type {
                            Some(IrType::F32) | Some(IrType::F64) => {
                                // Use haxe_array_set_f64(arr, index, value)
                                let func_id = self.get_or_register_extern_function(
                                    "haxe_array_set_f64",
                                    vec![
                                        IrType::Ptr(Box::new(IrType::Void)),
                                        IrType::I64,
                                        IrType::F64,
                                    ],
                                    IrType::Bool,
                                );
                                let value_f64 = match value_ir_type.clone() {
                                    Some(IrType::F64) => value,
                                    Some(IrType::F32) => self
                                        .builder
                                        .build_cast(value, IrType::F32, IrType::F64)
                                        .unwrap_or(value),
                                    Some(other) => self
                                        .builder
                                        .build_cast(value, other, IrType::F64)
                                        .unwrap_or(value),
                                    None => value,
                                };
                                self.builder.build_call_direct(
                                    func_id,
                                    vec![obj_reg, idx_i64, value_f64],
                                    IrType::Bool,
                                );
                            }
                            _ => {
                                // For Int, Bool, null, pointers: use haxe_array_set_i64
                                // null=0, bool=0/1, pointers=address - all fit in i64
                                let func_id = self.get_or_register_extern_function(
                                    "haxe_array_set_i64",
                                    vec![
                                        IrType::Ptr(Box::new(IrType::Void)),
                                        IrType::I64,
                                        IrType::I64,
                                    ],
                                    IrType::Bool,
                                );
                                let value_i64 = match value_ir_type.clone() {
                                    Some(IrType::I64) => value,
                                    Some(IrType::I32) => self
                                        .builder
                                        .build_cast(value, IrType::I32, IrType::I64)
                                        .unwrap_or(value),
                                    Some(IrType::Bool) => self
                                        .builder
                                        .build_cast(value, IrType::Bool, IrType::I64)
                                        .unwrap_or(value),
                                    Some(IrType::Ptr(_)) => self
                                        .builder
                                        .build_bitcast(value, IrType::I64)
                                        .unwrap_or(value),
                                    Some(IrType::F64) => self
                                        .builder
                                        .build_bitcast(value, IrType::I64)
                                        .unwrap_or(value),
                                    Some(IrType::F32) => {
                                        let as_i32 = self
                                            .builder
                                            .build_bitcast(value, IrType::I32)
                                            .unwrap_or(value);
                                        self.builder
                                            .build_cast(as_i32, IrType::I32, IrType::I64)
                                            .unwrap_or(as_i32)
                                    }
                                    Some(other) => self
                                        .builder
                                        .build_cast(value, other, IrType::I64)
                                        .unwrap_or(value),
                                    None => value,
                                };
                                self.builder.build_call_direct(
                                    func_id,
                                    vec![obj_reg, idx_i64, value_i64],
                                    IrType::Bool,
                                );
                            }
                        }
                    }
                }
            }
        }
    }

    fn lower_field_access(
        &mut self,
        obj: IrId,
        field: SymbolId,
        receiver_ty: TypeId,
        field_ty: TypeId,
    ) -> Option<IrId> {
        // Type erasure: if field_ty is a TypeParameter, resolve to concrete type
        // using the receiver's type arguments (e.g., Container<Float>.value → Float)
        let resolved_field_ty = self.resolve_type_param_from_receiver(field_ty, receiver_ty);
        let field_ty = resolved_field_ty.unwrap_or(field_ty);

        // SPECIAL CASE: Auto-unbox Dynamic for field access
        // If receiver is Dynamic, automatically unbox to get the actual object pointer
        let (obj, receiver_ty) = {
            let type_table = self.type_table.borrow();
            let obj_ir_type = self.builder.get_register_type(obj);
            if let Some(ty) = type_table.get(receiver_ty) {
                if matches!(ty.kind, TypeKind::Dynamic) {
                    // Dynamic-typed receiver: may be a boxed DynamicValue* (from Let handler boxing)
                    // or a raw pointer from StringMap/IntMap.get().
                    // For Ptr(Void): unbox first to get the actual object pointer, then
                    // decide class vs anonymous path.
                    if let Some(IrType::Ptr(inner)) = &obj_ir_type {
                        if matches!(**inner, IrType::Void) {
                            let field_in_class = self.field_exists_in_any_class(field);
                            drop(type_table);

                            // Unbox to get the actual object pointer from DynamicValue*
                            let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                            let unbox_func = self.get_or_register_extern_function(
                                "haxe_unbox_reference_ptr",
                                vec![ptr_u8.clone()],
                                ptr_u8.clone(),
                            );
                            let unboxed_obj =
                                self.builder
                                    .build_call_direct(unbox_func, vec![obj], ptr_u8)?;

                            if field_in_class {
                                return self.lower_field_access_for_class(
                                    unboxed_obj,
                                    field,
                                    field_ty,
                                );
                            }
                            // No class has this field — use Reflect API (anonymous object).
                            // Already unboxed above, so use raw_anon path (no double-unbox).
                            return self.raw_anon_reflect_field_read(unboxed_obj, field, field_ty);
                        }
                    }
                    // Also check for I64 - this is a raw pointer from Array element access
                    if matches!(&obj_ir_type, Some(IrType::I64)) {
                        let field_in_class = self.field_exists_in_any_class(field);
                        drop(type_table);
                        if field_in_class {
                            return self.lower_field_access_for_class(obj, field, field_ty);
                        }
                        return self.dynamic_reflect_field_read(obj, field, field_ty);
                    }
                    // Ptr(U8) from stdlib method returns (e.g., MutexGuard_get) is a raw
                    // class pointer, NOT a boxed DynamicValue. Check class fields first.
                    if matches!(&obj_ir_type, Some(IrType::Ptr(inner)) if matches!(**inner, IrType::U8))
                    {
                        let field_in_class = self.field_exists_in_any_class(field);
                        drop(type_table);
                        if field_in_class {
                            return self.lower_field_access_for_class(obj, field, field_ty);
                        }
                        // Raw Ptr(U8) is NOT boxed — call haxe_reflect_field directly
                        // without the haxe_unbox_reference_ptr step that
                        // dynamic_reflect_field_read would apply.
                        return self.raw_anon_reflect_field_read(obj, field, field_ty);
                    }
                    drop(type_table);

                    // Unbox to get the actual object pointer
                    let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                    let unbox_func_id = self.get_or_register_extern_function(
                        "haxe_unbox_reference_ptr",
                        vec![ptr_u8.clone()],
                        ptr_u8.clone(),
                    );
                    let unboxed_obj =
                        self.builder
                            .build_call_direct(unbox_func_id, vec![obj], ptr_u8.clone())?;

                    // Get the actual class type from the field's class
                    // The field_index_map tells us which class this field belongs to
                    // For Dynamic types, the field symbol may be a newly created placeholder,
                    // so we need to look up by field name instead
                    let (actual_type, _resolved_field) = if let Some(&(class_type_id, _field_idx)) =
                        self.field_index_map.get(&field)
                    {
                        (class_type_id, field)
                    } else {
                        // Field not found by SymbolId - try looking up by name
                        // This handles Dynamic field access where a new symbol was created
                        let field_name = self.symbol_table.get_symbol(field).map(|s| s.name);

                        if let Some(name) = field_name {
                            // Search for any field with the same name in field_index_map
                            let mut found = None;
                            for (sym, &(class_ty, _idx)) in &self.field_index_map {
                                if let Some(sym_info) = self.symbol_table.get_symbol(*sym) {
                                    if sym_info.name == name {
                                        // Get the field's actual type from the symbol
                                        let resolved_field_ty = sym_info.type_id;
                                        found = Some((class_ty, *sym, resolved_field_ty));
                                        break;
                                    }
                                }
                            }

                            if let Some((class_ty, resolved_sym, resolved_field_ty)) = found {
                                // Early return with the correct field symbol AND correct field type
                                return self.lower_field_access(
                                    unboxed_obj,
                                    resolved_sym,
                                    class_ty,
                                    resolved_field_ty,
                                );
                            } else {
                                // Dynamic field READ fallback via Reflect API.
                                // Safe: field_index_map name-match failed, so no class has this field.
                                // Only anonymous objects (typed as Dynamic) reach here.
                                return self.dynamic_reflect_field_read(
                                    unboxed_obj,
                                    field,
                                    field_ty,
                                );
                            }
                        } else {
                            (receiver_ty, field)
                        }
                    };

                    // If we reach here, we couldn't resolve the field - fall through to normal handling
                    // This shouldn't happen for valid Dynamic field access, but provides a fallback
                    (unboxed_obj, actual_type)
                } else {
                    drop(type_table);
                    (obj, receiver_ty)
                }
            } else {
                drop(type_table);
                (obj, receiver_ty)
            }
        };

        // SPECIAL CASE: Check if this is a property access on a @:coreType extern class
        // For example, Array.length should map to haxe_array_length() runtime call
        // These classes have no actual fields - all access must go through runtime functions
        //
        // IMPORTANT: Skip this check if the field is a known user class field.
        // Without this guard, brute-force fallback in get_stdlib_runtime_info can match
        // user fields to unrelated stdlib methods with the same bare name (e.g.,
        // ArrayIterator.current matched to Thread.current → sys_thread_current).
        // When receiver type is Placeholder (unresolved extern class like rayzor.Bytes),
        // never consider it a known user field — it must go through stdlib dispatch.
        let receiver_is_placeholder = {
            let type_table = self.type_table.borrow();
            type_table
                .get(receiver_ty)
                .map_or(false, |t| matches!(t.kind, TypeKind::Placeholder { .. }))
        };
        let is_known_user_field = !receiver_is_placeholder
            && (self.field_index_map.contains_key(&field)
                || self
                    .resolve_field_index_by_name(
                        self.symbol_table
                            .get_symbol(field)
                            .map(|s| s.name)
                            .unwrap_or_default(),
                        receiver_ty,
                    )
                    .is_some());

        let field_name_debug = self
            .symbol_table
            .get_symbol(field)
            .and_then(|s| self.string_interner.get(s.name))
            .unwrap_or("<unknown>");

        if !is_known_user_field {
            if let Some((_class_match, _method, runtime_call)) =
                self.get_stdlib_runtime_info(field, receiver_ty, Some(0), None)
            {
                let runtime_func = runtime_call.runtime_name;
                debug!(
                    "[lower_field_access] Found stdlib property! runtime_func={}",
                    runtime_func
                );

                // Determine result type based on whether it returns a primitive or complex type
                // If needs_out_param is false and has_return is true, it returns a primitive (i32/i64/f64)
                // Otherwise it returns a complex type (Ptr) or void
                let result_type = if !runtime_call.needs_out_param && runtime_call.has_return {
                    // Returns a primitive - get the actual primitive type from field_ty
                    let field_kind = {
                        let type_table = self.type_table.borrow();
                        type_table.get(field_ty).map(|t| t.kind.clone())
                    };

                    // Map TAST primitive types to IR types correctly
                    match field_kind {
                        Some(crate::tast::TypeKind::Int) => IrType::I64,
                        Some(crate::tast::TypeKind::Float) => IrType::F64,
                        Some(crate::tast::TypeKind::Bool) => IrType::Bool,
                        _ => {
                            warn!(
                                "Unexpected field kind {:?} for primitive-returning function {}",
                                field_kind, runtime_func
                            );
                            self.convert_type(field_ty)
                        }
                    }
                } else {
                    // Returns a complex type or void
                    self.convert_type(field_ty)
                };

                debug!(
                    "[lower_field_access] result_type for {} = {:?} (needs_out_param={}, has_return={})",
                    runtime_func,
                    result_type,
                    runtime_call.needs_out_param,
                    runtime_call.has_return
                );

                // Generate a call to the runtime property getter
                // Property getters take the object as the only parameter
                // Use explicit Ptr(Void) type for opaque stdlib objects (Array, String, etc.)
                let param_types = vec![IrType::Ptr(Box::new(IrType::Void))];
                let runtime_func_id = self.get_or_register_extern_function(
                    &runtime_func,
                    param_types,
                    result_type.clone(),
                );

                // Call the property getter with just the object
                let result_reg =
                    self.builder
                        .build_call_direct(runtime_func_id, vec![obj], result_type.clone());

                // DEBUG: Check actual type of result register
                if let Some(reg) = result_reg {
                    if let Some(reg_type) = self.builder.get_register_type(reg) {
                        debug!(
                            "[lower_field_access] result_reg={}, register_type={:?}",
                            reg, reg_type
                        );
                    } else {
                        debug!(
                            "[lower_field_access] result_reg={} has no type in builder",
                            reg
                        );
                    }
                }

                return result_reg;
            } else {
                debug!(
                    "[lower_field_access] get_stdlib_runtime_info returned None for field='{}' ({:?}), receiver_ty={:?}",
                    field_name_debug, field, receiver_ty
                );
            }
        } // end if !is_known_user_field

        // Check if this is a property with a custom getter
        // Try direct SymbolId lookup first, then fall back to name-based matching
        let property_info_owned = self.property_access_map.get(&field).cloned().or_else(|| {
            // Name-based fallback: SymbolIds may differ between import and user modules
            let field_name = self.symbol_table.get_symbol(field).map(|s| s.name)?;
            self.property_access_map.iter().find_map(|(sym_id, info)| {
                let sym_name = self.symbol_table.get_symbol(*sym_id).map(|s| s.name)?;
                if sym_name == field_name {
                    Some(info.clone())
                } else {
                    None
                }
            })
        });
        if let Some(property_info) = property_info_owned.as_ref() {
            match &property_info.getter {
                crate::tast::PropertyAccessor::Method(getter_method_name) => {
                    // Look up the getter method by name in function_map and external_function_map
                    let getter_func_id = self
                        .function_map
                        .iter()
                        .find(|(sym_id, _)| {
                            if let Some(symbol) = self.symbol_table.get_symbol(**sym_id) {
                                symbol.name == *getter_method_name
                            } else {
                                false
                            }
                        })
                        .map(|(_, func_id)| *func_id)
                        .or_else(|| {
                            self.external_function_map
                                .iter()
                                .find(|(sym_id, _)| {
                                    if let Some(symbol) = self.symbol_table.get_symbol(**sym_id) {
                                        symbol.name == *getter_method_name
                                    } else {
                                        false
                                    }
                                })
                                .map(|(_, func_id)| *func_id)
                        });

                    if let Some(func_id) = getter_func_id {
                        // Determine the result type: check the function signature first,
                        // then try the definition-site field symbol (from property_access_map),
                        // finally fall back to the expression-level field_ty.
                        let result_type = self
                            .builder
                            .module
                            .functions
                            .get(&func_id)
                            .map(|f| f.signature.return_type.clone())
                            .unwrap_or_else(|| {
                                // Function not in module (forward ref from import).
                                // The access-site field symbol may have unresolved type.
                                // Try the definition-site symbol from property_access_map
                                // which was populated from the defining module.
                                let def_sym_type =
                                    self.property_access_map.iter().find_map(|(def_sym, _)| {
                                        let sym = self.symbol_table.get_symbol(*def_sym)?;
                                        let name = self.symbol_table.get_symbol(field)?.name;
                                        if sym.name == name && sym.type_id.as_raw() != u32::MAX {
                                            Some(sym.type_id)
                                        } else {
                                            None
                                        }
                                    });
                                let ty = def_sym_type.unwrap_or(field_ty);
                                self.convert_type(ty)
                            });
                        return self
                            .builder
                            .build_call_direct(func_id, vec![obj], result_type);
                    }
                    // Getter not found — fall through to other paths (stdlib dispatch, GEP, etc.)
                }
                crate::tast::PropertyAccessor::Null | crate::tast::PropertyAccessor::Never => {
                    self.add_error(
                        "Cannot read from write-only property (Null or Never getter)",
                        SourceLocation::unknown(),
                    );
                    return None;
                }
                crate::tast::PropertyAccessor::Default | crate::tast::PropertyAccessor::Dynamic => {
                    // Fall through to direct field access
                }
            }
        }

        // ANONYMOUS OBJECT FIELD ACCESS
        // If receiver is an anonymous type (or a typedef alias to one),
        // use rayzor_anon_get_field_by_index
        {
            let resolved_receiver_ty = self.resolve_through_aliases(receiver_ty);
            let type_table = self.type_table.borrow();
            let is_anon = matches!(
                type_table.get(resolved_receiver_ty).map(|t| &t.kind),
                Some(TypeKind::Anonymous { .. })
            );

            if is_anon {
                // Get field name and find its sorted index + actual type from the anonymous struct
                let field_name = self
                    .symbol_table
                    .get_symbol(field)
                    .and_then(|s| self.string_interner.get(s.name))
                    .map(|s| s.to_string());

                if let Some(field_name) = field_name {
                    // Get all anonymous fields, sort them, and find both the sorted index
                    // AND the actual field type (not the possibly-Dynamic expr type)
                    let sorted_result = if let Some(ty_info) = type_table.get(resolved_receiver_ty)
                    {
                        if let TypeKind::Anonymous {
                            fields: anon_fields,
                        } = &ty_info.kind
                        {
                            // Build (name, type_id) pairs and sort by name
                            let mut named_fields: Vec<(String, TypeId)> = anon_fields
                                .iter()
                                .filter_map(|f| {
                                    self.string_interner
                                        .get(f.name)
                                        .map(|s| (s.to_string(), f.type_id))
                                })
                                .collect();
                            named_fields.sort_by(|a, b| a.0.cmp(&b.0));
                            named_fields
                                .iter()
                                .enumerate()
                                .find(|(_, (n, _))| *n == field_name)
                                .map(|(idx, (_, ty))| (idx, *ty))
                        } else {
                            None
                        }
                    } else {
                        None
                    };
                    drop(type_table);

                    if let Some((sorted_idx, actual_field_ty)) = sorted_result {
                        // Emit: rayzor_anon_get_field_by_index(handle, sorted_idx) -> u64
                        let anon_get_id = self.get_or_register_extern_function(
                            "rayzor_anon_get_field_by_index",
                            vec![IrType::Ptr(Box::new(IrType::U8)), IrType::I32],
                            IrType::I64,
                        );

                        let idx_val = self.builder.build_const(IrValue::I32(sorted_idx as i32))?;
                        let raw_val = self.builder.build_call_direct(
                            anon_get_id,
                            vec![obj, idx_val],
                            IrType::I64,
                        )?;

                        // Convert the raw u64 back to the field's actual type
                        // Use the anonymous struct's field type (not the expression-level type
                        // which may be Dynamic)
                        return self.coerce_from_i64(raw_val, actual_field_ty);
                    }
                } else {
                    drop(type_table);
                }
            }
        }

        // Look up the field index from our field_index_map
        // Also capture the actual field type from the symbol table for correct IR type resolution.
        // The passed-in field_ty may be Dynamic when the TAST couldn't resolve the field type
        // (e.g., forward-referenced classes in the same file).
        let (class_type_id, field_index, actual_field_ty) = match self.field_index_map.get(&field) {
            Some(&(class_ty, idx)) => {
                // Get actual field type from symbol table
                let sym_type = self
                    .symbol_table
                    .get_symbol(field)
                    .map(|s| s.type_id)
                    .unwrap_or(field_ty);
                (class_ty, idx, sym_type)
            }
            None => {
                // Fallback: Try to find field by name instead of SymbolId
                // This handles cases where the same field has different SymbolIds in different scopes
                let field_name = self
                    .symbol_table
                    .get_symbol(field)
                    .map(|s| s.name)
                    .or_else(|| None)?;

                let field_name_str = self.string_interner.get(field_name).unwrap_or("<unknown>");

                // Use helper that disambiguates by receiver type when multiple classes
                // have the same field name (e.g., StringBuf.length vs List.length)
                let found_result = self
                    .resolve_field_index_by_name(field_name, receiver_ty)
                    .map(|(class_ty, idx)| {
                        let sym_type = {
                            // Find the symbol in field_index_map that matches this class_ty + idx
                            let mut st = field_ty;
                            for (sym, &(cty, cidx)) in &self.field_index_map {
                                if cty == class_ty && cidx == idx {
                                    if let Some(si) = self.symbol_table.get_symbol(*sym) {
                                        st = si.type_id;
                                    }
                                    break;
                                }
                            }
                            st
                        };
                        (class_ty, idx, sym_type)
                    });

                // Fallback: class_instance_fields lookup via register_class_hints
                // This handles derive trait returns (e.g. clone()) where the receiver's
                // HIR type is Dynamic but the register has a class hint set.
                let found_result = found_result.or_else(|| {
                    let class_hint = self.register_class_hints.get(&obj)?;
                    // Find the class SymbolId matching this hint name
                    for (sym_id, fields) in &self.class_instance_fields {
                        let sym_name = self
                            .symbol_table
                            .get_symbol(*sym_id)
                            .and_then(|s| self.string_interner.get(s.name));
                        if sym_name == Some(class_hint.as_str()) {
                            // Search for our field by name in this class's fields
                            for &(f_sym, f_type, gep_idx) in fields {
                                let f_name = self
                                    .symbol_table
                                    .get_symbol(f_sym)
                                    .and_then(|s| self.string_interner.get(s.name));
                                if f_name == Some(field_name_str) {
                                    return Some((receiver_ty, gep_idx, f_type));
                                }
                            }
                        }
                    }
                    None
                });

                match found_result {
                    Some(result) => result,
                    None => {
                        // Try typedef_field_map for anonymous struct fields (like FileStat)
                        // This handles cases where the typedef's anonymous struct fields
                        // are accessed with newly created symbols at the access site
                        //
                        // receiver_ty might be the typedef's TypeId OR the aliased anonymous struct TypeId
                        // Try both and also search all registered typedefs for this field name
                        let mut typedef_lookup = self
                            .typedef_field_map
                            .get(&(receiver_ty, field_name))
                            .copied();

                        // If not found with receiver_ty, search all typedefs for this field
                        if typedef_lookup.is_none() {
                            for ((typedef_ty, fname), &idx) in &self.typedef_field_map {
                                if *fname == field_name {
                                    typedef_lookup = Some(idx);
                                    // Use the typedef's type id for the result
                                    return Some(self.lower_typedef_field_access(
                                        obj,
                                        *typedef_ty,
                                        idx,
                                        field_ty,
                                    )?);
                                }
                            }
                        }

                        if let Some(typedef_field_idx) = typedef_lookup {
                            // Found in typedef_field_map - return (receiver_type, field_index, field_ty)
                            (receiver_ty, typedef_field_idx, field_ty)
                        } else {
                            // Last resort: look up the field by name in the type_table for anonymous structs
                            // This handles cross-module typedef field access where the typedef was
                            // registered in a different HIR->MIR pass
                            let type_table = self.type_table.borrow();

                            // Get the field name string for lookup
                            let field_name_str = self
                                .string_interner
                                .get(field_name)
                                .map(|s| s.to_string())
                                .unwrap_or_default();

                            // Search all types for an anonymous struct with this field name
                            let mut found_field = None;
                            for (type_id, type_info) in type_table.iter() {
                                if let TypeKind::Anonymous { fields } = &type_info.kind {
                                    for (idx, anon_field) in fields.iter().enumerate() {
                                        let anon_field_name = self
                                            .string_interner
                                            .get(anon_field.name)
                                            .map(|s| s.to_string())
                                            .unwrap_or_default();
                                        if anon_field_name == field_name_str {
                                            found_field = Some((type_id, idx as u32));
                                            break;
                                        }
                                    }
                                    if found_field.is_some() {
                                        break;
                                    }
                                }
                            }
                            drop(type_table);

                            if let Some((found_type_id, field_idx)) = found_field {
                                // Get the actual field type from the type_table
                                let actual_field_ty = {
                                    let type_table = self.type_table.borrow();
                                    if let Some(type_info) = type_table.get(found_type_id) {
                                        if let TypeKind::Anonymous { fields } = &type_info.kind {
                                            if let Some(field) = fields.get(field_idx as usize) {
                                                field.type_id
                                            } else {
                                                field_ty
                                            }
                                        } else {
                                            field_ty
                                        }
                                    } else {
                                        field_ty
                                    }
                                };
                                return Some(self.lower_typedef_field_access(
                                    obj,
                                    receiver_ty,
                                    field_idx,
                                    actual_field_ty,
                                )?);
                            }

                            // Check if this is actually a static field accessed as instance field
                            let global_lookup = self.global_symbol_map.get(&field).copied()
                                .or_else(|| {
                                    self.builder.module.globals.values()
                                        .find(|g| g.name.ends_with(&format!(".{}", field_name_str)))
                                        .map(|g| g.id)
                                });
                            if let Some(global_id) = global_lookup {
                                let global_type = self
                                    .builder
                                    .module
                                    .globals
                                    .get(&global_id)
                                    .map(|g| g.ty.clone())
                                    .unwrap_or(IrType::Any);
                                return self.builder.build_load_global(global_id, global_type);
                            }

                            self.add_error(
                                &format!(
                                    "Field '{}' ({:?}) index not found - class may not be registered",
                                    field_name, field
                                ),
                                SourceLocation::unknown(),
                            );
                            return None;
                        }
                    }
                }
            }
        };

        // Get the type of the field — use actual_field_ty from the class metadata
        // (the symbol table's type), not field_ty (the expression-level type which
        // may be Dynamic when the TAST couldn't resolve forward-referenced class fields)
        let field_ir_ty = self.convert_type(actual_field_ty);

        // Type erasure: if the field's declared type is TypeParameter, use I64 for GEP stride
        // (all type-erased fields are stored as I64 regardless of concrete type)
        let field_is_type_param = {
            let declared_type_id = self.symbol_table.get_symbol(field).map(|s| s.type_id);
            if let Some(decl_id) = declared_type_id {
                let type_table = self.type_table.borrow();
                type_table.get(decl_id).map_or(false, |ti| {
                    matches!(ti.kind, crate::tast::TypeKind::TypeParameter { .. })
                })
            } else {
                false
            }
        };
        let gep_element_ty = if field_is_type_param {
            IrType::I64
        } else {
            field_ir_ty.clone()
        };

        // @:cstruct: use byte-offset PtrAdd instead of index-based GEP
        // Check both class_type_id (from field_index_map) and receiver_ty (expression type)
        let cstruct_type = if self.is_cstruct_class(class_type_id) {
            Some(class_type_id)
        } else if self.is_cstruct_class(receiver_ty) {
            Some(receiver_ty)
        } else {
            None
        };
        if let Some(cstruct_ty) = cstruct_type {
            if let Some(layout) = self.get_or_compute_cstruct_layout(cstruct_ty) {
                if let Some(field_layout) = layout.fields.iter().find(|f| f.symbol_id == field) {
                    let offset_const = self
                        .builder
                        .build_const(IrValue::I64(field_layout.byte_offset as i64))?;
                    let byte_ptr_ty = IrType::Ptr(Box::new(IrType::U8));
                    let field_ptr = self.builder.build_ptr_add(obj, offset_const, byte_ptr_ty)?;
                    let field_value = self.builder.build_load(field_ptr, field_ir_ty.clone())?;
                    self.builder.set_register_type(field_value, field_ir_ty);
                    return Some(field_value);
                }
                // Field not found by symbol_id — try by name
                let field_name = self.symbol_table.get_symbol(field).map(|s| s.name);
                if let Some(fname) = field_name {
                    let fname_str = self.string_interner.get(fname).unwrap_or("");
                    if let Some(field_layout) = layout.fields.iter().find(|f| f.name == fname_str) {
                        let offset_const = self
                            .builder
                            .build_const(IrValue::I64(field_layout.byte_offset as i64))?;
                        let byte_ptr_ty = IrType::Ptr(Box::new(IrType::U8));
                        let field_ptr =
                            self.builder.build_ptr_add(obj, offset_const, byte_ptr_ty)?;
                        let field_value =
                            self.builder.build_load(field_ptr, field_ir_ty.clone())?;
                        self.builder.set_register_type(field_value, field_ir_ty);
                        return Some(field_value);
                    }
                }
            }
        }

        // @:gpuStruct: byte-offset PtrAdd with f32→f64 promotion on read
        let gpu_struct_type = if self.is_gpu_struct_class(class_type_id) {
            Some(class_type_id)
        } else if self.is_gpu_struct_class(receiver_ty) {
            Some(receiver_ty)
        } else {
            None
        };
        if let Some(gpu_ty) = gpu_struct_type {
            if let Some(layout) = self.get_or_compute_gpu_struct_layout(gpu_ty) {
                let find_field = |layout: &GpuStructLayout| -> Option<GpuStructFieldLayout> {
                    layout
                        .fields
                        .iter()
                        .find(|f| f.symbol_id == field)
                        .cloned()
                        .or_else(|| {
                            let fname = self
                                .symbol_table
                                .get_symbol(field)
                                .and_then(|s| self.string_interner.get(s.name));
                            fname.and_then(|n| layout.fields.iter().find(|f| f.name == n).cloned())
                        })
                };
                if let Some(fl) = find_field(&layout) {
                    let offset_const = self
                        .builder
                        .build_const(IrValue::I64(fl.byte_offset as i64))?;
                    let byte_ptr_ty = IrType::Ptr(Box::new(IrType::U8));
                    let field_ptr = self.builder.build_ptr_add(obj, offset_const, byte_ptr_ty)?;
                    // Load as GPU type (f32/i32)
                    let raw_value = self.builder.build_load(field_ptr, fl.ir_type.clone())?;
                    // Promote f32→f64 so Haxe Float semantics work on CPU
                    let promoted = if fl.ir_type == IrType::F32 {
                        let cast = self.builder.build_cast(raw_value, IrType::F32, IrType::F64);
                        cast.unwrap_or(raw_value)
                    } else if fl.ir_type == IrType::I32 && field_ir_ty == IrType::I64 {
                        let cast = self.builder.build_cast(raw_value, IrType::I32, IrType::I64);
                        cast.unwrap_or(raw_value)
                    } else {
                        raw_value
                    };
                    self.builder.set_register_type(promoted, field_ir_ty);
                    return Some(promoted);
                }
            }
        }

        // Create constant for field index
        let index_const = self.builder.build_const(IrValue::I32(field_index as i32))?;

        // Use GetElementPtr to get pointer to the field
        // obj is a pointer to the struct, indices are [field_index]
        let field_ptr = self
            .builder
            .build_gep(obj, vec![index_const], gep_element_ty.clone())?;

        // Load the value from the field pointer
        let field_value = self.builder.build_load(field_ptr, gep_element_ty.clone())?;

        // Type erasure coercion: if field was loaded as I64 (erased type param),
        // coerce to the concrete type expected by the caller.
        // Note: field_ir_ty is always I64 for type params (from convert_type(TypeParameter)),
        // so we must check the RESOLVED type (field_ty) to detect when coercion is needed.
        let expected_ir_ty = self.convert_type(field_ty);
        if field_is_type_param && expected_ir_ty != IrType::I64 {
            let coerced = self.coerce_from_i64(field_value, field_ty)?;
            self.builder.set_register_type(coerced, expected_ir_ty);
            return Some(coerced);
        }

        // Register the type of the loaded value for use in later instructions (e.g., Cmp)
        self.builder.set_register_type(field_value, field_ir_ty);

        Some(field_value)
    }

    /// Resolve a field index by name, disambiguating by receiver type when multiple classes
    /// have the same field name (e.g., both StringBuf.length and List.length).
    /// Returns (class_type_id, field_index) or None if not found.
    fn resolve_field_index_by_name(
        &self,
        field_name: InternedString,
        receiver_ty: TypeId,
    ) -> Option<(TypeId, u32)> {
        let mut all_matches: Vec<(TypeId, u32)> = Vec::new();
        let target_name_str = self.string_interner.get(field_name).unwrap_or("<unknown>");
        for (_sym, &(class_ty, idx)) in &self.field_index_map {
            if let Some(sym_info) = self.symbol_table.get_symbol(*_sym) {
                // Compare by InternedString ID first (fast), then by string content (handles
                // cross-context InternedString mismatches where same string gets different IDs)
                let id_match = sym_info.name == field_name;
                let str_match = {
                    let a = self.string_interner.get(sym_info.name);
                    let b = self.string_interner.get(field_name);
                    a.is_some() && a == b
                };
                if id_match || str_match {
                    all_matches.push((class_ty, idx));
                }
            } else {
                debug!(
                    "[RESOLVE_FIELD] symbol_table.get_symbol({:?}) returned None (looking for '{}')",
                    _sym, target_name_str
                );
            }
        }

        if all_matches.is_empty() {
            debug!(
                "[RESOLVE_FIELD] No matches found for '{}' in {} field_index_map entries",
                target_name_str,
                self.field_index_map.len()
            );
            return None;
        }

        if all_matches.len() == 1 {
            // Even with a single match, verify it belongs to the receiver's class.
            // Without this check, String.length could incorrectly match StringBuf.length.
            let (match_class_ty, match_idx) = all_matches[0];
            if match_class_ty == receiver_ty {
                return Some((match_class_ty, match_idx));
            }
            // Fall through to disambiguation logic which checks type chains
        }

        // Multiple classes have this field name — disambiguate by receiver type.
        // Strategy 1: Resolve receiver_ty through TypeAlias/GenericInstance chains to find
        // the underlying class TypeId, then match directly against candidates' class_ty.
        {
            // Resolve receiver_ty through TypeAlias/GenericInstance/Placeholder chains
            // to find the underlying Class type and its symbol_id
            let mut resolved = self.resolve_through_aliases(receiver_ty);
            let type_table = self.type_table.borrow();
            // Also follow GenericInstance to base type
            let mut visited = HashSet::new();
            loop {
                if !visited.insert(resolved) {
                    break;
                }
                if let Some(ti) = type_table.get(resolved) {
                    match &ti.kind {
                        TypeKind::GenericInstance { base_type, .. } => resolved = *base_type,
                        _ => break,
                    }
                } else {
                    break;
                }
            }

            // Check if resolved type directly matches a candidate's class_type_id
            for &(class_ty, idx) in &all_matches {
                if class_ty == resolved {
                    return Some((class_ty, idx));
                }
            }

            // Extract class symbol_id from resolved type (handles Class with type_args)
            let receiver_symbol = type_table.get(resolved).and_then(|ti| match &ti.kind {
                TypeKind::Class { symbol_id, .. } => Some(*symbol_id),
                _ => None,
            });

            // Match by class symbol_id using the class_type_to_symbol mapping
            // This survives type_table overwrites where class TypeIds get reused
            if let Some(recv_sym) = receiver_symbol {
                for &(class_ty, idx) in &all_matches {
                    let candidate_sym = self.class_type_to_symbol.get(&class_ty);
                    if let Some(&csym) = candidate_sym {
                        if csym == recv_sym {
                            return Some((class_ty, idx));
                        }
                    }
                }
            }
        }

        // Strategy 2: Resolve receiver to class name, match against candidate class names
        let receiver_class_name = {
            let type_table = self.type_table.borrow();
            self.resolve_type_class_name_with(&type_table, receiver_ty)
        };

        if let Some(ref recv_name) = receiver_class_name {
            for &(class_ty, idx) in &all_matches {
                let candidate_name = {
                    let type_table = self.type_table.borrow();
                    self.resolve_type_class_name_with(&type_table, class_ty)
                };
                if candidate_name.as_ref() == Some(recv_name) {
                    return Some((class_ty, idx));
                }
            }
        }

        // Fall back to first match
        Some(all_matches[0])
    }

    /// Check if any class in field_index_map has a field with the same name.
    fn field_exists_in_any_class(&self, field: SymbolId) -> bool {
        // Check by SymbolId first
        if self.field_index_map.contains_key(&field) {
            return true;
        }
        // Check by name
        let field_name = match self.symbol_table.get_symbol(field).map(|s| s.name) {
            Some(name) => name,
            None => return false,
        };
        for (sym, _) in &self.field_index_map {
            if let Some(sym_info) = self.symbol_table.get_symbol(*sym) {
                if sym_info.name == field_name {
                    return true;
                }
            }
        }
        false
    }

    /// Dynamic field READ fallback via Reflect API.
    /// Used when receiver is Dynamic and field_index_map has no matching class field.
    /// The object may be a boxed DynamicValue (from boxing) — unbox to get the anonymous handle.
    fn dynamic_reflect_field_read(
        &mut self,
        obj: IrId,
        field: SymbolId,
        field_ty: TypeId,
    ) -> Option<IrId> {
        let field_name_str = self
            .symbol_table
            .get_symbol(field)
            .and_then(|s| self.string_interner.get(s.name))
            .map(|s| s.to_string())?;

        let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));

        // Unbox the Dynamic value to get the anonymous object handle.
        // The object may be a boxed DynamicValue (from haxe_box_reference_ptr).
        let unbox_ref_id = self.get_or_register_extern_function(
            "haxe_unbox_reference_ptr",
            vec![ptr_u8.clone()],
            ptr_u8.clone(),
        );
        let handle = self
            .builder
            .build_call_direct(unbox_ref_id, vec![obj], ptr_u8.clone())?;

        let field_name_reg = self.builder.build_const(IrValue::String(field_name_str))?;
        let reflect_field_id = self.get_or_register_extern_function(
            "haxe_reflect_field",
            vec![ptr_u8.clone(), ptr_u8.clone()],
            ptr_u8.clone(),
        );
        let dynamic_result = self.builder.build_call_direct(
            reflect_field_id,
            vec![handle, field_name_reg],
            ptr_u8.clone(),
        )?;

        // Unbox based on field_ty
        let type_table = self.type_table.borrow();
        let field_type_kind = type_table.get(field_ty).map(|t| t.kind.clone());
        drop(type_table);

        let result = match field_type_kind.as_ref() {
            Some(TypeKind::Int) => {
                let unbox_id = self.get_or_register_extern_function(
                    "haxe_unbox_int_ptr",
                    vec![ptr_u8.clone()],
                    IrType::I64,
                );
                self.builder
                    .build_call_direct(unbox_id, vec![dynamic_result], IrType::I64)?
            }
            Some(TypeKind::Float) => {
                let unbox_id = self.get_or_register_extern_function(
                    "haxe_unbox_float_ptr",
                    vec![ptr_u8.clone()],
                    IrType::F64,
                );
                self.builder
                    .build_call_direct(unbox_id, vec![dynamic_result], IrType::F64)?
            }
            Some(TypeKind::Bool) => {
                let unbox_id = self.get_or_register_extern_function(
                    "haxe_unbox_bool_ptr",
                    vec![ptr_u8.clone()],
                    IrType::Bool,
                );
                self.builder
                    .build_call_direct(unbox_id, vec![dynamic_result], IrType::Bool)?
            }
            Some(TypeKind::String) => {
                let unbox_id = self.get_or_register_extern_function(
                    "haxe_unbox_reference_ptr",
                    vec![ptr_u8.clone()],
                    ptr_u8.clone(),
                );
                self.builder
                    .build_call_direct(unbox_id, vec![dynamic_result], ptr_u8)?
            }
            _ => {
                // Dynamic or unknown: return DynamicValue* as-is
                dynamic_result
            }
        };
        Some(result)
    }

    /// Read a field from a raw anonymous object handle via Reflect API.
    /// Unlike `dynamic_reflect_field_read`, this does NOT call
    /// `haxe_unbox_reference_ptr` first — the handle is already raw.
    fn raw_anon_reflect_field_read(
        &mut self,
        obj: IrId,
        field: SymbolId,
        field_ty: TypeId,
    ) -> Option<IrId> {
        let field_name_str = self
            .symbol_table
            .get_symbol(field)
            .and_then(|s| self.string_interner.get(s.name))
            .map(|s| s.to_string())?;

        let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));

        let field_name_reg = self.builder.build_const(IrValue::String(field_name_str))?;
        let reflect_field_id = self.get_or_register_extern_function(
            "haxe_reflect_field",
            vec![ptr_u8.clone(), ptr_u8.clone()],
            ptr_u8.clone(),
        );
        let dynamic_result = self.builder.build_call_direct(
            reflect_field_id,
            vec![obj, field_name_reg],
            ptr_u8.clone(),
        )?;

        // Unbox based on field_ty
        let type_table = self.type_table.borrow();
        let field_type_kind = type_table.get(field_ty).map(|t| t.kind.clone());
        drop(type_table);

        let result = match field_type_kind.as_ref() {
            Some(TypeKind::Int) => {
                let unbox_id = self.get_or_register_extern_function(
                    "haxe_unbox_int_ptr",
                    vec![ptr_u8.clone()],
                    IrType::I64,
                );
                self.builder
                    .build_call_direct(unbox_id, vec![dynamic_result], IrType::I64)?
            }
            Some(TypeKind::Float) => {
                let unbox_id = self.get_or_register_extern_function(
                    "haxe_unbox_float_ptr",
                    vec![ptr_u8.clone()],
                    IrType::F64,
                );
                self.builder
                    .build_call_direct(unbox_id, vec![dynamic_result], IrType::F64)?
            }
            Some(TypeKind::Bool) => {
                let unbox_id = self.get_or_register_extern_function(
                    "haxe_unbox_bool_ptr",
                    vec![ptr_u8.clone()],
                    IrType::Bool,
                );
                self.builder
                    .build_call_direct(unbox_id, vec![dynamic_result], IrType::Bool)?
            }
            Some(TypeKind::String) => {
                let unbox_id = self.get_or_register_extern_function(
                    "haxe_unbox_reference_ptr",
                    vec![ptr_u8.clone()],
                    ptr_u8.clone(),
                );
                self.builder
                    .build_call_direct(unbox_id, vec![dynamic_result], ptr_u8)?
            }
            _ => {
                // Dynamic or unknown: return DynamicValue* as-is
                dynamic_result
            }
        };
        Some(result)
    }

    /// Direct field access for typedef'd anonymous structs (like FileStat)
    /// All fields are 8 bytes for consistent boxing/sizing
    fn lower_typedef_field_access(
        &mut self,
        obj: IrId,
        _typedef_ty: TypeId,
        field_index: u32,
        field_ty: TypeId,
    ) -> Option<IrId> {
        // Create constant for field index
        let index_const = self.builder.build_const(IrValue::I32(field_index as i32))?;

        // Get the type of the field
        let field_ir_ty = self.convert_type(field_ty);

        // Use GetElementPtr to get pointer to the field
        // All typedef anonymous struct fields are 8 bytes
        let field_ptr = self
            .builder
            .build_gep(obj, vec![index_const], field_ir_ty.clone())?;

        // Load the value from the field pointer
        let field_value = self.builder.build_load(field_ptr, field_ir_ty.clone())?;

        // Register the type of the loaded value
        self.builder.set_register_type(field_value, field_ir_ty);

        Some(field_value)
    }

    /// Direct field access for class objects without Dynamic unboxing.
    /// Used when we know the object is a raw pointer (e.g., from StringMap<Point>.get())
    /// but TAST thinks it's Dynamic because the type parameter wasn't resolved.
    fn lower_field_access_for_class(
        &mut self,
        obj: IrId,
        field: SymbolId,
        field_ty: TypeId,
    ) -> Option<IrId> {
        // Get field name for debugging
        let field_name = self
            .symbol_table
            .get_symbol(field)
            .and_then(|s| self.string_interner.get(s.name))
            .unwrap_or("<unknown>");

        debug!(
            "[lower_field_access_for_class] field_name='{}', field={:?}",
            field_name, field
        );

        // Check field_index_map FIRST — if the field exists as a user-defined class field,
        // use GEP directly. This prevents stdlib name collisions (e.g., user class with
        // "length" field being incorrectly dispatched to array_length()).
        // Only fall through to stdlib dispatch if the field is NOT found in field_index_map.
        let field_found_in_class = self.field_index_map.contains_key(&field) || {
            // Also check by name
            if let Some(sym) = self.symbol_table.get_symbol(field) {
                self.field_index_map.iter().any(|(s, _)| {
                    self.symbol_table.get_symbol(*s).map(|si| si.name) == Some(sym.name)
                })
            } else {
                false
            }
        };

        if !field_found_in_class {
            // Field not found as a class field — try stdlib dispatch (e.g., Array.length on a
            // Dynamic-typed Array). This is only reached for actual stdlib objects whose fields
            // are runtime functions, not for user-defined classes.
            debug!(
                "[lower_field_access_for_class] field '{}' not in field_index_map, trying stdlib",
                field_name
            );
            let common_stdlib_types = [
                crate::tast::TypeKind::Array {
                    element_type: TypeId::from_raw(0),
                },
                crate::tast::TypeKind::String,
            ];

            for ref_kind in &common_stdlib_types {
                let matching_type_id = {
                    let type_table = self.type_table.borrow();
                    let mut found = None;
                    for (type_id, type_info) in type_table.iter() {
                        let matches = match (&type_info.kind, ref_kind) {
                            (
                                crate::tast::TypeKind::Array { .. },
                                crate::tast::TypeKind::Array { .. },
                            ) => true,
                            (crate::tast::TypeKind::String, crate::tast::TypeKind::String) => true,
                            _ => false,
                        };
                        if matches {
                            found = Some(type_id);
                            break;
                        }
                    }
                    found
                };

                if let Some(class_ty) = matching_type_id {
                    if let Some((_class, _method, runtime_call)) =
                        self.get_stdlib_runtime_info(field, class_ty, None, None)
                    {
                        let runtime_func = runtime_call.runtime_name;
                        debug!(
                            "[lower_field_access_for_class] Found stdlib property! runtime_func={}",
                            runtime_func
                        );
                        let param_types = vec![IrType::Ptr(Box::new(IrType::Void))];

                        let result_type =
                            if !runtime_call.needs_out_param && runtime_call.has_return {
                                if let Some(mir_func) = self
                                    .builder
                                    .module
                                    .functions
                                    .iter()
                                    .find(|(_, f)| f.name == runtime_func)
                                    .map(|(_, f)| f)
                                {
                                    mir_func.signature.return_type.clone()
                                } else {
                                    let actual_field_type = self
                                        .symbol_table
                                        .get_symbol(field)
                                        .map(|s| s.type_id)
                                        .unwrap_or(field_ty);
                                    let field_kind = {
                                        let type_table = self.type_table.borrow();
                                        type_table.get(actual_field_type).map(|t| t.kind.clone())
                                    };
                                    match field_kind {
                                        Some(crate::tast::TypeKind::Int) => IrType::I64,
                                        Some(crate::tast::TypeKind::Float) => IrType::F64,
                                        Some(crate::tast::TypeKind::Bool) => IrType::Bool,
                                        _ => IrType::I64,
                                    }
                                }
                            } else {
                                self.convert_type(field_ty)
                            };

                        let runtime_func_id = self.get_or_register_extern_function(
                            &runtime_func,
                            param_types,
                            result_type.clone(),
                        );

                        return self.builder.build_call_direct(
                            runtime_func_id,
                            vec![obj],
                            result_type,
                        );
                    }
                }
            }
        }

        debug!(
            "[lower_field_access_for_class] Using field_index_map for field '{}'",
            field_name
        );

        // Look up the field index from our field_index_map
        // Also get the actual field type from the symbol table, NOT from the passed-in field_ty
        // which may be Dynamic due to unresolved type parameters
        let (_, field_index, actual_field_type) = match self.field_index_map.get(&field) {
            Some(&(class_ty, idx)) => {
                // Get the actual field type from the symbol table
                let sym_type = self
                    .symbol_table
                    .get_symbol(field)
                    .map(|s| s.type_id)
                    .unwrap_or(field_ty);
                (class_ty, idx, sym_type)
            }
            None => {
                // Fallback: Try to find field by name instead of SymbolId
                let field_name = self.symbol_table.get_symbol(field).map(|s| s.name)?;

                let field_name_str = self.string_interner.get(field_name).unwrap_or("<unknown>");
                debug!(
                    "[lower_field_access_for_class] Looking up field '{}' ({:?}) by name in field_index_map ({} entries)",
                    field_name_str,
                    field,
                    self.field_index_map.len()
                );

                // Search for any field with the same name
                let mut found = None;
                for (sym, &(class_ty, idx)) in &self.field_index_map {
                    if let Some(sym_info) = self.symbol_table.get_symbol(*sym) {
                        if sym_info.name == field_name {
                            debug!(
                                "[lower_field_access_for_class] Found field '{}' at index {} in class_ty={:?}",
                                field_name_str, idx, class_ty
                            );
                            // Get the actual field type from the matched symbol
                            found = Some((class_ty, idx, sym_info.type_id));
                            break;
                        }
                    }
                }

                match found {
                    Some(result) => result,
                    None => {
                        debug!(
                            "[lower_field_access_for_class] Field '{}' ({:?}) NOT FOUND in field_index_map!",
                            field_name_str, field
                        );
                        self.add_error(
                            &format!(
                                "Field '{}' ({:?}) index not found for raw pointer access",
                                field_name_str, field
                            ),
                            SourceLocation::unknown(),
                        );
                        return None;
                    }
                }
            }
        };

        // Create constant for field index
        let index_const = self.builder.build_const(IrValue::I32(field_index as i32))?;

        // Get the type of the field from the actual field symbol, NOT the Dynamic-typed field_ty
        let field_ir_ty = self.convert_type(actual_field_type);

        // Use GetElementPtr to get pointer to the field
        let field_ptr = self
            .builder
            .build_gep(obj, vec![index_const], field_ir_ty.clone())?;

        // Load the value from the field pointer
        let field_value = self.builder.build_load(field_ptr, field_ir_ty.clone())?;

        // Register the type of the loaded value
        self.builder
            .set_register_type(field_value, field_ir_ty.clone());

        // Type erasure coercion: if field is I64 (erased type param) but expr expects concrete type
        let expected_ir_ty = self.convert_type(field_ty);
        if field_ir_ty == IrType::I64 && expected_ir_ty != IrType::I64 {
            return self.coerce_from_i64(field_value, field_ty);
        }

        Some(field_value)
    }

    fn lower_index_access(&mut self, obj: IrId, idx: IrId, ty: TypeId) -> Option<IrId> {
        // Array index access - call haxe_array_get_ptr runtime function
        // For HaxeArray, we need to call the runtime function instead of using GEP
        // because array elements may be boxed and require proper dynamic type handling
        //
        // Signature: fn haxe_array_get_ptr(arr: *const HaxeArray, index: usize) -> *mut u8
        //
        // The runtime function returns a pointer to the boxed element

        // Get or declare the haxe_array_get_ptr extern function
        let func_id = self.get_or_register_extern_function(
            "haxe_array_get_ptr",
            vec![IrType::Ptr(Box::new(IrType::Void)), IrType::I64],
            IrType::Ptr(Box::new(IrType::U8)),
        );

        // Call haxe_array_get_ptr(array, index)
        // The function returns a pointer to the element (*mut u8)
        let elem_ptr = self.builder.build_call_direct(
            func_id,
            vec![obj, idx],
            IrType::Ptr(Box::new(IrType::U8)),
        )?;

        // Determine the correct load type based on the element type.
        // Array slots are always 8 bytes, so we load as the storage type first.
        // For types smaller than 8 bytes (Int→I32, Bool), we need to cast after loading.
        let (load_type, target_type) = {
            let type_table = self.type_table.borrow();
            match type_table.get(ty).map(|ti| &ti.kind) {
                Some(crate::tast::TypeKind::String) => {
                    let t = IrType::Ptr(Box::new(IrType::String));
                    (t.clone(), t)
                }
                Some(crate::tast::TypeKind::Float) => (IrType::F64, IrType::F64),
                Some(crate::tast::TypeKind::Int) => (IrType::I64, IrType::I32),
                Some(crate::tast::TypeKind::Bool) => (IrType::I64, IrType::Bool),
                _ => {
                    let t = IrType::I64;
                    (t.clone(), t)
                }
            }
        };

        let loaded = self.builder.build_load(elem_ptr, load_type.clone())?;

        // Cast to target type if different from load type (e.g., I64 → I32 for Int elements)
        if load_type != target_type {
            self.builder.build_cast(loaded, load_type, target_type)
        } else {
            Some(loaded)
        }
    }

    fn lower_logical_and(&mut self, lhs: &HirExpr, rhs: &HirExpr) -> Option<IrId> {
        // Short-circuit AND: if lhs is false, don't evaluate rhs
        // Create blocks: eval_rhs, merge
        let eval_rhs = self.builder.create_block()?;
        let merge = self.builder.create_block()?;

        // Evaluate LHS
        let lhs_val = self.lower_expression(lhs)?;

        // Create false_val BEFORE branching so it's in this block's scope
        let false_val = self.builder.build_bool(false)?;

        // Capture the current block BEFORE branching - this is where LHS was evaluated
        let lhs_block = self.builder.current_block()?;

        // Branch on LHS: if true, evaluate RHS; if false, skip to merge with false
        self.builder.build_cond_branch(lhs_val, eval_rhs, merge)?;

        // Block for evaluating RHS
        self.builder.switch_to_block(eval_rhs);
        let rhs_val = self.lower_expression(rhs)?;
        let rhs_block = self.builder.current_block()?;
        self.builder.build_branch(merge)?;

        // Merge block with phi node
        self.builder.switch_to_block(merge);
        let result = self.builder.build_phi(merge, IrType::Bool)?;
        // lhs_block is where we came from if LHS was false (short-circuit path)
        self.builder
            .add_phi_incoming(merge, result, lhs_block, false_val)?;
        self.builder
            .add_phi_incoming(merge, result, rhs_block, rhs_val)?;

        Some(result)
    }

    fn lower_logical_or(&mut self, lhs: &HirExpr, rhs: &HirExpr) -> Option<IrId> {
        // Short-circuit OR: if lhs is true, don't evaluate rhs
        // Create blocks: eval_rhs, merge
        let eval_rhs = self.builder.create_block()?;
        let merge = self.builder.create_block()?;

        // Evaluate LHS
        let lhs_val = self.lower_expression(lhs)?;

        // Create true_val BEFORE branching so it's in this block's scope
        let true_val = self.builder.build_bool(true)?;

        // Capture the current block BEFORE branching - this is where LHS was evaluated
        let lhs_block = self.builder.current_block()?;

        // Branch on LHS: if false, evaluate RHS; if true, skip to merge with true
        self.builder.build_cond_branch(lhs_val, merge, eval_rhs)?;

        // Block for evaluating RHS
        self.builder.switch_to_block(eval_rhs);
        let rhs_val = self.lower_expression(rhs)?;
        let rhs_block = self.builder.current_block()?;
        self.builder.build_branch(merge)?;

        // Merge block with phi node
        self.builder.switch_to_block(merge);
        let result = self.builder.build_phi(merge, IrType::Bool)?;
        // lhs_block is where we came from if LHS was true (short-circuit path)
        self.builder
            .add_phi_incoming(merge, result, lhs_block, true_val)?;
        self.builder
            .add_phi_incoming(merge, result, rhs_block, rhs_val)?;

        Some(result)
    }

    /// Lower field-by-field equality for classes that @:derive([PartialEq]).
    /// Generates: ptr_eq fast path → null guards → field-by-field short-circuit chain.
    fn lower_derived_equality(
        &mut self,
        op: &HirBinaryOp,
        lhs: &HirExpr,
        rhs: &HirExpr,
        class_sym: SymbolId,
    ) -> Option<IrId> {
        let is_eq = matches!(op, HirBinaryOp::Eq);
        let fields = self.class_instance_fields.get(&class_sym)?.clone();

        let lhs_reg = self.lower_expression(lhs)?;
        let rhs_reg = self.lower_expression(rhs)?;

        let null_check = self.builder.create_block()?;
        let null_check2 = self.builder.create_block()?;
        let fail = self.builder.create_block()?;
        let pass = self.builder.create_block()?;
        let merge = self.builder.create_block()?;

        // Fast path: pointer equality (handles same-object and both-null)
        let ptr_eq = self.builder.build_cmp(CompareOp::Eq, lhs_reg, rhs_reg)?;
        self.builder.build_cond_branch(ptr_eq, pass, null_check)?;

        // Null check LHS (ptr_eq was false, so if lhs is null → rhs is not → not equal)
        self.builder.switch_to_block(null_check);
        let null_val = self.builder.build_const(IrValue::I64(0))?;
        let lhs_is_null = self.builder.build_cmp(CompareOp::Eq, lhs_reg, null_val)?;
        self.builder
            .build_cond_branch(lhs_is_null, fail, null_check2)?;

        // Null check RHS
        self.builder.switch_to_block(null_check2);
        let null_val2 = self.builder.build_const(IrValue::I64(0))?;
        let rhs_is_null = self.builder.build_cmp(CompareOp::Eq, rhs_reg, null_val2)?;

        if fields.is_empty() {
            // No instance fields — both non-null objects of same type are equal
            self.builder.build_cond_branch(rhs_is_null, fail, pass)?;
        } else {
            let first_field = self.builder.create_block()?;
            self.builder
                .build_cond_branch(rhs_is_null, fail, first_field)?;

            // Field-by-field comparison with short-circuit
            let mut current_block = first_field;
            for (i, &(_field_sym, field_type_id, gep_idx)) in fields.iter().enumerate() {
                self.builder.switch_to_block(current_block);

                let field_ir_type = self.convert_type(field_type_id);
                let idx_const = self.builder.build_const(IrValue::I32(gep_idx as i32))?;

                // Load field from LHS
                let lhs_ptr =
                    self.builder
                        .build_gep(lhs_reg, vec![idx_const], field_ir_type.clone())?;
                let lhs_val = self.builder.build_load(lhs_ptr, field_ir_type.clone())?;

                // Load field from RHS (reuse same index constant — IrId is Copy)
                let rhs_ptr =
                    self.builder
                        .build_gep(rhs_reg, vec![idx_const], field_ir_type.clone())?;
                let rhs_val = self.builder.build_load(rhs_ptr, field_ir_type.clone())?;

                let field_eq = self.emit_field_equality(field_type_id, lhs_val, rhs_val)?;

                if i == fields.len() - 1 {
                    // Last field — branch to pass or fail
                    self.builder.build_cond_branch(field_eq, pass, fail)?;
                } else {
                    let next = self.builder.create_block()?;
                    self.builder.build_cond_branch(field_eq, next, fail)?;
                    current_block = next;
                }
            }
        }

        // Pass block
        self.builder.switch_to_block(pass);
        let pass_val = self.builder.build_bool(is_eq)?;
        self.builder.build_branch(merge)?;

        // Fail block
        self.builder.switch_to_block(fail);
        let fail_val = self.builder.build_bool(!is_eq)?;
        self.builder.build_branch(merge)?;

        // Merge
        self.builder.switch_to_block(merge);
        let result = self.builder.build_phi(merge, IrType::Bool)?;
        self.builder
            .add_phi_incoming(merge, result, pass, pass_val)?;
        self.builder
            .add_phi_incoming(merge, result, fail, fail_val)?;

        Some(result)
    }

    /// Emit equality comparison for a single field based on its type.
    /// Returns a Bool register: true if equal.
    fn emit_field_equality(&mut self, type_id: TypeId, lhs: IrId, rhs: IrId) -> Option<IrId> {
        let is_string = {
            let type_table = self.type_table.borrow();
            type_table
                .get(type_id)
                .map(|t| matches!(t.kind, TypeKind::String))
                .unwrap_or(false)
        };

        if is_string {
            let string_ptr_ty = IrType::Ptr(Box::new(IrType::String));
            let cmp_func = self.get_or_register_extern_function(
                "haxe_string_compare",
                vec![string_ptr_ty.clone(), string_ptr_ty.clone()],
                IrType::I32,
            );
            let cmp_result =
                self.builder
                    .build_call_direct(cmp_func, vec![lhs, rhs], IrType::I32)?;
            let zero = self.builder.build_const(IrValue::I32(0))?;
            self.builder.build_cmp(CompareOp::Eq, cmp_result, zero)
        } else {
            // Direct comparison: Int, Float, Bool, pointers (class/enum)
            self.builder.build_cmp(CompareOp::Eq, lhs, rhs)
        }
    }

    /// Lower lexicographic ordering for classes that @:derive([PartialOrd]).
    /// Computes a three-way comparison per field, short-circuiting on first difference.
    fn lower_derived_ordering(
        &mut self,
        op: &HirBinaryOp,
        lhs: &HirExpr,
        rhs: &HirExpr,
        class_sym: SymbolId,
    ) -> Option<IrId> {
        let fields = self.class_instance_fields.get(&class_sym)?.clone();

        let lhs_reg = self.lower_expression(lhs)?;
        let rhs_reg = self.lower_expression(rhs)?;

        // All paths converge at final_cmp with a three-way i32 value
        let final_cmp = self.builder.create_block()?;
        let mut phi_inputs: Vec<(IrBlockId, IrId)> = Vec::new();

        // Fast path: pointer equality → cmp_val = 0 (equal)
        let null_check = self.builder.create_block()?;
        let same_ptr = self.builder.create_block()?;
        let ptr_eq = self.builder.build_cmp(CompareOp::Eq, lhs_reg, rhs_reg)?;
        self.builder
            .build_cond_branch(ptr_eq, same_ptr, null_check)?;

        self.builder.switch_to_block(same_ptr);
        let zero_same = self.builder.build_const(IrValue::I32(0))?;
        phi_inputs.push((same_ptr, zero_same));
        self.builder.build_branch(final_cmp)?;

        // Null guards: null is treated as "less than" any non-null value
        self.builder.switch_to_block(null_check);
        let null_val = self.builder.build_const(IrValue::I64(0))?;
        let lhs_is_null = self.builder.build_cmp(CompareOp::Eq, lhs_reg, null_val)?;
        let lhs_null_block = self.builder.create_block()?;
        let null_check2 = self.builder.create_block()?;
        self.builder
            .build_cond_branch(lhs_is_null, lhs_null_block, null_check2)?;

        // LHS is null, RHS is not → LHS < RHS → cmp_val = -1
        self.builder.switch_to_block(lhs_null_block);
        let neg_one_null = self.builder.build_const(IrValue::I32(-1))?;
        phi_inputs.push((lhs_null_block, neg_one_null));
        self.builder.build_branch(final_cmp)?;

        self.builder.switch_to_block(null_check2);
        let null_val2 = self.builder.build_const(IrValue::I64(0))?;
        let rhs_is_null = self.builder.build_cmp(CompareOp::Eq, rhs_reg, null_val2)?;
        let rhs_null_block = self.builder.create_block()?;
        let field_start = self.builder.create_block()?;
        self.builder
            .build_cond_branch(rhs_is_null, rhs_null_block, field_start)?;

        // RHS is null, LHS is not → LHS > RHS → cmp_val = 1
        self.builder.switch_to_block(rhs_null_block);
        let pos_one_null = self.builder.build_const(IrValue::I32(1))?;
        phi_inputs.push((rhs_null_block, pos_one_null));
        self.builder.build_branch(final_cmp)?;

        // Field-by-field three-way comparison
        self.builder.switch_to_block(field_start);
        if fields.is_empty() {
            // No fields → equal → cmp_val = 0
            let zero_empty = self.builder.build_const(IrValue::I32(0))?;
            phi_inputs.push((field_start, zero_empty));
            self.builder.build_branch(final_cmp)?;
        } else {
            for (i, &(_field_sym, field_type_id, gep_idx)) in fields.iter().enumerate() {
                let field_ir_type = self.convert_type(field_type_id);
                let idx_const = self.builder.build_const(IrValue::I32(gep_idx as i32))?;

                let lhs_ptr =
                    self.builder
                        .build_gep(lhs_reg, vec![idx_const], field_ir_type.clone())?;
                let lhs_val = self.builder.build_load(lhs_ptr, field_ir_type.clone())?;

                let rhs_ptr =
                    self.builder
                        .build_gep(rhs_reg, vec![idx_const], field_ir_type.clone())?;
                let rhs_val = self.builder.build_load(rhs_ptr, field_ir_type.clone())?;

                let cmp_val = self.emit_field_three_way_cmp(field_type_id, lhs_val, rhs_val)?;

                if i == fields.len() - 1 {
                    // Last field — always go to final_cmp
                    let cur = self.builder.current_block()?;
                    phi_inputs.push((cur, cmp_val));
                    self.builder.build_branch(final_cmp)?;
                } else {
                    // Non-zero → decided, go to final_cmp; zero → next field
                    let zero = self.builder.build_const(IrValue::I32(0))?;
                    let is_ne = self.builder.build_cmp(CompareOp::Ne, cmp_val, zero)?;
                    let cur = self.builder.current_block()?;
                    phi_inputs.push((cur, cmp_val));
                    let next = self.builder.create_block()?;
                    self.builder.build_cond_branch(is_ne, final_cmp, next)?;
                    self.builder.switch_to_block(next);
                }
            }
        }

        // Final comparison: cmp_val <op> 0
        self.builder.switch_to_block(final_cmp);
        let cmp_val = self.builder.build_phi(final_cmp, IrType::I32)?;
        for &(block, val) in &phi_inputs {
            self.builder
                .add_phi_incoming(final_cmp, cmp_val, block, val)?;
        }
        let zero_final = self.builder.build_const(IrValue::I32(0))?;
        let cmp_op = match op {
            HirBinaryOp::Lt => CompareOp::Lt,
            HirBinaryOp::Le => CompareOp::Le,
            HirBinaryOp::Gt => CompareOp::Gt,
            HirBinaryOp::Ge => CompareOp::Ge,
            _ => unreachable!(),
        };
        self.builder.build_cmp(cmp_op, cmp_val, zero_final)
    }

    /// Compute a three-way comparison value (i32: -1, 0, 1) for a single field.
    fn emit_field_three_way_cmp(&mut self, type_id: TypeId, lhs: IrId, rhs: IrId) -> Option<IrId> {
        let is_string = {
            let type_table = self.type_table.borrow();
            type_table
                .get(type_id)
                .map(|t| matches!(t.kind, TypeKind::String))
                .unwrap_or(false)
        };

        if is_string {
            // haxe_string_compare already returns a three-way i32
            let string_ptr_ty = IrType::Ptr(Box::new(IrType::String));
            let cmp_func = self.get_or_register_extern_function(
                "haxe_string_compare",
                vec![string_ptr_ty.clone(), string_ptr_ty.clone()],
                IrType::I32,
            );
            self.builder
                .build_call_direct(cmp_func, vec![lhs, rhs], IrType::I32)
        } else {
            // (a < b) ? -1 : ((a > b) ? 1 : 0)
            let lt_block = self.builder.create_block()?;
            let gt_check = self.builder.create_block()?;
            let gt_block = self.builder.create_block()?;
            let eq_block = self.builder.create_block()?;
            let cmp_merge = self.builder.create_block()?;

            let is_lt = self.builder.build_cmp(CompareOp::Lt, lhs, rhs)?;
            self.builder.build_cond_branch(is_lt, lt_block, gt_check)?;

            self.builder.switch_to_block(lt_block);
            let neg_one = self.builder.build_const(IrValue::I32(-1))?;
            self.builder.build_branch(cmp_merge)?;

            self.builder.switch_to_block(gt_check);
            let is_gt = self.builder.build_cmp(CompareOp::Gt, lhs, rhs)?;
            self.builder.build_cond_branch(is_gt, gt_block, eq_block)?;

            self.builder.switch_to_block(gt_block);
            let pos_one = self.builder.build_const(IrValue::I32(1))?;
            self.builder.build_branch(cmp_merge)?;

            self.builder.switch_to_block(eq_block);
            let zero = self.builder.build_const(IrValue::I32(0))?;
            self.builder.build_branch(cmp_merge)?;

            self.builder.switch_to_block(cmp_merge);
            let result = self.builder.build_phi(cmp_merge, IrType::I32)?;
            self.builder
                .add_phi_incoming(cmp_merge, result, lt_block, neg_one)?;
            self.builder
                .add_phi_incoming(cmp_merge, result, gt_block, pos_one)?;
            self.builder
                .add_phi_incoming(cmp_merge, result, eq_block, zero)?;

            Some(result)
        }
    }

    /// Lower inline hash computation for classes that @:derive([Hash]).
    /// Computes: hash = seed; for each field: hash = hash * 31 + field_hash; return hash as I32.
    fn lower_derived_hash_code(&mut self, object: &HirExpr, class_sym: SymbolId) -> Option<IrId> {
        let fields = self.class_instance_fields.get(&class_sym)?.clone();
        let obj_reg = self.lower_expression(object)?;

        // Start with seed based on number of fields (deterministic per-class)
        let mut hash_reg = self.builder.build_const(IrValue::I64(2166136261i64))?; // FNV offset basis

        let thirty_one = self.builder.build_const(IrValue::I64(31))?;

        for &(_field_sym, field_type_id, gep_idx) in &fields {
            let field_ir_type = self.convert_type(field_type_id);
            let idx_const = self.builder.build_const(IrValue::I32(gep_idx as i32))?;
            let field_ptr =
                self.builder
                    .build_gep(obj_reg, vec![idx_const], field_ir_type.clone())?;
            let field_val = self.builder.build_load(field_ptr, field_ir_type.clone())?;

            // Compute field hash based on type
            let field_hash = self.emit_field_hash(field_type_id, &field_ir_type, field_val)?;

            // hash = hash * 31 + field_hash
            let mul = self
                .builder
                .build_binop(BinaryOp::Mul, hash_reg, thirty_one)?;
            hash_reg = self.builder.build_binop(BinaryOp::Add, mul, field_hash)?;
        }

        // Truncate to I32 for Haxe Int return type
        self.builder.build_cast(hash_reg, IrType::I64, IrType::I32)
    }

    /// Compute a hash value (i64) for a single field based on its type.
    fn emit_field_hash(&mut self, type_id: TypeId, ir_type: &IrType, val: IrId) -> Option<IrId> {
        let type_kind = {
            let type_table = self.type_table.borrow();
            type_table.get(type_id).map(|t| t.kind.clone())
        };

        match type_kind.as_ref() {
            Some(TypeKind::String) => {
                // Call haxe_string_hash → i32, then widen to i64
                let string_ptr_ty = IrType::Ptr(Box::new(IrType::String));
                let hash_func = self.get_or_register_extern_function(
                    "haxe_string_hash",
                    vec![string_ptr_ty],
                    IrType::I32,
                );
                let hash_i32 = self
                    .builder
                    .build_call_direct(hash_func, vec![val], IrType::I32)?;
                self.builder.build_cast(hash_i32, IrType::I32, IrType::I64)
            }
            Some(TypeKind::Int) => {
                // Widen i32 to i64
                self.builder.build_cast(val, IrType::I32, IrType::I64)
            }
            Some(TypeKind::Bool) => {
                // false → 0, true → 1
                self.builder.build_cast(val, IrType::Bool, IrType::I64)
            }
            Some(TypeKind::Float) => {
                // Bitcast f64 to i64 for hash
                self.builder.build_bitcast(val, IrType::I64)
            }
            _ => {
                // Pointer/enum/other — use as i64 directly
                match ir_type {
                    IrType::I32 => self.builder.build_cast(val, IrType::I32, IrType::I64),
                    IrType::I64 => Some(val),
                    _ => self.builder.build_cast(val, ir_type.clone(), IrType::I64),
                }
            }
        }
    }

    /// @:derive(Clone) — deep copy an instance by allocating a new object and copying each field.
    /// String and Array fields are deep-copied; class fields with Clone are recursively cloned;
    /// primitives and other pointers are shallow-copied.
    fn lower_derived_clone(&mut self, object: &HirExpr, class_sym: SymbolId) -> Option<IrId> {
        let fields = self.class_instance_fields.get(&class_sym)?.clone();
        let obj_reg = self.lower_expression(object)?;

        // Compute allocation size: (num_fields + 1) * 8  (slot 0 = type_id header)
        let alloc_size = (fields.len() as u64 + 1) * 8;
        let alloc_size = alloc_size.max(16); // minimum 16 bytes
        let new_ptr = self.build_heap_alloc(alloc_size)?;

        // Copy type_id header from source (GEP index 0)
        let zero = self.builder.build_const(IrValue::I32(0))?;
        let header_ptr = self.builder.build_gep(obj_reg, vec![zero], IrType::I64)?;
        let header_val = self.builder.build_load(header_ptr, IrType::I64)?;
        let zero2 = self.builder.build_const(IrValue::I32(0))?;
        let new_header_ptr = self.builder.build_gep(new_ptr, vec![zero2], IrType::I64)?;
        self.builder.build_store(new_header_ptr, header_val)?;

        // Copy each field
        for &(_field_sym, field_type_id, gep_idx) in &fields {
            let field_ir_type = self.convert_type(field_type_id);
            let idx_const = self.builder.build_const(IrValue::I32(gep_idx as i32))?;
            let src_field_ptr =
                self.builder
                    .build_gep(obj_reg, vec![idx_const], field_ir_type.clone())?;
            let field_val = self
                .builder
                .build_load(src_field_ptr, field_ir_type.clone())?;

            // Determine copy strategy based on type
            let cloned_val = {
                let type_kind = {
                    let type_table = self.type_table.borrow();
                    type_table.get(field_type_id).map(|t| t.kind.clone())
                };
                match type_kind.as_ref() {
                    Some(TypeKind::String) => {
                        // Deep copy string via haxe_string_copy
                        let string_ptr_ty = IrType::Ptr(Box::new(IrType::String));
                        let copy_func = self.get_or_register_extern_function(
                            "haxe_string_copy",
                            vec![string_ptr_ty.clone()],
                            string_ptr_ty,
                        );
                        self.builder.build_call_direct(
                            copy_func,
                            vec![field_val],
                            IrType::Ptr(Box::new(IrType::String)),
                        )?
                    }
                    Some(TypeKind::Class { symbol_id, .. })
                        if self.derive_clone_classes.contains(symbol_id) =>
                    {
                        // Recursively clone nested Clone class
                        // For now, shallow copy (recursive clone would need the HirExpr)
                        field_val
                    }
                    _ => {
                        // Primitive (Int, Float, Bool) or other pointer — bitwise copy
                        field_val
                    }
                }
            };

            let dst_idx = self.builder.build_const(IrValue::I32(gep_idx as i32))?;
            let dst_field_ptr = self
                .builder
                .build_gep(new_ptr, vec![dst_idx], field_ir_type)?;
            self.builder.build_store(dst_field_ptr, cloned_val)?;
        }

        // Set class hint so field access on cloned value uses GEP, not reflection
        if let Some(sym) = self.symbol_table.get_symbol(class_sym) {
            let name = self.string_interner.get(sym.name).unwrap_or("").to_string();
            if !name.is_empty() {
                self.register_class_hints.insert(new_ptr, name);
            }
        }

        Some(new_ptr)
    }

    /// Check if a type is a @:derive(Copy) class, returning its SymbolId.
    fn get_copy_class_symbol(&self, type_id: TypeId) -> Option<SymbolId> {
        let (kind_class_sym, generic_base) = {
            let type_table = self.type_table.borrow();
            let type_ref = type_table.get(type_id)?;
            match &type_ref.kind {
                TypeKind::Class { symbol_id, .. } => (Some(*symbol_id), None),
                TypeKind::GenericInstance { base_type, .. } => (None, Some(*base_type)),
                _ => (None, None),
            }
        };
        if let Some(sym) = kind_class_sym {
            if self.derive_copy_classes.contains(&sym) {
                return Some(sym);
            }
        }
        if let Some(base) = generic_base {
            return self.get_copy_class_symbol(base);
        }
        None
    }

    /// @:derive(Copy) — emit a shallow (bitwise) copy of a class instance.
    /// All fields must be primitives (enforced at validation time).
    fn emit_shallow_copy(&mut self, src_reg: IrId, class_sym: SymbolId) -> Option<IrId> {
        let fields = self.class_instance_fields.get(&class_sym)?.clone();

        // Allocate: (num_fields + 1) * 8  (slot 0 = type_id header)
        let alloc_size = ((fields.len() as u64 + 1) * 8).max(16);
        let new_ptr = self.build_heap_alloc(alloc_size)?;

        // Copy type_id header (GEP index 0)
        let zero = self.builder.build_const(IrValue::I32(0))?;
        let header_ptr = self.builder.build_gep(src_reg, vec![zero], IrType::I64)?;
        let header_val = self.builder.build_load(header_ptr, IrType::I64)?;
        let zero2 = self.builder.build_const(IrValue::I32(0))?;
        let new_header_ptr = self.builder.build_gep(new_ptr, vec![zero2], IrType::I64)?;
        self.builder.build_store(new_header_ptr, header_val)?;

        // Copy each field (all primitives — bitwise copy)
        for &(_field_sym, field_type_id, gep_idx) in &fields {
            let field_ir_type = self.convert_type(field_type_id);
            let idx_const = self.builder.build_const(IrValue::I32(gep_idx as i32))?;
            let src_field_ptr =
                self.builder
                    .build_gep(src_reg, vec![idx_const], field_ir_type.clone())?;
            let field_val = self
                .builder
                .build_load(src_field_ptr, field_ir_type.clone())?;
            let dst_idx = self.builder.build_const(IrValue::I32(gep_idx as i32))?;
            let dst_field_ptr = self
                .builder
                .build_gep(new_ptr, vec![dst_idx], field_ir_type)?;
            self.builder.build_store(dst_field_ptr, field_val)?;
        }

        // Set class hint for field access on copied value
        if let Some(sym) = self.symbol_table.get_symbol(class_sym) {
            let name = self.string_interner.get(sym.name).unwrap_or("").to_string();
            if !name.is_empty() {
                self.register_class_hints.insert(new_ptr, name);
            }
        }

        Some(new_ptr)
    }

    /// @:derive(Copy) — copy any Copy-typed variable arguments at call boundaries.
    /// Returns new arg_regs with copies substituted for Copy-type variables.
    fn maybe_copy_call_args(&mut self, args: &[HirExpr], arg_regs: Vec<IrId>) -> Vec<IrId> {
        if self.derive_copy_classes.is_empty() {
            return arg_regs;
        }
        args.iter()
            .zip(arg_regs)
            .map(|(arg_expr, reg)| {
                if let HirExprKind::Variable { .. } = &arg_expr.kind {
                    if let Some(class_sym) = self.get_copy_class_symbol(arg_expr.ty) {
                        if let Some(copy_ptr) = self.emit_shallow_copy(reg, class_sym) {
                            return copy_ptr;
                        }
                    }
                }
                reg
            })
            .collect()
    }

    /// @:derive(Drop) — get the class SymbolId for an IrId if it's a Drop class.
    /// Uses register_class_hints to map IrId → class name, then resolves to SymbolId.
    fn get_drop_class_for_ir(&self, ir_id: IrId) -> Option<SymbolId> {
        if self.derive_drop_classes.is_empty() {
            return None;
        }
        // First check the direct mapping
        if let Some(&class_sym) = self.ir_to_drop_class.get(&ir_id) {
            return Some(class_sym);
        }
        // Fallback: use register_class_hints to find the class name, then resolve
        let class_name = self.register_class_hints.get(&ir_id)?;
        for &class_sym in &self.derive_drop_classes {
            if let Some(symbol) = self.symbol_table.get_symbol(class_sym) {
                let sym_name = self.string_interner.get(symbol.name);
                if sym_name == Some(class_name.as_str()) {
                    return Some(class_sym);
                }
            }
        }
        None
    }

    /// @:derive(Drop) — emit a call to the user's drop() method on the given object.
    /// Called before Free at scope exit, reassignment, and early return.
    fn emit_drop_call(&mut self, obj_reg: IrId, class_sym: SymbolId) {
        let drop_name = self.string_interner.intern("drop");
        // Look up the drop() method
        let method_sym = match self.resolve_class_method_symbol(class_sym, drop_name) {
            Some(sym) => sym,
            None => {
                trace!(
                    "Drop: Could not find drop() method for class {:?}",
                    class_sym
                );
                return;
            }
        };
        let func_id = match self.get_function_id(&method_sym) {
            Some(id) => id,
            None => {
                trace!(
                    "Drop: Could not find IrFunctionId for drop() method {:?}",
                    method_sym
                );
                return;
            }
        };
        // Call drop(this) — the object pointer is passed as the receiver
        self.builder
            .build_call_direct(func_id, vec![obj_reg], IrType::Void);
    }

    /// @:derive(Drop) — conditionally emit drop() call before Free for an IrId.
    /// Returns true if a drop call was emitted.
    fn maybe_emit_drop_call(&mut self, ir_id: IrId) -> bool {
        if let Some(class_sym) = self.get_drop_class_for_ir(ir_id) {
            self.emit_drop_call(ir_id, class_sym);
            true
        } else {
            false
        }
    }

    /// @:derive(Debug) — generate toString() returning "ClassName { field1: val1, field2: val2 }"
    fn lower_derived_to_string(&mut self, object: &HirExpr, class_sym: SymbolId) -> Option<IrId> {
        let fields = self.class_instance_fields.get(&class_sym)?.clone();
        let obj_reg = self.lower_expression(object)?;

        let string_ptr_ty = IrType::Ptr(Box::new(IrType::String));
        let concat_fn = self.get_or_register_extern_function(
            "haxe_string_concat",
            vec![string_ptr_ty.clone(), string_ptr_ty.clone()],
            string_ptr_ty.clone(),
        );
        let std_string_fn = self.get_or_register_extern_function(
            "haxe_std_string_ptr",
            vec![IrType::Ptr(Box::new(IrType::U8))],
            string_ptr_ty.clone(),
        );
        let box_int_fn = self.get_or_register_extern_function(
            "haxe_box_int_ptr",
            vec![IrType::I64],
            IrType::Ptr(Box::new(IrType::U8)),
        );
        let box_float_fn = self.get_or_register_extern_function(
            "haxe_box_float_ptr",
            vec![IrType::F64],
            IrType::Ptr(Box::new(IrType::U8)),
        );

        // Check for @:debugFormat custom format string
        if let Some(fmt) = self.debug_format_strings.get(&class_sym).cloned() {
            return self.emit_custom_debug_format(
                obj_reg,
                &fields,
                &fmt,
                concat_fn,
                std_string_fn,
                box_int_fn,
                box_float_fn,
                &string_ptr_ty,
            );
        }

        // Get class name
        let class_name = self
            .symbol_table
            .get_symbol(class_sym)
            .and_then(|s| self.string_interner.get(s.name))
            .unwrap_or("Unknown");

        // Start with "ClassName { "
        let mut result = self.builder.build_string(format!("{} {{ ", class_name))?;

        for (i, &(field_sym, field_type_id, gep_idx)) in fields.iter().enumerate() {
            // Get field name
            let field_name = self
                .symbol_table
                .get_symbol(field_sym)
                .and_then(|s| self.string_interner.get(s.name))
                .unwrap_or("?");

            // Append "fieldName: "
            let prefix = if i > 0 {
                format!(", {}: ", field_name)
            } else {
                format!("{}: ", field_name)
            };
            let prefix_str = self.builder.build_string(prefix)?;
            result = self.builder.build_call_direct(
                concat_fn,
                vec![result, prefix_str],
                string_ptr_ty.clone(),
            )?;

            // Load field value
            let field_ir_type = self.convert_type(field_type_id);
            let idx_const = self.builder.build_const(IrValue::I32(gep_idx as i32))?;
            let field_ptr =
                self.builder
                    .build_gep(obj_reg, vec![idx_const], field_ir_type.clone())?;
            let field_val = self.builder.build_load(field_ptr, field_ir_type.clone())?;

            // Convert field to string based on type
            let type_kind = {
                let type_table = self.type_table.borrow();
                type_table.get(field_type_id).map(|t| t.kind.clone())
            };
            let field_str = match type_kind.as_ref() {
                Some(TypeKind::String) => {
                    // String field — use directly
                    field_val
                }
                Some(TypeKind::Bool) => {
                    // Bool → "true" / "false" via branch
                    let true_str = self.builder.build_string("true".to_string())?;
                    let false_str = self.builder.build_string("false".to_string())?;
                    self.builder.build_select(field_val, true_str, false_str)?
                }
                Some(TypeKind::Int) => {
                    // Int → box → haxe_std_string_ptr
                    let as_i64 = self
                        .builder
                        .build_cast(field_val, IrType::I32, IrType::I64)?;
                    let boxed = self.builder.build_call_direct(
                        box_int_fn,
                        vec![as_i64],
                        IrType::Ptr(Box::new(IrType::U8)),
                    )?;
                    self.builder.build_call_direct(
                        std_string_fn,
                        vec![boxed],
                        string_ptr_ty.clone(),
                    )?
                }
                Some(TypeKind::Float) => {
                    // Float → box → haxe_std_string_ptr
                    let boxed = self.builder.build_call_direct(
                        box_float_fn,
                        vec![field_val],
                        IrType::Ptr(Box::new(IrType::U8)),
                    )?;
                    self.builder.build_call_direct(
                        std_string_fn,
                        vec![boxed],
                        string_ptr_ty.clone(),
                    )?
                }
                _ => {
                    // Check if field type is a @:derive(Debug) class — recursive toString
                    let nested_debug_sym = {
                        let type_table = self.type_table.borrow();
                        match type_table.get(field_type_id).map(|t| &t.kind) {
                            Some(TypeKind::Class { symbol_id, .. }) => {
                                if self.derive_debug_classes.contains(symbol_id) {
                                    Some(*symbol_id)
                                } else {
                                    None
                                }
                            }
                            _ => None,
                        }
                    };
                    if let Some(nested_sym) = nested_debug_sym {
                        // Recursively generate toString for the nested @:derive(Debug) object
                        if let Some(nested_fields) =
                            self.class_instance_fields.get(&nested_sym).cloned()
                        {
                            self.emit_debug_to_string_for_ptr_depth(
                                field_val,
                                nested_sym,
                                &nested_fields,
                                concat_fn,
                                std_string_fn,
                                box_int_fn,
                                box_float_fn,
                                &string_ptr_ty,
                                1,
                            )?
                        } else {
                            self.builder.build_string("<object>".to_string())?
                        }
                    } else {
                        // Non-debug class — "<object>"
                        self.builder.build_string("<object>".to_string())?
                    }
                }
            };

            result = self.builder.build_call_direct(
                concat_fn,
                vec![result, field_str],
                string_ptr_ty.clone(),
            )?;
        }

        // Append " }"
        let suffix = self.builder.build_string(" }".to_string())?;
        self.builder
            .build_call_direct(concat_fn, vec![result, suffix], string_ptr_ty)
    }

    /// Emit a custom @:debugFormat string. Parses "{fieldName}" placeholders in the format
    /// and replaces them with field value conversions.
    #[allow(clippy::too_many_arguments)]
    fn emit_custom_debug_format(
        &mut self,
        obj_reg: IrId,
        fields: &[(SymbolId, TypeId, u32)],
        fmt: &str,
        concat_fn: IrFunctionId,
        std_string_fn: IrFunctionId,
        box_int_fn: IrFunctionId,
        box_float_fn: IrFunctionId,
        string_ptr_ty: &IrType,
    ) -> Option<IrId> {
        // Build a name→(type_id, gep_idx) map for field lookup
        let field_map: std::collections::HashMap<String, (TypeId, u32)> = fields
            .iter()
            .filter_map(|&(sym, ty, idx)| {
                let name = self
                    .symbol_table
                    .get_symbol(sym)
                    .and_then(|s| self.string_interner.get(s.name))
                    .map(|s| s.to_string())?;
                Some((name, (ty, idx)))
            })
            .collect();

        // Parse format string into segments: literal text and {fieldName} references
        let mut result = self.builder.build_string(String::new())?;
        let mut chars = fmt.chars().peekable();
        let mut literal = String::new();

        while let Some(ch) = chars.next() {
            if ch == '{' {
                // Flush accumulated literal
                if !literal.is_empty() {
                    let lit_str = self.builder.build_string(literal.clone())?;
                    result = self.builder.build_call_direct(
                        concat_fn,
                        vec![result, lit_str],
                        string_ptr_ty.clone(),
                    )?;
                    literal.clear();
                }
                // Read field name until '}'
                let mut field_name = String::new();
                for ch2 in chars.by_ref() {
                    if ch2 == '}' {
                        break;
                    }
                    field_name.push(ch2);
                }
                // Look up field and emit value
                if let Some(&(field_type_id, gep_idx)) = field_map.get(&field_name) {
                    let field_ir_type = self.convert_type(field_type_id);
                    let idx_const = self.builder.build_const(IrValue::I32(gep_idx as i32))?;
                    let field_ptr =
                        self.builder
                            .build_gep(obj_reg, vec![idx_const], field_ir_type.clone())?;
                    let field_val = self.builder.build_load(field_ptr, field_ir_type)?;

                    let type_kind = {
                        let type_table = self.type_table.borrow();
                        type_table.get(field_type_id).map(|t| t.kind.clone())
                    };
                    let field_str = match type_kind.as_ref() {
                        Some(TypeKind::String) => field_val,
                        Some(TypeKind::Bool) => {
                            let t = self.builder.build_string("true".to_string())?;
                            let f = self.builder.build_string("false".to_string())?;
                            self.builder.build_select(field_val, t, f)?
                        }
                        Some(TypeKind::Int) => {
                            let as_i64 =
                                self.builder
                                    .build_cast(field_val, IrType::I32, IrType::I64)?;
                            let boxed = self.builder.build_call_direct(
                                box_int_fn,
                                vec![as_i64],
                                IrType::Ptr(Box::new(IrType::U8)),
                            )?;
                            self.builder.build_call_direct(
                                std_string_fn,
                                vec![boxed],
                                string_ptr_ty.clone(),
                            )?
                        }
                        Some(TypeKind::Float) => {
                            let boxed = self.builder.build_call_direct(
                                box_float_fn,
                                vec![field_val],
                                IrType::Ptr(Box::new(IrType::U8)),
                            )?;
                            self.builder.build_call_direct(
                                std_string_fn,
                                vec![boxed],
                                string_ptr_ty.clone(),
                            )?
                        }
                        _ => self.builder.build_string("<object>".to_string())?,
                    };
                    result = self.builder.build_call_direct(
                        concat_fn,
                        vec![result, field_str],
                        string_ptr_ty.clone(),
                    )?;
                } else {
                    // Unknown field — emit literal "{fieldName}"
                    let unknown = self.builder.build_string(format!("{{{}}}", field_name))?;
                    result = self.builder.build_call_direct(
                        concat_fn,
                        vec![result, unknown],
                        string_ptr_ty.clone(),
                    )?;
                }
            } else {
                literal.push(ch);
            }
        }
        // Flush remaining literal
        if !literal.is_empty() {
            let lit_str = self.builder.build_string(literal)?;
            result = self.builder.build_call_direct(
                concat_fn,
                vec![result, lit_str],
                string_ptr_ty.clone(),
            )?;
        }
        Some(result)
    }

    /// Emit Debug toString for a pointer to a @:derive(Debug) class, using pre-resolved extern fns.
    /// Used for recursive nested object formatting.
    #[allow(clippy::too_many_arguments)]
    fn emit_debug_to_string_for_ptr(
        &mut self,
        obj_reg: IrId,
        class_sym: SymbolId,
        fields: &[(SymbolId, TypeId, u32)],
        concat_fn: IrFunctionId,
        std_string_fn: IrFunctionId,
        box_int_fn: IrFunctionId,
        box_float_fn: IrFunctionId,
        string_ptr_ty: &IrType,
    ) -> Option<IrId> {
        self.emit_debug_to_string_for_ptr_depth(
            obj_reg,
            class_sym,
            fields,
            concat_fn,
            std_string_fn,
            box_int_fn,
            box_float_fn,
            string_ptr_ty,
            0,
        )
    }

    fn emit_debug_to_string_for_ptr_depth(
        &mut self,
        obj_reg: IrId,
        class_sym: SymbolId,
        fields: &[(SymbolId, TypeId, u32)],
        concat_fn: IrFunctionId,
        std_string_fn: IrFunctionId,
        box_int_fn: IrFunctionId,
        box_float_fn: IrFunctionId,
        string_ptr_ty: &IrType,
        depth: u32,
    ) -> Option<IrId> {
        // Depth limit to prevent infinite recursion for self-referential types
        const MAX_DEBUG_DEPTH: u32 = 4;
        if depth >= MAX_DEBUG_DEPTH {
            return self.builder.build_string("<...>".to_string());
        }

        let class_name = self
            .symbol_table
            .get_symbol(class_sym)
            .and_then(|s| self.string_interner.get(s.name))
            .unwrap_or("Unknown");

        let mut result = self.builder.build_string(format!("{} {{ ", class_name))?;

        for (i, &(field_sym, field_type_id, gep_idx)) in fields.iter().enumerate() {
            let field_name = self
                .symbol_table
                .get_symbol(field_sym)
                .and_then(|s| self.string_interner.get(s.name))
                .unwrap_or("?");

            let prefix = if i > 0 {
                format!(", {}: ", field_name)
            } else {
                format!("{}: ", field_name)
            };
            let prefix_str = self.builder.build_string(prefix)?;
            result = self.builder.build_call_direct(
                concat_fn,
                vec![result, prefix_str],
                string_ptr_ty.clone(),
            )?;

            let field_ir_type = self.convert_type(field_type_id);
            let idx_const = self.builder.build_const(IrValue::I32(gep_idx as i32))?;
            let field_ptr =
                self.builder
                    .build_gep(obj_reg, vec![idx_const], field_ir_type.clone())?;
            let field_val = self.builder.build_load(field_ptr, field_ir_type.clone())?;

            let type_kind = {
                let type_table = self.type_table.borrow();
                type_table.get(field_type_id).map(|t| t.kind.clone())
            };
            let field_str = match type_kind.as_ref() {
                Some(TypeKind::String) => field_val,
                Some(TypeKind::Bool) => {
                    let true_str = self.builder.build_string("true".to_string())?;
                    let false_str = self.builder.build_string("false".to_string())?;
                    self.builder.build_select(field_val, true_str, false_str)?
                }
                Some(TypeKind::Int) => {
                    let as_i64 = self
                        .builder
                        .build_cast(field_val, IrType::I32, IrType::I64)?;
                    let boxed = self.builder.build_call_direct(
                        box_int_fn,
                        vec![as_i64],
                        IrType::Ptr(Box::new(IrType::U8)),
                    )?;
                    self.builder.build_call_direct(
                        std_string_fn,
                        vec![boxed],
                        string_ptr_ty.clone(),
                    )?
                }
                Some(TypeKind::Float) => {
                    let boxed = self.builder.build_call_direct(
                        box_float_fn,
                        vec![field_val],
                        IrType::Ptr(Box::new(IrType::U8)),
                    )?;
                    self.builder.build_call_direct(
                        std_string_fn,
                        vec![boxed],
                        string_ptr_ty.clone(),
                    )?
                }
                _ => self.builder.build_string("<object>".to_string())?,
            };

            result = self.builder.build_call_direct(
                concat_fn,
                vec![result, field_str],
                string_ptr_ty.clone(),
            )?;
        }

        let suffix = self.builder.build_string(" }".to_string())?;
        self.builder
            .build_call_direct(concat_fn, vec![result, suffix], string_ptr_ty.clone())
    }

    /// @:derive(Default) — allocate a zero-initialized instance with default values for all fields.
    fn lower_derived_default(&mut self, class_sym: SymbolId) -> Option<IrId> {
        let fields = self.class_instance_fields.get(&class_sym)?.clone();

        // Compute allocation size
        let alloc_size = (fields.len() as u64 + 1) * 8;
        let alloc_size = alloc_size.max(16);
        let new_ptr = self.build_heap_alloc(alloc_size)?;

        // Store type_id header at GEP index 0
        let type_id_val = self
            .builder
            .build_const(IrValue::I64(class_sym.as_raw() as i64))?;
        let zero = self.builder.build_const(IrValue::I32(0))?;
        let header_ptr = self.builder.build_gep(new_ptr, vec![zero], IrType::I64)?;
        self.builder.build_store(header_ptr, type_id_val)?;

        // Initialize each field to its default value
        // Priority: @:default(value) metadata > field initializer > type-based default
        let field_defaults: Vec<_> = fields
            .iter()
            .map(|&(field_sym, _, _)| self.field_default_exprs.get(&field_sym).cloned())
            .collect();

        for (i, &(_field_sym, field_type_id, gep_idx)) in fields.iter().enumerate() {
            let field_ir_type = self.convert_type(field_type_id);

            // Try custom default from @:default(value) or field initializer first
            let default_val = if let Some(ref default_expr) = field_defaults[i] {
                match self.lower_expression(default_expr) {
                    Some(val) => val,
                    None => self.build_type_default(field_type_id)?,
                }
            } else {
                self.build_type_default(field_type_id)?
            };

            let idx_const = self.builder.build_const(IrValue::I32(gep_idx as i32))?;
            let field_ptr = self
                .builder
                .build_gep(new_ptr, vec![idx_const], field_ir_type)?;
            self.builder.build_store(field_ptr, default_val)?;
        }

        // Set class hint so field access on default instance uses GEP, not reflection
        if let Some(sym) = self.symbol_table.get_symbol(class_sym) {
            let name = self.string_interner.get(sym.name).unwrap_or("").to_string();
            if !name.is_empty() {
                self.register_class_hints.insert(new_ptr, name);
            }
        }

        Some(new_ptr)
    }

    /// Build a type-based default value: 0 for Int, 0.0 for Float, false for Bool, "" for String,
    /// recursive default or no-arg constructor for classes, null otherwise.
    fn build_type_default(&mut self, field_type_id: TypeId) -> Option<IrId> {
        let type_kind = {
            let type_table = self.type_table.borrow();
            type_table.get(field_type_id).map(|t| t.kind.clone())
        };

        match type_kind.as_ref() {
            Some(TypeKind::Int) => self.builder.build_const(IrValue::I32(0)),
            Some(TypeKind::Float) => self.builder.build_const(IrValue::F64(0.0)),
            Some(TypeKind::Bool) => self.builder.build_const(IrValue::Bool(false)),
            Some(TypeKind::String) => self.builder.build_string(String::new()),
            _ => {
                // Try recursive default or no-arg constructor, else null
                Some(
                    self.try_default_for_class_field(field_type_id)
                        .unwrap_or_else(|| self.builder.build_null().unwrap()),
                )
            }
        }
    }

    /// Try to produce a default value for a class-typed field:
    /// 1. If the field's class has @:derive(Default), recursively default-initialize it
    /// 2. Else if the field's class has a no-arg constructor, call it
    /// 3. Else return None (caller should use null)
    fn try_default_for_class_field(&mut self, field_type_id: TypeId) -> Option<IrId> {
        // Resolve field type to class symbol
        let (class_symbol, class_name) = {
            let type_table = self.type_table.borrow();
            match type_table.get(field_type_id).map(|t| &t.kind) {
                Some(TypeKind::Class { symbol_id, .. }) => {
                    let name = self
                        .symbol_table
                        .get_symbol(*symbol_id)
                        .and_then(|s| self.string_interner.get(s.name))
                        .map(|s| s.to_string());
                    Some((*symbol_id, name))
                }
                _ => None,
            }
        }?;

        // Option 1: field's class has @:derive(Default) — recursive
        if self.derive_default_classes.contains(&class_symbol) {
            return self.lower_derived_default(class_symbol);
        }

        // Option 2: field's class has a no-arg constructor
        let class_name_str = class_name?;
        let ctor_id = self.constructor_name_map.get(&class_name_str).copied()?;

        // Check that constructor has no required params (only `this`)
        let sig_params = self
            .builder
            .module
            .functions
            .get(&ctor_id)
            .map(|f| f.signature.parameters.len())
            .unwrap_or(0);

        // All params must have defaults, or there's only the `this` param
        let all_optional = if sig_params <= 1 {
            true // only `this` or no params
        } else if let Some(defaults) = self.function_param_defaults.get(&ctor_id) {
            // defaults[0] is `this` (always None), check params 1..
            defaults.iter().skip(1).all(|d| d.is_some())
        } else {
            sig_params <= 1
        };

        if !all_optional {
            return None;
        }

        // Allocate and call constructor
        let alloc_size = self
            .class_alloc_sizes_by_name
            .get(&class_name_str)
            .copied()
            .unwrap_or(16);
        let obj_ptr = self.build_heap_alloc(alloc_size)?;

        // Store type_id header
        let type_id_const = self
            .builder
            .build_const(IrValue::I64(class_symbol.as_raw() as i64))?;
        let zero = self.builder.build_const(IrValue::I32(0))?;
        let header_ptr = self.builder.build_gep(obj_ptr, vec![zero], IrType::I64)?;
        self.builder.build_store(header_ptr, type_id_const);

        // Call constructor with just `this`
        let mut args = vec![obj_ptr];
        self.fill_default_args(ctor_id, &mut args, true);
        self.builder.build_call_direct(ctor_id, args, IrType::Void);

        // Set class hint
        self.register_class_hints.insert(obj_ptr, class_name_str);

        Some(obj_ptr)
    }

    fn lower_null_coalesce(&mut self, lhs: &HirExpr, rhs: &HirExpr) -> Option<IrId> {
        // Null coalescing: lhs ?? rhs
        // If lhs is non-null, return lhs; otherwise evaluate and return rhs
        //
        // Uses intermediary blocks (like ternary) to avoid Cranelift phi issues
        // when br_if targets a merge block directly.
        let lhs_pass = self.builder.create_block()?;
        let eval_rhs = self.builder.create_block()?;
        let merge = self.builder.create_block()?;

        // Check if LHS is Optional{primitive} — needs unbox in pass-through
        let opt_prim = self.is_optional_primitive(lhs.ty);

        // Evaluate LHS
        let lhs_val = self.lower_expression(lhs)?;

        // Null check: lhs != 0 (null pointers and null values are 0)
        // Use same type as LHS to avoid type mismatch in comparison
        let lhs_ir_type = self.builder.get_register_type(lhs_val);
        let zero = match lhs_ir_type {
            Some(IrType::I32) => self.builder.build_const(IrValue::I32(0))?,
            Some(IrType::F32) => self.builder.build_const(IrValue::F32(0.0))?,
            Some(IrType::F64) => self.builder.build_const(IrValue::F64(0.0))?,
            _ => self.builder.build_const(IrValue::I64(0))?,
        };
        let is_not_null = self.builder.build_cmp(CompareOp::Ne, lhs_val, zero)?;

        // If not null -> lhs_pass block, else -> evaluate rhs
        self.builder
            .build_cond_branch(is_not_null, lhs_pass, eval_rhs)?;

        // LHS pass-through block — unbox if Optional{primitive}
        self.builder.switch_to_block(lhs_pass);
        let lhs_final = if opt_prim {
            // Unbox the boxed primitive: Ptr(U8) → inner type
            let inner_type = {
                let type_table = self.type_table.borrow();
                match type_table.get(lhs.ty).map(|t| &t.kind) {
                    Some(crate::tast::TypeKind::Optional { inner_type }) => Some(*inner_type),
                    _ => None,
                }
            };
            if let Some(inner_ty) = inner_type {
                let inner_ir = self.convert_type(inner_ty);
                let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
                match &inner_ir {
                    IrType::I32 => {
                        let unbox_func = self.get_or_register_extern_function(
                            "haxe_unbox_int_ptr",
                            vec![ptr_u8],
                            IrType::I64,
                        );
                        let unboxed = self.builder.build_call_direct(
                            unbox_func,
                            vec![lhs_val],
                            IrType::I64,
                        )?;
                        self.builder.build_cast(unboxed, IrType::I64, IrType::I32)?
                    }
                    IrType::F64 => {
                        let unbox_func = self.get_or_register_extern_function(
                            "haxe_unbox_float_ptr",
                            vec![ptr_u8],
                            IrType::F64,
                        );
                        self.builder
                            .build_call_direct(unbox_func, vec![lhs_val], IrType::F64)?
                    }
                    IrType::Bool => {
                        let unbox_func = self.get_or_register_extern_function(
                            "haxe_unbox_bool_ptr",
                            vec![ptr_u8],
                            IrType::I64,
                        );
                        let unboxed = self.builder.build_call_direct(
                            unbox_func,
                            vec![lhs_val],
                            IrType::I64,
                        )?;
                        self.builder
                            .build_cast(unboxed, IrType::I64, IrType::Bool)?
                    }
                    _ => lhs_val,
                }
            } else {
                lhs_val
            }
        } else {
            lhs_val
        };
        let lhs_pass_block = self.builder.current_block()?;
        self.builder.build_branch(merge)?;

        // Block for evaluating RHS (only when lhs is null)
        self.builder.switch_to_block(eval_rhs);
        let rhs_val = self.lower_expression(rhs)?;
        let rhs_block = self.builder.current_block()?;
        self.builder.build_branch(merge)?;

        // Merge block with phi node
        // When LHS was Optional{primitive}, result type is the unboxed primitive type (RHS type)
        self.builder.switch_to_block(merge);
        let result_type = if opt_prim {
            self.convert_type(rhs.ty)
        } else {
            self.convert_type(lhs.ty)
        };
        let result = self.builder.build_phi(merge, result_type)?;
        self.builder
            .add_phi_incoming(merge, result, lhs_pass_block, lhs_final)?;
        self.builder
            .add_phi_incoming(merge, result, rhs_block, rhs_val)?;

        Some(result)
    }

    fn lower_conditional(
        &mut self,
        cond: &HirExpr,
        then_expr: &HirExpr,
        else_expr: &HirExpr,
    ) -> Option<IrId> {
        self.lower_conditional_typed(cond, then_expr, else_expr, None)
    }

    fn lower_conditional_typed(
        &mut self,
        cond: &HirExpr,
        then_expr: &HirExpr,
        else_expr: &HirExpr,
        result_ty: Option<TypeId>,
    ) -> Option<IrId> {
        // Conditional expression: cond ? then : else
        //
        // Becomes:
        //   %cond_val = <evaluate cond>
        //   br %cond_val, then_block, else_block
        // then_block:
        //   %then_val = <evaluate then>
        //   br merge_block
        // else_block:
        //   %else_val = <evaluate else>
        //   br merge_block
        // merge_block:
        //   %result = phi [%then_val, then_block], [%else_val, else_block]
        //   (plus phi nodes for any variables modified in branches)

        let then_block = self.builder.create_block()?;
        let else_block = self.builder.create_block()?;
        let merge_block = self.builder.create_block()?;

        // Snapshot symbol_map before branches
        let symbol_map_before = self.symbol_map.clone();
        // eprintln!(
        //     "DEBUG lower_conditional: symbol_map has {} entries before condition",
        //     symbol_map_before.len()
        // );

        // Evaluate condition
        let cond_val = self.lower_expression(cond)?;
        // eprintln!(
        //     "DEBUG lower_conditional: After evaluating condition, in block {:?}",
        //     self.builder.current_block()
        // );

        // Branch based on condition
        self.builder
            .build_cond_branch(cond_val, then_block, else_block)?;

        // Then block
        self.builder.switch_to_block(then_block);
        let mut then_val = self.lower_expression(then_expr);
        let then_terminated = self.is_terminated();
        // Box primitive values for Optional<primitive> result types
        if !then_terminated {
            if let (Some(val), Some(rty)) = (then_val, result_ty) {
                if let Some(boxed) = self.maybe_box_for_optional(val, then_expr.ty, rty) {
                    then_val = Some(boxed);
                }
            }
            // NOTE: branch building deferred until after type harmonization
        }
        let then_end_block = self.builder.current_block()?;
        let symbol_map_after_then = self.symbol_map.clone();

        // Else block
        self.symbol_map = symbol_map_before.clone(); // Reset to before-branch state
        self.builder.switch_to_block(else_block);
        let mut else_val = self.lower_expression(else_expr);
        let else_terminated = self.is_terminated();
        // Box primitive values for Optional<primitive> result types
        if !else_terminated {
            if let (Some(val), Some(rty)) = (else_val, result_ty) {
                if let Some(boxed) = self.maybe_box_for_optional(val, else_expr.ty, rty) {
                    else_val = Some(boxed);
                }
            }
            // NOTE: branch building deferred until after type harmonization
        }
        let else_end_block = self.builder.current_block()?;
        let symbol_map_after_else = self.symbol_map.clone();

        // Type harmonization: if one branch produces Ptr (e.g. null) and other produces
        // a primitive (e.g. i64 from field access), box the primitive to make the phi valid.
        // This handles Null<T> return types where if(x==null) null else x.field merges
        // incompatible types.
        if let (Some(tv), Some(ev)) = (then_val, else_val) {
            if !then_terminated && !else_terminated {
                let then_rty = self.builder.get_register_type(tv);
                let else_rty = self.builder.get_register_type(ev);
                let then_is_ptr = matches!(then_rty, Some(IrType::Ptr(_)));
                let else_is_ptr = matches!(else_rty, Some(IrType::Ptr(_)));
                let then_is_prim = matches!(
                    then_rty,
                    Some(IrType::I32 | IrType::I64 | IrType::F64 | IrType::F32 | IrType::Bool)
                );
                let else_is_prim = matches!(
                    else_rty,
                    Some(IrType::I32 | IrType::I64 | IrType::F64 | IrType::F32 | IrType::Bool)
                );

                if then_is_ptr && else_is_prim {
                    // Box the else value (primitive) to match the then pointer
                    self.builder.switch_to_block(else_end_block);
                    let boxed = self.box_primitive_to_dynamic(ev, else_rty.unwrap());
                    if let Some(b) = boxed {
                        else_val = Some(b);
                    }
                } else if else_is_ptr && then_is_prim {
                    // Box the then value (primitive) to match the else pointer
                    self.builder.switch_to_block(then_end_block);
                    let boxed = self.box_primitive_to_dynamic(tv, then_rty.unwrap());
                    if let Some(b) = boxed {
                        then_val = Some(b);
                    }
                }
            }
        }

        // Now build branches for non-terminated blocks
        if !then_terminated {
            self.builder.switch_to_block(then_end_block);
            self.builder.build_branch(merge_block)?;
        }
        if !else_terminated {
            self.builder.switch_to_block(else_end_block);
            self.builder.build_branch(merge_block)?;
        }
        // eprintln!(
        //     "DEBUG lower_conditional: else_end_block = {:?}, symbol_map has {} entries",
        //     else_end_block,
        //     symbol_map_after_else.len()
        // );

        // If both branches terminated, no merge block needed
        if then_terminated && else_terminated {
            // Both branches returned/broke/continued
            // No value to return, and we shouldn't create unreachable merge block
            return None;
        }

        // Merge block with phi nodes
        self.builder.switch_to_block(merge_block);

        // Find variables that were modified in either branch
        let mut modified_symbols = std::collections::HashSet::new();
        // debug!("Checking for modified symbols");
        // eprintln!("  symbol_map_before: {} entries", symbol_map_before.len());
        // eprintln!(
        //     "  symbol_map_after_then: {} entries",
        //     symbol_map_after_then.len()
        // );
        // eprintln!(
        //     "  symbol_map_after_else: {} entries",
        //     symbol_map_after_else.len()
        // );

        for (sym, reg_after_then) in &symbol_map_after_then {
            if symbol_map_before.get(sym) != Some(reg_after_then) {
                // eprintln!(
                //     "  Modified in then branch: {:?} (before: {:?}, after: {:?})",
                //     sym,
                //     symbol_map_before.get(sym),
                //     reg_after_then
                // );
                modified_symbols.insert(*sym);
            }
        }
        for (sym, reg_after_else) in &symbol_map_after_else {
            if symbol_map_before.get(sym) != Some(reg_after_else) {
                // eprintln!(
                //     "  Modified in else branch: {:?} (before: {:?}, after: {:?})",
                //     sym,
                //     symbol_map_before.get(sym),
                //     reg_after_else
                // );
                modified_symbols.insert(*sym);
            }
        }
        // debug!("Found {} modified symbols", modified_symbols.len());

        // Create phi nodes for modified variables
        // eprintln!(
        //     "DEBUG: Creating phi nodes for {} symbols",
        //     modified_symbols.len()
        // );
        for symbol_id in &modified_symbols {
            // eprintln!("  Processing symbol {:?}", symbol_id);
            let before_reg = symbol_map_before.get(symbol_id).copied();
            let then_reg = symbol_map_after_then.get(symbol_id).copied();
            let else_reg = symbol_map_after_else.get(symbol_id).copied();

            // Get type from locals table using the "before" register (from variable declaration)
            // because new registers from assignments don't have local entries
            let type_lookup_reg = before_reg.or(then_reg).or(else_reg);
            let var_type = match type_lookup_reg.and_then(|r| {
                self.builder
                    .current_function()
                    .and_then(|f| f.locals.get(&r))
                    .map(|local| local.ty.clone())
            }) {
                Some(t) => {
                    // eprintln!("  Found type {:?} for symbol {:?}", t, symbol_id);
                    t
                }
                None => {
                    // eprintln!(
                    //     "  No type found for symbol {:?} (tried {:?}), skipping",
                    //     symbol_id, type_lookup_reg
                    // );
                    continue;
                }
            };

            // Only create phi nodes for variables that have values from all non-terminated branches
            // This prevents creating invalid phi nodes for branch-local variables
            let has_then_value = !then_terminated && (then_reg.is_some() || before_reg.is_some());
            let has_else_value = !else_terminated && (else_reg.is_some() || before_reg.is_some());

            // Skip if we can't provide values from all active branches
            if (!then_terminated && !has_then_value) || (!else_terminated && !has_else_value) {
                // eprintln!("  Skipping phi for {:?} - not in all branches", symbol_id);
                continue;
            }

            let sample_reg = then_reg.or(else_reg).or(before_reg).unwrap();

            // Create phi node
            // eprintln!(
            //     "  Creating phi for {:?} with type {:?}",
            //     symbol_id, var_type
            // );
            let phi_reg = match self.builder.build_phi(merge_block, var_type.clone()) {
                Some(r) => r,
                None => {
                    // eprintln!("  Failed to create phi node");
                    continue;
                }
            };
            // eprintln!("  Created phi node {:?}", phi_reg);

            // Add incoming edges for non-terminated branches
            // IMPORTANT: Only add phi incoming if the variable exists in that branch
            // Don't use variables from other branches (causes domination errors)
            // eprintln!(
            //     "  Adding phi incoming: then_terminated={}, else_terminated={}",
            //     then_terminated, else_terminated
            // );
            if !then_terminated {
                // Use then_reg if it exists, otherwise before_reg
                // Do NOT use else_reg here - it would violate SSA dominance
                if let Some(val) = then_reg.or(before_reg) {
                    // eprintln!(
                    //     "  Calling add_phi_incoming(merge={:?}, phi={:?}, from={:?}, val={:?})",
                    //     merge_block, phi_reg, then_end_block, val
                    // );
                    self.builder
                        .add_phi_incoming(merge_block, phi_reg, then_end_block, val);
                    // {
                    //     Some(()) => eprintln!("  Successfully added phi incoming from then"),
                    //     None => eprintln!(
                    //         "  WARNING: Failed to add phi incoming from then block {:?}",
                    //         then_end_block
                    //     ),
                    // }
                }
            }
            if !else_terminated {
                // Use else_reg if it exists, otherwise before_reg
                // Do NOT use then_reg here - it would violate SSA dominance
                if let Some(val) = else_reg.or(before_reg) {
                    // eprintln!(
                    //     "  Calling add_phi_incoming(merge={:?}, phi={:?}, from={:?}, val={:?})",
                    //     merge_block, phi_reg, else_end_block, val
                    // );
                    self.builder
                        .add_phi_incoming(merge_block, phi_reg, else_end_block, val);
                    // {
                    //     Some(()) => eprintln!("  Successfully added phi incoming from else"),
                    //     None => eprintln!(
                    //         "  WARNING: Failed to add phi incoming from else block {:?}",
                    //         else_end_block
                    //     ),
                    // }
                }
            }

            // Register phi as local
            if let Some(func) = self.builder.current_function_mut() {
                if let Some(local) = func.locals.get(&sample_reg).cloned() {
                    func.locals.insert(
                        phi_reg,
                        super::IrLocal {
                            name: format!("{}_phi", local.name),
                            ty: var_type.clone(),
                            mutable: true,
                            source_location: local.source_location,
                            allocation: super::AllocationHint::Register,
                        },
                    );
                }
            }

            // Update symbol map to use phi
            self.symbol_map.insert(*symbol_id, phi_reg);
        }

        // Create phi for expression result if both branches returned values
        let mut result_phi = None;
        // eprintln!(
        //     "DEBUG: Checking if need result phi: then_val={:?}, else_val={:?}",
        //     then_val.is_some(),
        //     else_val.is_some()
        // );
        // Only create result phi if BOTH branches return values (for expression-style ifs)
        // If only one returns a value, that's a type error - skip result phi
        if then_val.is_some() && else_val.is_some() {
            // Determine result type from the ACTUAL register types after harmonization,
            // not the original HIR type (which may be pre-boxing, e.g. I32 before the
            // type harmonization boxed it to Ptr(U8) to match a null branch).
            let result_type = if let Some(tv) = then_val {
                self.builder
                    .get_register_type(tv)
                    .unwrap_or_else(|| self.convert_type(then_expr.ty))
            } else {
                self.convert_type(then_expr.ty)
            };
            let result = match self.builder.build_phi(merge_block, result_type.clone()) {
                Some(r) => {
                    // debug!("Created result phi {:?}", r);
                    r
                }
                None => {
                    // debug!("Failed to create result phi");
                    return None;
                }
            };

            // eprintln!(
            //     "DEBUG: Adding result phi incoming: then_term={}, else_term={}",
            //     then_terminated, else_terminated
            // );
            // Both branches returned values, so add phi incoming from both
            if !then_terminated {
                let val = then_val.unwrap(); // Safe because we checked is_some() above
                                             // eprintln!(
                                             //     "DEBUG:   Adding from then: block={:?}, val={:?}",
                                             //     then_end_block, val
                                             // );
                self.builder
                    .add_phi_incoming(merge_block, result, then_end_block, val);
                // {
                //     Some(()) => debug!("  Success"),
                //     None => debug!("  FAILED!"),
                // }
            }
            if !else_terminated {
                let val = else_val.unwrap(); // Safe because we checked is_some() above
                                             // eprintln!(
                                             //     "DEBUG:   Adding from else: block={:?}, val={:?}",
                                             //     else_end_block, val
                                             // );
                self.builder
                    .add_phi_incoming(merge_block, result, else_end_block, val);
            }
            result_phi = Some(result);
        }

        result_phi
    }

    fn lower_do_while_loop(
        &mut self,
        body: &HirBlock,
        condition: &HirExpr,
        label: Option<&SymbolId>,
    ) {
        // Do-while loop structure:
        // do {
        //     body;
        // } while (condition);
        //
        // MIR structure with phi nodes:
        // entry_block:
        //     goto body_block(initial_values)
        // body_block(phi_nodes):
        //     <body statements>
        //     goto cond_block
        // cond_block:
        //     %cond = <evaluate condition>
        //     br %cond, body_block(updated_values), exit_block(final_values)
        // exit_block(exit_phi_nodes):
        //     <continue>

        // Create blocks
        let Some(body_block) = self.builder.create_block() else {
            return;
        };
        let Some(cond_block) = self.builder.create_block() else {
            return;
        };
        let Some(exit_block) = self.builder.create_block() else {
            return;
        };

        // Save the entry block (current block before loop)
        let entry_block = if let Some(block_id) = self.builder.current_block() {
            block_id
        } else {
            return;
        };

        // Find all variables that are referenced in the loop body and condition
        let mut referenced_vars = std::collections::HashSet::new();
        self.collect_referenced_variables_in_block(body, &mut referenced_vars);
        self.collect_referenced_variables_in_expr(condition, &mut referenced_vars);

        // Only include variables that were declared before the loop
        // (i.e., they're already in the symbol_map)
        // Exclude function parameters since they're immutable
        let modified_vars: std::collections::HashSet<SymbolId> = referenced_vars
            .into_iter()
            .filter(|sym| {
                let in_map = self.symbol_map.contains_key(sym);
                // Check if this is a function parameter by seeing if it's in the current function's parameters
                let is_param = if let Some(func) = self.builder.current_function() {
                    func.signature
                        .parameters
                        .iter()
                        .any(|p| self.symbol_map.get(sym) == Some(&p.reg))
                } else {
                    false
                };
                in_map && !is_param
            })
            .collect();

        // Save initial values of loop variables before jumping to body
        let mut loop_var_initial_values: BTreeMap<SymbolId, (IrId, IrType)> = BTreeMap::new();
        for symbol_id in &modified_vars {
            if let Some(&reg) = self.symbol_map.get(symbol_id) {
                // Get the type from the locals table
                if let Some(func) = self.builder.current_function() {
                    if let Some(local) = func.locals.get(&reg) {
                        loop_var_initial_values.insert(*symbol_id, (reg, local.ty.clone()));
                    }
                }
            }
        }

        // Jump to body first (do-while always executes once)
        self.builder.build_branch(body_block);

        // Body block - create phi nodes for loop variables
        self.builder.switch_to_block(body_block);

        // Create phi nodes for all loop variables at the start of body block
        let mut phi_nodes: BTreeMap<SymbolId, IrId> = BTreeMap::new();
        for (symbol_id, (initial_reg, var_type)) in &loop_var_initial_values {
            if let Some(phi_reg) = self.builder.build_phi(body_block, var_type.clone()) {
                // Add incoming value from entry block (first iteration)
                self.builder
                    .add_phi_incoming(body_block, phi_reg, entry_block, *initial_reg);

                // Register the phi node as a local so Cranelift can find its type
                if let Some(func) = self.builder.current_function_mut() {
                    if let Some(local) = func.locals.get(initial_reg).cloned() {
                        func.locals.insert(
                            phi_reg,
                            super::IrLocal {
                                name: format!("{}_phi", local.name),
                                ty: var_type.clone(),
                                mutable: true,
                                source_location: local.source_location,
                                allocation: super::AllocationHint::Register,
                            },
                        );
                    }
                }

                // Update symbol map to use phi node
                phi_nodes.insert(*symbol_id, phi_reg);
                self.symbol_map.insert(*symbol_id, phi_reg);

                // Also update owned_heap_values so drop tracking uses the phi result
                // This ensures that when a loop variable is reassigned, we free the
                // current iteration's value (from phi), not the initial value
                if self.owned_heap_values.contains_key(symbol_id) {
                    self.owned_heap_values.insert(*symbol_id, phi_reg);
                }
            }
        }

        // Push loop context with empty exit_phi_nodes (will be populated later)
        self.loop_stack.push(LoopContext {
            continue_block: cond_block,
            break_block: exit_block,
            label: label.cloned(),
            exit_phi_nodes: BTreeMap::new(),
            continue_phi_nodes: BTreeMap::new(),
        });

        // Lower the body statements
        self.enter_drop_scope(); // Enter scope for loop body allocations
        self.lower_block(body);

        // Get the block we're in after the body (might be different if there are nested blocks)
        let body_end_block = if let Some(block_id) = self.builder.current_block() {
            block_id
        } else {
            self.loop_stack.pop();
            return;
        };

        // Branch to condition block if not already terminated
        if !self.is_terminated() {
            self.exit_drop_scope(); // Free loop body allocations before condition check
            self.builder.build_branch(cond_block);
        }

        // Build condition block
        self.builder.switch_to_block(cond_block);
        let cond_result = self.lower_expression(condition);

        // Capture the block we're actually in AFTER condition evaluation
        // This is where the conditional branch to body/exit will happen
        let cond_end_block = self.builder.current_block().unwrap_or(cond_block);

        // Now create exit block phi nodes with the correct predecessor block
        let mut exit_phi_nodes: BTreeMap<SymbolId, IrId> = BTreeMap::new();
        for (symbol_id, _phi_reg) in &phi_nodes {
            if let Some((_, var_type)) = loop_var_initial_values.get(symbol_id) {
                // Get the current value of the variable after the loop body
                let current_value = if let Some(&updated_reg) = self.symbol_map.get(symbol_id) {
                    updated_reg
                } else {
                    continue;
                };

                // Allocate a new register for the exit block parameter
                let exit_param_reg = self.builder.alloc_reg().unwrap();

                // Create the phi node in the exit block with incoming edge from cond_end_block
                if let Some(func) = self.builder.current_function_mut() {
                    if let Some(exit_block_data) = func.cfg.get_block_mut(exit_block) {
                        let exit_phi = super::IrPhiNode {
                            dest: exit_param_reg,
                            incoming: vec![(cond_end_block, current_value)],
                            ty: var_type.clone(),
                        };
                        exit_block_data.add_phi(exit_phi);

                        // Register as a local
                        func.locals.insert(
                            exit_param_reg,
                            super::IrLocal {
                                name: format!("loop_exit_{}", symbol_id.as_raw()),
                                ty: var_type.clone(),
                                mutable: false,
                                source_location: super::IrSourceLocation::unknown(),
                                allocation: super::AllocationHint::Register,
                            },
                        );
                    }
                }

                exit_phi_nodes.insert(*symbol_id, exit_param_reg);
            }
        }

        // Update loop context with the exit phi nodes
        if let Some(loop_ctx) = self.loop_stack.last_mut() {
            loop_ctx.exit_phi_nodes = exit_phi_nodes.clone();
        }

        // Add back-edge phi incoming values from body end to body block
        // These represent the updated values for the next iteration
        for (symbol_id, phi_reg) in &phi_nodes {
            // Get the current value of the variable after the loop body
            let back_edge_value = if let Some(&updated_reg) = self.symbol_map.get(symbol_id) {
                updated_reg
            } else {
                *phi_reg
            };

            // Add incoming value from cond block (back edge for next iteration)
            // The back edge comes from cond_end_block (after condition is evaluated)
            self.builder
                .add_phi_incoming(body_block, *phi_reg, cond_end_block, back_edge_value);
        }

        // Build conditional branch from the block we're actually in
        if let Some(cond_reg) = cond_result {
            self.builder
                .build_cond_branch(cond_reg, body_block, exit_block);
        }

        // Pop loop context
        self.loop_stack.pop();

        // Continue at exit block
        self.builder.switch_to_block(exit_block);

        // Update symbol map to use exit phi nodes after the loop
        for (symbol_id, exit_reg) in &exit_phi_nodes {
            self.symbol_map.insert(*symbol_id, *exit_reg);
        }

        // CRITICAL: Also update owned_heap_values to use exit phi values.
        // Same fix as in lower_while_loop — prevents SSA dominance violations
        // and double-free crashes when outer scopes free loop-carried heap values.
        for (symbol_id, exit_reg) in &exit_phi_nodes {
            if self.owned_heap_values.contains_key(symbol_id) {
                self.owned_heap_values.insert(*symbol_id, *exit_reg);
            }
        }
    }

    fn lower_for_in_loop(
        &mut self,
        pattern: &HirPattern,
        iter_expr: &HirExpr,
        body: &HirBlock,
        label: Option<&SymbolId>,
    ) {
        debug!("[for-in]: ENTERED lower_for_in_loop!");
        debug!("[for-in]: pattern={:?}", pattern);
        debug!("[for-in]: iter_expr.ty={:?}", iter_expr.ty);

        // Check for range expressions (0...5) — desugar to counter loop
        if let HirExprKind::Binary {
            op: HirBinaryOp::Range,
            lhs,
            rhs,
        } = &iter_expr.kind
        {
            self.lower_for_in_range(pattern, lhs, rhs, body, label);
            return;
        }

        // Check the iterable expression's type to determine iteration strategy
        let iter_type_kind = {
            let type_table = self.type_table.borrow();
            type_table.get(iter_expr.ty).map(|t| t.kind.clone())
        };

        // For Map types (including IntMap/StringMap extern classes), convert keys
        // to a HaxeArray and iterate over that
        let map_kv_types: Option<(TypeId, TypeId)> = match &iter_type_kind {
            Some(crate::tast::TypeKind::Map {
                key_type,
                value_type,
            }) => Some((*key_type, *value_type)),
            Some(crate::tast::TypeKind::Class {
                symbol_id,
                type_args,
            }) => {
                let class_name = self
                    .symbol_table
                    .get_symbol(*symbol_id)
                    .and_then(|sym| self.string_interner.get(sym.name));
                let type_table = self.type_table.borrow();
                match class_name {
                    Some("IntMap") => {
                        let value_type = type_args
                            .first()
                            .copied()
                            .unwrap_or_else(|| type_table.dynamic_type());
                        Some((type_table.int_type(), value_type))
                    }
                    Some("StringMap") => {
                        let value_type = type_args
                            .first()
                            .copied()
                            .unwrap_or_else(|| type_table.dynamic_type());
                        Some((type_table.string_type(), value_type))
                    }
                    Some("ObjectMap") => {
                        // ObjectMap<K, V> has two type args
                        let key_type = type_args
                            .first()
                            .copied()
                            .unwrap_or_else(|| type_table.dynamic_type());
                        let value_type = type_args
                            .get(1)
                            .copied()
                            .unwrap_or_else(|| type_table.dynamic_type());
                        Some((key_type, value_type))
                    }
                    _ => None,
                }
            }
            _ => None,
        };
        if let Some((key_type, value_type)) = map_kv_types {
            let key_type_kind = {
                let type_table = self.type_table.borrow();
                type_table.get(key_type).map(|t| t.kind.clone())
            };
            let is_int_key = matches!(
                key_type_kind,
                Some(crate::tast::TypeKind::Int) | Some(crate::tast::TypeKind::Bool)
            );
            let is_string_key = matches!(key_type_kind, Some(crate::tast::TypeKind::String));

            // Lower the map expression
            let Some(map_ptr) = self.lower_expression(iter_expr) else {
                return;
            };

            // Call keys_to_array to get a HaxeArray of keys
            let ptr_void = IrType::Ptr(Box::new(IrType::Void));
            let keys_fn_name = if is_int_key {
                "haxe_intmap_keys_to_array"
            } else if is_string_key {
                "haxe_stringmap_keys_to_array"
            } else {
                "haxe_objectmap_keys_to_array"
            };
            let keys_fn = self.get_or_register_extern_function(
                keys_fn_name,
                vec![ptr_void.clone()],
                ptr_void.clone(),
            );
            let Some(keys_array) = self
                .builder
                .build_call_direct(keys_fn, vec![map_ptr], ptr_void)
            else {
                return;
            };

            // Check if this is key=>value iteration (Tuple pattern)
            if let HirPattern::Tuple(sub_patterns) = pattern {
                if sub_patterns.len() == 2 {
                    self.lower_for_in_map_kv(
                        &sub_patterns[0],
                        &sub_patterns[1],
                        map_ptr,
                        keys_array,
                        key_type,
                        value_type,
                        is_int_key,
                        is_string_key,
                        body,
                        label,
                    );
                    return;
                }
            }

            // Key-only iteration: iterate over the keys array
            self.lower_for_in_over_array(pattern, keys_array, key_type, body, label);
            return;
        }

        // For class/interface types with hasNext()/next() iterator protocol,
        // desugar to a while loop calling those methods directly.
        // Dynamic is included because arr.iterator() returns Dynamic-typed iterators
        // that have hasNext/next via stdlib mappings.
        if let Some(ref kind) = iter_type_kind {
            let is_iterator_class = matches!(
                kind,
                crate::tast::TypeKind::Class { .. }
                    | crate::tast::TypeKind::Interface { .. }
                    | crate::tast::TypeKind::TypeAlias { .. }
                    | crate::tast::TypeKind::Placeholder { .. }
                    | crate::tast::TypeKind::Dynamic
            );
            if is_iterator_class {
                self.lower_for_in_iterator_protocol(pattern, iter_expr, body, label);
                return;
            }
        }

        // For-in loops over Arrays desugar to index-based iteration:
        // for (x in arr) { body }
        //
        // Becomes:
        // {
        //     var _i = 0;
        //     var _len = haxe_array_length(arr);
        //     while (_i < _len) {
        //         var x = arr[_i];  // Using lower_index_access
        //         body;
        //         _i++;
        //     }
        // }

        // Step 1: Lower the collection expression (the array)
        debug!("[for-in]: lowering collection expression...");
        let Some(collection) = self.lower_expression(iter_expr) else {
            debug!("[for-in]: FAILED to lower collection expression!");
            return;
        };

        // DEBUG: Log collection info
        let collection_type = self.builder.get_register_type(collection);
        debug!(
            "[for-in]: collection reg={:?}, type={:?}",
            collection, collection_type
        );

        // Get element type from the iterator expression type
        // iter_expr.ty is the Array<T> type, we need to extract T
        let elem_type_id = self
            .get_array_element_type(iter_expr.ty)
            .unwrap_or(iter_expr.ty);
        debug!(
            "[for-in]: array_type={:?}, elem_type={:?}",
            iter_expr.ty, elem_type_id
        );

        self.lower_for_in_over_array(pattern, collection, elem_type_id, body, label);
    }

    /// Lower a range-based for-in loop: `for (i in start...end) { body }`
    /// Desugars to: `var i = start; while (i < end) { body; i++; }`
    fn lower_for_in_range(
        &mut self,
        pattern: &HirPattern,
        start_expr: &HirExpr,
        end_expr: &HirExpr,
        body: &HirBlock,
        label: Option<&SymbolId>,
    ) {
        debug!("[for-in-range]: lowering range-based for-in loop");

        // Lower start and end expressions
        let Some(start_val) = self.lower_expression(start_expr) else {
            return;
        };
        let Some(end_val) = self.lower_expression(end_expr) else {
            return;
        };
        let start_i64 = {
            let start_ty = self.builder.get_register_type(start_val);
            match start_ty {
                Some(IrType::I64) => start_val,
                Some(IrType::I32) => self
                    .builder
                    .build_cast(start_val, IrType::I32, IrType::I64)
                    .unwrap_or(start_val),
                Some(IrType::Bool) => self
                    .builder
                    .build_cast(start_val, IrType::Bool, IrType::I64)
                    .unwrap_or(start_val),
                Some(other) => self
                    .builder
                    .build_cast(start_val, other, IrType::I64)
                    .unwrap_or(start_val),
                None => start_val,
            }
        };
        let end_i64 = {
            let end_ty = self.builder.get_register_type(end_val);
            match end_ty {
                Some(IrType::I64) => end_val,
                Some(IrType::I32) => self
                    .builder
                    .build_cast(end_val, IrType::I32, IrType::I64)
                    .unwrap_or(end_val),
                Some(IrType::Bool) => self
                    .builder
                    .build_cast(end_val, IrType::Bool, IrType::I64)
                    .unwrap_or(end_val),
                Some(other) => self
                    .builder
                    .build_cast(end_val, other, IrType::I64)
                    .unwrap_or(end_val),
                None => end_val,
            }
        };

        // Save the entry block for loop-carried phi incoming edges.
        let entry_block = if let Some(block_id) = self.builder.current_block() {
            block_id
        } else {
            return;
        };

        // Collect variables referenced in the body that need loop-carried SSA values.
        let mut referenced_vars = std::collections::HashSet::new();
        self.collect_referenced_variables_in_block(body, &mut referenced_vars);

        let modified_vars: std::collections::HashSet<SymbolId> = referenced_vars
            .into_iter()
            .filter(|sym| {
                let in_map = self.symbol_map.contains_key(sym);
                let is_param = if let Some(func) = self.builder.current_function() {
                    func.signature
                        .parameters
                        .iter()
                        .any(|p| self.symbol_map.get(sym) == Some(&p.reg))
                } else {
                    false
                };
                in_map && !is_param
            })
            .collect();

        let mut loop_var_initial_values: BTreeMap<SymbolId, (IrId, IrType)> = BTreeMap::new();
        for symbol_id in &modified_vars {
            if let Some(&reg) = self.symbol_map.get(symbol_id) {
                let reg_ty = self
                    .builder
                    .current_function()
                    .and_then(|func| func.locals.get(&reg).map(|l| l.ty.clone()))
                    .or_else(|| self.builder.get_register_type(reg))
                    .unwrap_or(IrType::I64);
                loop_var_initial_values.insert(*symbol_id, (reg, reg_ty));
            }
        }

        // Allocate counter on stack, initialize to start
        let Some(counter_ptr) = self.builder.build_alloc(IrType::I64, None) else {
            return;
        };
        self.builder.build_store(counter_ptr, start_i64);

        // Create loop blocks
        let Some(loop_cond_block) = self.builder.create_block() else {
            return;
        };
        let Some(loop_body_block) = self.builder.create_block() else {
            return;
        };
        let Some(loop_exit_block) = self.builder.create_block() else {
            return;
        };

        // Jump to condition check
        self.builder.build_branch(loop_cond_block);

        // Condition block: create loop-carried phis first.
        self.builder.switch_to_block(loop_cond_block);
        let mut phi_nodes: BTreeMap<SymbolId, IrId> = BTreeMap::new();
        for (symbol_id, (initial_reg, var_type)) in &loop_var_initial_values {
            if let Some(phi_reg) = self.builder.build_phi(loop_cond_block, var_type.clone()) {
                self.builder
                    .add_phi_incoming(loop_cond_block, phi_reg, entry_block, *initial_reg);

                if let Some(func) = self.builder.current_function_mut() {
                    if let Some(local) = func.locals.get(initial_reg).cloned() {
                        func.locals.insert(
                            phi_reg,
                            super::IrLocal {
                                name: format!("{}_phi", local.name),
                                ty: var_type.clone(),
                                mutable: true,
                                source_location: local.source_location,
                                allocation: super::AllocationHint::Register,
                            },
                        );
                    }
                }

                phi_nodes.insert(*symbol_id, phi_reg);
                self.symbol_map.insert(*symbol_id, phi_reg);

                if self.owned_heap_values.contains_key(symbol_id) {
                    self.owned_heap_values.insert(*symbol_id, phi_reg);
                }
            }
        }

        // Build exit phi nodes up-front so break statements can target them.
        let mut exit_phi_nodes: BTreeMap<SymbolId, IrId> = BTreeMap::new();
        for (symbol_id, loop_phi_reg) in &phi_nodes {
            if let Some((_, var_type)) = loop_var_initial_values.get(symbol_id) {
                let exit_param_reg = self.builder.alloc_reg().unwrap();

                if let Some(func) = self.builder.current_function_mut() {
                    if let Some(exit_block_data) = func.cfg.get_block_mut(loop_exit_block) {
                        let exit_phi = super::IrPhiNode {
                            dest: exit_param_reg,
                            incoming: vec![(loop_cond_block, *loop_phi_reg)],
                            ty: var_type.clone(),
                        };
                        exit_block_data.add_phi(exit_phi);

                        func.locals.insert(
                            exit_param_reg,
                            super::IrLocal {
                                name: format!("loop_exit_{}", symbol_id.as_raw()),
                                ty: var_type.clone(),
                                mutable: false,
                                source_location: super::IrSourceLocation::unknown(),
                                allocation: super::AllocationHint::Register,
                            },
                        );
                    }
                }

                exit_phi_nodes.insert(*symbol_id, exit_param_reg);
            }
        }

        // Push loop context for break/continue
        self.loop_stack.push(LoopContext {
            continue_block: loop_cond_block,
            break_block: loop_exit_block,
            label: label.cloned(),
            exit_phi_nodes: exit_phi_nodes.clone(),
            continue_phi_nodes: BTreeMap::new(),
        });

        // Condition block: counter < end
        let Some(current_val) = self.builder.build_load(counter_ptr, IrType::I64) else {
            self.loop_stack.pop();
            return;
        };
        let Some(cmp_result) =
            self.builder
                .build_cmp(crate::ir::instructions::CompareOp::Lt, current_val, end_i64)
        else {
            self.loop_stack.pop();
            return;
        };
        self.builder
            .build_cond_branch(cmp_result, loop_body_block, loop_exit_block);

        // Body block
        self.builder.switch_to_block(loop_body_block);

        // Reload counter and bind to pattern variable
        let Some(loop_val) = self.builder.build_load(counter_ptr, IrType::I64) else {
            self.loop_stack.pop();
            return;
        };
        match pattern {
            HirPattern::Variable { symbol, .. } => {
                self.symbol_map.insert(*symbol, loop_val);
            }
            _ => {}
        }

        // Lower loop body
        self.enter_drop_scope();
        self.lower_block(body);

        // Capture the block we ended up in after lowering the body.
        let body_end_block = self.builder.current_block().unwrap_or(loop_body_block);

        // Add loop back-edge values for loop-carried variables.
        for (symbol_id, phi_reg) in &phi_nodes {
            let back_edge_value = if let Some(&updated_reg) = self.symbol_map.get(symbol_id) {
                updated_reg
            } else {
                *phi_reg
            };
            self.builder.add_phi_incoming(
                loop_cond_block,
                *phi_reg,
                body_end_block,
                back_edge_value,
            );
        }

        // Increment counter
        if !self.is_terminated() {
            self.exit_drop_scope();
            let Some(idx_to_inc) = self.builder.build_load(counter_ptr, IrType::I64) else {
                self.loop_stack.pop();
                return;
            };
            let Some(one) = self.builder.build_const(IrValue::I64(1)) else {
                self.loop_stack.pop();
                return;
            };
            let Some(next_val) =
                self.builder
                    .build_binop(crate::ir::instructions::BinaryOp::Add, idx_to_inc, one)
            else {
                self.loop_stack.pop();
                return;
            };
            self.builder.build_store(counter_ptr, next_val);
            self.builder.build_branch(loop_cond_block);
        }

        // Pop loop context
        self.loop_stack.pop();

        // Continue at exit block
        self.builder.switch_to_block(loop_exit_block);

        // Update symbols to exit phi values after the loop.
        for (symbol_id, exit_reg) in &exit_phi_nodes {
            self.symbol_map.insert(*symbol_id, *exit_reg);
            if self.owned_heap_values.contains_key(symbol_id) {
                self.owned_heap_values.insert(*symbol_id, *exit_reg);
            }
        }
    }

    /// Lower for-in iteration using the hasNext()/next() iterator protocol.
    /// Synthesizes HIR for `while (obj.hasNext()) { var x = obj.next(); body; }`
    /// and delegates to lower_while_loop which handles phi nodes for mutable variables.
    fn lower_for_in_iterator_protocol(
        &mut self,
        pattern: &HirPattern,
        iter_expr: &HirExpr,
        body: &HirBlock,
        label: Option<&SymbolId>,
    ) {
        // Lower the iterable expression and store it in a temp variable
        let Some(obj_reg) = self.lower_expression(iter_expr) else {
            return;
        };

        // Resolve the class symbol from the iterable's type
        let class_sym = {
            let type_table = self.type_table.borrow();
            let mut tid = iter_expr.ty;
            let mut result: Option<SymbolId> = None;
            let mut visited = HashSet::new();
            loop {
                if !visited.insert(tid) {
                    break;
                }
                if let Some(ty) = type_table.get(tid) {
                    match &ty.kind {
                        crate::tast::TypeKind::Class { symbol_id, .. } => {
                            result = Some(*symbol_id);
                            break;
                        }
                        crate::tast::TypeKind::TypeAlias {
                            symbol_id,
                            target_type,
                            ..
                        } => {
                            result = Some(*symbol_id);
                            tid = *target_type;
                        }
                        crate::tast::TypeKind::GenericInstance { base_type, .. } => {
                            tid = *base_type;
                        }
                        crate::tast::TypeKind::Placeholder { .. } => break,
                        _ => break,
                    }
                } else {
                    break;
                }
            }
            result
        };

        // For Dynamic-typed iterators (e.g., from arr.iterator()), class_sym is None.
        // Use register class hints to find the iterator class and resolve via stdlib mappings.
        if class_sym.is_none() {
            if let Some(class_hint) = self.register_class_hints.get(&obj_reg).cloned() {
                let hn_mapping = self.stdlib_mapping.find_by_name(&class_hint, "hasNext");
                let n_mapping = self.stdlib_mapping.find_by_name(&class_hint, "next");
                if let (Some((_hn_sig, hn_rt)), Some((_n_sig, n_rt))) = (hn_mapping, n_mapping) {
                    let hn_name = hn_rt.runtime_name.to_string();
                    let n_name = n_rt.runtime_name.to_string();
                    let hn_is_mir = hn_rt.is_mir_wrapper;
                    let n_is_mir = n_rt.is_mir_wrapper;
                    let ptr_void = IrType::Ptr(Box::new(IrType::Void));

                    let has_next_fn = if hn_is_mir {
                        self.register_stdlib_mir_forward_ref(
                            &hn_name,
                            vec![ptr_void.clone()],
                            IrType::I32,
                        )
                    } else {
                        self.get_or_register_extern_function(
                            &hn_name,
                            vec![ptr_void.clone()],
                            IrType::I32,
                        )
                    };
                    let next_fn = if n_is_mir {
                        self.register_stdlib_mir_forward_ref(
                            &n_name,
                            vec![ptr_void.clone()],
                            IrType::I64,
                        )
                    } else {
                        self.get_or_register_extern_function(
                            &n_name,
                            vec![ptr_void.clone()],
                            IrType::I64,
                        )
                    };

                    self.emit_iterator_while_loop(
                        pattern,
                        obj_reg,
                        has_next_fn,
                        next_fn,
                        body,
                        label,
                    );
                    return;
                }
            }
            return;
        }
        let class_sym = class_sym.unwrap();

        // Look up hasNext and next methods on the class
        let has_next_name = self.string_interner.intern("hasNext");
        let next_name = self.string_interner.intern("next");

        let has_next_sym = self
            .class_method_symbols
            .get(&(class_sym, has_next_name))
            .copied();
        let next_sym = self
            .class_method_symbols
            .get(&(class_sym, next_name))
            .copied();

        // If the class doesn't have hasNext/next directly, try several fallback paths:
        // 1. Check stdlib runtime mappings (for runtime-backed iterators like ArrayIterator)
        // 2. Check for iterator() method on the class (Haxe iterator protocol)
        // 3. Check for keyValueIterator() method on the class
        let (obj_reg, has_next_fn, next_fn) = if let (Some(hn_sym), Some(n_sym)) =
            (has_next_sym, next_sym)
        {
            match (self.get_function_id(&hn_sym), self.get_function_id(&n_sym)) {
                (Some(hn), Some(n)) => (obj_reg, hn, n),
                _ => return,
            }
        } else {
            // Fallback 1: Check stdlib runtime mappings by class name
            // This handles runtime-backed iterator classes (ArrayIterator, ArrayKeyValueIterator)
            // that don't have compiled hasNext/next in class_method_symbols.
            let class_name_str = self
                .symbol_table
                .get_symbol(class_sym)
                .and_then(|sym| self.string_interner.get(sym.name))
                .map(|s| s.to_string());

            // Extract runtime names first to avoid borrow conflict with get_or_register_extern_function
            let stdlib_names = class_name_str.as_ref().and_then(|class_name| {
                let hn_mapping = self.stdlib_mapping.find_by_name(class_name, "hasNext");
                let n_mapping = self.stdlib_mapping.find_by_name(class_name, "next");
                if let (Some((_hn_sig, hn_rt)), Some((_n_sig, n_rt))) = (hn_mapping, n_mapping) {
                    Some((
                        hn_rt.runtime_name.to_string(),
                        n_rt.runtime_name.to_string(),
                    ))
                } else {
                    None
                }
            });
            let stdlib_result = stdlib_names.map(|(hn_name, n_name)| {
                let ptr_void = IrType::Ptr(Box::new(IrType::Void));
                let hn_fn = self.get_or_register_extern_function(
                    &hn_name,
                    vec![ptr_void.clone()],
                    IrType::I32,
                );
                let n_fn = self.get_or_register_extern_function(
                    &n_name,
                    vec![ptr_void.clone()],
                    IrType::I64,
                );
                (obj_reg, hn_fn, n_fn)
            });

            if let Some(result) = stdlib_result {
                result
            } else {
                // Fallback 2: Look for iterator() method on the class via class_method_symbols
                let iterator_name = self.string_interner.intern("iterator");
                let kv_iterator_name = self.string_interner.intern("keyValueIterator");
                let iterator_sym = self
                    .class_method_symbols
                    .get(&(class_sym, iterator_name))
                    .copied();

                // Also check for iterator/keyValueIterator via stdlib mapping (e.g., Array.iterator)
                // Extract names first to avoid borrow conflicts
                let stdlib_iter_names = if iterator_sym.is_none() {
                    class_name_str.as_ref().and_then(|class_name| {
                        let iter_mapping = self
                            .stdlib_mapping
                            .find_by_name(class_name, "iterator")
                            .or_else(|| {
                                self.stdlib_mapping
                                    .find_by_name(class_name, "keyValueIterator")
                            });
                        if let Some((_sig, rt)) = iter_mapping {
                            let iter_rt_name = rt.runtime_name.to_string();
                            let is_kv = iter_rt_name.contains("kv_iterator");
                            let iter_class_name = if is_kv {
                                "ArrayKeyValueIterator"
                            } else {
                                "ArrayIterator"
                            };
                            let hn_mapping =
                                self.stdlib_mapping.find_by_name(iter_class_name, "hasNext");
                            let n_mapping =
                                self.stdlib_mapping.find_by_name(iter_class_name, "next");
                            if let (Some((_hn_sig, hn_rt)), Some((_n_sig, n_rt))) =
                                (hn_mapping, n_mapping)
                            {
                                Some((
                                    iter_rt_name,
                                    hn_rt.runtime_name.to_string(),
                                    n_rt.runtime_name.to_string(),
                                ))
                            } else {
                                None
                            }
                        } else {
                            None
                        }
                    })
                } else {
                    None
                };
                let stdlib_iter_result =
                    stdlib_iter_names.and_then(|(iter_name, hn_name, n_name)| {
                        let ptr_void = IrType::Ptr(Box::new(IrType::Void));
                        let iter_fn = self.get_or_register_extern_function(
                            &iter_name,
                            vec![ptr_void.clone()],
                            ptr_void.clone(),
                        );
                        let iter_obj = self.builder.build_call_direct(
                            iter_fn,
                            vec![obj_reg],
                            ptr_void.clone(),
                        )?;
                        let hn_fn = self.get_or_register_extern_function(
                            &hn_name,
                            vec![ptr_void.clone()],
                            IrType::I32,
                        );
                        let n_fn = self.get_or_register_extern_function(
                            &n_name,
                            vec![ptr_void],
                            IrType::I64,
                        );
                        Some((iter_obj, hn_fn, n_fn))
                    });

                if let Some(result) = stdlib_iter_result {
                    result
                } else if let Some(iter_sym) = iterator_sym {
                    // Compiled iterator() method path (existing logic)
                    let Some(iter_fn) = self.get_function_id(&iter_sym) else {
                        return;
                    };

                    // Call iterator() to get the iterator object
                    let ptr_void = IrType::Ptr(Box::new(IrType::Void));
                    let Some(iter_obj) =
                        self.builder
                            .build_call_direct(iter_fn, vec![obj_reg], ptr_void)
                    else {
                        return;
                    };

                    // Find the iterator class from the return type
                    let iter_class_sym = {
                        let sym = self.symbol_table.get_symbol(iter_sym);
                        sym.and_then(|s| {
                            let tt = self.type_table.borrow();
                            let ret_ty = tt.get(s.type_id)?;
                            if let crate::tast::TypeKind::Function { return_type, .. } =
                                &ret_ty.kind
                            {
                                let ret = tt.get(*return_type)?;
                                if let crate::tast::TypeKind::Class { symbol_id, .. } = &ret.kind {
                                    return Some(*symbol_id);
                                }
                            }
                            None
                        })
                    };

                    // Fallback: search class_method_symbols for any class with hasNext+next
                    let iter_class_sym = iter_class_sym.or_else(|| {
                        for ((cls, method_name), _) in self.class_method_symbols.iter() {
                            if *method_name == has_next_name && *cls != class_sym {
                                if self.class_method_symbols.contains_key(&(*cls, next_name)) {
                                    return Some(*cls);
                                }
                            }
                        }
                        None
                    });

                    let Some(iter_cls) = iter_class_sym else {
                        return;
                    };
                    let hn_sym = self
                        .class_method_symbols
                        .get(&(iter_cls, has_next_name))
                        .copied();
                    let n_sym = self
                        .class_method_symbols
                        .get(&(iter_cls, next_name))
                        .copied();
                    match (hn_sym, n_sym) {
                        (Some(hn), Some(n)) => {
                            match (self.get_function_id(&hn), self.get_function_id(&n)) {
                                (Some(hn_fn), Some(n_fn)) => (iter_obj, hn_fn, n_fn),
                                _ => return,
                            }
                        }
                        _ => return,
                    }
                } else {
                    // Fallback 3: Check for keyValueIterator() method (compiled user class)
                    let kv_iter_sym = self
                        .class_method_symbols
                        .get(&(class_sym, kv_iterator_name))
                        .copied();
                    let Some(kv_sym) = kv_iter_sym else {
                        return;
                    };
                    let Some(kv_fn) = self.get_function_id(&kv_sym) else {
                        return;
                    };

                    // Call keyValueIterator() to get the KV iterator object
                    let ptr_void = IrType::Ptr(Box::new(IrType::Void));
                    let Some(kv_obj) =
                        self.builder
                            .build_call_direct(kv_fn, vec![obj_reg], ptr_void)
                    else {
                        return;
                    };

                    // Find hasNext/next on the returned KV iterator class
                    let kv_class_sym = {
                        let sym = self.symbol_table.get_symbol(kv_sym);
                        sym.and_then(|s| {
                            let tt = self.type_table.borrow();
                            let ret_ty = tt.get(s.type_id)?;
                            if let crate::tast::TypeKind::Function { return_type, .. } =
                                &ret_ty.kind
                            {
                                let ret = tt.get(*return_type)?;
                                if let crate::tast::TypeKind::Class { symbol_id, .. } = &ret.kind {
                                    return Some(*symbol_id);
                                }
                            }
                            None
                        })
                    };

                    let kv_class_sym = kv_class_sym.or_else(|| {
                        for ((cls, method_name), _) in self.class_method_symbols.iter() {
                            if *method_name == has_next_name && *cls != class_sym {
                                if self.class_method_symbols.contains_key(&(*cls, next_name)) {
                                    return Some(*cls);
                                }
                            }
                        }
                        None
                    });

                    let Some(kv_cls) = kv_class_sym else {
                        return;
                    };
                    let hn_sym = self
                        .class_method_symbols
                        .get(&(kv_cls, has_next_name))
                        .copied();
                    let n_sym = self.class_method_symbols.get(&(kv_cls, next_name)).copied();
                    match (hn_sym, n_sym) {
                        (Some(hn), Some(n)) => {
                            match (self.get_function_id(&hn), self.get_function_id(&n)) {
                                (Some(hn_fn), Some(n_fn)) => (kv_obj, hn_fn, n_fn),
                                _ => return,
                            }
                        }
                        _ => return,
                    }
                }
            }
        };

        self.emit_iterator_while_loop(pattern, obj_reg, has_next_fn, next_fn, body, label);
    }

    /// Emit a while loop that calls hasNext/next on an iterator object.
    /// Used by lower_for_in_iterator_protocol for both typed and Dynamic iterators.
    fn emit_iterator_while_loop(
        &mut self,
        pattern: &HirPattern,
        obj_reg: IrId,
        has_next_fn: IrFunctionId,
        next_fn: IrFunctionId,
        body: &HirBlock,
        label: Option<&SymbolId>,
    ) {
        // Store obj pointer to a stack slot so it survives across blocks
        let obj_ty = self
            .builder
            .get_register_type(obj_reg)
            .unwrap_or(IrType::Ptr(Box::new(IrType::Void)));
        let Some(obj_slot) = self.builder.build_alloc(obj_ty.clone(), None) else {
            return;
        };
        self.builder.build_store(obj_slot, obj_reg);

        // Also store mutable variables from outer scope in stack slots
        // so assignments in the loop body are visible after the loop
        let modified_vars = {
            let mut modified = std::collections::HashSet::new();
            for stmt in &body.statements {
                self.find_modified_variables_in_statement(stmt, &mut modified);
            }
            modified
        };

        // Create stack slots for each modified variable
        let mut var_slots: BTreeMap<SymbolId, (IrId, IrType)> = BTreeMap::new();
        for sym in &modified_vars {
            if let Some(&current_reg) = self.symbol_map.get(sym) {
                let ty = self
                    .builder
                    .get_register_type(current_reg)
                    .unwrap_or(IrType::I64);
                if let Some(slot) = self.builder.build_alloc(ty.clone(), None) {
                    self.builder.build_store(slot, current_reg);
                    var_slots.insert(*sym, (slot, ty));
                }
            }
        }

        // Create loop blocks
        let Some(loop_cond_block) = self.builder.create_block() else {
            return;
        };
        let Some(loop_body_block) = self.builder.create_block() else {
            return;
        };
        let Some(loop_exit_block) = self.builder.create_block() else {
            return;
        };

        self.builder.build_branch(loop_cond_block);

        // Push loop context
        self.loop_stack.push(LoopContext {
            continue_block: loop_cond_block,
            break_block: loop_exit_block,
            label: label.cloned(),
            exit_phi_nodes: BTreeMap::new(),
            continue_phi_nodes: BTreeMap::new(),
        });

        // Condition block: call hasNext()
        self.builder.switch_to_block(loop_cond_block);
        let Some(obj_for_cond) = self.builder.build_load(obj_slot, obj_ty.clone()) else {
            self.loop_stack.pop();
            return;
        };
        let Some(has_next_result) =
            self.builder
                .build_call_direct(has_next_fn, vec![obj_for_cond], IrType::Bool)
        else {
            self.loop_stack.pop();
            return;
        };
        self.builder
            .build_cond_branch(has_next_result, loop_body_block, loop_exit_block);

        // Body block
        self.builder.switch_to_block(loop_body_block);

        // Load modified vars from slots at body entry
        for (sym, (slot, ty)) in &var_slots {
            if let Some(loaded) = self.builder.build_load(*slot, ty.clone()) {
                self.symbol_map.insert(*sym, loaded);
            }
        }

        // Call next() and bind the pattern
        let Some(obj_for_body) = self.builder.build_load(obj_slot, obj_ty) else {
            self.loop_stack.pop();
            return;
        };
        let Some(next_value) =
            self.builder
                .build_call_direct(next_fn, vec![obj_for_body], IrType::I64)
        else {
            self.loop_stack.pop();
            return;
        };

        match pattern {
            HirPattern::Variable { symbol, .. } => {
                self.symbol_map.insert(*symbol, next_value);
            }
            HirPattern::Tuple(sub_patterns) if sub_patterns.len() == 2 => {
                // Destructure {key, value} from next() return (anon object handle)
                // Fields are alphabetically sorted: key at index 0, value at index 1
                let ptr_void = IrType::Ptr(Box::new(IrType::Void));
                let get_field_fn = self.get_or_register_extern_function(
                    "rayzor_anon_get_field_by_index",
                    vec![ptr_void.clone(), IrType::I32],
                    IrType::I64,
                );
                // key = rayzor_anon_get_field_by_index(next_value, 0)
                if let Some(idx_0) = self.builder.build_const(crate::ir::IrValue::I32(0)) {
                    if let Some(key_val) = self.builder.build_call_direct(
                        get_field_fn,
                        vec![next_value, idx_0],
                        IrType::I64,
                    ) {
                        if let HirPattern::Variable { symbol, .. } = &sub_patterns[0] {
                            self.symbol_map.insert(*symbol, key_val);
                        }
                    }
                }
                // value = rayzor_anon_get_field_by_index(next_value, 1)
                if let Some(idx_1) = self.builder.build_const(crate::ir::IrValue::I32(1)) {
                    if let Some(value_val) = self.builder.build_call_direct(
                        get_field_fn,
                        vec![next_value, idx_1],
                        IrType::I64,
                    ) {
                        if let HirPattern::Variable { symbol, .. } = &sub_patterns[1] {
                            self.symbol_map.insert(*symbol, value_val);
                        }
                    }
                }
            }
            _ => {}
        }

        // Lower the loop body
        self.enter_drop_scope();
        self.lower_block(body);

        // Store modified vars back to slots before branching back
        if !self.is_terminated() {
            for (sym, (slot, _ty)) in &var_slots {
                if let Some(&current_reg) = self.symbol_map.get(sym) {
                    self.builder.build_store(*slot, current_reg);
                }
            }
            self.exit_drop_scope();
            self.builder.build_branch(loop_cond_block);
        } else {
            self.exit_drop_scope();
        }

        self.loop_stack.pop();

        // Exit block: load final values from slots
        self.builder.switch_to_block(loop_exit_block);
        for (sym, (slot, ty)) in &var_slots {
            if let Some(loaded) = self.builder.build_load(*slot, ty.clone()) {
                self.symbol_map.insert(*sym, loaded);
            }
        }
    }

    /// Helper: iterate over map keys and look up values for `for (key => value in map)`.
    /// Iterates the keys array, calls map.get(key) for each, and binds both key and value.
    #[allow(clippy::too_many_arguments)]
    fn lower_for_in_map_kv(
        &mut self,
        key_pattern: &HirPattern,
        value_pattern: &HirPattern,
        map_ptr: IrId,
        keys_array: IrId,
        key_type_id: TypeId,
        value_type_id: TypeId,
        is_int_key: bool,
        is_string_key: bool,
        body: &HirBlock,
        label: Option<&SymbolId>,
    ) {
        let ptr_void = IrType::Ptr(Box::new(IrType::Void));

        // Read keys array length
        let Some(offset_8) = self.builder.build_const(IrValue::I64(8)) else {
            return;
        };
        let Some(len_ptr) =
            self.builder
                .build_binop(crate::ir::instructions::BinaryOp::Add, keys_array, offset_8)
        else {
            return;
        };
        let Some(array_len) = self.builder.build_load(len_ptr, IrType::I64) else {
            return;
        };

        // Initialize index to 0
        let Some(zero) = self.builder.build_const(IrValue::I64(0)) else {
            return;
        };
        let Some(index_ptr) = self.builder.build_alloc(IrType::I64, None) else {
            return;
        };
        self.builder.build_store(index_ptr, zero);

        // Save entry block for phi node incoming edges
        let entry_block = if let Some(block_id) = self.builder.current_block() {
            block_id
        } else {
            return;
        };

        // Collect referenced variables in body for phi node creation
        // (same pattern as lower_while_loop)
        let mut referenced_vars = std::collections::HashSet::new();
        self.collect_referenced_variables_in_block(body, &mut referenced_vars);
        let modified_vars: std::collections::HashSet<SymbolId> = referenced_vars
            .into_iter()
            .filter(|sym| {
                let in_map = self.symbol_map.contains_key(sym);
                let is_param = if let Some(func) = self.builder.current_function() {
                    func.signature
                        .parameters
                        .iter()
                        .any(|p| self.symbol_map.get(sym) == Some(&p.reg))
                } else {
                    false
                };
                in_map && !is_param
            })
            .collect();

        // Save initial values of loop variables
        let mut loop_var_initial_values: BTreeMap<SymbolId, (IrId, IrType)> = BTreeMap::new();
        for symbol_id in &modified_vars {
            if let Some(&reg) = self.symbol_map.get(symbol_id) {
                let reg_ty = self
                    .builder
                    .current_function()
                    .and_then(|func| func.locals.get(&reg).map(|l| l.ty.clone()))
                    .or_else(|| self.builder.get_register_type(reg))
                    .unwrap_or(IrType::I64);
                loop_var_initial_values.insert(*symbol_id, (reg, reg_ty));
            }
        }

        // Create loop blocks
        let Some(loop_cond_block) = self.builder.create_block() else {
            return;
        };
        let Some(loop_body_block) = self.builder.create_block() else {
            return;
        };
        let Some(loop_exit_block) = self.builder.create_block() else {
            return;
        };

        self.builder.build_branch(loop_cond_block);

        // Condition block: create phi nodes for loop-carried variables
        self.builder.switch_to_block(loop_cond_block);

        let mut phi_nodes: BTreeMap<SymbolId, IrId> = BTreeMap::new();
        for (symbol_id, (initial_reg, var_type)) in &loop_var_initial_values {
            if let Some(phi_reg) = self.builder.build_phi(loop_cond_block, var_type.clone()) {
                self.builder
                    .add_phi_incoming(loop_cond_block, phi_reg, entry_block, *initial_reg);
                if let Some(func) = self.builder.current_function_mut() {
                    if let Some(local) = func.locals.get(initial_reg).cloned() {
                        func.locals.insert(
                            phi_reg,
                            super::IrLocal {
                                name: format!("{}_phi", local.name),
                                ty: var_type.clone(),
                                mutable: true,
                                source_location: local.source_location,
                                allocation: super::AllocationHint::Register,
                            },
                        );
                    }
                }
                phi_nodes.insert(*symbol_id, phi_reg);
                self.symbol_map.insert(*symbol_id, phi_reg);
            }
        }

        // Create exit phi nodes so post-loop code sees final values
        let mut exit_phi_nodes: BTreeMap<SymbolId, IrId> = BTreeMap::new();
        for (symbol_id, loop_phi_reg) in &phi_nodes {
            if let Some((_, var_type)) = loop_var_initial_values.get(symbol_id) {
                let Some(exit_param_reg) = self.builder.alloc_reg() else {
                    continue;
                };
                if let Some(func) = self.builder.current_function_mut() {
                    if let Some(exit_block_data) = func.cfg.get_block_mut(loop_exit_block) {
                        let exit_phi = super::IrPhiNode {
                            dest: exit_param_reg,
                            incoming: vec![(loop_cond_block, *loop_phi_reg)],
                            ty: var_type.clone(),
                        };
                        exit_block_data.add_phi(exit_phi);
                        func.locals.insert(
                            exit_param_reg,
                            super::IrLocal {
                                name: format!("loop_exit_{}", symbol_id.as_raw()),
                                ty: var_type.clone(),
                                mutable: false,
                                source_location: super::IrSourceLocation::unknown(),
                                allocation: super::AllocationHint::Register,
                            },
                        );
                    }
                }
                exit_phi_nodes.insert(*symbol_id, exit_param_reg);
            }
        }

        // Push loop context for break/continue
        self.loop_stack.push(LoopContext {
            continue_block: loop_cond_block,
            break_block: loop_exit_block,
            label: label.cloned(),
            exit_phi_nodes: exit_phi_nodes.clone(),
            continue_phi_nodes: BTreeMap::new(),
        });

        // Condition: index < length
        let Some(current_index) = self.builder.build_load(index_ptr, IrType::I64) else {
            self.loop_stack.pop();
            return;
        };
        let Some(cmp_result) = self.builder.build_cmp(
            crate::ir::instructions::CompareOp::Lt,
            current_index,
            array_len,
        ) else {
            self.loop_stack.pop();
            return;
        };
        self.builder
            .build_cond_branch(cmp_result, loop_body_block, loop_exit_block);

        // Body block: get key, look up value, bind both, execute body, increment
        self.builder.switch_to_block(loop_body_block);
        let Some(idx_for_access) = self.builder.build_load(index_ptr, IrType::I64) else {
            self.loop_stack.pop();
            return;
        };

        // Get key from keys array
        let Some(key_value) = self.lower_index_access(keys_array, idx_for_access, key_type_id)
        else {
            self.loop_stack.pop();
            return;
        };

        // Bind key to pattern
        if let HirPattern::Variable { symbol, .. } = key_pattern {
            self.symbol_map.insert(*symbol, key_value);
        }

        // Look up value: map.get(key)
        let get_fn_name = if is_int_key {
            "haxe_intmap_get"
        } else if is_string_key {
            "haxe_stringmap_get"
        } else {
            "haxe_objectmap_get"
        };
        let key_ir_type = if is_int_key {
            IrType::I64
        } else {
            // Both StringMap and ObjectMap keys are pointers
            IrType::Ptr(Box::new(IrType::U8))
        };
        let get_fn = self.get_or_register_extern_function(
            get_fn_name,
            vec![ptr_void.clone(), key_ir_type],
            IrType::I64,
        );
        let Some(raw_value) =
            self.builder
                .build_call_direct(get_fn, vec![map_ptr, key_value], IrType::I64)
        else {
            self.loop_stack.pop();
            return;
        };

        // Convert raw u64 to the correct value type
        let value_ir_type = self.convert_type(value_type_id);
        let map_value = match &value_ir_type {
            IrType::Ptr(_) => {
                // Pointer types: bitcast i64 to ptr
                if let Some(cast) = self.builder.build_bitcast(raw_value, value_ir_type) {
                    cast
                } else {
                    raw_value
                }
            }
            IrType::F64 => {
                // Float: bitcast i64 bits to f64
                if let Some(cast) = self.builder.build_bitcast(raw_value, IrType::F64) {
                    cast
                } else {
                    raw_value
                }
            }
            _ => {
                // Int, Bool, etc.: raw i64 is fine (truncate/cast as needed)
                raw_value
            }
        };

        // Bind value to pattern
        if let HirPattern::Variable { symbol, .. } = value_pattern {
            self.symbol_map.insert(*symbol, map_value);
        }

        // Lower the loop body
        self.enter_drop_scope();
        self.lower_block(body);

        // Add back-edge phi incoming values from body end to cond block
        let body_end_block = self.builder.current_block().unwrap_or(loop_body_block);
        for (symbol_id, phi_reg) in &phi_nodes {
            let back_edge_value = if let Some(&updated_reg) = self.symbol_map.get(symbol_id) {
                updated_reg
            } else {
                *phi_reg
            };
            self.builder.add_phi_incoming(
                loop_cond_block,
                *phi_reg,
                body_end_block,
                back_edge_value,
            );
        }

        // Increment index
        if !self.is_terminated() {
            self.exit_drop_scope();
            let Some(idx_to_inc) = self.builder.build_load(index_ptr, IrType::I64) else {
                self.loop_stack.pop();
                return;
            };
            let Some(one) = self.builder.build_const(IrValue::I64(1)) else {
                self.loop_stack.pop();
                return;
            };
            let Some(next_val) =
                self.builder
                    .build_binop(crate::ir::instructions::BinaryOp::Add, idx_to_inc, one)
            else {
                self.loop_stack.pop();
                return;
            };
            self.builder.build_store(index_ptr, next_val);
            self.builder.build_branch(loop_cond_block);
        }

        self.loop_stack.pop();
        self.builder.switch_to_block(loop_exit_block);

        // Update symbol map to use exit phi nodes for post-loop code
        for (symbol_id, exit_param_reg) in &exit_phi_nodes {
            self.symbol_map.insert(*symbol_id, *exit_param_reg);
        }
        // Update owned_heap_values to use exit phi values
        for (symbol_id, exit_param_reg) in &exit_phi_nodes {
            if self.owned_heap_values.contains_key(symbol_id) {
                self.owned_heap_values.insert(*symbol_id, *exit_param_reg);
            }
        }
    }

    /// Helper: iterate over a HaxeArray by index. Used by both Array for-in and Map for-in
    /// (where keys are first converted to a HaxeArray).
    fn lower_for_in_over_array(
        &mut self,
        pattern: &HirPattern,
        collection: IrId,
        elem_type_id: TypeId,
        body: &HirBlock,
        label: Option<&SymbolId>,
    ) {
        // Read array length from HaxeArray struct (offset 8 = len field)
        let Some(offset_8) = self.builder.build_const(IrValue::I64(8)) else {
            return;
        };
        let Some(len_ptr) =
            self.builder
                .build_binop(crate::ir::instructions::BinaryOp::Add, collection, offset_8)
        else {
            return;
        };
        let Some(array_len) = self.builder.build_load(len_ptr, IrType::I64) else {
            return;
        };

        // Initialize index to 0
        let Some(zero) = self.builder.build_const(IrValue::I64(0)) else {
            return;
        };
        let Some(index_ptr) = self.builder.build_alloc(IrType::I64, None) else {
            return;
        };
        self.builder.build_store(index_ptr, zero);

        // Save entry block for loop-carried phi incoming edges.
        let entry_block = if let Some(block_id) = self.builder.current_block() {
            block_id
        } else {
            return;
        };

        // Collect referenced variables in loop body for loop-carried SSA updates.
        let mut referenced_vars = std::collections::HashSet::new();
        self.collect_referenced_variables_in_block(body, &mut referenced_vars);

        let modified_vars: std::collections::HashSet<SymbolId> = referenced_vars
            .into_iter()
            .filter(|sym| {
                let in_map = self.symbol_map.contains_key(sym);
                let is_param = if let Some(func) = self.builder.current_function() {
                    func.signature
                        .parameters
                        .iter()
                        .any(|p| self.symbol_map.get(sym) == Some(&p.reg))
                } else {
                    false
                };
                in_map && !is_param
            })
            .collect();

        let mut loop_var_initial_values: BTreeMap<SymbolId, (IrId, IrType)> = BTreeMap::new();
        for symbol_id in &modified_vars {
            if let Some(&reg) = self.symbol_map.get(symbol_id) {
                let reg_ty = self
                    .builder
                    .current_function()
                    .and_then(|func| func.locals.get(&reg).map(|l| l.ty.clone()))
                    .or_else(|| self.builder.get_register_type(reg))
                    .unwrap_or(IrType::I64);
                loop_var_initial_values.insert(*symbol_id, (reg, reg_ty));
            }
        }

        // Create loop blocks
        let Some(loop_cond_block) = self.builder.create_block() else {
            return;
        };
        let Some(loop_body_block) = self.builder.create_block() else {
            return;
        };
        let Some(loop_exit_block) = self.builder.create_block() else {
            return;
        };

        self.builder.build_branch(loop_cond_block);

        // Condition block: create loop-carried phis first.
        self.builder.switch_to_block(loop_cond_block);
        let mut phi_nodes: BTreeMap<SymbolId, IrId> = BTreeMap::new();
        for (symbol_id, (initial_reg, var_type)) in &loop_var_initial_values {
            if let Some(phi_reg) = self.builder.build_phi(loop_cond_block, var_type.clone()) {
                self.builder
                    .add_phi_incoming(loop_cond_block, phi_reg, entry_block, *initial_reg);
                if let Some(func) = self.builder.current_function_mut() {
                    if let Some(local) = func.locals.get(initial_reg).cloned() {
                        func.locals.insert(
                            phi_reg,
                            super::IrLocal {
                                name: format!("{}_phi", local.name),
                                ty: var_type.clone(),
                                mutable: true,
                                source_location: local.source_location,
                                allocation: super::AllocationHint::Register,
                            },
                        );
                    }
                }
                phi_nodes.insert(*symbol_id, phi_reg);
                self.symbol_map.insert(*symbol_id, phi_reg);
                if self.owned_heap_values.contains_key(symbol_id) {
                    self.owned_heap_values.insert(*symbol_id, phi_reg);
                }
            }
        }

        // Build exit phis now so break statements can target the correct values.
        let mut exit_phi_nodes: BTreeMap<SymbolId, IrId> = BTreeMap::new();
        for (symbol_id, loop_phi_reg) in &phi_nodes {
            if let Some((_, var_type)) = loop_var_initial_values.get(symbol_id) {
                let Some(exit_param_reg) = self.builder.alloc_reg() else {
                    continue;
                };
                if let Some(func) = self.builder.current_function_mut() {
                    if let Some(exit_block_data) = func.cfg.get_block_mut(loop_exit_block) {
                        let exit_phi = super::IrPhiNode {
                            dest: exit_param_reg,
                            incoming: vec![(loop_cond_block, *loop_phi_reg)],
                            ty: var_type.clone(),
                        };
                        exit_block_data.add_phi(exit_phi);
                        func.locals.insert(
                            exit_param_reg,
                            super::IrLocal {
                                name: format!("loop_exit_{}", symbol_id.as_raw()),
                                ty: var_type.clone(),
                                mutable: false,
                                source_location: super::IrSourceLocation::unknown(),
                                allocation: super::AllocationHint::Register,
                            },
                        );
                    }
                }
                exit_phi_nodes.insert(*symbol_id, exit_param_reg);
            }
        }

        // Push loop context for break/continue
        self.loop_stack.push(LoopContext {
            continue_block: loop_cond_block,
            break_block: loop_exit_block,
            label: label.cloned(),
            exit_phi_nodes: exit_phi_nodes.clone(),
            continue_phi_nodes: BTreeMap::new(),
        });

        // Condition block: index < length
        let Some(current_index) = self.builder.build_load(index_ptr, IrType::I64) else {
            self.loop_stack.pop();
            return;
        };
        let Some(cmp_result) = self.builder.build_cmp(
            crate::ir::instructions::CompareOp::Lt,
            current_index,
            array_len,
        ) else {
            self.loop_stack.pop();
            return;
        };
        self.builder
            .build_cond_branch(cmp_result, loop_body_block, loop_exit_block);

        // Body block: get element, bind, execute body, increment
        self.builder.switch_to_block(loop_body_block);
        let Some(idx_for_access) = self.builder.build_load(index_ptr, IrType::I64) else {
            self.loop_stack.pop();
            return;
        };
        let Some(element_value) = self.lower_index_access(collection, idx_for_access, elem_type_id)
        else {
            self.loop_stack.pop();
            return;
        };

        // Bind the pattern to the element value
        match pattern {
            HirPattern::Variable { symbol, .. } => {
                self.symbol_map.insert(*symbol, element_value);
            }
            _ => {}
        }

        // Lower the loop body
        self.enter_drop_scope();
        self.lower_block(body);

        // Add loop-carried phi incoming values from the body-end block.
        let body_end_block = self.builder.current_block().unwrap_or(loop_body_block);
        for (symbol_id, phi_reg) in &phi_nodes {
            let back_edge_value = if let Some(&updated_reg) = self.symbol_map.get(symbol_id) {
                updated_reg
            } else {
                *phi_reg
            };
            self.builder.add_phi_incoming(
                loop_cond_block,
                *phi_reg,
                body_end_block,
                back_edge_value,
            );
        }

        // Increment index
        if !self.is_terminated() {
            self.exit_drop_scope();
            let Some(idx_to_inc) = self.builder.build_load(index_ptr, IrType::I64) else {
                self.loop_stack.pop();
                return;
            };
            let Some(one) = self.builder.build_const(IrValue::I64(1)) else {
                self.loop_stack.pop();
                return;
            };
            let Some(next_index) =
                self.builder
                    .build_binop(crate::ir::instructions::BinaryOp::Add, idx_to_inc, one)
            else {
                self.loop_stack.pop();
                return;
            };
            self.builder.build_store(index_ptr, next_index);
            self.builder.build_branch(loop_cond_block);
        }

        self.loop_stack.pop();
        self.builder.switch_to_block(loop_exit_block);

        // Update symbol map and owned heap tracking to loop-exit values.
        for (symbol_id, exit_param_reg) in &exit_phi_nodes {
            self.symbol_map.insert(*symbol_id, *exit_param_reg);
            if self.owned_heap_values.contains_key(symbol_id) {
                self.owned_heap_values.insert(*symbol_id, *exit_param_reg);
            }
        }
    }

    /// Collect enum variant names covered by switch case patterns.
    /// Returns (covered_variants, has_wildcard).
    fn collect_covered_enum_variants(
        &self,
        cases: &[HirMatchCase],
    ) -> (HashSet<InternedString>, bool) {
        let mut covered = HashSet::new();
        let mut has_wildcard = false;

        for case in cases {
            // Cases with guards don't guarantee coverage (guard may fail at runtime)
            let case_has_guard = case.guard.is_some();

            for pattern in &case.patterns {
                self.collect_variants_from_pattern(
                    pattern,
                    case_has_guard,
                    &mut covered,
                    &mut has_wildcard,
                );
            }
        }

        (covered, has_wildcard)
    }

    /// Recursively walk a pattern collecting covered enum variants.
    fn collect_variants_from_pattern(
        &self,
        pattern: &HirPattern,
        has_guard: bool,
        covered: &mut HashSet<InternedString>,
        has_wildcard: &mut bool,
    ) {
        match pattern {
            HirPattern::Constructor { variant, .. } => {
                if !has_guard {
                    covered.insert(*variant);
                }
            }
            HirPattern::Wildcard => {
                if !has_guard {
                    *has_wildcard = true;
                }
            }
            HirPattern::Variable { .. } => {
                if !has_guard {
                    *has_wildcard = true;
                }
            }
            HirPattern::Or(sub_patterns) => {
                for sub in sub_patterns {
                    self.collect_variants_from_pattern(sub, has_guard, covered, has_wildcard);
                }
            }
            HirPattern::Guard { .. } => {
                // Guard patterns don't count for exhaustiveness
            }
            HirPattern::Typed { pattern, .. } => {
                self.collect_variants_from_pattern(pattern, has_guard, covered, has_wildcard);
            }
            _ => {}
        }
    }

    /// Check if a switch on a Bool type is exhaustive.
    fn check_bool_exhaustiveness(&mut self, scrutinee: &HirExpr, cases: &[HirMatchCase]) {
        let mut has_true = false;
        let mut has_false = false;
        let mut has_wildcard = false;

        for case in cases {
            if case.guard.is_some() {
                continue;
            }
            for pattern in &case.patterns {
                match pattern {
                    HirPattern::Literal(HirLiteral::Bool(true)) => has_true = true,
                    HirPattern::Literal(HirLiteral::Bool(false)) => has_false = true,
                    HirPattern::Wildcard | HirPattern::Variable { .. } => has_wildcard = true,
                    HirPattern::Or(subs) => {
                        for sub in subs {
                            match sub {
                                HirPattern::Literal(HirLiteral::Bool(true)) => has_true = true,
                                HirPattern::Literal(HirLiteral::Bool(false)) => has_false = true,
                                HirPattern::Wildcard | HirPattern::Variable { .. } => {
                                    has_wildcard = true
                                }
                                _ => {}
                            }
                        }
                    }
                    _ => {}
                }
            }
        }

        if has_wildcard || (has_true && has_false) {
            return;
        }

        let missing = match (has_true, has_false) {
            (false, false) => "true, false",
            (true, false) => "false",
            (false, true) => "true",
            _ => return,
        };

        let span = Self::source_location_to_span(&scrutinee.source_location);
        let diagnostic = diagnostics::DiagnosticBuilder::warning(
            format!("non-exhaustive switch on Bool — missing: {}", missing),
            span.clone(),
        )
        .code("W0007")
        .label(span, "missing cases")
        .help("consider adding a default case with `default:`")
        .build();
        self.diagnostics.push(diagnostic);
    }

    /// Convert a compiler SourceLocation to a diagnostics SourceSpan.
    fn source_location_to_span(loc: &SourceLocation) -> diagnostics::SourceSpan {
        let start = diagnostics::SourcePosition::new(
            loc.line as usize,
            loc.column as usize,
            loc.byte_offset as usize,
        );
        let end = diagnostics::SourcePosition::new(
            loc.line as usize,
            (loc.column + 1) as usize,
            (loc.byte_offset + 1) as usize,
        );
        diagnostics::SourceSpan::new(start, end, diagnostics::FileId::new(loc.file_id as usize))
    }

    /// Check exhaustiveness of a switch statement on enum or bool types.
    /// Emits diagnostics for non-exhaustive matches — does not affect code generation.
    fn check_switch_exhaustiveness(&mut self, scrutinee: &HirExpr, cases: &[HirMatchCase]) {
        // Resolve scrutinee type to determine if it's an enum
        let type_table = self.type_table.borrow();
        let type_info = match type_table.get(scrutinee.ty) {
            Some(info) => info,
            None => return,
        };

        let enum_symbol = match &type_info.kind {
            crate::tast::TypeKind::Enum { symbol_id, .. } => *symbol_id,
            crate::tast::TypeKind::GenericInstance { base_type, .. } => {
                match type_table.get(*base_type) {
                    Some(base_info) => match &base_info.kind {
                        crate::tast::TypeKind::Enum { symbol_id, .. } => *symbol_id,
                        _ => return,
                    },
                    None => return,
                }
            }
            crate::tast::TypeKind::Bool => {
                drop(type_table); // Release borrow before calling method
                self.check_bool_exhaustiveness(scrutinee, cases);
                return;
            }
            _ => return,
        };

        // Get all variant names from enum definition
        let variant_symbols = match self.symbol_table.get_enum_variants(enum_symbol) {
            Some(v) => v.clone(),
            None => return,
        };
        drop(type_table); // Release borrow

        let all_variants: HashSet<InternedString> = variant_symbols
            .iter()
            .filter_map(|sid| self.symbol_table.get_symbol(*sid).map(|s| s.name))
            .collect();

        if all_variants.is_empty() {
            return;
        }

        // Collect covered variants from patterns
        let (covered, has_wildcard) = self.collect_covered_enum_variants(cases);

        if has_wildcard {
            return;
        }

        // Compute missing variants
        let missing: Vec<InternedString> = all_variants
            .iter()
            .filter(|v| !covered.contains(v))
            .copied()
            .collect();

        if missing.is_empty() {
            return;
        }

        // Emit warning
        let enum_name = self
            .symbol_table
            .get_symbol(enum_symbol)
            .and_then(|s| self.string_interner.get(s.name))
            .unwrap_or("?");
        let missing_names: Vec<&str> = missing
            .iter()
            .filter_map(|n| self.string_interner.get(*n))
            .collect();
        let span = Self::source_location_to_span(&scrutinee.source_location);
        let mut builder = diagnostics::DiagnosticBuilder::warning(
            format!("non-exhaustive switch on enum '{}'", enum_name),
            span.clone(),
        )
        .code("W0006")
        .label(
            span,
            format!("missing variants: {}", missing_names.join(", ")),
        );

        for name in &missing_names {
            builder = builder.note(format!("add case for `{}`", name));
        }
        builder = builder.help("consider adding a default case with `default:`");

        self.diagnostics.push(builder.build());
    }

    fn lower_switch_statement(&mut self, scrutinee: &HirExpr, cases: &[HirMatchCase]) {
        // Check exhaustiveness (analysis only, no codegen effect)
        self.check_switch_exhaustiveness(scrutinee, cases);

        // Switch/match statement lowering:
        // switch (scrutinee) {
        //   case pattern1 if guard1: body1
        //   case pattern2: body2
        //   default: default_body
        // }
        //
        // Becomes a series of conditional branches:
        //   %scrut = evaluate scrutinee
        //   br pattern1_test
        // pattern1_test:
        //   %match1 = test pattern1 against %scrut
        //   br %match1, guard1_test, pattern2_test
        // guard1_test:
        //   %guard1 = evaluate guard1
        //   br %guard1, body1_block, pattern2_test
        // body1_block:
        //   <body1>
        //   br continuation
        // pattern2_test:
        //   %match2 = test pattern2 against %scrut
        //   br %match2, body2_block, default_block
        // ...
        // continuation:

        // Evaluate scrutinee once
        let scrut_val = match self.lower_expression(scrutinee) {
            Some(v) => v,
            None => return,
        };

        // Create continuation block (after switch)
        let continuation = match self.builder.create_block() {
            Some(b) => b,
            None => return,
        };

        // Create blocks for each case
        let mut case_test_blocks = Vec::new();
        let mut case_body_blocks = Vec::new();

        for _ in cases {
            if let (Some(test), Some(body)) =
                (self.builder.create_block(), self.builder.create_block())
            {
                case_test_blocks.push(test);
                case_body_blocks.push(body);
            }
        }

        // Default block (for non-exhaustive matches)
        let default_block = match self.builder.create_block() {
            Some(b) => b,
            None => return,
        };

        // Branch to first case test
        if let Some(&first_test) = case_test_blocks.first() {
            self.builder.build_branch(first_test);
        } else {
            // No cases, go to default
            self.builder.build_branch(default_block);
            return;
        }

        // Lower each case
        for (i, case) in cases.iter().enumerate() {
            let test_block = case_test_blocks[i];
            let body_block = case_body_blocks[i];
            let next_test = case_test_blocks
                .get(i + 1)
                .copied()
                .unwrap_or(default_block);

            // Generate pattern test block
            self.builder.switch_to_block(test_block);

            let pattern_matches = if case.patterns.is_empty() {
                // No pattern means default case
                self.builder.build_bool(true)
            } else if case.patterns.len() == 1 {
                self.lower_pattern_test(scrut_val, &case.patterns[0])
            } else {
                // Multiple patterns per case: OR them all together
                let mut result = self.lower_pattern_test(scrut_val, &case.patterns[0]);
                for pat in &case.patterns[1..] {
                    if let Some(prev) = result {
                        if let Some(pat_match) = self.lower_pattern_test(scrut_val, pat) {
                            result = self.builder.build_binop(BinaryOp::Or, prev, pat_match);
                        }
                    }
                }
                result
            };

            let pattern_matches = match pattern_matches {
                Some(v) => v,
                None => {
                    // Pattern test failed, go to next
                    self.builder.build_branch(next_test);
                    continue;
                }
            };

            // If there's a guard, test it
            if let Some(ref guard) = case.guard {
                let guard_block = match self.builder.create_block() {
                    Some(b) => b,
                    None => return,
                };

                // Branch: if pattern matches, test guard; else try next pattern
                self.builder
                    .build_cond_branch(pattern_matches, guard_block, next_test);

                // Guard test block
                self.builder.switch_to_block(guard_block);
                let guard_val = match self.lower_expression(guard) {
                    Some(v) => v,
                    None => {
                        self.builder.build_branch(next_test);
                        continue;
                    }
                };

                // Branch: if guard true, execute body; else try next pattern
                self.builder
                    .build_cond_branch(guard_val, body_block, next_test);
            } else {
                // No guard, just test pattern
                self.builder
                    .build_cond_branch(pattern_matches, body_block, next_test);
            }

            // Generate case body block
            self.builder.switch_to_block(body_block);
            // Bind pattern variables (extract enum fields into variable symbols)
            if !case.patterns.is_empty() {
                self.bind_pattern_with_scrutinee_type(
                    &case.patterns[0],
                    scrut_val,
                    Some(scrutinee.ty),
                );
            }
            self.lower_block(&case.body);
            self.builder.build_branch(continuation);
        }

        // Default block - just continue (could also panic for exhaustive matches)
        self.builder.switch_to_block(default_block);
        self.builder.build_branch(continuation);

        // Continue after switch
        self.builder.switch_to_block(continuation);
    }

    fn lower_pattern_test(&mut self, scrutinee: IrId, pattern: &HirPattern) -> Option<IrId> {
        // Test if scrutinee matches pattern
        // Returns a boolean IrId indicating match success
        match pattern {
            HirPattern::Variable { name, symbol } => {
                // Variable pattern always matches. Don't bind here — binding happens
                // in bind_pattern_with_scrutinee_type() in the body block, which ensures
                // the register is defined in the correct SSA block.
                self.builder.build_bool(true)
            }

            HirPattern::Wildcard => {
                // Wildcard always matches
                self.builder.build_bool(true)
            }

            HirPattern::Literal(lit) => {
                // Literal pattern: compare scrutinee with literal value
                // TODO: Get proper type from pattern context
                // For now, use a default type based on the literal kind
                let default_type = match lit {
                    HirLiteral::Int(_) => TypeId::from_raw(1), // Assume Int type (ID 1)
                    HirLiteral::Float(_) => TypeId::from_raw(2), // Assume Float type
                    HirLiteral::Bool(_) => TypeId::from_raw(3), // Assume Bool type
                    HirLiteral::String(_) => TypeId::from_raw(4), // Assume String type
                    _ => TypeId::from_raw(1),                  // Default to Int
                };
                let lit_val = self.lower_literal(lit, default_type)?;
                // TODO: Use proper comparison based on type
                self.builder.build_cmp(CompareOp::Eq, scrutinee, lit_val)
            }

            HirPattern::Constructor {
                enum_type,
                variant,
                fields,
            } => {
                // Constructor pattern: check enum tag and optionally extract fields.
                // Resolve whether this enum uses boxed or unboxed representation.
                let enum_symbol = self.resolve_enum_symbol(*enum_type);
                let mut is_boxed = enum_symbol.map_or(false, |s| self.enum_is_boxed(s));

                // Override boxed/unboxed based on scrutinee register type:
                // - I32 scalar: force unboxed (plain discriminant, pointer would SIGSEGV)
                // - Ptr: force boxed (e.g., Type.typeof() returns heap-allocated ValueType)
                let scrut_type = self.builder.get_register_type(scrutinee);
                if matches!(scrut_type, Some(IrType::I32)) {
                    is_boxed = false;
                } else if matches!(scrut_type, Some(IrType::Ptr(_))) {
                    is_boxed = true;
                }

                let variant_discriminant = self
                    .resolve_enum_variant_discriminant(*enum_type, *variant)
                    .unwrap_or(0);

                if !is_boxed {
                    // Unboxed enum: scrutinee IS the discriminant (i32 or i64)
                    let scrut_ir_type = scrut_type.unwrap_or(IrType::I64);
                    let expected = self
                        .builder
                        .build_int(variant_discriminant, scrut_ir_type)?;
                    return self.builder.build_cmp(CompareOp::Eq, scrutinee, expected);
                }

                // Boxed enum: scrutinee is ptr-as-i64, bitcast to pointer
                let enum_ptr = self
                    .builder
                    .build_bitcast(scrutinee, IrType::Ptr(Box::new(IrType::I8)))?;

                // Load tag at offset 0
                let zero_offset = self.builder.build_int(0, IrType::I64)?;
                let tag_gep = self.builder.build_gep(
                    enum_ptr,
                    vec![zero_offset],
                    IrType::Ptr(Box::new(IrType::I8)),
                )?;
                let tag_ptr = self
                    .builder
                    .build_bitcast(tag_gep, IrType::Ptr(Box::new(IrType::I32)))?;
                let tag_val = self.builder.build_load(tag_ptr, IrType::I32)?;

                let expected_tag = self.builder.build_int(variant_discriminant, IrType::I32)?;
                let tag_matches = self
                    .builder
                    .build_cmp(CompareOp::Eq, tag_val, expected_tag)?;

                // If no fields to match, just return tag comparison
                if fields.is_empty() || fields.iter().all(|f| matches!(f, HirPattern::Wildcard)) {
                    return Some(tag_matches);
                }

                // Must short-circuit field extraction behind tag check.
                // Other variants may have smaller allocations (e.g., None = 8 bytes tag only),
                // so loading fields at offset 8+ would be out-of-bounds if tag doesn't match.
                let false_val = self.builder.build_const(IrValue::Bool(false))?;
                let tag_check_block = self.builder.current_block()?;
                let fields_block = self.builder.create_block()?;
                let merge_block = self.builder.create_block()?;
                self.builder
                    .build_cond_branch(tag_matches, fields_block, merge_block);

                // --- fields_block: tag matched, extract and test fields ---
                self.builder.switch_to_block(fields_block);
                let mut all_fields_match = None;

                for (i, field_pattern) in fields.iter().enumerate() {
                    // Field at byte offset 8 + i*8
                    let field_offset = self.builder.build_int((8 + i * 8) as i64, IrType::I64)?;
                    let field_gep = self.builder.build_gep(
                        enum_ptr,
                        vec![field_offset],
                        IrType::Ptr(Box::new(IrType::I8)),
                    )?;
                    let field_ptr = self
                        .builder
                        .build_bitcast(field_gep, IrType::Ptr(Box::new(IrType::I64)))?;
                    let field_val = self.builder.build_load(field_ptr, IrType::I64)?;

                    let field_match = self.lower_pattern_test(field_val, field_pattern)?;
                    all_fields_match = Some(match all_fields_match {
                        Some(prev) => self.builder.build_binop(BinaryOp::And, prev, field_match)?,
                        None => field_match,
                    });
                }

                let fields_result = all_fields_match.unwrap_or(tag_matches);
                self.builder.build_branch(merge_block);
                let fields_exit_block = self.builder.current_block()?;

                // --- merge_block: phi(fields_result | false) ---
                self.builder.switch_to_block(merge_block);
                let result = self.builder.build_phi(merge_block, IrType::Bool)?;
                self.builder.add_phi_incoming(
                    merge_block,
                    result,
                    fields_exit_block,
                    fields_result,
                );
                self.builder
                    .add_phi_incoming(merge_block, result, tag_check_block, false_val);

                Some(result)
            }

            HirPattern::Tuple(patterns) => {
                // Tuple pattern: extract and test each element
                //
                // Tuple layout:
                // struct Tuple { elem0, elem1, elem2, ... }
                //
                // Strategy:
                // 1. Extract each element by index
                // 2. Test each element against its pattern
                // 3. Combine all results with AND

                if patterns.is_empty() {
                    // Empty tuple always matches
                    return self.builder.build_bool(true);
                }

                let mut all_match = self.builder.build_bool(true)?;

                for (i, elem_pattern) in patterns.iter().enumerate() {
                    // Extract element at index i
                    let Some(elem_idx) = self.builder.build_int(i as i64, IrType::I64) else {
                        return None;
                    };

                    let Some(elem_ptr) = self.builder.build_gep(
                        scrutinee,
                        vec![elem_idx],
                        IrType::Ptr(Box::new(IrType::Any)),
                    ) else {
                        return None;
                    };

                    let Some(elem_val) = self.builder.build_load(elem_ptr, IrType::Any) else {
                        return None;
                    };

                    // Recursively test element pattern
                    let Some(elem_match) = self.lower_pattern_test(elem_val, elem_pattern) else {
                        return None;
                    };

                    // Combine with AND
                    all_match = self
                        .builder
                        .build_binop(BinaryOp::And, all_match, elem_match)?;
                }

                Some(all_match)
            }

            HirPattern::Array { elements, rest } => {
                // Array pattern: check length and test elements
                //
                // Array layout:
                // struct Array { length: i64, data: [elements...] }
                //
                // Strategy:
                // 1. Extract array length (index 0)
                // 2. Check length matches expected (if no rest pattern)
                // 3. Extract and test each specified element
                // 4. If rest pattern exists, bind remaining elements

                // Extract array length from header (index 0)
                let Some(zero_idx) = self.builder.build_int(0, IrType::I64) else {
                    return None;
                };

                let Some(length_ptr) = self.builder.build_gep(
                    scrutinee,
                    vec![zero_idx],
                    IrType::Ptr(Box::new(IrType::I64)),
                ) else {
                    return None;
                };

                let Some(array_length) = self.builder.build_load(length_ptr, IrType::I64) else {
                    return None;
                };

                let mut all_match = self.builder.build_bool(true)?;

                // If no rest pattern, check exact length
                if rest.is_none() {
                    let Some(expected_len) =
                        self.builder.build_int(elements.len() as i64, IrType::I64)
                    else {
                        return None;
                    };

                    let Some(length_matches) =
                        self.builder
                            .build_cmp(CompareOp::Eq, array_length, expected_len)
                    else {
                        return None;
                    };

                    all_match =
                        self.builder
                            .build_binop(BinaryOp::And, all_match, length_matches)?;
                } else {
                    // With rest pattern, check minimum length
                    let Some(min_len) = self.builder.build_int(elements.len() as i64, IrType::I64)
                    else {
                        return None;
                    };

                    let Some(length_sufficient) =
                        self.builder.build_cmp(CompareOp::Ge, array_length, min_len)
                    else {
                        return None;
                    };

                    all_match =
                        self.builder
                            .build_binop(BinaryOp::And, all_match, length_sufficient)?;
                }

                // Test each specified element
                for (i, elem_pattern) in elements.iter().enumerate() {
                    // Array elements start at index 1 (after length header)
                    let Some(elem_idx) = self.builder.build_int((i + 1) as i64, IrType::I64) else {
                        return None;
                    };

                    let Some(elem_ptr) = self.builder.build_gep(
                        scrutinee,
                        vec![elem_idx],
                        IrType::Ptr(Box::new(IrType::Any)),
                    ) else {
                        return None;
                    };

                    let Some(elem_val) = self.builder.build_load(elem_ptr, IrType::Any) else {
                        return None;
                    };

                    // Recursively test element pattern
                    let Some(elem_match) = self.lower_pattern_test(elem_val, elem_pattern) else {
                        return None;
                    };

                    all_match = self
                        .builder
                        .build_binop(BinaryOp::And, all_match, elem_match)?;
                }

                // TODO: Handle rest pattern binding
                // For now, we just ignore the rest pattern
                // In a full implementation, we'd create a slice of remaining elements

                Some(all_match)
            }

            HirPattern::Object { fields, rest } => {
                // Object pattern: extract and test fields
                //
                // Object layout (simplified):
                // Hash map or struct with named fields
                //
                // Strategy:
                // 1. For each pattern field, extract object field by name
                // 2. Test extracted value against pattern
                // 3. Combine all results with AND
                // 4. rest flag indicates whether additional fields are allowed

                if fields.is_empty() {
                    // Empty object pattern always matches (or matches any object if rest=true)
                    return self.builder.build_bool(true);
                }

                let mut all_match = self.builder.build_bool(true)?;

                for (field_name, field_pattern) in fields {
                    // Extract field from object
                    // TODO: Implement proper field lookup by name
                    // For now, we use a simple hash-based approach

                    // Calculate field offset based on name hash (placeholder)
                    let field_offset = field_name.to_string().len() as i64;

                    let Some(field_idx) = self.builder.build_int(field_offset, IrType::I64) else {
                        return None;
                    };

                    let Some(field_ptr) = self.builder.build_gep(
                        scrutinee,
                        vec![field_idx],
                        IrType::Ptr(Box::new(IrType::Any)),
                    ) else {
                        return None;
                    };

                    let Some(field_val) = self.builder.build_load(field_ptr, IrType::Any) else {
                        return None;
                    };

                    // Recursively test field pattern
                    let Some(field_match) = self.lower_pattern_test(field_val, field_pattern)
                    else {
                        return None;
                    };

                    all_match = self
                        .builder
                        .build_binop(BinaryOp::And, all_match, field_match)?;
                }

                // TODO: If rest=false, verify no additional fields exist
                // For now, we just ignore the rest flag

                Some(all_match)
            }

            HirPattern::Typed { pattern, ty } => {
                // Typed pattern: check type and test inner pattern
                // TODO: Implement type checking
                self.lower_pattern_test(scrutinee, pattern)
            }

            HirPattern::Or(patterns) => {
                // Or pattern: test each pattern with OR logic
                if patterns.is_empty() {
                    return self.builder.build_bool(false);
                }
                let mut result = self.lower_pattern_test(scrutinee, &patterns[0])?;
                for pat in &patterns[1..] {
                    let pat_match = self.lower_pattern_test(scrutinee, pat)?;
                    result = self.builder.build_binop(BinaryOp::Or, result, pat_match)?;
                }
                Some(result)
            }

            HirPattern::Guard { pattern, condition } => {
                // Guard pattern: test pattern then condition
                let pattern_match = self.lower_pattern_test(scrutinee, pattern)?;
                let guard_val = self.lower_expression(condition)?;
                // AND the pattern match with the guard
                self.builder
                    .build_binop(BinaryOp::And, pattern_match, guard_val)
            }
        }
    }

    fn lower_try_catch(
        &mut self,
        try_block: &HirBlock,
        catches: &[HirCatchClause],
        finally: Option<&HirBlock>,
    ) {
        // Exception handling via setjmp/longjmp:
        //
        //   try_entry (current block):
        //     %jmp_buf = call rayzor_exception_push_handler()  // returns *mut u8
        //     %result = call _setjmp(%jmp_buf)                 // returns 0 normally, 1 on longjmp
        //     br %result == 0, normal_path, landing_pad
        //   normal_path:
        //     <try block>
        //     call rayzor_exception_pop_handler()
        //     br finally / continuation
        //   landing_pad:
        //     call rayzor_exception_pop_handler()
        //     %exc = call rayzor_get_exception()
        //     br catch_0
        //   catch_0:
        //     <catch block>
        //     br finally / continuation
        //   finally_block:
        //     <finally code>
        //     br continuation
        //   continuation:
        //     <rest of code>

        let normal_path_block = match self.builder.create_block() {
            Some(b) => b,
            None => return,
        };

        let landing_pad_block = match self.builder.create_block() {
            Some(b) => b,
            None => return,
        };

        let finally_block = if finally.is_some() {
            self.builder.create_block()
        } else {
            None
        };

        let continuation_block = match self.builder.create_block() {
            Some(b) => b,
            None => return,
        };

        // --- try_entry block (current block) ---

        // Call rayzor_exception_push_handler() -> *mut u8 (jmp_buf pointer)
        let push_fn = self.get_or_register_extern_function(
            "rayzor_exception_push_handler",
            vec![],
            IrType::Ptr(Box::new(IrType::Void)),
        );
        let jmp_buf =
            self.builder
                .build_call_direct(push_fn, vec![], IrType::Ptr(Box::new(IrType::Void)));

        // Call _setjmp(jmp_buf) -> i32 (0 = normal, 1 = exception caught)
        let setjmp_fn = self.get_or_register_extern_function(
            "_setjmp",
            vec![IrType::Ptr(Box::new(IrType::Void))],
            IrType::I32,
        );
        let jmp_buf_reg = jmp_buf.unwrap_or_else(|| {
            self.builder
                .build_const(IrValue::I64(0))
                .expect("failed to create const")
        });
        let setjmp_result =
            self.builder
                .build_call_direct(setjmp_fn, vec![jmp_buf_reg], IrType::I32);

        // Branch: setjmp_result == 0 → normal_path, else → landing_pad
        let zero = self
            .builder
            .build_const(IrValue::I32(0))
            .expect("failed to create const");
        let setjmp_reg = setjmp_result.unwrap_or(zero);
        let cmp = self
            .builder
            .build_cmp(CompareOp::Eq, setjmp_reg, zero)
            .expect("failed to build cmp");
        self.builder
            .build_cond_branch(cmp, normal_path_block, landing_pad_block);

        // --- normal_path block: execute try body ---
        self.builder.switch_to_block(normal_path_block);
        self.lower_block(try_block);

        // Pop handler on normal exit
        let pop_fn = self.get_or_register_extern_function(
            "rayzor_exception_pop_handler",
            vec![],
            IrType::Void,
        );
        self.builder.build_call_direct(pop_fn, vec![], IrType::Void);

        if let Some(fb) = finally_block {
            self.builder.build_branch(fb);
        } else {
            self.builder.build_branch(continuation_block);
        }

        // --- landing_pad block: exception was thrown ---
        self.builder.switch_to_block(landing_pad_block);

        // Pop handler (the longjmp already happened, but we need to remove it from the stack)
        let pop_fn2 = self.get_or_register_extern_function(
            "rayzor_exception_pop_handler",
            vec![],
            IrType::Void,
        );
        self.builder
            .build_call_direct(pop_fn2, vec![], IrType::Void);

        // Get the exception value and type_id
        let get_exc_fn =
            self.get_or_register_extern_function("rayzor_get_exception", vec![], IrType::I64);
        let exception_id = self
            .builder
            .build_call_direct(get_exc_fn, vec![], IrType::I64)
            .unwrap_or_else(|| {
                self.builder
                    .build_const(IrValue::I64(0))
                    .expect("failed to create const")
            });

        let get_exc_type_fn = self.get_or_register_extern_function(
            "rayzor_get_exception_type_id",
            vec![],
            IrType::I32,
        );
        let exc_type_id = self
            .builder
            .build_call_direct(get_exc_type_fn, vec![], IrType::I32)
            .unwrap_or_else(|| {
                self.builder
                    .build_const(IrValue::I32(0))
                    .expect("failed to create const")
            });

        // Type-based dispatch across catch clauses
        if !catches.is_empty() {
            let after_catch_target = if let Some(fb) = finally_block {
                fb
            } else {
                continuation_block
            };

            // Build chain: for each catch, test type match → body or next catch
            let mut next_test_block: Option<IrBlockId> = None;

            for (i, catch_clause) in catches.iter().enumerate() {
                let catch_type_kind = {
                    let type_table = self.type_table.borrow();
                    type_table
                        .get(catch_clause.exception_type)
                        .map(|t| t.kind.clone())
                };
                let is_dynamic = matches!(catch_type_kind, Some(crate::tast::TypeKind::Dynamic));

                let catch_body_block = match self.builder.create_block() {
                    Some(b) => b,
                    None => return,
                };

                // If this is not the first catch, the previous test's false branch leads here
                if let Some(test_block) = next_test_block {
                    self.builder.switch_to_block(test_block);
                }
                // else: we're still in the landing_pad block from above

                if is_dynamic || i == catches.len() - 1 {
                    // Dynamic catches everything; last catch is also unconditional fallback
                    self.builder.build_branch(catch_body_block);
                    next_test_block = None;
                } else {
                    let expected_type_id = self.runtime_type_id(catch_clause.exception_type);
                    let expected_const = self
                        .builder
                        .build_const(IrValue::I32(expected_type_id as i32))
                        .expect("failed to create type_id const");

                    // Use polymorphic matching for class types (walks inheritance),
                    // exact match for primitives (Int, String, etc.)
                    let is_class_type =
                        matches!(catch_type_kind, Some(crate::tast::TypeKind::Class { .. }));

                    let type_match = if is_class_type {
                        // Call rayzor_exception_type_matches(actual, expected) -> i32
                        let match_fn = self.get_or_register_extern_function(
                            "rayzor_exception_type_matches",
                            vec![IrType::I32, IrType::I32],
                            IrType::I32,
                        );
                        let result = self
                            .builder
                            .build_call_direct(
                                match_fn,
                                vec![exc_type_id, expected_const],
                                IrType::I32,
                            )
                            .unwrap_or_else(|| {
                                self.builder
                                    .build_const(IrValue::I32(0))
                                    .expect("failed to create const")
                            });
                        let zero_val = self
                            .builder
                            .build_const(IrValue::I32(0))
                            .expect("failed to create const");
                        self.builder
                            .build_cmp(CompareOp::Ne, result, zero_val)
                            .expect("failed to build type cmp")
                    } else {
                        // Exact match for primitive types
                        self.builder
                            .build_cmp(CompareOp::Eq, exc_type_id, expected_const)
                            .expect("failed to build type cmp")
                    };

                    let next_block = self.builder.create_block().expect("failed to create block");
                    self.builder
                        .build_cond_branch(type_match, catch_body_block, next_block);
                    next_test_block = Some(next_block);
                }

                // --- catch body ---
                self.builder.switch_to_block(catch_body_block);
                self.symbol_map
                    .insert(catch_clause.exception_var, exception_id);
                self.lower_block(&catch_clause.body);
                self.builder.build_branch(after_catch_target);
            }

            // If all typed catches failed and no Dynamic/final catch consumed it,
            // branch to finally/continuation (exception goes unhandled at this level)
            if let Some(fallthrough_block) = next_test_block {
                self.builder.switch_to_block(fallthrough_block);
                self.builder.build_branch(after_catch_target);
            }
        } else {
            // No catch clauses — go directly to finally or continuation
            if let Some(fb) = finally_block {
                self.builder.build_branch(fb);
            } else {
                self.builder.build_branch(continuation_block);
            }
        }

        // --- finally block (if present) ---
        if let Some(finally_body) = finally {
            if let Some(fb) = finally_block {
                self.builder.switch_to_block(fb);
                self.lower_block(finally_body);
                self.builder.build_branch(continuation_block);
            }
        }

        // Continue with rest of code
        self.builder.switch_to_block(continuation_block);
    }

    fn lower_lambda(
        &mut self,
        params: &[HirParam],
        body: &HirExpr,
        captures: &[HirCapture],
        lambda_type: TypeId,
    ) -> Option<IrId> {
        // Closure/Lambda lowering using MakeClosure instruction:
        //
        // For: |x, y| { x + y + captured_z }
        //
        // Strategy:
        // 1. Generate a lambda function that takes (env*, params...) where
        //    env* is a struct containing all captured variables
        // 2. Collect the values to be captured (from current scope)
        // 3. Use MakeClosure instruction to create closure at runtime
        //
        // The MakeClosure instruction will:
        // - Allocate an environment struct
        // - Copy captured values into it
        // - Create a closure struct { func_ptr, env_ptr }
        // - Return the closure

        // Step 1: Collect captured values from current scope FIRST
        // (before generate_lambda_function which saves/restores state)
        let mut captured_values = Vec::new();
        // Filter captures to only include actual variables, not global functions
        // Global functions (like `trace`) don't need to be captured - they're resolved by name
        let filtered_captures: Vec<_> = captures
            .iter()
            .filter(|c| {
                if let Some(sym) = self.symbol_table.get_symbol(c.symbol) {
                    // Skip Function symbols - they don't need capturing
                    if sym.kind == crate::tast::SymbolKind::Function {
                        debug!(
                            "Skipping function capture {:?} (name={:?})",
                            c.symbol,
                            self.string_interner.get(sym.name)
                        );
                        return false;
                    }
                }
                true
            })
            .collect();

        debug!(
            "Collecting {} captured values (filtered from {})",
            filtered_captures.len(),
            captures.len()
        );
        debug!("symbol_map has {} entries", self.symbol_map.len());
        for capture in &filtered_captures {
            debug!("Looking for captured symbol {:?}", capture.symbol);
            if let Some(&captured_val) = self.symbol_map.get(&capture.symbol) {
                debug!("  Found! Register: {:?}", captured_val);
                captured_values.push(captured_val);
            } else {
                // Captured variable not found in current scope
                debug!("  NOT FOUND! Available symbols:");
                for (sym, reg) in &self.symbol_map {
                    debug!("    {:?} -> {:?}", sym, reg);
                }
                self.errors.push(LoweringError {
                    message: format!("Captured variable {:?} not found in scope", capture.symbol),
                    location: body.source_location.clone(),
                });
                return None;
            }
        }

        // Step 2: Generate the lambda function
        // Pass filtered captures so the lambda doesn't try to load global functions from env
        let filtered_captures_slice: Vec<HirCapture> =
            filtered_captures.iter().map(|c| (*c).clone()).collect();
        let lambda_func_id =
            self.generate_lambda_function(params, body, &filtered_captures_slice, lambda_type)?;

        // Step 3: Use MakeClosure instruction to create closure
        let result = self
            .builder
            .build_make_closure(lambda_func_id, captured_values);

        // Step 4: Transfer ownership of captured variables to the closure
        // When a variable is captured by a closure, ownership is MOVED into the closure
        // environment. The enclosing scope should NOT free captured variables.
        // This prevents double-free when both the enclosing scope and the closure
        // try to free the same memory.
        for capture in &filtered_captures {
            if self.owned_heap_values.remove(&capture.symbol).is_some() {
                debug!(
                    "Transferred ownership of {:?} to closure (removed from owned_heap_values)",
                    capture.symbol
                );
            }
        }

        result
    }

    // ========================================================================
    // Two-Pass Lambda Generation (New Architecture) - Helper Methods
    // ========================================================================

    fn save_state(&self) -> SavedLoweringState {
        SavedLoweringState {
            current_function: self.builder.current_function,
            current_block: self.builder.current_block,
            symbol_map: self.symbol_map.clone(),
            current_env_layout: self.current_env_layout.clone(),
            // Save drop tracking state so lambda bodies don't inherit parent's owned values
            owned_heap_values: self.owned_heap_values.clone(),
            drop_scope_stack: self.drop_scope_stack.clone(),
            temp_heap_values: self.temp_heap_values.clone(),
            reassigned_in_scope: self.reassigned_in_scope.clone(),
            current_drop_points: self.current_drop_points.clone(),
            current_stmt_index: self.current_stmt_index,
            boxed_dynamic_symbols: self.boxed_dynamic_symbols.clone(),
            value_type_symbols: self.value_type_symbols.clone(),
            anon_views: self.anon_views.clone(),
            raw_anon_symbols: self.raw_anon_symbols.clone(),
        }
    }

    fn restore_state(&mut self, state: SavedLoweringState) {
        self.builder.current_function = state.current_function;
        self.builder.current_block = state.current_block;
        self.symbol_map = state.symbol_map;
        self.current_env_layout = state.current_env_layout;
        // Restore drop tracking state
        self.owned_heap_values = state.owned_heap_values;
        self.drop_scope_stack = state.drop_scope_stack;
        self.temp_heap_values = state.temp_heap_values;
        self.reassigned_in_scope = state.reassigned_in_scope;
        self.current_drop_points = state.current_drop_points;
        self.current_stmt_index = state.current_stmt_index;
        self.boxed_dynamic_symbols = state.boxed_dynamic_symbols;
        self.value_type_symbols = state.value_type_symbols;
        self.anon_views = state.anon_views;
        self.raw_anon_symbols = state.raw_anon_symbols;
    }

    /// PASS 1: Create lambda skeleton with placeholder signature
    fn generate_lambda_skeleton(
        &mut self,
        params: &[HirParam],
        captures: &[HirCapture],
    ) -> LambdaContext {
        // Allocate function ID
        let func_id = self.builder.module.alloc_function_id();
        let lambda_name = format!("<lambda_{}>", self.lambda_counter);
        self.lambda_counter += 1;

        // Build environment layout if we have captures
        let env_layout = if !captures.is_empty() {
            Some(EnvironmentLayout::new(captures, |ty| self.convert_type(ty)))
        } else {
            None
        };

        // Build parameters: env* is ALWAYS first param (CallIndirect always prepends env_ptr)
        let mut func_params = Vec::new();
        let mut next_reg_id = 0u32;

        // Always add env_ptr as first parameter - even for capture-less lambdas.
        // Cranelift's CallIndirect always loads env_ptr from closure struct and
        // prepends it as the first argument, so the function signature must match.
        func_params.push(IrParameter {
            name: "env".to_string(),
            ty: IrType::Ptr(Box::new(IrType::Void)),
            reg: IrId::new(next_reg_id),
            by_ref: false,
        });
        next_reg_id += 1;

        for param in params {
            let param_type = self.convert_type(param.ty);
            let param_name = self
                .string_interner
                .get(param.name)
                .unwrap_or("<param>")
                .to_string();

            func_params.push(IrParameter {
                name: param_name,
                ty: param_type,
                reg: IrId::new(next_reg_id),
                by_ref: false,
            });
            next_reg_id += 1;
        }

        // Create PLACEHOLDER signature
        let signature = IrFunctionSignature {
            parameters: func_params,
            return_type: IrType::Any, // PLACEHOLDER - will be inferred
            calling_convention: CallingConvention::Haxe,
            can_throw: false,
            type_params: vec![],
            uses_sret: false,
        };

        // Create empty function
        let symbol_id = SymbolId::from_raw(1000000 + func_id.0);
        let lambda_function = IrFunction::new(func_id, symbol_id, lambda_name, signature);
        let entry_block = lambda_function.entry_block();

        // Add to module
        self.builder.module.add_function(lambda_function);

        LambdaContext {
            func_id,
            entry_block,
            param_offset: 1, // env_ptr is always first param
            env_layout,
        }
    }

    /// PASS 2: Lower lambda body and infer signature
    #[allow(dead_code)] // Will be used once we switch to two-pass
    fn lower_lambda_body(
        &mut self,
        context: LambdaContext,
        params: &[HirParam],
        body: &HirExpr,
    ) -> Option<IrFunctionId> {
        let LambdaContext {
            func_id,
            entry_block,
            param_offset,
            env_layout,
        } = context;

        // Save state
        let saved_state = self.save_state();

        // Switch to lambda context
        self.builder.current_function = Some(func_id);
        self.builder.current_block = Some(entry_block);
        self.symbol_map.clear();
        self.current_env_layout = env_layout.clone();

        // Clear drop tracking state for the lambda body.
        // Lambda bodies are separate functions with their own register namespace.
        // Without this, cleanup_all_scopes (called on return) would try to free
        // the parent function's owned heap values using IrIds that refer to
        // different registers in the lambda's context, causing heap corruption.
        self.owned_heap_values.clear();
        self.drop_scope_stack.clear();
        self.temp_heap_values.clear();
        self.reassigned_in_scope.clear();
        self.current_drop_points = None;
        self.current_stmt_index = 0;

        // Map lambda parameters to registers AND register as locals
        // (matching regular function param setup at line ~2274-2288)
        for (i, param) in params.iter().enumerate() {
            let param_reg = IrId::new(param_offset + i as u32);
            self.symbol_map.insert(param.symbol_id, param_reg);

            // Also register parameter as a local so type inference can find it
            let param_type = self.convert_type(param.ty);
            let param_name = self
                .string_interner
                .get(param.name)
                .unwrap_or("<param>")
                .to_string();
            if let Some(func) = self.builder.current_function_mut() {
                func.locals.insert(
                    param_reg,
                    super::IrLocal {
                        name: param_name,
                        ty: param_type,
                        mutable: false,
                        source_location: super::IrSourceLocation::unknown(),
                        allocation: super::AllocationHint::Register,
                    },
                );
            }
        }

        // Setup captured variables using environment layout
        if let Some(layout) = &env_layout {
            debug!(
                "Lambda has {} captured variables in environment",
                layout.fields.len()
            );
            for field in &layout.fields {
                debug!("Captured symbol: {:?}", field.symbol);
            }

            let env_ptr = IrId::new(0); // First parameter

            for field in &layout.fields {
                // Use layout to load field (handles casting automatically)
                let value_reg = layout.load_field(&mut self.builder, env_ptr, field.symbol)?;
                self.symbol_map.insert(field.symbol, value_reg);
            }
        }

        // Lower the body expression.
        // For arrow functions, the body is typically a Block wrapping a single expression
        // statement. lower_expression(Block) returns None because blocks don't have return
        // values in general. To get the lambda's body result, we unwrap the block and
        // lower the inner expression directly.
        let body_result = match &body.kind {
            crate::ir::hir::HirExprKind::Block(block) => {
                if block.statements.len() == 1 && block.expr.is_none() {
                    // Single-expression block (common in arrow functions):
                    // Extract the expression from the Expr statement and lower directly
                    if let crate::ir::hir::HirStatement::Expr(expr) = &block.statements[0] {
                        self.lower_expression(expr)
                    } else {
                        // Single non-expression statement (e.g., Let) — lower normally
                        self.lower_statement(&block.statements[0]);
                        None
                    }
                } else {
                    // Multi-statement block: lower all statements, use trailing expr if any
                    for stmt in &block.statements {
                        self.lower_statement(stmt);
                    }
                    if let Some(trailing_expr) = &block.expr {
                        self.lower_expression(trailing_expr)
                    } else {
                        None
                    }
                }
            }
            _ => self.lower_expression(body),
        };

        // Infer return type from actual generated code (borrows function immutably)
        let return_type = {
            let lambda_func = self.builder.module.functions.get(&func_id)?;
            self.infer_lambda_return_type(lambda_func, entry_block, body_result)
        };

        // Update signature and add terminator (borrows function mutably)
        {
            let lambda_func = self.builder.module.functions.get_mut(&func_id)?;
            debug!(
                "Updating lambda signature from {:?} to {:?}",
                lambda_func.signature.return_type, return_type
            );
            debug!(
                "Lambda has {} parameters: {:?}",
                lambda_func.signature.parameters.len(),
                lambda_func
                    .signature
                    .parameters
                    .iter()
                    .map(|p| &p.name)
                    .collect::<Vec<_>>()
            );
            lambda_func.signature.return_type = return_type.clone();
            Self::finalize_lambda_terminator_static(
                lambda_func,
                entry_block,
                body_result,
                &return_type,
            )?;
        }

        // Restore state
        self.current_env_layout = None;
        self.restore_state(saved_state);

        Some(func_id)
    }

    /// Infer the return type from generated MIR instructions
    fn infer_lambda_return_type(
        &self,
        function: &IrFunction,
        entry_block: IrBlockId,
        body_result: Option<IrId>,
    ) -> IrType {
        use crate::ir::IrInstruction;

        // Strategy 1: Search ALL blocks for Return terminators (not just entry block)
        // Lambdas with complex control flow (loops, conditionals) may have return in other blocks
        for (block_id, block) in &function.cfg.blocks {
            if let IrTerminator::Return {
                value: Some(ret_reg),
            } = &block.terminator
            {
                debug!(
                    "Found Return terminator in block {:?} with register {:?}",
                    block_id, ret_reg
                );

                // First try locals table (for parameters and explicitly registered values)
                if let Some(local) = function.locals.get(ret_reg) {
                    debug!("Found type in locals table: {:?}", local.ty);
                    return local.ty.clone();
                }

                // If not in locals table, scan ALL blocks for the instruction that defines this register
                debug!("Register not in locals, scanning all blocks for defining instruction...");
                for (search_block_id, search_block) in &function.cfg.blocks {
                    for inst in &search_block.instructions {
                        match inst {
                            IrInstruction::Load { dest, ty, .. } if *dest == *ret_reg => {
                                debug!(
                                    "Inferred type from Load instruction in block {:?}: {:?}",
                                    search_block_id, ty
                                );
                                return ty.clone();
                            }
                            IrInstruction::Cast { dest, to_ty, .. } if *dest == *ret_reg => {
                                debug!("Inferred type from Cast instruction: {:?}", to_ty);
                                return to_ty.clone();
                            }
                            IrInstruction::Const { dest, value, .. } if *dest == *ret_reg => {
                                // Infer from constant value
                                let ty = match value {
                                    IrValue::I32(_) => IrType::I32,
                                    IrValue::I64(_) => IrType::I64,
                                    IrValue::F64(_) => IrType::F64,
                                    IrValue::Bool(_) => IrType::Bool,
                                    IrValue::Null => IrType::Ptr(Box::new(IrType::Void)),
                                    _ => IrType::I64,
                                };
                                debug!("Inferred type from Const instruction: {:?}", ty);
                                return ty;
                            }
                            IrInstruction::Cmp { dest, .. } if *dest == *ret_reg => {
                                debug!("Inferred type from Cmp instruction: Bool");
                                return IrType::Bool;
                            }
                            IrInstruction::BinOp { dest, left, .. } if *dest == *ret_reg => {
                                // Infer from left operand type (BinOp preserves operand type)
                                if let Some(local) = function.locals.get(left) {
                                    debug!(
                                        "Inferred type from BinOp left operand local: {:?}",
                                        local.ty
                                    );
                                    return local.ty.clone();
                                }
                                if let Some(ty) = function.register_types.get(left) {
                                    debug!("Inferred type from BinOp left operand register_types: {:?}", ty);
                                    return ty.clone();
                                }
                                // BinOp on params is likely I64 (Haxe Int)
                                debug!("BinOp operand type unknown, defaulting to I64");
                                return IrType::I64;
                            }
                            IrInstruction::UnOp { dest, operand, .. } if *dest == *ret_reg => {
                                if let Some(local) = function.locals.get(operand) {
                                    debug!("Inferred type from UnOp operand local: {:?}", local.ty);
                                    return local.ty.clone();
                                }
                                if let Some(ty) = function.register_types.get(operand) {
                                    debug!(
                                        "Inferred type from UnOp operand register_types: {:?}",
                                        ty
                                    );
                                    return ty.clone();
                                }
                                return IrType::I64;
                            }
                            _ => {}
                        }
                    }
                }

                // Instruction scan didn't match — try register_types for the return register
                if let Some(ty) = function.register_types.get(ret_reg) {
                    debug!(
                        "Inferred return type from register_types for ret_reg: {:?}",
                        ty
                    );
                    return ty.clone();
                }
            }
        }

        // Strategy 2: Use body result register type from locals
        if let Some(result_reg) = body_result {
            if let Some(local) = function.locals.get(&result_reg) {
                debug!(
                    "Inferred return type from body result locals: {:?}",
                    local.ty
                );
                return local.ty.clone();
            }
        }

        // Strategy 3: Check register_types map (populated by build_binop, build_call_direct, etc.)
        if let Some(result_reg) = body_result {
            if let Some(ty) = function.register_types.get(&result_reg) {
                debug!("Inferred return type from register_types: {:?}", ty);
                return ty.clone();
            }
        }

        // Fallback: Void return
        debug!("No return type found, using Void");
        IrType::Void
    }

    /// Add terminator to lambda if not already present (static version)
    fn finalize_lambda_terminator_static(
        function: &mut IrFunction,
        entry_block: IrBlockId,
        body_result: Option<IrId>,
        return_type: &IrType,
    ) -> Option<()> {
        // Check if terminator already exists
        {
            let block = function.cfg.get_block_mut(entry_block)?;
            if !matches!(block.terminator, IrTerminator::Unreachable) {
                return Some(()); // Already has terminator
            }
        }

        // Create appropriate terminator
        let terminator = match return_type {
            IrType::Void => IrTerminator::Return { value: None },
            _ => {
                if let Some(result_reg) = body_result {
                    IrTerminator::Return {
                        value: Some(result_reg),
                    }
                } else {
                    // Create default value - allocate register first
                    let default_reg = function.alloc_reg();
                    let default_value = match return_type {
                        IrType::I32 => IrValue::I32(0),
                        IrType::I64 => IrValue::I64(0),
                        IrType::Bool => IrValue::Bool(false),
                        _ => IrValue::I64(0),
                    };

                    // Now get block and add instruction
                    let block = function.cfg.get_block_mut(entry_block)?;
                    block.add_instruction(IrInstruction::Const {
                        dest: default_reg,
                        value: default_value,
                    });

                    IrTerminator::Return {
                        value: Some(default_reg),
                    }
                }
            }
        };

        let block = function.cfg.get_block_mut(entry_block)?;
        block.set_terminator(terminator);
        Some(())
    }

    // ========================================================================
    // Lambda Generation - Now Using Two-Pass Architecture
    // ========================================================================

    /// Generate a lambda function using two-pass architecture
    ///
    /// Creates a new function that takes (env*, params...) as arguments,
    /// where env* is a pointer to a struct containing captured variables.
    ///
    /// Two-Pass Architecture:
    /// - Pass 1: Create skeleton with placeholder signature
    /// - Pass 2: Lower body, infer types from actual MIR, update signature
    fn generate_lambda_function(
        &mut self,
        params: &[HirParam],
        body: &HirExpr,
        captures: &[HirCapture],
        _lambda_type: TypeId, // No longer needed - type inferred from MIR
    ) -> Option<IrFunctionId> {
        // TWO-PASS LAMBDA LOWERING
        // Pass 1: Create skeleton with placeholder signature
        let context = self.generate_lambda_skeleton(params, captures);

        // Pass 2: Lower body and infer return type from actual MIR
        self.lower_lambda_body(context, params, body)
    }

    fn lower_array_literal(&mut self, elements: &[HirExpr]) -> Option<IrId> {
        // Array literal: [e1, e2, e3, ...]
        //
        // HaxeArray is a 32-byte struct (4 x 8-byte fields): ptr, len, cap, elem_size
        //
        // Strategy:
        // 1. Allocate HaxeArray struct on HEAP (not stack!)
        //    CRITICAL: Stack allocation causes use-after-free when the array is
        //    stored in a global/static variable and accessed after the function returns.
        // 2. Zero-initialize it (like new Array<T>())
        // 3. For each element, call haxe_array_push_ptr to add it
        // 4. Return pointer to HaxeArray struct

        let element_count = elements.len();

        // Heap-allocate HaxeArray struct (4 x i64 = 32 bytes) using malloc
        // HaxeArray layout: { len: usize, cap: usize, elem_size: usize, ptr: *u8 }
        let malloc_func_id = self.get_or_register_extern_function(
            "malloc",
            vec![IrType::U64],
            IrType::Ptr(Box::new(IrType::U8)),
        );
        let size_32 = self.builder.build_const(IrValue::U64(32))?;
        let array_ptr = self.builder.build_call_direct(
            malloc_func_id,
            vec![size_32],
            IrType::Ptr(Box::new(IrType::U8)),
        )?;

        // Zero-initialize the HaxeArray struct fields
        if let Some(zero_i64) = self.builder.build_const(IrValue::I64(0)) {
            // Zero out ptr field (offset 0)
            if let Some(index_0) = self.builder.build_const(IrValue::I32(0)) {
                if let Some(ptr_field) =
                    self.builder
                        .build_gep(array_ptr, vec![index_0], IrType::I64)
                {
                    self.builder.build_store(ptr_field, zero_i64);
                }
            }
            // Zero out len field (offset 8)
            if let Some(index_1) = self.builder.build_const(IrValue::I32(1)) {
                if let Some(len_field) =
                    self.builder
                        .build_gep(array_ptr, vec![index_1], IrType::I64)
                {
                    self.builder.build_store(len_field, zero_i64);
                }
            }
            // Zero out cap field (offset 16)
            if let Some(index_2) = self.builder.build_const(IrValue::I32(2)) {
                if let Some(cap_field) =
                    self.builder
                        .build_gep(array_ptr, vec![index_2], IrType::I64)
                {
                    self.builder.build_store(cap_field, zero_i64);
                }
            }
            // Set elem_size field to 8 bytes (offset 24) - assume pointer size
            if let Some(elem_size_val) = self.builder.build_const(IrValue::I64(8)) {
                if let Some(index_3) = self.builder.build_const(IrValue::I32(3)) {
                    if let Some(elem_size_field) =
                        self.builder
                            .build_gep(array_ptr, vec![index_3], IrType::I64)
                    {
                        self.builder.build_store(elem_size_field, elem_size_val);
                    }
                }
            }
        }

        // For non-empty arrays, push each element using haxe_array_push_i64
        // This is inefficient but works correctly with the HaxeArray runtime
        if element_count > 0 {
            // Register haxe_array_push_i64: fn(arr: *HaxeArray, val: i64) -> void
            let push_func_id = self.get_or_register_extern_function(
                "haxe_array_push_i64",
                vec![
                    IrType::Ptr(Box::new(IrType::I64)), // arr pointer
                    IrType::I64,                        // value (i64 for pointer-sized values)
                ],
                IrType::Void,
            );

            for elem in elements.iter() {
                let elem_val = self.lower_expression(elem)?;

                // Convert element to i64 to match haxe_array_push_i64's signature.
                let elem_type = self.builder.get_register_type(elem_val);
                let push_val = match &elem_type {
                    Some(IrType::Ptr(_)) => {
                        // Pointer → i64: bitcast (reinterpret pointer as integer)
                        self.builder
                            .build_bitcast(elem_val, IrType::I64)
                            .unwrap_or(elem_val)
                    }
                    Some(IrType::I32) => {
                        // I32 → I64: sign-extend (not bitcast)
                        self.builder
                            .build_cast(elem_val, IrType::I32, IrType::I64)
                            .unwrap_or(elem_val)
                    }
                    Some(IrType::F64) => {
                        // F64 → I64: bitcast (reinterpret bits as integer)
                        self.builder
                            .build_bitcast(elem_val, IrType::I64)
                            .unwrap_or(elem_val)
                    }
                    Some(IrType::F32) => {
                        // F32 → I32 → I64
                        let as_i32 = self
                            .builder
                            .build_bitcast(elem_val, IrType::I32)
                            .unwrap_or(elem_val);
                        self.builder
                            .build_cast(as_i32, IrType::I32, IrType::I64)
                            .unwrap_or(as_i32)
                    }
                    _ => elem_val,
                };

                // Call haxe_array_push_i64(arr, val) - this is a void function, so ignore the None return
                self.builder.build_call_direct(
                    push_func_id,
                    vec![array_ptr, push_val],
                    IrType::Void,
                );
            }
        }

        Some(array_ptr)
    }

    fn lower_map_literal(&mut self, entries: &[(HirExpr, HirExpr)]) -> Option<IrId> {
        // Map literal: [key1 => val1, key2 => val2, ...]
        //
        // Determine key type from first entry and use appropriate runtime:
        // - Int keys → IntMap (haxe_intmap_new/set)
        // - String keys → StringMap (haxe_stringmap_new/set)
        // - Object keys → ObjectMap (haxe_objectmap_new/set, pointer identity)

        if entries.is_empty() {
            // Default to StringMap for empty map literals
            let new_fn = self.get_or_register_extern_function(
                "haxe_stringmap_new",
                vec![],
                IrType::Ptr(Box::new(IrType::Void)),
            );
            return self.builder.build_call_direct(
                new_fn,
                vec![],
                IrType::Ptr(Box::new(IrType::Void)),
            );
        }

        // Determine key type from first entry
        let key_type_kind = {
            let type_table = self.type_table.borrow();
            type_table.get(entries[0].0.ty).map(|t| t.kind.clone())
        };
        let is_int_key = matches!(
            key_type_kind,
            Some(crate::tast::TypeKind::Int) | Some(crate::tast::TypeKind::Bool)
        );
        let is_string_key = matches!(key_type_kind, Some(crate::tast::TypeKind::String));

        let map_ptr_type = IrType::Ptr(Box::new(IrType::Void));

        if is_int_key {
            // IntMap
            let new_fn = self.get_or_register_extern_function(
                "haxe_intmap_new",
                vec![],
                map_ptr_type.clone(),
            );
            let map_ptr = self
                .builder
                .build_call_direct(new_fn, vec![], map_ptr_type.clone())?;

            let set_fn = self.get_or_register_extern_function(
                "haxe_intmap_set",
                vec![map_ptr_type.clone(), IrType::I64, IrType::U64],
                IrType::Void,
            );

            for (key, value) in entries.iter() {
                let key_val = self.lower_expression(key)?;
                let value_val = self.lower_expression(value)?;

                // Cast key to i64
                let key_type = self.convert_type(key.ty);
                let key_i64 = if key_type != IrType::I64 {
                    self.builder
                        .build_cast(key_val, key_type, IrType::I64)
                        .unwrap_or(key_val)
                } else {
                    key_val
                };

                // Cast value to u64 for raw storage
                let val_type = self.convert_type(value.ty);
                let val_u64 = match &val_type {
                    IrType::F64 => self
                        .builder
                        .build_bitcast(value_val, IrType::U64)
                        .unwrap_or(value_val),
                    IrType::U64 => value_val,
                    _ => self
                        .builder
                        .build_cast(value_val, val_type, IrType::U64)
                        .unwrap_or(value_val),
                };

                self.builder.build_call_direct(
                    set_fn,
                    vec![map_ptr, key_i64, val_u64],
                    IrType::Void,
                );
            }

            Some(map_ptr)
        } else if is_string_key {
            // StringMap
            let new_fn = self.get_or_register_extern_function(
                "haxe_stringmap_new",
                vec![],
                map_ptr_type.clone(),
            );
            let map_ptr = self
                .builder
                .build_call_direct(new_fn, vec![], map_ptr_type.clone())?;

            let set_fn = self.get_or_register_extern_function(
                "haxe_stringmap_set",
                vec![
                    map_ptr_type.clone(),
                    IrType::Ptr(Box::new(IrType::U8)),
                    IrType::U64,
                ],
                IrType::Void,
            );

            for (key, value) in entries.iter() {
                let key_val = self.lower_expression(key)?;
                let value_val = self.lower_expression(value)?;

                // Cast value to u64 for raw storage
                let val_type = self.convert_type(value.ty);
                let val_u64 = match &val_type {
                    IrType::F64 => self
                        .builder
                        .build_bitcast(value_val, IrType::U64)
                        .unwrap_or(value_val),
                    IrType::U64 => value_val,
                    _ => self
                        .builder
                        .build_cast(value_val, val_type, IrType::U64)
                        .unwrap_or(value_val),
                };

                self.builder.build_call_direct(
                    set_fn,
                    vec![map_ptr, key_val, val_u64],
                    IrType::Void,
                );
            }

            Some(map_ptr)
        } else {
            // ObjectMap (object/pointer keys, identity-based)
            let new_fn = self.get_or_register_extern_function(
                "haxe_objectmap_new",
                vec![],
                map_ptr_type.clone(),
            );
            let map_ptr = self
                .builder
                .build_call_direct(new_fn, vec![], map_ptr_type.clone())?;

            let set_fn = self.get_or_register_extern_function(
                "haxe_objectmap_set",
                vec![map_ptr_type.clone(), IrType::U64, IrType::U64],
                IrType::Void,
            );

            for (key, value) in entries.iter() {
                let key_val = self.lower_expression(key)?;
                let value_val = self.lower_expression(value)?;

                // Cast key pointer to u64 for identity-based lookup
                let key_type = self.convert_type(key.ty);
                let key_u64 = match &key_type {
                    IrType::U64 | IrType::I64 => key_val,
                    _ => self
                        .builder
                        .build_cast(key_val, key_type, IrType::U64)
                        .unwrap_or(key_val),
                };

                // Cast value to u64 for raw storage
                let val_type = self.convert_type(value.ty);
                let val_u64 = match &val_type {
                    IrType::F64 => self
                        .builder
                        .build_bitcast(value_val, IrType::U64)
                        .unwrap_or(value_val),
                    IrType::U64 => value_val,
                    _ => self
                        .builder
                        .build_cast(value_val, val_type, IrType::U64)
                        .unwrap_or(value_val),
                };

                self.builder.build_call_direct(
                    set_fn,
                    vec![map_ptr, key_u64, val_u64],
                    IrType::Void,
                );
            }

            Some(map_ptr)
        }
    }

    /// Wrap a class instance in an interface fat pointer.
    /// Fat pointer layout: { object_ptr: i64, fn_ptr_0: i64, fn_ptr_1: i64, ... }
    /// One slot per interface method, in the interface's method order.
    fn wrap_in_interface_fat_ptr(
        &mut self,
        obj_reg: IrId,
        class_symbol: SymbolId,
        interface_symbol: SymbolId,
    ) -> Option<IrId> {
        let vtable = self
            .interface_vtables
            .get(&(class_symbol, interface_symbol))
            .cloned()?;
        let method_count = vtable.len();
        let fat_ptr_size = ((1 + method_count) * 8) as u64; // object_ptr + N function pointers
                                                            // Allocate fat pointer with malloc so IrInstruction::Free
                                                            // (lowered to libc free) uses matching allocator semantics.
        let malloc_fn = self.get_or_register_extern_function(
            "malloc",
            vec![IrType::U64],
            IrType::Ptr(Box::new(IrType::U8)),
        );
        let size_reg = self.builder.build_const(IrValue::U64(fat_ptr_size))?;
        let fat_ptr = self.builder.build_call_direct(
            malloc_fn,
            vec![size_reg],
            IrType::Ptr(Box::new(IrType::U8)),
        )?;

        // Store object pointer at offset 0
        // Need to bitcast obj_reg to i64 if it's a pointer
        let obj_as_i64 = {
            let obj_ty = self
                .builder
                .get_register_type(obj_reg)
                .unwrap_or(IrType::I64);
            if matches!(obj_ty, IrType::Ptr(_)) {
                self.builder.build_bitcast(obj_reg, IrType::I64)?
            } else {
                obj_reg
            }
        };
        self.builder.build_store(fat_ptr, obj_as_i64);

        // Store function pointers for each interface method
        for (i, method_sym) in vtable.iter().enumerate() {
            let func_id_opt = self.function_map.get(method_sym).copied();
            if let Some(func_id) = func_id_opt {
                let fn_ref = self.builder.build_function_ref(func_id)?;
                let offset_val = self
                    .builder
                    .build_const(IrValue::I64(((i + 1) * 8) as i64))?;
                let slot_ptr = self.builder.build_ptr_add(
                    fat_ptr,
                    offset_val,
                    IrType::Ptr(Box::new(IrType::U8)),
                )?;
                self.builder.build_store(slot_ptr, fn_ref);
            }
        }

        Some(fat_ptr)
    }

    /// Clone an interface fat pointer when assigning interface -> interface.
    /// This prevents multiple variables from aliasing the same wrapper allocation,
    /// so source reassignment can free only the source wrapper without invalidating
    /// other interface variables.
    fn clone_interface_fat_ptr(
        &mut self,
        fat_ptr_reg: IrId,
        source_interface: SymbolId,
        target_interface: SymbolId,
    ) -> Option<IrId> {
        let source_method_count = self.interface_method_names.get(&source_interface)?.len();
        let target_method_count = self.interface_method_names.get(&target_interface)?.len();

        // Reject downcast-like layout growth to avoid reading past source wrapper.
        if source_method_count < target_method_count {
            return None;
        }

        let slot_count = 1 + target_method_count; // object ptr + method slots
        let fat_ptr_size = (slot_count * 8) as u64;
        let malloc_fn = self.get_or_register_extern_function(
            "malloc",
            vec![IrType::U64],
            IrType::Ptr(Box::new(IrType::U8)),
        );
        let size_reg = self.builder.build_const(IrValue::U64(fat_ptr_size))?;
        let cloned_ptr = self.builder.build_call_direct(
            malloc_fn,
            vec![size_reg],
            IrType::Ptr(Box::new(IrType::U8)),
        )?;

        let src_ptr = {
            let src_ty = self
                .builder
                .get_register_type(fat_ptr_reg)
                .unwrap_or(IrType::I64);
            if matches!(src_ty, IrType::Ptr(_)) {
                fat_ptr_reg
            } else {
                self.builder
                    .build_bitcast(fat_ptr_reg, IrType::Ptr(Box::new(IrType::U8)))?
            }
        };

        // Copy object slot + required method slots.
        let obj_ptr = self.builder.build_load(src_ptr, IrType::I64)?;
        self.builder.build_store(cloned_ptr, obj_ptr);
        for i in 1..slot_count {
            let offset_reg = self.builder.build_const(IrValue::I64((i * 8) as i64))?;
            let src_slot_ptr = self.builder.build_ptr_add(
                src_ptr,
                offset_reg,
                IrType::Ptr(Box::new(IrType::U8)),
            )?;
            let slot_val = self.builder.build_load(src_slot_ptr, IrType::I64)?;

            let dst_slot_ptr = self.builder.build_ptr_add(
                cloned_ptr,
                offset_reg,
                IrType::Ptr(Box::new(IrType::U8)),
            )?;
            self.builder.build_store(dst_slot_ptr, slot_val);
        }

        Some(cloned_ptr)
    }

    /// Resolve the return type for an interface method call.
    /// If the method symbol has a Function type in the type table, extract the return type.
    /// Otherwise fall back to convert_type(expr_ty).
    fn resolve_interface_method_return_type(
        &self,
        method_symbol: SymbolId,
        expr_ty: TypeId,
    ) -> IrType {
        let fallback = self.convert_type(expr_ty);
        // If fallback is already a concrete type (not Ptr), it's correct
        if !matches!(fallback, IrType::Ptr(_)) {
            return fallback;
        }
        // Look up the method name from the symbol table
        let method_name_interned = self.symbol_table.get_symbol(method_symbol).map(|s| s.name);
        if let Some(method_name) = method_name_interned {
            // Search all interfaces for this method's return type
            for ((_, name), &ret_type_id) in &self.interface_method_return_types {
                if *name == method_name {
                    let resolved = self.convert_type(ret_type_id);
                    if !matches!(resolved, IrType::Ptr(_)) {
                        return resolved;
                    }
                }
            }
        }
        fallback
    }

    /// Check if a type is an interface type and return its SymbolId.
    /// Also handles TypeParameters with interface constraints (T:Printable).
    fn get_interface_symbol(&self, type_id: TypeId) -> Option<SymbolId> {
        let type_table = self.type_table.borrow();
        let type_ref = type_table.get(type_id)?;
        match &type_ref.kind {
            TypeKind::Interface { symbol_id, .. } => Some(*symbol_id),
            TypeKind::TypeParameter { constraints, .. } => {
                // For constrained type params, find the first interface constraint
                for constraint_id in constraints {
                    if let Some(constraint_type) = type_table.get(*constraint_id) {
                        if let TypeKind::Interface { symbol_id, .. } = &constraint_type.kind {
                            return Some(*symbol_id);
                        }
                    }
                }
                None
            }
            _ => None,
        }
    }

    /// Check if a list of constraint TypeIds contains at least one interface constraint
    fn has_interface_constraint(&self, constraints: &[TypeId]) -> bool {
        let type_table = self.type_table.borrow();
        constraints.iter().any(|c| {
            type_table
                .get(*c)
                .map_or(false, |t| matches!(t.kind, TypeKind::Interface { .. }))
        })
    }

    /// Record which function parameters are constrained type parameters.
    /// Used at call sites to wrap class arguments in fat pointers.
    fn record_constrained_params(
        &mut self,
        func_id: IrFunctionId,
        hir_func: &HirFunction,
        has_this: bool,
    ) {
        let mut constrained = Vec::new();
        for (i, param) in hir_func.params.iter().enumerate() {
            let type_table = self.type_table.borrow();
            if let Some(type_info) = type_table.get(param.ty) {
                if let TypeKind::TypeParameter { constraints, .. } = &type_info.kind {
                    // Find the first interface constraint
                    for constraint_id in constraints {
                        if let Some(constraint_type) = type_table.get(*constraint_id) {
                            if let TypeKind::Interface { symbol_id, .. } = &constraint_type.kind {
                                // param_index in MIR includes 'this' offset
                                let mir_index = if has_this { i + 1 } else { i };
                                constrained.push((mir_index, *symbol_id));
                                break;
                            }
                        }
                    }
                }
            }
        }
        if !constrained.is_empty() {
            self.constrained_param_interfaces
                .insert(func_id, constrained);
        }
    }

    /// Check if a type is a class type and return its SymbolId
    fn get_class_symbol(&self, type_id: TypeId) -> Option<SymbolId> {
        self.resolve_receiver_class_symbol(type_id)
    }

    /// If value_type is a class and target_type is an interface the class implements,
    /// wrap the value in a fat pointer. Otherwise return the value unchanged.
    fn maybe_wrap_for_interface(
        &mut self,
        value_reg: IrId,
        value_type: TypeId,
        target_type: TypeId,
    ) -> (IrId, bool) {
        let iface_sym = match self.get_interface_symbol(target_type) {
            Some(s) => s,
            None => return (value_reg, false),
        };

        // Class -> interface: build a fresh fat pointer wrapper from class vtable entries.
        if let Some(class_sym) = self.get_class_symbol(value_type) {
            // Check if we have a vtable for this (class, interface) pair
            if !self.interface_vtables.contains_key(&(class_sym, iface_sym)) {
                return (value_reg, false);
            }

            return match self.wrap_in_interface_fat_ptr(value_reg, class_sym, iface_sym) {
                Some(wrapped) => (wrapped, true),
                None => (value_reg, false),
            };
        }

        // Interface -> same or different interface: clone the fat pointer so destination
        // does not alias source wrapper. This prevents use-after-free when one variable
        // is later reassigned (freeing its old fat pointer while the other still uses it).
        if let Some(src_iface_sym) = self.get_interface_symbol(value_type) {
            return match self.clone_interface_fat_ptr(value_reg, src_iface_sym, iface_sym) {
                Some(cloned) => (cloned, true),
                None => (value_reg, false),
            };
        }

        (value_reg, false)
    }

    fn lower_object_literal(
        &mut self,
        fields: &[(InternedString, HirExpr)],
        expr_type: TypeId,
    ) -> Option<IrId> {
        // Object literal: { field1: val1, field2: val2, ... }
        //
        // Lowering strategy using Arc-based anonymous objects:
        // 1. Resolve field names and sort alphabetically for canonical ordering
        // 2. Check typedef type for optional fields missing from the literal
        // 3. Get or create a shape ID for the complete field set
        // 4. Call rayzor_anon_new(shape_id, field_count) → Arc<AnonObject> handle
        // 5. For each field: call rayzor_anon_set_field_by_index(handle, index, value)
        // 6. Return the handle pointer (PtrU8)

        // Resolve field names from the literal
        let mut literal_field_names: Vec<(String, usize)> = Vec::with_capacity(fields.len());
        for (i, (interned_name, _expr)) in fields.iter().enumerate() {
            let name = self
                .string_interner
                .get(*interned_name)
                .unwrap_or("<unknown>")
                .to_string();
            literal_field_names.push((name, i));
        }

        // Check if the expression type (resolved through aliases) has additional
        // optional fields not present in the literal
        let resolved_ty = self.resolve_through_aliases(expr_type);
        let mut optional_defaults: Vec<String> = Vec::new();
        {
            let type_table = self.type_table.borrow();
            if let Some(ty_info) = type_table.get(resolved_ty) {
                if let TypeKind::Anonymous {
                    fields: anon_fields,
                } = &ty_info.kind
                {
                    let literal_names: std::collections::HashSet<&str> = literal_field_names
                        .iter()
                        .map(|(n, _)| n.as_str())
                        .collect();
                    for af in anon_fields {
                        if af.optional {
                            if let Some(fname) = self.string_interner.get(af.name) {
                                if !literal_names.contains(fname) {
                                    optional_defaults.push(fname.to_string());
                                }
                            }
                        }
                    }
                }
            }
        }

        // Build sorted (name, source) list — source is either an index into literal fields
        // or None for optional defaults
        let mut named_fields: Vec<(String, Option<usize>)> = literal_field_names
            .into_iter()
            .map(|(name, idx)| (name, Some(idx)))
            .collect();
        for opt_name in &optional_defaults {
            named_fields.push((opt_name.clone(), None));
        }
        // Sort by field name for canonical ordering (matches runtime shape table)
        named_fields.sort_by(|a, b| a.0.cmp(&b.0));

        let total_field_count = named_fields.len();

        // Build shape key as comma-joined sorted field names
        let shape_key: String = named_fields
            .iter()
            .map(|(name, _)| name.as_str())
            .collect::<Vec<_>>()
            .join(",");

        let shape_id = if let Some(&existing_id) = self.anonymous_shapes.get(&shape_key) {
            existing_id
        } else {
            let id = self.next_anon_shape_id;
            self.next_anon_shape_id += 1;
            self.anonymous_shapes.insert(shape_key, id);
            id
        };

        // Build shape descriptor string: "name1:type_id1,name2:type_id2,..."
        // Type IDs: 0=Void, 1=Null, 2=Bool, 3=Int, 4=Float, 5=String
        let descriptor = {
            let mut parts = Vec::with_capacity(named_fields.len());
            for (name, source) in &named_fields {
                let runtime_type_id = match source {
                    Some(orig_idx) => {
                        let field_type = fields[*orig_idx].1.ty;
                        self.runtime_type_id(field_type)
                    }
                    None => 1, // null for optional defaults
                };
                parts.push(format!("{}:{}", name, runtime_type_id));
            }
            parts.join(",")
        };

        // Register rayzor_ensure_shape extern: (shape_id: u32, descriptor: HaxeString*) -> void
        let ensure_shape_id = self.get_or_register_extern_function(
            "rayzor_ensure_shape",
            vec![IrType::I32, IrType::String],
            IrType::Void,
        );

        // Emit: rayzor_ensure_shape(shape_id, descriptor) — idempotent, registers once
        let shape_id_const = self.builder.build_const(IrValue::I32(shape_id as i32))?;
        let desc_str = self.builder.build_const(IrValue::String(descriptor))?;
        self.builder.build_call_direct(
            ensure_shape_id,
            vec![shape_id_const, desc_str],
            IrType::Void,
        );

        // Register rayzor_anon_new extern: (shape_id: u32, field_count: u32) -> *mut u8
        let anon_new_id = self.get_or_register_extern_function(
            "rayzor_anon_new",
            vec![IrType::I32, IrType::I32],
            IrType::Ptr(Box::new(IrType::U8)),
        );

        // Register rayzor_anon_set_field_by_index extern: (handle: *mut u8, index: u32, value: u64) -> void
        let anon_set_id = self.get_or_register_extern_function(
            "rayzor_anon_set_field_by_index",
            vec![IrType::Ptr(Box::new(IrType::U8)), IrType::I32, IrType::I64],
            IrType::Void,
        );

        // Emit: handle = rayzor_anon_new(shape_id, total_field_count)
        let shape_id_val = self.builder.build_const(IrValue::I32(shape_id as i32))?;
        let field_count_val = self
            .builder
            .build_const(IrValue::I32(total_field_count as i32))?;
        let handle = self.builder.build_call_direct(
            anon_new_id,
            vec![shape_id_val, field_count_val],
            IrType::Ptr(Box::new(IrType::U8)),
        )?;

        // Lower each field value and store at its sorted index
        for (sorted_idx, (_, source)) in named_fields.iter().enumerate() {
            let idx_val = self.builder.build_const(IrValue::I32(sorted_idx as i32))?;

            match source {
                Some(orig_idx) => {
                    // Literal field — lower the expression
                    let field_expr = &fields[*orig_idx].1;
                    let field_val = self.lower_expression(field_expr)?;
                    let val_as_i64 = self.coerce_to_i64(field_val, field_expr.ty)?;
                    self.builder.build_call_direct(
                        anon_set_id,
                        vec![handle, idx_val, val_as_i64],
                        IrType::Void,
                    );
                }
                None => {
                    // Optional field with default value (0/null)
                    let zero = self.builder.build_const(IrValue::I64(0))?;
                    self.builder.build_call_direct(
                        anon_set_id,
                        vec![handle, idx_val, zero],
                        IrType::Void,
                    );
                }
            }
        }

        Some(handle)
    }

    /// Resolve a TypeParameter TypeId to its concrete type using the receiver's type arguments.
    /// For example, if expr.ty is TypeParameter(T) and receiver is Container<Float>,
    /// returns Some(Float_TypeId).
    fn resolve_type_param_from_receiver(
        &self,
        type_param_id: TypeId,
        receiver_type_id: TypeId,
    ) -> Option<TypeId> {
        let type_table = self.type_table.borrow();

        // Check if type_param_id is actually a TypeParameter
        let param_info = type_table.get(type_param_id)?;
        let param_symbol = match &param_info.kind {
            crate::tast::TypeKind::TypeParameter { symbol_id, .. } => *symbol_id,
            _ => return None,
        };

        // Get receiver's class info with concrete type_args
        let recv_info = type_table.get(receiver_type_id)?;
        let (class_symbol, concrete_args) = match &recv_info.kind {
            crate::tast::TypeKind::Class {
                symbol_id,
                type_args,
            } => (*symbol_id, type_args.clone()),
            crate::tast::TypeKind::GenericInstance {
                base_type,
                type_args,
                ..
            } => {
                // Unwrap GenericInstance to get the base class's symbol_id
                if let Some(base_info) = type_table.get(*base_type) {
                    match &base_info.kind {
                        crate::tast::TypeKind::Class { symbol_id, .. } => {
                            (*symbol_id, type_args.clone())
                        }
                        _ => return None,
                    }
                } else {
                    return None;
                }
            }
            _ => return None,
        };
        drop(type_table);

        // Find the type parameter's name
        let param_name = self.symbol_table.get_symbol(param_symbol)?.name;

        // Find the class declaration in HIR to get type parameter order
        for (_tid, decl) in self.current_hir_types.iter() {
            if let crate::ir::hir::HirTypeDecl::Class(c) = decl {
                if c.symbol_id == class_symbol {
                    for (i, tp) in c.type_params.iter().enumerate() {
                        if tp.name == param_name {
                            return concrete_args.get(i).copied();
                        }
                    }
                }
            }
        }
        None
    }

    /// Box a raw value as a DynamicValue* for functions that expect Dynamic parameters.
    /// Resolves TypeParameter types through the current class context.
    /// Returns Some(boxed_reg) on success, None if value is already Dynamic or can't be resolved.
    fn box_value_for_dynamic(&mut self, value: IrId, type_id: TypeId) -> Option<IrId> {
        let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));

        // Resolve the concrete type — handles TypeParameter through class context
        let concrete_type_id = {
            let type_table = self.type_table.borrow();
            if let Some(ti) = type_table.get(type_id) {
                match &ti.kind {
                    crate::tast::TypeKind::TypeParameter { .. } => {
                        // Try to resolve through current class's type_args
                        drop(type_table);
                        if let Some(this_ty) = self.current_this_type {
                            self.resolve_type_param_from_receiver(type_id, this_ty)
                                .unwrap_or(type_id)
                        } else {
                            type_id
                        }
                    }
                    crate::tast::TypeKind::Dynamic => {
                        // Already Dynamic (boxed) — no boxing needed
                        return None;
                    }
                    _ => {
                        drop(type_table);
                        type_id
                    }
                }
            } else {
                type_id
            }
        };

        let ir_type = self.convert_type(concrete_type_id);
        let (is_string, is_enum, is_function) = {
            let type_table = self.type_table.borrow();
            let ti = type_table.get(concrete_type_id);
            (
                ti.map(|t| matches!(t.kind, crate::tast::TypeKind::String))
                    .unwrap_or(false),
                ti.map(|t| matches!(t.kind, crate::tast::TypeKind::Enum { .. }))
                    .unwrap_or(false),
                ti.map(|t| matches!(t.kind, crate::tast::TypeKind::Function { .. }))
                    .unwrap_or(false),
            )
        };

        // Enum values need haxe_box_reference_ptr to preserve the enum's type_id
        if is_enum {
            let type_id_u32 = concrete_type_id.as_raw();
            let type_id_const = self.builder.build_const(IrValue::U32(type_id_u32))?;
            let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
            // Cast the raw i64 discriminant (or boxed enum ptr) to *u8
            let actual_reg_type = self
                .builder
                .get_register_type(value)
                .unwrap_or(ir_type.clone());
            let as_ptr = if matches!(&actual_reg_type, IrType::Ptr(_)) {
                value
            } else {
                self.builder
                    .build_cast(value, actual_reg_type, ptr_u8.clone())
                    .unwrap_or(value)
            };
            let box_func = self.get_or_register_extern_function(
                "haxe_box_reference_ptr",
                vec![ptr_u8.clone(), IrType::U32],
                ptr_u8.clone(),
            );
            return self
                .builder
                .build_call_direct(box_func, vec![as_ptr, type_id_const], ptr_u8);
        }

        if is_function {
            // Function values are represented as closure pointers at runtime.
            // Normalize to *u8 and tag with TYPE_FUNCTION for Reflect/Type parity.
            let actual_reg_type = self
                .builder
                .get_register_type(value)
                .unwrap_or(ir_type.clone());
            let as_ptr = if matches!(&actual_reg_type, IrType::Ptr(_)) {
                value
            } else if matches!(&actual_reg_type, IrType::Function { .. }) {
                let as_i64 = self
                    .builder
                    .build_bitcast(value, IrType::I64)
                    .unwrap_or(value);
                self.builder
                    .build_cast(as_i64, IrType::I64, ptr_u8.clone())
                    .unwrap_or(as_i64)
            } else {
                self.builder
                    .build_cast(value, actual_reg_type, ptr_u8.clone())
                    .unwrap_or(value)
            };
            let box_func = self.get_or_register_extern_function(
                "haxe_box_function_ptr",
                vec![ptr_u8.clone()],
                ptr_u8.clone(),
            );
            return self
                .builder
                .build_call_direct(box_func, vec![as_ptr], ptr_u8);
        }

        if is_string || matches!(&ir_type, IrType::Ptr(_)) {
            // String or pointer type — box as HaxeString
            // haxe_box_haxestring_ptr wraps a HaxeString* pointer in a DynamicValue.
            // The actual register may be I64 (type-erased) even though the resolved type is Ptr.
            let actual_reg_type = self
                .builder
                .get_register_type(value)
                .unwrap_or(ir_type.clone());
            let as_ptr = if matches!(&actual_reg_type, IrType::Ptr(_)) {
                value
            } else {
                // i64 → *u8 cast (for type-erased string pointers)
                self.builder
                    .build_cast(value, actual_reg_type, ptr_u8.clone())
                    .unwrap_or(value)
            };
            let box_func = self.get_or_register_extern_function(
                "haxe_box_haxestring_ptr",
                vec![ptr_u8.clone()],
                ptr_u8.clone(),
            );
            self.builder
                .build_call_direct(box_func, vec![as_ptr], ptr_u8)
        } else if matches!(&ir_type, IrType::I32) {
            // Int (i32) — extend to i64 and box
            let as_i64 = self
                .builder
                .build_cast(value, IrType::I32, IrType::I64)
                .unwrap_or(value);
            let box_func = self.get_or_register_extern_function(
                "haxe_box_int_ptr",
                vec![IrType::I64],
                ptr_u8.clone(),
            );
            self.builder
                .build_call_direct(box_func, vec![as_i64], ptr_u8)
        } else if matches!(&ir_type, IrType::I64) {
            // i64 — box as int (type-erased int or fallback)
            let box_func = self.get_or_register_extern_function(
                "haxe_box_int_ptr",
                vec![IrType::I64],
                ptr_u8.clone(),
            );
            self.builder
                .build_call_direct(box_func, vec![value], ptr_u8)
        } else if matches!(&ir_type, IrType::F64) {
            let box_func = self.get_or_register_extern_function(
                "haxe_box_float_ptr",
                vec![IrType::F64],
                ptr_u8.clone(),
            );
            self.builder
                .build_call_direct(box_func, vec![value], ptr_u8)
        } else if matches!(&ir_type, IrType::Bool) {
            let box_func = self.get_or_register_extern_function(
                "haxe_box_bool_ptr",
                vec![IrType::Bool],
                ptr_u8.clone(),
            );
            self.builder
                .build_call_direct(box_func, vec![value], ptr_u8)
        } else {
            // Unknown type — can't box
            None
        }
    }

    /// Coerce a value to i64 for anonymous object field storage.
    /// Ints pass through, floats are bitcast, pointers are cast to i64.
    fn coerce_to_i64(&mut self, value: IrId, type_id: TypeId) -> Option<IrId> {
        let ir_type = self.convert_type(type_id);
        match &ir_type {
            IrType::I64 => Some(value),
            IrType::I32 | IrType::U64 | IrType::Bool => {
                self.builder.build_cast(value, ir_type.clone(), IrType::I64)
            }
            IrType::F64 => {
                // Float: bitcast f64 to i64 (preserves bits)
                self.builder.build_bitcast(value, IrType::I64)
            }
            IrType::F32 => {
                let as_f64 = self.builder.build_cast(value, IrType::F32, IrType::F64)?;
                self.builder.build_bitcast(as_f64, IrType::I64)
            }
            IrType::Ptr(_) => self.builder.build_cast(value, ir_type.clone(), IrType::I64),
            _ => self.builder.build_cast(value, ir_type.clone(), IrType::I64),
        }
    }

    /// Coerce a raw i64 value from anonymous object storage back to the target type.
    /// Inverse of coerce_to_i64.
    fn coerce_from_i64(&mut self, value: IrId, type_id: TypeId) -> Option<IrId> {
        let ir_type = self.convert_type(type_id);
        match &ir_type {
            IrType::I64 => Some(value),
            IrType::I32 | IrType::U64 | IrType::Bool => {
                self.builder.build_cast(value, IrType::I64, ir_type.clone())
            }
            IrType::F64 => {
                // i64 -> f64 bitcast (preserves bits)
                self.builder.build_bitcast(value, IrType::F64)
            }
            IrType::F32 => {
                let as_f64 = self.builder.build_bitcast(value, IrType::F64)?;
                self.builder.build_cast(as_f64, IrType::F64, IrType::F32)
            }
            IrType::Ptr(_) => self.builder.build_cast(value, IrType::I64, ir_type.clone()),
            _ => self.builder.build_cast(value, IrType::I64, ir_type.clone()),
        }
    }

    /// Map a compiler TypeId to the runtime's type_id constant.
    /// Used for anonymous object shape descriptors.
    /// Runtime type IDs: 0=Void, 1=Null, 2=Bool, 3=Int, 4=Float, 5=String
    fn runtime_type_id(&self, type_id: TypeId) -> u32 {
        use crate::tast::TypeKind;
        let type_table = self.type_table.borrow();
        match type_table.get(type_id).map(|t| &t.kind) {
            Some(TypeKind::Void) => 0,
            Some(TypeKind::Bool) => 2,
            Some(TypeKind::Int) => 3,
            Some(TypeKind::Float) => 4,
            Some(TypeKind::String) => 5,
            Some(TypeKind::Dynamic) => 5, // Dynamic matches anything
            Some(TypeKind::Class { symbol_id, .. }) => {
                // Class runtime IDs must align with MIR typedef type_id used for RTTI
                // registration and object headers.
                self.resolve_runtime_class_type_id(type_id, *symbol_id)
                    .as_raw()
                    + 1000
            }
            Some(TypeKind::Interface { .. }) => type_id.as_raw(),
            Some(TypeKind::Enum { .. }) => type_id.as_raw() + 1000,
            Some(TypeKind::TypeAlias { target_type, .. }) => {
                let target = *target_type;
                drop(type_table);
                self.runtime_type_id(target)
            }
            _ => 0, // default to void/unknown
        }
    }

    /// Resolve a TypeId through TypeAlias chains to find the underlying type.
    /// Returns the resolved TypeId (following aliases), or the original if not an alias.
    fn resolve_through_aliases(&self, type_id: TypeId) -> TypeId {
        let type_table = self.type_table.borrow();
        let mut current = type_id;
        let mut visited = HashSet::new();
        loop {
            if !visited.insert(current) {
                break;
            }
            match type_table.get(current).map(|t| &t.kind) {
                Some(TypeKind::TypeAlias { target_type, .. }) => current = *target_type,
                Some(TypeKind::Placeholder { name }) => {
                    // Try to resolve Placeholder by searching for a class with matching name
                    if let Some(name_str) = self.string_interner.get(*name) {
                        // Search for "rayzor.Bytes" → match class "Bytes" with qualified "rayzor.Bytes"
                        // Also try bare name: "rayzor.Bytes" → "Bytes"
                        let bare_name = name_str.rsplit('.').next().unwrap_or(name_str);
                        let mut found = None;
                        for (tid, ti) in type_table.iter() {
                            if let TypeKind::Class { symbol_id, .. } = &ti.kind {
                                if let Some(sym) = self.symbol_table.get_symbol(*symbol_id) {
                                    let sym_name = self.string_interner.get(sym.name).unwrap_or("");
                                    let sym_qname = sym
                                        .qualified_name
                                        .and_then(|qn| self.string_interner.get(qn));
                                    let matches = sym_qname.map_or(false, |qn| qn == name_str)
                                        || sym_name == name_str
                                        || sym_name == bare_name
                                        || sym_qname.map_or(false, |qn| qn == bare_name);
                                    if matches {
                                        found = Some(tid);
                                        break;
                                    }
                                }
                            }
                        }
                        if let Some(resolved_tid) = found {
                            current = resolved_tid;
                        } else {
                            break;
                        }
                    } else {
                        break;
                    }
                }
                _ => break,
            }
        }
        current
    }

    /// Check if `source_type` is a subclass of `target_type` by walking the extends chain.
    /// Uses SymbolId-based lookup to handle TAST/HIR TypeId mismatch.
    fn is_subclass_of(&self, source_type: TypeId, target_type: TypeId) -> bool {
        // Get target SymbolId from type_table
        let target_sym = {
            let type_table = self.type_table.borrow();
            match type_table.get(target_type).map(|ti| &ti.kind) {
                Some(TypeKind::Class { symbol_id, .. }) => *symbol_id,
                _ => return false,
            }
        };

        // Get source SymbolId and walk the class hierarchy
        let source_sym = {
            let type_table = self.type_table.borrow();
            match type_table.get(source_type).map(|ti| &ti.kind) {
                Some(TypeKind::Class { symbol_id, .. }) => *symbol_id,
                _ => return false,
            }
        };

        let mut current_sym = source_sym;
        let mut visited = HashSet::new();
        while visited.insert(current_sym) {
            // Find the class with this SymbolId in current_hir_types
            let parent_type = self.current_hir_types.values().find_map(|decl| {
                if let super::hir::HirTypeDecl::Class(class) = decl {
                    if class.symbol_id == current_sym {
                        class.extends
                    } else {
                        None
                    }
                } else {
                    None
                }
            });

            match parent_type {
                Some(parent_type_id) => {
                    // Get parent's SymbolId from type_table
                    let parent_sym = {
                        let type_table = self.type_table.borrow();
                        match type_table.get(parent_type_id).map(|ti| &ti.kind) {
                            Some(TypeKind::Class { symbol_id, .. }) => *symbol_id,
                            _ => return false,
                        }
                    };
                    if parent_sym == target_sym {
                        return true;
                    }
                    current_sym = parent_sym;
                }
                None => return false,
            }
        }
        false
    }

    fn lower_string_interpolation(&mut self, parts: &[HirStringPart]) -> Option<IrId> {
        if parts.is_empty() {
            return self.builder.build_string(String::new());
        }

        let string_ptr_ty = IrType::Ptr(Box::new(IrType::String));

        // Pre-register extern functions for type conversion and concatenation
        let concat_fn = self.get_or_register_extern_function(
            "haxe_string_concat",
            vec![string_ptr_ty.clone(), string_ptr_ty.clone()],
            string_ptr_ty.clone(),
        );

        let mut result: Option<IrId> = None;

        for part in parts {
            let part_str = match part {
                HirStringPart::Literal(s) => self.builder.build_string(s.to_string())?,
                HirStringPart::Interpolation(expr) => {
                    let expr_val = self.lower_expression(expr)?;

                    if self.expr_is_value_type_expr(expr) {
                        self.convert_value_type_to_string(expr_val)?
                    } else {
                        // Convert to string based on expression type
                        let expr_type_kind = {
                            let type_table = self.type_table.borrow();
                            type_table.get(expr.ty).map(|ti| ti.kind.clone())
                        };

                        match expr_type_kind.as_ref() {
                            Some(TypeKind::String) => expr_val, // already a string
                            Some(TypeKind::Int) => {
                                let conv_fn = self.get_or_register_extern_function(
                                    "haxe_string_from_int",
                                    vec![IrType::I64],
                                    string_ptr_ty.clone(),
                                );
                                self.builder.build_call_direct(
                                    conv_fn,
                                    vec![expr_val],
                                    string_ptr_ty.clone(),
                                )?
                            }
                            Some(TypeKind::Float) => {
                                let conv_fn = self.get_or_register_extern_function(
                                    "haxe_string_from_float",
                                    vec![IrType::F64],
                                    string_ptr_ty.clone(),
                                );
                                self.builder.build_call_direct(
                                    conv_fn,
                                    vec![expr_val],
                                    string_ptr_ty.clone(),
                                )?
                            }
                            Some(TypeKind::Bool) => {
                                let conv_fn = self.get_or_register_extern_function(
                                    "haxe_string_from_bool",
                                    vec![IrType::I32],
                                    string_ptr_ty.clone(),
                                );
                                self.builder.build_call_direct(
                                    conv_fn,
                                    vec![expr_val],
                                    string_ptr_ty.clone(),
                                )?
                            }
                            _ => {
                                // Fallback: treat as int (prints raw i64 value)
                                let conv_fn = self.get_or_register_extern_function(
                                    "haxe_string_from_int",
                                    vec![IrType::I64],
                                    string_ptr_ty.clone(),
                                );
                                self.builder.build_call_direct(
                                    conv_fn,
                                    vec![expr_val],
                                    string_ptr_ty.clone(),
                                )?
                            }
                        }
                    }
                }
            };

            result = match result {
                None => Some(part_str),
                Some(acc) => self.builder.build_call_direct(
                    concat_fn,
                    vec![acc, part_str],
                    string_ptr_ty.clone(),
                ),
            };
        }

        result
    }

    /// Declare a single TCC extern function and register it
    fn declare_tcc_extern(
        &mut self,
        name: &str,
        param_types: Vec<IrType>,
        return_type: IrType,
        dummy_id_offset: u32,
    ) -> IrFunctionId {
        use super::modules::IrExternFunction;
        use super::{CallingConvention, IrFunctionSignature, IrId, IrParameter};

        let parameters: Vec<IrParameter> = param_types
            .into_iter()
            .enumerate()
            .map(|(i, ty)| IrParameter {
                name: format!("p{}", i),
                ty,
                reg: IrId::new(0),
                by_ref: false,
            })
            .collect();

        let signature = IrFunctionSignature {
            parameters,
            return_type,
            calling_convention: CallingConvention::C,
            can_throw: false,
            type_params: vec![],
            uses_sret: false,
        };

        let func_id = self.builder.module.alloc_function_id();
        let extern_func = IrExternFunction {
            id: func_id,
            name: name.to_string(),
            symbol_id: SymbolId::from_raw(u32::MAX - 100 - dummy_id_offset),
            signature,
            source: "rayzor_runtime".to_string(),
        };
        self.builder
            .module
            .extern_functions
            .insert(func_id, extern_func);
        func_id
    }

    /// Lazily initialize TCC runtime extern function declarations
    fn ensure_tcc_runtime(&mut self) -> TccFuncIds {
        if let Some(ids) = self.tcc_func_ids {
            return ids;
        }

        let create = self.declare_tcc_extern("rayzor_tcc_create", vec![], IrType::I64, 0);
        let compile = self.declare_tcc_extern(
            "rayzor_tcc_compile",
            vec![IrType::I64, IrType::I64],
            IrType::I32,
            1,
        );
        let add_value_symbol = self.declare_tcc_extern(
            "rayzor_tcc_add_value_symbol",
            vec![IrType::I64, IrType::I64, IrType::I64],
            IrType::I64,
            2,
        );
        let relocate =
            self.declare_tcc_extern("rayzor_tcc_relocate", vec![IrType::I64], IrType::I32, 3);
        let get_symbol = self.declare_tcc_extern(
            "rayzor_tcc_get_symbol",
            vec![IrType::I64, IrType::I64],
            IrType::I64,
            4,
        );
        let delete =
            self.declare_tcc_extern("rayzor_tcc_delete", vec![IrType::I64], IrType::Void, 5);
        let call0 = self.declare_tcc_extern("rayzor_tcc_call0", vec![IrType::I64], IrType::I64, 6);
        let free_value =
            self.declare_tcc_extern("rayzor_tcc_free_value", vec![IrType::I64], IrType::Void, 7);
        let string_ptr = IrType::Ptr(Box::new(IrType::String));
        let string_replace = self.declare_tcc_extern(
            "haxe_string_replace",
            vec![string_ptr.clone(), string_ptr.clone(), string_ptr.clone()],
            string_ptr,
            8,
        );

        let add_framework = self.declare_tcc_extern(
            "rayzor_tcc_add_framework",
            vec![IrType::I64, IrType::I64],
            IrType::I32,
            9,
        );
        let add_include_path = self.declare_tcc_extern(
            "rayzor_tcc_add_include_path",
            vec![IrType::I64, IrType::I64],
            IrType::I32,
            10,
        );
        let add_file = self.declare_tcc_extern(
            "rayzor_tcc_add_file",
            vec![IrType::I64, IrType::I64],
            IrType::I32,
            11,
        );
        let add_clib = self.declare_tcc_extern(
            "rayzor_tcc_add_clib",
            vec![IrType::I64, IrType::I64],
            IrType::I32,
            12,
        );

        let ids = TccFuncIds {
            create,
            compile,
            add_value_symbol,
            relocate,
            get_symbol,
            delete,
            call0,
            free_value,
            string_replace,
            add_framework,
            add_include_path,
            add_file,
            add_clib,
        };
        self.tcc_func_ids = Some(ids);
        ids
    }

    /// Lower __c__("C code {0} {1}", arg0, arg1) to TCC JIT compilation + execution
    fn lower_inline_code(
        &mut self,
        target: &str,
        code_expr: &HirExpr,
        args: &[HirExpr],
    ) -> Option<IrId> {
        if target != "__c__" {
            self.errors.push(LoweringError {
                message: format!(
                    "Unsupported inline code target: '{}' (only '__c__' is supported)",
                    target
                ),
                location: code_expr.source_location,
            });
            return None;
        }

        let tcc = self.ensure_tcc_runtime();
        let create_id = tcc.create;
        let compile_id = tcc.compile;
        let add_value_symbol_id = tcc.add_value_symbol;
        let free_value_id = tcc.free_value;
        let relocate_id = tcc.relocate;
        let get_symbol_id = tcc.get_symbol;
        let delete_id = tcc.delete;
        let call0_id = tcc.call0;
        let replace_id = tcc.string_replace;

        // Lower the code expression (string literal or concat like cdef() + "...")
        let code_reg = self.lower_expression(code_expr)?;

        // Lower all argument expressions
        let mut arg_regs = Vec::new();
        for arg in args {
            if let Some(reg) = self.lower_expression(arg) {
                arg_regs.push(reg);
            }
        }

        // Auto-inject module-local @:cstruct typedefs into TCC context
        // Use already-cached cstruct_layouts (populated by field accesses, constructors, cdef() calls)
        let mut cstruct_prefix = String::new();
        {
            let mut seen_typedefs = std::collections::HashSet::new();
            let layouts: Vec<_> = self.cstruct_layouts.values().cloned().collect();
            for layout in &layouts {
                for dep in &layout.dep_cdefs {
                    if seen_typedefs.insert(dep.clone()) {
                        cstruct_prefix.push_str(dep);
                    }
                }
                if seen_typedefs.insert(layout.own_cdef.clone()) {
                    cstruct_prefix.push_str(&layout.own_cdef);
                }
            }
        }

        // Build prefix: cstruct typedefs + extern declarations, do {N} -> __argN substitution
        let string_ptr_ty = IrType::Ptr(Box::new(IrType::String));
        let has_prefix = !cstruct_prefix.is_empty() || !arg_regs.is_empty();
        let final_code_reg = if !has_prefix {
            code_reg
        } else {
            // Replace {0} -> __arg0, {1} -> __arg1, etc. in the code string
            let mut current_code = code_reg;
            for i in 0..arg_regs.len() {
                let needle = self
                    .builder
                    .build_const(IrValue::String(format!("{{{}}}", i)))?;
                let replacement = self
                    .builder
                    .build_const(IrValue::String(format!("__arg{}", i)))?;
                current_code = self.builder.build_call_direct(
                    replace_id,
                    vec![current_code, needle, replacement],
                    string_ptr_ty.clone(),
                )?;
            }

            // Build compile-time prefix: cstruct typedefs + extern long declarations
            let mut prefix = cstruct_prefix;
            for i in 0..arg_regs.len() {
                prefix.push_str(&format!("extern long __arg{};\n", i));
            }
            let prefix_reg = self.builder.build_const(IrValue::String(prefix))?;

            // Concat: prefix + substituted_code via string_concat runtime
            let concat_func_id = self.register_stdlib_mir_forward_ref(
                "string_concat",
                vec![string_ptr_ty.clone(), string_ptr_ty.clone()],
                string_ptr_ty.clone(),
            );
            self.builder.build_call_direct(
                concat_func_id,
                vec![prefix_reg, current_code],
                string_ptr_ty.clone(),
            )?
        };

        // Collect @:frameworks, @:cInclude, @:cSource from module-local types and current function
        let add_framework_id = tcc.add_framework;
        let add_include_path_id = tcc.add_include_path;
        let add_file_id = tcc.add_file;
        let add_clib_id = tcc.add_clib;
        let mut framework_names: Vec<String> = Vec::new();
        let mut include_paths: Vec<String> = Vec::new();
        let mut source_files: Vec<String> = Vec::new();
        let mut clib_names: Vec<String> = Vec::new();
        {
            let mut seen_fw = std::collections::HashSet::new();
            let mut seen_inc = std::collections::HashSet::new();
            let mut seen_src = std::collections::HashSet::new();
            let mut seen_lib = std::collections::HashSet::new();

            // Collect metadata from all relevant symbols
            let mut sym_ids: Vec<SymbolId> = Vec::new();
            for (_type_id, type_decl) in self.current_hir_types {
                if let crate::ir::hir::HirTypeDecl::Class(c) = type_decl {
                    sym_ids.push(c.symbol_id);
                }
            }
            if let Some(func_sym_id) = self.current_function_symbol {
                sym_ids.push(func_sym_id);
            }

            for sid in &sym_ids {
                if let Some(sym) = self.symbol_table.get_symbol(*sid) {
                    if let Some(ref fws) = sym.frameworks {
                        for f in fws {
                            if let Some(n) = self.string_interner.get(*f) {
                                if seen_fw.insert(n.to_string()) {
                                    framework_names.push(n.to_string());
                                }
                            }
                        }
                    }
                    if let Some(ref incs) = sym.c_includes {
                        for i in incs {
                            if let Some(n) = self.string_interner.get(*i) {
                                if seen_inc.insert(n.to_string()) {
                                    include_paths.push(n.to_string());
                                }
                            }
                        }
                    }
                    if let Some(ref srcs) = sym.c_sources {
                        for s in srcs {
                            if let Some(n) = self.string_interner.get(*s) {
                                if seen_src.insert(n.to_string()) {
                                    source_files.push(n.to_string());
                                }
                            }
                        }
                    }
                    if let Some(ref libs) = sym.c_libs {
                        for l in libs {
                            if let Some(n) = self.string_interner.get(*l) {
                                if seen_lib.insert(n.to_string()) {
                                    clib_names.push(n.to_string());
                                }
                            }
                        }
                    }
                }
            }
        }

        // 1. state = rayzor_tcc_create()
        let state = self
            .builder
            .build_call_direct(create_id, vec![], IrType::I64)?;

        // 1b. Auto-load @:cInclude paths
        for path in &include_paths {
            let path_reg = self.builder.build_const(IrValue::String(path.clone()))?;
            self.builder
                .build_call_direct(add_include_path_id, vec![state, path_reg], IrType::I32);
        }

        // 1c. Auto-load @:frameworks into TCC context
        for fw_name in &framework_names {
            let name_reg = self.builder.build_const(IrValue::String(fw_name.clone()))?;
            self.builder
                .build_call_direct(add_framework_id, vec![state, name_reg], IrType::I32);
        }

        // 1d. Auto-add @:cSource files (compiled before main code so symbols are available)
        for src_path in &source_files {
            let path_reg = self
                .builder
                .build_const(IrValue::String(src_path.clone()))?;
            self.builder
                .build_call_direct(add_file_id, vec![state, path_reg], IrType::I32);
        }

        // 1e. Auto-load @:clib libraries via pkg-config discovery
        for lib_name in &clib_names {
            let name_reg = self
                .builder
                .build_const(IrValue::String(lib_name.clone()))?;
            self.builder
                .build_call_direct(add_clib_id, vec![state, name_reg], IrType::I32);
        }

        // 2. rayzor_tcc_compile(state, code)
        self.builder
            .build_call_direct(compile_id, vec![state, final_code_reg], IrType::I32);

        // 3. Register arg values via add_value_symbol (heap-allocates each value so TCC can read it)
        //    Must be after compile, before relocate (resolves extern symbols at link time)
        let mut value_addrs = Vec::new();
        for (i, arg_reg) in arg_regs.iter().enumerate() {
            let name_reg = self
                .builder
                .build_const(IrValue::String(format!("__arg{}", i)))?;
            let addr = self.builder.build_call_direct(
                add_value_symbol_id,
                vec![state, name_reg, *arg_reg],
                IrType::I64,
            )?;
            value_addrs.push(addr);
        }

        // 4. rayzor_tcc_relocate(state)
        self.builder
            .build_call_direct(relocate_id, vec![state], IrType::I32);

        // 5. entry = rayzor_tcc_get_symbol(state, "__entry__")
        let entry_name = self
            .builder
            .build_const(IrValue::String("__entry__".to_string()))?;
        let entry_addr =
            self.builder
                .build_call_direct(get_symbol_id, vec![state, entry_name], IrType::I64)?;

        // 6. result = rayzor_tcc_call0(entry_addr)
        let result = self
            .builder
            .build_call_direct(call0_id, vec![entry_addr], IrType::I64);

        // 7. rayzor_tcc_delete(state)
        self.builder
            .build_call_direct(delete_id, vec![state], IrType::Void);

        // 8. Free heap-allocated value symbols
        for addr in &value_addrs {
            self.builder
                .build_call_direct(free_value_id, vec![*addr], IrType::Void);
        }

        result
    }

    fn lower_global(&mut self, symbol: SymbolId, global: &HirGlobal) {
        // Allocate a global ID
        let global_id = self.builder.module.alloc_global_id();

        // Convert initialization expression to IrValue if present
        // For now, we only support constant expressions
        let initializer = if let Some(init_expr) = &global.init {
            // Try to evaluate as constant expression
            match &init_expr.kind {
                HirExprKind::Literal(lit) => {
                    match lit {
                        HirLiteral::Bool(b) => Some(IrValue::Bool(*b)),
                        HirLiteral::Int(i) => Some(IrValue::I64(*i)),
                        HirLiteral::Float(f) => Some(IrValue::F64(*f)),
                        HirLiteral::String(s) => {
                            // String literals are added to string pool
                            // and referenced by their pool ID
                            let string_id = self.builder.module.string_pool.add(s.to_string());
                            // Store the string pool ID as an integer value
                            // The runtime will look up the actual string from the pool
                            Some(IrValue::I32(string_id as i32))
                        }
                        HirLiteral::Regex { .. } => {
                            // Regex needs special handling
                            None
                        }
                    }
                }
                _ => {
                    // Non-constant initialization - needs runtime evaluation
                    // Collect for __init__ function generation
                    self.dynamic_globals.push((symbol, init_expr.clone()));
                    // Use Undef as placeholder - will be initialized at runtime
                    Some(IrValue::Undef)
                }
            }
        } else {
            // No initializer - use Undef
            Some(IrValue::Undef)
        };

        // Create the global variable
        // Note: Using placeholder name based on symbol ID since HirGlobal doesn't store name
        let ir_global = IrGlobal {
            id: global_id,
            name: format!("global_{}", symbol.as_raw()),
            symbol_id: symbol,
            ty: IrType::Any, // TODO: Convert TypeId to IrType properly
            initializer,
            mutable: !global.is_const,
            linkage: Linkage::Internal, // TODO: Determine linkage from visibility
            alignment: None,
            source_location: IrSourceLocation::unknown(),
        };

        // Add to module
        self.builder.module.add_global(ir_global);

        // Store the mapping so we can look up globals by symbol ID later
        self.global_symbol_map.insert(symbol, global_id);
        debug!("[GLOBAL] Registered global {:?} -> {:?}", symbol, global_id);

        // TODO: For non-constant initializers, create an __init__ function
        // that runs at module load time to initialize the global
    }

    /// Try to evaluate an expression as a constant value for static field initialization
    fn try_evaluate_constant_init(&self, init_expr: &HirExpr) -> Option<IrValue> {
        match &init_expr.kind {
            HirExprKind::Literal(lit) => {
                match lit {
                    HirLiteral::Bool(b) => Some(IrValue::Bool(*b)),
                    HirLiteral::Int(i) => Some(IrValue::I64(*i)),
                    HirLiteral::Float(f) => Some(IrValue::F64(*f)),
                    HirLiteral::String(_) => None, // Strings need special handling
                    HirLiteral::Regex { .. } => None,
                }
            }
            // For non-constant expressions, return None
            // The actual initialization will happen at runtime
            _ => None,
        }
    }

    /// Build class vtables by analyzing override relationships.
    /// Called after all type metadata is registered but before function body lowering.
    fn build_class_vtables(&mut self) {
        if self.override_methods.is_empty() {
            return;
        }

        // Step 1: For each override, trace up the parent chain to find the base class
        // that originally defines the method. Mark that base method as needing a virtual slot.
        let mut base_virtual_methods: BTreeSet<(SymbolId, InternedString)> = BTreeSet::new();

        for (child_sym, method_name) in self.override_methods.clone() {
            // Walk up the parent chain to find the topmost class defining this method
            let mut defining_class = None;
            let mut current = child_sym;
            while let Some(&parent) = self.class_parent_map.get(&current) {
                if self
                    .class_method_by_name
                    .contains_key(&(parent, method_name))
                {
                    defining_class = Some(parent);
                }
                current = parent;
            }
            if let Some(base) = defining_class {
                base_virtual_methods.insert((base, method_name));
            }
        }

        // Step 2: Assign virtual slots for each base class
        for (base_class, method_name) in &base_virtual_methods {
            let slots = self.class_virtual_slots.entry(*base_class).or_default();
            if !slots.iter().any(|(n, _)| *n == *method_name) {
                let slot_idx = slots.len() as u32;
                slots.push((*method_name, slot_idx));
            }
        }

        // Step 3: Build vtables for all classes in hierarchies with virtual methods.
        // Process topologically (parents before children).
        let mut classes_to_process: BTreeSet<SymbolId> = BTreeSet::new();
        // Include all classes that define or override virtual methods
        for (base_class, _) in &base_virtual_methods {
            classes_to_process.insert(*base_class);
        }
        for (child_sym, _) in &self.override_methods {
            classes_to_process.insert(*child_sym);
        }
        // Also include intermediate classes in the hierarchy
        for (child, _) in self.override_methods.clone() {
            let mut current = child;
            while let Some(&parent) = self.class_parent_map.get(&current) {
                classes_to_process.insert(parent);
                current = parent;
            }
        }
        // Include ALL subclasses of classes with vtables — leaf classes that
        // inherit (but don't override) virtual methods still need vtable entries
        // so that haxe_vtable_lookup finds them by type_id at runtime.
        let mut changed = true;
        while changed {
            changed = false;
            for (child, parent) in self.class_parent_map.clone() {
                if classes_to_process.contains(&parent) && !classes_to_process.contains(&child) {
                    classes_to_process.insert(child);
                    changed = true;
                }
            }
        }

        let mut processed: BTreeSet<SymbolId> = BTreeSet::new();
        let mut remaining: Vec<SymbolId> = classes_to_process.into_iter().collect();
        let max_iters = remaining.len() + 1;
        for _ in 0..max_iters {
            if remaining.is_empty() {
                break;
            }
            let mut next_remaining = Vec::new();
            for cls in remaining {
                let parent_ready = self
                    .class_parent_map
                    .get(&cls)
                    .map_or(true, |p| processed.contains(p));
                if parent_ready {
                    self.build_vtable_for_class(cls);
                    processed.insert(cls);
                } else {
                    next_remaining.push(cls);
                }
            }
            remaining = next_remaining;
        }
        for cls in remaining {
            self.build_vtable_for_class(cls);
        }

        // Step 4: Populate virtual_dispatch_info for call sites.
        // Map ALL method SymbolIds in virtual hierarchies (base + overrides) to their slot.
        // This ensures calls through both base and derived types dispatch through the vtable.
        for (class_sym, slots) in self.class_virtual_slots.clone() {
            for (method_name, slot_idx) in &slots {
                if let Some(&method_sym) = self.class_method_by_name.get(&(class_sym, *method_name))
                {
                    self.virtual_dispatch_info
                        .insert(method_sym, (*slot_idx, class_sym));
                }
            }
        }
    }

    /// Build the vtable for a single class — inherits parent's slots and uses
    /// the most-derived implementation for each slot.
    fn build_vtable_for_class(&mut self, class_sym: SymbolId) {
        // Inherit parent's virtual slots
        let parent_slots = self
            .class_parent_map
            .get(&class_sym)
            .and_then(|parent| self.class_virtual_slots.get(parent))
            .cloned()
            .unwrap_or_default();

        let mut slots = parent_slots;

        // Add any new virtual slots defined at this class level
        if let Some(own_slots) = self.class_virtual_slots.get(&class_sym).cloned() {
            for (name, _) in own_slots {
                if !slots.iter().any(|(n, _)| *n == name) {
                    let idx = slots.len() as u32;
                    slots.push((name, idx));
                }
            }
        }

        if slots.is_empty() {
            return;
        }

        // Build vtable entries: for each slot, find the most-derived implementation
        let mut vtable = Vec::new();
        for (method_name, _) in &slots {
            let method_sym = self
                .class_method_by_name
                .get(&(class_sym, *method_name))
                .copied()
                .or_else(|| {
                    // Walk parent chain to find inherited implementation
                    let mut current = class_sym;
                    while let Some(&parent) = self.class_parent_map.get(&current) {
                        if let Some(&sym) = self.class_method_by_name.get(&(parent, *method_name)) {
                            return Some(sym);
                        }
                        current = parent;
                    }
                    None
                });

            if let Some(sym) = method_sym {
                vtable.push(sym);
            }
        }

        if !vtable.is_empty() {
            self.class_virtual_slots.insert(class_sym, slots);
            self.class_vtables.insert(class_sym, vtable);
        }
    }

    fn register_type_metadata(&mut self, type_id: TypeId, type_decl: &HirTypeDecl) {
        // Register type definitions in MIR for runtime type information
        // This metadata is used for:
        // - Enum discriminant values (for pattern matching)
        // - Struct field layouts (for field access)
        // - Interface method tables (for dynamic dispatch)
        // - Type checking at runtime

        match type_decl {
            HirTypeDecl::Class(class) => {
                self.register_class_metadata(type_id, class);
            }
            HirTypeDecl::Interface(interface) => {
                self.register_interface_metadata(type_id, interface);
            }
            HirTypeDecl::Enum(enum_decl) => {
                self.register_enum_metadata(type_id, enum_decl);
            }
            HirTypeDecl::Abstract(abstract_decl) => {
                self.register_abstract_metadata(type_id, abstract_decl);
            }
            HirTypeDecl::TypeAlias(alias) => {
                self.register_alias_metadata(type_id, alias);
            }
        }
    }

    fn register_enum_metadata(&mut self, _type_id: TypeId, enum_decl: &HirEnum) {
        // Register enum type with discriminant values
        let typedef_id = self.builder.module.alloc_typedef_id();

        // Use the symbol's type_id for consistency with trace call sites
        let sym_type_id = self
            .symbol_table
            .get_symbol(enum_decl.symbol_id)
            .map(|sym| sym.type_id)
            .unwrap_or(_type_id);

        let enum_name = self
            .string_interner
            .get(enum_decl.name)
            .unwrap_or("<unknown>")
            .to_string();

        let mut variants = Vec::new();
        for (i, variant) in enum_decl.variants.iter().enumerate() {
            // Use explicit discriminant if provided, otherwise use index
            let discriminant = variant.discriminant.unwrap_or(i as i32) as i64;

            let variant_name = self
                .string_interner
                .get(variant.name)
                .unwrap_or("<unknown>")
                .to_string();

            // Convert variant fields to IR fields with resolved types
            let fields: Vec<IrField> = variant
                .fields
                .iter()
                .map(|field| {
                    let field_name = self
                        .string_interner
                        .get(field.name)
                        .unwrap_or("<unknown>")
                        .to_string();
                    IrField {
                        name: field_name,
                        ty: self.convert_type(field.ty),
                        offset: None,
                    }
                })
                .collect();

            variants.push(IrEnumVariant {
                name: variant_name,
                discriminant,
                fields,
            });
        }

        let typedef = IrTypeDef {
            id: typedef_id,
            name: enum_name,
            type_id: sym_type_id,
            definition: IrTypeDefinition::Enum {
                variants,
                discriminant_type: IrType::I32,
            },
            source_location: IrSourceLocation::unknown(),
            super_type_id: None,
        };

        self.builder.module.add_type(typedef);
    }

    /// Recursively collect fields from parent classes
    fn collect_inherited_fields(
        &mut self,
        parent_type: Option<TypeId>,
        child_type: TypeId,
        fields: &mut Vec<IrField>,
        field_index: &mut u32,
    ) {
        if let Some(parent_type_id) = parent_type {
            // Try direct lookup first
            if let Some(HirTypeDecl::Class(parent_class)) =
                self.current_hir_types.get(&parent_type_id)
            {
                self.add_parent_fields(parent_class, child_type, fields, field_index);
            } else {
                // TypeId mismatch - the extends field might use instance type while
                // hir_module.types uses declaration type. Search by matching class type.

                // Get the type definition to find the class symbol
                if let Some(parent_type_def) = self.type_table.borrow().get(parent_type_id) {
                    if let crate::tast::TypeKind::Class {
                        symbol_id: parent_symbol,
                        ..
                    } = &parent_type_def.kind
                    {
                        // Find the HIR class by symbol_id
                        for (decl_type_id, type_decl) in self.current_hir_types.iter() {
                            if let HirTypeDecl::Class(class) = type_decl {
                                if class.symbol_id == *parent_symbol {
                                    self.add_parent_fields(class, child_type, fields, field_index);
                                    return;
                                }
                            }
                        }

                        // Cross-module parent class fallback:
                        // Collect parent fields from field_index_map (seeded from external modules).
                        // These already include inherited fields from grandparent classes.
                        let parent_sym = *parent_symbol;
                        let mut parent_fields: Vec<(SymbolId, u32)> = Vec::new();
                        for (field_sym, (class_ty, idx)) in &self.field_index_map {
                            if *class_ty == parent_type_id
                                || self.class_type_to_symbol.get(class_ty) == Some(&parent_sym)
                            {
                                parent_fields.push((*field_sym, *idx));
                            }
                        }
                        parent_fields.sort_by_key(|(_, idx)| *idx);

                        for (field_sym, _orig_idx) in &parent_fields {
                            let field_name = self
                                .symbol_table
                                .get_symbol(*field_sym)
                                .and_then(|s| self.string_interner.get(s.name))
                                .unwrap_or("<unknown>")
                                .to_string();
                            let field_ir_type = self
                                .symbol_table
                                .get_symbol(*field_sym)
                                .map(|s| self.convert_type(s.type_id))
                                .unwrap_or(IrType::I64);

                            // Re-map this field to the child class with correct index
                            self.field_index_map
                                .insert(*field_sym, (child_type, *field_index));

                            fields.push(IrField {
                                name: field_name,
                                ty: field_ir_type,
                                offset: None,
                            });

                            *field_index += 1;
                        }
                        return;
                    }
                }
            }
        }
    }

    /// Collect parent instance fields for derive codegen (PartialEq/PartialOrd/Hash).
    /// Builds a simple (SymbolId, TypeId, gep_index) list by walking the parent chain.
    fn collect_parent_instance_fields(
        &self,
        parent_type_id: TypeId,
        fields: &mut Vec<(SymbolId, TypeId, u32)>,
        idx: &mut u32,
    ) {
        if let Some(HirTypeDecl::Class(parent_class)) = self.current_hir_types.get(&parent_type_id)
        {
            // Recurse to grandparent first
            if let Some(gp_ty) = parent_class.extends {
                self.collect_parent_instance_fields(gp_ty, fields, idx);
            }
            // Then parent's own fields
            for field in &parent_class.fields {
                if !field.is_static {
                    if let Some(ref prop) = field.property_access {
                        if !matches!(prop.getter, crate::tast::PropertyAccessor::Default) {
                            continue;
                        }
                    }
                    fields.push((field.symbol_id, field.ty, *idx));
                    *idx += 1;
                }
            }
        }
    }

    /// Add parent class fields to the field list
    fn add_parent_fields(
        &mut self,
        parent_class: &HirClass,
        child_type: TypeId,
        fields: &mut Vec<IrField>,
        field_index: &mut u32,
    ) {
        // First, recursively collect grandparent fields
        self.collect_inherited_fields(parent_class.extends, child_type, fields, field_index);

        // Then add parent's own fields
        let parent_class_name = self
            .symbol_table
            .get_symbol(parent_class.symbol_id)
            .and_then(|sym| sym.qualified_name.and_then(|n| self.string_interner.get(n)))
            .or_else(|| self.string_interner.get(parent_class.name))
            .unwrap_or("<unknown>")
            .to_string();
        for parent_field in &parent_class.fields {
            // Skip static fields — they're globals, not instance fields
            if parent_field.is_static {
                continue;
            }

            // Skip property fields with non-Default getters (no backing storage)
            if let Some(ref prop) = parent_field.property_access {
                if !matches!(prop.getter, crate::tast::PropertyAccessor::Default) {
                    continue;
                }
            }

            // Map parent field symbol to child class's type with the correct index
            self.field_index_map
                .insert(parent_field.symbol_id, (child_type, *field_index));
            self.field_class_names
                .insert(parent_field.symbol_id, parent_class_name.clone());

            fields.push(IrField {
                name: self
                    .string_interner
                    .get(parent_field.name)
                    .unwrap_or("<unknown>")
                    .to_string(),
                ty: self.convert_type(parent_field.ty),
                offset: None,
            });

            *field_index += 1;
        }
    }

    fn register_class_metadata(&mut self, type_id: TypeId, class: &HirClass) {
        // Store class TypeId → SymbolId mapping (survives type_table overwrites)
        self.class_type_to_symbol.insert(type_id, class.symbol_id);

        // Register class as struct type
        let typedef_id = self.builder.module.alloc_typedef_id();

        let mut fields = Vec::new();
        // Index 0 is reserved for the object header (__type_id: i64)
        // This enables runtime type identification for downcasting, Dynamic field access, Type.getClass()
        fields.push(IrField {
            name: "__type_id".to_string(),
            ty: IrType::I64,
            offset: None,
        });
        let mut field_index = 1u32; // User fields start at index 1

        // Collect all inherited fields from parent classes (recursively)
        self.collect_inherited_fields(class.extends, type_id, &mut fields, &mut field_index);

        // Then add this class's own fields

        for field in &class.fields {
            // Static fields should be stored as globals, not instance fields
            if field.is_static {
                // Register static field as a global
                let global_id = self.builder.module.alloc_global_id();
                let field_name = self.string_interner.get(field.name).unwrap_or("<unknown>");
                let class_name = self.string_interner.get(class.name).unwrap_or("<unknown>");

                // Get initializer value if it's a constant
                let initializer = if let Some(ref init_expr) = field.init {
                    // Try to evaluate as constant
                    self.try_evaluate_constant_init(init_expr)
                } else {
                    None
                };

                let ir_global = IrGlobal {
                    id: global_id,
                    name: format!("{}.{}", class_name, field_name),
                    symbol_id: field.symbol_id,
                    ty: self.convert_type(field.ty),
                    initializer,
                    mutable: !field.is_final,
                    linkage: Linkage::Internal,
                    alignment: None,
                    source_location: IrSourceLocation::unknown(),
                };

                self.builder.module.add_global(ir_global);
                self.global_symbol_map.insert(field.symbol_id, global_id);
                debug!(
                    "[STATIC FIELD] Registered static field {}.{} ({:?}) as global {:?}",
                    class_name, field_name, field.symbol_id, global_id
                );
                continue; // Don't add to instance fields
            }

            // Store property accessor info if this is a property with custom getters/setters
            if let Some(ref property_info) = field.property_access {
                self.property_access_map
                    .insert(field.symbol_id, property_info.clone());

                // Properties with non-Default getters have no backing storage —
                // skip field_index_map and struct layout for them.
                // But still record the class name for BLADE cache serialization
                // so the property accessor can be restored from cache.
                if !matches!(property_info.getter, crate::tast::PropertyAccessor::Default) {
                    let class_name_str = self
                        .symbol_table
                        .get_symbol(class.symbol_id)
                        .and_then(|sym| {
                            sym.qualified_name.and_then(|n| self.string_interner.get(n))
                        })
                        .or_else(|| self.string_interner.get(class.name))
                        .unwrap_or("<unknown>");
                    self.field_class_names
                        .insert(field.symbol_id, class_name_str.to_string());
                    continue;
                }
            }

            // Store field index mapping for field access lowering (instance fields only)
            {
                let fn_str = self.string_interner.get(field.name).unwrap_or("?");
                let cn_str = self.string_interner.get(class.name).unwrap_or("?");
                if cn_str.contains("Constraint") || cn_str.contains("Scale") || cn_str.contains("Binary") {
                }
            }
            self.field_index_map
                .insert(field.symbol_id, (type_id, field_index));

            // Store qualified class name for BLADE cache serialization
            let class_name_str = self
                .symbol_table
                .get_symbol(class.symbol_id)
                .and_then(|sym| sym.qualified_name.and_then(|n| self.string_interner.get(n)))
                .or_else(|| self.string_interner.get(class.name))
                .unwrap_or("<unknown>");
            self.field_class_names
                .insert(field.symbol_id, class_name_str.to_string());

            fields.push(IrField {
                name: self
                    .string_interner
                    .get(field.name)
                    .unwrap_or("<unknown>")
                    .to_string(),
                ty: self.convert_type(field.ty),
                offset: None,
            });

            field_index += 1;
        }

        let typedef = IrTypeDef {
            id: typedef_id,
            name: self
                .string_interner
                .get(class.name)
                .unwrap_or("<unknown>")
                .to_string(),
            type_id,
            definition: IrTypeDefinition::Struct {
                fields,
                packed: false,
            },
            source_location: IrSourceLocation::unknown(),
            super_type_id: class.extends,
        };

        self.builder.module.add_type(typedef);

        // Record allocation size: field_index is the next available index,
        // so total slots = field_index (includes header at index 0).
        let alloc_size = (field_index as u64 * 8).max(16);
        self.class_alloc_sizes.insert(type_id, alloc_size);
        // Also store by qualified class name for cross-compilation-context lookups.
        // TypeIds are unstable across compilation units, but class names are stable.
        let class_name_for_alloc = self
            .symbol_table
            .get_symbol(class.symbol_id)
            .and_then(|sym| sym.qualified_name.and_then(|n| self.string_interner.get(n)))
            .or_else(|| self.string_interner.get(class.name))
            .unwrap_or("<unknown>");
        self.class_alloc_sizes_by_name
            .insert(class_name_for_alloc.to_string(), alloc_size);

        // Build interface vtables for each implemented interface AND their
        // transitive parent interfaces. For each interface method, find the
        // matching class method by name.
        //
        // Collect all interface symbols (direct + transitive parents)
        let mut all_iface_symbols: Vec<SymbolId> = Vec::new();
        for &iface_type_id in &class.implements {
            let iface_symbol = {
                let type_table = self.type_table.borrow();
                type_table.get(iface_type_id).and_then(|t| {
                    if let TypeKind::Interface { symbol_id, .. } = &t.kind {
                        Some(*symbol_id)
                    } else {
                        None
                    }
                })
            };
            if let Some(iface_sym) = iface_symbol {
                // Add this interface
                if !all_iface_symbols.contains(&iface_sym) {
                    all_iface_symbols.push(iface_sym);
                }
                // Recursively add parent interfaces
                let mut stack = vec![iface_sym];
                while let Some(current) = stack.pop() {
                    if let Some(parents) = self.interface_extends.get(&current).cloned() {
                        for parent in parents {
                            if !all_iface_symbols.contains(&parent) {
                                all_iface_symbols.push(parent);
                                stack.push(parent);
                            }
                        }
                    }
                }
            }
        }

        // Build vtable for each interface (direct and inherited)
        for iface_sym in all_iface_symbols {
            if let Some(method_names) = self.interface_method_names.get(&iface_sym).cloned() {
                let mut vtable_entries = Vec::new();
                for iface_method_name in &method_names {
                    // Find the class method that matches this interface method name
                    let class_method_sym = class
                        .methods
                        .iter()
                        .find(|m| m.function.name == *iface_method_name)
                        .map(|m| m.function.symbol_id);

                    if let Some(method_sym) = class_method_sym {
                        vtable_entries.push(method_sym);
                    }
                }
                self.interface_vtables
                    .insert((class.symbol_id, iface_sym), vtable_entries);
            }
        }

        // Inherit interface vtables from parent class.
        // If a parent implements IDrawable, Button (which extends Widget) also implements IDrawable.
        // Build vtables for inherited interfaces using the child's methods (which may override).
        if let Some(extends_type_id) = class.extends {
            let parent_symbol = {
                let type_table = self.type_table.borrow();
                type_table.get(extends_type_id).and_then(|t| {
                    if let TypeKind::Class { symbol_id, .. } = &t.kind {
                        Some(*symbol_id)
                    } else {
                        None
                    }
                })
            };
            if let Some(parent_sym) = parent_symbol {
                // Find all interfaces the parent implements
                let parent_iface_keys: Vec<(SymbolId, SymbolId)> = self
                    .interface_vtables
                    .keys()
                    .filter(|(cs, _)| *cs == parent_sym)
                    .cloned()
                    .collect();
                for (_, iface_sym) in parent_iface_keys {
                    // Skip if child already has a vtable for this interface
                    if self
                        .interface_vtables
                        .contains_key(&(class.symbol_id, iface_sym))
                    {
                        continue;
                    }
                    // Build vtable using child's methods (with overrides) or parent's vtable entry
                    if let Some(method_names) = self.interface_method_names.get(&iface_sym).cloned()
                    {
                        let parent_vtable = self
                            .interface_vtables
                            .get(&(parent_sym, iface_sym))
                            .cloned()
                            .unwrap_or_default();
                        let mut vtable_entries = Vec::new();
                        for (i, iface_method_name) in method_names.iter().enumerate() {
                            // Prefer child's own method (override)
                            let child_method = class
                                .methods
                                .iter()
                                .find(|m| m.function.name == *iface_method_name)
                                .map(|m| m.function.symbol_id);
                            if let Some(sym) = child_method {
                                vtable_entries.push(sym);
                            } else if i < parent_vtable.len() {
                                // Fall back to parent's vtable entry
                                vtable_entries.push(parent_vtable[i]);
                            }
                        }
                        self.interface_vtables
                            .insert((class.symbol_id, iface_sym), vtable_entries);
                    }
                }
            }
        }

        // Register class method symbols for iterator protocol lookup
        for method in &class.methods {
            self.class_method_symbols.insert(
                (class.symbol_id, method.function.name),
                method.function.symbol_id,
            );
        }

        // Record method names and overrides for virtual dispatch
        for method in &class.methods {
            self.class_method_by_name.insert(
                (class.symbol_id, method.function.name),
                method.function.symbol_id,
            );
            if method.is_override {
                self.override_methods
                    .insert((class.symbol_id, method.function.name));
            }
        }

        // Record parent class relationship
        if let Some(extends_type_id) = class.extends {
            let parent_symbol = {
                let type_table = self.type_table.borrow();
                type_table.get(extends_type_id).and_then(|t| {
                    if let TypeKind::Class { symbol_id, .. } = &t.kind {
                        Some(*symbol_id)
                    } else {
                        None
                    }
                })
            };
            if let Some(parent_sym) = parent_symbol {
                self.class_parent_map.insert(class.symbol_id, parent_sym);
            }
        }

        // Populate derive trait sets from HirClass metadata
        {
            use crate::tast::DerivedTrait;
            for trait_ in &class.derived_traits {
                match trait_ {
                    DerivedTrait::PartialEq | DerivedTrait::Eq => {
                        self.derive_partial_eq_classes.insert(class.symbol_id);
                    }
                    DerivedTrait::PartialOrd | DerivedTrait::Ord => {
                        self.derive_partial_ord_classes.insert(class.symbol_id);
                    }
                    DerivedTrait::Hash => {
                        self.derive_hash_classes.insert(class.symbol_id);
                    }
                    DerivedTrait::Clone => {
                        self.derive_clone_classes.insert(class.symbol_id);
                    }
                    DerivedTrait::Copy => {
                        self.derive_copy_classes.insert(class.symbol_id);
                    }
                    DerivedTrait::Drop => {
                        self.derive_drop_classes.insert(class.symbol_id);
                    }
                    DerivedTrait::Debug => {
                        self.derive_debug_classes.insert(class.symbol_id);
                        // Check for @:debugFormat("pattern") on the class
                        if let Some(ref fmt) = class.debug_format {
                            self.debug_format_strings
                                .insert(class.symbol_id, fmt.clone());
                        }
                    }
                    DerivedTrait::Default => {
                        self.derive_default_classes.insert(class.symbol_id);
                    }
                    _ => {}
                }
            }

            // Check for @:manualDrop metadata
            for attr in &class.metadata {
                if let Some(attr_name) = self.string_interner.get(attr.name) {
                    if attr_name == "manualDrop" {
                        self.manual_drop_classes.insert(class.symbol_id);
                    }
                }
            }

            // Build instance field list for derive codegen (non-static fields only)
            let needs_field_list = self.derive_partial_eq_classes.contains(&class.symbol_id)
                || self.derive_partial_ord_classes.contains(&class.symbol_id)
                || self.derive_hash_classes.contains(&class.symbol_id)
                || self.derive_clone_classes.contains(&class.symbol_id)
                || self.derive_copy_classes.contains(&class.symbol_id)
                || self.derive_debug_classes.contains(&class.symbol_id)
                || self.derive_default_classes.contains(&class.symbol_id);

            if needs_field_list {
                let mut instance_fields = Vec::new();
                // field_index starts at 1 (0 = type_id header)
                let mut idx = 1u32;
                // Include inherited fields (walk parent chain)
                if let Some(extends_ty) = class.extends {
                    self.collect_parent_instance_fields(extends_ty, &mut instance_fields, &mut idx);
                }
                // Then this class's own fields
                for field in &class.fields {
                    if !field.is_static {
                        if let Some(ref prop) = field.property_access {
                            if !matches!(prop.getter, crate::tast::PropertyAccessor::Default) {
                                continue; // Skip computed properties
                            }
                        }
                        instance_fields.push((field.symbol_id, field.ty, idx));
                        idx += 1;

                        // Store field default expression: @:default(value) takes priority, then field initializer
                        if let Some(ref default_expr) = field.metadata_default {
                            self.field_default_exprs
                                .insert(field.symbol_id, default_expr.clone());
                        } else if let Some(ref init_expr) = field.init {
                            self.field_default_exprs
                                .insert(field.symbol_id, init_expr.clone());
                        }
                    }
                }
                self.class_instance_fields
                    .insert(class.symbol_id, instance_fields);
            }
        }
    }

    fn register_interface_metadata(&mut self, type_id: TypeId, interface: &HirInterface) {
        // Interfaces are represented as method tables
        let typedef_id = self.builder.module.alloc_typedef_id();

        // Collect parent interface SymbolIds and their methods
        let mut parent_symbols = Vec::new();
        let mut all_method_names: Vec<InternedString> = Vec::new();

        for &parent_type_id in &interface.extends {
            let parent_sym = {
                let type_table = self.type_table.borrow();
                type_table.get(parent_type_id).and_then(|t| {
                    if let TypeKind::Interface { symbol_id, .. } = &t.kind {
                        Some(*symbol_id)
                    } else {
                        None
                    }
                })
            };
            if let Some(psym) = parent_sym {
                parent_symbols.push(psym);
                // Add inherited methods (already registered due to ordering)
                if let Some(parent_methods) = self.interface_method_names.get(&psym).cloned() {
                    for m in parent_methods {
                        if !all_method_names.contains(&m) {
                            all_method_names.push(m);
                        }
                    }
                }
            }
        }

        // Add own methods after inherited ones, and store return types
        for method in &interface.methods {
            if !all_method_names.contains(&method.name) {
                all_method_names.push(method.name);
            }
            self.interface_method_return_types
                .insert((interface.symbol_id, method.name), method.return_type);
        }

        // Store extends relationships for transitive vtable building
        self.interface_extends
            .insert(interface.symbol_id, parent_symbols);

        let fields: Vec<IrField> = all_method_names
            .iter()
            .map(|name| IrField {
                name: self
                    .string_interner
                    .get(*name)
                    .unwrap_or("<unknown>")
                    .to_string(),
                ty: IrType::Ptr(Box::new(IrType::Function {
                    params: vec![IrType::Any],
                    return_type: Box::new(IrType::Any),
                    varargs: false,
                })),
                offset: None,
            })
            .collect();

        let typedef = IrTypeDef {
            id: typedef_id,
            name: self
                .string_interner
                .get(interface.name)
                .unwrap_or("<unknown>")
                .to_string(),
            type_id,
            definition: IrTypeDefinition::Struct {
                fields,
                packed: false,
            },
            source_location: IrSourceLocation::unknown(),
            super_type_id: None,
        };

        self.builder.module.add_type(typedef);

        // Store method ordering for vtable construction (includes inherited methods)
        self.interface_method_names
            .insert(interface.symbol_id, all_method_names);
    }

    fn register_abstract_metadata(&mut self, type_id: TypeId, abstract_decl: &HirAbstract) {
        // Abstract types are type aliases with additional constraints
        let typedef_id = self.builder.module.alloc_typedef_id();

        let typedef = IrTypeDef {
            id: typedef_id,
            name: self
                .string_interner
                .get(abstract_decl.name)
                .unwrap_or("<unknown>")
                .to_string(),
            type_id,
            definition: IrTypeDefinition::Alias {
                aliased_type: IrType::Any, // TODO: Get underlying type
            },
            source_location: IrSourceLocation::unknown(),
            super_type_id: None,
        };

        self.builder.module.add_type(typedef);

        // Store @:from/@:to conversion rules keyed by abstract qualified_name.
        // We use qualified_name (or native_name for extern abstracts, or plain name as fallback)
        // because HIR and type_table have different SymbolIds/TypeIds for the same abstract.
        // The name is the only stable identifier shared between both.
        let rule_key = self
            .symbol_table
            .get_symbol(abstract_decl.symbol_id)
            .and_then(|sym| sym.qualified_name.or(sym.native_name).or(Some(sym.name)))
            .unwrap_or(abstract_decl.name);

        if !abstract_decl.from_rules.is_empty() {
            self.abstract_from_rules
                .insert(rule_key, abstract_decl.from_rules.clone());
        }
        if !abstract_decl.to_rules.is_empty() {
            self.abstract_to_rules
                .insert(rule_key, abstract_decl.to_rules.clone());
        }

        // Store @:forward rules if present
        if !abstract_decl.forward_fields.is_empty()
            || self
                .symbol_table
                .get_symbol(abstract_decl.symbol_id)
                .map_or(false, |s| s.flags.is_forward())
        {
            self.abstract_forward_rules.insert(
                abstract_decl.symbol_id,
                (
                    abstract_decl.underlying,
                    abstract_decl.forward_fields.clone(),
                ),
            );
        }
    }

    fn register_alias_metadata(&mut self, type_id: TypeId, alias: &HirTypeAlias) {
        // Type aliases - check if it's an alias to an anonymous struct
        // If so, register the anonymous struct fields in typedef_field_map
        // This allows field access on typedef'd anonymous structs like FileStat

        let type_table = self.type_table.borrow();
        if let Some(aliased_info) = type_table.get(alias.aliased_type) {
            if let TypeKind::Anonymous { fields } = &aliased_info.kind {
                // Register each field of the anonymous struct by name
                // All fields are 8 bytes for consistent boxing/sizing
                for (index, field) in fields.iter().enumerate() {
                    // Register in typedef_field_map by (typedef_type_id, field_name) -> index
                    // This allows lookup when field access creates new symbols
                    self.typedef_field_map
                        .insert((type_id, field.name), index as u32);

                    // Also try to register any existing symbols with this name
                    let field_symbol = self
                        .symbol_table
                        .symbols_of_kind(crate::tast::symbols::SymbolKind::Field)
                        .into_iter()
                        .find(|s| s.name == field.name)
                        .map(|s| s.id);

                    if let Some(field_sym_id) = field_symbol {
                        // Register in field_index_map: (TypeId of typedef, field index)
                        self.field_index_map
                            .insert(field_sym_id, (type_id, index as u32));
                    }
                }

                // Also create an IrTypeDef with struct fields for proper layout info
                let typedef_id = self.builder.module.alloc_typedef_id();

                let ir_fields: Vec<IrField> = fields
                    .iter()
                    .enumerate()
                    .map(|(idx, f)| {
                        let field_name = self
                            .string_interner
                            .get(f.name)
                            .map(|s| s.to_string())
                            .unwrap_or_else(|| format!("field_{}", idx));
                        IrField {
                            name: field_name,
                            ty: self.convert_type(f.type_id),
                            offset: Some((idx * 8) as u32), // 8 bytes per field
                        }
                    })
                    .collect();

                let typedef = IrTypeDef {
                    id: typedef_id,
                    name: self
                        .string_interner
                        .get(alias.name)
                        .unwrap_or("<unknown>")
                        .to_string(),
                    type_id,
                    definition: IrTypeDefinition::Struct {
                        fields: ir_fields,
                        packed: false,
                    },
                    source_location: IrSourceLocation::unknown(),
                    super_type_id: None,
                };

                self.builder.module.add_type(typedef);
                drop(type_table);
                return;
            }
        }
        drop(type_table);

        // Not an anonymous struct - just register as simple alias
        let typedef_id = self.builder.module.alloc_typedef_id();

        let typedef = IrTypeDef {
            id: typedef_id,
            name: self
                .string_interner
                .get(alias.name)
                .unwrap_or("<unknown>")
                .to_string(),
            type_id,
            definition: IrTypeDefinition::Alias {
                aliased_type: IrType::Any, // TODO: Convert aliased TypeId to IrType
            },
            source_location: IrSourceLocation::unknown(),
            super_type_id: None,
        };

        self.builder.module.add_type(typedef);
    }

    /// Generate uniform constructor wrappers used by `Type.createInstance`.
    ///
    /// Wrapper ABI: `fn(obj_ptr: *u8, args: *void) -> void`
    /// Runtime passes raw 64-bit array slots via `args`; wrappers reinterpret/cast
    /// each slot to match the concrete constructor signature.
    fn generate_constructor_reflect_wrappers(&mut self) {
        let ptr_u8 = IrType::Ptr(Box::new(IrType::U8));
        let ptr_void = IrType::Ptr(Box::new(IrType::Void));

        // Runtime helper used by generated wrappers.
        let array_get_i64_fn = self.get_or_register_extern_function(
            "haxe_array_get_i64",
            vec![ptr_void.clone(), IrType::I64],
            IrType::I64,
        );

        let ctor_entries: Vec<(TypeId, IrFunctionId)> = self
            .constructor_map
            .iter()
            .map(|(class_type_id, ctor_func_id)| (*class_type_id, *ctor_func_id))
            .collect();

        let saved_symbol_map = self.symbol_map.clone();
        self.symbol_map.clear();

        for (class_type_id, ctor_func_id) in ctor_entries {
            if self
                .constructor_reflect_wrappers
                .contains_key(&class_type_id)
            {
                continue;
            }

            // Only emit wrappers for classes known to this module's type metadata.
            let has_typedef = self
                .builder
                .module
                .types
                .values()
                .any(|typedef| typedef.type_id == class_type_id);
            if !has_typedef {
                continue;
            }

            let ctor_sig = match self.builder.module.functions.get(&ctor_func_id) {
                Some(func) => func.signature.clone(),
                None => continue, // Imported constructor body not available in this module.
            };
            if ctor_sig.parameters.is_empty() {
                continue;
            }

            let wrapper_symbol = SymbolId::from_raw(u32::MAX - 1000 - self.next_wrapper_id);
            self.next_wrapper_id += 1;
            let wrapper_name = format!("__reflect_ctor_wrap_{}", class_type_id.as_raw());

            let wrapper_sig = FunctionSignatureBuilder::new()
                .param("obj".to_string(), ptr_u8.clone())
                .param("args".to_string(), ptr_void.clone())
                .returns(IrType::Void)
                .calling_convention(CallingConvention::Haxe)
                .build();

            let wrapper_func_id =
                self.builder
                    .start_function(wrapper_symbol, wrapper_name, wrapper_sig);

            let (obj_reg, args_reg) = {
                let Some(func) = self.builder.current_function() else {
                    self.builder.finish_function();
                    continue;
                };
                let Some(obj) = func.get_param_reg(0) else {
                    self.builder.finish_function();
                    continue;
                };
                let Some(args) = func.get_param_reg(1) else {
                    self.builder.finish_function();
                    continue;
                };
                (obj, args)
            };

            let mut ctor_args: Vec<IrId> = Vec::new();
            let this_ty = ctor_sig.parameters[0].ty.clone();
            let this_arg = if this_ty == ptr_u8 {
                obj_reg
            } else {
                self.builder
                    .build_cast(obj_reg, ptr_u8.clone(), this_ty)
                    .unwrap_or(obj_reg)
            };
            ctor_args.push(this_arg);

            for (param_idx, param) in ctor_sig.parameters.iter().enumerate().skip(1) {
                let Some(index_reg) = self
                    .builder
                    .build_const(IrValue::I64((param_idx.saturating_sub(1)) as i64))
                else {
                    continue;
                };

                let raw_i64 = self
                    .builder
                    .build_call_direct(array_get_i64_fn, vec![args_reg, index_reg], IrType::I64)
                    .or_else(|| self.builder.build_const(IrValue::I64(0)));
                let Some(raw_i64) = raw_i64 else {
                    continue;
                };

                let arg_reg_opt = match &param.ty {
                    IrType::Bool => self.builder.build_cast(raw_i64, IrType::I64, IrType::Bool),
                    IrType::F64 => self.builder.build_bitcast(raw_i64, IrType::F64),
                    IrType::F32 => {
                        let as_i32 = self.builder.build_cast(raw_i64, IrType::I64, IrType::I32);
                        as_i32.and_then(|v| self.builder.build_bitcast(v, IrType::F32))
                    }
                    IrType::I8
                    | IrType::I16
                    | IrType::I32
                    | IrType::I64
                    | IrType::U8
                    | IrType::U16
                    | IrType::U32
                    | IrType::U64 => {
                        if param.ty == IrType::I64 {
                            Some(raw_i64)
                        } else {
                            self.builder
                                .build_cast(raw_i64, IrType::I64, param.ty.clone())
                        }
                    }
                    _ => {
                        let ref_ptr = self
                            .builder
                            .build_cast(raw_i64, IrType::I64, ptr_u8.clone());
                        match &param.ty {
                            IrType::Ptr(_) | IrType::Ref(_) | IrType::Any => {
                                ref_ptr.and_then(|r| {
                                    self.builder.build_cast(r, ptr_u8.clone(), param.ty.clone())
                                })
                            }
                            IrType::String | IrType::Function { .. } => ref_ptr,
                            _ => ref_ptr,
                        }
                    }
                };

                if let Some(arg_reg) = arg_reg_opt {
                    ctor_args.push(arg_reg);
                }
            }

            self.builder
                .build_call_direct(ctor_func_id, ctor_args, IrType::Void);
            self.builder.build_return(None);
            self.builder.finish_function();

            self.constructor_reflect_wrappers
                .insert(class_type_id, wrapper_func_id);
        }

        self.symbol_map = saved_symbol_map;
    }

    fn generate_vtable_init_function(&mut self) {
        // Generate __vtable_init__ function that registers class vtables at startup.
        // Called before main() by the backend (same pattern as __init__).

        let sig = FunctionSignatureBuilder::new()
            .returns(IrType::Void)
            .calling_convention(CallingConvention::Haxe)
            .build();

        let vtable_init_symbol = SymbolId::from_raw(u32::MAX - 2);
        let _func_id =
            self.builder
                .start_function(vtable_init_symbol, "__vtable_init__".to_string(), sig);

        let saved_symbol_map = self.symbol_map.clone();
        self.symbol_map.clear();

        // Register extern functions for vtable operations
        let vtable_init_fn = self.get_or_register_extern_function(
            "haxe_vtable_init",
            vec![IrType::I32, IrType::I32],
            IrType::Void,
        );
        let vtable_set_fn = self.get_or_register_extern_function(
            "haxe_vtable_set_slot",
            vec![IrType::I32, IrType::I32, IrType::I64],
            IrType::Void,
        );
        let register_ctor_fn = self.get_or_register_extern_function(
            "haxe_type_register_constructor",
            vec![IrType::I64, IrType::I64],
            IrType::Void,
        );
        let register_iface_impl_fn = self.get_or_register_extern_function(
            "haxe_register_interface_impl",
            vec![IrType::I64, IrType::I64],
            IrType::Void,
        );

        let class_vtables = self.class_vtables.clone();
        for (class_sym, vtable) in &class_vtables {
            let type_id = class_sym.as_raw() as i32;
            let slot_count = vtable.len() as i32;

            // haxe_vtable_init(type_id, slot_count)
            let type_id_reg = self.builder.build_const(IrValue::I32(type_id));
            let slot_count_reg = self.builder.build_const(IrValue::I32(slot_count));
            if let (Some(tid), Some(sc)) = (type_id_reg, slot_count_reg) {
                self.builder
                    .build_call_direct(vtable_init_fn, vec![tid, sc], IrType::Void);
            }

            // For each slot, create a FunctionRef closure and store it
            for (slot_idx, method_sym) in vtable.iter().enumerate() {
                if let Some(&func_id) = self.function_map.get(method_sym) {
                    let closure_ptr = self.builder.build_function_ref(func_id);
                    let slot_reg = self.builder.build_const(IrValue::I32(slot_idx as i32));
                    let type_id_reg2 = self.builder.build_const(IrValue::I32(type_id));
                    if let (Some(cp), Some(sr), Some(tid2)) = (closure_ptr, slot_reg, type_id_reg2)
                    {
                        self.builder.build_call_direct(
                            vtable_set_fn,
                            vec![tid2, sr, cp],
                            IrType::Void,
                        );
                    }
                }
            }
        }

        // Register class -> interface implementation pairs for Std.is(..., Interface) runtime checks.
        let mut registered_iface_pairs: BTreeSet<(i64, i64)> = BTreeSet::new();
        let interface_vtables = self.interface_vtables.clone();
        for ((class_sym, iface_sym), _methods) in interface_vtables {
            let mut class_ids: BTreeSet<i64> = BTreeSet::new();
            class_ids.insert(class_sym.as_raw() as i64);
            class_ids.insert(class_sym.as_raw() as i64 + 1000);
            if let Some(sym) = self.symbol_table.get_symbol(class_sym) {
                class_ids.insert(sym.type_id.as_raw() as i64);
            }

            let mut iface_ids: BTreeSet<i64> = BTreeSet::new();
            iface_ids.insert(iface_sym.as_raw() as i64);
            iface_ids.insert(iface_sym.as_raw() as i64 + 1000);
            if let Some(sym) = self.symbol_table.get_symbol(iface_sym) {
                iface_ids.insert(sym.type_id.as_raw() as i64);
            }

            for class_type_id in &class_ids {
                for iface_type_id in &iface_ids {
                    if !registered_iface_pairs.insert((*class_type_id, *iface_type_id)) {
                        continue;
                    }
                    let class_tid = self.builder.build_const(IrValue::I64(*class_type_id));
                    let iface_tid = self.builder.build_const(IrValue::I64(*iface_type_id));
                    if let (Some(cid), Some(iid)) = (class_tid, iface_tid) {
                        self.builder.build_call_direct(
                            register_iface_impl_fn,
                            vec![cid, iid],
                            IrType::Void,
                        );
                    }
                }
            }
        }

        // Register constructor closure pointers for Type.createInstance.
        let ctor_wrappers = self.constructor_reflect_wrappers.clone();
        for (class_type_id, wrapper_func_id) in ctor_wrappers {
            let type_id_reg = self
                .builder
                .build_const(IrValue::I64(class_type_id.as_raw() as i64));
            let closure_ptr = self.builder.build_function_ref(wrapper_func_id);
            if let (Some(tid), Some(cptr)) = (type_id_reg, closure_ptr) {
                self.builder
                    .build_call_direct(register_ctor_fn, vec![tid, cptr], IrType::Void);
            }
        }

        self.builder.build_return(None);
        self.builder.finish_function();
        self.symbol_map = saved_symbol_map;
    }

    fn generate_module_init_function(&mut self) {
        // Generate __init__ function that initializes dynamic globals
        // This function is called once at module load time
        //
        // Function signature: fn __init__() -> void
        // Body: Initialize each dynamic global in order

        let init_sig = FunctionSignatureBuilder::new()
            .returns(IrType::Void)
            .calling_convention(CallingConvention::Haxe)
            .build();

        let init_symbol = SymbolId::from_raw(u32::MAX - 1); // Reserved symbol for __init__
        let _init_func_id =
            self.builder
                .start_function(init_symbol, "__init__".to_string(), init_sig);

        // Save current symbol map (should be empty, but just in case)
        let saved_symbol_map = self.symbol_map.clone();
        self.symbol_map.clear();

        // Lower each dynamic global initialization
        for (_symbol, init_expr) in &self.dynamic_globals.clone() {
            // Evaluate the initialization expression
            let Some(_init_value) = self.lower_expression(init_expr) else {
                continue;
            };

            // TODO: Store the result to the global variable
            // This requires accessing the global by symbol ID
            // For now, we just evaluate the expression (side effects occur)
            // In a full implementation, we'd:
            // 1. Get the global's address
            // 2. Store init_value to that address
        }

        // Return void
        self.builder.build_return(None);

        // Finish the __init__ function
        self.builder.finish_function();

        // Restore symbol map
        self.symbol_map = saved_symbol_map;
    }

    fn add_error(&mut self, msg: &str, location: SourceLocation) {
        self.errors.push(LoweringError {
            message: msg.to_string(),
            location,
        });
    }
}

enum MirBinaryOp {
    Binary(BinaryOp),
    Compare(CompareOp),
}

/// Public API for HIR to MIR lowering
pub fn lower_hir_to_mir(
    hir_module: &HirModule,
    string_interner: &StringInterner,
    type_table: &Rc<RefCell<TypeTable>>,
    symbol_table: &SymbolTable,
) -> Result<IrModule, Vec<LoweringError>> {
    lower_hir_to_mir_with_externals(
        hir_module,
        string_interner,
        type_table,
        symbol_table,
        BTreeMap::new(),
    )
}

/// Public API for HIR to MIR lowering with external function references
///
/// The `external_functions` map contains SymbolId -> IrFunctionId mappings for functions
/// defined in other modules (e.g., stdlib) that can be called from this module.
pub fn lower_hir_to_mir_with_externals(
    hir_module: &HirModule,
    string_interner: &StringInterner,
    type_table: &Rc<RefCell<TypeTable>>,
    symbol_table: &SymbolTable,
    external_functions: BTreeMap<SymbolId, IrFunctionId>,
) -> Result<IrModule, Vec<LoweringError>> {
    let mut context = HirToMirContext::new(
        hir_module.name.clone(),
        hir_module.metadata.source_file.clone(),
        string_interner,
        type_table,
        &hir_module.types,
        symbol_table,
        StdlibMapping::new(),
    );

    // Set the external function map
    context.external_function_map = external_functions;

    context.lower_module(hir_module)
}

/// Result of MIR lowering that includes both the module and the function mappings
pub struct MirLoweringResult {
    /// The compiled MIR module
    pub module: IrModule,
    /// Mapping from HIR function symbols to MIR function IDs
    /// This can be used to build the external_functions map for other modules
    pub function_map: BTreeMap<SymbolId, IrFunctionId>,
    /// Field index mappings for class instances (SymbolId -> (TypeId, field_index))
    /// Exported so that importing modules can resolve field access on imported classes
    pub field_index_map: BTreeMap<SymbolId, (TypeId, u32)>,
    /// Property accessor info for class properties
    pub property_access_map: BTreeMap<SymbolId, crate::tast::PropertyAccessInfo>,
    /// Constructor name map (class qualified name -> constructor IrFunctionId)
    /// Exported so that importing modules can resolve `new ClassName()` across files
    pub constructor_name_map: BTreeMap<String, IrFunctionId>,
    /// Class allocation sizes (TypeId -> byte size)
    /// Exported so importing modules know how much memory to allocate for `new ClassName()`
    pub class_alloc_sizes: BTreeMap<TypeId, u64>,
    /// Name-keyed class allocation sizes (class_name → bytes).
    /// Stable across compilation contexts where TypeIds differ.
    pub class_alloc_sizes_by_name: BTreeMap<String, u64>,
    /// Class method symbols (class_symbol, method_name) -> method_symbol
    /// Exported so importing modules can resolve iterator protocol methods
    pub class_method_symbols: BTreeMap<(SymbolId, InternedString), SymbolId>,
    /// Class TypeId → SymbolId mapping. Survives type_table overwrites.
    /// Used for field disambiguation when multiple classes have same-named fields.
    pub class_type_to_symbol: BTreeMap<TypeId, SymbolId>,
    /// Field SymbolId → class name string. Used by BLADE cache to store field entries
    /// with class names that survive across compilation contexts (where TypeIds differ).
    pub field_class_names: BTreeMap<SymbolId, String>,
    /// Non-fatal diagnostics from the lowering pass (e.g., exhaustiveness warnings)
    pub diagnostics: Vec<diagnostics::Diagnostic>,
}

/// Lower HIR to MIR and return both the module and function mappings
///
/// This is useful when you need to compile multiple modules and have later modules
/// call functions from earlier modules (e.g., user code calling stdlib functions).
pub fn lower_hir_to_mir_with_function_map(
    hir_module: &HirModule,
    string_interner: &StringInterner,
    type_table: &Rc<RefCell<TypeTable>>,
    symbol_table: &SymbolTable,
    external_functions: BTreeMap<SymbolId, IrFunctionId>,
    external_functions_by_name: BTreeMap<String, IrFunctionId>,
    stdlib_mapping: StdlibMapping,
    external_field_index_map: BTreeMap<SymbolId, (TypeId, u32)>,
    external_property_access_map: BTreeMap<SymbolId, crate::tast::PropertyAccessInfo>,
    external_constructor_name_map: BTreeMap<String, IrFunctionId>,
    external_class_alloc_sizes: BTreeMap<TypeId, u64>,
    external_class_method_symbols: BTreeMap<(SymbolId, InternedString), SymbolId>,
    external_class_type_to_symbol: BTreeMap<TypeId, SymbolId>,
    external_constructor_param_counts: BTreeMap<IrFunctionId, usize>,
    external_function_param_types: BTreeMap<IrFunctionId, Vec<IrType>>,
    external_class_alloc_sizes_by_name: BTreeMap<String, u64>,
) -> Result<MirLoweringResult, Vec<LoweringError>> {
    let mut context = HirToMirContext::new(
        hir_module.name.clone(),
        hir_module.metadata.source_file.clone(),
        string_interner,
        type_table,
        &hir_module.types,
        symbol_table,
        stdlib_mapping,
    );

    // Set the external function maps (by SymbolId and by qualified name)
    context.external_function_map = external_functions;
    context.external_function_name_map = external_functions_by_name;

    // Seed field_index_map and property_access_map from previously compiled imports
    context.field_index_map = external_field_index_map;
    context.property_access_map = external_property_access_map;

    // Seed constructor_name_map from previously compiled imports
    context.constructor_name_map = external_constructor_name_map;

    // Seed class_alloc_sizes from previously compiled imports
    context.class_alloc_sizes = external_class_alloc_sizes;

    // Seed class_method_symbols from previously compiled imports
    context.class_method_symbols = external_class_method_symbols;

    // Seed class_type_to_symbol from previously compiled imports
    context.class_type_to_symbol = external_class_type_to_symbol;

    // Seed name-keyed alloc sizes from previously compiled imports (stable across contexts)
    context.class_alloc_sizes_by_name = external_class_alloc_sizes_by_name;

    // Also populate from the TypeId-keyed map + symbol table.
    for (&type_id, &size) in &context.class_alloc_sizes {
        if let Some(&sym_id) = context.class_type_to_symbol.get(&type_id) {
            if let Some(sym) = symbol_table.get_symbol(sym_id) {
                let name = sym
                    .qualified_name
                    .and_then(|n| string_interner.get(n))
                    .or_else(|| string_interner.get(sym.name));
                if let Some(name) = name {
                    context
                        .class_alloc_sizes_by_name
                        .insert(name.to_string(), size);
                }
            }
        }
    }
    // Also try to resolve names directly from the type_table for entries not in class_type_to_symbol
    {
        let tt = type_table.borrow();
        for (&type_id, &size) in &context.class_alloc_sizes {
            if context.class_type_to_symbol.contains_key(&type_id) {
                continue; // Already handled above
            }
            if let Some(info) = tt.get(type_id) {
                if let crate::tast::core::TypeKind::Class { symbol_id, .. } = &info.kind {
                    if let Some(sym) = symbol_table.get_symbol(*symbol_id) {
                        let name = sym
                            .qualified_name
                            .and_then(|n| string_interner.get(n))
                            .or_else(|| string_interner.get(sym.name));
                        if let Some(name) = name {
                            context
                                .class_alloc_sizes_by_name
                                .insert(name.to_string(), size);
                        }
                    }
                }
            }
        }
    }

    // Seed constructor param counts for fill_default_args fallback
    context.external_constructor_param_counts = external_constructor_param_counts;

    // Seed function param types for fill_default_args (cross-module optional params)
    context.external_function_param_types = external_function_param_types;

    let mut module = context.lower_module(hir_module)?;

    // Build reverse map: func_id -> qualified_name for all external functions.
    // This enables blade cache to resolve cross-module references when function IDs
    // change between sessions (different renumbering bases).
    {
        let mut ext_id_to_name: BTreeMap<IrFunctionId, String> = BTreeMap::new();
        for (name, &func_id) in &context.external_function_name_map {
            ext_id_to_name
                .entry(func_id)
                .or_insert_with(|| name.clone());
        }
        // Scan module for references to external functions
        for func in module.functions.values() {
            for block in func.cfg.blocks.values() {
                for inst in &block.instructions {
                    let ref_ids: Vec<IrFunctionId> = match inst {
                        crate::ir::IrInstruction::CallDirect { func_id, .. }
                        | crate::ir::IrInstruction::FunctionRef { func_id, .. }
                        | crate::ir::IrInstruction::MakeClosure { func_id, .. } => {
                            vec![*func_id]
                        }
                        _ => vec![],
                    };
                    for fid in ref_ids {
                        if !module.functions.contains_key(&fid)
                            && !module.extern_functions.contains_key(&fid)
                        {
                            if let Some(name) = ext_id_to_name.get(&fid) {
                                module.external_function_names.insert(fid, name.clone());
                            }
                        }
                    }
                }
            }
        }
    }

    Ok(MirLoweringResult {
        module,
        function_map: context.function_map,
        field_index_map: context.field_index_map,
        property_access_map: context.property_access_map,
        constructor_name_map: context.constructor_name_map,
        class_alloc_sizes: context.class_alloc_sizes,
        class_alloc_sizes_by_name: context.class_alloc_sizes_by_name,
        class_method_symbols: context.class_method_symbols,
        class_type_to_symbol: context.class_type_to_symbol,
        field_class_names: context.field_class_names,
        diagnostics: context.diagnostics,
    })
}
